INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광나루 자전거공원 인증센터', '한강 종주 자전거길의 필수 거점인 광나루 자전거공원 인증센터입니다. 주변에 자전거 공원, 대여소, 편의점이 있어 라이딩 중 휴식과 보급을 하기에 좋습니다.', '{checkpoint,park,river,convenience_store,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.120215, 37.546545), 4326), false, '{"source": "KOMOOT", "source_ids": ["1909", "1207", "116", "2001", "108", "219", "105", "133", "112", "56"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1s/1s6k87gin1omb1dac9z2noyjbm44pnvsh8-uhi48440793/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 45, "nearby_landmarks": ["광나루 자전거공원", "광진교", "세븐일레븐 한강광나루1호점"], "confidence": "high", "address": "대한민국 서울특별시 강동구 천호동 483-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('잠수교 남단', '한강 자전거길 남북을 잇는 핵심 교차점이자 세빛섬, 반포한강공원과 연결되어 라이더들의 만남의 광장으로 사랑받는 곳입니다.', '{bridge,rest_area,viewpoint,river,park,landmark,convenience_store,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.998708, 37.511023), 4326), false, '{"source": "KOMOOT", "source_ids": ["914", "554", "99", "874", "208", "53", "159", "139", "526", "1293"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k1/1n/1n9eut5mbr3xl1aelk9nkdxixn2b1zzr20-uhi1566114/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/19/19mire984f58x110rwh5sthmku3vh1yq7u-uhi39192209/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1b/1bldhr22zahovz90agj3w9x4f4lr3sedg-uhi61111841/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 39, "nearby_landmarks": ["세빛섬", "반포대교 달빛무지개분수", "반포한강공원"], "confidence": "high", "address": "대한민국 서울특별시 세빛섬"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('북한강철교', '옛 중앙선 기찻길을 개조한 자전거·보행자 전용 교량입니다. 남한강 자전거길의 하이라이트 구간으로, 두물머리와 팔당호의 탁 트인 절경을 감상하며 달릴 수 있습니다.', '{bridge,viewpoint,historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.318107, 37.550531), 4326), false, '{"source": "KOMOOT", "category_raw": "bridge", "tour_count": 34, "nearby_landmarks": ["두물머리", "능내역(폐역)", "물의정원", "팔당호"], "confidence": "high", "address": "대한민국 경기도 양평군 양서면 양수리 512-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('용비쉼터', '중랑천과 한강이 만나는 합수부에 위치한 자전거 전용 로터리 및 휴게 공간(용비쉼터)입니다. 여러 자전거길이 교차하여 라이더들의 주요 만남의 장소로 애용됩니다.', '{rest_area,river,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.030502, 37.545819), 4326), false, '{"source": "KOMOOT", "source_ids": ["948", "72", "207", "99", "150", "372", "453", "632", "1581", "1105"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/ys/ys5wwvvesm2j12bjiy7ru3f4qgj8fjs-uhi66002208/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/uq/uqc3sqo739471dwcjdx03jisz3cx79jak-uhi12441366/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1j/1j7jeetbiz2fi1s0rzdtdf01c73a3s49hc-uhi10603538/0?width=1920&crop=false"], "tips": [{"text": "Bike-only roundabout, what is there not to love about this! Could be a good meeting point if heading in this direction.", "author": "Jon"}, {"text": "Bike-only roundabout, what is there not to love about this! Could be a good meeting point if heading in this direction.", "author": ""}], "category_raw": "facilities", "tour_count": 33, "nearby_landmarks": ["용비교", "응봉산", "서울숲"], "confidence": "high", "address": "대한민국 서울특별시 성동구 금호동4가 2-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('아라한강갑문 인증센터', '국토종주 자전거길의 주요 인증센터입니다. 화장실, 음수대, 공기주입기 등 라이더를 위한 휴식 및 경정비 시설이 잘 갖춰져 있습니다.', '{checkpoint,rest_area,restroom,water_fountain,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.800175, 37.598795), 4326), false, '{"source": "KOMOOT", "source_ids": ["114", "197", "240", "718", "362", "1162", "158", "199", "195", "264"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/12/12bn7bk1hoqxh1jvpdllvoarz54qwliag4-uhi66434275/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/k6/k61tfkf778a1ua5hd2q5io4x4qwlib9k-uhi66434276/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/14/14jcjytwr4r414a59qwwf0y9o44pnxw9s-uhi48440850/0?width=1920&crop=false"], "tips": [{"text": "Nice and quiet area incl. pitstop for some snacks or repairs at your bike.", "author": "Dirkster"}], "category_raw": "facilities", "tour_count": 29, "nearby_landmarks": ["판개목 쉼터", "강서습지생태공원", "행주대교", "아라뱃길"], "confidence": "high", "address": "대한민국 서울특별시 강서구 개화동 31-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광나루 한강공원 드론공원', '광나루 한강공원 내 위치한 드론 전용 비행장입니다. 한강 자전거길과 바로 인접해 있어 라이딩 중 드론 비행을 구경하며 잠시 쉬어가기 좋은 장소입니다.', '{park,river,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.120688, 37.547837), 4326), false, '{"source": "KOMOOT", "source_ids": ["112", "104", "90", "491", "24", "137", "116", "147", "109", "190"], "category_raw": "other_man_made", "tour_count": 28, "nearby_landmarks": ["광나루 자전거공원", "광나루 한강공원", "한강"], "confidence": "high", "address": "대한민국 서울특별시 강동구 천호제2동 344-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('잠실한강공원 자전거길', '잠실한강공원을 지나는 한강 자전거길 구간입니다. 라이더와 보행자 안전을 위한 회전교차로와 교통 표지판이 잘 정비되어 있습니다.', '{river,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.100317, 37.522852), 4326), false, '{"source": "KOMOOT", "source_ids": ["174", "146", "124", "71", "213", "88", "142", "2067", "152", "1068"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1n/1njh6dhdo0z7t18ctbfnpipf8b56dg0906-uhi80788625/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/dn/dnvkay7i3vly2rrenoy1ufb456dg090w-uhi80788626/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/b0/b0007vb2gf6j7ohwunubpeyp56dg092w-uhi80788627/0?width=1920&crop=false"], "tips": [{"text": "A well-designed segment of roadway featuring traffic signs and a roundabout.", "author": "Vitale Vasilieff"}], "category_raw": "cycle_way", "tour_count": 27, "nearby_landmarks": ["잠실한강공원", "잠실철교", "올림픽대교"], "confidence": "high", "address": "대한민국 서울특별시 송파구 신천동 5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('양재천·탄천 합수부', '탄천과 양재천 자전거길이 교차하는 합수부입니다. 라이더들의 주요 만남의 장소이자 쉼터로 활용되는 필수 웨이포인트입니다.', '{river,rest_area,checkpoint,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.072826, 37.500449), 4326), false, '{"source": "KOMOOT", "source_ids": ["241", "99", "1056", "1114", "395", "223", "300", "203", "22", "74"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1j/1jy4lqtoaf5b10lxq33ypmi74me6r9oi-uhi61781159/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/15/15jtad3skm78ldag4ita0u8k95dhxixb7-uhi86768379/0?width=1920&crop=false"], "category_raw": "river", "tour_count": 26, "nearby_landmarks": ["탄천", "양재천", "학여울역", "대치교"], "confidence": "high", "address": "대한민국 서울특별시 강남구 대치동 4-20 양재천 합수부"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('월드컵대교 아래', '한강 자전거길 북단 월드컵대교 하부 공간입니다. 라이딩 중 그늘에서 휴식하기 좋으며, 엘리베이터를 통해 교량 위 자전거길로 진입할 수 있습니다.', '{bridge,rest_area,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.895708, 37.554344), 4326), false, '{"source": "KOMOOT", "source_ids": ["457", "149", "91", "106", "162", "326", "105", "487", "662", "552"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/9t/9tgj4a5s4gnf8jg2co6z34cb4pytqk7s-uhi65436268/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/44/44vidqfw8p321a05ac650jchr4pytqmxl-uhi65436269/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 26, "nearby_landmarks": ["월드컵대교", "망원한강공원", "난지한강공원"], "confidence": "high", "address": "대한민국 서울특별시 마포구 마포나루길 437"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('성수 스카이라인 전망대', '영동대교와 성수대교 사이 한강 남단 자전거길에 위치한 뷰포인트입니다. 강 건너 성수동의 화려한 스카이라인을 조망하며 라이딩 중 쉬어가기 좋습니다.', '{viewpoint,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.051355, 37.528915), 4326), false, '{"source": "KOMOOT", "source_ids": ["1002", "403", "27", "2152", "112", "1168", "54", "104", "90", "366"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1l/1lapqs00f7nwj1hfbhjzx84vka3ji6ebkd-uhi24231023/0?width=1920&crop=false"], "category_raw": "viewpoint", "tour_count": 25, "nearby_landmarks": ["영동대교", "성수대교", "한강 자전거길"], "confidence": "high", "address": "대한민국 서울특별시 강남구 청담동 342-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('난지한강공원', '한강 자전거길 북단에 위치한 친환경 테마공원입니다. 편의점, 화장실, 음수대 등 휴식 시설이 풍부하며 MTB 체험장도 갖추고 있어 라이더들이 쉬어가기 좋습니다.', '{park,river,convenience_store,restroom,water_fountain,rest_area,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.876709, 37.565689), 4326), false, '{"source": "KOMOOT", "source_ids": ["235", "647", "248", "133", "645", "584", "1411", "478", "65", "887"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1h/1hv0nwzw5vad011bcolcnxp88b3dvzize3-uhi13807982/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1r/1rg6ny0wodcbof34pgap12ag23dvzj5gd-uhi13807985/0?width=1920&crop=false"], "tips": [{"text": "Nanji Hangang Park was built on the site of old garbage landfill and its surrounding areas as part of Hangang Renaissance project. It is an eco-friendly theme park which features the Nanji Eco-Wetland, Nanji Campground and a marina. The park is also one of the 5 parks celebrating the FIFA World Cup in 2002 in Korea and Japan.\n\nThere, you can also find a designed area where visitors can enjoy extreme sports such as inline skating and BMX. A riverside swimming pool, the Water Plaza, and a riverside stage will be set up as well.", "author": "AsuRa"}, {"text": "Nanji Hangang Park was built on the site of old garbage landfill and its surrounding areas as part of Hangang Renaissance project. It is an eco-friendly theme park which features the Nanji Eco-Wetland, Nanji Campground and a marina. The park is also one of the 5 parks celebrating the FIFA World Cup in 2002 in Korea and Japan.\n\nThere, you can also find a designed area where visitors can enjoy extreme sports such as inline skating and BMX. A riverside swimming pool, the Water Plaza, and a riverside stage will be set up as well.", "author": ""}], "category_raw": "facilities", "tour_count": 21, "nearby_landmarks": ["난지캠핑장", "하늘공원", "노을공원", "월드컵대교"], "confidence": "high", "address": "대한민국 서울특별시 마포구 상암동 482-123"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('중랑천·부용천 합수부', '중랑천과 부용천 자전거길이 만나는 주요 합수부입니다. 한강에서 북상 시 우측(동측) 자전거길은 공사로 통제될 수 있으니 주의가 필요합니다.', '{river,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.054244, 37.744056), 4326), false, '{"source": "KOMOOT", "source_ids": ["1465", "454", "370", "910", "209", "61", "94", "197", "79", "140"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/lh/lhbo4g0tiwm1vlu68k4zk7cb3bs7r1hg-uhi11260339/0?width=1920&crop=false"], "tips": [{"text": "중량천은 공사중인데가 많아요. 자난 11월17일에 라이딩 시 오른쪽 길은 공사로 인하여 막혀 있는 부분이 있습니다. 오른쪽이란 한강에서 의정부 가는 방향입니다.", "author": "유리"}], "category_raw": "river", "tour_count": 21, "nearby_landmarks": ["중랑천", "부용천", "발곡역"], "confidence": "high", "address": "대한민국 경기도 의정부시 의정부동 1-72"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('밝은광장 인증센터', '북한강 자전거길이 시작되는 인증센터로, 운길산역과 가까워 대중교통 접근성이 뛰어납니다. 탁 트인 북한강 풍경을 감상하며 라이딩을 출발하기 좋은 필수 거점입니다.', '{checkpoint,rest_area,viewpoint,river,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.312741, 37.553312), 4326), false, '{"source": "KOMOOT", "source_ids": ["2190", "1799", "146", "341", "1332", "51", "439", "373", "430", "116"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/jf/jfd7xwgqlhyldvhwyqlhew0z361z38rr-uhi9058579/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/oj/ojbtqba230uq1w1d3xlvokuqw361z3eu4-uhi9058582/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/7o/7okmgpbvukru54ys6zj9f7oh3trzomyu-uhi36537375/0?width=1920&crop=false"], "tips": [{"text": "One of my favorite trails begins here: the Buhangang Bicycle Path, which features many mountains along the route. It''s truly inspiring.", "author": "Vitale Vasilieff"}, {"text": "One of my favorite trails begins here: the Buhangang Bicycle Path, which features many mountains along the route. It''s truly inspiring.", "author": ""}], "category_raw": "cycle_way", "tour_count": 18, "nearby_landmarks": ["운길산역", "북한강 철교", "물의 정원", "두물머리"], "confidence": "high", "address": "대한민국 경기도 남양주시 조안면 진중리 303-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('유등천 자전거길', '유등천을 따라 조성된 자전거길 구간입니다. ''퇴근''이라는 명칭은 라이더가 자전거 출퇴근(자출/자퇴) 코스로 기록한 개인 웨이포인트로 추정됩니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.403589, 36.349111), 4326), false, '{"source": "KOMOOT", "source_ids": ["193", "69", "51", "557", "604", "50", "626", "784", "376", "95"], "category_raw": "unknown", "tour_count": 18, "nearby_landmarks": ["유등천", "유등천 자전거길"], "confidence": "high", "address": "대한민국 대전광역시 중구 중촌동 413-29"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('행주대교 남단', '아름다운 저녁 노을을 감상할 수 있는 한강 횡단 교량입니다. 자전거길이 좁고 노면에 파편이 있을 수 있으며, 진입로 유턴 구간에서 안전에 각별히 주의해야 합니다.', '{bridge,viewpoint,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.804896, 37.592427), 4326), false, '{"source": "KOMOOT", "source_ids": ["1077", "291", "336", "168", "99", "1650", "240", "245", "249", "1184"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/l4/l4gq3t6lu2eu1iolx6tlunqpp3dvzc81f-uhi13807825/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1x/1xuk6eebtb7er199ragn13sd3n3gr854vm-uhi18943513/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/xe/xe7sncpthp0b1gr5vgs584f6u3gr85hmn-uhi18943517/0?width=1920&crop=false"], "tips": [{"text": "Southbound section of the bridge is great for catching evening sunsets depending on conditions and season. \n\nWARNING: Please take care bridge crossing is very narrow and can often capture debris and rubbish from heavy traffic across the bridge. It also operates in one direction only per side, Northbound on Seoul side and Southbound on Goyang side.", "author": ""}, {"text": "Southbound section of the bridge is great for catching evening sunsets depending on conditions and season. \n\nWARNING: Please take care bridge crossing is very narrow and can often capture debris and rubbish from heavy traffic across the bridge. It also operates in one direction only per side, Northbound on Seoul side and Southbound on Goyang side.", "author": "Jon"}], "category_raw": "bridge", "tour_count": 18, "nearby_landmarks": ["강서습지생태공원", "아라한강갑문", "한강자전거길"], "confidence": "high", "address": "대한민국 서울특별시 강서구 개화동 143-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('HBC 커피', '자전거 핸들 문고리와 실내 자전거 장식이 돋보이는 라이더들의 아지트 카페입니다. 뚝섬 자전거길과 가까워 접근성이 좋고, 훌륭한 커피와 힙한 분위기를 즐길 수 있습니다.', '{cafe}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.055281, 37.534986), 4326), false, '{"source": "KOMOOT", "source_ids": ["223", "766", "169", "114", "87", "61", "231", "324", "186", "380"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/dj/djz6lum5sawkp2z6yo1dmhk052l0ki5x-uhi76230995/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/gd/gduwmsg75nh5i6imtpmes0fh52l0kp1t-uhi76230996/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1g/1gy4a9la8kkpm1xinbcnftzuzf52l0kp1t-uhi76230997/0?width=1920&crop=false"], "tips": [{"text": "A unique cafe for bicycle and coffee aficionados. The coffee is superb and the place a great vibe.", "author": "Max"}], "category_raw": "cafe", "tour_count": 17, "nearby_landmarks": ["뚝섬 자전거길", "성수역"], "confidence": "high", "address": "대한민국 서울특별시 성동구 성수동2가 715-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('덕풍천 징검다리', '하남 당정뜰 인근 덕풍천을 건너는 징검다리(세월교)입니다. 평소에는 자전거와 함께 건널 수 있으나, 큰비로 수위가 높아지면 물에 잠기므로 우회해야 합니다.', '{river,bridge,park,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.21873, 37.548813), 4326), false, '{"source": "KOMOOT", "source_ids": ["104", "343", "234", "43", "89", "192", "373", "388", "91", "520"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1x/1x7iy6qat023lnmjgjzmrbljw4dcpxjoj-uhi56170422/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/da/dalxkd8aag04wqqu6kexvjn65czz8lc6-uhi86049601/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/15/152jpsltbfrg31n5ntikb3s7bw4dcpxk68-uhi56170423/0?width=1920&crop=false"], "tips": [{"text": "Nur bei Hochwasser wird es nass.", "author": "Andreas Wendtland"}], "category_raw": "river", "tour_count": 17, "nearby_landmarks": ["당정뜰", "덕풍천", "하남유니온타워", "팔당대교"], "confidence": "high", "address": "대한민국 경기도 하남시 신장동 18-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('갑천 만년 자전거길', '대전 만년동 갑천을 따라 조성된 평탄하고 쾌적한 자전거길입니다. 한밭수목원과 엑스포다리를 지나며 도심 속 아름다운 수변 풍경을 즐기며 라이딩하기 좋습니다.', '{river,park,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.375508, 36.364997), 4326), false, '{"source": "KOMOOT", "source_ids": ["193", "589", "36", "199", "896", "817", "801", "453", "28", "619"], "category_raw": "cycle_way", "tour_count": 17, "nearby_landmarks": ["갑천", "한밭수목원", "엑스포다리", "한빛탑"], "confidence": "high", "address": "대한민국 대전광역시 만년동"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('방화대교 남단 편의점', '방화대교 남단 교각 아래 위치한 편의점입니다. 화장실과 넓은 그늘 쉼터가 있어 한강 자전거길 라이더들의 훌륭한 휴식처이자 만남의 장소입니다.', '{convenience_store,rest_area,restroom,bridge,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.820877, 37.584797), 4326), false, '{"source": "KOMOOT", "source_ids": ["59", "279", "298", "325", "1218", "64", "238", "244", "70", "594"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/kt/ktvfydnqauiz1n20ehrvob7y83g4k8nbe-uhi17675652/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/t1/t16lq3pbvfdt14pza358m723l4nya1u8q-uhi63289402/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/an/anxpgojmbb5910zn517ox5heh4pf59b83-uhi64830863/0?width=1920&crop=false"], "tips": [{"text": "Another good meeting point or stop off on a longer journey. \n\nAs well as the convenience store there is also a set of toilets and large undercover area just near here where the bridge crosses the river so can make a great place to shelter.", "author": "Jon"}, {"text": "Another good meeting point or stop off on a longer journey. \n\nAs well as the convenience store there is also a set of toilets and large undercover area just near here where the bridge crosses the river so can make a great place to shelter.", "author": ""}], "category_raw": "facilities", "tour_count": 16, "nearby_landmarks": ["방화대교", "한강 자전거길 남단"], "confidence": "high", "address": "대한민국 서울특별시 강서구 양천로27길 280-11"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('성심당 DCC점', '갑천 자전거길과 인접해 있어 라이딩 중 빵으로 당을 충전하고 휴식하기 좋은 대전의 대표 랜드마크 빵집입니다.', '{cafe,rest_area,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.392164, 36.375353), 4326), false, '{"source": "KOMOOT", "source_ids": ["112", "146", "48", "122", "647", "492", "493", "190", "106", "103"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/zq/zq9t362ko91a1en0bpuqq6d6n5i1jk6cv-uhi93031856/0?width=1920&crop=false"], "category_raw": "cafe", "tour_count": 16, "nearby_landmarks": ["갑천 자전거길", "대전컨벤션센터(DCC)", "엑스포과학공원"], "confidence": "high", "address": "대한민국 대전광역시 유성구 엑스포로 107"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('중랑천 자전거길 입구 (응봉역 방향)', '응봉역 인근에 위치한 중랑천 자전거길 진출입로입니다. 한강 자전거길과 중랑천 코스가 이어지는 주요 기점으로 대중교통 연계와 접근성이 매우 좋습니다.', '{river,transit,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.035947, 37.550683), 4326), false, '{"source": "KOMOOT", "source_ids": ["220", "713", "13", "1269", "366", "128", "271", "110", "961", "376"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/hz/hzrkwb37j1sbqsbko0op66f43fxgeayr-uhi17242635/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 16, "nearby_landmarks": ["응봉역", "중랑천", "용비교", "응봉산"], "confidence": "high", "address": "대한민국 서울특별시 성동구 응봉동 242-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('아라한강갑문', '아라자전거길과 한강종주자전거길이 연결되는 지점에 위치한 웅장한 수문입니다. 국토종주 라이더들이 반드시 거쳐 가는 주요 기점이자 랜드마크입니다.', '{landmark,river,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.794351, 37.59208), 4326), false, '{"source": "KOMOOT", "source_ids": ["1667", "90", "1802", "955", "333", "199", "248", "228", "184", "156"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k0/1e/1e9d7y6h88ey1spgmru0aiq9e1xfq9kr1-uhi551830/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1jz/yb/ybc5lknm44561w23m32tyw1ao1e3vg8x4-uhinull/0?width=1920&crop=false"], "category_raw": "other_man_made", "tour_count": 16, "nearby_landmarks": ["아라한강갑문 인증센터", "전호대교", "아라뱃길"], "confidence": "high", "address": "대한민국 경기도 김포시 고촌읍 아라육로 37"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('방화대교 북단 쉼터', '방화대교 북단 창릉천 합수부에 위치한 자전거 쉼터입니다. 다리 아래 넓은 그늘과 벤치가 있어 한강 라이딩 중 햇빛과 비를 피해 휴식하기 좋은 주요 거점입니다.', '{rest_area,bridge,river,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.830442, 37.600021), 4326), false, '{"source": "KOMOOT", "source_ids": ["255", "386", "457", "114", "161", "396", "81", "729", "266", "270"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1g/1g4iem4i58vg41hm40as8w0kk473w5b82-uhi50493174/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/an/an6ilvktm43j1p3x6klnb19un473w5ef3-uhi50493175/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/f0/f0lpxbqwg6ny677f4wuit9j5473w5gm5-uhi50493176/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 15, "nearby_landmarks": ["방화대교", "창릉천 합수부", "고양대덕생태공원", "행주산성"], "confidence": "high", "address": "대한민국 경기도 고양시 덕양구 행주내동 116-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('수영교 교차로', '수영강 자전거길과 수영교가 만나는 지점입니다. 광안리, 해운대, 온천천 방면으로 진출입하거나 수영강을 건널 수 있는 주요 라이딩 길목입니다.', '{checkpoint,bridge,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.125427, 35.165663), 4326), false, '{"source": "KOMOOT", "source_ids": ["90", "63", "755", "61", "51", "833", "1331", "767", "54", "106"], "category_raw": "other_man_made", "tour_count": 15, "nearby_landmarks": ["수영교", "수영강", "민락수변공원"], "confidence": "high", "address": "대한민국 부산광역시 수영구 민락동 수영강변 산책로"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('봉크', '행주산성 인근에 위치한 자전거 테마 카페 겸 프리미엄 용품점입니다. 한강 자전거길과 가까워 라이딩 중 휴식과 보급을 하기에 좋습니다.', '{cafe,bike_shop,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.823056, 37.605049), 4326), false, '{"source": "KOMOOT", "source_ids": ["41", "267", "348", "74", "343", "857", "363", "677", "373", "201"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/3j/3jc0leh5eisl1ctkmbvnk61kw33fkexp2-uhi7652789/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/we/wewnuxogoq5wyyfmb3ufqusi33fkifxz-uhi7652817/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/18/18yzcj2whwu3v13l7k5or8p0py37cjhwgn-uhi9465892/0?width=1920&crop=false"], "tips": [{"text": "Premium outlet, stocking VOID & Fizik and SIDI. There is also an attached coffee counter with outside seating. This is a good stop off on Han River loops, or routes returning or going to / through Goyang or Paju. Already added as a Road Cycling Highlight.", "author": "Jon"}, {"text": "Premium outlet, stocking VOID & Fizik and SIDI. There is also an attached coffee counter with outside seating. This is a good stop off on Han River loops, or routes returning or going to / through Goyang or Paju. Already added as a Road Cycling Highlight.", "author": ""}], "category_raw": "cafe", "tour_count": 15, "nearby_landmarks": ["행주산성", "한강 자전거길"], "confidence": "high", "address": "대한민국 경기도 고양시 덕양구 행주내동 733-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('여의도 인증센터', '국토종주 및 한강 자전거길의 필수 스탬프 인증 지점입니다. 국회의사당과 서울마리나 인근 여의도 한강공원 내에 위치해 있어 라이더들이 자주 찾는 곳입니다.', '{checkpoint,park,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.945319, 37.518065), 4326), false, '{"source": "KOMOOT", "source_ids": ["173", "1419", "1019", "154", "1409", "1450", "670", "141", "312", "405"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1w/1w1lh83bemeb01gagrz0ul64ml3ds2jxk9-uhi13659886/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1p/1pnl34tn6ke9m13kl3nwqrjxad3dwwl55f-uhi13825833/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 15, "nearby_landmarks": ["국회의사당", "서울마리나", "여의도 한강공원"], "confidence": "high", "address": "대한민국 서울특별시 영등포구 여의동 87-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('을지대학교병원', '중랑천 자전거길 인근에 위치한 대형 종합병원입니다. 라이딩 중 길잡이가 되는 주요 랜드마크이자 응급 상황 시 유용한 시설입니다.', '{hospital,landmark,convenience_store,cafe,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.049148, 37.750634), 4326), false, '{"source": "KOMOOT", "source_ids": ["212", "202", "358", "516", "517", "1083", "865", "447", "708", "903"], "category_raw": "facilities", "tour_count": 15, "nearby_landmarks": ["중랑천", "부용천", "을지대학교 의정부캠퍼스"], "confidence": "high", "address": "대한민국 경기도 의정부시 금오동 440-37"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('망원한강공원 피크닉장', '망원한강공원 내 위치한 피크닉장입니다. 자전거 라이딩 중 한강 경치를 감상하며 휴식하거나 간식을 먹기 좋은 쉼터입니다.', '{rest_area,park,viewpoint,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.898299, 37.553546), 4326), false, '{"source": "KOMOOT", "source_ids": ["59", "329", "72", "165", "94", "484", "273", "152", "44", "159"], "category_raw": "facilities", "tour_count": 15, "nearby_landmarks": ["망원한강공원", "성산나들목", "서울함공원"], "confidence": "high", "address": "대한민국 서울특별시 마포구 망원동 302-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('홍제천 한강 합수부', '홍제천과 한강 자전거길이 만나는 합수부(성산대교 북단)입니다. 한강에서 홍제천 코스로 진입하는 주요 기점이자 라이더들의 만남의 장소입니다.', '{river,checkpoint,bridge,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.894605, 37.559797), 4326), false, '{"source": "KOMOOT", "source_ids": ["72", "64", "540", "106", "118", "165", "876", "435", "479", "330"], "category_raw": "190", "tour_count": 15, "nearby_landmarks": ["성산대교", "홍제천 합수부", "난지한강공원", "평화의공원"], "confidence": "high", "address": "대한민국 서울특별시 마포구 상암동 1563-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('세월교', '중랑천을 가로질러 노원구와 도봉구 자전거길을 잇는 다리입니다. 우천 시 물에 잠길 수 있는 잠수교 형태이므로 비 온 뒤에는 노면 미끄러움과 통제에 주의해야 합니다.', '{bridge,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.049326, 37.673825), 4326), false, '{"source": "KOMOOT", "source_ids": ["489", "555", "338", "1257", "208", "178", "183", "260", "355", "625"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/10/102rmo1kd3jll9n4gjdopcmq43e1dmpvz-uhi14146939/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1d/1dqdpuet8uea425ydgxjdyqmc3e1doa77-uhi14147233/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/3v/3vt2i20hf2ze7y0oel8jmids3e1dog3v-uhi14147259/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 14, "nearby_landmarks": ["중랑천", "상계주공16단지", "상계교"], "confidence": "high", "address": "대한민국 서울특별시 노원구 상계동 1084-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('수영강변', '부산을 대표하는 쾌적한 수영강변 자전거길입니다. 온천천과 광안리를 잇는 핵심 코스로, 도심과 강변의 아름다운 풍경을 감상하며 평탄하게 라이딩하기 좋습니다.', '{river,park,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.120926, 35.173011), 4326), false, '{"source": "KOMOOT", "source_ids": ["173", "144", "491", "475", "813", "125", "70", "718", "34", "786"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/10/10b9hei43dgln1i2undfwsukey3uasb16j-uhi37265108/0?width=1920&crop=false"], "category_raw": "river", "tour_count": 14, "nearby_landmarks": ["온천천", "광안리해수욕장", "APEC나루공원", "수영교"], "confidence": "high", "address": "대한민국 부산광역시 수영구 망미동 1066-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('중랑천 자전거길 입구 (군자교 서쪽)', '군자교 서단에서 중랑천 자전거길로 진입하는 입구입니다. 한강이나 의정부 방향으로 이어지는 쾌적한 수변 라이딩을 시작하기 좋습니다.', '{river,bridge,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.071824, 37.560559), 4326), false, '{"source": "KOMOOT", "source_ids": ["21", "358", "33", "239", "300", "442", "1037", "178", "108", "409"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1q/1q82sggx1xycz1mi99gs19fkaa3fxg3zhl-uhi17242379/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 14, "nearby_landmarks": ["군자교", "중랑천", "장안벚꽃안길"], "confidence": "high", "address": "대한민국 서울특별시 동대문구 장안동 204-13"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('탄천 합수부', '한강과 탄천 자전거길이 교차하는 교통의 요지입니다. 분당, 하남, 여의도 등 다양한 코스로 향하는 라이더들의 대표적인 만남의 광장 겸 휴식처입니다.', '{river,rest_area,checkpoint,viewpoint,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.065751, 37.51869), 4326), false, '{"source": "KOMOOT", "source_ids": ["174", "204", "341", "51", "87", "71", "65", "128", "28", "205"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1p/1pxdmhreird71tjp2gybs61ju32undxcj-uhi7391145/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/gy/gyboaoy8jnz51ibf63ahchod832une0bu-uhi7391150/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/7q/7qef65we9bsu12d3hdvlvtn2j3ejo2re9-uhi15005302/0?width=1920&crop=false"], "tips": [{"text": "Popular cycling meeting spot for rides going east along the Han River or  Namhansanseong and other popular routes for destinations going south, such as Bundang, Seongnam and Anyang. From here you can see the Olympic stadium across the river tributary. There are also, as is common at such spots here, some free to use exercise equipment, sports courts and during summer several food & drink trucks. Local tip: Avoid the chicken skewers.", "author": "Jon"}], "category_raw": "cycle_way", "tour_count": 14, "nearby_landmarks": ["잠실종합운동장", "청담대교", "잠실한강공원"], "confidence": "high", "address": "대한민국 서울특별시 강남구 삼성동 185-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오산', '오산천 자전거길이 가로지르는 오산시 도심 구역으로, 동탄과 평택을 잇는 경기 남부 라이딩 코스의 주요 거점입니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.062276, 37.147818), 4326), false, '{"source": "KOMOOT", "source_ids": ["117", "112", "267", "202", "74", "153", "25", "156", "506", "152"], "image_urls": ["https://photos.komoot.de/wiki/commons/c/c8/Korail_Osan_Stn_20090621.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b1/오산역_환승센터_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/49/Osan_station_sign.jpg?width=1920&crop=false"], "category_raw": "settlement", "tour_count": 13, "nearby_landmarks": ["오산천", "맑음터공원", "오산역"], "confidence": "high", "address": "대한민국 경기도 오산시 가수동 315-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('용담터널', '남한강 자전거길의 옛 중앙선 철길을 개조한 터널입니다. ''아트터널''이라는 명칭에 비해 예술 작품은 부족하지만, 시원하고 쾌적해 라이딩하기 좋습니다.', '{tunnel,historic}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.336612, 37.542112), 4326), false, '{"source": "KOMOOT", "source_ids": ["1481", "771", "206", "25", "417", "339", "1820", "1026", "1449", "49"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/10/10qreibokt3eb15pyaywdgpxy24jia60ly-uhi59003825/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1j/1j63qz9bdb1ra177xu39c9ja954jia60oi-uhi59003826/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/xv/xv2f0vxtolpuetlxm7meqzux5czz8j4d-uhi86049600/0?width=1920&crop=false"], "tips": [{"text": "Lacks art but is fun to ride down.", "author": ""}, {"text": "Lacks art but is fun to ride down.", "author": "Claire Tayler"}], "category_raw": "cycle_way", "tour_count": 13, "nearby_landmarks": ["남한강 자전거길", "양수역", "부용터널", "두물머리"], "confidence": "high", "address": "대한민국 경기도 양평군 양서면 용담리 산25-16"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('잠수교 북단', '한강 남북 자전거길을 잇는 핵심 교량으로, 강물과 가장 가까이서 라이딩할 수 있는 서울의 대표적인 자전거 명소입니다.', '{bridge,river,landmark,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.994486, 37.519013), 4326), false, '{"source": "KOMOOT", "source_ids": ["59", "204", "124", "114", "94", "73", "211", "186", "53", "148"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/uk/uktiwpp3pwm3fsvhikec0xsx3dvz98uf-uhi13807747/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1l/1l7rrf2xpprthacw1kltpq28c4lr3sexf-uhi61111842/0?width=1920&crop=false"], "tips": [{"text": "The Banpo Bridge (Korean: 반포대교; Hanja: 盤浦大橋) is a major bridge in downtown Seoul over the Han River, South Korea, connecting the Seocho and Yongsan districts. The bridge is on top of Jamsu Bridge, forming the upper half of a double-deck bridge; it is the first double deck bridge built in South Korea. During periods of high rainfall, the Jamsu Bridge is designed to submerge as the water level of the river rises, as the lower deck lies close to the waterline. The bridge was built as a girder bridge and was completed in 1982.", "author": "AsuRa"}, {"text": "The Banpo Bridge (Korean: 반포대교; Hanja: 盤浦大橋) is a major bridge in downtown Seoul over the Han River, South Korea, connecting the Seocho and Yongsan districts. The bridge is on top of Jamsu Bridge, forming the upper half of a double-deck bridge; it is the first double deck bridge built in South Korea. During periods of high rainfall, the Jamsu Bridge is designed to submerge as the water level of the river rises, as the lower deck lies close to the waterline. The bridge was built as a girder bridge and was completed in 1982.", "author": ""}], "category_raw": "bridge", "tour_count": 13, "nearby_landmarks": ["반포대교", "이촌한강공원", "한강자전거길"], "confidence": "high", "address": "대한민국 서울특별시 용산구 서빙고동 287-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('하오고개', '의왕과 성남을 잇는 수도권 남부의 대표적인 자전거 업힐 명소입니다. 차량 통행이 적고 노면이 훌륭해 라이더들에게 인기가 많습니다.', '{mountain,nature,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.038299, 37.393882), 4326), false, '{"source": "KOMOOT", "source_ids": ["337", "206", "780", "439", "576", "211", "130", "376", "273", "774"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1o/1o66msbonpmjtqyogobdywevc50vpips7-uhi74168475/0?width=1920&crop=false"], "tips": [{"text": "150m ascend, winding road, cyclists paradise, great tarmac, calm road, awesome downhill! fully recommended 👍", "author": "667 The Neighbour of the Beast"}], "category_raw": "climb", "tour_count": 13, "nearby_landmarks": ["청계산", "하오고개 육교", "도깨비도로"], "confidence": "high", "address": "대한민국 경기도 의왕시 청계동 산8-81"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('뚝섬 한강공원 수변무대', '과거 뚝섬 한강공원의 대표적인 라이딩 포토존이자 만남의 장소였습니다. 2023년 서울시 브랜드 변경으로 인해 현재 조형물은 철거된 상태입니다.', '{landmark,historic,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.069042, 37.528478), 4326), false, '{"source": "KOMOOT", "source_ids": ["291", "202", "348", "145", "207", "86", "345", "113", "93", "256"], "category_raw": "man_made_monument", "tour_count": 12, "nearby_landmarks": ["뚝섬 한강공원 수변무대", "청담대교", "뚝섬 자벌레(서울생각마루)", "뚝섬선착장"], "confidence": "high", "address": "대한민국 서울특별시 광진구 자양동 126-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('덕풍천', '하남 시내와 한강 자전거길을 연결하는 하천 자전거길입니다. 한강 합수부나 미사리 방면으로 진입하기 좋으며, 산책로와 분리되어 쾌적한 라이딩이 가능합니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.219778, 37.551048), 4326), false, '{"source": "KOMOOT", "source_ids": ["369", "85", "348", "1856", "516", "135", "2108", "196", "1723", "47"], "category_raw": "190", "tour_count": 12, "nearby_landmarks": ["하남유니온타워", "미사리경정공원", "당정뜰", "한강 자전거길"], "confidence": "high", "address": "대한민국 경기도 하남시 미사동 3-31"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('성수대교 남단 엘리베이터', '성수대교 남단 한강 자전거길에서 다리 위로 올라갈 수 있는 엘리베이터와 보행로입니다. 강남에서 강북(서울숲) 방향으로 한강을 건널 때 유용한 진입 거점입니다.', '{bridge,river,park,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.034174, 37.533149), 4326), false, '{"source": "KOMOOT", "source_ids": ["191", "149", "101", "300", "65", "238", "116", "175", "115", "321"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/fn/fn9wv52emg8bgmvhru0g9h204j9g36wq-uhi58754438/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/fk/fkd9bjuctcfjw1o0z7n8wqfk4j9g375w-uhi58754439/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 12, "nearby_landmarks": ["성수대교", "잠원한강공원", "서울숲"], "confidence": "high", "address": "대한민국 서울특별시 강남구 압구정동 501"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오산천', '동탄에서 평택호까지 이어지는 생태하천 자전거길입니다. 맑음터공원 등 쉼터가 잘 조성되어 있어 사계절 내내 쾌적한 자연 풍경 속에서 라이딩을 즐기기 좋습니다.', '{river,nature,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.059488, 37.135831), 4326), false, '{"source": "KOMOOT", "source_ids": ["332", "166", "131", "167", "216", "39", "243", "520", "170", "98"], "category_raw": "190", "tour_count": 12, "nearby_landmarks": ["맑음터공원", "오산에코리움", "오산천 자전거대여소", "오산반려동물테마파크"], "confidence": "high", "address": "대한민국 경기도 오산시 누읍동 137-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('잠실철교 일몰 전망대', '잠실철교 자전거길에 위치한 일몰 조망 포인트입니다. 한강의 붉은 노을과 나란히 달리는 전철을 한 앵글에 담을 수 있어 라이더들에게 인기 있는 포토존입니다.', '{viewpoint,bridge}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.09799, 37.529899), 4326), false, '{"source": "KOMOOT", "source_ids": ["204", "1055", "38", "165", "282", "207", "89", "394", "142", "129"], "category_raw": "viewpoint", "tour_count": 12, "nearby_landmarks": ["잠실철교", "올림픽대교", "강변역", "롯데월드타워"], "confidence": "high", "address": "G3HX+X5 대한민국 서울특별시"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대청호 로하스 자전거길', '신탄진에서 대청댐으로 이어지는 금강 변의 탁 트인 자전거길입니다. 로하스 산호빛공원 등 수변 풍경이 아름다워 쾌적하게 라이딩하기 좋습니다.', '{river,park,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.417103, 36.45396), 4326), false, '{"source": "KOMOOT", "source_ids": ["173", "662", "316", "146", "1142", "366", "282", "57", "355", "1095"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1w/1w7xevmsw057w158gkiuwbnlio4rubntze-uhi67095037/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 11, "nearby_landmarks": ["금강로하스 산호빛공원", "금강", "대청댐", "신탄진역"], "confidence": "high", "address": "대한민국 대전광역시 대덕구 석봉동 680"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('뚝섬한강공원', '한강 자전거길의 주요 거점으로 편의점, 화장실 등 편의시설이 풍부해 라이딩 중 휴식 및 만남의 장소로 최적인 수변공원입니다.', '{park,rest_area,river,convenience_store,restroom,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.068803, 37.528858), 4326), false, '{"source": "KOMOOT", "source_ids": ["83", "90", "204", "288", "211", "250", "110", "116", "142", "253"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1h/1hkxqxch4ef4a1v812ov5yfji24qjbtjsm-uhi66072455/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/iq/iqktvf1sed1y6xl7rorqeqmo4qjbtjwl-uhi66072456/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1r/1r5pa6kxfr2xl1c1pjo4lqlzpv4qjbtju8-uhi66072458/0?width=1920&crop=false"], "tips": [{"text": "Park am Hangang River mit zahlreichen Veranstaltungen an den Wochenenden", "author": "Puffin"}], "category_raw": "facilities", "tour_count": 11, "nearby_landmarks": ["청담대교", "자양역(구 뚝섬유원지역)", "서울생각마루(자벌레)"], "confidence": "high", "address": "대한민국 서울특별시 광진구 자양동 559-5 뚝섬한강공원 수변무대"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('북악 팔각정', '가파른 업힐 끝에 만나는 서울 자전거 라이더들의 성지입니다. 탁 트인 전망과 함께 편의점, 카페에서 휴식을 취하기 좋습니다.', '{viewpoint,rest_area,cafe,convenience_store,restroom,mountain,landmark,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.981338, 37.601808), 4326), false, '{"source": "KOMOOT", "source_ids": ["742", "280", "216", "1074", "877", "413", "566", "345", "196", "233"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1j/1jvo9nht624nv1r1ox2zu31cp83sz6qk90-uhi35387948/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/6g/6gh3gswtugiq17sw125eg6enj3mor7g9q-uhi27619692/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/4y/4y91j30m4n0k1vrbb4f2ty9at524z0cmu-uhi75646755/0?width=1920&crop=false"], "tips": [{"text": "Good place for a coffee or refreshment after the steep hillclimb. Lots of cyclists are there, always something to talk :)", "author": "667 The Neighbour of the Beast"}], "category_raw": "viewpoint", "tour_count": 11, "nearby_landmarks": ["북악산", "창의문", "백사실계곡"], "confidence": "high", "address": "대한민국 서울특별시 성북구 성북동 산25-123"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('피반령', '충청권 자전거 라이더들의 성지로 불리는 해발 360m의 고개입니다. 약 5km에 걸쳐 5~7%의 완만한 경사가 이어지며, 정상의 정자와 주차장에서 휴식하기 좋습니다.', '{mountain,nature,rest_area,parking,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.572218, 36.535838), 4326), false, '{"source": "KOMOOT", "source_ids": ["297", "744", "125", "249", "982", "885", "266", "203", "564", "302"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k2/80/808evrvfl5a81dr4h58ghho272pxmhcin-uhi3929228/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k2/lv/lvuclbb882985qab7mpyhkux2rjniv44-uhi4367063/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k2/ka/kattihpt3z531e8q1oshjj0fz2rjnktrn-uhi4367070/0?width=1920&crop=false"], "tips": [{"text": "청주에서 제일 유명하고 많은사람들이 라이딩하는 업힐.\n5~7%대의 업힐이 5km정도", "author": "SangGyu, Lim _ Korea"}], "category_raw": "mountain_pass", "tour_count": 11, "nearby_landmarks": ["대청호", "피반령터널"], "confidence": "high", "address": "대한민국 충청북도 보은군 회인면 오동리 산 50-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('산곡천', '하남시를 가로질러 한강으로 합류하는 하천입니다. 하천을 따라 자전거길이 잘 조성되어 있으며, 한강 자전거길 및 팔당대교 방면으로 연계하기 좋은 라이딩 코스입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.231195, 37.542675), 4326), false, '{"source": "KOMOOT", "source_ids": ["359", "267", "124", "406", "295", "628", "1025", "232", "162", "640"], "category_raw": "190", "tour_count": 11, "nearby_landmarks": ["팔당대교", "당정섬", "한강 자전거길", "하남검단산역"], "confidence": "high", "address": "대한민국 경기도 하남시 창우동 472-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('우이천 합류지', '우이천과 중랑천 자전거길이 만나는 합류 지점입니다. 북한산이나 한강 방면으로 코스를 전환하기 좋은 라이딩 주요 분기점입니다.', '{river,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.070837, 37.61301), 4326), false, '{"source": "KOMOOT", "source_ids": ["151", "154", "439", "79", "1118", "97", "171", "40", "152", "533"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/6x/6xnuczfepcb4g6khbntmi71z3hhhgx8x-uhi20454368/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1i/1iq5q7sl4h97b2r1ovgjoxam53hhhh0xy-uhi20454374/0?width=1920&crop=false"], "tips": [{"text": "Where Ui-cheon flows into Joongrang-cheon", "author": ""}, {"text": "Where Ui-cheon flows into Joongrang-cheon", "author": "AsuRa"}], "category_raw": "river", "tour_count": 11, "nearby_landmarks": ["중랑천 자전거길", "우이천 자전거길", "석계역", "성북구 자전거교통안전체험장"], "confidence": "high", "address": "대한민국 서울특별시 성북구 석관동 375-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('이응다리', '상층부는 보행로, 하층부는 자전거 전용도로로 분리된 국내 최장 원형 교량입니다. 금강과 세종시의 아름다운 풍경을 감상하며 안전하게 라이딩하기 좋습니다.', '{bridge,landmark,viewpoint,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.284115, 36.48577), 4326), false, '{"source": "KOMOOT", "source_ids": ["604", "592", "1432", "911", "95", "159", "643", "585", "49", "1165"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1i/1ie6837b1zmme1m1t4j0x3oqtf5lkjlw5n-uhi96630816/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1g/1gpqplhbkt12c1hzrf38c5c1io5lkjlwp7-uhi96630818/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1b/1b3z6dfmpykts17pthpmgr1inb5lkjlykm-uhi96630820/0?width=1920&crop=false"], "tips": [{"text": "The Geumgang Pedestrian Bridge is the longest footbridge in Korea. With a total length of 1,446 meters, it commemorates the year in which the Korean writing system, Hangeul, was introduced.\n\nThe bridge and its elevated lookout offer a fantastic view of the Geumgang River, as well as the Sejong City skyline stretching along both sides of the water.\n\nIt’s a popular spot for nighttime scenery, especially from sunset into the late evening, and it closes at 11:00 PM.", "author": "Johannes"}], "category_raw": "bridge", "tour_count": 11, "nearby_landmarks": ["세종시청", "세종중앙공원", "금강수변공원", "국립세종수목원"], "confidence": "high", "address": "대한민국 세종특별자치시 연기면 세종리 753-475"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금은모래캠핑장', '남한강 자전거길 옆에 위치한 대규모 캠핑장입니다. 화장실, 매점 등 편의시설이 잘 갖춰져 있어 자전거 여행 중 휴식이나 1박을 하기에 매우 좋습니다.', '{rest_area,park,restroom,convenience_store,water_fountain}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.665124, 37.294214), 4326), false, '{"source": "KOMOOT", "source_ids": ["56", "563", "329", "1158", "88", "187"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1n/1nfziyi6obx021406wikk213g34pd5i9f6-uhi64779116/0?width=1920&crop=false"], "tips": [{"text": "Big camping area", "author": "Alex Kasch"}], "category_raw": "facilities", "tour_count": 11, "nearby_landmarks": ["남한강", "금은모래강변공원", "강천보"], "confidence": "high", "address": "대한민국 경기도 여주시 연양동 304-19"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('행주대교 북단', '한강 자전거길과 평화누리길(일산/파주 방향)이 연결되는 기점이자 한강을 도강하는 주요 교량입니다. 인근에 행주산성 먹거리촌이 있어 라이더들의 필수 경유지로 꼽힙니다.', '{bridge,river,checkpoint,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.814919, 37.603436), 4326), false, '{"source": "KOMOOT", "source_ids": ["1212", "1055", "358", "1162", "419", "232", "242", "281", "57", "363"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/o3/o3lipr8mz9si1579syaroonlx3dvzewzr-uhi13807892/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/12/12k4sfu892fbeho6ns3zeickg3gr828xv-uhi18943481/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/9b/9b1esgumr3rm9j4fbbu66fzx3gr83p8h-uhi18943497/0?width=1920&crop=false"], "tips": [{"text": "The Haengju Bridge crosses the Han River in South Korea and connects the city of Goyang and the district of Gangseo-gu. The bridge was first completed in 1978, but the bridge was very narrow and could not handle the increased traffic as the neighboring cities of Ilsan and Bucheon experienced housing booms.\n\nConstruction of the second bridge (called the New Haengju Bridge) adjacent to the original began in October 1987. During construction in 1992, the new bridge collapsed. Repairs took three more years, and the bridge opened in 1995.\n\nConstruction on a third bridge began in the space between the first and the second in 1996 and finished in December 2000. With the completion of the third bridge, the first bridge was closed. Currently, the second bridge handles southward traffic and the third bridge handles northward traffic.", "author": "AsuRa"}, {"text": "The Haengju Bridge crosses the Han River in South Korea and connects the city of Goyang and the district of Gangseo-gu. The bridge was first completed in 1978, but the bridge was very narrow and could not handle the increased traffic as the neighboring cities of Ilsan and Bucheon experienced housing booms.\n\nConstruction of the second bridge (called the New Haengju Bridge) adjacent to the original began in October 1987. During construction in 1992, the new bridge collapsed. Repairs took three more years, and the bridge opened in 1995.\n\nConstruction on a third bridge began in the space between the first and the second in 1996 and finished in December 2000. With the completion of the third bridge, the first bridge was closed. Currently, the second bridge handles southward traffic and the third bridge handles northward traffic.", "author": ""}], "category_raw": "bridge", "tour_count": 11, "nearby_landmarks": ["행주산성", "행주산성 국수거리", "평화누리 자전거길"], "confidence": "high", "address": "대한민국 경기도 고양시 덕양구 행주외동 225-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('아라한강갑문 인증센터', '국토종주 아라자전거길과 한강자전거길이 만나는 아라한강갑문 인증센터입니다. 라이더들의 필수 스탬프 인증 지점이며 화장실을 이용할 수 있습니다.', '{checkpoint,landmark,rest_area,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.800271, 37.598858), 4326), false, '{"source": "KOMOOT", "source_ids": ["117", "212", "259", "161", "192", "200", "284", "237", "155"], "category_raw": "other_man_made", "tour_count": 10, "nearby_landmarks": ["아라한강갑문", "행주대교", "강서한강공원"], "confidence": "high", "address": "대한민국 서울특별시 강서구 개화동 31-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('강정고령보', '낙동강 종주 자전거길의 필수 거점인 강정고령보(우륵교)입니다. 자전거 통행이 원활하며, 인근에 디아크와 인증센터가 있어 라이더들이 쉬어가기 좋은 랜드마크입니다.', '{bridge,river,landmark,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.468324, 35.838161), 4326), false, '{"source": "KOMOOT", "source_ids": ["397", "436", "55", "1216", "349", "388", "377", "53"], "category_raw": "bridge", "tour_count": 10, "nearby_landmarks": ["디아크(The ARC)", "강정고령보 인증센터", "낙동강 종주 자전거길"], "confidence": "high", "address": "RFQ9+78 대한민국 대구광역시"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('온천천 자전거길 동래역 거점', '온천천 자전거길로 바로 진입할 수 있는 주요 거점입니다. 자전거 주차장과 대여소가 있으며, 수영강 방면 라이딩의 출발점이나 휴식처로 매우 유용합니다.', '{transit,river,park,parking,rest_area,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.078838, 35.205706), 4326), false, '{"source": "KOMOOT", "source_ids": ["881", "225", "11", "727", "118", "1366", "49"], "category_raw": "facilities", "tour_count": 10, "nearby_landmarks": ["온천천시민공원", "온천천 자전거길"], "confidence": "high", "address": "대한민국 부산광역시 동래역4번출구"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('이화령', '국토종주 새재 자전거길의 대표적인 업힐 코스인 백두대간 이화령입니다. 정상에 인증센터와 휴게소, 화장실이 갖춰져 있어 라이딩 중 반드시 들르는 주요 거점입니다.', '{mountain,checkpoint,rest_area,restroom,parking,viewpoint,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.0319, 36.751875), 4326), false, '{"source": "KOMOOT", "source_ids": ["1287", "1943", "391", "625", "449"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/6c/6ccdb7npn2hcl29ap80law944qis2x95-uhi66062502/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/12/123zvd1dpnhmr6w7qi0qktrf54qis2xeq-uhi66062505/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/rd/rdb4awx8zlk0dbjezajemie82znc7fnc-uhi6016613/0?width=1920&crop=false"], "category_raw": "mountain_pass", "tour_count": 10, "nearby_landmarks": ["이화령휴게소", "이화령 국토종주 인증센터", "조령산"], "confidence": "high", "address": "대한민국 충청북도 괴산군 연풍면 주진리 산3-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('서재리 일몰 전망', '금호강 자전거길 서재리 구간에 위치한 일몰 명소입니다. 탁 트인 서쪽 강변을 바라보며 라이딩 중 아름다운 노을을 감상하고 쉬어가기 좋습니다.', '{viewpoint,river,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.499744, 35.882878), 4326), false, '{"source": "KOMOOT", "source_ids": ["428", "340", "236", "216", "751", "215", "286", "636", "820"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/yh/yhkb301k4jys1sgdkz1syps3h5h62pmni-uhi91619177/0?width=1920&crop=false"], "category_raw": "viewpoint", "tour_count": 10, "nearby_landmarks": ["금호강", "세천교", "와룡대교"], "confidence": "high", "address": "대한민국 대구광역시 달성군 다사읍 서재리 1-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('수영강 야경', '수영강변 자전거길에 위치한 야경 명소입니다. 센텀시티의 화려한 불빛이 강물에 비치는 환상적인 뷰를 감상하며 야간 라이딩을 즐기기 좋습니다.', '{river,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.126968, 35.16723), 4326), false, '{"source": "KOMOOT", "source_ids": ["653", "104", "84", "738", "77", "750", "176", "18", "80"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/19/19o21d7wd33zdfym77yrvnhlb3udued9e-uhi37379403/0?width=1920&crop=false"], "category_raw": "river", "tour_count": 10, "nearby_landmarks": ["APEC나루공원", "센텀시티", "영화의전당", "수영교"], "confidence": "high", "address": "대한민국 부산광역시 해운대구 우동 1291-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('칠곡보 인증센터', '낙동강 종주 자전거길의 칠곡보 인증센터입니다. 인접한 건물에 GS25 편의점이 있어 라이딩 중 보급과 휴식을 취하기 매우 좋습니다.', '{checkpoint,convenience_store,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.400838, 36.015265), 4326), false, '{"source": "KOMOOT", "source_ids": ["686", "752", "72", "172", "573", "664", "65", "426", "966", "845"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/gq/gqlf6e58mrlsrlo889hpozum5dr45tlt-uhi87069787/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1v/1vhr0tab5d8j5ns6x2cbl578s5du4n9f9-uhi87159173/0?width=1920&crop=false"], "tips": [{"text": "Has a GS 25 convenience store in the adjacent Building", "author": "Fitz_carraldo"}, {"text": "Has a GS 25 convenience store in the adjacent Building", "author": ""}], "category_raw": "facilities", "tour_count": 10, "nearby_landmarks": ["칠곡보", "낙동강", "칠곡보 전망대"], "confidence": "high", "address": "대한민국 경상북도 칠곡군 석적읍 중지리 559-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남한강 자전거길 (국수역 구간)', '남한강을 따라 시원하게 달릴 수 있는 남한강 자전거길 구간입니다. 평탄하고 경치가 좋아 많은 라이더들이 찾는 필수 코스입니다.', '{river,nature,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.397435, 37.515254), 4326), false, '{"source": "KOMOOT", "source_ids": ["702", "1376", "336", "234", "1302", "992", "252", "666", "132", "1344"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/19/19oqo2d46hda3cqokay6o99h14ov08vzy-uhi64252105/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1i/1iue53ct72kwk1394jcn8zulwu4qyoz7v6-uhi66469683/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1p/1p25btisdeokukkewm3xmzog74zhs3pe3-uhi72525322/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 10, "nearby_landmarks": ["국수역", "남한강", "두바퀴 휴게쉼터"], "confidence": "high", "address": "대한민국 경기도 양평군 양서면 국수리 293-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('중랑천 창동교 자전거길 진입로', '노원역 인근 창동교 동쪽에서 중랑천 자전거길로 진입하는 나들목입니다. 여름철에는 생수를 제공하는 무더위 쉼터가 운영되어 라이딩 중 휴식하기 좋습니다.', '{river,bridge,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.054624, 37.652782), 4326), false, '{"source": "KOMOOT", "source_ids": ["586", "307", "40", "387", "240", "53", "1114", "649", "690", "229"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/t1/t1uvqe5qhrh91tovp6tsee23i3fxghaz9-uhi17242766/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 10, "nearby_landmarks": ["창동교", "노원역", "노원구청"], "confidence": "high", "address": "대한민국 서울특별시 노원구 상계동 790-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금호꽃섬(하중도)', '금호강 자전거길에 위치한 생태공원(현 금호꽃섬)으로 사계절 꽃이 만발하는 라이딩 명소입니다. 최근 도보교가 개통되어 다리를 통해 섬으로 진입하기 좋습니다.', '{park,nature,river,landmark,viewpoint,bridge}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.561881, 35.898869), 4326), false, '{"source": "KOMOOT", "source_ids": ["676", "572", "193", "88", "518", "659", "1205", "196", "185", "1183"], "tips": [{"text": "이제 다리를 걷는갈수 있어요", "author": "James"}], "category_raw": "settlement", "tour_count": 10, "nearby_landmarks": ["금호강 자전거길", "노곡교", "팔달교", "하중도 보도교"], "confidence": "high", "address": "대한민국 대구광역시 북구 노곡동 789"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('잠실한강공원 편의점', '잠실 한강공원 내 위치한 편의점입니다. 자전거 라이딩 중 시원한 음료와 간식을 보급하거나, 한강 라면을 먹으며 휴식하기 좋은 필수 정차 지점입니다.', '{convenience_store,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.082458, 37.517894), 4326), false, '{"source": "KOMOOT", "source_ids": ["174", "104", "202", "124", "99", "240", "152", "148", "62"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/15/150hhkjktgqq21rzdoi55quaj54nm2tm6-uhi78892755/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 10, "nearby_landmarks": ["잠실한강공원", "잠실대교", "잠실선착장"], "confidence": "high", "address": "대한민국 서울특별시 송파구 잠실동 1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('능내역 인증센터', '남한강 자전거길의 주요 인증센터입니다. 폐역이 된 능내역의 레트로한 분위기를 즐기며 주변 식당과 카페에서 쉬어가기 좋은 필수 정차 코스입니다.', '{checkpoint,historic,rest_area,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.294998, 37.522423), 4326), false, '{"source": "KOMOOT", "source_ids": ["259", "930", "225", "125", "1873", "1333", "246", "509", "1950", "1213"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1h/1htvlt5p8erx11md0epnyhz6m44xodyur-uhi48547088/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/go/goy37bbsd4if1685z6m0r2yvu46uk11gt-uhi50253393/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/5e/5ebzbvi4cm8i2kx2qofevscp4hnzwv7a-uhi57896002/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 10, "nearby_landmarks": ["능내역(폐역)", "다산생태공원", "팔당댐"], "confidence": "high", "address": "대한민국 경기도 남양주시 조안면 능내리 131-15"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('해거름마을공원 인증센터', '제주 환상 자전거길의 주요 인증센터로 탁 트인 바다와 풍차를 조망할 수 있습니다. 공원 내 화장실과 전망대 카페가 있어 라이딩 중 휴식하기 매우 좋습니다.', '{checkpoint,park,rest_area,viewpoint,restroom,cafe}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.206476, 33.369707), 4326), false, '{"source": "KOMOOT", "source_ids": ["328", "599", "244", "1054", "275", "44", "281", "880", "251", "685"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/mv/mv2pfeo3thpilau62u7zvyu92ywihfkd-uhi5726853/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/m8/m8cnwv0n2qow74drptk0iw0y2ywihoo1-uhi5726858/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1l/1lu1ifvn5oyrw1858ldn9dxif72ywihk4m-uhi5726854/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 10, "nearby_landmarks": ["해거름전망대 카페", "신창풍차해안도로", "판포포구"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 한경면 판포리 1608-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('CVS 편의점(폐업)', '낙동강 자전거길 칠곡보 인근에 위치했던 편의점이나, 현재는 폐업하여 부지가 경매 진행 중입니다. 라이딩 보급 계획 시 반드시 제외하세요.', '{convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.398747, 35.952949), 4326), false, '{"source": "KOMOOT", "source_ids": ["144", "347", "673", "669", "262", "77", "690", "924"], "tips": [{"text": "no longer exists", "author": "Max Roving"}], "category_raw": "other_man_made", "tour_count": 9, "nearby_landmarks": ["낙동강 자전거길", "칠곡보", "금산체육공원"], "confidence": "high", "address": "대한민국 경상북도 칠곡군 왜관읍 금산리 851-68"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('굴포천 팜', '굴포천 자전거길 상야동 구간에 위치한 농장 주변 포인트로, 탁 트인 시야와 함께 시원한 강바람을 맞으며 잠시 쉬어가기 좋은 곳입니다.', '{rest_area,river,viewpoint,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.763699, 37.572311), 4326), false, '{"source": "KOMOOT", "source_ids": ["117", "230", "464", "99", "1724", "54", "106", "1012", "645"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1d/1dmh6z8qol8p6qy3fnfjj53vj48duf8dw-uhi51764509/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/gk/gk4tqh5l7w1t2ugk2wfjyp0q48dufwjq-uhi51764526/0?width=1920&crop=false"], "tips": [{"text": "강바람 시원한곳", "author": "CYG"}, {"text": "강바람 시원한곳", "author": ""}], "category_raw": "other_man_made", "tour_count": 9, "nearby_landmarks": ["굴포천 자전거길", "경인아라뱃길"], "confidence": "low", "address": "대한민국 인천광역시 계양구 상야동 397-13"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남한강–섬강 자전거길 교차점', '남한강과 섬강이 만나는 합수부이자 두 자전거길이 교차하는 지점입니다. 과거 조창이 있던 흥원창 터로, 일몰 풍경이 아름다워 라이더들이 쉬어가기 좋습니다.', '{river,viewpoint,historic,rest_area,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.750732, 37.241579), 4326), false, '{"source": "KOMOOT", "source_ids": ["517", "122", "277", "973", "178", "62", "392", "405", "1080"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1h/1hf8pq1pkxjghc73p7450em2137ej53lr-uhi9478590/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1w/1wzwssznof4rh18lb6i5b180c237ej56nt-uhi9478592/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 9, "nearby_landmarks": ["흥원창", "조운선 전망대", "남한강대교"], "confidence": "high", "address": "대한민국 강원특별자치도 원주시 부론면 흥호리 산47-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동탄역', 'SRT와 GTX-A 탑승이 가능한 동탄역입니다. 오산천 자전거길과 가까워 대중교통 연계(점프) 및 만남의 장소로 유용합니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.096014, 37.200146), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/1/10/동탄역_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/35/동탄역_003.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/65/20240327_gtx-a_동탄역.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b0/20240327_gtx_동탄역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/68/Hwaseong_Dongtan_Post_office.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 9, "nearby_landmarks": ["오산천 자전거길", "동탄여울공원", "롯데백화점 동탄점"], "confidence": "high", "address": "대한민국 경기도 화성시 동탄역로 지하 151"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('목행교 북단', '남한강 자전거길과 탄금호 코스의 주요 기점입니다. 충주댐이나 탄금대 방향으로 이동할 때 남한강을 건너기 위해 거쳐가는 다리 북단 진입로입니다.', '{bridge,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.917837, 37.0212), 4326), false, '{"source": "KOMOOT", "source_ids": ["225", "149", "168", "75", "86", "246", "273", "148", "399"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1q/1qtribibb1p8m1dixq109opexx3ga8woxn-uhi18014581/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 9, "nearby_landmarks": ["목행교", "남한강", "충주댐", "탄금호"], "confidence": "high", "address": "대한민국 충청북도 충주시 동량면 용교리 892-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('중랑천·묵동천 합수부', '중랑천과 묵동천 자전거길이 만나는 합수부입니다. 경춘선 숲길 방면으로 진입하는 주요 분기점이며, 인근에 매점과 쉼터가 있어 라이더들이 쉬어가기 좋습니다.', '{river,checkpoint,rest_area,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.072072, 37.614758), 4326), false, '{"source": "KOMOOT", "source_ids": ["507", "114", "101", "81", "1166", "106", "218", "105", "1053"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1k/1kxkld7fme4v01t511ke1inhy437g40rlu-uhi9491099/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/15/15ocok8kvwp2ckhdgjofphi4c3d2o2qn1-uhi12596334/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1f/1f5fdf4a2i81pqrqi6dr8tj5x3gdmviss-uhi18203641/0?width=1920&crop=false"], "tips": [{"text": "Where Mukdong-cheon flows into Joongrang-cheon", "author": ""}, {"text": "Where Mukdong-cheon flows into Joongrang-cheon", "author": "AsuRa"}], "category_raw": "river", "tour_count": 9, "nearby_landmarks": ["월릉교", "경춘선 숲길", "중랑천 자전거길"], "confidence": "high", "address": "대한민국 서울특별시 중랑구 묵동 374-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('사슴 벽화 자전거길 지하도', '행주산성과 일산을 연결하는 자전거길 지하도입니다. 행주 방면 진입 시 갑작스러운 계단이 있고, 일산 방면은 공사 펜스가 있을 수 있어 라이딩 시 주의가 필요합니다.', '{tunnel}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.783245, 37.625788), 4326), false, '{"source": "KOMOOT", "source_ids": ["403", "1117", "976", "236", "186", "53", "374", "195", "681"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/2t/2tfbw41fp1c1pood28rv5v5q3h7jes2t-uhi19836539/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/17/17uy7wl03v0u31ldzbpsiralu73h7jevc0-uhi19836545/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/q0/q09tdix7rq4quoq8emxpzzh63h7jew8v-uhi19836546/0?width=1920&crop=false"], "tips": [{"text": "From the 행주 (Seoul side) take care, as the path finishes rather suddenly and there are stairs descending into the tunnel. Additionally, approaching from the 일산/고양 side, there is fencing that looks like construction and the path appears to pass under the fence as if renovation is taking place. During summer when grass and other greenery is in full growth you might completely miss the obscured tunnel entrance on the right, as I did the very first time coming this way.", "author": "Jon"}, {"text": "From the 행주 (Seoul side) take care, as the path finishes rather suddenly and there are stairs descending into the tunnel. Additionally, approaching from the 일산/고양 side, there is fencing that looks like construction and the path appears to pass under the fence as if renovation is taking place. During summer when grass and other greenery is in full growth you might completely miss the obscured tunnel entrance on the right, as I did the very first time coming this way.", "author": ""}], "category_raw": "cycle_way", "tour_count": 9, "nearby_landmarks": ["평화누리길", "자유로"], "confidence": "medium", "address": "대한민국 경기도 고양시 덕양구 신평동 26-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('센트럴시티터미널', '호남권으로 자전거 점프(시외 이동) 시 이용하는 핵심 버스 터미널입니다. 반포한강공원과 가까워 자전거길 접근성이 매우 좋습니다.', '{transit,convenience_store,restaurant,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.003847, 37.504599), 4326), false, '{"source": "KOMOOT", "source_ids": ["618", "470", "519", "30", "835", "515", "596", "1254", "243"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/z0/z04ihk1mxkqk4uy1tsc9kg763dvznfcb-uhi13808070/0?width=1920&crop=false"], "tips": [{"text": "Seoul Express Terminal (Honam Line) is also known as Central City Terminal. It operates as a major transportation hub, offering express buses connecting various cities in the southern region of Korea, as well as airport limousine buses.", "author": "AsuRa"}, {"text": "Seoul Express Terminal (Honam Line) is also known as Central City Terminal. It operates as a major transportation hub, offering express buses connecting various cities in the southern region of Korea, as well as airport limousine buses.", "author": ""}], "category_raw": "facilities", "tour_count": 9, "nearby_landmarks": ["서울고속버스터미널", "반포한강공원", "신세계백화점 강남점"], "confidence": "high", "address": "2F, 176 신반포로 서초구 서울특별시 대한민국"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('중랑천', '서울 한강부터 의정부를 거쳐 양주까지 이어지는 대표적인 자전거길 코스입니다. 평탄하고 관리가 잘 되어 있어 초보자부터 숙련자까지 모두 달리기 좋습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.048573, 37.778778), 4326), false, '{"source": "KOMOOT", "source_ids": ["425", "358", "135", "802", "608", "120", "429", "315", "283"], "category_raw": "190", "tour_count": 9, "nearby_landmarks": ["양주역", "불곡산"], "confidence": "high", "address": "대한민국 경기도 양주시 남방동 78-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('충주 탄금대 인증센터', '남한강 자전거길의 종점이자 새재 자전거길이 시작되는 국토종주 필수 인증센터입니다. 인근에 탄금대와 공원이 있어 화장실 이용 및 휴식을 취하기 좋습니다.', '{checkpoint,rest_area,park,river,historic}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.903502, 36.989336), 4326), false, '{"source": "KOMOOT", "source_ids": ["1570", "90", "214", "459", "819", "75", "109", "290", "371"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1s/1s529rennqk1wxmeyzxzce5c37ejpcyv-uhi9478704/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/7y/7yglc0r31a7r18zd9jojrq0e4zal9o0o-uhi72323878/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 9, "nearby_landmarks": ["탄금대", "충주세계무술공원", "남한강"], "confidence": "high", "address": "대한민국 충청북도 충주시 칠금동 산1-30"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('칠암항 조각상', '동해안 자전거길 기장 해안도로에 위치한 조형물입니다. 인근 신평소공원 배 조형물과 칠암항의 이색 등대들을 배경으로 라이딩 인증샷을 남기기 좋습니다.', '{landmark,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.259895, 35.302291), 4326), false, '{"source": "KOMOOT", "source_ids": ["254", "630", "146", "581", "647", "274", "380", "189", "745"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/zr/zrjvu43fi0511fos7wtrm9q1g3u7nd4b5-uhi37179898/0?width=1920&crop=false"], "category_raw": "man_made_monument", "tour_count": 9, "nearby_landmarks": ["신평소공원", "칠암항 야구등대", "문중방파제"], "confidence": "medium", "address": "대한민국 부산광역시 기장군 일광면 문중리 17 일광면 문중리 17번지 기장군 부산광역시 KR 46039"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('한강 자전거길', '압구정동 인근 한강 남단 자전거길입니다. 성수대교 주변으로 노면이 평탄하고 시야가 탁 트여 있어 쾌적한 라이딩이 가능합니다.', '{river,park,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.03897, 37.53214), 4326), false, '{"source": "KOMOOT", "source_ids": ["359", "510", "1429", "153", "651", "278", "175", "323", "734"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/kj/kjkfawxfp2k1ns8ogftokavp5bw0esm7-uhi84791114/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/rt/rtyq6pm2ch9610xx3mqf2bj9b5czz8wg8-uhi86049612/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/b9/b94phlt4gjqafxpq1nv9mmf85czz8yob-uhi86049613/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 9, "nearby_landmarks": ["성수대교", "압구정나들목", "한강시민공원"], "confidence": "high", "address": "대한민국 서울특별시 강남구 압구정동 384-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('반포나들목', '반포한강공원으로 연결되는 핵심 진출입로(나들목)입니다. 유동인구가 많아 병목현상이 심하므로 진출입 시 반드시 감속하고 보행자 및 추돌 사고에 주의해야 합니다.', '{tunnel,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.001679, 37.512024), 4326), false, '{"source": "KOMOOT", "source_ids": ["107", "38", "167", "71", "160", "268", "19", "110", "251"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1c/1cbtk3j75gdx31oxbz8sljp5kb3g4kkzdm-uhi17676080/0?width=1920&crop=false"], "tips": [{"text": "반포한강공원 혼잡 시 감속, 추돌 주의", "author": "정조대왕13"}], "category_raw": "cycle_way", "tour_count": 9, "nearby_landmarks": ["반포한강공원", "잠수교", "세빛섬", "반포대교 달빛무지개분수"], "confidence": "high", "address": "대한민국 서울특별시 서초구 잠원동 122-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('무심천 청남교 화장실', '무심천 자전거길 서안, 청남교 인근에 위치한 공중화장실입니다. 라이딩 중 급한 용무를 해결하기 좋으나 위생 상태가 다소 아쉬울 수 있습니다.', '{restroom,park,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.490131, 36.624557), 4326), false, '{"source": "KOMOOT", "source_ids": ["1538", "630", "222", "515", "107", "578", "167", "301", "182", "257"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1f/1fyh4nv26uhrg1zu5gqnd87qj5135ayoj-uhi74412087/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/12/12de61hbjealpz39w2y8oxqvr5135dp7h-uhi74412120/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 9, "nearby_landmarks": ["무심천 자전거길", "청남교", "무심천"], "confidence": "high", "address": "대한민국 충청북도 청주시 서원구 모충동 69"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('무심천 자전거길 쉼터', '청주 무심천 자전거길에 위치한 야외 쉼터입니다. 무심천을 따라 라이딩 중 잠시 자전거를 세우고 휴식하며 재정비하기 좋습니다.', '{rest_area,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.480989, 36.631875), 4326), false, '{"source": "KOMOOT", "source_ids": ["96", "612", "222", "559", "149", "89", "111", "669", "171", "103"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/19/198f13c20cz6u1smbzg96ivahl54jaxjjw-uhi78772008/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/12/12w2sr403r8s61brft7kbc6idp5135bzv5-uhi74412099/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 9, "nearby_landmarks": ["무심천", "무심천 자전거길"], "confidence": "high", "address": "대한민국 청주시 서원구 사직동 710-21번지 청주시 충청북도 KR"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('강가 휴게소', '북한강 자전거길 대성리 구간에 위치한 강변 휴게소입니다. 탁 트인 북한강 풍경을 감상하며 음료 보충과 휴식을 취하기 좋은 라이더들의 쉼터입니다.', '{rest_area,convenience_store,restroom,viewpoint,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.398421, 37.714305), 4326), false, '{"source": "KOMOOT", "source_ids": ["61", "1807", "648", "812", "570", "1131", "1757", "949"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/15/155jpz2zl63n07iprfdf0ii05d425u2k-uhi86177687/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1x/1xjt3ua5w428g1i04g4jgny5kw5e821fkb-uhi87605287/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/es/eslmxxf74k1912dm9v01yhsyv5d425u2k-uhi86177686/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 8, "nearby_landmarks": ["북한강 자전거길", "대성리국민관광지", "대성리역", "북한강"], "confidence": "high", "address": "대한민국 경기도 가평군 청평면 대성리 63"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('경안천', '용인과 광주를 잇는 경안천을 따라 조성된 자전거길 구간입니다. 탁 트인 하천 풍경과 자연을 감상하며 여유롭게 라이딩하기 좋습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.211558, 37.270519), 4326), false, '{"source": "KOMOOT", "source_ids": ["41", "72", "288", "87", "79", "353", "361", "467", "354"], "category_raw": "190", "tour_count": 8, "nearby_landmarks": ["둔전역", "경안천 자전거길", "에버랜드"], "confidence": "high", "address": "대한민국 경기도 용인시 처인구 포곡읍 둔전리 416-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동탄여울공원', '동탄신도시에 위치한 동탄여울공원입니다. 자전거 주행이 가능한 넓은 길과 전망대, 주차장 등 편의시설이 잘 갖춰져 있어 라이딩 중 쾌적하게 휴식하기 좋은 장소입니다.', '{park,rest_area,parking,viewpoint,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.08634, 37.198432), 4326), false, '{"source": "KOMOOT", "source_ids": ["957", "331", "966", "982", "44", "106", "861"], "category_raw": "other_man_made", "tour_count": 8, "nearby_landmarks": ["오산천", "동탄역", "반석산"], "confidence": "high", "address": "대한민국 경기도 화성시 오산동 1060"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('낙동강', '대구 다사읍 문산리를 지나는 낙동강 자전거길 구간입니다. 탁 트인 강변 풍경을 감상하며 라이딩하기 좋은 국토종주 코스입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.42048, 35.852222), 4326), false, '{"source": "KOMOOT", "source_ids": ["303", "279", "72", "346", "467", "1484", "370", "589", "796", "151"], "image_urls": ["https://photos.komoot.de/wiki/commons/f/f0/낙동강.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3e/Andong_Bridge.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a3/Korea-Andong-Nakdong_River-02.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/58/Korea-Andong-Nakdong_River-01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f6/상주보.jpg?width=1920&crop=false"], "category_raw": "190", "tour_count": 8, "nearby_landmarks": ["강정고령보", "디아크", "문산나루터"], "confidence": "high", "address": "대한민국 대구광역시 달성군 다사읍 문산리 산28-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('노라바', '애월 해안도로 라이딩 중 들르기 좋은 오션뷰 해물라면 맛집입니다. 푸짐한 해산물과 얼큰한 국물로 든든하게 에너지를 보충하기 좋습니다.', '{restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.376227, 33.482859), 4326), false, '{"source": "KOMOOT", "source_ids": ["222", "548", "271", "642", "736", "93", "323"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1m/1m6t7hndb6orx1osz9vclb03515e1izivh-uhi87424732/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/x3/x3l4r9gicbpc1pyc2dbygbp7h5e1izl5s-uhi87424735/0?width=1920&crop=false"], "tips": [{"text": "Tasty seafood noodles", "author": "Lee"}], "category_raw": "restaurant", "tour_count": 8, "nearby_landmarks": ["애월해안도로", "구엄리 돌염전"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 애월읍 구엄리 1286-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대청댐', '금강 자전거길의 기종점이자 국토종주 인증센터가 위치한 핵심 랜드마크입니다. 대청호와 금강의 탁 트인 경치를 감상하며 휴식과 보급을 하기 좋습니다.', '{checkpoint,landmark,lake,river,viewpoint,rest_area,restroom,convenience_store,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.480876, 36.475899), 4326), false, '{"source": "KOMOOT", "source_ids": ["618", "5", "505", "769", "447", "313", "1234"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1g/1g40qlkbv2kgwwbvxszrakcdq4nlkmc1r-uhi62961869/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1r/1rc6ss09mhykeuhfa6ta64lxv4nlkmeg7-uhi62961870/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1j/1jhxo6ehzbci71wuwqzzk0xr4r4nlkmgvj-uhi62961873/0?width=1920&crop=false"], "category_raw": "man_made_monument", "tour_count": 8, "nearby_landmarks": ["대청댐 인증센터", "대청댐 물문화관", "금강로하스 대청공원", "대청교"], "confidence": "high", "address": "대한민국 대전광역시 대청댐(종점)"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('르꼬끄 스포르티프 바운더리 반포', '반포 한강공원에 위치한 르꼬끄 스포르티프의 사이클 복합 문화 공간입니다. 라이더를 위한 휴식처이자 자전거 대여 및 시승 이벤트가 열리는 거점입니다.', '{rest_area,bike_shop}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.001118, 37.512105), 4326), false, '{"source": "KOMOOT", "source_ids": ["173", "104", "157", "265", "68", "248", "190", "35"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1v/1vodqzflf9w7y15k19wn6xryv03gaarb60-uhi18016813/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 8, "nearby_landmarks": ["반포한강공원", "반포나들목", "반포 자전거대여점"], "confidence": "medium", "address": "대한민국 서울특별시 서초구 잠원동 122-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('운탄고도 1177갱', '운탄고도 MTB·그래블 라이딩의 필수 인증 지점인 1177갱 입구입니다. 과거 탄광 흔적과 조각상이 있어 라이딩 중 쉬어가며 기념사진을 남기기 좋습니다.', '{historic,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.811964, 37.182696), 4326), false, '{"source": "KOMOOT", "category_raw": "other_man_made", "tour_count": 8, "nearby_landmarks": ["도롱이연못", "화절령", "황금폭포 전망대"], "confidence": "high", "address": "8Q9C5RM6+3Q"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('탄천 수서역 구간', '강남구 수서동 탄천 자전거길 구간으로, 한강을 거쳐 춘천으로 향하는 장거리 라이딩의 주요 통과 거점입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.101834, 37.492619), 4326), false, '{"source": "KOMOOT", "source_ids": ["403", "255", "213", "238", "717", "196", "411", "126"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/5f/5fn2k5p7ddebxa8thwmertwh5akun1pp-uhi83576019/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/10/103y1u1uf287r1jj4c2eavaktb5akun47y-uhi83576022/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 8, "nearby_landmarks": ["탄천", "광평교", "수서역"], "confidence": "high", "address": "대한민국 서울특별시 강남구 수서동 331-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('학의날개교', '차량 도로 하부에 자전거 전용 통로가 있는 이중 구조의 교량입니다. 눈비와 햇빛을 피할 수 있으며, 금강의 멋진 야경을 감상하기 좋습니다.', '{bridge,river,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.257, 36.470104), 4326), false, '{"source": "KOMOOT", "source_ids": ["223", "79", "638", "86", "1027", "1359", "512", "102"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k0/1k/1k5tne9991ypk1xdglxae4jlqp1qc50blp-uhi297297/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k0/x5/x5fdfoqoy8rw1a5yc0kr878rl1qc50ijz-uhi297298/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k0/ny/nyo00lvdvo705hqjvl74zw0r1qc50o2j-uhi297299/0?width=1920&crop=false"], "tips": [{"text": "Gerade Nachts ist es ein beeindruckendes Bild, welches sich hier bietet.\nEin Besuch wert.", "author": "Wanderschnecke"}], "category_raw": "bridge", "tour_count": 8, "nearby_landmarks": ["금강", "이응다리"], "confidence": "high", "address": "대한민국 세종특별자치시 연기면 세종리 752-26"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('수영강 자전거길 (센텀 구간)', '실제 위치는 해운대 수영강 자전거길입니다. 수영강을 따라 회동수원지까지 거슬러 올라가는 라이딩 코스의 출발지나 연결 구간으로 활용하기 좋습니다.', '{river,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.134112, 35.163695), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "724", "40", "679", "78", "103", "196"], "category_raw": "trail", "tour_count": 8, "nearby_landmarks": ["수영강", "센텀시티", "APEC나루공원", "영화의전당"], "confidence": "high", "address": "대한민국 부산광역시 해운대구 우동 1417-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('무심천 자전거길 쉼터', '청주 무심천 자전거길에 위치한 쉼터입니다. 라이딩 중 안전하게 자전거를 세우고 휴식을 취하기 좋습니다.', '{rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.47161, 36.658231), 4326), false, '{"source": "KOMOOT", "source_ids": ["96", "612", "222", "559", "149", "89", "111", "669", "171", "103"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/19/198f13c20cz6u1smbzg96ivahl54jaxjjw-uhi78772008/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/12/12w2sr403r8s61brft7kbc6idp5135bzv5-uhi74412099/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 8, "nearby_landmarks": ["무심천", "무심천 자전거길"], "confidence": "high", "address": "대한민국 충청북도 청주시 흥덕구 신봉동 16-19"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('안양7둔치주차장', '안양천 자전거길 박석교 인근 구간으로, 평탄한 자전거도로가 조성되어 있습니다. 바로 옆에 안양7둔치주차장과 화장실이 있어 라이딩 출발지나 휴식처로 활용하기 좋습니다.', '{river,parking,bridge,rest_area,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.909132, 37.407774), 4326), false, '{"source": "KOMOOT", "source_ids": ["653", "112", "588", "349", "137", "615", "164"], "category_raw": "unknown", "tour_count": 7, "nearby_landmarks": ["박석교", "안양천", "안양7둔치주차장", "박달빗물배수펌프장"], "confidence": "high", "address": "대한민국 경기도 안양시 만안구 박달동 10-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('경향신문 구로 공장', '가산동에 위치한 경향신문 인쇄 공장입니다. 안양천 자전거길과 인접해 있어 도심 라이딩 시 방향을 확인하는 랜드마크로 활용할 수 있습니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.89068, 37.472993), 4326), false, '{"source": "KOMOOT", "source_ids": ["463", "153", "239", "485", "95", "35", "198"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/98/98l7mes34vkp16pr3h160yap64dpx6951-uhi56389228/0?width=1920&crop=false"], "category_raw": "other_man_made", "tour_count": 7, "nearby_landmarks": ["안양천", "가산디지털단지"], "confidence": "medium", "address": "대한민국 서울특별시 금천구 가산동 237-106"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('영산강·광주천 합수부', '영산강과 광주천이 만나는 합수부 인근 자전거길입니다. ''계곡 온 7월''은 공식 명칭이 아니며, 라이더가 임의로 등록한 것으로 추정됩니다.', '{river,checkpoint,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.831097, 35.148662), 4326), false, '{"source": "KOMOOT", "source_ids": ["1408", "140", "205", "208", "434", "180"], "category_raw": "gorge", "tour_count": 7, "nearby_landmarks": ["영산강 자전거길", "광주천 합수부"], "confidence": "low", "address": "대한민국 광주광역시 서구 마륵동 594"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금호강', '대구 도심과 낙동강을 잇는 금호강 자전거길 구간입니다. 평탄하고 경치가 좋아 라이딩하기 좋으며, 강정고령보(디아크)로의 접근성이 뛰어납니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.467663, 35.863134), 4326), false, '{"source": "KOMOOT", "source_ids": ["143", "13", "914", "160", "310", "540", "70", "159", "845", "330"], "image_urls": ["https://photos.komoot.de/wiki/commons/d/df/GeumhoriverYC.jpg?width=1920&crop=false"], "category_raw": "190", "tour_count": 7, "nearby_landmarks": ["강정고령보(디아크)", "낙동강 자전거길", "대실역"], "confidence": "high", "address": "대한민국 대구광역시 다사읍 매곡리 1534-5번지 1층 달성군 대구광역시 KR"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('기흥호수공원', '용인 기흥호수를 한 바퀴 도는 약 10km의 순환 코스입니다. 수변 경관이 뛰어나지만, 일부 비포장 흙길과 야자매트 구간이 있어 로드 자전거 라이딩 시 주의가 필요합니다.', '{lake,park,viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.100974, 37.263604), 4326), false, '{"source": "KOMOOT", "source_ids": ["90", "107", "42", "388", "1156", "429"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/ui/ui3tk3faj08ydfht6bedoizu4zwct0xi-uhi73068076/0?width=1920&crop=false"], "category_raw": "lake", "tour_count": 7, "nearby_landmarks": ["기흥호수공원", "신갈저수지", "용인조정경기장"], "confidence": "high", "address": "대한민국 경기도 용인시 기흥구 상갈동 204-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('흥원창 쉼터', '남한강과 섬강이 합류하는 흥원창 지점의 자전거길입니다. 화장실과 쉼터, 전망대가 갖춰져 있으며 일몰 풍경이 아름다워 라이더들이 쉬어가기 좋은 명소입니다.', '{rest_area,restroom,viewpoint,river,historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.750996, 37.218825), 4326), false, '{"source": "KOMOOT", "source_ids": ["559", "350", "1371", "339", "1038", "20", "164"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1u/1u3w2wharg2bxt3v6t5m1d1wq358ielpm-uhi8565054/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1t/1tw4guwvehg971qy558vos421g358iep5s-uhi8565056/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1p/1pn0nc5bcivdxihurqqj9fia93i5f7pki-uhi21857533/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 7, "nearby_landmarks": ["흥원창", "섬강", "남한강", "법천소공원"], "confidence": "high", "address": "대한민국 강원특별자치도 원주시 부론면 흥호리 1124-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('단양역', '단양 자전거 여행의 출발점이자 대중교통 연계 거점인 단양역입니다. 내부에 매점과 화장실이 있으며, 남한강 자전거길 코스로 진입하기 좋습니다.', '{transit,restroom,convenience_store,parking,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.343358, 36.973171), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/62/20201009_단양역_역사_건물.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/46/20201009_단양역_고상홈.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9e/Korea-Danyang_Korail_Trainstation_3440-07.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b2/Danyang_Station_1985.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/39/Danyang_Station_of_Before_the_1985(19821220).jpg?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 7, "nearby_landmarks": ["만천하스카이워크", "단양강 잔도"], "confidence": "high", "address": "대한민국 단양군 단양역앞"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('현암정 전망대', '대청호와 대청댐의 탁 트인 절경을 조망할 수 있는 현암정 전망대입니다. 휴게소 내 편의점, 화장실 등 편의시설이 잘 갖춰져 있어 라이딩 중 쉬어가기 좋습니다.', '{viewpoint,rest_area,convenience_store,restroom,parking,lake}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.485699, 36.492817), 4326), false, '{"source": "KOMOOT", "source_ids": ["948", "630", "896", "314", "485", "1359", "532"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/35/35j4pg1fizlm9tpuuwxbqbgy4rubnv4m-uhi67095038/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/18/18qp1nlc91vcg1h6l8mow6fb8s4rubnywm-uhi67095043/0?width=1920&crop=false"], "category_raw": "viewpoint", "tour_count": 7, "nearby_landmarks": ["대청댐", "대청호", "현암정", "현암사", "청남대"], "confidence": "high", "address": "대한민국 충청북도 청주시 상당구 문의면 덕유리 산70-17"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('수영강 자전거길', '수영강을 따라 조성된 평탄하고 쾌적한 자전거길입니다. 온천천 및 광안리 해변과 연결되어 부산 도심 라이딩 코스로 인기가 높습니다.', '{river,park,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.114934, 35.19726), 4326), false, '{"source": "KOMOOT", "source_ids": ["678", "1375", "1226", "101", "121", "619", "139"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/tp/tp17e41tg28q12aeairfbfvmc3uaousoe-uhi37263634/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/13/131cllqeitjiu17y98revtncib3uaoywqa-uhi37263683/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 7, "nearby_landmarks": ["수영강", "수영강시민공원", "반여농수산물도매시장"], "confidence": "high", "address": "대한민국 부산광역시 해운대구 반여동 1502-38"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('무심천교 인증센터', '오천자전거길 무심천교에 위치한 무인 인증센터입니다. 주변에 식당이나 매점 등 보급처가 부족하므로 방문 전 식수와 간식을 미리 준비하는 것이 좋습니다.', '{checkpoint,bridge,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.446942, 36.677638), 4326), false, '{"source": "KOMOOT", "source_ids": ["254", "55", "462", "77", "518", "575", "181"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/zp/zpi9vr3cmjom1usp1gr6xspy9511wqrkx-uhi74380564/0?width=1920&crop=false"], "tips": [{"text": "국토종주 자전거길 무심천교 무인인증부스", "author": "​​"}, {"text": "국토종주 자전거길 무심천교 무인인증부스", "author": ""}], "category_raw": "facilities", "tour_count": 7, "nearby_landmarks": ["무심천교", "미호강", "오천자전거길"], "confidence": "high", "address": "대한민국 충청북도 청주시 흥덕구 원평동 72-2 무심천교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('물의정원 꽃양귀비 단지', '남양주 물의정원 내 붉은 꽃양귀비가 만발하는 초화단지입니다. 북한강 자전거길에 위치해 라이딩 중 화려한 꽃물결을 배경으로 사진을 남기고 쉬어가기 완벽한 명소입니다.', '{park,nature,viewpoint,river,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.317025, 37.558655), 4326), false, '{"source": "KOMOOT", "source_ids": ["2163", "1238", "366", "2505", "346", "1305", "396"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/10/10cg7n0jkvgiyuuazayogdfd3dzmdaot-uhi13955307/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1h/1hdf2zyazrvbjc6wukuyr8xcn3dzmeyfb-uhi13955454/0?width=1920&crop=false"], "category_raw": "other_natural", "tour_count": 7, "nearby_landmarks": ["남양주 물의정원", "북한강 자전거길", "뱃나들이교", "운길산역"], "confidence": "high", "address": "대한민국 경기도 남양주시 조안면 송촌리 465-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('백석천 합류지', '중랑천과 백석천 자전거길이 만나는 주요 분기점입니다. 서울, 양주 방향이나 의정부 시내로 진입하기 좋아 라이더들이 자주 거쳐 가는 곳입니다.', '{river,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.051801, 37.727124), 4326), false, '{"source": "KOMOOT", "source_ids": ["114", "158", "40", "88", "176", "258", "133"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/18/18wznp3afn3kp1js09l0hiu1n7385qoiw0-uhi9853349/0?width=1920&crop=false"], "category_raw": "river", "tour_count": 7, "nearby_landmarks": ["중랑천", "백석천"], "confidence": "high", "address": "대한민국 경기도 의정부시 호원동 20-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('무심천교 인증센터', '오천자전거길 무심천교 인증센터가 위치한 자전거 쉼터입니다. 국토종주 스탬프를 찍고 미호강과 무심천 합수부 경치를 보며 쉬어가기 좋습니다.', '{rest_area,checkpoint,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.44765, 36.676821), 4326), false, '{"source": "KOMOOT", "source_ids": ["59", "470", "522", "81", "250", "579", "185"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1j/1jjwrkpy3dfx01b3rdzu5wigzk5135cp12-uhi74412107/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 7, "nearby_landmarks": ["무심천교", "문암생태공원", "미호강", "오천자전거길"], "confidence": "high", "address": "대한민국 충청북도 청주시 청원구 정상동 368-45"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('아라 서해갑문 인증센터', '국토종주 자전거길의 출발점이자 종착점인 핵심 인증센터입니다. 아라타워 내 유인센터와 야외 무인부스가 있으며, 화장실과 편의점 등 휴식 시설이 잘 갖춰져 있습니다.', '{checkpoint,rest_area,restroom,convenience_store,landmark,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.607724, 37.558166), 4326), false, '{"source": "KOMOOT", "source_ids": ["142", "503", "967"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/18/18z2739bp7girh48o4rx4vway54qd1jek-uhi78955329/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/yw/ywijgh0psiqrrma880o2b6ar54qd1lwl-uhi78955330/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/18/18ywp4we1057achfb9jirkdzh54qd1ocr-uhi78955331/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 7, "nearby_landmarks": ["정서진", "아라타워", "아라서해갑문"], "confidence": "high", "address": "대한민국 인천광역시 서구 오류동 1563"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('여주보', '남한강 자전거길의 주요 인증센터가 있는 보(Weir)입니다. 차량 통행이 없어 안전하게 강을 건널 수 있으며, 탁 트인 남한강 풍경을 감상하기 좋습니다.', '{bridge,checkpoint,convenience_store,restroom,rest_area,viewpoint,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.608582, 37.328399), 4326), false, '{"source": "KOMOOT", "source_ids": ["515", "1688", "178", "1255", "345", "466", "371"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/s9/s91lfhwms4fi1hd4kvmh125494dcn2v0q-uhi56169188/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/uh/uh6ckft9i8a4te24t4tpj4wp4dcn2wu2-uhi56169189/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1h/1h3eqgm966k071j6ehlyz8ae2r4dcn2xth-uhi56169190/0?width=1920&crop=false"], "tips": [{"text": "Perfekte Flußquerung auf einem Damm, autofrei. Teilstück des 4-Flüsse-Radweges.\nSchöner Blick auf den Fluss und das jeweilige Flussufer.", "author": "Andreas Wendtland"}], "category_raw": "bridge", "tour_count": 7, "nearby_landmarks": ["여주보문화관", "세종대왕릉"], "confidence": "high", "address": "8Q998JH5+9C"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오산천 동탄 직선 구간', '자연생태하천인 오산천과 탁 트인 논밭 풍경을 감상하며 시원하게 속도를 낼 수 있는 평탄한 직선 자전거길입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.082752, 37.174024), 4326), false, '{"source": "KOMOOT", "source_ids": ["128", "99", "400", "321", "176", "100"], "tips": [{"text": "자연생태하천 오산천과 논밭과 함께하는 직선구간", "author": "min seong kim"}], "category_raw": "river", "tour_count": 7, "nearby_landmarks": ["오산천", "동탄일반산업단지", "방아다리공원"], "confidence": "high", "address": "대한민국 경기도 화성시 방교동 872-85"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('용문역', '대전 1호선 용문역입니다. 유등천 자전거길과 가까워 접근성이 좋으며, 주말 라이딩 시 자전거를 싣고 대중교통을 연계(점프)하기 좋은 거점입니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.393259, 36.338204), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/f/fe/Yongmun_Stn._Exit_5_(DJET).jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9b/Yongmun_Stn._Platform_(DJET).jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d3/Yongmun_Stn._Nameplate_(DJET).jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a2/YongmunSta.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/ko/3/3d/SAM_0036.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 7, "nearby_landmarks": ["유등천 자전거길", "롯데백화점 대전점"], "confidence": "high", "address": "대한민국 대전광역시 서구 용문동 용문"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('월릉교 매점', '중랑천 자전거길 동편 월릉교 아래 위치한 매점 겸 휴게소입니다. 라이더들 사이에서 ''월매(월릉교 매점)''로 불리며 보급 및 만남의 장소로 인기가 높습니다.', '{convenience_store,rest_area,bridge,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.071901, 37.616351), 4326), false, '{"source": "KOMOOT", "source_ids": ["59", "667", "738", "73", "148", "78", "35"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1t/1tvz1gb1xkr3b1fqs6amqypfix3fiutzih-uhi16517237/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/qg/qgi12xn5lum91r6xqp95jjfh03fiuvfso-uhi16517251/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 7, "nearby_landmarks": ["월릉교", "중랑천"], "confidence": "high", "address": "대한민국 서울특별시 중랑구 묵동 330-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('당거리 오성강변 자전거길', '안성천(평택강)을 따라 조성된 경치가 뛰어난 자전거 전용도로입니다. 당거쉼터와 공공자전거 대여소가 인접해 있어 라이더들의 주요 휴식처이자 출발점으로 사랑받는 구간입니다.', '{river,rest_area,viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.01243, 36.985157), 4326), false, '{"source": "KOMOOT", "source_ids": ["475", "760", "419", "788", "600", "365", "420"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/82/825chrz1d0dx1r55eefxjqj3h9vhgci-uhi19973370/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/16/164ltm6mx03tl1puos39iet05j3h9vhl57-uhi19973373/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/yw/ywpas2u6i8ftbjbensme54eo3h9vhoe3-uhi19973374/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 7, "nearby_landmarks": ["당거쉼터", "두바퀴의 행복 2호점", "오성강변", "안성천"], "confidence": "high", "address": "대한민국 경기도 평택시 오성면 당거리 26-38"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('화장실', '오천자전거길 미호강변 청주시 장애인파크골프장 내에 위치한 화장실입니다. 자전거길과 인접해 있어 라이딩 중 편리하게 이용할 수 있습니다.', '{restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.445499, 36.678879), 4326), false, '{"source": "KOMOOT", "source_ids": ["1538", "630", "222", "515", "107", "578", "167", "301", "182", "257"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1f/1fyh4nv26uhrg1zu5gqnd87qj5135ayoj-uhi74412087/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/12/12de61hbjealpz39w2y8oxqvr5135dp7h-uhi74412120/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 7, "nearby_landmarks": ["미호강", "오천자전거길", "청주시 장애인파크골프장", "문암생태공원"], "confidence": "high", "address": "대한민국 충청북도 청주시 흥덕구 원평동 68-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('회룡천 합류지', '중랑천과 회룡천 자전거길이 만나는 합류 지점입니다. 서울과 의정부를 잇는 중랑천 코스 라이딩 시 거쳐가는 주요 길목으로 수변 경관이 좋습니다.', '{river,nature,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.050139, 37.723718), 4326), false, '{"source": "KOMOOT", "source_ids": ["144", "165", "77", "147", "29", "103", "269"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/c2/c2bar7m9fmau1q6w19601rzuy385qj5qr-uhi9853261/0?width=1920&crop=false"], "category_raw": "river", "tour_count": 7, "nearby_landmarks": ["중랑천 자전거길", "회룡역"], "confidence": "high", "address": "대한민국 경기도 의정부시 호원동 37-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('흥원창 전망대', '남한강과 섬강이 만나는 흥원창 합수머리에 위치한 조운선 모양의 전망대입니다. 자전거길 옆에 있어 탁 트인 강 풍경과 노을을 감상하며 쉬어가기 좋습니다.', '{viewpoint,rest_area,river,historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.748056, 37.233303), 4326), false, '{"source": "KOMOOT", "source_ids": ["369", "145", "540", "39", "273", "1057"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1o/1o3eigvu3rysv1c0llpti882jo56j9pnv0-uhi80940812/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/17/17ui7pzjenkc2pxebleml7n0c5ckdxign-uhi85493779/0?width=1920&crop=false"], "category_raw": "viewpoint", "tour_count": 6, "nearby_landmarks": ["흥원창", "남한강 자전거길", "섬강 자전거길"], "confidence": "high", "address": "대한민국 강원특별자치도 원주시 부론면 흥호리 806"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('강천섬', '남한강 자전거길에 위치한 하중도로, 평탄한 코스와 가을철 은행나무 길이 아름다워 자전거 여행객에게 인기 있는 휴식처입니다.', '{park,nature,river,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.693432, 37.235023), 4326), false, '{"source": "KOMOOT", "source_ids": ["59", "652", "81", "1069", "178", "177"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/z1/z11gir3e36i1f7jkmcevkgaa36xwnsti-uhi9363361/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/e4/e4ppsledpch1fp1rx5hz5qxk36xwnw78-uhi9363362/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/o5/o5etus49436n1gx9l84twcpqo550i7l1m-uhi79287043/0?width=1920&crop=false"], "category_raw": "other_natural", "tour_count": 6, "nearby_landmarks": ["강천보", "신륵사", "금은모래강변공원"], "confidence": "high", "address": "대한민국 경기도 여주시 강천면 강천리 627"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('굴포천', '인천 부평에서 아라뱃길로 이어지는 굴포천 자전거길 구간입니다. 평탄한 하천변을 따라 쾌적하게 라이딩하기 좋은 코스입니다.', '{river,nature,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.760709, 37.534906), 4326), false, '{"source": "KOMOOT", "source_ids": ["58", "1786", "278", "339", "92", "512"], "image_urls": ["https://photos.komoot.de/wiki/commons/a/a6/Gulpocheon-20121030-1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b0/Gulpocheon-20121030-3.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/ko/b/b1/Gulpocheon-20121030-4.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8b/Gulpocheon_Station3.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/59/Gulpocheon-20121030-2.JPG?width=1920&crop=false"], "category_raw": "190", "tour_count": 6, "nearby_landmarks": ["오정대공원", "부천자전거문화센터", "아라뱃길 합수부"], "confidence": "high", "address": "대한민국 경기도 부천시 오정동 535"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남한강대교', '강원도 원주와 충북 충주를 잇는 남한강 자전거길의 주요 교량입니다. 국토종주 자전거길을 달리는 라이더들이 반드시 건너게 되는 상징적인 구간입니다.', '{bridge,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.745836, 37.20502), 4326), false, '{"source": "KOMOOT", "source_ids": ["571", "338", "8", "351", "1026", "176"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1n/1ndrxvcp26094khty6p7dzczr5d1alyk2-uhi86080443/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 6, "nearby_landmarks": ["남한강", "섬강 합수부"], "confidence": "high", "address": "대한민국 강원특별자치도 원주시 부론면 법천리 1592 남한강(충주구간)"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('노랑등대', '평택호 자전거길 오성강변에 위치한 라이더들의 필수 휴식처입니다. 자전거 거치대와 공기주입기가 마련되어 있으며, 음료와 국수 등 간식을 즐기며 쉬어가기 좋습니다.', '{cafe,rest_area,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.973115, 36.971985), 4326), false, '{"source": "KOMOOT", "source_ids": ["682", "56", "522", "497", "443", "710"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1r/1rdibiiu8fof0gurqew4717123u3gek99-uhi36983281/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1n/1nn74s7i3p3551j93sinfezbc93u3gfab5-uhi36983292/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/qp/qpm2zjrn4lxp10yfzdh60s68l3u3gejve-uhi36983280/0?width=1920&crop=false"], "tips": [{"text": "Get a snack and drink. The Cafe is right off the bike path.", "author": "Curry (カレー)"}, {"text": "Get a snack and drink. The Cafe is right off the bike path.", "author": ""}], "category_raw": "cafe", "tour_count": 6, "nearby_landmarks": ["평택호 자전거길", "오성강변", "안성천"], "confidence": "high", "address": "대한민국 경기도 평택시 안중읍 삼정리 384-16"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('다락쉼터 인증센터', '제주환상자전거길의 필수 인증센터입니다. 탁 트인 바다 조망이 일품인 해안 절벽 위 쉼터로, 근처에 고양이 카페와 매점이 있습니다.', '{checkpoint,rest_area,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.340189, 33.469659), 4326), false, '{"source": "KOMOOT", "source_ids": ["359", "638", "552", "361", "458", "183"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1i/1ikwd67pfel661gi3mqbqd5kac47e130tt-uhi50787365/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/19/199po7sb5cclx1vfk456fyx58h4zhvj1kz-uhi72527307/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1d/1decoaxe7xt81j0yha9mc613x2ywihtp7-uhi5726859/0?width=1920&crop=false"], "tips": [{"text": "It is literally just a shelter with a view, something to aim for. There is a cat coffee shop soon after the shelter  and a shop.", "author": "Martin"}], "category_raw": "hut", "tour_count": 6, "nearby_landmarks": ["애월해안도로", "고내포구"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 애월읍 고내리 471-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('매노천 덩굴 쉼터', '갑천누리길 3코스 매노천변 자전거길에 위치한 파고라(덩굴 쉼터)입니다. 라이딩 중 햇빛을 피해 잠시 쉬어가기 좋습니다.', '{rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.335766, 36.251377), 4326), false, '{"source": "KOMOOT", "source_ids": ["308", "238", "380", "129", "996", "229"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1p/1pb2tygozar9ecixxywxfl2k44n21b7gg-uhi62442372/0?width=1920&crop=false"], "category_raw": "other_man_made", "tour_count": 6, "nearby_landmarks": ["갑천누리길 3코스", "매노천", "토옥마을"], "confidence": "medium", "address": "대한민국 대전광역시 서구 매노동 600-15"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('도봉역 중랑천 보급소', '중랑천 자전거길 진출입로와 바로 연결되는 오피스텔 단지입니다. 1층에 편의점과 식당 등 상가가 있어 라이딩 중 보급과 휴식을 취하기 좋습니다.', '{other,convenience_store,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.047055, 37.682748), 4326), false, '{"source": "KOMOOT", "source_ids": ["510", "121", "1327", "446", "284", "580"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/ki/ki1fvqueeu0kisg04lpuragw37crj99z-uhi9466487/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/16/16pzusa4pvgl11c6e186t6cxxu37g11th5-uhi9490223/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/25/2538glns017yag6do1fua74737g11x69-uhi9490224/0?width=1920&crop=false"], "category_raw": "settlement", "tour_count": 6, "nearby_landmarks": ["중랑천 자전거길", "도봉역"], "confidence": "high", "address": "대한민국 서울특별시 도봉구 도봉동 62-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('물안해수욕장', '거제 칠천도 일주 라이딩(약 15km) 중 만나게 되는 아담하고 잔잔한 모래해변입니다. 화장실과 카페가 있어 탁 트인 바다 풍경을 감상하며 땀을 식히고 휴식하기 좋습니다.', '{beach,rest_area,restroom,cafe}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.652524, 35.011088), 4326), false, '{"source": "KOMOOT", "source_ids": ["235", "422", "666", "745", "591", "734"], "category_raw": "12", "tour_count": 6, "nearby_landmarks": ["칠천교", "송포테마공원", "수야방도", "씨릉섬"], "confidence": "high", "address": "대한민국 경상남도 거제시 하청면 어온리 13-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('미음나루', '한강 자전거길 남양주 구간의 대표적인 난코스인 ''미음나루 고개''가 있는 곳입니다. 짧지만 15% 이상의 급경사로 악명 높으며, 주변에 식당가가 밀집해 있어 휴식하기 좋습니다.', '{landmark,mountain,river,restaurant,historic}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.176002, 37.590336), 4326), false, '{"source": "KOMOOT", "source_ids": ["760", "1448", "729", "852", "922", "2427"], "category_raw": "21", "tour_count": 6, "nearby_landmarks": ["수석한강공원", "왕숙천 합수부", "구리암사대교"], "confidence": "high", "address": "대한민국 경기도 남양주시 수석동 산2-73"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼패공원 자작나무숲', '남양주 한강 자전거길 바로 옆에 위치한 이국적인 자작나무 숲입니다. 라이딩 중 잠시 자전거를 세우고 아름다운 경관을 감상하며 휴식하기 좋은 자연 명소입니다.', '{park,nature,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.189915, 37.592183), 4326), false, '{"source": "KOMOOT", "source_ids": ["701", "894", "880", "2399", "1420", "732"], "category_raw": "191", "tour_count": 6, "nearby_landmarks": ["남양주 한강공원 삼패지구", "미음나루", "덕소역"], "confidence": "high", "address": "대한민국 경기도 남양주시 삼패동 376"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('섬진강댐 인증센터', '섬진강 자전거길 종주의 시작점이자 스탬프를 찍을 수 있는 인증센터입니다. 주차장과 화장실 등 편의시설이 잘 갖춰져 있어 라이딩 출발지로 적합합니다.', '{checkpoint,restroom,parking,park,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.149593, 35.521792), 4326), false, '{"source": "KOMOOT", "source_ids": ["334", "42", "850"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/qt/qtmj2al10jul1xyjx5hzlv6mk5e583e3c-uhi87511942/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 6, "nearby_landmarks": ["섬진강생활체육공원", "섬진강", "강진교"], "confidence": "high", "address": "대한민국 전북특별자치도 임실군 덕치면 회문리 825-84"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('안양천 자전거길 (금천구 구간)', '서울 서남부와 경기 남부를 잇는 대표적인 자전거 코스입니다. 평탄하고 길게 뻗어 있어 한강 합수부나 안양 방향으로 장거리 라이딩을 즐기기에 좋습니다.', '{river,park,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.89259, 37.468302), 4326), false, '{"source": "KOMOOT", "source_ids": ["146", "246", "492", "205", "456", "102"], "image_urls": ["https://photos.komoot.de/wiki/commons/0/01/Anyangcheon_Stream_Walkway_in_Spring.jpg?width=1920&crop=false"], "category_raw": "190", "tour_count": 6, "nearby_landmarks": ["독산역", "금천교", "독산보도교"], "confidence": "high", "address": "대한민국 서울특별시 금천구 독산제1동 332-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('양수역', '남한강 자전거길 라이딩의 주요 거점이자 출발지로 사랑받는 경의중앙선 전철역입니다. 자전거 대여소, 편의점, 화장실 등 라이더를 위한 편의시설이 밀집해 있습니다.', '{transit,rest_area,convenience_store,restroom,bike_shop}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.329206, 37.546281), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/6d/Yangsu_Station_in_Jungang_Line.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8f/K130_Yangsu_01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/59/K130_Yangsu_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/84/K130_Yangsu_Station_02.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bb/K130_Yangsu_Station_03.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 6, "nearby_landmarks": ["두물머리", "북한강철교(양수철교)", "세미원"], "confidence": "high", "address": "대한민국 경기도 양평군 양서면 용담리 684-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('여주종합터미널', '남한강 자전거길 종주 시 출발이나 복귀를 위해 라이더들이 가장 많이 이용하는 핵심 교통 거점(점프 포인트)입니다.', '{transit,restroom,convenience_store,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.634846, 37.290128), 4326), false, '{"source": "KOMOOT", "source_ids": ["276", "972", "108", "317", "311"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1h/1hmhy13cuo1h8eig9eq6xoskd37g4fswl-uhi9491286/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 6, "nearby_landmarks": ["남한강 자전거길", "여주시청"], "confidence": "high", "address": "대한민국 경기도 여주시 홍문동 274-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('일광천', '일광해수욕장에서 내륙으로 이어지는 생태하천입니다. 억새가 어우러진 자전거 산책로(건강 10리길)가 조성되어 있어 쾌적하고 여유로운 라이딩을 즐기기 좋습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.23504, 35.268378), 4326), false, '{"source": "KOMOOT", "source_ids": ["267", "68", "503", "708", "196", "302"], "category_raw": "190", "tour_count": 6, "nearby_landmarks": ["일광해수욕장", "이천생태공원"], "confidence": "high", "address": "대한민국 부산광역시 기장군 일광면 이천리 922-25"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('이호테우해변 일몰 전망대', '제주환상자전거길을 달리며 만나는 이호테우해변 일몰 명소입니다. 이국적인 말 등대를 배경으로 붉은 노을을 감상하며 라이딩 피로를 풀기 좋습니다.', '{viewpoint,beach,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.455141, 33.496362), 4326), false, '{"source": "KOMOOT", "source_ids": ["908", "48", "75", "508", "98", "723"], "category_raw": "viewpoint", "tour_count": 6, "nearby_landmarks": ["이호테우해변", "이호테우 말등대"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 이호일동 1599-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('달맞이길 전망대', '해운대 달맞이길 초입에 위치해 해운대 해변과 광안대교 절경을 조망할 수 있습니다. 달맞이고개 업힐 전후로 잠시 숨을 고르며 멋진 풍경과 함께 쉬어가기 좋은 뷰포인트입니다.', '{viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.171724, 35.161357), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 6, "nearby_landmarks": ["해운대해수욕장", "달맞이고개", "엘시티"], "confidence": "high", "address": "대한민국 부산광역시 해운대구 중동 938-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('도동 한옥마을', '유네스코 세계유산 도동서원 옆에 조성된 한옥 체험 단지(도동유교문화관)입니다. 다람재를 넘기 전후로 고즈넉한 한옥을 배경으로 휴식하며 사진을 남기기 좋습니다.', '{historic,landmark,rest_area,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.371844, 35.702168), 4326), false, '{"source": "KOMOOT", "source_ids": ["117", "424", "273", "98", "503", "645"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/4e/4eqp3evqkvt51lmxtbdcgytba5kdkb3fe-uhi95860888/0?width=1920&crop=false"], "category_raw": "historical_site", "tour_count": 6, "nearby_landmarks": ["도동서원", "다람재", "낙동강"], "confidence": "high", "address": "대한민국 대구광역시 달성군 구지면 도동리 33"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('한림 해상풍력단지 전망대', '제주 환상자전거길 해안도로에서 조망할 수 있는 국내 최대 해상풍력 단지입니다. 웅장한 경관을 자랑하지만, 강풍이 잦은 구간이므로 라이딩 시 측풍에 각별히 주의해야 합니다.', '{landmark,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.284956, 33.444632), 4326), false, '{"source": "KOMOOT", "source_ids": ["55", "781", "504", "607", "503", "326"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/ab/ab32chcbc3758t20lrr31a065bub5q0s-uhi84761854/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/r1/r118j1bdz3bn1qzammuivak8o5e3vtbo7-uhi87480690/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/uk/ukq0sqwv7viq1113n4fg3o1n45e3vte60-uhi87480691/0?width=1920&crop=false"], "tips": [{"text": "Careful of strong winds in this area", "author": "etkchee"}, {"text": "Careful of strong winds in this area", "author": ""}], "category_raw": "other_man_made", "tour_count": 6, "nearby_landmarks": ["제주환상자전거길", "귀덕해안도로", "제주올레길 15코스"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 한림읍 귀덕리 3082-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('진위천·황구지천 합수부', '황구지천과 진위천이 만나는 합수점 부근의 자전거길입니다. 탁 트인 수변 풍경을 즐기며 평택호 방향으로 라이딩하기 좋은 코스입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.019225, 37.094638), 4326), false, '{"source": "KOMOOT", "source_ids": ["221", "150", "86", "278", "273", "251"], "category_raw": "190", "tour_count": 6, "nearby_landmarks": ["황구지천 합수점"], "confidence": "high", "address": "대한민국 경기도 평택시 서탄면 회화리 162-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('행주산성 로스터리 카페', '행주산성 인근의 숲속 산장 느낌 로스터리 카페입니다. 라이딩 중 빈티지 오디오와 LP 음악을 감상하며 커피와 디저트로 휴식하기 좋습니다.', '{cafe,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.825408, 37.60166), 4326), false, '{"source": "KOMOOT", "source_ids": ["182", "60", "93", "315", "354", "214"], "tips": [{"text": "Great Tiramisu, a real tasty Mocha and Cappuccino, great vinyl collection and a great sound system!", "author": "667 The Neighbour of the Beast"}], "category_raw": "cafe", "tour_count": 6, "nearby_landmarks": ["행주산성", "행주대교"], "confidence": "high", "address": "대한민국 경기도 고양시 덕양구 행주내동 167-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('충주공용버스터미널', '국토종주(새재, 남한강 자전거길) 라이더들의 주요 교통 거점입니다. 터미널 내 카페(스타벅스 등)와 식당, 편의시설이 있어 버스 대기 및 휴식에 매우 좋습니다.', '{transit,cafe,restaurant,restroom,convenience_store,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.915169, 36.980741), 4326), false, '{"source": "KOMOOT", "category_raw": "cafe", "tour_count": 6, "nearby_landmarks": ["탄금대", "충주역", "남한강 자전거길", "충주세계무술공원"], "confidence": "high", "address": "대한민국 충청북도 충주시 봉방동 76-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('한강 자전거길 동작대교 남단', '한강 자전거길과 바로 연결되는 동작대교 남단 쉼터입니다. 엘리베이터를 통해 전망카페(노을·구름카페)로 이동할 수 있어 라이더들의 야경 감상 및 휴식처로 인기가 높습니다.', '{cafe,viewpoint,rest_area,bridge,river,transit,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.980929, 37.505394), 4326), false, '{"source": "KOMOOT", "source_ids": ["58", "24", "153", "190", "78", "378"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/kl/kl48ktfpl4jp1s3tgr1vtrdu43g4kiio2-uhi17675982/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/11/11na39lgdjc0c1st1yklqe07bq3wzxnqy6-uhi41756496/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/b9/b9gwxefvkjs91jhzy0v0b42ma4afemtum-uhi53721530/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 6, "nearby_landmarks": ["동작대교 노을카페", "동작대교 구름카페", "동작역"], "confidence": "high", "address": "대한민국 서울특별시 동작대교전망카페"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신창풍차해안도로', '신창풍차해안도로의 해상풍력발전단지로, 거대한 풍차 바로 아래를 자전거로 지날 수 있습니다. 탁 트인 바다와 어우러진 이국적인 풍경과 일몰이 아름다운 라이딩 명소입니다.', '{landmark,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.173657, 33.343008), 4326), false, '{"source": "KOMOOT", "source_ids": ["127", "1128", "358", "312", "317", "318"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/76/76499fj19fqs14kkdmncjsyyp5bubc589-uhi84761916/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1t/1ts2k7zlnczyw115xkaktq50x95bubc58p-uhi84761917/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1x/1xey4w0qw8w4n1mobt9r41r7xr5bubam0g-uhi84761903/0?width=1920&crop=false"], "tips": [{"text": "Windmills are so close you can walk underneath them", "author": ""}, {"text": "Windmills are so close you can walk underneath them", "author": "etkchee"}], "category_raw": "man_made_monument", "tour_count": 6, "nearby_landmarks": ["신창풍차해안도로", "싱게물공원", "차귀도"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 한경면 신창리 1322-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('춘천대첩기념평화공원', '소양강 자전거길에 인접한 춘천대첩기념평화공원입니다. 6.25 전쟁 춘천지구 전투를 기념하는 조형물들이 있어 라이딩 중 역사를 되새기며 휴식하기 좋습니다.', '{park,historic,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.71796, 37.889473), 4326), false, '{"source": "KOMOOT", "source_ids": ["764", "235", "655", "60", "103", "264"], "category_raw": "man_made_monument", "tour_count": 6, "nearby_landmarks": ["소양강 스카이워크", "소양강 처녀상", "소양2교"], "confidence": "high", "address": "대한민국 강원특별자치도 춘천시 근화동 32"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('해바라기 안심폰', '아라한강갑문 인근 한강자전거길에 위치한 해바라기 모양의 긴급 안심폰입니다. 라이딩 중 위급 상황 발생 시 신속하게 구조 요청을 할 수 있는 안전 시설입니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.800123, 37.598731), 4326), false, '{"source": "KOMOOT", "source_ids": ["174", "428", "150", "156", "159", "242"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1ka/ks/ks8u7ijjoru51uc39r9xb75lk5nh5un6a-uhi97559737/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 6, "nearby_landmarks": ["아라한강갑문", "행주대교", "한강자전거길"], "confidence": "high", "address": "대한민국 서울특별시 강서구 개화동 31-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('시인과 나', '낙동강 자전거길 황산공원 인근의 카페 ''시인과 나''입니다. 탁 트인 강변 뷰를 보며 시원한 커피를 마시고 식수도 보충할 수 있어 라이더에게 오아시스 같은 휴식처입니다.', '{cafe,rest_area,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.978482, 35.310605), 4326), false, '{"source": "KOMOOT", "source_ids": ["705", "780", "165", "1047", "200", "512"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/nf/nf14y17rb4r411mnldro3rh7054tfpnf2-uhi79081010/0?width=1920&crop=false"], "tips": [{"text": "Mmmm iced latte!", "author": "Veronica Anderson"}], "category_raw": "cafe", "tour_count": 6, "nearby_landmarks": ["낙동강 자전거길", "황산공원", "물금역"], "confidence": "high", "address": "대한민국 경상남도 양산시 물금읍 낙동로 436"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('목감천 광명스피돔 자전거길', '광명스피돔 인근 목감천을 따라 조성된 평탄한 자전거길입니다. 초보자나 어린이도 안전하게 타기 좋으며, 현재 명칭은 개인이 등록한 구간 이름으로 보입니다.', '{river,park,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.850232, 37.481421), 4326), false, '{"source": "KOMOOT", "source_ids": ["489", "101", "142", "118", "105"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/cn/cnllu3127z0iivvuz10py9us4dgtjp2n-uhi56230679/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 5, "nearby_landmarks": ["목감천", "광명스피돔"], "confidence": "high", "address": "대한민국 경기도 광명시 광명동 679-333"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('CBR', '울산 북구 송정동에 위치한 지점으로 정확한 시설은 확인되지 않습니다. 라이더들이 주행 중 휴식이나 만남의 장소로 활용하는 웨이포인트로 추정됩니다.', '{other,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.34933, 35.598353), 4326), false, '{"source": "KOMOOT", "source_ids": ["112", "104", "131", "118", "218"], "category_raw": "unknown", "tour_count": 5, "nearby_landmarks": ["송정지구", "동천강"], "confidence": "low", "address": "대한민국 울산광역시 북구 송정동 907-18"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('Nanii의 가게', '영산강 자전거길 청호리 구간에 위치한 매점 겸 쉼터입니다. 라이딩 중 음료, 아이스크림, 라면 등을 먹으며 휴식하기 좋습니다.', '{convenience_store,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.511278, 34.783527), 4326), false, '{"source": "KOMOOT", "source_ids": ["198", "189", "126", "759"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1k/1kpcl9xmgbzxjxnabn7lvshaj37e4euc7-uhi9476322/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/3w/3ww9lot9xrhq1gocai3usjs5r37e4eurd-uhi9476323/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1r/1raj5kpw6gp1v1hl1hkjj0wssh37e4ev3f-uhi9476324/0?width=1920&crop=false"], "tips": [{"text": "쉼터, 편의점.\n음료수, 아이스크림, 라면, 물 등", "author": "AsuRa"}, {"text": "쉼터, 편의점.\n음료수, 아이스크림, 라면, 물 등", "author": ""}], "category_raw": "facilities", "tour_count": 5, "nearby_landmarks": ["영산강 자전거길", "청호쉼터"], "confidence": "medium", "address": "대한민국 전라남도 무안군 일로읍 청호리 288-55"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('가람 커피 로스터스', '청계산 및 여의천 자전거길 인근의 조용한 로스터리 카페입니다. 라이딩 중 맛있는 에스프레소와 싱글 오리진 핸드드립 커피를 마시며 휴식하기 좋습니다.', '{cafe}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.053409, 37.454274), 4326), false, '{"source": "KOMOOT", "source_ids": ["225", "847", "689", "511", "233"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/w8/w8f88k6wwjtr1vzdda4tsz7lj3qu8pl7e-uhi31896309/0?width=1920&crop=false"], "tips": [{"text": "Nice place to stop for a coffee, good espresso and offer single origin pour-over.", "author": "Jonathan Strand"}], "category_raw": "cafe", "tour_count": 5, "nearby_landmarks": ["청계산", "여의천"], "confidence": "high", "address": "대한민국 서울특별시 서초구 신원동 445-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오두산 강변 전망대', '파주 필승로 구간의 뷰포인트로, 구불구불한 강변 도로와 다리의 멋진 조화를 감상할 수 있습니다. 오두산 통일전망대 인근 라이딩 중 탁 트인 풍경을 즐기며 쉬어가기 좋습니다.', '{viewpoint,river,bridge}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.677766, 37.773591), 4326), false, '{"source": "KOMOOT", "source_ids": ["770", "426", "498", "874", "800"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1m/1mpb4k2s18xg1hzgs0iy6lwjb5bbjq688-uhi84281547/0?width=1920&crop=false"], "category_raw": "viewpoint", "tour_count": 5, "nearby_landmarks": ["오두산 통일전망대", "임진강", "헤이리 예술마을"], "confidence": "medium", "address": "대한민국 경기도 파주시 탄현면 필승로"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금강보행교', '세종시의 랜드마크인 원형 복층 교량입니다. 하층이 자전거 전용도로로 분리되어 있어 쾌적한 라이딩과 아름다운 금강 경치를 즐길 수 있습니다.', '{bridge,landmark,river,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.283751, 36.482478), 4326), false, '{"source": "KOMOOT", "source_ids": ["221", "596", "1421", "508", "213"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/15/159vk299s7pn472aei0il1bkq4z2ge9pi-uhi71952854/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1g/1ggom0fv784u8qnpyi29zha6o4z2gehv8-uhi71952856/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1g/1gak4uvee3xit1vi5q00lj28gg4z2gepk0-uhi71952858/0?width=1920&crop=false"], "tips": [{"text": "very large circle that is a bridge with a bike path!", "author": "Jesse Badash"}], "category_raw": "bridge", "tour_count": 5, "nearby_landmarks": ["세종중앙공원", "국립세종수목원", "세종시청", "금강수변공원"], "confidence": "high", "address": "F7JM+XG 대한민국 세종특별자치시"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구미보 인증센터', '낙동강 종주 자전거길의 주요 거점인 구미보 인증센터입니다. 화장실, 휴식 공간, 전망대가 마련되어 있어 라이딩 중 쉬어가기 좋습니다.', '{checkpoint,river,bridge,viewpoint,rest_area,restroom,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.347955, 36.237851), 4326), false, '{"source": "KOMOOT", "source_ids": ["303", "279", "72", "346", "467", "1484", "370", "589", "796", "151"], "image_urls": ["https://photos.komoot.de/wiki/commons/f/f0/낙동강.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3e/Andong_Bridge.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a3/Korea-Andong-Nakdong_River-02.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/58/Korea-Andong-Nakdong_River-01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f6/상주보.jpg?width=1920&crop=false"], "category_raw": "190", "tour_count": 5, "nearby_landmarks": ["구미보", "구미보 전망대"], "confidence": "high", "address": "대한민국 경상북도 구미시 해평면 월곡리 770"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('여주저류지 제방길', '남한강 자전거길에 위치한 여주저류지 제방도로입니다. 비행기 활주로처럼 넓고 곧게 뻗어 있으며, 억새와 노을 등 경관이 뛰어나 라이더들에게 인기 있는 장소입니다.', '{nature,river,park,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.584848, 37.354611), 4326), false, '{"source": "KOMOOT", "source_ids": ["425", "474", "137", "232", "413"], "category_raw": "other_natural", "tour_count": 5, "nearby_landmarks": ["남한강 자전거길", "여주저류지", "여주보", "이포보"], "confidence": "high", "address": "대한민국 경기도 여주시 대신면 당산리 110-215"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대금리 팽나무', '거제 대금마을 입구에 위치한 수령 320년의 웅장한 보호수입니다. 풍성한 그늘을 제공해 라이딩 중 잠시 땀을 식히며 쉬어가기 좋은 자연 랜드마크입니다.', '{landmark,historic,nature,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.69997, 34.969741), 4326), false, '{"source": "KOMOOT", "source_ids": ["902", "1844", "346", "800", "1140"], "category_raw": "14", "tour_count": 5, "nearby_landmarks": ["대금산", "대금마을"], "confidence": "high", "address": "대한민국 경상남도 거제시 장목면 대금리 333-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('덕포해수욕장', '거제도 해안 라이딩 중 휴식하기 좋은 한적한 해수욕장입니다. 명물인 펭귄 화장실을 비롯해 식수대, 편의점, 카페 등 편의시설이 잘 갖춰져 있습니다.', '{beach,restroom,water_fountain,convenience_store,cafe,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.71178, 34.912454), 4326), false, '{"source": "KOMOOT", "source_ids": ["1425", "1437", "2129", "1187", "631"], "category_raw": "12", "tour_count": 5, "nearby_landmarks": ["옥포대첩기념공원", "덕포랜드 씨라인"], "confidence": "high", "address": "대한민국 경상남도 거제시 덕포5길 45"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('도두 추억애거리 조각상', '제주 환상자전거길 북쪽 코스인 도두 추억애거리에 위치한 조각상입니다. 탁 트인 바다를 배경으로 제주의 옛 정취를 느끼며 사진을 남기고 쉬어가기 좋은 랜드마크입니다.', '{landmark,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.463349, 33.503976), 4326), false, '{"source": "KOMOOT", "source_ids": ["553", "55", "277", "768", "120"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/bp/bpehy0p3gpjoagoz3x151gwz5bp3f53j-uhi84614572/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/pp/pp9go90qc5l71pk126vqimxzl5bub5pi5-uhi84761853/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1i/1ic4y56g8sg8wc6kj3qy552hp5gh7mms8-uhi90681055/0?width=1920&crop=false"], "category_raw": "man_made_monument", "tour_count": 5, "nearby_landmarks": ["도두동 무지개 해안도로", "도두봉", "도두항", "이호테우 해변"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 도두일동 도공로 3-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('명동리 은행나무', '거제시 보호수 1호로 지정된 300년 수령의 거대한 은행나무입니다. 가을철 노란 단풍이 장관을 이루며, 한적한 마을에 위치해 라이딩 중 잠시 쉬며 사진 찍기 좋습니다.', '{nature,landmark,historic,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.671275, 34.947332), 4326), false, '{"source": "KOMOOT", "source_ids": ["223", "212", "1195", "227", "681"], "category_raw": "14", "tour_count": 5, "nearby_landmarks": ["명하경로당", "명하마을"], "confidence": "high", "address": "대한민국 경상남도 거제시 연초면 명동리 458-13"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('바이크 카페', '이촌 한강공원 자전거길 옆에 위치한 카페입니다. 라이딩 중 나무 그늘 아래서 커피를 마시며 여유롭게 쉬어가기 좋은 휴식처입니다.', '{cafe,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.958029, 37.517362), 4326), false, '{"source": "KOMOOT", "source_ids": ["692", "210", "844", "145", "230", "590", "101", "514", "208", "162"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1p/1p13780anttf2tqa1zpq007eo3r4sqrur-uhi32381590/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/15/152z8eau11ltl5vqt06mgw0bk3r4sqv43-uhi32381596/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/2n/2n6tw8ac1cvif9bzgdi9l3nz3r4sqyla-uhi32381601/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1o/1ocmq4l6ymunj8odmzmos4ewa45dhdnvc-uhi49000053/0?width=1920&crop=false"], "tips": [{"text": "Great Cappuccino, bike stuff and bike gear!", "author": "667 The Neighbour of the Beast"}, {"text": "The coffee shop looks nice from the outside. I didn’t stop but I will do it the next time maybe. It is next to the bike path and it seems to be a good place to relax unten shade.", "author": "kimcito"}, {"text": "Great Cappuccino, bike stuff and bike gear!", "author": ""}], "category_raw": "cafe", "tour_count": 5, "nearby_landmarks": ["이촌 한강공원", "한강대교"], "confidence": "medium", "address": "대한민국 서울특별시 용산구 이촌동 304-17"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('누모카페', '여의천 자전거길 인근에 위치한 전동 모빌리티 테마 카페(누모카페)입니다. 라이딩 중 그늘에서 휴식하며 커피를 즐기기 좋습니다.', '{cafe,bike_shop,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.052322, 37.454964), 4326), false, '{"source": "KOMOOT", "source_ids": ["692", "210", "844", "145", "230", "590", "101", "514", "208", "162"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1p/1p13780anttf2tqa1zpq007eo3r4sqrur-uhi32381590/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/15/152z8eau11ltl5vqt06mgw0bk3r4sqv43-uhi32381596/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/2n/2n6tw8ac1cvif9bzgdi9l3nz3r4sqyla-uhi32381601/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1o/1ocmq4l6ymunj8odmzmos4ewa45dhdnvc-uhi49000053/0?width=1920&crop=false"], "tips": [{"text": "Great Cappuccino, bike stuff and bike gear!", "author": "667 The Neighbour of the Beast"}, {"text": "The coffee shop looks nice from the outside. I didn’t stop but I will do it the next time maybe. It is next to the bike path and it seems to be a good place to relax unten shade.", "author": "kimcito"}, {"text": "Great Cappuccino, bike stuff and bike gear!", "author": ""}], "category_raw": "cafe", "tour_count": 5, "nearby_landmarks": ["여의천 자전거길", "청계산입구역"], "confidence": "high", "address": "대한민국 서울특별시 서초구 신원동 436-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동작대교 전망카페', '반포와 이촌을 잇는 동작대교 자전거길입니다. 자전거 승강기를 통해 다리로 진입할 수 있으며, 다리 위 전망카페에서 한강 노을을 감상하며 휴식하기 좋습니다.', '{bridge,river,viewpoint,cafe,rest_area,transit,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.981023, 37.50583), 4326), false, '{"source": "KOMOOT", "source_ids": ["210", "89", "77", "57", "102"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/zh/zh3dnf4qrd5f1gxazla1rwm3834j4hay5-uhi8101961/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/11/115vbkkn225r2u6jsm2l1vqw93ciqpfz1-uhi11871941/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 5, "nearby_landmarks": ["동작대교 전망카페(구름카페, 노을카페)", "동작역", "반포한강공원"], "confidence": "high", "address": "대한민국 서울특별시 동작대교전망카페"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('안동 법흥사지 칠층전탑', '국내 최대 규모의 통일신라시대 칠층전탑입니다. 자전거에서 잠시 내려 기단부에 새겨진 정교한 고대 석조 조각들을 감상해 보세요.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.746784, 36.565871), 4326), false, '{"source": "KOMOOT", "source_ids": ["32", "31", "130", "1065", "148"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/12/12jxvgesgz6yz1sa12k3bd4sdm4ryikxae-uhi67146106/0?width=1920&crop=false"], "tips": [{"text": "Make sure you take a close look - there are very old stone carvings on the base", "author": "CyclingGravel"}], "category_raw": "man_made_monument", "tour_count": 5, "nearby_landmarks": ["임청각", "고성이씨 탑동파 종택"], "confidence": "high", "address": "대한민국 경상북도 안동시 법흥동 7-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('벵디못', '제주 한림읍 금악리에 위치한 고즈넉한 자연 연못입니다. 금오름 인근에 자리하여 라이딩 중 제주의 평화로운 풍경을 감상하며 잠시 쉬어가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.29604, 33.357874), 4326), false, '{"source": "KOMOOT", "source_ids": ["143", "630", "98", "765", "264"], "category_raw": "190", "tour_count": 5, "nearby_landmarks": ["금오름", "금악마을"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 한림읍 금악리 2108-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('뿌리공원 만성교', '유등천 자전거길과 연결된 야간 라이딩 명소 만성교입니다. 화려한 야경을 감상하기 좋으나, 다리 너머 뿌리공원 내부로는 자전거 반입이 금지되어 있으니 주의하세요.', '{bridge,landmark,viewpoint,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.38492, 36.284961), 4326), false, '{"source": "KOMOOT", "source_ids": ["357", "338", "8", "493", "183"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1q/1qw3awm25yeyzdoww39wljeee5dsm5zjb-uhi87112999/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1x/1xxprooapbuj8xt3a5vjbaytl5dsm61cl-uhi87113001/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/9g/9glan5ja7wgf9q6wuvxmqbgu5dsm62pg-uhi87113004/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 5, "nearby_landmarks": ["유등천", "뿌리공원", "한국족보박물관"], "confidence": "high", "address": "대한민국 대전광역시 중구 안영동 71-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('서울고속버스터미널', '장거리 라이딩 전후 자전거를 싣고 시외로 이동(점프)하기 좋은 핵심 교통 거점입니다. 반포한강공원 자전거길과 인접해 접근성이 뛰어납니다.', '{transit,convenience_store,restaurant,restroom,cafe}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.004816, 37.50503), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 5, "nearby_landmarks": ["반포한강공원", "잠수교", "신세계백화점 강남점"], "confidence": "high", "address": "-dong, 반포4동 서초구 서울특별시 대한민국"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('송산역', '의정부 경전철 송산역입니다. 부용천 자전거길과 가까워 접근성이 좋으며, 자전거 보관소와 공공자전거 대여소가 있어 라이딩 출발이나 연계 거점으로 활용하기 좋습니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.087219, 37.737255), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/4/48/U124_Songan_01.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 5, "nearby_landmarks": ["부용천 자전거길", "다리목근린공원"], "confidence": "high", "address": "대한민국 의정부시 용현동 송산"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신천 남구 자전거 수리센터', '대구 도심을 가로지르는 쾌적한 신천 자전거길입니다. 이천동 둔치에 무료 자전거 수리센터와 공기주입기가 있어 라이딩 중 정비와 휴식을 하기에 매우 좋습니다.', '{river,bike_shop,rest_area,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.607697, 35.854574), 4326), false, '{"source": "KOMOOT", "source_ids": ["366", "300", "62", "367", "722"], "image_urls": ["https://photos.komoot.de/wiki/commons/6/68/Daegu_Sincheon_ducks.jpg?width=1920&crop=false"], "category_raw": "190", "tour_count": 5, "nearby_landmarks": ["신천자전거길", "희망교", "남구 자전거수리센터"], "confidence": "high", "address": "대한민국 대구광역시 남구 이천동 121-380"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('여주역', '경강선의 종착역으로 남한강 자전거길 종주를 시작하거나 끝내는 라이더들의 주요 대중교통 거점입니다.', '{transit,restroom,convenience_store,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.628626, 37.282451), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/e/e9/Yeoju_Station_Panorama_(night).jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/45/Gyeonggang_Line_Yeoju_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/89/Yeoju_stn_1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/35/Yeoju_Station_Plaza.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c9/Yeoju_Station_Mural_1.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 5, "nearby_landmarks": ["남한강 자전거길", "여주보", "강천보", "신륵사"], "confidence": "high", "address": "대한민국 여주시 여주역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('여천역', '여수 자전거 여행의 주요 출발점이 되는 KTX 정차역입니다. 편의점, 화장실, 카페 및 자전거 보관대가 있어 라이딩 전후 휴식과 정비에 좋습니다.', '{transit,restroom,convenience_store,cafe,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.664606, 34.779142), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/6e/Korail_Yeocheon_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f7/Yeocheon_Station.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 5, "nearby_landmarks": ["전라선 옛 철길 자전거도로", "여수시 자전거 문화센터(구 여천역)"], "confidence": "high", "address": "대한민국 전라남도 여수시 여천동 900-32"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('연초호', '거제 연초면에 위치한 조용한 저수지로, 대금산이나 국사봉으로 향하는 라이딩 코스의 주요 길목입니다. 한적한 수변 풍경을 즐기며 달리기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.669726, 34.939739), 4326), false, '{"source": "KOMOOT", "source_ids": ["705", "1171", "199", "188", "251"], "category_raw": "190", "tour_count": 5, "nearby_landmarks": ["연초댐", "대금산", "국사봉"], "confidence": "high", "address": "대한민국 경상남도 거제시 연초면 이목리 산115-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('서창감성조망대', '영산강 자전거길에 위치한 노을 명소 ''서창감성조망대''입니다. 억새밭과 강변 풍경을 감상하며 라이딩 중 쉬어가기 좋은 랜드마크입니다.', '{viewpoint,rest_area,landmark,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.819788, 35.109235), 4326), false, '{"source": "KOMOOT", "source_ids": ["87", "289", "824", "266", "350"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/mu/munim3ba0hnk8ynzvp7eiubq5k237t08-uhi95565236/0?width=1920&crop=false"], "category_raw": "viewpoint", "tour_count": 5, "nearby_landmarks": ["영산강 자전거길", "서창포구", "서창 억새밭"], "confidence": "high", "address": "대한민국 광주광역시 서구 서창동 589-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('원주역', '강원도 자전거 여행의 주요 출발지인 중앙선 KTX 정차역입니다. 섬강 자전거길과 치악산 코스 접근성이 좋으며 공영자전거 대여소가 있습니다.', '{transit,restroom,convenience_store,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.922842, 37.316633), 4326), false, '{"source": "KOMOOT", "source_ids": ["83", "42"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/f1/f1dzon69slzrm8w9r04z5y5a3riog7xt-uhi32886854/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1s/1s8c92sxolnea1pqlscsgzw5if3rioi3uj-uhi32886873/0?width=1920&crop=false"], "tips": [{"text": "Wonju station is a railway station in the city of Wonju, Gangwon province, South Korea. It is on the Jungang Line.", "author": "AsuRa"}], "category_raw": "219", "tour_count": 5, "nearby_landmarks": ["섬강 자전거길", "치악산 바람숲길", "무실동 상업지구"], "confidence": "high", "address": "대한민국 강원특별자치도 원주시 무실동 754-11"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('유등천', '대전 3대 하천 중 하나인 유등천입니다. 갑천과 이어지는 평탄하고 쾌적한 자전거 전용도로가 잘 조성되어 있어 도심 속 라이딩을 즐기기 좋습니다.', '{river,nature,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.383517, 36.300548), 4326), false, '{"source": "KOMOOT", "source_ids": ["202", "111", "285", "421", "266"], "category_raw": "190", "tour_count": 5, "nearby_landmarks": ["뿌리공원", "사정교", "안영교"], "confidence": "high", "address": "대한민국 대전광역시 중구 사정동 452-13"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('이호테우해변', '제주환상자전거길의 주요 경유지로, 유명한 말등대를 배경으로 인증샷을 남기기 좋은 해변입니다. 공항과 가까워 라이딩 시작이나 마무리 코스로 적합합니다.', '{beach,viewpoint,landmark,rest_area,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.452219, 33.497193), 4326), false, '{"source": "KOMOOT", "source_ids": ["711", "86", "60", "110", "63"], "category_raw": "12", "tour_count": 5, "nearby_landmarks": ["이호테우 말등대", "제주국제공항", "도두동 무지개해안도로"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 이호일동 1781-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('장회교', '충주호와 구담봉, 제비봉의 절경을 감상할 수 있는 국도 36호선 상의 교량입니다. 단양 청풍명월 라이딩 코스의 주요 길목으로 경치가 매우 뛰어납니다.', '{bridge,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.251183, 36.929773), 4326), false, '{"source": "KOMOOT", "source_ids": ["927", "828", "718", "1194", "323"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/rl/rlf49nvq8e6o1n7ydpuheojqq37eohix6-uhi9479855/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/2r/2ra5b2cl2h301xq6klfgv0k5r37eohjb0-uhi9479856/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 5, "nearby_landmarks": ["장회나루", "구담봉", "제비봉", "충주호"], "confidence": "high", "address": "대한민국 충청북도 단양군 단성면 장회리 121-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('중흥저수지', '대전 근교에서 평지 위주의 한적한 라이딩 코스로 사랑받는 저수지입니다. 둘레길과 수령 320년의 신촌 느티나무 등 고즈넉한 풍경을 즐기며 쉬어가기 좋습니다.', '{lake,rest_area,viewpoint,parking,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.173263, 36.572606), 4326), false, '{"source": "KOMOOT", "source_ids": ["320", "285", "377", "362", "445"], "category_raw": "190", "tour_count": 5, "nearby_landmarks": ["신촌 느티나무", "도신교"], "confidence": "high", "address": "대한민국 충청남도 공주시 의당면 중흥리 518-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('의암호 전망대', '의암댐 인근 자전거길에서 만나는 탁 트인 의암호 뷰포인트입니다. 라이딩 중 주변 카페에 들러 호수 풍경을 감상하며 휴식하기 좋습니다.', '{lake,viewpoint,cafe,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.677098, 37.83792), 4326), false, '{"source": "KOMOOT", "source_ids": ["1627", "234", "586", "186", "184"], "category_raw": "lake", "tour_count": 5, "nearby_landmarks": ["의암댐", "의암호 자전거길", "삼악산 호수케이블카"], "confidence": "medium", "address": "대한민국 춘천시 의암댐"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('탄천어울림공원', '탄천 자전거길(광평교 인근)과 인접한 무장애 공원입니다. 평탄한 산책로와 휴게 시설이 잘 갖춰져 있어 라이딩 중 편안하게 쉬어가기 좋습니다.', '{park,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.106831, 37.487597), 4326), false, '{"source": "KOMOOT", "source_ids": ["96", "166", "225", "440", "746"], "category_raw": "191", "tour_count": 5, "nearby_landmarks": ["탄천 자전거길", "수서역", "광평교"], "confidence": "high", "address": "대한민국 서울특별시 강남구 수서동 722-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('탄천 합수부 그래피티', '탄천과 한강이 만나는 합수부(탄합) 고가 아래의 그래피티입니다. 자전거 도로가 잘 정비되어 있어 라이더들의 주요 만남의 광장이자 휴식처로 사랑받는 곳입니다.', '{landmark,rest_area,bridge,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.065805, 37.518655), 4326), false, '{"source": "KOMOOT", "source_ids": ["204", "64", "138", "28", "177"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/11/112rp9iziarnw1r5n3u8q59gsa4qgj8gzz-uhi66002213/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/5t/5ty2ugndnye4jofy17q5vegx4qgj8h7r-uhi66002215/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/gd/gd4yg439ujne1ftrc1w0pkid54qgj8gx6-uhi66002212/0?width=1920&crop=false"], "tips": [{"text": "Nice area with good bike lanes.", "author": "Dirkster"}], "category_raw": "other_man_made", "tour_count": 5, "nearby_landmarks": ["탄천 한강 합수부", "청담대교", "잠실종합운동장"], "confidence": "high", "address": "대한민국 서울특별시 강남구 삼성동 185-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('반포한강공원 피크닉장', '라이딩 중 휴식하기 좋은 반포한강공원 피크닉장입니다. 주차장과 편의점이 가깝고 나무 그늘이 있어, 한강을 보며 간식을 즐기고 재충전하기 좋습니다.', '{park,rest_area,parking,river,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.994456, 37.509972), 4326), false, '{"source": "KOMOOT", "source_ids": ["337", "112", "64", "228", "98"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1r/1rp8troh93o3yfypd5gcz9ai7563yd37s-uhi80537999/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/10/100mfp62d3j4g161ype3bbry1y563yd691-uhi80538003/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/5y/5yde5azm9fyx4qtsq231ew9f563yd693-uhi80538004/0?width=1920&crop=false"], "tips": [{"text": "Perfekter Platz fürs abendliche Picknick. Hier gibt’s einen großen Parkplatz und Möglichkeiten zum Essen einkaufen. Der Park erstreckt sich bis zum Fluss und ist teils mit Bäumen bestanden, die Schatten spenden.", "author": "Su"}], "category_raw": "facilities", "tour_count": 5, "nearby_landmarks": ["반포대교", "세빛섬", "잠수교", "달빛무지개분수"], "confidence": "high", "address": "대한민국 서울특별시 서초구 반포동 115-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('해밀동', '원수산 MTB 공원과 BMX 경기장이 인접해 산악자전거를 즐기기 좋은 자전거 친화 마을입니다. 네덜란드식 자전거 교차로와 해밀단길 상권이 있어 라이딩 중 휴식하기 좋습니다.', '{park,mountain,cafe,restaurant,rest_area,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.263962, 36.528727), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 5, "nearby_landmarks": ["원수산 MTB 공원", "BMX 경기장", "해밀단길", "원수천"], "confidence": "high", "address": "대한민국 세종특별자치시 해밀리"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('해운대 해수욕장', '부산을 대표하는 해변으로 해안 라이딩 시 멋진 경치를 즐기며 쉬어가기 좋은 필수 경유지입니다. 보행자가 많아 산책로에서는 서행 및 주의가 필요합니다.', '{beach,landmark,viewpoint,rest_area,restroom,convenience_store,cafe}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.16079, 35.159059), 4326), false, '{"source": "KOMOOT", "source_ids": ["25", "262", "159", "156"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/k2/k258znkpchdslj5a2a725e6c30tz7shd-uhi6500072/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1d/1dfiks8f0b7446u31kxrn1vtq3qvv3v34-uhi31942133/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/ai/aibnvax5b7c015tyyre0t1up4ppyi8lh-uhi65169426/0?width=1920&crop=false"], "category_raw": "beach", "tour_count": 5, "nearby_landmarks": ["동백섬", "달맞이길", "엘시티(LCT)"], "confidence": "high", "address": "대한민국 부산광역시 해운대구 중동 1415-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('행주대교에서 보는 일몰 전망', '행주대교 위 또는 인근 자전거길에서 한강의 아름다운 일몰을 감상할 수 있는 뷰포인트입니다. 탁 트인 시야와 붉은 노을이 어우러져 라이딩 중 멋진 사진을 남기기 좋습니다.', '{viewpoint,bridge,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.719669, 37.655427), 4326), false, '{"source": "KOMOOT", "source_ids": ["515", "307", "262", "322", "115"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1k/1k4j9aqisflu21i0u4hcoxb4r74o6yh1ce-uhi63501781/0?width=1920&crop=false"], "category_raw": "viewpoint", "tour_count": 5, "nearby_landmarks": ["행주대교", "행주산성", "한강 자전거길"], "confidence": "medium", "address": "MP49+5V 대한민국 경기도 고양시"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('명달리 헤어핀 포토존', '동부 5고개 코스 중 명달리 업힐 정상 직전에 위치한 유명한 헤어핀 포토존입니다. 멋진 라이딩 사진을 남기기 좋으나 코너를 도는 차량 통행에 주의해야 합니다.', '{viewpoint,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.434, 37.61084), 4326), false, '{"source": "KOMOOT", "source_ids": ["337", "461", "881", "336", "401"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1p/1ptufviv0q68zztz1tv3m5x1z564wfeyc-uhi80557044/0?width=1920&crop=false"], "category_raw": "viewpoint", "tour_count": 5, "nearby_landmarks": ["명달리 정상", "농부네쉼터", "서후고개"], "confidence": "high", "address": "대한민국 경기도 양평군 서종면 정배리 산56-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('화명', '부산 지하철 2호선 화명역 인근의 도심 지점으로, 주변에 식당과 편의시설이 밀집해 있어 라이딩 중 휴식과 보급을 하기에 좋습니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.013773, 35.235255), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/51/Busan-subway-235-Hwamyeong-station-5-entrance.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6e/Hwamyeong_station_sign_20180506_212045.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/85/Hwamyeong_station_platform_20180506_212003.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d8/Busan-subway-235-Hwamyeong-station-platform.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b1/Busan-subway-235-Hwamyeong-station-5-entrance-elevator.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 5, "nearby_landmarks": ["화명역", "화명생태공원"], "confidence": "medium", "address": "대한민국 부산광역시 북구 화명동 1472-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('후미개고개', '남한강 자전거길 양평~이포보 구간의 대표적인 업힐(경사도 10% 이상) 코스입니다. 짧고 굵은 난이도로 많은 라이더들이 PR에 도전하는 주요 랜드마크입니다.', '{mountain,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.519798, 37.442569), 4326), false, '{"source": "KOMOOT", "source_ids": ["209", "1504", "140", "1439", "120"], "category_raw": "21", "tour_count": 5, "nearby_landmarks": ["남한강 자전거길", "이포보", "개군저수지"], "confidence": "high", "address": "대한민국 경기도 양평군 개군면 구미리 100-20"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('GS25 한강 뚝섬 3호점', '뚝섬 한강공원 내 야외 좌석이 많은 대형 편의점입니다. 마포, 행주 등 서쪽이나 중랑천 등 북쪽으로 향하는 라이딩의 만남의 장소 및 휴식처로 추천합니다.', '{convenience_store,rest_area,park,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.063303, 37.530464), 4326), false, '{"source": "KOMOOT", "source_ids": ["96", "77", "98", "103"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1k/1k2fs3v303ml1oeqox6z0fw2k3eiuoxnw-uhi14977959/0?width=1920&crop=false"], "tips": [{"text": "Great stop off for routes originating or terminating around Mapo, Haengju or Goyang area. Could make a good meet-up if heading north or west of this area. This is a huge store with lots of exterior seating in summer months, I haven’t used facilities but imagine this one caters well for winter use given size. Will make a note to check out next time passing. \n\nLocal convenience stores are plentiful, especially on the river path around Seoul, these are great for both hot and cold snacks. Some also have covered or indoor areas for use during winter, as well as hot water, microwaves and Ramyun making machines. These maybe not be on par with “Japanese convini” according to some but they are not to be sniffed at, especially when riding and water or a quick snack is required. These surpass anything similar in the west. Look out of Mini-Stop, GS24, Seven Eleven, CU and E-mart.", "author": "Jon"}, {"text": "Great stop off for routes originating or terminating around Mapo, Haengju or Goyang area. Could make a good meet-up if heading north or west of this area. This is a huge store with lots of exterior seating in summer months, I haven’t used facilities but imagine this one caters well for winter use given size. Will make a note to check out next time passing. \n\nLocal convenience stores are plentiful, especially on the river path around Seoul, these are great for both hot and cold snacks. Some also have covered or indoor areas for use during winter, as well as hot water, microwaves and Ramyun making machines. These maybe not be on par with “Japanese convini” according to some but they are not to be sniffed at, especially when riding and water or a quick snack is required. These surpass anything similar in the west. Look out of Mini-Stop, GS24, Seven Eleven, CU and E-mart.", "author": ""}], "category_raw": "facilities", "tour_count": 4, "nearby_landmarks": ["뚝섬 한강공원", "청담대교", "자양역(구 뚝섬유원지역)"], "confidence": "high", "address": "대한민국 서울특별시 광진구 자양동 102-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구스티모 이촌점', '이촌한강공원 자전거길 인근에 위치해 라이딩 중 젤라또로 당 충전하기 좋은 카페입니다. 현재는 폐업 가능성이 있어 방문 전 확인이 필요합니다.', '{cafe,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.98057, 37.517881), 4326), false, '{"source": "KOMOOT", "source_ids": ["723", "160", "12", "102"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1t/1t2x519pqxokrcfbmar2k3cjy3tgvu453-uhi36103474/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/l7/l7j66a2rtiso1r36599rqnzgk3u3dq8eh-uhi36981549/0?width=1920&crop=false"], "category_raw": "cafe", "tour_count": 4, "nearby_landmarks": ["이촌한강공원", "래미안 첼리투스", "렉스상가"], "confidence": "medium", "address": "대한민국 서울특별시 용산구 이촌로 300 6-2호"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동량대교', '2021년 개통된 충주 용탄동과 동량면을 연결하는 동량대교입니다. 남한강 위를 지나며 자전거 통행이 가능해 주변 자전거길 코스로 자주 이용됩니다.', '{bridge,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.961056, 37.021829), 4326), false, '{"source": "KOMOOT", "source_ids": ["120", "2040", "248", "238"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1s/1sb89ltzcg2cxqvfos2v2rmxs47fi3li7-uhi50831707/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 4, "nearby_landmarks": ["남한강", "충주댐"], "confidence": "high", "address": "대한민국 충청북도 충주시 용탄동 132-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('KTX 강릉역', '동해안 자전거길 라이딩의 주요 출발지이자 도착지인 KTX 강릉역입니다. 역사 내 화장실, 편의점, 물품 보관소 등 다양한 편의시설을 이용할 수 있습니다.', '{transit,landmark,restroom,convenience_store,cafe}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.899042, 37.764303), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/3/3a/KTX_Gangneung_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/13/Gangneung_Station_20220502_006.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d2/Press_Tour_KTX_Gyeonggang_Line_10.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/ed/Gangneung_station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/75/Gangneung_Station.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 4, "nearby_landmarks": ["월화거리", "강릉중앙시장"], "confidence": "high", "address": "대한민국 강원특별자치도 강릉시 교동 1494-24"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('강창역', '대구 2호선 강창역 인근으로 금호강 자전거길 및 강창교와 가깝습니다. 대중교통 연계 라이딩 출발지나 달성습지 방면 경유지로 활용하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.478076, 35.853096), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/6b/Gangchang_Station_20180217_122338_4287_photo.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/be/Gangchang_Station_20180217_123337_4286_photo.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b8/Daegu-metropolitan-transit-corporation-219-Gangchang-station-entrance-5-20161010-154036.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 4, "nearby_landmarks": ["강창교", "금호강 자전거길", "달성습지", "계명대학교 동산병원"], "confidence": "high", "address": "대한민국 대구광역시 신당동 강창"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('아라뱃길 아라마루 휴게소', '경인아라뱃길 자전거길 종주 중 쉬어가기 좋은 수변 테마공원입니다. 자전거 대여소, 편의점, 화장실 등 편의시설이 잘 갖춰져 있어 라이더들의 만남의 광장 역할을 합니다.', '{rest_area,park,river,bike_shop,parking,restroom,convenience_store,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.772263, 37.583034), 4326), false, '{"source": "KOMOOT", "source_ids": ["1721", "432", "1756", "274"], "category_raw": "cycle_way", "tour_count": 4, "nearby_landmarks": ["경인아라뱃길", "벌말교"], "confidence": "high", "address": "대한민국 인천광역시 계양구 평동 24-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('고기저수지', '지리산 정령치 업힐(남원 방향) 초입에 위치한 저수지입니다. 본격적인 급경사가 시작되기 전 수려한 풍경을 감상하며 호흡을 고르기 좋은 이정표입니다.', '{lake,nature,landmark,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.506536, 35.377396), 4326), false, '{"source": "KOMOOT", "source_ids": ["409", "1375", "438", "407"], "category_raw": "190", "tour_count": 4, "nearby_landmarks": ["정령치", "고기삼거리", "육모정"], "confidence": "high", "address": "대한민국 전북특별자치도 남원시 주천면 정령치로 999"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('고성내산리고분군', '동해면 해안도로 라이딩 코스에 위치한 소가야 시대 고분군입니다. 탁 트인 바다 풍경과 함께 역사적 유적을 감상하며 쉬어가기 좋은 포인트입니다.', '{historic,landmark,viewpoint,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.453243, 35.045285), 4326), false, '{"source": "KOMOOT", "source_ids": ["169", "871", "474", "890"], "category_raw": "15", "tour_count": 4, "nearby_landmarks": ["동해면 해안도로", "마동호", "당항포관광지"], "confidence": "high", "address": "대한민국 경상남도 고성군 동해면 양촌리 668-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금호강', '대구와 경산을 잇는 금호강 자전거길 구간으로, 탁 트인 강변 풍경을 감상하며 평탄하게 달리기 좋은 코스입니다.', '{river,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.823079, 35.907092), 4326), false, '{"source": "KOMOOT", "source_ids": ["143", "13", "914", "160", "310", "540", "70", "159", "845", "330"], "image_urls": ["https://photos.komoot.de/wiki/commons/d/df/GeumhoriverYC.jpg?width=1920&crop=false"], "category_raw": "190", "tour_count": 4, "nearby_landmarks": ["금호강 자전거길", "환상리 자전거 오아시스", "대구대학교"], "confidence": "high", "address": "대한민국 경상북도 경산시 진량읍 부기리 624-250"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남한강', '충주댐 인증센터로 향하는 남한강 자전거길 구간입니다. 탁 트인 남한강의 수려한 경치를 감상하며 시원하게 라이딩을 즐길 수 있습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.964154, 37.018818), 4326), false, '{"source": "KOMOOT", "source_ids": ["223", "2025", "140", "253", "233"], "image_urls": ["https://photos.komoot.de/wiki/commons/b/b6/Hangang-s-big.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b7/Korea-Seoul-Han_River-01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/5b/Seoul-Han.River-01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/34/Hangang_Railway_Bridge.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e5/한강경찰대_망원한강치안센터.JPG?width=1920&crop=false"], "category_raw": "190", "tour_count": 4, "nearby_landmarks": ["남한강 자전거길", "충주댐", "목행교"], "confidence": "high", "address": "대한민국 충청북도 충주시 용탄동 126-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('내도몽돌해변', '제주 환상자전거길에 위치한 몽돌 해변(알작지)입니다. 파도와 조약돌이 부딪히는 소리를 들으며 라이딩 중 잠시 쉬어가기 좋은 아름다운 자연 명소입니다.', '{beach,viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.439629, 33.495897), 4326), false, '{"source": "KOMOOT", "source_ids": ["135", "686", "133", "38"], "category_raw": "12", "tour_count": 4, "nearby_landmarks": ["알작지", "제주환상자전거길", "이호테우해변"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 내도동 515-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('노현지', '청주시 문의면에 위치한 조용하고 경치 좋은 저수지입니다. 피반령이나 대청호 주변 코스와 연계하여 자연 경관을 즐기며 라이딩하기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.550209, 36.51508), 4326), false, '{"source": "KOMOOT", "source_ids": ["378", "818", "520", "457"], "category_raw": "190", "tour_count": 4, "nearby_landmarks": ["대청호", "피반령"], "confidence": "high", "address": "대한민국 충청북도 청주시 상당구 문의면 노현리 산1-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('도로니 연못', '해발 1,000m 고지대 운탄고도 라이딩 코스의 백미인 생태 연못입니다. 과거 탄광 갱도가 침하되어 만들어진 곳으로, 신비로운 숲속 풍경을 감상하며 휴식하기 좋습니다.', '{lake,nature,historic,rest_area,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.81048, 37.1894), 4326), false, '{"source": "KOMOOT", "source_ids": ["845", "251", "799", "1081"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1v/1v3z4px74elbklo1nilv6sa5937ddw27b-uhi9471650/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1p/1pckgln90152r1t45f014j06ih37ddw2l6-uhi9471652/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/qb/qbph2ufcsmyt1idpbir2jcmek3kd4lwra-uhi25436227/0?width=1920&crop=false"], "category_raw": "lake", "tour_count": 4, "nearby_landmarks": ["운탄고도", "하이원리조트", "백운산"], "confidence": "high", "address": "대한민국 강원특별자치도 정선군 사북읍 사북리"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('도봉천 합수부', '도봉천과 중랑천이 만나는 지점으로, 중랑천 자전거길을 이용하는 라이더들이 코스를 전환하거나 쉬어가는 주요 합수부입니다.', '{river,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.050537, 37.679402), 4326), false, '{"source": "KOMOOT", "source_ids": ["68", "611", "426", "16"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/a7/a7gl4ghepc2xzkin6gn6qpsq3bs7v8jq-uhi11260416/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1f/1fobzh803uaji1nazs1j4abyo83bs7vs8z-uhi11260432/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/16/16dzx7mvpk7ykiazbrepigwzi3hhijkhl-uhi20456675/0?width=1920&crop=false"], "tips": [{"text": "Where Dobongcheon flows into Joongrangcheon", "author": "AsuRa"}, {"text": "Where Dobongcheon flows into Joongrangcheon", "author": ""}], "category_raw": "river", "tour_count": 4, "nearby_landmarks": ["노원교", "도봉1교", "중랑천 자전거길"], "confidence": "high", "address": "대한민국 서울특별시 도봉구 도봉동 643-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동막해변', '강화도 일주 코스의 주요 경유지로 낙조가 아름다운 해변입니다. 편의시설과 식당이 많아 보급하기 좋으나, 주변 도로는 차량이 많고 갓길이 좁아 라이딩 시 주의해야 합니다.', '{beach,viewpoint,rest_area,convenience_store,cafe,restaurant,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.459099, 37.592501), 4326), false, '{"source": "KOMOOT", "source_ids": ["439", "1144", "1407", "1867"], "category_raw": "12", "tour_count": 4, "nearby_landmarks": ["마니산", "함허동천", "정수사"], "confidence": "high", "address": "대한민국 인천광역시 강화군 화도면 동막리 5-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동백역', '용인 경전철(에버라인) 동백역입니다. 에버라인은 접이식을 포함한 모든 자전거의 휴대 승차가 전면 금지되어 있으니 라이딩 코스 계획 시 유의하세요.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.152517, 37.268899), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/f/f0/Busan-subway-204-Dongbaek-station-4-entrance.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8f/Dongbaek_station_sign_20180317_211051.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8b/Dongbaek_Station_20200522_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/64/Dongbaek_station_platform_20180317_211033.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a3/Busan-subway-204-Dongbaek-station-platform.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 4, "nearby_landmarks": ["동백호수공원", "용인세브란스병원"], "confidence": "high", "address": "대한민국 경기도 용인시 기흥구 중동 462번지 1층"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('뚝섬 한강공원 인증센터', '한강 자전거길 국토종주 스탬프를 찍을 수 있는 무인 인증센터입니다. 영동대교 상류 부근 자전거길이 갈라지는 분기점 중앙 교통섬에 빨간 부스 형태로 위치해 있습니다.', '{checkpoint,park,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.059783, 37.532235), 4326), false, '{"source": "KOMOOT", "source_ids": ["27", "105", "107", "110"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/xo/xo29zc66xaqs1hyh0a65nw1rc3eiuw2yq-uhi14978272/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/85/85khrxlbjfebjaecnctinvx744xgq6ba-uhi48544911/0?width=1920&crop=false"], "tips": [{"text": "The red “phone box” stamp certification location is in the middle island where the bike path forks.", "author": ""}, {"text": "The red “phone box” stamp certification location is in the middle island where the bike path forks.", "author": "Jon"}], "category_raw": "cycle_way", "tour_count": 4, "nearby_landmarks": ["뚝섬한강공원", "영동대교", "청담대교"], "confidence": "high", "address": "대한민국 서울특별시 광진구 자양동 158-17"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('마사터널', '낙동강 자전거길의 폐터널을 리모델링한 자전거 통행 터널입니다. 자전거 카페, 화장실, 쉼터 광장이 잘 갖춰져 있어 라이딩 중 휴식하기 좋습니다.', '{tunnel,cafe,restroom,rest_area,parking,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.810958, 35.355814), 4326), false, '{"source": "KOMOOT", "source_ids": ["211", "567", "775", "186"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1a/1a98tpee3zp78462g4h6efhs55m0ds5p-uhi79959961/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/bj/bjccrk2e8viaxm79el97zkmf35vugtm9-uhi8971618/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1q/1qxs8k8wzfblgmyuzphvtfvln55m0dx24-uhi79959963/0?width=1920&crop=false"], "category_raw": "other_man_made", "tour_count": 4, "nearby_landmarks": ["낙동강레일파크", "생림오토캠핑장", "마사1구 예술마을"], "confidence": "high", "address": "대한민국 경상남도 김해시 생림면 금곡로 382"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('부흥산공원 인공폭포', '영산강 자전거길 인근 부흥산공원에 위치한 인공폭포입니다. 매점과 자전거 보관소가 있어 라이딩 중 시원한 폭포를 보며 쉬어가기 좋은 랜드마크입니다.', '{landmark,park,rest_area,convenience_store,parking,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.439669, 34.802904), 4326), false, '{"source": "KOMOOT", "source_ids": ["827", "315", "883", "72"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/dm/dmefgbx15gjx17q8ry3v71on237e4gvvx-uhi9476333/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/kd/kdx4x1dkjnq41u3ejjacct3t737e4gwkd-uhi9476334/0?width=1920&crop=false"], "category_raw": "waterfall", "tour_count": 4, "nearby_landmarks": ["영산강 하굿둑", "부흥산공원", "평화광장"], "confidence": "high", "address": "대한민국 전라남도 목포시 옥암동 1124-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('바람재 휴게소', '세종시 라이더들의 필수 업힐 코스인 바람재 정상에 위치한 쉼터입니다. 정자와 화장실이 있어 등반 후 휴식하기 좋으며, 탁 트인 경치를 감상할 수 있습니다.', '{rest_area,restroom,parking,viewpoint,mountain}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.32422, 36.447549), 4326), false, '{"source": "KOMOOT", "source_ids": ["328", "191", "316", "555"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/cu/cu9ge374sfm3vfs9gcyb5jct5f4s22be-uhi88882594/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/zd/zd9u3dfijai8qgn2guicjd25f4s232i-uhi88882595/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/14/14fourdd60xn3il4zl6hrrs8x5f4s25dg-uhi88882597/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 4, "nearby_landmarks": ["소소루 카페", "비학산~금병산 누리길"], "confidence": "high", "address": "대한민국 세종특별자치시 금남면 영대리 777-13"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('배후령', '평균 8% 경사도가 꾸준히 이어지는 춘천의 대표적인 힐클라임 코스입니다. 자전거 우선도로로 지정되어 노면이 좋고 차량 통행이 적어 안전하게 오를 수 있습니다.', '{mountain,checkpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.787779, 37.981105), 4326), false, '{"source": "KOMOOT", "source_ids": ["1015", "1604", "301"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/7q/7qve7cbf3t85rs4l2c4hug164zp3umvm-uhi72807111/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1u/1ubpcz5o9fy5co38argvkwq0a4zp3ur1f-uhi72807115/0?width=1920&crop=false"], "tips": [{"text": "this is a steep climb and it sent at consistently 8% (with some sections a bit above).  but there is a nice 2 hour hike at the top to Obongson mountain, and the road is in good shape, very quiet, with a climbing lane for the climber.", "author": "Jesse Badash"}], "category_raw": "climb", "tour_count": 4, "nearby_landmarks": ["오봉산", "배후령터널", "청평사"], "confidence": "high", "address": "XQJQ+C4 대한민국 강원특별자치도 춘천시"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('화랑공원 생태림', '판교 화랑공원 내 위치한 생태림입니다. 운중천과 탄천 자전거길이 인접해 있어 라이딩 중 자연을 감상하며 가볍게 쉬어가기 좋은 장소입니다.', '{park,nature,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.104446, 37.397783), 4326), false, '{"source": "KOMOOT", "source_ids": ["499", "543", "62", "589"], "category_raw": "191", "tour_count": 4, "nearby_landmarks": ["화랑공원", "판교환경생태학습원", "판교테크노밸리"], "confidence": "high", "address": "대한민국 경기도 성남시 분당구 삼평동 637"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('석봉', '평택 안성천 자전거길 인근 팽성읍 석봉리에 위치한 작은 야산(언덕)입니다. 탁 트인 농촌 풍경과 하천변을 따라 여유로운 라이딩을 즐기기 좋은 구간입니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.03962, 36.985343), 4326), false, '{"source": "KOMOOT", "source_ids": ["61", "125", "44"], "category_raw": "21", "tour_count": 4, "nearby_landmarks": ["안성천", "석봉낚시터"], "confidence": "medium", "address": "대한민국 경기도 평택시 팽성읍 석봉리 105-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('석장리박물관', '금강 자전거길과 바로 연결된 구석기 유적 박물관입니다. 화장실과 주차장 등 편의시설이 잘 갖춰져 있어 라이딩 중 휴식과 역사 탐방을 겸하기 좋습니다.', '{museum,historic,restroom,parking,river,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.186788, 36.447676), 4326), false, '{"source": "KOMOOT", "source_ids": ["394", "1187", "592", "323"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/2b/2b68xhyrhjcf1p0c8it7gh2083xohbzpo-uhi42660019/0?width=1920&crop=false"], "category_raw": "historical_site", "tour_count": 4, "nearby_landmarks": ["금강", "금강신관공원", "공산성"], "confidence": "high", "address": "대한민국 충청남도 공주시 석장리동 104-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('성내천', '한강과 올림픽공원을 잇는 쾌적한 도심 하천 자전거길입니다. 보행로와 자전거도로가 잘 분리되어 있어 안전한 라이딩이 가능합니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.116013, 37.523303), 4326), false, '{"source": "KOMOOT", "source_ids": ["47", "191", "323", "22"], "category_raw": "190", "tour_count": 4, "nearby_landmarks": ["올림픽공원", "서울아산병원", "광나루한강공원"], "confidence": "high", "address": "대한민국 서울특별시 송파구 신천동 25"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('송악산 인증센터', '제주 환상자전거길 종주를 위한 송악산 무인 인증센터입니다. 카페 앞 코너에 자리 잡고 있어 무심코 지나치기 쉬우니 주의하세요.', '{checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.28952, 33.206579), 4326), false, '{"source": "KOMOOT", "source_ids": ["528", "130", "872", "343"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/yd/yd5izdlwc2tnl4r9db2i6lwx33o8qgl9-uhi7745625/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/sb/sb7q2jz7b65c1iam9qyx7sbpl33o8d6v0-uhi7745385/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/11/11k3y94osvy2fzrwh7ri8jx6f33o8qexq-uhi7745624/0?width=1920&crop=false"], "tips": [{"text": "Hiding in plain Sight tight on the corner in front of a coffee shop.", "author": "Fitz_carraldo"}, {"text": "Hiding in plain Sight tight on the corner in front of a coffee shop.", "author": ""}], "category_raw": "facilities", "tour_count": 4, "nearby_landmarks": ["송악산", "마라도 여객선 선착장", "산방산"], "confidence": "high", "address": "대한민국 제주특별자치도 서귀포시 대정읍 상모리 157-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('안동댐 인증센터', '낙동강 자전거길의 시작점이자 종주 인증을 할 수 있는 곳입니다. 안동의 랜드마크인 월영교가 바로 옆에 있으며, 주변에 경치 좋은 카페가 많아 라이딩 전후 휴식하기 좋습니다.', '{checkpoint,rest_area,cafe,landmark,river,bridge}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.758685, 36.577524), 4326), false, '{"source": "KOMOOT", "source_ids": ["47", "146", "1081", "164"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/13/13iogkezn70nk134l8xli5kph65du4t1j4-uhi87159538/0?width=1920&crop=false"], "tips": [{"text": "Lots of nice Cafes nearby", "author": "Fitz_carraldo"}], "category_raw": "facilities", "tour_count": 4, "nearby_landmarks": ["월영교", "안동물문화관", "안동댐"], "confidence": "high", "address": "대한민국 경상북도 안동시 석주로"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('송악산 오션뷰 카페', '송악산 해안도로 라이딩 중 탁 트인 오션뷰와 함께 야외 테라스에서 휴식하기 좋은 카페입니다.', '{cafe,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.275711, 33.200185), 4326), false, '{"source": "KOMOOT", "source_ids": ["319", "154", "504", "848"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/12/12g9lgkb4quewm5ugpfxqfn2g5edw2qtf-uhi87787363/0?width=1920&crop=false"], "category_raw": "cafe", "tour_count": 4, "nearby_landmarks": ["송악산", "알뜨르비행장", "상모해녀의집"], "confidence": "high", "address": "대한민국 제주특별자치도 서귀포시 대정읍 상모리 1670-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('양재시민의숲', '양재천 자전거길과 연결되어 라이딩 중 쉬어가기 좋은 도심 속 숲 공원입니다. 화장실, 벤치, 식수대 등 휴식 인프라가 잘 갖춰져 있습니다.', '{park,nature,rest_area,restroom,water_fountain,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.038516, 37.469725), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 4, "nearby_landmarks": ["양재천", "aT센터", "매헌윤봉길의사기념관", "양재시민의숲역"], "confidence": "high", "address": "대한민국 서울특별시 서초구 양재동 237-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('양평역', '남한강 자전거길 라이딩 시 대중교통(점프)을 이용하거나 출발/도착지로 자주 활용되는 경의중앙선 전철역입니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.49233, 37.493053), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/58/Gyeonggi_Yangpyeong_Station_2010.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/59/양평역.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/60/Yangpyeonggu.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/22/Korail_Jungang_Line_Yangpyeong_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6f/K135_Yangpyeong_01.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 4, "nearby_landmarks": ["양평시장", "남한강 자전거길"], "confidence": "high", "address": "대한민국 경기도 양평군 양평읍 양근리 370-14"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오룡역', '대전 도시철도 1호선 오룡역입니다. 출퇴근 시간을 제외하면 평일에도 자전거 휴대 승차가 가능해 점프(지하철 이동) 시 유용한 대중교통 거점입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.405061, 36.328382), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/7/7d/DJET_Daejeon_Subway_Line_1_Oryong_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9d/Oryong_Station_Exit_1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a9/Oryong_subway_station.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/cf/Oryong_Sta._nameplate.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f5/Oryong_Station_2011-05-02.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 4, "nearby_landmarks": ["서대전네거리", "오류동"], "confidence": "high", "address": "대한민국 대전광역시 중구 오류동 187-27"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('옥순대교', '청풍호와 옥순봉의 절경을 감상하며 건널 수 있는 교량입니다. 충주호 일주 라이딩의 핵심 코스로, 봄 벚꽃과 가을 단풍이 특히 아름답습니다.', '{bridge,viewpoint,lake,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.231776, 36.947187), 4326), false, '{"source": "KOMOOT", "source_ids": ["981", "1347", "475", "1080"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/sk/sk2v5xbiy0f6w2ot5hzaz7n637eoo59q-uhi9479961/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1x/1xu579kdhmd4pp3k8kxtkf8oi37eoo7ek-uhi9479962/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1d/1dugyctnayb3u1jg9hask64lt637eoo8fj-uhi9479963/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 4, "nearby_landmarks": ["옥순봉", "옥순봉 출렁다리", "청풍호"], "confidence": "high", "address": "대한민국 충청북도 제천시 수산면 상천리 470"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('왜관역', '낙동강 자전거길 종주 시 기차 점프(환승) 거점으로 많이 이용되는 왜관역입니다. 역 주변 공영주차장이 있어 차량 주차 후 라이딩을 시작하기 좋습니다.', '{transit,parking,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.400132, 35.991554), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/9/9e/Waegwanst.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/ko/0/04/%EC%99%9C%EA%B4%80%EC%97%AD_%EC%A7%80%ED%95%98%EB%8F%84.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 4, "nearby_landmarks": ["낙동강 자전거길", "호국의 다리", "왜관시장"], "confidence": "high", "address": "대한민국 경상북도 칠곡군 왜관읍 왜관리 216-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('월영교', '낙동강 종주 자전거길의 출발점이자 인증센터가 위치한 국내 최장 목조 다리입니다. 야경과 주변 경관이 매우 뛰어나 라이딩 중 반드시 들러야 할 안동의 대표 랜드마크입니다.', '{bridge,checkpoint,landmark,viewpoint,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.758678, 36.57753), 4326), false, '{"source": "KOMOOT", "source_ids": ["48", "147", "163", "1082"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/rb/rbllic6g3cypzrnegx73nhrm546wd4kp-uhi78304967/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/66/66bofr9ftxcl1dhkmradulsta546wdm2t-uhi78305005/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 4, "nearby_landmarks": ["안동댐", "낙강물길공원", "안동민속박물관", "임청각"], "confidence": "high", "address": "대한민국 경상북도 안동시 석주로"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('이화령 인증센터', '국토종주 새재자전거길의 대표적인 업힐 정상에 위치한 인증센터입니다. 휴게소에서 보급이 가능하며, 일부 구간의 고르지 못한 노면 상태에 주의해야 합니다.', '{checkpoint,rest_area,convenience_store,restroom,parking,viewpoint,mountain,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.031899, 36.751872), 4326), false, '{"source": "KOMOOT", "source_ids": ["618", "384", "442", "1950"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/k2/k2g21aqr783l16glwswblatel2zs6t4j8-uhi6052147/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/so/so9nfcug9oov14u07gi7kyqfe2zs6tagy-uhi6052148/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/g6/g60a3n9rgmp7xid32lfi2o1k2zs6tnik-uhi6052170/0?width=1920&crop=false"], "tips": [{"text": "국토종주 새재길.\n- 이화령이 무서운게아니고, 도로상태 안습ㅜㅜ", "author": "SangGyu, Lim _ Korea"}], "category_raw": "facilities", "tour_count": 4, "nearby_landmarks": ["이화령 휴게소", "백두대간 이화령 표석", "이화령 터널"], "confidence": "high", "address": "대한민국 충청북도 괴산군 연풍면 주진리 산3-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('임랑해수욕장', '동해안 자전거길의 시작점이자 좌광천 자전거길과 연결되는 한적한 해수욕장입니다. 식당, 카페, 화장실 등 편의시설이 잘 갖춰져 있어 라이딩 전후 휴식하기 좋습니다.', '{beach,checkpoint,rest_area,restroom,cafe,restaurant,parking,convenience_store,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.2644, 35.319189), 4326), false, '{"source": "KOMOOT", "source_ids": ["635", "574", "226", "204"], "category_raw": "12", "tour_count": 4, "nearby_landmarks": ["박태준기념관", "좌광천 자전거길", "카페 헤이든"], "confidence": "high", "address": "대한민국 부산광역시 기장군 장안읍 임랑리 1-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('이포보 전망대', '남한강 자전거길 이포보에 위치한 전망대입니다. 수려한 강 풍경을 감상하며 실내 카페와 화장실을 이용할 수 있어 라이더들의 훌륭한 휴식처가 됩니다.', '{viewpoint,rest_area,cafe,restroom,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.54187, 37.407625), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 4, "nearby_landmarks": ["이포보", "파사성", "천서리 막국수촌", "당남리섬"], "confidence": "high", "address": "대한민국 경기도 여주시 대신면 천서리 산13-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('중랑교 동쪽 자전거길 입구', '중랑교 동단에서 중랑천 자전거길로 진입할 수 있는 접근로입니다. 한강이나 의정부 방향으로 라이딩을 시작하기 좋은 주요 기점입니다.', '{bridge,river,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.07086, 37.592535), 4326), false, '{"source": "KOMOOT", "source_ids": ["184", "115", "159", "72"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/hk/hkcjopeufpojxxbwmmt68shl3gb3uamb-uhi18074676/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/16/169qw2u0k468zuywxi7agul4r3gb3uyo9-uhi18074710/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 4, "nearby_landmarks": ["중랑천", "중랑교", "중랑천체육공원"], "confidence": "high", "address": "대한민국 서울특별시 중랑구 상봉동 474-26"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('창의문', '북악 스카이웨이 업힐의 주요 기점이자 자하문 고개 정상에 위치한 한양도성 성곽문입니다. 라이딩 전후로 숨을 고르며 쉬어가기 좋은 체크포인트입니다.', '{historic,landmark,checkpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.966573, 37.592789), 4326), false, '{"source": "KOMOOT", "source_ids": ["307", "52", "122", "234"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k1/og/ogij6bu20zj15627himr7j6d212hjddu-uhi663715/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k2/n2/n2rzuuggxbm4196umg5a5oztx2k96s6lp-uhi2492987/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/kf/kf7h5hpgdnk71e1cpstnmtinz4res0zb5-uhi66798111/0?width=1920&crop=false"], "tips": [{"text": "Die südkoreanischen Hauptstadt Seoul hatte ursprüngliche eine Statdmauer mit vier großen und vier kleinen Stadttoren. Das Changuimun Gate ist eines der vier kleinen Stadttore, liegt im nördlichen Teil der Festungsmauer und wurde im Jahre 1396 errichtet.", "author": ""}, {"text": "Die südkoreanischen Hauptstadt Seoul hatte ursprüngliche eine Statdmauer mit vier großen und vier kleinen Stadttoren. Das Changuimun Gate ist eines der vier kleinen Stadttore, liegt im nördlichen Teil der Festungsmauer und wurde im Jahre 1396 errichtet.", "author": "Maik"}], "category_raw": "historical_site", "tour_count": 4, "nearby_landmarks": ["자하문고개", "북악스카이웨이", "윤동주문학관", "클럽 에스프레소"], "confidence": "high", "address": "대한민국 서울특별시 종로구 창의문로 118"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('춘천물레길', '의암호 자전거길의 주요 거점인 송암레포츠타운 내 춘천물레길입니다. 탁 트인 호수 풍경을 감상하며 쉬어가거나 레저를 즐기기 좋은 라이딩 명소입니다.', '{lake,park,landmark,rest_area,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.685846, 37.855184), 4326), false, '{"source": "KOMOOT", "source_ids": ["128", "1569", "882", "121"], "image_urls": ["https://photos.komoot.de/wiki/commons/9/99/Chuncheon_station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b5/New_Chuncheon_Station.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9f/춘천역.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bb/Chuncheonstation.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/93/ChuncheonSta.jpg?width=1920&crop=false"], "category_raw": "settlement", "tour_count": 4, "nearby_landmarks": ["의암호", "송암레포츠타운", "의암스카이워크", "삼악산 호수케이블카"], "confidence": "high", "address": "대한민국 강원특별자치도 춘천시 송암동 644-23"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('춘천 두바퀴', '의암호 자전거길 송암스포츠타운 구간에 위치한 라이더 쉼터 겸 식당입니다. 라이딩 중 가볍게 식사나 음료를 즐기며 휴식하기 좋습니다.', '{restaurant,cafe,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.685695, 37.855006), 4326), false, '{"source": "KOMOOT", "source_ids": ["243", "177", "646", "1902"], "category_raw": "restaurant", "tour_count": 4, "nearby_landmarks": ["의암호 자전거길", "송암스포츠타운"], "confidence": "medium", "address": "대한민국 강원특별자치도 춘천시 송암동 816-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('클럽 ES 제천 리조트', '청풍호와 월악산의 수려한 경관을 품은 리조트입니다. 충주호(청풍호) 주변을 라이딩할 때 숙박하거나 뷰를 감상하며 휴식을 취하기 좋은 거점입니다.', '{rest_area,viewpoint,parking,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.194223, 36.987999), 4326), false, '{"source": "KOMOOT", "source_ids": ["1564", "1198", "692", "1297"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1c/1cm7kp82ob64d1aaka3r8243sv37eoppa4-uhi9479971/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 4, "nearby_landmarks": ["청풍호", "월악산", "옥순봉"], "confidence": "high", "address": "대한민국 충청북도 제천시 수산면 능강리 214-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('홍제천', '한강 자전거길과 연결되는 도심 속 하천 코스로, 평탄하게 정비된 자전거도로와 인공폭포 등 볼거리가 있어 쾌적한 라이딩이 가능합니다.', '{river,park,rest_area,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.917986, 37.568764), 4326), false, '{"source": "KOMOOT", "source_ids": ["72", "64", "540", "106", "118", "165", "876", "435", "479", "330"], "category_raw": "190", "tour_count": 4, "nearby_landmarks": ["홍제천 인공폭포", "난지한강공원", "안산자락길"], "confidence": "high", "address": "대한민국 서울특별시 서대문구 연희동 542-77"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('횡계시외버스공용정류장', '대관령 옛길, 안반데기 등 강원도 주요 업힐 라이딩을 위해 자전거를 싣고 점프(시외버스 이동)하기 좋은 핵심 교통 거점입니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.70509, 37.673102), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 4, "nearby_landmarks": ["대관령", "대관령양떼목장", "평창올림픽플라자"], "confidence": "high", "address": "대한민국 평창군 횡계시외버스공용정류장"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('카페 하라', '자전거와 바이크 라이더들의 성지로 불리는 천안의 유명 라이더 카페입니다. 2025년 4월 화재가 발생한 이력이 있어 방문 전 영업 여부 확인을 권장합니다.', '{cafe,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.128493, 36.784745), 4326), false, '{"source": "KOMOOT", "source_ids": ["93", "122", "345"], "tips": [{"text": "라이더 카페", "author": "아스펜7"}], "category_raw": "cafe", "tour_count": 3, "nearby_landmarks": ["신방동", "남부대로"], "confidence": "high", "address": "대한민국 충청남도 천안시 동남구 신방동 106-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('미쁜제과', '제주 환상자전거길 노을해안로 인근의 대형 한옥 베이커리 카페입니다. 오션뷰와 넓은 정원이 있어 라이딩 중 빵과 커피로 당 충전하며 휴식하기 좋습니다.', '{cafe,rest_area,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.179725, 33.269271), 4326), false, '{"source": "KOMOOT", "source_ids": ["268", "580", "586"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/6x/6xtm85lkn1ed1rfsj366j8pd85e1xgl3w-uhi87436288/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/xi/xijy3c7f50i2p1dmny0fx3a5e1xgnkn-uhi87436289/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/hv/hv2l0nzfvz5lyrxkiwu7qfxw5e1xgpv2-uhi87436290/0?width=1920&crop=false"], "category_raw": "cafe", "tour_count": 3, "nearby_landmarks": ["노을해안로", "신도포구"], "confidence": "high", "address": "대한민국 제주특별자치도 서귀포시 대정읍 신도리 2415-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('옥포대첩기념공원', '임진왜란 첫 승전을 기념하는 공원으로 옥포만의 탁 트인 오션뷰를 제공합니다. 거제 해안 라이딩 중 역사적 의미를 되새기며 쉬어가기 좋은 훌륭한 조망점입니다.', '{park,historic,landmark,viewpoint,museum,rest_area,restroom,parking,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.714532, 34.900474), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 3, "nearby_landmarks": ["옥포항", "옥포수변공원", "팔랑포방파제", "한화오션(구 대우조선해양)"], "confidence": "high", "address": "대한민국 경상남도 거제시 팔랑포2길 87"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('운탄고도', '과거 석탄을 나르던 해발 1,000m 이상의 고산 임도로, 수려한 풍경과 적당한 난이도를 갖춰 그래블 및 MTB 라이더들에게 사랑받는 국내 최고의 자전거 트레일입니다.', '{nature,mountain,historic,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.89377, 37.153675), 4326), false, '{"source": "KOMOOT", "source_ids": ["364", "1280", "599"], "category_raw": "trail", "tour_count": 3, "nearby_landmarks": ["만항재", "도롱이연못", "새비재", "타임캡슐공원"], "confidence": "high", "address": "5V3V+FG 대한민국 강원특별자치도 정선군"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('가정역', '인천 지하철 2호선 가정역입니다. 주말 및 공휴일 자전거 점프나 라이딩 모임 장소로 활용하기 좋으며, 역내 화장실을 이용할 수 있습니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.675316, 37.524551), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/a/a3/Q20823465_Gajeong_A01.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["루원시티", "가정중앙시장"], "confidence": "high", "address": "대한민국 인천광역시 서구 가정동 240-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('갑천', '갑천누리길 2코스가 지나는 대전 괴곡동 갑천 구간입니다. 자전거 도로가 잘 조성되어 있으며, 인근에 대규모 펌프트랙과 노루벌이 있어 라이더들에게 인기 있는 코스입니다.', '{river,nature,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.355417, 36.287124), 4326), false, '{"source": "KOMOOT", "source_ids": ["760", "295", "1327"], "image_urls": ["https://photos.komoot.de/wiki/commons/4/4b/Gapcheon_sta._nameplate.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6e/Gapcheon_sta._exit_3.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/55/Gapcheon_Station_exit_guide.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/93/DJET_Daejeon_Subway_Line_1_Gapcheon_Station.jpg?width=1920&crop=false"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["갑천누리길", "괴곡동 펌프트랙", "노루벌"], "confidence": "high", "address": "대한민국 대전광역시 서구 괴곡동 413-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('강암봉', '김해 천문대와 가야테마파크 인근에 위치한 해발 382m의 산봉우리입니다. 임도와 산길이 이어져 있어 MTB 라이더들이 업힐과 자연 경관을 즐기기 좋은 코스입니다.', '{mountain,viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.888862, 35.254466), 4326), false, '{"source": "KOMOOT", "source_ids": ["372", "196", "211"], "category_raw": "21", "tour_count": 3, "nearby_landmarks": ["김해천문대", "분성산", "김해가야테마파크"], "confidence": "high", "address": "대한민국 경상남도 김해시 어방동 산1-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('강화도 해안길', '강화도 동쪽 해안을 따라 조성된 자전거길로, 탁 트인 바다 풍경과 오두돈대 등 역사 유적을 감상하며 달리기 좋은 평탄한 라이딩 코스입니다.', '{nature,viewpoint,historic}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.506962, 37.667772), 4326), false, '{"source": "KOMOOT", "source_ids": ["143", "912", "123"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1k/1kpu2rxlci0j5p9zbumzksl4599013rb-uhi82639287/0?width=1920&crop=false"], "category_raw": "trail", "tour_count": 3, "nearby_landmarks": ["오두돈대", "광성보", "덕진진"], "confidence": "high", "address": "대한민국 인천광역시 강화군 불은면 넙성리 477-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('거린사슴전망대', '제주 1100고지 업힐 코스 중 서귀포 앞바다를 조망하며 쉴 수 있는 필수 휴식처입니다. 매점과 화장실이 있어 라이딩 중 보급과 정비에 매우 유용합니다.', '{viewpoint,rest_area,convenience_store,restroom,parking,mountain}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.454535, 33.307451), 4326), false, '{"source": "KOMOOT", "source_ids": ["522", "191", "685"], "image_urls": ["https://photos.komoot.de/wiki/commons/0/07/거린사슴전망대_Georin_Deer_Observatory.jpg?width=1920&crop=false"], "category_raw": "14", "tour_count": 3, "nearby_landmarks": ["1100고지", "서귀포자연휴양림", "거린사슴오름"], "confidence": "high", "address": "대한민국 제주특별자치도 서귀포시 대포동 산2-11"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('경포해변 인증센터', '동해안 자전거길의 주요 인증센터로 경포해변과 경포호 사이에 있습니다. 맑은 바다를 보며 쉴 수 있고 화장실, 식당, 매점 등 편의시설이 잘 갖춰져 있습니다.', '{checkpoint,beach,restroom,restaurant,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.907063, 37.805322), 4326), false, '{"source": "KOMOOT", "source_ids": ["636", "1552", "108"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/m3/m3virxlb0jzq15bu7sig3xdmq3rbv8g63-uhi32677745/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1p/1pfg1l1kpos5dr0gb6zr0g2v946kf6d4z-uhi49969628/0?width=1920&crop=false"], "tips": [{"text": "Langer, recht breiter Sandstreifen, klares Wasser. Sanitäre Anlagen gibt es in regelmäßigen Abständen, Restaurant und kleine Läden ebenfalls. \nDas Wasser ist sehr klar!", "author": "Wanderschnecke"}], "category_raw": "facilities", "tour_count": 3, "nearby_landmarks": ["경포해변", "경포호"], "confidence": "high", "address": "대한민국 강원특별자치도 강릉시 안현동 89-48"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('계양역 아라뱃길 자전거 거점', '아라뱃길 자전거길 라이딩의 주요 출발지이자 대중교통 점프가 가능한 계양역입니다. 자전거 대여소와 화장실, 매점 등 편의시설이 잘 갖춰져 있습니다.', '{transit,restroom,convenience_store,restaurant,bike_shop,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.736155, 37.571345), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/c/c5/Gyeyang_Station_logo.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/63/계양역.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/ca/AREX_gyeyang_station_platform.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/dd/20250702_공항철도_계양역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/12/20250702_공항철도_계양역_승강장3.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["경인 아라뱃길", "계양대교", "아라뱃길 자전거도로"], "confidence": "high", "address": "대한민국 인천광역시 계양구 귤현동 451-475"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('고려대역 자전거 보관소', '정릉천과 성북천 자전거길을 통해 한강으로 연결되는 라이딩 거점입니다. 인근 고려대역에 사물함형 자전거 보관함이 있어 주차와 대중교통 환승이 편리합니다.', '{landmark,parking,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.036125, 37.590359), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/4/4d/Q488478_Korea_University_A01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e1/Koreauniv-pf.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6d/Seoul-metro-640-Korea-university-station-entrance-2-20181125-153208.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/56/Seoul-metro-640-Korea-university-station-platform-20181125-153624.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/ce/Seoul_Subway_6_Korea_University_Station.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["고려대역", "정릉천 자전거길", "고려대 교우회관"], "confidence": "high", "address": "대한민국 서울특별시 성북구 종암동 29-50"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광화문광장', '서울의 중심이자 대표적인 랜드마크로, 세종대왕과 이순신 장군 동상이 있는 넓은 광장입니다. 매년 서울자전거대행진이 출발하는 곳이며 라이딩 중 기념사진을 남기기 좋습니다.', '{landmark,historic,park,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.976798, 37.570672), 4326), false, '{"source": "KOMOOT", "source_ids": ["79", "197", "422"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/d4/d4uyt35du39y1eg0m8jqimy9343r0mloh-uhi47517407/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/12/12t2qhadkw1z191z4k4b5cydq4lq323q1-uhi61076622/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/g1/g1f8edw5lia8qfgokchd1nz95djterpn-uhi86810424/0?width=1920&crop=false"], "tips": [{"text": "Gwanghwamun Sehenswürdigkeiten\n\nDer Gwanghwamun-Platz (koreanisch 광화문광장 Gwanghwamungwangjang, Hanja 光化門廣場, englisch Gwanghwamun Square; Gwanghwamun Plaza) ist ein 2009 eröffneter Platz im Zentrum der südkoreanischen Hauptstadt Seoul. (aus wiki.)", "author": "Bouchi"}], "category_raw": "man_made_monument", "tour_count": 3, "nearby_landmarks": ["경복궁", "세종대왕 동상", "이순신 장군 동상", "청계천"], "confidence": "high", "address": "대한민국 서울특별시 종로구 세종대로 159 11층"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('교동 석갈비', '전주 한옥마을 내 위치한 유명 석갈비 전문점입니다. 구워져 나오는 고기로 든든하게 에너지를 보충하기 좋으나, 주말엔 인파가 많아 자전거 주차 시 주의가 필요합니다.', '{restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.151999, 35.814652), 4326), false, '{"source": "KOMOOT", "source_ids": ["1214", "614", "534"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/2w/2wosgdskadixhr4hena2acll3y8lzea1-uhi43398002/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/14/14tjplx14cfy9yy1quxhdrjnq3y8lzeal-uhi43398003/0?width=1920&crop=false"], "category_raw": "restaurant", "tour_count": 3, "nearby_landmarks": ["전주한옥마을", "경기전", "전동성당"], "confidence": "high", "address": "대한민국 전북특별자치도 전주시 완산구 풍남동3가 66-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구리암사대교', '한강 남북 자전거길을 잇는 교량입니다. 북단의 가파른 미음나루고개를 피해 남단의 아이유고개(암사고개)로 우회하려는 라이더들이 강을 건널 때 주로 이용합니다.', '{bridge}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.130931, 37.570113), 4326), false, '{"source": "KOMOOT", "source_ids": ["869", "2535", "215"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1v/1v3azumh3odsc1fcjtwy7jd96i55ag4i3a-uhi79595132/0?width=1920&crop=false"], "tips": [{"text": "미음나루 대신 아이유로 우회할때 자주 이용", "author": ""}], "category_raw": "bridge", "tour_count": 3, "nearby_landmarks": ["아이유고개(암사고개)", "미음나루고개", "구리한강시민공원", "광나루한강공원"], "confidence": "high", "address": "대한민국 경기도 구리시 토평동 739-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('극락강', '광주를 지나는 영산강 구간을 일컫는 명칭으로, 영산강 종주 자전거길이 평탄하게 잘 조성되어 있어 라이더들이 즐겨 찾는 수변 코스입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.829975, 35.17606), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["영산강 자전거길", "극락교", "극락친수공원"], "confidence": "high", "address": "대한민국 광주광역시 극락강"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금계마을', '지리산 둘레길 3, 4코스가 교차하는 거점 마을로 지리산둘레길 함양센터가 있습니다. 지리산 및 오도재 라이딩 시 휴식과 보급을 위한 중간 기착지로 유용합니다.', '{checkpoint,rest_area,landmark,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.685552, 35.403889), 4326), false, '{"source": "KOMOOT", "source_ids": ["424", "1344", "493"], "category_raw": "14", "tour_count": 3, "nearby_landmarks": ["지리산둘레길 함양센터", "엄천강", "오도재"], "confidence": "high", "address": "대한민국 경상남도 함양군 마천면 의탄리 859-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금련산', '황령산과 연계하여 오르기 좋은 부산의 대표적인 도심 업힐 코스입니다. 고된 업힐 끝에 광안대교와 바다 조망을 즐길 수 있습니다.', '{mountain,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.110936, 35.149762), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/0/0c/Geumnyeonsan_Station_2013.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/68/Geumnyeonsan_station_sign_June_6,_2024.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/de/Busan-subway-210-Geumnyeonsan-station-entrance-1-20180402-180218.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0b/210geumnyeonsan2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/10/Geumnyeonsan_Station_2010.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["황령산", "금련산청소년수련원", "광안리해수욕장"], "confidence": "high", "address": "대한민국 부산광역시 금련산역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금천 자전거종합서비스센터', '안양천 자전거길과 금천구청역을 잇는 진입로입니다. 자전거종합서비스센터와 공기주입기가 위치해 있어 라이더들이 정비와 휴식을 취하기 좋은 주요 거점입니다.', '{bike_shop,rest_area,transit,river,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.893803, 37.456019), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/8/88/20200707_금천구청역.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/37/Geumcheon-gu_office_Station.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/90/202403_Junctions_South_to_the_Geumcheon-gu_Office_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/43/20230711_금천구청역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f0/금천구청역_1번출구.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["안양천 자전거길", "금천구청역", "금천자전거종합서비스센터"], "confidence": "high", "address": "대한민국 서울특별시 금천구 독산동 732-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('기장', '부산 기장군의 중심지인 기장읍 일대입니다. 인근에 기장역과 기장시장이 있어 대중교통 연계(점프) 및 식사, 행동식 보급을 위한 거점으로 활용하기 좋습니다.', '{landmark,transit,convenience_store,restaurant,cafe}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.219145, 35.244439), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/e/ef/Korail-Donghae-line-K123-Gijang-station-entrance-20180331-101802.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c6/Korail_Gijang_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/eb/Korail_Gijang_Station2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/5c/Gijang_Station_platform_in_2017.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/fb/Korail-Donghae-line-K123-Gijang-station-sign-20180331-100810.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["기장역", "기장시장", "기장군청"], "confidence": "high", "address": "대한민국 부산광역시 기장군 기장읍 청강리 839"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('선암다리', '부산 강서구와 김해를 잇는 서낙동강 교량입니다. ''선암다리''로도 불리며, 두 지역을 오가는 자전거 라이더들이 자주 이용하는 주요 길목입니다.', '{bridge,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.928618, 35.220975), 4326), false, '{"source": "KOMOOT", "source_ids": ["433", "666", "1211"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/qg/qgmv3xoem9ffi6p7mvupo22u53wtbmip-uhi77960169/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 3, "nearby_landmarks": ["금옥문 조형물", "불암장어마을", "김해카누경기장"], "confidence": "high", "address": "대한민국 경상남도 김해시 불암동 221-17"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('낙동강', '구미에서 칠곡보로 향하는 낙동강 종주 자전거길 구간입니다. 탁 트인 낙동강의 수려한 경관을 감상하며 평탄하게 달리기 좋은 쾌적한 강변 코스입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.395499, 36.065204), 4326), false, '{"source": "KOMOOT", "source_ids": ["303", "279", "72", "346", "467", "1484", "370", "589", "796", "151"], "image_urls": ["https://photos.komoot.de/wiki/commons/f/f0/낙동강.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3e/Andong_Bridge.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a3/Korea-Andong-Nakdong_River-02.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/58/Korea-Andong-Nakdong_River-01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f6/상주보.jpg?width=1920&crop=false"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["칠곡보", "남구미대교", "석적체육공원"], "confidence": "high", "address": "대한민국 경상북도 칠곡군 석적읍 남율리 820"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남춘천역 커피니', '명칭은 남춘천역을 의미하며, 주소는 2번 출구 앞 카페(커피니)를 가리킵니다. ITX 자전거 점프 전후로 대기하며 휴식하기 좋은 주요 거점입니다.', '{transit,cafe,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.724054, 37.86414), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["남춘천역", "공지천"], "confidence": "high", "address": "대한민국 강원특별자치도 춘천시 우묵길 24 1,2층"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('녹번역', '지하철 3호선 녹번역입니다. 5번 출구 뒤편에 자전거 공기주입기가 있어 정비가 가능하며, 불광천이나 북한산 방면 라이딩의 환승 및 출발 거점으로 유용합니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.935708, 37.600965), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/f/f2/Nokbeon_Station_20210628_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a8/Seoul-metro-323-Nokbeon-station-entrance-4-20191022-130814.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/00/Nokbeon_Station_2.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/91/Seoul-metro-323-Nokbeon-station-sign-20191022-130106.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2f/Seoul-metro-323-Nokbeon-station-platform-20191022-130254.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["북한산", "불광천", "백련산", "은평구청"], "confidence": "high", "address": "대한민국 서울특별시 은평구 녹번동 48"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('다락천', '의정부 호원동에서 중랑천 자전거길로 합류하는 소하천입니다. 라이딩 중 도봉산 주변의 자연 경관을 즐기며 지나치기 좋은 포인트입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.045067, 37.696421), 4326), false, '{"source": "KOMOOT", "source_ids": ["1357", "413", "565"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["중랑천 자전거길", "다락천 합수부", "다락교"], "confidence": "high", "address": "대한민국 경기도 의정부시 호원동 204-38"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('단항', '사천에서 대교를 건너 남해로 진입하는 자전거길의 첫 관문 마을입니다. 단항항 주변으로 식당과 편의시설이 있어 라이딩 중 보급과 휴식을 취하기 좋습니다.', '{landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.017105, 34.91686), 4326), false, '{"source": "KOMOOT", "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["창선·삼천포대교", "단항항", "단항회센터"], "confidence": "high", "address": "대한민국 경상남도 남해군 창선면 대벽리 424"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('부라우나루터', '남한강 자전거길과 여강길 1코스가 지나는 구간으로, 수려한 강변 풍경과 옛 부라우나루터의 정취를 즐기며 라이딩하기 좋은 곳입니다.', '{river,viewpoint,nature,historic}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.677813, 37.263574), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 3, "nearby_landmarks": ["남한강 자전거길", "부라우나루터", "강천보", "여강길 1코스"], "confidence": "high", "address": "대한민국 여주시 단현동"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('달성보', '낙동강 자전거길의 주요 거점인 달성보입니다. 인증센터, 편의점, 화장실, 주차장 등 편의시설이 잘 갖춰져 있어 라이더들이 쉬어가기 좋은 필수 코스입니다.', '{bridge,checkpoint,convenience_store,restroom,parking,viewpoint,rest_area,river,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.419193, 35.736953), 4326), false, '{"source": "KOMOOT", "source_ids": ["499", "572", "685"], "category_raw": "bridge", "tour_count": 3, "nearby_landmarks": ["낙동강", "달성보 인증센터", "달성노을공원"], "confidence": "high", "address": "대한민국 대구광역시 달성군 논공읍 하리 707-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('달천길', '여수 여자만 해안을 따라 이어지는 아름다운 자전거 길입니다. 탁 트인 바다 풍경과 해질 무렵의 붉은 노을이 매력적인 라이딩 명소입니다.', '{nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.55513, 34.808203), 4326), false, '{"source": "KOMOOT", "source_ids": ["1926", "264", "457"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/te/tegy08uw6rh71656wfvxc49je4sk4dqdq-uhi67441948/0?width=1920&crop=false"], "category_raw": "trail", "tour_count": 3, "nearby_landmarks": ["여자만", "반월마을", "노을전망광장"], "confidence": "high", "address": "대한민국 전라남도 여수시 율촌면 반월리 705"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('담양대나무숲 인증센터', '영산강 종주 자전거길의 필수 인증센터입니다. 이름과 달리 실제 위치는 광주이며 주변에 대나무가 없어 종종 라이더들을 당황하게 합니다. 도장 획득 후 잠시 쉬어가기 좋습니다.', '{checkpoint,rest_area,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.891854, 35.247215), 4326), false, '{"source": "KOMOOT", "source_ids": ["201", "1013", "95"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/99/998wjjak602y8dy2ztaoy4jl5e6r1ig2-uhi87549241/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 3, "nearby_landmarks": ["영산강"], "confidence": "high", "address": "대한민국 광주광역시 북구 용전동 576-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대구역', '대구 도심에 위치한 주요 철도역으로, 신천 자전거길과 가까워 대중교통 연계(점프) 및 보급을 위한 거점으로 활용하기 좋습니다.', '{transit,restroom,convenience_store,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.597049, 35.87604), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/en/e/ec/DaeguStation.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e9/DaeguStationFlatform.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/cd/대구역_내부.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/02/대구역_내부2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8d/1951년_대구역_주변.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["신천 자전거길", "칠성시장", "동성로"], "confidence": "high", "address": "대한민국 대구광역시 북구 칠성동2가 302-349"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대실역', '금호강 및 낙동강 자전거길(강정고령보)과 가까운 대구 2호선 전철역입니다. 라이딩 출발 및 복귀 지점으로 접근성이 좋고 쾌적한 화장실을 이용할 수 있습니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.465643, 35.857302), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["강정고령보", "디아크", "금호강 자전거길"], "confidence": "high", "address": "대한민국 대구광역시 다사읍 대실"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대전천', '대전 원도심을 가로지르는 하천으로, 유등천 및 갑천과 연결되는 자전거길이 잘 조성되어 있어 도심 속 라이딩을 즐기기 좋습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.429008, 36.329761), 4326), false, '{"source": "KOMOOT", "source_ids": ["533", "34", "315"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["목척교", "중앙로 지하상가", "으능정이문화거리"], "confidence": "high", "address": "대한민국 대전광역시 중구 중앙로 145 신지하상가 A가5호"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대현지', '경주 산내면에 위치한 크고 길쭉한 계곡형 저수지입니다. 영남알프스의 산세와 어우러진 탁 트인 수변 경치를 감상하며 라이딩하기 좋습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.063754, 35.748217), 4326), false, '{"source": "KOMOOT", "source_ids": ["1014", "670", "299"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["문복산", "동창천", "산내국민청소년수련원"], "confidence": "high", "address": "대한민국 경상북도 경주시 산내면 대현리 952-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('덕정역', '수도권 전철 1호선 덕정역입니다. 중랑천 자전거길과 인접해 있어 라이딩 연계가 좋으며, 자전거 보관소와 화장실 등 편의시설을 갖추고 있어 대중교통 점프 및 휴식 거점으로 적합합니다.', '{transit,restroom,convenience_store,parking,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.062234, 37.843478), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/64/Deokjeong_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a2/20210626_덕정역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/21/20210626_덕정역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/7e/20210626_덕정역_스크린도어.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["중랑천 자전거길", "덕정5일장", "엄상마을 음식문화거리"], "confidence": "high", "address": "대한민국 양주시 덕정역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('도봉천', '중랑천 자전거길과 연결되는 도봉천 생태하천입니다. 도봉산에서 발원한 맑은 물길을 따라 쾌적하게 라이딩을 즐길 수 있습니다.', '{river,nature,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.043573, 37.679348), 4326), false, '{"source": "KOMOOT", "source_ids": ["601", "98", "531"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["중랑천", "도봉산", "도봉역"], "confidence": "high", "address": "대한민국 서울특별시 도봉구 도봉동 594-23"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('도암호', '대관령과 안반데기를 잇는 길목에 위치한 거대한 호수입니다. 차량 통행이 적고 한적하여 고요한 자연 풍경을 감상하며 라이딩하기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.70882, 37.610432), 4326), false, '{"source": "KOMOOT", "source_ids": ["1667", "602", "1377"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["안반데기", "도암댐", "대관령"], "confidence": "high", "address": "대한민국 강원특별자치도 평창군 대관령면 수하리 산20-31"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('두산1리', '청주 남일면 두산1리 마을 입구 및 버스 정류장입니다. 무심천 자전거길 종점에서 피반령이나 미원면 방향으로 공도 라이딩 시 지나가는 길목입니다.', '{transit,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.541535, 36.562394), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 3, "nearby_landmarks": ["두산1리 버스정류장", "단재로"], "confidence": "high", "address": "대한민국 충청북도 청주시 상당구 남일면 두산리 138-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('아산호 신언천 제방길', '아산호 인근 하천을 따라 이어진 둑길(제방)입니다. 평탄하고 탁 트인 풍경을 감상하며 자전거 라이딩을 즐기기 좋은 구간입니다.', '{river,nature,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.958567, 36.909747), 4326), false, '{"source": "KOMOOT", "source_ids": ["686", "267", "361"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["아산호", "신언천"], "confidence": "medium", "address": "대한민국 충청남도 아산시 영인면 구성리 885-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('라제통문', '무주 자전거 둘레길의 핵심 경유지이자 라이더들의 필수 포토존인 암벽 터널입니다. 신라와 백제의 경계로 알려진 무주 구천동 제1경으로 역사적 의미와 독특한 경관을 제공합니다.', '{tunnel,historic,landmark,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.795416, 35.996108), 4326), false, '{"source": "KOMOOT", "source_ids": ["1222", "241", "1029"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/e7/e7912jgen1zl1uz6kus4yht3u5eqm73jb-uhi88294981/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1b/1bwsq5sb52qwhqsjuqzjfg4ef5fcf8260-uhi89239617/0?width=1920&crop=false"], "category_raw": "other_man_made", "tour_count": 3, "nearby_landmarks": ["설천교", "원당천", "무주 반디랜드"], "confidence": "high", "address": "대한민국 전북특별자치도 무주군 설천면 두길리 971"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('마곡역', '지하철 5호선 마곡역입니다. 자전거 인프라가 잘 갖춰진 마곡지구 중심에 있으며, 서울식물원을 거쳐 한강 자전거도로로 진입하기 좋은 라이딩 기점입니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.824708, 37.560006), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/a/ae/Seoul-metro-514-Magok-station-platform-20180915-165412.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/fb/Seoul-metro-514-Magok-station-entrance-2-20180915-165726.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/dd/20241026_마곡역_1번출구.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/29/20250224_마곡역_2번출구.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c4/20241115_마곡역_통로_공사중.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["서울식물원", "마곡-한강 자전거도로"], "confidence": "high", "address": "대한민국 서울특별시 강서구 가양제1동 공항대로 지하163 마곡"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('마천역', '지하철 5호선 마천역입니다. 성내천 자전거길을 통해 한강으로 진출하거나 남한산성 라이딩을 시작하기 좋은 대중교통 점프 포인트입니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.15274, 37.494939), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/4/4e/Seoul-metro-P555-Macheon-station-platform-20180915-110842.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/89/Seoul-metro-P555-Macheon-station-entrance-1-20180915-110058.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/43/P555_Macheon_Station_Sign_Terminal.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/fb/P555_Macheon_Old_Station_Running_in_board.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/94/P555_Macheon_Old_wall_surface_of_the_track_depths.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["성내천 자전거길", "남한산성", "마천중앙시장"], "confidence": "high", "address": "대한민국 서울특별시 송파구 마천1동 마천로57길"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('만종역', '동해안 종주나 원주 투어 시 KTX 점프(대중교통 연계) 거점으로 유용한 기차역입니다. 내부에 편의점, 화장실 등 편의시설이 잘 갖춰져 있어 출발 전후 정비와 휴식에 좋습니다.', '{transit,convenience_store,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.893301, 37.353235), 4326), false, '{"source": "KOMOOT", "source_ids": ["14", "172"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/mq/mqvghf5076i01qy4l319sqcox37eix6g1-uhi9478521/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 3, "nearby_landmarks": ["원주천 자전거길", "만종역 공영주차장"], "confidence": "high", "address": "대한민국 원주시 KTX만종역(문막방면)"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('만항재', '해발 1,330m로 국내 포장도로 중 가장 높은 고개입니다. 로드 자전거 업힐 명소이자 운탄고도 MTB 코스의 출발점으로 라이더들에게 상징적인 성지입니다.', '{mountain,viewpoint,rest_area,nature,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.899283, 37.148367), 4326), false, '{"source": "KOMOOT", "source_ids": ["339", "1305", "574"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/3e/3ezq3hrjkdec7suu346oxoyy37ddi0rs-uhi9471515/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/18/1874by5f3t15m1uo9bew9qxi1i37ddi43s-uhi9471516/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1e/1eyt2280recu3srra0qmtvltb5i3liejh-uhi93125062/0?width=1920&crop=false"], "tips": [{"text": "대간길 중 차로 오를 수 있는 가장 높은 곳", "author": "Sam"}], "category_raw": "mountain_pass", "tour_count": 3, "nearby_landmarks": ["함백산", "운탄고도", "정암사", "삼탄아트마인"], "confidence": "high", "address": "대한민국 강원특별자치도 정선군 고한읍 고한리 산216-34"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('말티재', '12굽이 헤어핀으로 유명한 충북 보은의 대표적인 업힐 명소입니다. 정상의 말티재 전망대에서 내려다보는 굽잇길 풍경이 일품이며, 라이더들에게 큰 성취감을 주는 필수 코스입니다.', '{mountain,viewpoint,landmark,cafe,rest_area,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.789568, 36.499017), 4326), false, '{"source": "KOMOOT", "source_ids": ["989", "220"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/74/74ra8lenwu4ophjkphpphsy15kxtx546-uhi96288087/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/ks/ks7kp4vgklsb1856x1634c7185kxtx8ol-uhi96288088/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1ka/g4/g43g1moyukm51dww9ypjycz9v5owb48jm-uhi98319549/0?width=1920&crop=false"], "category_raw": "mountain_pass", "tour_count": 3, "nearby_landmarks": ["말티재 전망대", "속리산 관문", "꼬부랑길 카페"], "confidence": "high", "address": "대한민국 충청북도 보은군 장안면 장재리 산4-21"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('무주공용버스터미널', '무주 남대천 및 태권도원 자전거 여행의 주요 출발점이자 복귀점입니다. 내부에 매점과 화장실 등 편의시설이 있어 라이딩 전후 휴식과 보급에 좋습니다.', '{transit,convenience_store,restroom,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.664317, 36.004901), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 3, "nearby_landmarks": ["남대천", "지남공원", "반딧불장터"], "confidence": "high", "address": "대한민국 무주군 무주공용버스터미널"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('박석저수지', '자전거 동호인들에게 유명한 말티재 12굽이 업힐 코스의 시작점에 위치한 저수지입니다. 수려한 경관을 감상하며 본격적인 업힐 전 숨을 고르기 좋은 장소입니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.774544, 36.49505), 4326), false, '{"source": "KOMOOT", "source_ids": ["893", "124"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["말티재", "말티재 전망대", "국립속리산말티재자연휴양림"], "confidence": "high", "address": "대한민국 충청북도 보은군 장안면 장재리 72"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('반도지', '유림공원 내에 위치한 한반도 모양의 인공 호수입니다. 갑천 자전거길과 인접해 있어 라이딩 중 경치를 감상하며 쉬어가기 좋은 아름다운 휴식처입니다.', '{lake,park,rest_area,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.356242, 36.359921), 4326), false, '{"source": "KOMOOT", "source_ids": ["176", "181", "131"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["유림공원", "갑천 자전거길", "유성구청"], "confidence": "high", "address": "대한민국 대전광역시 유성구 봉명동 2-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('반석역 라이딩 거점', '대전 지하철 1호선 종점으로 자전거 휴대 승차(점프)가 용이하며, 반석천 및 세종-대전 자전거도로가 시작되는 주요 라이딩 거점입니다.', '{transit,restroom,convenience_store,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.314789, 36.391981), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/4/4d/DJET_Banseok_Station-Platform.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3f/Banseok_sta._exit_6.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/49/DJET_Banseok_Station-Gate.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/1c/DJET_Banseok_Station-Sign.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["반석천", "세종-대전 자전거도로"], "confidence": "high", "address": "대한민국 대전광역시 반석역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('버드나무브루어리', '1926년 지어진 탁주 양조장을 개조한 강릉의 유명 수제 맥주 펍입니다. 자전거길과 인접해 있어 라이딩 후 피자와 로컬 맥주를 즐기며 쉬어가기 좋습니다.', '{restaurant,historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.88458, 37.748034), 4326), false, '{"source": "KOMOOT", "source_ids": ["52"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/qy/qyizga8djamp13l3klswkkiw94xs36dqs-uhi70589852/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/11/118p8x294cgh9yesuh8fhvkom4xs36oy5-uhi70589854/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/18/18zbf8c4umcey79bej5d919y85j9g72l8-uhi94695285/0?width=1920&crop=false"], "tips": [{"text": "Budnamu Brewery is a popular American-style brewpub and craft brewery located in Gangneung. Established in 2015 in the historic location of the city''s oldest makgeolli distillery, it is known for brewing unique beers using local ingredients like rice, pine, and chrysanthemum. The brewery offers a unique atmosphere with industrial-style decor, an outdoor seating area, and serves a menu of American and local-influenced food such as pizzas, burgers, and fries. Opens at noon till 11pm. They have a Budnamu Sampler for Krw18k for their most popular 4 beer.", "author": "Everesta Life Behind Bars"}], "category_raw": "pub", "tour_count": 3, "nearby_landmarks": ["남대천 자전거길", "홍제정수장 벚꽃길", "명주동 거리"], "confidence": "high", "address": "대한민국 강원특별자치도 강릉시 홍제동 96-105"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼락생태공원 벚꽃길', '낙동강 종주 자전거길 구간으로, 봄이면 환상적인 벚꽃 터널이 펼쳐지는 라이딩 명소입니다. 삼락생태공원과 인접해 강변 풍경을 즐기며 달리기 좋습니다.', '{viewpoint,river,nature,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.969907, 35.146693), 4326), false, '{"source": "KOMOOT", "source_ids": ["297", "259", "666"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1v/1v7hpq9cmz4957nk425w14gxa4xutl6jh-uhi70731102/0?width=1920&crop=false"], "category_raw": "trail", "tour_count": 3, "nearby_landmarks": ["삼락생태공원", "낙동강", "낙동강 종주 자전거길"], "confidence": "high", "address": "대한민국 부산광역시 사상구 감전동 172-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('봉전소류지', '통영 산양읍에 위치한 조용한 소류지(작은 저수지)입니다. 한려해상국립공원 구역 내 한적한 자연 경관을 즐기며 라이딩하기 좋은 코스 기점입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.413562, 34.780271), 4326), false, '{"source": "KOMOOT", "source_ids": ["446", "1574", "913"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["한려해상국립공원", "화양초등학교", "답하마을"], "confidence": "high", "address": "대한민국 경상남도 통영시 산양읍 신전리 1094-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('봉황교', '해반천 자전거길이 지나는 봉황교 부근입니다. 봉황대공원과 가야 유적지가 인접해 있어 라이딩 중 경관을 즐기며 통과하기 좋습니다.', '{bridge,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.874397, 35.22722), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/5a/Bonghwang_Station.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/5b/Bonghwang_Gimhae_Bus_Terminal_Station_20150505_170317.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/84/Bonghwang_Gimhae_Bus_Terminal_Station_20150505_170521.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b1/Bonghwang_Gimhae_Bus_Terminal_Station_20150505_172305.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9d/Bonghwang_Gimhae_Bus_Terminal_Station_20150505_172334.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["해반천", "봉황대공원", "봉황동 유적", "봉황역"], "confidence": "high", "address": "대한민국 김해시 전하동 봉황"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('부안 구암리 지석묘군', '청동기 시대의 독특한 고인돌 유적지로, 부안 지역이나 서해랑길 자전거 라이딩 중 가볍게 들러 역사적 정취를 느낄 수 있는 포인트입니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.654659, 35.707842), 4326), false, '{"source": "KOMOOT", "source_ids": ["151", "1201", "189"], "image_urls": ["https://photos.komoot.de/wiki/commons/4/47/%EB%B6%80%EC%95%88_%EA%B5%AC%EC%95%94%EB%A6%AC_%EC%A7%80%EC%84%9D%EB%AC%98%EA%B5%B0.jpg?width=1920&crop=false"], "category_raw": "15", "tour_count": 3, "nearby_landmarks": ["청호저수지", "서해랑길 50코스"], "confidence": "high", "address": "대한민국 전북특별자치도 부안군 하서면 석상리 703-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('북악 팔각정', '초반 업힐 후 완만해지는 서울 라이더들의 대표적인 성지입니다. 정상 팔각정에는 멋진 전망과 함께 편의점, 카페, 자전거 거치대 등 휴식 인프라가 잘 갖춰져 있습니다.', '{viewpoint,convenience_store,cafe,rest_area,mountain,landmark,parking,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.973569, 37.598527), 4326), false, '{"source": "KOMOOT", "source_ids": ["185", "148", "115"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/10/105m24mgawtiz4w4ihbg965cc32u1j99f-uhi7372006/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/5e/5e10g2iipq5b1mycf76uompv132u1jcd9-uhi7372007/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/3q/3qu6hmci246w4z7xo3rt5meb3ma3fb58-uhi27139619/0?width=1920&crop=false"], "tips": [{"text": "After some initial ramping up, this climb builds gently and is more achievable than the profile suggests. Some great views reward the effort at the lookout point, there are several cafes at the top and a convenience store. At the Skyway Cafe there is a bike weight scale suspended from the awning - should you be curious to know your bike’s weight.", "author": "Jon"}], "category_raw": "viewpoint", "tour_count": 3, "nearby_landmarks": ["북악산", "북악스카이웨이", "창의문"], "confidence": "high", "address": "대한민국 서울특별시 종로구 부암동 2-11"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('불국사', '유네스코 세계문화유산인 경주의 대표 사찰입니다. 토함산 자락에 위치해 라이딩 중 가벼운 업힐을 즐길 수 있으며, 역사적 볼거리와 훌륭한 휴식처를 제공합니다.', '{historic,landmark,rest_area,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.328562, 35.788606), 4326), false, '{"source": "KOMOOT", "source_ids": ["572", "41", "162", "67", "188", "598"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/mk/mk3carp86cfz8cqxt8rxdzgi525qtnez-uhi75658738/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1y/1y1mal4xlu2tdspf5y2i4b1e95i1jdvlr-uhi93031497/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/bi/bib407v8hf0o1abatlgdd1nkg4rybslae-uhi67144771/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k0/21/21jh3w98i8ba1flbdxbuq4ml21xk4b1qe-uhi559127/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k0/1q/1q4aknh0oydas9i1wps8ruczk1xk4hr61-uhi559130/0?width=1920&crop=false"], "tips": [{"text": "The temple Bulguksa is an UNESCO world heritage. The site has different interesting buildings to visit.", "author": "Marcel"}], "category_raw": "religious_building", "tour_count": 3, "nearby_landmarks": ["석굴암", "토함산", "보문관광단지"], "confidence": "high", "address": "대한민국 경상북도 경주시 진현동 44-11"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('불국사', '유네스코 세계문화유산인 경주의 대표 사찰입니다. 토함산 업힐 코스의 주요 거점이며, 경내 자전거 반입이 불가해 외곽에 주차 후 도보로 관람해야 합니다.', '{historic,landmark,parking,restroom,mountain}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.331311, 35.790034), 4326), false, '{"source": "KOMOOT", "source_ids": ["572", "41", "162", "67", "188", "598"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/mk/mk3carp86cfz8cqxt8rxdzgi525qtnez-uhi75658738/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1y/1y1mal4xlu2tdspf5y2i4b1e95i1jdvlr-uhi93031497/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/bi/bib407v8hf0o1abatlgdd1nkg4rybslae-uhi67144771/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k0/21/21jh3w98i8ba1flbdxbuq4ml21xk4b1qe-uhi559127/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k0/1q/1q4aknh0oydas9i1wps8ruczk1xk4hr61-uhi559130/0?width=1920&crop=false"], "tips": [{"text": "The temple Bulguksa is an UNESCO world heritage. The site has different interesting buildings to visit.", "author": "Marcel"}], "category_raw": "religious_building", "tour_count": 3, "nearby_landmarks": ["석굴암", "토함산", "불국사 상가시장"], "confidence": "high", "address": "대한민국 경상북도 경주시 진현동 16"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('살곶이체육공원', '중랑천과 청계천 합수부에 위치한 체육공원입니다. 자전거길과 직접 연결되어 있으며 화장실과 주차장 등 편의시설이 잘 갖춰져 라이더들의 훌륭한 휴식처가 됩니다.', '{park,rest_area,restroom,parking,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.048902, 37.554047), 4326), false, '{"source": "KOMOOT", "source_ids": ["98", "293", "99"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/be/beuq654n8kni10ozdrgrawjzr3fxgbgce-uhi17242553/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 3, "nearby_landmarks": ["중랑천", "청계천", "살곶이다리", "한양대학교"], "confidence": "high", "address": "대한민국 서울특별시 성동구 사근동 102-16"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼랑진', '낙동강 종주 자전거길의 주요 거점인 삼랑진 읍내입니다. 식당과 편의점 등 보급처가 많고 삼랑진역을 통한 대중교통 연계(점프)가 편리합니다.', '{landmark,rest_area,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.843956, 35.398438), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/1/1a/Samnagjin_station_front.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/ec/Korail0samnangjin.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/82/Samnagjin_station_square.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/ko/6/6f/Samnangjin_sation_ticket.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/51/Samnagjin_station_tracks1.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["삼랑진역", "낙동강 자전거길", "삼랑진생태문화공원", "구 삼랑진교"], "confidence": "high", "address": "대한민국 경상남도 밀양시 삼랑진읍 송지리 770-13"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('상일동', '지하철 5호선 상일동역 일대입니다. 한강으로 이어지는 고덕천 자전거길 접근성이 좋아 라이딩 출발지나 경유지로 적합하며 주변 편의시설이 풍부합니다.', '{transit,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.166776, 37.556788), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/8/82/20210408_상일동역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f5/Seoul-metro-553-Sangil-dong-station-entrance-1-20180914-125506.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/47/20210408_상일동역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/35/Seoul-metro-553-Sangil-dong-station-entrance-4-20180914-125136.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/69/20200804_상일동역_게이트.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["고덕천 자전거길", "상일동역", "강동바이크스쿨"], "confidence": "high", "address": "대한민국 서울특별시 상일동"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('서귀포자연휴양림', '제주 1100도로 업힐 중 만나는 주요 랜드마크입니다. 휴양림 내부는 자전거 출입이 금지되어 있으므로 입구에 주차 후 휴식이나 화장실을 이용해야 합니다.', '{nature,landmark,rest_area,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.459663, 33.312397), 4326), false, '{"source": "KOMOOT", "source_ids": ["225", "494", "657"], "category_raw": "191", "tour_count": 3, "nearby_landmarks": ["1100도로", "거린사슴전망대", "한라산둘레길"], "confidence": "high", "address": "대한민국 제주특별자치도 서귀포시 대포동 산1-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('석화봉', '평택호 자전거길과 평택섶길 코스에 인접한 해발 38.3m의 작은 산봉우리입니다. 평택호 관광단지와 가까워 라이딩 중 경치를 즐기기 좋습니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.924807, 36.923745), 4326), false, '{"source": "KOMOOT", "source_ids": ["480", "474", "260"], "category_raw": "191", "tour_count": 3, "nearby_landmarks": ["평택호 관광단지", "평택호 자전거길", "평택국제대교"], "confidence": "high", "address": "대한민국 경기도 평택시 현덕면 권관리 290"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남설악 탐방지원센터', '한계령 업힐(오색 방면) 코스에 위치한 국립공원 탐방지원센터입니다. 본격적인 고개 등반 전 화장실 이용과 휴식을 취하기 좋은 주요 거점입니다.', '{restroom,rest_area,checkpoint,mountain,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.449012, 38.084785), 4326), false, '{"source": "KOMOOT", "source_ids": ["531", "1196", "1412"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1r/1rmtisu0e6pn21vdwh5bocn29y503qhy35-uhi73304464/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/e8/e80owyf268vn1qqa7a7pajbp6503qi4vg-uhi73304472/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/p8/p8qei2mh2rmwmt3m6qpuquuf50kmx2xs-uhi73817373/0?width=1920&crop=false"], "tips": [{"text": "위치가 조금 잘못되어, 위치수정 요청했습니다.", "author": "싸리"}], "category_raw": "facilities", "tour_count": 3, "nearby_landmarks": ["오색약수터", "한계령", "설악산 대청봉"], "confidence": "high", "address": "대한민국 강원특별자치도 양양군 서면 오색리 산1-43"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('춘천 거두리 현대성우오스타', '춘천 거두리에 위치한 현대성우오스타 아파트입니다. 거두리 자전거길을 지날 때 경로상의 이정표나 지역 라이더들의 동네 출발지로 활용되는 주거 랜드마크입니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.754837, 37.856204), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 3, "nearby_landmarks": ["거두리 자전거길", "춘천교도소", "호반베르디움 아파트"], "confidence": "high", "address": "대한민국 춘천시 성우오스타A"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('소금산 출렁다리', '섬강 자전거길 인근 간현관광지의 대표 랜드마크입니다. 자전거 진입은 불가하여 하차 후 도보로 올라가야 하며, 아찔한 높이에서 섬강의 멋진 절경을 감상할 수 있습니다.', '{bridge,landmark,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.842232, 37.347643), 4326), false, '{"source": "KOMOOT", "source_ids": ["720", "432", "142"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/qh/qh6iredf070s40dyc09tpesf4l39bnux-uhi60361852/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/11/11i3tabym3t1910qm09ivnih574l39bquu-uhi60361865/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 3, "nearby_landmarks": ["간현관광지", "섬강 자전거길", "소금산 그랜드밸리", "원주 레일바이크"], "confidence": "high", "address": "대한민국 강원특별자치도 원주시 지정면 간현리 1187"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('속초고속버스터미널', '동해안 자전거길 종주나 속초 라이딩의 주요 출발 및 도착지입니다. 자전거를 고속버스에 싣고 복귀(점프)하기 좋은 필수 교통 거점입니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.598879, 38.190322), 4326), false, '{"source": "KOMOOT", "source_ids": ["1724", "1064", "20"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1u/1utcneuoy81jq1m8e77h0hyf03r9pgev9-uhi32547629/0?width=1920&crop=false"], "tips": [{"text": "속초고속버스터미널", "author": "AsuRa"}], "category_raw": "facilities", "tour_count": 3, "nearby_landmarks": ["속초해수욕장", "청초호"], "confidence": "high", "address": "대한민국 강원특별자치도 속초시 조양동 1417-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('수안산 쉬운 트레일', '김포 수안산의 완만한 숲길 트레일입니다. 고도가 낮아 초보자도 가볍게 MTB 라이딩을 즐기기 좋으며, 정상의 탁 트인 조망과 산성 터가 매력적입니다.', '{mountain,nature,historic,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.589323, 37.637625), 4326), false, '{"source": "KOMOOT", "source_ids": ["1010", "1802", "94"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1t/1ta56q1z9xl8v19iu9ln4ug43x53faex31-uhi77351489/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/18/18t88gvrx9vz135zqoy43br5753faez56-uhi77351490/0?width=1920&crop=false"], "category_raw": "trail", "tour_count": 3, "nearby_landmarks": ["수안산성", "수안산생태원", "승마산"], "confidence": "high", "address": "대한민국 경기도 김포시 대곶면 대벽리 산3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('수영강', '온천천과 광안리를 잇는 평탄하고 쾌적한 자전거길이 조성된 강입니다. 센텀시티의 도심 풍경과 여유로운 강변 경치를 감상하며 달리기 좋은 부산의 대표적인 라이딩 코스입니다.', '{river,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.119981, 35.18766), 4326), false, '{"source": "KOMOOT", "source_ids": ["1398", "1249", "144"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["센텀시티", "과정교", "APEC나루공원"], "confidence": "high", "address": "대한민국 부산광역시 해운대구 재송동 900-127"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('심곡천의 시작', '심곡천 자전거길의 출발점입니다. 청라호수공원을 거쳐 서해까지 이어지는 약 5km의 쾌적한 수변 라이딩을 시작하기 좋습니다.', '{river,nature,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.611812, 37.524326), 4326), false, '{"source": "KOMOOT", "source_ids": ["68", "69"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1o/1oz6zs9f09t45k9ktj2j0t2074ce5a3zz-uhi55368287/0?width=1920&crop=false"], "category_raw": "river", "tour_count": 3, "nearby_landmarks": ["청라호수공원", "루원시티"], "confidence": "high", "address": "대한민국 인천광역시 서구 청라동 100-67"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('어승생제2저수지', '제주 1100도로 업힐 구간에 위치한 저수지입니다. 천아계곡과 천아숲길 진입로에 자리하여 라이딩 중 위치를 파악하기 좋은 랜드마크입니다.', '{lake,landmark,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.475452, 33.407529), 4326), false, '{"source": "KOMOOT", "source_ids": ["378", "504", "215"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["1100도로", "천아계곡", "천아숲길"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 해안동 2821-1 어승생제2저수지"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('어정', '용인 에버라인 어정역과 신갈천 자전거길이 만나는 지점입니다. 기흥저수지나 동백호수공원 방향으로 라이딩 시 접근성이 좋고 대중교통 연계가 편리합니다.', '{transit,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.143724, 37.274933), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/53/Eojeongsta.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/cd/Eojeong-o.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c4/Eojeong-g.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/4a/Eojeong-s.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a1/Eojeong-y.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["어정역", "신갈천", "동백호수공원"], "confidence": "high", "address": "대한민국 용인시 어정"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('수창공원', '대구 수창공원 내 위치한 지점으로, 유저가 가족과 방문 후 임의로 등록한 명칭으로 추정됩니다. 라이딩 중 공원에서 가볍게 휴식하기 좋습니다.', '{park,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.585501, 35.876411), 4326), false, '{"source": "KOMOOT", "source_ids": ["468", "18", "1350"], "category_raw": "unknown", "tour_count": 3, "nearby_landmarks": ["수창공원", "대구예술발전소", "수창청춘맨숀"], "confidence": "low", "address": "대한민국 대구광역시 중구 수창동 175"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('염창역 자전거 거점', '지하철 9호선 염창역과 버스정류장이 있는 교통 요지입니다. 안양천과 한강 자전거길 진입이 수월하며, 역 주변에 자전거 보관소와 편의시설이 있어 라이딩 전후 정비하기 좋습니다.', '{transit,parking,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.875318, 37.547028), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/9/9f/Yeomchang_Station_Platform.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0b/Yeomchang_Station_3.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["안양천", "용왕산", "한강공원"], "confidence": "high", "address": "대한민국 서울특별시 염창역.서울도시가스"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('영랑호 (Yeongnang Lake)', '약 8km의 평탄한 순환 자전거길이 조성된 아름다운 호수입니다. 설악산 울산바위 절경을 감상하며 초보자도 안전하고 여유롭게 라이딩을 즐길 수 있습니다.', '{lake,park,nature,viewpoint,landmark,bridge,bike_shop}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.590313, 38.220368), 4326), false, '{"source": "KOMOOT", "source_ids": ["236", "1822", "164"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/dp/dp60nxoyqr6h1vm49euahrlwm4v1zdgke-uhi68575744/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/85/85lmqsye9ofxpe0liaenw9k04v1zdgkh-uhi68575746/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/15/15qj65ha9sose1rxuehzkchsry4v1zdgkh-uhi68575745/0?width=1920&crop=false"], "tips": [{"text": "Yeongnang Lake is situated in the north of Sokcho, just a few meters from the shoreline. Encompassing this splendid body of water is a paved hiking trail, extending approximately 7.8 kilometers in length. From any point on the lake, you can enjoy a picturesque view of nearby Seorak Mountain range.", "author": "Johannes"}], "category_raw": "lake", "tour_count": 3, "nearby_landmarks": ["범바위", "영랑호수윗길", "설악산 울산바위", "속초등대전망대"], "confidence": "high", "address": "대한민국 강원특별자치도 속초시 영랑동 163-62"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('영산강', '광주 북구 지야동을 지나는 영산강 자전거길 구간입니다. 탁 트인 강변 풍경을 감상하며 평탄하게 라이딩하기 좋은 코스입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.876662, 35.236867), 4326), false, '{"source": "KOMOOT", "source_ids": ["61", "235"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["영산강 자전거길", "용산교", "광주시민의숲"], "confidence": "high", "address": "대한민국 광주광역시 북구 지야동 767-29"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('용흥지', '여름철 연꽃이 아름답게 피는 아담한 저수지 겸 수변공원입니다. 도로변에 있어 자전거로 접근하기 좋고, 인근 역사 유적지와 함께 가볍게 쉬며 경치를 즐기기 좋습니다.', '{lake,park,viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.430066, 35.6679), 4326), false, '{"source": "KOMOOT", "source_ids": ["133", "24", "278"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["현풍곽씨 십이정려각", "도동서원"], "confidence": "high", "address": "대한민국 대구광역시 달성군 현풍읍 지리 1359"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('착량묘', '이순신 장군을 기리는 사당인 착량묘입니다. 통영 앞바다가 내려다보이는 언덕에 있어 라이딩 중 역사적 의미를 되새기며 잠시 쉬어가기 좋은 유적지입니다.', '{historic,landmark,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.410916, 34.835568), 4326), false, '{"source": "KOMOOT", "source_ids": ["1164", "97", "402", "1246"], "category_raw": "15", "tour_count": 3, "nearby_landmarks": ["통영해저터널", "충무교"], "confidence": "high", "address": "대한민국 경상남도 통영시 당동 1-12"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('달성보 인증센터', '낙동강 자전거길의 달성보 무인 인증센터입니다. 인접한 관리센터 건물에 편의점과 화장실, 전망대가 있어 라이딩 중 보급과 휴식을 취하기 좋습니다.', '{checkpoint,convenience_store,rest_area,restroom,viewpoint,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.419114, 35.73699), 4326), false, '{"source": "KOMOOT", "source_ids": ["686", "752", "72", "172", "573", "664", "65", "426", "966", "845"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/gq/gqlf6e58mrlsrlo889hpozum5dr45tlt-uhi87069787/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1v/1vhr0tab5d8j5ns6x2cbl578s5du4n9f9-uhi87159173/0?width=1920&crop=false"], "tips": [{"text": "Has a GS 25 convenience store in the adjacent Building", "author": "Fitz_carraldo"}, {"text": "Has a GS 25 convenience store in the adjacent Building", "author": ""}], "category_raw": "facilities", "tour_count": 3, "nearby_landmarks": ["달성보", "낙동강", "노을공원"], "confidence": "high", "address": "대한민국 대구광역시 달성군 논공읍 하리 707-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('임성리역', '호남선 기차역인 임성리역입니다. 영산강 자전거길이나 해남, 강진 방면 자전거 투어 시 출발지나 경유지로 활용하기 좋은 교통 거점입니다.', '{transit,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.435163, 34.820935), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/0/09/Imseongri01.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["영산강 자전거길", "남악신도시"], "confidence": "high", "address": "대한민국 전라남도 목포시 옥암동 759-120"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('임진각 평화누리공원', '평화누리 자전거길의 종착지이자 분단의 역사를 간직한 랜드마크입니다. 서울 출발 시 장거리 코스에 해당하므로 도착 전 충분한 식수와 간식 보급이 필수적입니다.', '{park,historic,landmark,museum,viewpoint,bridge,rest_area,convenience_store,cafe,restaurant,restroom,parking,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.751641, 37.888456), 4326), false, '{"source": "KOMOOT", "source_ids": ["454", "278", "704"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/t0/t0vn2tz9ivqx14zcf8smbjkwg47m3fmg7-uhi51053657/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1a/1anhb33jabpvq1mehjvr960x0e47m3foxf-uhi51053662/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/n5/n5c4ae18t8mv1prkmfqf8xpzp47m3frri-uhi51053670/0?width=1920&crop=false"], "tips": [{"text": "장가리 라이딩이므로 간식과 물 확보 필요", "author": "CYG"}], "category_raw": "historical_site", "tour_count": 3, "nearby_landmarks": ["자유의 다리", "임진강역", "임진각 평화곤돌라", "독개다리"], "confidence": "high", "address": "대한민국 경기도 파주시 문산읍 마정리 814-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('자양역(뚝섬한강공원)', '지하철 7호선 자양역(구 뚝섬유원지역)입니다. 뚝섬한강공원 자전거길과 바로 연결되어 라이딩 출발 및 합류 지점으로 인기가 높습니다.', '{transit,park,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.066775, 37.531522), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/0/00/20240229_자양역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/22/20240427_자양역_2번_출구.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9d/20240229_자양역_1번출구.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bb/20240427_자양역_3번출구.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/11/20240229_자양역_승강장.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["뚝섬한강공원", "청담대교", "뚝섬 자벌레"], "confidence": "high", "address": "대한민국 서울특별시 뚝섬유원지"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('장지역 1번 출구', '8호선 장지역 1번 출구 인근으로 따릉이 대여소가 있습니다. 송파둘레길(장지천)과 가까워 대중교통 연계 및 라이딩 코스 진출입 지점으로 활용하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.125963, 37.478853), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/e/e7/Seoul-metro-819-Jangji-station-platform-20181124-155732.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/02/Q75348_jangji_A03.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/24/Q75348_jangji_A02.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0a/Q75348_jangji_A01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b2/Q75348_jangji_A04.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["가든파이브", "송파둘레길", "장지천"], "confidence": "high", "address": "대한민국 서울특별시 송파구 장지동 216-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('저수지', '대전 유성구 문지동 갑천 자전거길 인근에 위치한 작은 저수지입니다. 라이딩 중 잔잔한 수변 풍경을 감상하며 가볍게 지나치기 좋은 자연 포인트입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.409325, 36.397001), 4326), false, '{"source": "KOMOOT", "source_ids": ["247", "691", "605"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["갑천 자전거길", "카이스트 문지캠퍼스", "대덕연구단지"], "confidence": "medium", "address": "대한민국 대전광역시 유성구 문지동 663"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('고성 해맞이공원 전망대', '고성 동해면 해안도로에 위치한 해맞이공원 내 전망대입니다. 탁 트인 바다 경치와 화장실을 갖추고 있어 라이딩 중 쉬어가기 좋은 일출 명소입니다.', '{viewpoint,park,rest_area,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.478966, 35.059873), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 3, "nearby_landmarks": ["해맞이공원", "동진대교", "소담수목원"], "confidence": "high", "address": "대한민국 경상남도 고성군 동해면 조선특구로 2084"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('정부청사역', '대전 지하철 1호선 정부청사역입니다. 출퇴근 시간 외 자전거 휴대 승차가 가능해 점프 거점으로 유용하며, 인근에 타슈 대여소와 화장실이 있습니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.381616, 36.357615), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/3/3e/Government_Complex_Daejeon_Station-DJET1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/45/Daejeon_Subway_Government_Complex_Daejeon_Station_Sign.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/24/DJET_Government_Complex_Daejeon_Station_Station-Exit_No_4.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3f/Government_Complex_Daejeon_Station_gate3.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/61/Dajeon_Public_Bicycle_Tashu_at_Government_Complex_Station.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["정부대전청사", "샘머리공원", "둔산경찰서"], "confidence": "high", "address": "대한민국 대전광역시 서구 둔산2동 한밭대로 지하 744"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('제주항 연안여객터미널', '육지에서 자전거를 싣고 제주도로 들어오는 주요 관문입니다. 화장실, 편의점 등 휴게 시설이 잘 갖춰져 있어 라이딩 전후 정비와 휴식에 좋습니다.', '{transit,restroom,convenience_store,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.534901, 33.519183), 4326), false, '{"source": "KOMOOT", "source_ids": ["111", "330", "26"], "category_raw": "facilities", "tour_count": 3, "nearby_landmarks": ["제주항", "탑동광장", "사라봉"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 건입동 918-30"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('주지봉', '남원 백두대간 코스에 위치한 가파른 산봉우리입니다. 경사가 험해 MTB 라이딩이나 끌바 시 각별한 주의가 필요하며, 정상에 작은 불상이 있습니다.', '{mountain,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.489265, 35.448246), 4326), false, '{"source": "KOMOOT", "source_ids": ["1569", "2135", "577"], "category_raw": "21", "tour_count": 3, "nearby_landmarks": ["여원재", "수정봉", "고남산"], "confidence": "high", "address": "대한민국 전북특별자치도 남원시 이백면 양가리 산55-36"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('중랑천 상계교 진입로', '노원고등학교 인근에서 중랑천 자전거길로 진입하는 나들목입니다. 상계교와 가까우며, 주변에 공중화장실이 있어 라이딩 전후 정비와 휴식에 유용합니다.', '{river,restroom,bridge,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.051923, 37.662339), 4326), false, '{"source": "KOMOOT", "source_ids": ["677", "227", "374"], "category_raw": "cycle_way", "tour_count": 3, "nearby_landmarks": ["노원고등학교", "상계교", "중랑천"], "confidence": "high", "address": "대한민국 서울특별시 노원구 상계동 854"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('중모소류지', '전북 진안군 동향면에 위치한 조용한 소류지(작은 저수지)입니다. 한적한 농촌 풍경과 수변 경관을 감상하며 라이딩 중 가볍게 지나치거나 쉬어가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.558238, 35.855818), 4326), false, '{"source": "KOMOOT", "source_ids": ["68", "1410", "637"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["호티재"], "confidence": "high", "address": "대한민국 전북특별자치도 진안군 동향면 자산리 1338-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('증산역 4번 출구 따릉이 대여소', '증산역 4번 출구에 위치한 서울시 공공자전거 따릉이 대여소입니다. 불광천 자전거길과 바로 연결되어 대중교통 연계 라이딩을 하기에 매우 편리합니다.', '{transit,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.909896, 37.584134), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/e/e5/Seoul-metro-617-Jeungsan-station-sign-20191022-092814.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/12/Seoul-metro-617-Jeungsan-station-entrance-4-20191022-093634.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3a/증산역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/ff/Seoul-metro-617-Jeungsan-station-platform-20191022-092906.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["증산역", "불광천"], "confidence": "high", "address": "대한민국 서울특별시 은평구 증산로 305"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('지행역', '수도권 전철 1호선 지행역입니다. 왕방산 MTB 코스와 신천 자전거길로 진입하기 좋은 라이딩 출발점이며, 주변에 자전거 매장과 편의시설이 많아 보급 및 정비에 좋습니다.', '{transit,restroom,convenience_store,parking,bike_shop}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.055789, 37.892511), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/0/01/Jihaeng_Station.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/79/Jihaeng_Station_Entrance.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/17/Jihaeng_Station_Shop.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e9/Jihaeng_Station_Platforms.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c0/Jihaeng_Station_-_Looking_North.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["신천 자전거길", "왕방산", "칠봉산"], "confidence": "high", "address": "대한민국 경기도 동두천시 지행동 483-16"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금호지', '진주 금산면에 위치한 금호지로, 수변 생태공원이 잘 조성된 아름다운 호수입니다. 인근 폐철도 자전거길과 연계하여 라이딩 중 여유롭게 풍경을 감상하며 휴식하기 좋습니다.', '{lake,park,rest_area,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.131809, 35.200449), 4326), false, '{"source": "KOMOOT", "source_ids": ["104", "583", "163"], "category_raw": "lake", "tour_count": 3, "nearby_landmarks": ["월아산", "금호지생태공원", "소망교"], "confidence": "high", "address": "대한민국 경상남도 진주시 금산면 송백리 산71"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('창릉천 자전거길', '창릉천을 따라 한강 자전거길까지 이어지는 쾌적한 자전거길입니다. 도심 속 자연을 느끼며 여유롭게 라이딩하기 좋습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.876066, 37.639924), 4326), false, '{"source": "KOMOOT", "source_ids": ["243", "49", "95"], "category_raw": "cycle_way", "tour_count": 3, "nearby_landmarks": ["창릉천", "행주산성", "고양아크비즈지식산업센터"], "confidence": "high", "address": "대한민국 경기도 고양시 덕양구 삼원로 63 111호"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('장원막국수', '부여 구드래나루터 인근의 유명한 ''장원막국수''입니다. 시원한 메밀막국수와 편육으로 라이딩 중 든든하게 보급하기 좋으나, 주말에는 대기가 길어 일정에 참고해야 합니다.', '{restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.908643, 36.289263), 4326), false, '{"source": "KOMOOT", "source_ids": ["143", "1538", "24"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1s/1s680uhgfqmqyb9yvhdcjrtd33xohdzo8-uhi42660102/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1m/1m5ucyrkafk571t0npt2u32ict3xohdzsz-uhi42660103/0?width=1920&crop=false"], "category_raw": "restaurant", "tour_count": 3, "nearby_landmarks": ["구드래나루터", "부소산성", "구드래조각공원"], "confidence": "high", "address": "대한민국 충청남도 부여군 부여읍 구교리 7-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('CU 마장안민빌딩점', '청계천 자전거길 마장동 구간에 위치한 포인트입니다. 해당 주소(안민빌딩)에 편의점(CU)이 있어 라이딩 중 식수 보급과 휴식을 취하기 좋습니다.', '{river,convenience_store,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.043622, 37.568287), 4326), false, '{"source": "KOMOOT", "source_ids": ["1031", "525", "69"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["청계천 자전거길", "마장동 우시장", "살곶이 체육공원"], "confidence": "high", "address": "대한민국 서울특별시 마장동 768-1번지 101호 안민빌딩 성동구 서울특별시 KR"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('청계천-중랑천 합류점', '청계천과 중랑천 자전거길이 만나는 합류점입니다. 최근 자전거도로가 정비되어 한강까지 끊김 없는 라이딩을 이어갈 수 있는 핵심 길목입니다.', '{river,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.051372, 37.556149), 4326), false, '{"source": "KOMOOT", "source_ids": ["294", "237", "186"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1q/1qwtqry575d9d1cvir4rxwwpq23gnhzb7q-uhi18739933/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1q/1qp1v035jl1b01hjp5zz00nakq3gnhzd53-uhi18739941/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1g/1g3lbc49fqasxdnz9eb5i71mc4jias87w-uhi59004106/0?width=1920&crop=false"], "category_raw": "river", "tour_count": 3, "nearby_landmarks": ["살곶이다리", "중랑천", "한양대학교"], "confidence": "high", "address": "대한민국 서울특별시 성동구 사근동 117-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('충주역', '새재자전거길과 남한강자전거길 종주 시 자전거를 싣고 이동(점프)하기 좋은 교통 거점인 충주역입니다.', '{transit,restroom,convenience_store,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.907682, 36.975251), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/1/18/Chungju_Station.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c2/충주역_역명판.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/81/20220521_충주역_Ktx_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/73/Chungju_station2.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["충주역 급수탑"], "confidence": "high", "address": "대한민국 충청북도 충주시 봉방동 461-65"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('충주 조정지댐', '남한강 자전거길 종주 중 자전거로 직접 건널 수 있는 조절지댐입니다. 남한강과 탄금호의 탁 트인 풍경을 감상하며 시원하게 라이딩하기 좋은 랜드마크입니다.', '{bridge,river,lake,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.866688, 37.044775), 4326), false, '{"source": "KOMOOT", "source_ids": ["61", "251", "204"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/s4/s49m96l8qeq81oogarfhwb9e537l4ay4d-uhi9536518/0?width=1920&crop=false"], "category_raw": "other_man_made", "tour_count": 3, "nearby_landmarks": ["남한강", "탄금호", "남한강 자전거길"], "confidence": "high", "address": "대한민국 충청북도 충주시 금가면 월상리 579-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('충주천', '충주 시내를 가로지르는 하천입니다. 강변을 따라 자전거도로와 산책로가 잘 조성되어 있어 도심 속에서 가볍게 라이딩을 즐기기 좋습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.914257, 36.977662), 4326), false, '{"source": "KOMOOT", "source_ids": ["41"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["충주역", "무학시장"], "confidence": "high", "address": "대한민국 충청북도 충주시 봉계9길 9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('탄금교', '새재자전거길 구간으로 달천을 가로지르는 교량입니다. 남한강과 합류하는 탁 트인 수변 풍경을 감상하며 편안하게 라이딩하기 좋습니다.', '{bridge,river,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.88892, 36.988532), 4326), false, '{"source": "KOMOOT", "source_ids": ["786", "323", "492"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1f/1fqh8yn6bkemn16qg0h7ti9w3b37enljr1-uhi9479551/0?width=1920&crop=false"], "tips": [{"text": "편안하게 뷰 보면서 넘어가요", "author": "대사님"}], "category_raw": "bridge", "tour_count": 3, "nearby_landmarks": ["탄금대", "탄금대 인증센터", "탄금공원"], "confidence": "high", "address": "XVQQ+CH 대한민국 충청북도 충주시"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('탑평2교', '남한강 자전거길과 탄금호 순환 코스를 잇는 다리입니다. 탄금호의 수려한 경관을 감상하며 중앙탑 사적공원으로 이동하기 좋은 라이딩 포인트입니다.', '{bridge,lake,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.855492, 37.030871), 4326), false, '{"source": "KOMOOT", "source_ids": ["584", "695", "6"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1c/1cu5k12i4akvuvnemiiqpfg2i37lk1228-uhi9539315/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 3, "nearby_landmarks": ["탄금호", "중앙탑 사적공원", "탄금호국제조정경기장"], "confidence": "high", "address": "대한민국 충청북도 충주시 중앙탑면 탑평리 203-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('태화강', '울산 도심을 가로지르는 태화강은 평탄하고 경치가 뛰어난 자전거 전용도로가 길게 이어져 있어 라이더들에게 사랑받는 필수 코스입니다.', '{river,nature,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.353717, 35.539197), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/d9/Taehwagang_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/67/Taehwagang_Station_Platforms.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["태화강역", "태화강 국가정원", "명촌교", "십리대숲"], "confidence": "high", "address": "대한민국 울산광역시 삼산동 태화강"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('텔스알커피', '양양 죽도해변 바로 옆에 위치한 카페로, 알루미늄 캔에 담아주는 시원한 커피가 특징입니다. 야외 테라스가 있어 자전거를 곁에 두고 휴식하기 좋습니다.', '{cafe}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.760856, 37.97224), 4326), false, '{"source": "KOMOOT", "source_ids": ["252", "1159", "1340"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/3d/3ddp8l7qhijmima8ppnd52ki3radn8io-uhi32566416/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/i1/i1gcgeyr36tz1of8yllndjoqr3radnjrj-uhi32566429/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1r/1rc7zgb138xv31u2rhcml5xueb3radoo5h-uhi32566484/0?width=1920&crop=false"], "tips": [{"text": "줄리스 알 커피 (Julie''s AL Coffee)\n\nhttp://naver.me/GAi4lb2r", "author": "AsuRa"}, {"text": "줄리스 알 커피 (Julie''s AL Coffee)\n\nhttp://naver.me/GAi4lb2r", "author": ""}], "category_raw": "cafe", "tour_count": 3, "nearby_landmarks": ["죽도해변", "인구해변"], "confidence": "high", "address": "대한민국 강원특별자치도 양양군 현남면 시변리 33-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('하우스디 더 레이크', '동탄호수공원 인근 하우스디 더 레이크 아파트 단지입니다. 특정 라이더가 자전거 퇴근(자퇴) 코스의 도착지인 자택을 개인 웨이포인트로 저장한 것으로 보입니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.104014, 37.17235), 4326), false, '{"source": "KOMOOT", "source_ids": ["193", "69", "51", "557", "604", "50", "626", "784", "376", "95"], "category_raw": "unknown", "tour_count": 3, "nearby_landmarks": ["동탄호수공원", "하우스디 더 레이크 아파트"], "confidence": "high", "address": "대한민국 경기도 화성시 송동 693-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('평택역·AK플라자', '평택역과 AK플라자가 위치한 복합 시설입니다. 라이딩 중 대중교통 연계(점프)나 식사, 화장실 이용 등 다목적으로 활용하기 좋은 주요 거점입니다.', '{transit,convenience_store,cafe,restaurant,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.085322, 36.990819), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/9/9c/Korail_Gyeongbu_Line_Pyeongtaek_Station1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a5/1953년경_평택역.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b0/20241109_평택역_대합실.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/4a/20241109_평택역_대합실2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/80/20201003_평택역_일반열차_승강장.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["AK플라자 평택점", "평택역 광장", "평택시외버스터미널"], "confidence": "high", "address": "대한민국 경기도 평택시 평택동 185-568"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('텐독스', '평택국제대교 인근에 위치한 이국적인 대형 카페 ''텐독스''입니다. 야외 테라스에서 반려견과 함께 피자와 커피를 즐길 수 있어 라이딩 중 든든한 보급과 휴식처로 추천합니다.', '{cafe,restaurant,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.001222, 36.940271), 4326), false, '{"source": "KOMOOT", "source_ids": ["432", "370", "593"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1h/1hb56z8nuxaqnu0ss842o0gv24a7lbgja-uhi53487439/0?width=1920&crop=false"], "tips": [{"text": "Great ambiance,  Dog friendly eating on the patio outside.", "author": "Michael Hill"}], "category_raw": "cafe", "tour_count": 3, "nearby_landmarks": ["평택국제대교", "평택호"], "confidence": "high", "address": "대한민국 경기도 평택시 팽성읍 노양리 100-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('학의천', '안양천과 백운호수를 잇는 생태 하천 자전거길입니다. 수도권 인기 라이딩 코스인 ''하트코스''의 일부이며, 산책로와 인접해 있어 보행자에 주의하며 주행해야 합니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.96291, 37.398475), 4326), false, '{"source": "KOMOOT", "source_ids": ["204", "788", "67"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["안양천", "백운호수", "쌍개울문화공원", "동편마을"], "confidence": "high", "address": "대한민국 경기도 안양시 동안구 관양동 1807"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('고덕천 한강 합수부', '고덕천 자전거길을 따라 한강으로 이어지는 진입 구간입니다. 도심 속 생태 하천 풍경을 감상하며 라이딩하기 좋습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.17117, 37.560716), 4326), false, '{"source": "KOMOOT", "source_ids": ["19", "960"], "image_urls": ["https://photos.komoot.de/wiki/commons/b/b6/Hangang-s-big.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b7/Korea-Seoul-Han_River-01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/5b/Seoul-Han.River-01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/34/Hangang_Railway_Bridge.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e5/한강경찰대_망원한강치안센터.JPG?width=1920&crop=false"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["고덕천", "고덕리엔파크"], "confidence": "high", "address": "대한민국 서울특별시 강동구 상일로 152"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('합정역', '한강 자전거길(망원/양화지구) 진입이 수월한 주요 대중교통 거점입니다. 라이딩 전후로 식사와 휴식을 취하거나 일행과 만나기 좋습니다.', '{transit,landmark,convenience_store,cafe,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.913679, 37.549332), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/e/e2/Hapjeong_Station_20201009_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/4d/Seoul-metro-Hapjeong-station-entrance-8-20191022-081720.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/58/Seoul_Subway_Line_6_Hapjeong_Station_Platform.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f0/합정역_2호선_2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/88/Seoul-metro-238-Hapjeong-station-sign-20181121-083954.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 3, "nearby_landmarks": ["양화대교", "망원한강공원", "메세나폴리스"], "confidence": "high", "address": "대한민국 서울특별시 합정역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('해미읍성', '서산 투어 라이딩의 훌륭한 출발점이자 휴식처인 조선시대 읍성입니다. 화장실과 주차장이 잘 갖춰져 있고, 바로 앞 해미시장에서 식음료 보급을 하기 좋습니다.', '{historic,landmark,park,rest_area,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.547266, 36.714318), 4326), false, '{"source": "KOMOOT", "source_ids": ["335", "543", "849"], "category_raw": "historical_site", "tour_count": 3, "nearby_landmarks": ["해미시장", "해미순교성지", "개심사"], "confidence": "high", "address": "대한민국 충청남도 서산시 해미면 읍내리 422"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('주문진해수욕장 BTS 버스정류장', '동해안 자전거길 종주 중 만나는 아름다운 해변입니다. 유명한 BTS 버스정류장 포토존이 있어 라이딩 중 사진을 남기며 쉬어가기 좋습니다.', '{beach,viewpoint,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.820213, 37.909813), 4326), false, '{"source": "KOMOOT", "source_ids": ["1073", "235", "165", "199", "99", "897", "1734", "322", "710", "284"], "image_urls": ["https://photos.komoot.de/wiki/commons/d/d1/주문진해수욕장_향호해변.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bd/Jumunjin_Beach_20220501_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/30/Jumunjin_Beach_20220501_007.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/10/Jumunjin_Beach_20220501_013.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2a/Jumunjin_Beach_20220501_016.jpg?width=1920&crop=false"], "category_raw": "12", "tour_count": 3, "nearby_landmarks": ["BTS 버스정류장", "주문진해수욕장", "향호호수", "향호야영장"], "confidence": "high", "address": "대한민국 강원특별자치도 강릉시 주문진읍 향호리 8-58"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신천 둔치 쉼터', '대구 신천 자전거길 옆에 위치한 하천변 둔치입니다. 실제 바다 해변이 아닌 강변 공간으로, 라이딩 중 신천의 풍경을 감상하며 잠시 쉬어가기 좋습니다.', '{river,park,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.606722, 35.843203), 4326), false, '{"source": "KOMOOT", "source_ids": ["1073", "235", "165", "199", "99", "897", "1734", "322", "710", "284"], "image_urls": ["https://photos.komoot.de/wiki/commons/d/d1/주문진해수욕장_향호해변.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bd/Jumunjin_Beach_20220501_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/30/Jumunjin_Beach_20220501_007.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/10/Jumunjin_Beach_20220501_013.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2a/Jumunjin_Beach_20220501_016.jpg?width=1920&crop=false"], "category_raw": "12", "tour_count": 3, "nearby_landmarks": ["신천", "신천자전거길", "신천수변공원"], "confidence": "high", "address": "대한민국 대구광역시 남구 봉덕동 878-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼칭이길 해변', '통영의 대표 자전거 코스인 삼칭이길(수륙~일운 해안도로)에 위치한 해변입니다. 평탄한 자전거 전용도로를 달리며 탁 트인 바다와 기암괴석 풍경을 감상하기 좋습니다.', '{beach,viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.439398, 34.819711), 4326), false, '{"source": "KOMOOT", "source_ids": ["1073", "235", "165", "199", "99", "897", "1734", "322", "710", "284"], "image_urls": ["https://photos.komoot.de/wiki/commons/d/d1/주문진해수욕장_향호해변.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bd/Jumunjin_Beach_20220501_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/30/Jumunjin_Beach_20220501_007.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/10/Jumunjin_Beach_20220501_013.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2a/Jumunjin_Beach_20220501_016.jpg?width=1920&crop=false"], "category_raw": "12", "tour_count": 3, "nearby_landmarks": ["삼칭이길", "수륙해수욕장", "통영등대낚시공원", "복바위"], "confidence": "high", "address": "대한민국 경상남도 통영시 산양읍 영운리 산33"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('해창쉼터', '새만금 방조제 진입 전후로 쉬어갈 수 있는 공원형 쉼터입니다. 화장실이 있으나 시설 관리가 다소 미흡할 수 있으니 참고하세요.', '{rest_area,park,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.576597, 35.699527), 4326), false, '{"source": "KOMOOT", "source_ids": ["1369", "970", "357"], "category_raw": "14", "tour_count": 3, "nearby_landmarks": ["새만금방조제", "부안신재생에너지테마파크"], "confidence": "high", "address": "대한민국 전북특별자치도 부안군 하서면 백련리 1018-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('용암 현대3차아파트', '청주시 용암동에 위치한 아파트 단지로, 지역 라이더들의 코스 기준점이나 만남의 장소로 활용됩니다. 인근 낙가천과 무심천 자전거길로 진입하기 좋습니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.504198, 36.61047), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 3, "nearby_landmarks": ["낙가천 자전거길", "무심천 자전거길", "용암동"], "confidence": "high", "address": "대한민국 청주시 현대3차아파트"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('풍남문', '전주읍성의 남문인 풍남문으로, 북측 현판에 ''호남제일성''이라 적혀 있습니다. 전주 한옥마을과 남부시장 사이에 위치해 라이딩 중 사진을 남기기 좋은 대표적인 역사 랜드마크입니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.148055, 35.813607), 4326), false, '{"source": "KOMOOT", "source_ids": ["1199", "603", "553"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/11/117yadg7sy9ud1dwg7g5a749ox3y8m1d5s-uhi43398139/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1l/1li6knqeavlxolwyscoqjq0cc3y8m1d6w-uhi43398140/0?width=1920&crop=false"], "category_raw": "historical_site", "tour_count": 3, "nearby_landmarks": ["전주 한옥마을", "전동성당", "전주 남부시장", "경기전"], "confidence": "high", "address": "대한민국 전북특별자치도 전주시 완산구 전동 77-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('아산호 전망대', '탁 트인 경관을 자랑하는 아산호(평택호)입니다. 수변을 따라 자전거길이 이어져 있어 호수 풍경을 감상하며 여유롭게 라이딩하기 좋습니다.', '{lake,viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.960509, 36.906004), 4326), false, '{"source": "KOMOOT", "source_ids": ["367", "680", "261", "535"], "category_raw": "190", "tour_count": 3, "nearby_landmarks": ["아산만방조제", "평택호", "서해랑길"], "confidence": "high", "address": "대한민국 충청남도 아산시 영인면 구성리 158-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('화정천 자전거길 시점', '화정천 자전거길과 산책로가 시작되는 상류 지점입니다. 시화호 방향으로 이어지는 자전거 코스의 출발점 및 휴식처로 유용합니다.', '{river,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.819659, 37.348753), 4326), false, '{"source": "KOMOOT", "source_ids": ["516", "673", "118"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/v9/v9c12mgwatmn10xhc9e8joiux4y7rl3ip-uhi71084191/0?width=1920&crop=false"], "category_raw": "lake", "tour_count": 3, "nearby_landmarks": ["정지공원", "화정천 산책로"], "confidence": "high", "address": "대한민국 경기도 안산시 단원구 선부동 318-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('휘게 도예 카페', '용인 이동읍에 위치한 아늑한 가정집 개조 카페입니다. 야외 좌석과 여유로운 분위기를 갖춰 라이딩 중 편안하게 휴식하며 보급하기 좋습니다.', '{cafe,restaurant,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.185547, 37.193905), 4326), false, '{"source": "KOMOOT", "source_ids": ["437", "216", "435"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/82/82v16zykolvo1sncfnm0i4ofr504cnnoj-uhi73327987/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/wy/wyx1xcemkk2h41vwqtur0ari504cnp97-uhi73327988/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1g/1g6fc7c6r79ywixd5gsb9g0hl504cnpxm-uhi73327989/0?width=1920&crop=false"], "tips": [{"text": "Super cute little cafe, have passed it countless times in the car and never quite had the opportunity to call in. Friendly owner and very chilled out ambiance, sat out the back to rest towards the end of my ride ✌🏻\n\n[NAVER Map]\nHwige\n경기 용인시 처인구 이동읍 서리로 46 1층\nhttps://naver.me/GUt1jlhX", "author": "Jon"}], "category_raw": "cafe", "tour_count": 3, "nearby_landmarks": ["용인 한숲시티", "학고개", "처인성"], "confidence": "high", "address": "대한민국 용인시 대원슈퍼"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남한강 비내섬 강변길', '남한강 자전거길 중 충주 앙성면 영죽리를 지나는 한적한 강변 구간입니다. 비내섬과 강천보 사이에 위치하며, 남한강의 수려한 자연을 감상하며 달리기 좋습니다.', '{river,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.768338, 37.155222), 4326), false, '{"source": "KOMOOT", "source_ids": ["1294", "959"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/ph/phc04c3y57ft17zp9no86ulot59xxvw1r-uhi83121210/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 2, "nearby_landmarks": ["남한강", "비내섬", "비내섬 인증센터"], "confidence": "high", "address": "대한민국 충청북도 충주시 앙성면 영죽리 33-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('제4수원지', '무등산 자락에 위치한 맑은 저수지로, 울창한 숲길 코스를 달리며 탁 트인 경관을 감상하고 인접한 청풍쉼터에서 쉬어가기 좋습니다.', '{lake,nature,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.961888, 35.164231), 4326), false, '{"source": "KOMOOT", "source_ids": ["877", "229"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["청풍쉼터", "청암교", "무등산 국립공원"], "confidence": "high", "address": "대한민국 광주광역시 북구 청풍동 산71-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('김포 석탄리 철새조망지', '김포 평화누리길 3코스에 위치한 군 검문소 겸 철새도래지입니다. 한강 철책을 따라 자연 생태를 감상하며 라이딩하기 좋으나, 군사지역이므로 통행 주의가 필요합니다.', '{checkpoint,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.66853, 37.735609), 4326), false, '{"source": "KOMOOT", "source_ids": ["403", "155"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1b/1bqv7wpmgyb7vd8huaryc5mvy3w9n2vsn-uhi40486712/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/pq/pqxwrmycqnk79mzu5zs460ju3w9n3fxo-uhi40486717/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/8z/8zofsdawg4fa3osuet9cec2g3w9n3lp0-uhi40486719/0?width=1920&crop=false"], "category_raw": "trail", "tour_count": 2, "nearby_landmarks": ["석탄리 철새조망지", "한강 철책길", "평화누리길 3코스"], "confidence": "high", "address": "대한민국 경기도 김포시 하성면 석탄리 810"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('KBS 광주방송총국', '광주 상무지구에 위치한 방송국 건물로 도심 라이딩 시 길잡이가 되는 랜드마크입니다. 인근 상무시민공원, 평화공원과 연계해 가볍게 경유하기 좋습니다.', '{landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.85568, 35.159074), 4326), false, '{"source": "KOMOOT", "source_ids": ["166", "141"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/bc/bcay6arot7do1hf50ag7cscyp37e5m9s6-uhi9476467/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1l/1l7nwn7jpvyjr1pilqdttl6re037e5mbko-uhi9476468/0?width=1920&crop=false"], "category_raw": "other_man_made", "tour_count": 2, "nearby_landmarks": ["상무시민공원", "평화공원", "광주광역시청"], "confidence": "high", "address": "대한민국 광주광역시 서구 치평동 1200-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('NLCS 제주', '제주영어교육도시에 위치한 국제학교입니다. 주변 도로가 넓고 쾌적하여 제주 남서부 내륙 코스 라이딩 시 길잡이가 되는 주요 랜드마크입니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.285425, 33.296583), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 2, "nearby_landmarks": ["제주영어교육도시", "제주곶자왈도립공원", "오설록 티뮤지엄"], "confidence": "high", "address": "대한민국 서귀포시 NLCS 제주"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오산천 반송교 하부', '동탄 반송동 일대를 지나는 오산천 자전거길 구간으로, 교량 하부를 통과합니다. 자전거길이 평탄하게 잘 정비되어 있어 쾌적한 라이딩이 가능합니다.', '{river,bridge}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.082666, 37.191102), 4326), false, '{"source": "KOMOOT", "source_ids": ["66", "142"], "category_raw": "river", "tour_count": 2, "nearby_landmarks": ["오산천", "동탄신도시"], "confidence": "high", "address": "대한민국 경기도 화성시 반송동 752"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('합천창녕보 인증센터', '낙동강 자전거길의 합천창녕보 인증센터입니다. 주변에 숙소가 적어 늦은 오후가 되면 하류 쪽 모텔에서 무료 픽업 차량을 제공하기도 하니 참고하세요.', '{checkpoint,rest_area,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.361623, 35.590969), 4326), false, '{"source": "KOMOOT", "source_ids": ["2", "540"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/9x/9xfj9ba64gqra7cxtpmk0ixe5du4kyd3-uhi87158990/0?width=1920&crop=false"], "tips": [{"text": "In the late afternoons you will find Motel owners offering free transfer to their 10 km downstream located cheap motels", "author": "Fitz_carraldo"}], "category_raw": "other_man_made", "tour_count": 2, "nearby_landmarks": ["합천창녕보", "낙동강"], "confidence": "high", "address": "대한민국 경상남도 창녕군 이방면 등림리 641-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('Uri Jip', '개인이 ''우리집''으로 등록한 사유지(주택)로 추정됩니다. 라이더를 위한 공공 시설이나 상업 시설이 아니므로 코스 계획 시 참고하시기 바랍니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.903228, 37.47967), 4326), false, '{"source": "KOMOOT", "source_ids": ["364", "64"], "category_raw": "facilities", "tour_count": 2, "nearby_landmarks": ["문성초등학교", "한양수자인아파트"], "confidence": "high", "address": "대한민국 서울특별시 금천구 독산동 996-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('새비재 배추밭 전망대', '정선 새비재 인근 고랭지 배추밭과 산세를 조망할 수 있는 뷰포인트입니다. 가파른 업힐 끝에 탁 트인 절경을 만날 수 있습니다.', '{viewpoint,mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.688983, 37.202555), 4326), false, '{"source": "KOMOOT", "source_ids": ["1732", "148"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/18/18v79ppco7fceruw29f2i6kvr37ddlvbp-uhi9471550/0?width=1920&crop=false"], "category_raw": "viewpoint", "tour_count": 2, "nearby_landmarks": ["타임캡슐공원", "새비재", "엽기소나무"], "confidence": "high", "address": "대한민국 강원특별자치도 정선군 신동읍 방제리 443-177"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('박근혜 전 대통령 사저', '박근혜 전 대통령의 달성군 사저로, 라이딩 중 잠시 들러 구경하기 좋은 지역 랜드마크입니다. 주변 경비가 삼엄할 수 있으니 통행에 주의하세요.', '{landmark,historic}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.458724, 35.705828), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 2, "nearby_landmarks": ["비슬구천공원", "대구테크노폴리스", "비슬산"], "confidence": "high", "address": "대한민국 대구광역시 달성군 유가읍 쌍계리 29"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('가평역', '북한강 자전거길의 주요 출발·도착지이자 전철 점프 거점인 가평역입니다. 화장실, 편의점 등 라이더를 위한 편의시설이 잘 갖춰져 있습니다.', '{transit,restroom,convenience_store,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.511164, 37.814806), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/b/bc/Gapyeong_Station_Front.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["북한강 자전거길", "자라섬", "남이섬"], "confidence": "high", "address": "대한민국 경기도 가평군 가평읍 달전리 603-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('갈마역', '대전 도시철도 1호선 갈마역입니다. 인접한 갈마공원에서 휴식을 취하거나, 자전거 점프 등 대중교통 연계 거점으로 활용하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.37275, 36.357634), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/7/7a/Galma_stn.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["갈마공원", "월평도서관", "올림픽기념국민생활관"], "confidence": "high", "address": "대한민국 대전광역시 갈마"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('갑곶돈대', '강화도 자전거 일주 코스의 인기 출발지이자 주차 거점입니다. 강화해협이 보이는 역사적 요새로, 화장실과 휴식 공간이 잘 갖춰져 있습니다.', '{historic,landmark,parking,rest_area,museum,restroom,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.517431, 37.732848), 4326), false, '{"source": "KOMOOT", "source_ids": ["548", "296"], "category_raw": "15", "tour_count": 2, "nearby_landmarks": ["강화전쟁박물관", "강화대교", "6.25참전용사기념공원"], "confidence": "high", "address": "대한민국 인천광역시 강화군 선원면 신정리 10-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('강동구청', '올림픽공원과 천호자전거거리 인근의 주요 관공서입니다. 개방 화장실과 식수대(정수기)를 이용할 수 있어 라이딩 중 안전하게 휴식과 재정비를 하기 좋습니다.', '{restroom,water_fountain,parking,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.120625, 37.530677), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/b/b8/Gangdong-gu_Office_Station_20241102_002.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/ad/Seoul-metro-812-Gangdong-gu-office-station-platform-20181125-124856.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c7/Seoul-metro-812-Gangdong-gu-office-station-entrance-5-20181125-125502.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6a/Gangdong-gu_office_Station_1.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8e/Gangdong-gu_Office_Station_20241102_003.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["천호자전거거리", "올림픽공원", "광나루 한강공원"], "confidence": "high", "address": "대한민국 서울특별시 강동구 올림픽로 550"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('강매역', '경의중앙선 강매역입니다. 성사천 자전거길과 바로 연결되어 라이딩 출발지나 대중교통 점프(환승) 장소로 유용하며, 화장실과 자전거 보관소가 있습니다.', '{transit,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.844526, 37.612596), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/a/ad/Gangmae_Station_20150304_163214.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/5d/Gangmae_Station_20150304_163534.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a1/Gangmae_Station_20150304_163452.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/5f/Gangmae_Station_(2).JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/46/Korail_Gangmae_station.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["성사천 자전거길", "강매석교공원", "행주산성"], "confidence": "high", "address": "대한민국 경기도 고양시 덕양구 행신동 108-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('강일역', '지하철 5호선 강일역입니다. 고덕천 자전거도로와 가까워 한강 진출입이 용이하며, 주말 자전거 휴대 승차를 통한 점프 포인트로 유용합니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.175749, 37.557519), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/b/b7/20210408_강일역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b5/20210408_강일역_역명판.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["고덕천 자전거도로", "강일 나들목"], "confidence": "high", "address": "대한민국 서울특별시 강일"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('개롱역', '지하철 5호선 개롱역입니다. 인근에 성내천 자전거길이 있으며, 역 주변 따릉이 대여소를 통해 대중교통과 연계한 라이딩을 즐기기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.134839, 37.49807), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/0/0f/Seoul-metro-P553-Gaerong-station-sign-20180915-103600.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/58/Seoul-metro-P553-Gaerong-station-entrance-3-20180915-103206.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/57/Seoul-metro-P553-Gaerong-station-platform-20180915-103628.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["오금공원", "성내천 자전거길"], "confidence": "high", "address": "105호, 아람빌딩 400 오금로 송파구 서울특별시 대한민국"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('거제자동차학원', '거제 양정동에 위치한 자동차 운전학원입니다. 부지가 넓어 라이딩 중 현재 위치를 파악하거나 경로를 확인하는 랜드마크로 활용하기 좋습니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.638884, 34.890253), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 2, "nearby_landmarks": ["거제시보건소", "신현농협하나로마트 수양점"], "confidence": "high", "address": "대한민국 거제시 거제자동차학원"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('경기광주역', '경강선 경기광주역입니다. 188대 규모의 전용 자전거 주차장이 있으며, 태전지구와 연결되는 자전거도로가 개통되어 라이딩 거점으로 활용하기 좋습니다.', '{transit,parking,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.253427, 37.399084), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/7/7b/Gyeonggi_Gwangju_Station_Panorama.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f8/Gyeonggi_Gwangju_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bc/Gyeonggi_Gwangju_Station_Exit_1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/40/GyeonggiGwangju_1.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["경안천", "중대천", "태전지구"], "confidence": "high", "address": "대한민국 경기도 광주시 역동 215-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('경주읍성 발굴지', '경주읍성의 옛 성벽 터를 발굴하는 유적지로, 경주 시내 자전거 여행 중 역사적 흔적을 살펴볼 수 있는 명소입니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.212503, 35.850068), 4326), false, '{"source": "KOMOOT", "source_ids": ["758", "6"], "category_raw": "17", "tour_count": 2, "nearby_landmarks": ["경주읍성", "계림초등학교"], "confidence": "high", "address": "대한민국 경상북도 경주시 성건동 43-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('계촌저수지', '420번 지방도 옆에 위치한 평창군 방림면의 조용한 저수지입니다. 산세와 어우러진 고즈넉한 수변 풍경을 감상하며 라이딩하기 좋은 자연 포인트입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.281896, 37.458), 4326), false, '{"source": "KOMOOT", "source_ids": ["364", "1220"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["평창강", "계촌마을"], "confidence": "high", "address": "대한민국 강원특별자치도 평창군 방림면 계촌리 2101"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('고복저수지', '세종시의 인기 라이딩 코스로 아름다운 호수 풍경과 봄철 벚꽃길이 유명합니다. 주변에 식당과 카페가 많아 라이딩 중 휴식하기 좋습니다.', '{lake,park,nature,viewpoint,restaurant,cafe}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.238224, 36.606964), 4326), false, '{"source": "KOMOOT", "source_ids": ["795", "586"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["연기대첩비공원", "민락정", "오봉산"], "confidence": "high", "address": "대한민국 세종특별자치시 연서면 고복리 562-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('고사포해수욕장', '변산해변 자전거길에 위치한 해수욕장입니다. 울창한 송림과 바다 경치가 아름다우며, 야영장 인근에 화장실과 매점 등 편의시설이 있어 라이딩 중 휴식하기 좋습니다.', '{beach,rest_area,restroom,convenience_store,viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.505651, 35.660081), 4326), false, '{"source": "KOMOOT", "source_ids": ["559", "179"], "category_raw": "12", "tour_count": 2, "nearby_landmarks": ["고사포야영장", "하섬", "변산반도국립공원"], "confidence": "high", "address": "대한민국 전북특별자치도 부안군 변산면 운산리 441-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('곡강천', '포항 흥해읍을 가로지르는 하천으로, 칠포해수욕장까지 이어지는 자전거길과 생태공원이 조성되어 있어 쾌적한 자연 속 라이딩을 즐길 수 있습니다.', '{river,park,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.398171, 36.128886), 4326), false, '{"source": "KOMOOT", "source_ids": ["223", "389"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["곡강천 생태공원", "칠포해수욕장", "용연저수지"], "confidence": "high", "address": "대한민국 경상북도 포항시 북구 흥해읍 곡강리 510-12"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('공세리성당', '아산만과 삽교천 인근에 위치한 한국에서 가장 아름다운 성당 중 하나입니다. 안성천, 곡교천 자전거길과 연계하여 방문하기 좋은 역사적인 라이딩 명소입니다.', '{historic,landmark,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.914006, 36.882584), 4326), false, '{"source": "KOMOOT", "source_ids": ["380", "794"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/f1/f1th1jwjngsoyd106ybef7bm4qdcq5md-uhi65873182/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/w6/w6zwtwebkuyd1kivb711cmjd74qdcq72q-uhi65873183/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1b/1bk7fsfetxa07edmnxbuob0s4qdcqfdg-uhi65873187/0?width=1920&crop=false"], "category_raw": "religious_building", "tour_count": 2, "nearby_landmarks": ["삽교천", "곡교천 은행나무길", "아산만방조제"], "confidence": "high", "address": "대한민국 충청남도 아산시 인주면 공세리 193-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('공작산저수지', '홍천 공작산 아래 위치한 맑고 경치 좋은 계곡형 저수지입니다. 자연 경관이 뛰어나 라이딩 중 호수 뷰를 감상하며 쉬어가기 좋습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.024699, 37.693357), 4326), false, '{"source": "KOMOOT", "source_ids": ["274"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["공작산", "공작산자연휴양림"], "confidence": "high", "address": "대한민국 강원특별자치도 홍천군 영귀미면 노천리 산203-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('공터', '탄천 자전거길 기점인 용인 청덕동 인근의 공터입니다. 라이더들의 만남의 장소나 출발 전 주차 및 휴식 공간으로 활용하기 좋습니다.', '{rest_area,parking,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.150636, 37.292373), 4326), false, '{"source": "KOMOOT", "source_ids": ["584", "400"], "category_raw": "191", "tour_count": 2, "nearby_landmarks": ["탄천 자전거길 기점", "물푸레마을", "아람공원"], "confidence": "medium", "address": "대한민국 경기도 용인시 기흥구 청덕동 600"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광운대학교', '중랑천 및 우이천 자전거길과 인접한 대학교입니다. 인근 광운대역은 경춘선 자전거길의 출발점이자 대중교통 연계 거점으로 라이더들이 자주 이용합니다.', '{landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.061177, 37.623517), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/0/01/Korail-119-Kwangwoon-university-station-platform-20181122-123400.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/83/Korail-119-Kwangwoon-university-station-entrance-3-20181126-140224.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b3/119_성북_(광운대앞).JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b5/Kwangwoon_University_Station_3.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/ko/c/c9/%EC%84%B1%EB%B6%81_2%EB%B2%88_%EC%8A%B9%EA%B0%95%EC%9E%A5.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["중랑천", "우이천", "광운대역", "경춘선 자전거길"], "confidence": "high", "address": "대한민국 서울특별시 노원구 월계동 85-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광장로 라이딩', '천안 불당동 신도시를 가로지르는 광장로 일대의 라이딩 코스입니다. 인근에 불당천과 도심 공원이 있어 가볍게 주행하기 좋습니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.098705, 36.79768), 4326), false, '{"source": "KOMOOT", "source_ids": ["65", "1230"], "category_raw": "cycle_way", "tour_count": 2, "nearby_landmarks": ["천안호수초등학교", "생태터널사거리", "불당천"], "confidence": "high", "address": "대한민국 충청남도 천안시 서북구 불당동 1288"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구래역', '김포골드라인 구래역입니다. 주변 상권이 발달해 라이딩 중 식사와 보급을 하기 좋으나, 일반 자전거는 전철에 탑승할 수 없으니 유의하세요.', '{transit,restroom,convenience_store,restaurant,cafe}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.628689, 37.645343), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/3/32/Gurae_Station3.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/91/Gurae_Station2.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["이마트 김포한강점", "구래환승센터", "한강신도시 호수공원"], "confidence": "high", "address": "대한민국 김포시 구래"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구리 한강시민공원', '서울과 남양주를 잇는 한강 자전거길의 주요 거점 공원입니다. 넓은 주차장, 편의점, 화장실, 음수대 등 편의시설이 잘 갖춰져 있어 라이딩 출발지나 휴식처로 매우 좋습니다.', '{parking,park,river,restroom,convenience_store,water_fountain,rest_area,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.150823, 37.5763), 4326), false, '{"source": "KOMOOT", "source_ids": ["161", "822"], "category_raw": "parking", "tour_count": 2, "nearby_landmarks": ["구리암사대교", "왕숙천", "코스모스 꽃단지"], "confidence": "high", "address": "대한민국 경기도 구리시 토평동 465-121 코스모스길 옆 자전거 도로"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('지리산호수공원', '지리산 자락의 맑은 저수지로, 수변 데크길과 출렁다리가 조성된 지리산호수공원이 있어 라이딩 중 수려한 경관을 보며 쉬어가기 좋습니다.', '{lake,park,nature,bridge,rest_area,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.424697, 35.281897), 4326), false, '{"source": "KOMOOT", "source_ids": ["8", "369"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["지리산치즈랜드", "지리산호수공원오토캠핑장", "지리산온천"], "confidence": "high", "address": "대한민국 전라남도 구례군 산동면 이평리 산30-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('국민건강보험.정보고등학교', '국민건강보험공단과 경주정보고등학교 인근에 위치한 버스 정류장입니다. 라이딩 중 위치를 확인하거나 잠시 대기하는 포인트로 활용하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.176949, 35.844318), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 2, "nearby_landmarks": ["국민건강보험공단 경주지사", "경주정보고등학교", "문화중고등학교"], "confidence": "high", "address": "대한민국 경상북도 경주시 충효동 556"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('굴포천', '아라뱃길과 한강 자전거길로 연결되는 주요 하천 코스입니다. 굴포천역 지하차도 인근으로 대중교통 접근성이 좋으나, 일부 구간의 노면 상태에 주의해야 합니다.', '{river,transit,tunnel}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.731292, 37.507016), 4326), false, '{"source": "KOMOOT", "source_ids": ["58", "1786", "278", "339", "92", "512"], "image_urls": ["https://photos.komoot.de/wiki/commons/a/a6/Gulpocheon-20121030-1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b0/Gulpocheon-20121030-3.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/ko/b/b1/Gulpocheon-20121030-4.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8b/Gulpocheon_Station3.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/59/Gulpocheon-20121030-2.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["굴포천역", "삼산체육관", "부평구청"], "confidence": "high", "address": "대한민국 인천광역시 부평구 길주로 굴포천역지하차도"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('궁남지', '백제 시대에 조성된 인공 연못으로, 금강 자전거길이나 부여 사비길 라이딩 중 연꽃 절경을 보며 쉬어가기 좋은 역사 공원입니다.', '{lake,historic,landmark,park,rest_area,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.912959, 36.269914), 4326), false, '{"source": "KOMOOT", "source_ids": ["50", "759"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/8a/8ajxsypnd6lp5wmpgeb5ox4d3xohfoo1-uhi42660193/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/a2/a299imujvodzfeb3aaov303c3xohfox7-uhi42660194/0?width=1920&crop=false"], "category_raw": "lake", "tour_count": 2, "nearby_landmarks": ["국립부여박물관", "정림사지", "부소산성"], "confidence": "high", "address": "대한민국 충청남도 부여군 부여읍 동남리 118-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금강하구둑 인증센터', '금강 자전거길의 종점이자 국토종주 필수 인증센터입니다. 탁 트인 금강하구둑과 철새조망대 풍경을 감상하며 라이딩을 마무리하거나 시작하기 좋은 거점입니다.', '{checkpoint,river,rest_area,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.764585, 36.020519), 4326), false, '{"source": "KOMOOT", "source_ids": ["803", "593"], "tips": [{"text": "Korea Cross Country Cycling Road Tour Certification Stamp Booth", "author": "Fitz_carraldo"}], "category_raw": "facilities", "tour_count": 2, "nearby_landmarks": ["금강하구둑", "금강철새조망대", "금강호 휴게소"], "confidence": "high", "address": "대한민국 전북특별자치도 군산시 성산면 성덕리 421-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금곡역 낙동강 자전거길 진입로', '부산 2호선 금곡역 4번 출구에서 낙동강 종주 자전거길로 바로 연결되는 진입로입니다. 대중교통 연계 및 라이딩 시작점으로 유용합니다.', '{transit,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.016055, 35.266669), 4326), false, '{"source": "KOMOOT", "source_ids": ["88", "1138"], "category_raw": "14", "tour_count": 2, "nearby_landmarks": ["금곡역", "낙동강 종주 자전거길"], "confidence": "high", "address": "대한민국 부산광역시 북구 금곡동 603-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금사역', '부산 도시철도 4호선 금사역입니다. 수영강 자전거길과 가까워 연계 라이딩에 좋으며, 주말과 공휴일에는 자전거 휴대 승차가 가능해 점프 거점으로 유용합니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.115258, 35.215863), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/4/4e/Geumsa_Station.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e1/408geumsa1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/ec/Busan-subway-408-Geumsa-station-entrance-3-20180401-084138.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/79/408geumsa2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/33/Geumsa_Station_4.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["수영강", "금사공단"], "confidence": "high", "address": "대한민국 부산광역시 금사"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금정산성 서문', '부산 금정산성의 4대문 중 하나로, 자전거 라이더들에게 인기 있는 업힐 코스의 주요 거점이자 역사적 명소입니다. 대천천 자전거길과 연결되어 있습니다.', '{historic,landmark,mountain,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.045431, 35.251487), 4326), false, '{"source": "KOMOOT", "source_ids": ["104"], "category_raw": "17", "tour_count": 2, "nearby_landmarks": ["금정산성", "화명수목원", "대천천"], "confidence": "high", "address": "대한민국 부산광역시 금정구 금성동 1098"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('길의 끝', '평택시 죽백동에 위치한 자전거 트레일의 끝 지점입니다. 더 이상 길이 이어지지 않는 막다른 곳이므로 라이더들은 이곳에서 유턴하여 돌아가야 합니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.107812, 37.017713), 4326), false, '{"source": "KOMOOT", "source_ids": ["212", "463"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1g/1gszw9yo6ycfn1b3mb4qnzw1hl3truyctp-uhi36535906/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/hr/hrinzppu4eaf2ofmbiv5v1so3truyiq0-uhi36535909/0?width=1920&crop=false"], "tips": [{"text": "Turn Around!", "author": "Adam"}], "category_raw": "trail", "tour_count": 2, "nearby_landmarks": ["배다리생태공원", "죽백동 자전거길"], "confidence": "high", "address": "대한민국 경기도 평택시 죽백동 668-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('낙동강', '안동 단호리를 지나는 낙동강 종주 자전거길 구간입니다. 탁 트인 강변 풍경을 감상하며 라이딩하기 좋으며, 인근에 단호샌드파크가 있습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.620718, 36.555714), 4326), false, '{"source": "KOMOOT", "source_ids": ["303", "279", "72", "346", "467", "1484", "370", "589", "796", "151"], "image_urls": ["https://photos.komoot.de/wiki/commons/f/f0/낙동강.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3e/Andong_Bridge.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a3/Korea-Andong-Nakdong_River-02.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/58/Korea-Andong-Nakdong_River-01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f6/상주보.jpg?width=1920&crop=false"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["단호샌드파크", "낙암정", "낙동강생태학습관"], "confidence": "high", "address": "대한민국 경상북도 안동시 남후면 단호리 135-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('낙동강 금곡 전망대', '부산 금곡동 낙동강 자전거길에 위치한 탁 트인 강변 전망 포인트입니다. 호수처럼 넓은 낙동강의 수려한 경치를 감상하며 달릴 수 있어 라이더들에게 강력히 추천되는 코스입니다.', '{viewpoint,river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.008289, 35.251019), 4326), false, '{"source": "KOMOOT", "source_ids": ["1165", "115"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/13/13zo4w933b38n6pyulibhsf5i4r1o1fey-uhi66526437/0?width=1920&crop=false"], "tips": [{"text": "A highly recommended route!", "author": "Ferry Y"}], "category_raw": "cycle_way", "tour_count": 2, "nearby_landmarks": ["낙동강", "화명생태공원", "금곡역"], "confidence": "high", "address": "대한민국 부산광역시 북구 금곡동 1518-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('낙동강하굿둑 인증센터', '자전거 국토종주 및 낙동강 자전거길의 최종 종착지입니다. 기나긴 라이딩의 성취감을 만끽하며 종주 인증 도장을 찍고 쉬어갈 수 있는 상징적인 장소입니다.', '{checkpoint,landmark,rest_area,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.948, 35.108456), 4326), false, '{"source": "KOMOOT", "source_ids": ["218", "338"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/c5/c5qns75xmqkkxgsjtnau9brs4qiwmiwd-uhi66063572/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1e/1e9mix6ev7llpso1s87eaupli4rtit8nt-uhi67090612/0?width=1920&crop=false"], "tips": [{"text": "낙동강 자전거길 종착지", "author": "Seunghun Kim"}], "category_raw": "cycle_way", "tour_count": 2, "nearby_landmarks": ["낙동강하굿둑", "을숙도 생태공원"], "confidence": "high", "address": "낙동강하굿둑인증센터, 낙동남로1233번길 하단제2동 사하구 부산광역시 대한민국"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('낙산해수욕장 송림길', '동해안 자전거길이 지나는 낙산해수욕장 인근의 송림 구간입니다. 탁 트인 바다 경치와 시원한 소나무 숲길을 즐기며 쉬어가기 좋은 라이딩 명소입니다.', '{beach,park,nature,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.63603, 38.114072), 4326), false, '{"source": "KOMOOT", "source_ids": ["816", "1517"], "category_raw": "191", "tour_count": 2, "nearby_landmarks": ["낙산해수욕장", "낙산사", "동해안 자전거길"], "confidence": "high", "address": "대한민국 강원특별자치도 양양군 양양읍 조산리 433-22"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구 남문산역', '경전선 폐철도 부지를 활용해 조성된 자전거길의 주요 거점입니다. 옛 기차역의 고즈넉한 정취를 느끼며 쾌적한 라이딩을 즐길 수 있습니다.', '{historic,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.162891, 35.164917), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/60/Korail_Gyeongjeon_Line_Nammunsan_Station_Rearside.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["문산성당", "문산전통시장"], "confidence": "high", "address": "대한민국 경상남도 진주시 동부로 556-5 구 남문산역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남원역', 'KTX 남원역으로 섬진강, 지리산 라이딩의 주요 점프(이동) 포인트입니다. 역 광장에 자전거 대여소(자전거RO)가 운영되어 로컬 라이딩을 시작하기 좋습니다.', '{transit,restroom,convenience_store,parking,bike_shop}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.361699, 35.411152), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/54/Namwon_Station_2013-02-13.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/58/Namwon_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2f/남원3.1운동기념비.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e6/Old_Namwon_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/25/Namwon_Station_board.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["요천자전거길", "광한루원", "춘향테마파크"], "confidence": "high", "address": "대한민국 남원시 남원역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남한산성 행궁', '유명한 남한산성 업힐 코스 정상부에 위치한 역사 명소입니다. 주변에 식당과 카페 등 보급처가 많지만, 주말에는 관광객과 차량이 많아 라이딩 시 주의해야 합니다.', '{historic,landmark,park,convenience_store,cafe,restaurant,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.184052, 37.477893), 4326), false, '{"source": "KOMOOT", "source_ids": ["928", "1679"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/19/19ra1f9pgc6yfnu162ukoqrts3t9yz0fc-uhi35869353/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1r/1ry8n1bugrbirv5lk5qd0jc543t9yz56i-uhi35869364/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1c/1cw6vtfpxy82ohhasioim6jh23t9yz9kh-uhi35869381/0?width=1920&crop=false"], "tips": [{"text": "actually the whole area is kind of recreation park. if you love hiking this is a good spot, but there are a lot of people especially during weekends. Restaurants, Cafés, Convenience Stores, etc. all you need for a full day outdoors. Even cyclists love the road which leads from all the way up to the small NHSS Village. The Fortress itself is stunning, as well as the 8km long wall you can walk along.", "author": "667 The Neighbour of the Beast"}], "category_raw": "historical_site", "tour_count": 2, "nearby_landmarks": ["남한산성", "수어장대", "남한산성 남문", "남한산성 북문"], "confidence": "high", "address": "대한민국 경기도 광주시 남한산성면 산성리 526-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('내리저수지', '기장군에 위치한 한적한 농업용 저수지로 안적사나 산성산 방면 라이딩 시 거쳐가는 길목입니다. 물안개 등 자연 경관이 수려해 가볍게 둘러보기 좋습니다.', '{lake,nature,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.186925, 35.220248), 4326), false, '{"source": "KOMOOT", "source_ids": ["58", "126"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["안적사", "산성산"], "confidence": "high", "address": "대한민국 부산광역시 기장군 기장읍 내리 741"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('내리회관', '안성천 자전거길과 내리문화공원 인근에 위치한 마을회관입니다. 평택 시내버스 종점이기도 하며, 라이딩 중 위치를 확인하거나 잠시 쉬어가는 기점으로 활용하기 좋습니다.', '{landmark,transit,checkpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.027291, 36.973665), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 2, "nearby_landmarks": ["내리문화공원", "안성천", "안성천 자전거길"], "confidence": "high", "address": "대한민국 경기도 평택시 팽성읍 내리 96-17"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('내린천', '홍천에서 인제로 흐르는 맑고 수려한 하천입니다. 구룡령이나 살둔계곡 방면으로 이어지는 아름다운 계곡 라이딩 코스로 인기가 높습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.402859, 37.834002), 4326), false, '{"source": "KOMOOT", "source_ids": ["735", "442"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["살둔계곡", "칡소폭포", "구룡령"], "confidence": "high", "address": "대한민국 강원특별자치도 홍천군 내면 광원리 1499-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('노들섬 서측 잔디마당', '자전거로 접근하기 좋은 한강 노들섬의 서쪽 공원입니다. 넓은 잔디밭에서 피크닉을 즐기며 여의도 스카이라인과 아름다운 일몰을 감상할 수 있는 완벽한 휴식처입니다.', '{park,rest_area,viewpoint,cafe,restaurant,convenience_store,restroom,parking,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.955045, 37.518783), 4326), false, '{"source": "KOMOOT", "source_ids": ["569", "959"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/s7/s7jobbfeoy4j185wm9ps8jorz3sqs2dj8-uhi35088702/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/fw/fwmmcm261kgqj3evxhlmvyxl3sqs2h5x-uhi35088703/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/98/988xoxtnaubp23kd65ecbl3a3sqs2ksp-uhi35088705/0?width=1920&crop=false"], "tips": [{"text": "great place for events, picnic, chill out, coffee, pizza, reading and much more. you can watch a great sunset and yeoido island with its great skyline is a always good for taking nice pictures. top infrastructure, can be easily reached by bus or bicycle.", "author": "667 The Neighbour of the Beast"}], "category_raw": "parking", "tour_count": 2, "nearby_landmarks": ["한강대교", "노들마당", "노들서가", "63빌딩"], "confidence": "high", "address": "대한민국 서울특별시 용산구 이촌동 314-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('느러지 전망대', '영산강 자전거길의 필수 인증센터로, 한반도 지형을 닮은 물돌이를 감상할 수 있는 전망대입니다. 초여름 수국길이 유명하며, 영산강 코스 중 드물게 짧은 업힐이 존재합니다.', '{viewpoint,checkpoint,rest_area,river,nature,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.541971, 34.915978), 4326), false, '{"source": "KOMOOT", "source_ids": ["700", "399"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/rx/rxlshwdkd2bkxv56qia7yb1r37e3ubo7-uhi9476249/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/12/1206lgmnwftz61720npzdn2rvp37e3uc4q-uhi9476250/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/gg/ggofxs4l4rxp1wnniyybc5blx37e3uciv-uhi9476251/0?width=1920&crop=false"], "category_raw": "viewpoint", "tour_count": 2, "nearby_landmarks": ["영산강", "느러지 전망대 인증센터", "한반도 지형 물돌이"], "confidence": "high", "address": "대한민국 전라남도 나주시 동강면 동강로 307-194"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('다랭이마을 전망대', '남해 해안도로 라이딩 중 탁 트인 바다와 계단식 다랭이논의 절경을 감상할 수 있는 유명 전망대입니다. 자전거를 잠시 멈추고 멋진 풍경을 배경으로 사진을 남기기 좋습니다.', '{viewpoint,landmark,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.89327, 34.725397), 4326), false, '{"source": "KOMOOT", "source_ids": ["1044", "717"], "category_raw": "14", "tour_count": 2, "nearby_landmarks": ["가천다랭이마을", "암수바위"], "confidence": "high", "address": "대한민국 경상남도 남해군 남면 홍현리 807-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('당고개지', '대구 수성구 삼덕동에 위치한 조용한 저수지입니다. 도심을 벗어나 한적한 농촌 풍경과 자연을 감상하며 여유롭게 라이딩하기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.659513, 35.824117), 4326), false, '{"source": "KOMOOT", "source_ids": ["659", "152"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["대구스타디움", "대덕지", "연호지"], "confidence": "high", "address": "대한민국 대구광역시 수성구 삼덕동 716"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('당리역 상권', '부산 1호선 당리역 인근의 상가 밀집 지역입니다. 카페, 식당 등이 모여 있어 라이딩 중 식음료 보급과 휴식을 취하거나 지하철을 연계하기 좋습니다.', '{transit,cafe,restaurant,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.973858, 35.103541), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/9/93/Dangni_Station_2010.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/1f/Busan-subway-103-Dangni-station-6-entrance.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/da/Dangni_subway_station-01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/94/Busan-subway-103-Dangni-station-platform.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["당리역", "사하구청"], "confidence": "high", "address": "대한민국 부산광역시 사하구 당리동 317-12"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대모산입구역', '수인분당선 대모산입구역입니다. 양재천 자전거길과 가까워 라이딩 진출입 및 만남의 장소로 유용하며, 역사 내 화장실을 이용할 수 있습니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.072756, 37.49138), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/65/Q46196_Daemosan_01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/1f/Korail-Bundang-line-K220-Daemosan-station-entrance-6-20181124-122558.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b1/대모산입구역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6b/Korail-Bundang-line-K220-Daemosan-station-entrance-3-20181124-122250.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/39/대모산입구역.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["양재천", "대모산"], "confidence": "high", "address": "대한민국 서울특별시 일원2동 대모산입구"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대불저수지', '무주군 설천면에 위치한 조용하고 한적한 저수지입니다. 산악 지형이 많은 무주 라이딩 코스 중 고즈넉한 수변 풍경을 감상하며 지나가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.821459, 36.011525), 4326), false, '{"source": "KOMOOT", "source_ids": ["334", "1317"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["라제통문", "덕유산"], "confidence": "high", "address": "대한민국 전북특별자치도 무주군 설천면 대불리 산27-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대천역', '장항선 대천역으로 대천해수욕장과 대천항으로 향하는 자전거 라이딩의 주요 출발점입니다. 내부에 편의점, 화장실, 대기실이 있어 보급과 휴식에 좋습니다.', '{transit,convenience_store,restroom,rest_area,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.58605, 36.341549), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["보령종합터미널", "이마트 보령점"], "confidence": "high", "address": "대한민국 충청남도 보령시 내항동 337"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대천해수욕장', '서해안의 탁 트인 바다 풍경을 감상하며 달릴 수 있는 해안 자전거길의 주요 경유지입니다. 넓은 백사장과 다양한 편의시설이 있어 라이딩 중 휴식하기 좋습니다.', '{beach,viewpoint,landmark,rest_area,restroom,convenience_store,cafe,restaurant,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.512171, 36.312606), 4326), false, '{"source": "KOMOOT", "source_ids": ["209", "164"], "image_urls": ["https://photos.komoot.de/wiki/commons/f/f3/Daecheon_Beach_during_Boryeong_Mud_Festival_-_panoramio.jpg?width=1920&crop=false"], "category_raw": "12", "tour_count": 2, "nearby_landmarks": ["대천항", "보령머드체험관", "대천해수욕장 스카이바이크"], "confidence": "high", "address": "대한민국 충청남도 보령시 신흑동 1143-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('덕수2리교차로', '산방산과 제주신화월드를 잇는 안덕면의 주요 교차로이자 버스 정류장입니다. 해안도로에서 중산간 지역으로 이동할 때 거쳐가는 길목으로 차량 통행에 주의가 필요합니다.', '{other,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.314209, 33.276665), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 2, "nearby_landmarks": ["산방산", "제주신화월드"], "confidence": "high", "address": "대한민국 제주특별자치도 서귀포시 안덕면 덕수리 1453-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('도봉역', '지하철 1호선 도봉역입니다. 중랑천 자전거길과 가까워 라이딩 전후로 지하철 점프를 하거나 만남의 장소로 활용하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.04556, 37.679284), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/a/a6/Dobong_Station_Jan_2006.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f3/Korail-114-Dobong-station-platform-20181126-123608.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/91/Korail-114-Dobong-station-entrance-2-20181126-123832.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a2/Q490310_Dobong_A01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/92/도봉역_방학방면_승강장.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["중랑천 자전거길", "서울북부지방법원"], "confidence": "high", "address": "대한민국 서울특별시 도봉구 도봉로170길 2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동백역', '부산 지하철 2호선 동백역입니다. 자전거 보관소가 설치되어 있어 대중교통 연계 및 주차에 용이합니다.', '{transit,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.148058, 35.161222), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/f/f0/Busan-subway-204-Dongbaek-station-4-entrance.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8f/Dongbaek_station_sign_20180317_211051.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8b/Dongbaek_Station_20200522_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/64/Dongbaek_station_platform_20180317_211033.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a3/Busan-subway-204-Dongbaek-station-platform.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["동백섬", "마린시티", "해운대해수욕장"], "confidence": "high", "address": "대한민국 부산광역시 해운대구 우동 993-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동천역', '신분당선 동천역입니다. 인근 동막천 및 탄천 자전거길과 가깝지만, 신분당선은 접이식 자전거만 휴대 승차가 가능하므로 점프(대중교통 연계) 시 주의가 필요합니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.102823, 37.338098), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/58/Q21025128_Dongcheon_A01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/df/Q21025128_Dongcheon_A02.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["동막천 자전거길", "탄천 자전거길", "동천유타워"], "confidence": "high", "address": "대한민국 경기도 용인시 수지구 신수로 지하 760"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('두계천', '계룡시에서 대전 갑천으로 이어지는 한적한 하천변 자전거길입니다. 호남선 철길을 따라 농로와 제방길을 달리며 여유로운 라이딩을 즐기기 좋습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.248701, 36.287308), 4326), false, '{"source": "KOMOOT", "source_ids": ["599", "60"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["호남선 철길", "갑천 합수부", "송정동 말채나무"], "confidence": "high", "address": "대한민국 대전광역시 유성구 송정동 239-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('두계천 강변길', '영화 ''클래식'' 촬영지로 유명한 한적한 하천변 자전거길입니다. 갑천 자전거길과 이어지며 평화로운 시골 풍경 속 라이딩을 즐기기 좋습니다.', '{river,nature,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.287702, 36.257061), 4326), false, '{"source": "KOMOOT", "source_ids": ["461", "626"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/6d/6d58zp70v8c71kbiqsmrwrd5u4jdwprr5-uhi58861863/0?width=1920&crop=false"], "category_raw": "trail", "tour_count": 2, "nearby_landmarks": ["원정역(폐역)", "위왕산", "무도리마을"], "confidence": "high", "address": "대한민국 대전광역시 서구 원정동 802"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('두정역', '수도권 전철 1호선이 지나는 두정역입니다. 주말 자전거 점프(전철 연계)가 가능하며, 주변 상권이 발달해 라이딩 중 식사나 보급을 해결하기 좋습니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.148563, 36.833625), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/b/ba/2008-11-08_-_Dujeong_Station_Entrance.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6e/20210612_두정역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/4e/두정역-20200711_191924.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c9/Korail_Dujeong_station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/20/2008-11-08_-_Dujeong_Station_Tracks.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["메가박스 천안", "북일고등학교"], "confidence": "high", "address": "대한민국 충청남도 천안시 서북구 두정동 77-21"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('딴들봉', '충남 금산군에 위치한 해발 254m의 작은 봉우리입니다. 산악 라이딩 시 고도 변화를 가늠하거나 코스의 주요 경유지 및 이정표로 참고하기 좋습니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.401901, 36.148048), 4326), false, '{"source": "KOMOOT", "source_ids": ["698", "918"], "category_raw": "21", "tour_count": 2, "nearby_landmarks": ["북만산", "백마산", "국사봉"], "confidence": "high", "address": "대한민국 충청남도 금산군 진산면 부암리 산10-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('라이드 자전거 도봉점', '도봉중학교 인근에 위치한 자전거 전문 매장으로, 다양한 브랜드의 자전거 판매 및 전문적인 정비 서비스를 제공합니다.', '{bike_shop}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.0458, 37.671214), 4326), false, '{"source": "KOMOOT", "source_ids": ["142", "64"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1n/1nzokixqiis1ysx5cadi573o537d8md8o-uhi9469877/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1c/1ccoh4i5b15421q9qk4oqpsqm437d9fp2g-uhi9470158/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/cd/cd8kk949pyo9gksqyuatr4nt37d8sm5u-uhi9469921/0?width=1920&crop=false"], "tips": [{"text": "Bicycle Store and Repair shop", "author": ""}, {"text": "Bicycle Store and Repair shop", "author": "AsuRa"}], "category_raw": "facilities", "tour_count": 2, "nearby_landmarks": ["도봉중학교", "서원아파트"], "confidence": "high", "address": "대한민국 서울특별시 도봉중학교.서원아파트"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('롯데마트 광주첨단점', '영산강 자전거길 인근에 위치한 대형마트 주차장입니다. 라이딩 중 식수와 간식을 보충하거나 화장실을 이용하며 휴식하기 좋은 거점입니다.', '{parking,restroom,rest_area,convenience_store,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.851893, 35.215868), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 2, "nearby_landmarks": ["영산강 자전거길", "쌍암공원", "첨단근린공원"], "confidence": "high", "address": "대한민국 광주광역시 광산구 쌍암동 694-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('마곡 나들목', '마곡지구와 한강공원을 잇는 자전거·보행자 겸용 나들목입니다. 계단 없는 경사로와 충돌 방지 설계가 적용되어 자전거로 한강 자전거길에 진출입하기 매우 안전하고 편리합니다.', '{tunnel,river,park,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.838378, 37.577433), 4326), false, '{"source": "KOMOOT", "source_ids": ["352", "306"], "category_raw": "other_man_made", "tour_count": 2, "nearby_landmarks": ["서울식물원", "한강공원"], "confidence": "high", "address": "대한민국 서울특별시 강서구 마곡동 1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('마골산', '다양한 난이도의 싱글 트랙 코스가 거미줄처럼 얽혀 있어 울산 지역 MTB 라이더들이 즐겨 찾는 산악 라이딩 명소입니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.416624, 35.558726), 4326), false, '{"source": "KOMOOT", "source_ids": ["200", "701"], "category_raw": "21", "tour_count": 2, "nearby_landmarks": ["동축산", "염포산", "염포정", "옥류천", "해골바위"], "confidence": "high", "address": "대한민국 울산광역시 동구 동부동 마골산"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('마석역', '경춘선 자전거길이 지나는 마석역 인근 거점입니다. 전철을 이용한 점프(환승)가 가능하며, 주변 상권이 발달해 라이딩 중 보급과 휴식을 취하기 좋습니다.', '{transit,rest_area,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.3117, 37.653188), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/db/마석역_전경.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/57/구_마석역.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/95/20240921_마석역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/ae/20240921_마석역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/ba/Q49978_Maseok_A01.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["마석역", "경춘선 자전거길"], "confidence": "high", "address": "대한민국 경기도 남양주시 화도읍 마석우리 241-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('마장호수와 기산저수지 내리막길', '기산저수지에서 마장호수로 이어지는 경치 좋은 내리막길입니다. 두 호수를 지나며 시원하게 달릴 수 있고, 마장호수 주변 카페에서 쉬어가기 좋습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.936557, 37.776733), 4326), false, '{"source": "KOMOOT", "source_ids": ["230", "475"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/3s/3s4oyecjc8o91jsb954h2nh433464tjzi-uhi7965078/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/yi/yi2xbxq2em8wsed8xt08yfbc3464tkme-uhi7965079/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1u/1u2h73ln8c8ln1udfpdiii4avo3470xl9b-uhi7972801/0?width=1920&crop=false"], "tips": [{"text": "Nice scenic flowing section, mainly descent, passing 2 big bodies of water. Not much to see at the reservoir that I am aware of but the lake itself warrants a stop, both before to admire at a cafe (will highlight separately) and at the lake itself there are a couple of coffee spots and a very cool suspension bridge between to points of land either side of the lake (walkers only). There is also an observatory tower.", "author": "Jon"}], "category_raw": "lake", "tour_count": 2, "nearby_landmarks": ["마장호수", "기산저수지", "마장호수 출렁다리"], "confidence": "high", "address": "대한민국 경기도 양주시 백석읍 기산리 409-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('마치터널', '옛 경춘선 폐철도를 개조한 644m 길이의 자전거 전용 터널입니다. 내부 조명이 아름다우며, 가파른 마치고개를 우회하여 안전하게 통과할 수 있어 라이더들에게 필수적인 코스입니다.', '{tunnel,landmark,historic}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.263031, 37.655962), 4326), false, '{"source": "KOMOOT", "source_ids": ["1123", "920"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/x1/x1rdkjjkl7kssbz68jc9soou560osqb6-uhi80423481/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/q7/q7kvleflvyhrd3r6h6lijrfr560osqli-uhi80423482/0?width=1920&crop=false"], "category_raw": "other_man_made", "tour_count": 2, "nearby_landmarks": ["평내호평역", "천마산", "마치고개"], "confidence": "high", "address": "대한민국 경기도 남양주시 호평동 2-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('말구리고개', '수도권 인기 코스인 ''하여말''에 속하는 짧고 강렬한 업힐입니다. 경사가 가파르고 노면이 고르지 않아 다운힐 시 각별한 주의가 필요합니다.', '{mountain}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.05391, 37.351298), 4326), false, '{"source": "KOMOOT", "source_ids": ["127", "277"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1h/1hubhvste17l51r799g94hrbd956iz68gv-uhi80934091/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1h/1hbtb2hdfpq7awqq8npiy05ij56iz69a4-uhi80934092/0?width=1920&crop=false"], "tips": [{"text": "Short punchy climb from south side, average gradient is 9% and reaches ~250m elevation over half a kilometer. Descending the otherside the road is similarly pretty steep, road quality is pretty sketchy - so take care!", "author": "Jon"}], "category_raw": "mountain_pass", "tour_count": 2, "nearby_landmarks": ["미륵사", "광교산체육공원"], "confidence": "high", "address": "대한민국 경기도 용인시 수지구 고기동 340-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('망미역', '부산 지하철 3호선 망미역입니다. 출구 인근에 자전거 보관소가 있으며, 수영강 자전거길로 진입하거나 대중교통을 연계하기 좋은 포인트입니다.', '{transit,parking,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.107526, 35.171762), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/4/4e/Mangmi_station_sign_20180324_182854.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/55/Busan-subway-302-Mangmi-station-8-entrance.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/90/Mangmi_station_platform_20180324_182908.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c0/Busan-subway-302-Mangmi-station-platform.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["수영강", "비콘그라운드", "F1963"], "confidence": "high", "address": "대한민국 부산광역시 수영구 망미동 425-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('매화동 마을', '충북 제천시 봉양읍 명도리에 위치한 한적한 농촌 마을입니다. 백곡산 인근에 자리하여 조용한 시골길 라이딩을 즐기며 쉬어가기 좋습니다.', '{nature,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.127, 37.16543), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 2, "nearby_landmarks": ["백곡산"], "confidence": "high", "address": "대한민국 제천시 매화동"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('면목역', '서울 지하철 7호선 면목역입니다. 주말 및 공휴일에 자전거 휴대 승차가 가능하여 라이딩 중 대중교통 연계(점프) 포인트로 유용합니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.087569, 37.588373), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/0/09/Seoul-metro-721-Myeonmok-station-sign-20181123-091150.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/5e/Seoul-metro-721-Myeonmok-station-entrance-2-20181123-091706.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9c/Seoul-metro-721-Myeonmok-station-platform-20181123-091204.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["동원시장", "면목역공원"], "confidence": "high", "address": "대한민국 서울특별시 중랑구 면목동 1216-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('명륜역 (온천천 자전거길)', '온천천 자전거길과 바로 연결되는 부산 1호선 전철역입니다. 자전거 보관소가 마련되어 있으며, 봄철 벚꽃 라이딩의 주요 출발점 및 경유지로 활용됩니다.', '{transit,parking,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.079896, 35.212571), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/9/9d/Myeongnyun_Station2.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/af/Busan-subway-126-Myeongnyun-dong-1-entrance.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/87/Myeongnyun_Station_2010.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/46/Myeongnyun_Station5.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/51/Myeongnyun_Station_1.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["온천천 자전거길", "롯데백화점 동래점"], "confidence": "high", "address": "대한민국 부산광역시 명륜역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('명암저수지', '제천 감악산 방면 길목에 있는 고즈넉한 저수지입니다. 낚시터와 캠핑장이 인접해 있으며, 라이딩 중 탁 트인 수변 풍경을 감상하며 잠시 쉬어가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.126926, 37.168613), 4326), false, '{"source": "KOMOOT", "source_ids": ["5"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["명암낚시터", "명암오토캠핑장", "감악산"], "confidence": "high", "address": "대한민국 충청북도 제천시 봉양읍 명도리 산13-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('호텔야자 대구계명대점', '계명대역과 성서공단 인근 모텔촌에 위치한 숙소(호텔야자)입니다. 주차장에 자전거를 안전하게 보관할 수 있어 라이더들이 숙박하며 쉬어가기 좋습니다.', '{other,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.490361, 35.840659), 4326), false, '{"source": "KOMOOT", "source_ids": ["1279", "16"], "tips": [{"text": "cheap motels around. we stayed here with 3 people for 100000 won per night. bikes can be stored safely at the parking", "author": "Alex Kasch"}], "category_raw": "facilities", "tour_count": 2, "nearby_landmarks": ["계명대학교", "성서산업단지", "모다아울렛 성서점"], "confidence": "high", "address": "대한민국 대구광역시 달서구 호산동 711-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('목동역', '지하철 5호선 목동역입니다. 자전거 보관소와 화장실을 갖추고 있으며, 주변 상권이 발달해 라이딩 중 대중교통 연계나 보급을 위한 경유지로 적합합니다.', '{transit,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.864516, 37.526116), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/9/9d/Mokdong_Station_nameplate_in_2018.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f7/Seoul-metro-520-Mok-dong-station-sign-20180915-154302.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/57/Seoul-metro-520-Mok-dong-station-entrance-4-20180915-154712.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/50/Mokdong_Station_exit_1_in_2018.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b4/Mokdong_Station_platform_in_2018.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["목동로데오거리", "서울남부지방법원"], "confidence": "high", "address": "대한민국 서울특별시 양천구 오목로 지하 245"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('몽탄교 남단 영산강 자전거길', '영산강 자전거길 종주 코스 중 무안군 몽탄교 남단에 위치한 구간입니다. 영산강의 탁 트인 풍경을 감상하며 달릴 수 있는 쾌적한 강변 라이딩 코스입니다.', '{river,bridge,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.526772, 34.896711), 4326), false, '{"source": "KOMOOT", "source_ids": ["311", "446"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1o/1o971azf6alodttl9jbd4x55q37e41jpq-uhi9476286/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 2, "nearby_landmarks": ["몽탄교", "영산강"], "confidence": "high", "address": "대한민국 전라남도 무안군 몽탄면 명산리 812-92"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('무등산국립공원', '광주 지역 라이더들의 필수 코스인 무등산국립공원입니다. 원효사 업힐과 무등산 순환 라이딩 등 수려한 자연경관을 배경으로 다양한 코스를 즐길 수 있습니다.', '{mountain,park,nature,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.970841, 35.153937), 4326), false, '{"source": "KOMOOT", "source_ids": ["43", "278"], "category_raw": "natural_monument", "tour_count": 2, "nearby_landmarks": ["원효사", "충장사", "평두메습지", "제4수원지"], "confidence": "high", "address": "대한민국 광주광역시 북구 화암동 147-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('무제등소공원 전망대', '신선대부두(컨테이너 항구)와 해군 기지가 한눈에 내려다보이는 무제등소공원 전망대입니다. 자전거 라이딩 중 탁 트인 부산항 풍경을 감상하며 휴식하기 좋습니다.', '{viewpoint,park,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.104743, 35.107214), 4326), false, '{"source": "KOMOOT", "source_ids": ["86", "134"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/x9/x9g0xzbq0x5f1x7pop52rs7b54h1vk9bf-uhi57611045/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/13/13twy3fagptyd1n9pwybnny5zx4h1vk9ie-uhi57611046/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/14/14evx1txmf3yoyzsc3eew9bbn4h1vk9kz-uhi57611047/0?width=1920&crop=false"], "tips": [{"text": "Blick auf den großen Containerhafen und US Marine Base.", "author": ""}, {"text": "Blick auf den großen Containerhafen und US Marine Base.", "author": "Arne"}], "category_raw": "viewpoint", "tour_count": 2, "nearby_landmarks": ["무제등소공원", "신선대부두", "부산항대교"], "confidence": "high", "address": "대한민국 부산광역시 남구 용당동 24-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('무창포 해수욕장', '서해안 해안도로 라이딩 코스의 주요 기착지로, 탁 트인 바다 경치와 낙조를 감상하기 좋습니다. 식당과 편의점 등 보급 시설이 잘 갖춰져 있어 쉬어가기 적합합니다.', '{beach,viewpoint,rest_area,convenience_store,restaurant,cafe,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.535246, 36.242822), 4326), false, '{"source": "KOMOOT", "source_ids": ["287"], "category_raw": "12", "tour_count": 2, "nearby_landmarks": ["무창포타워", "신비의 바닷길", "무창포 수산시장", "석대도", "닭벼슬섬"], "confidence": "high", "address": "대한민국 충청남도 보령시 웅천읍 열린바다1길 30"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('문산천', '파주 문산천을 따라 조성된 쾌적한 자전거길입니다. 초보자도 달리기 좋은 평탄한 코스이며, 최근 태양광 그늘막이 설치되어 라이딩 중 휴식하기 좋습니다.', '{river,nature,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.780192, 37.84559), 4326), false, '{"source": "KOMOOT", "source_ids": ["546", "314"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["신문산교", "문산역", "DMZ 평화누리길"], "confidence": "high", "address": "대한민국 경기도 파주시 문산읍 내포리 1443-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('물한재 터널', '논산 양촌면과 벌곡면을 잇는 고개에 위치한 생태 터널입니다. 대둔산, 배티재 등과 연계하여 라이딩하기 좋은 업힐 코스입니다.', '{tunnel,mountain}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.27212, 36.160334), 4326), false, '{"source": "KOMOOT", "source_ids": ["636", "1308"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/5g/5gqti9vyuu91qlzmtyz21byk3ypry79w-uhi44023528/0?width=1920&crop=false"], "category_raw": "other_man_made", "tour_count": 2, "nearby_landmarks": ["양촌자연휴양림", "대둔산", "배티재"], "confidence": "high", "address": "대한민국 충청남도 논산시 양촌면 반암리 산35-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('미사역', '5호선 미사역 및 문화의 거리입니다. 3, 8번 출구에 자전거 이동 레일과 대규모 지하 주차장이 있어 대중교통 연계 라이딩에 최적화된 장소입니다.', '{transit,parking,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.192783, 37.563045), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/4/49/20200808_미사역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c7/20200808_미사역_2번출구.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/67/20200808_미사역_게이트.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f4/20200808_미사역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f0/20200808_미사역_스크린도어.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["미사 문화의 거리", "미사역 시계탑", "미사호수공원"], "confidence": "high", "address": "대한민국 경기도 하남시 망월동 109-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('바깥아감 버스정류장', '대청호 오백리길 5구간에 위치한 버스 승강장입니다. 대청호반과 백골산성, 흥진마을로 향하는 자전거 라이딩 코스의 주요 진입로이자 기점으로 활용됩니다.', '{transit,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.498655, 36.353924), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 2, "nearby_landmarks": ["대청호", "백골산성", "흥진마을"], "confidence": "high", "address": "대한민국 대전광역시 바깥아감"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('바람재정', '창원 바람재 고개에 위치한 정자로, 마산만과 마창대교가 내려다보이는 탁 트인 조망을 자랑합니다. 산악 자전거(MTB) 라이더들의 인기 코스인 임도 구간의 훌륭한 휴식처입니다.', '{viewpoint,rest_area,mountain}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.526523, 35.182717), 4326), false, '{"source": "KOMOOT", "source_ids": ["227", "137"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/9m/9mqbhkg5imkzy763jc257rqh4b342bry-uhi54332445/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1ka/1c/1ca8bkhas0f9p1lmfn63jqlvnm5nxoo3z5-uhi97772290/0?width=1920&crop=false"], "category_raw": "viewpoint", "tour_count": 2, "nearby_landmarks": ["바람재", "쌀재고개", "광려산", "청량산"], "confidence": "high", "address": "대한민국 경상남도 창원시 마산합포구 예곡동 산163-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('반변천', '낙동강과 합류하는 지점에 위치한 하천 생태공원입니다. 자전거도로가 잘 정비되어 있어 낙동강 종주 자전거길과 연계해 쾌적하게 라이딩하기 좋습니다.', '{river,park,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.743252, 36.553805), 4326), false, '{"source": "KOMOOT", "source_ids": ["2073", "219", "1036"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["낙동강 종주 자전거길", "귀래정", "월영교"], "confidence": "high", "address": "대한민국 안동시 정상동"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('반포한강공원 우회로', '반포한강공원의 혼잡한 보행로와 차량 동선을 피하기 위해 주차장 인근으로 조성된 자전거 우회로입니다. 보행자 사고를 예방하고 안전하게 통과할 수 있습니다.', '{parking,park,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.002567, 37.513589), 4326), false, '{"source": "KOMOOT", "source_ids": ["116", "28"], "category_raw": "parking", "tour_count": 2, "nearby_landmarks": ["반포대교", "잠수교", "세빛섬", "반포달빛무지개분수"], "confidence": "high", "address": "대한민국 서울특별시 서초구 잠원동 122-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('방학천 합류지', '방학천과 중랑천 자전거길이 만나는 합류 지점입니다. 두 하천을 연계하여 코스를 계획하거나 방향을 전환하기 좋은 주요 길목입니다.', '{river,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.050952, 37.6608), 4326), false, '{"source": "KOMOOT", "source_ids": ["116", "155"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/uc/uclggv9umhe719j8shpxfnxxv3h683f9o-uhi19762788/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/3f/3fnn6zwlujge1xhrxt8b18pjk3hhijal2-uhi20456666/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/xm/xm0fi8udtio191027838wm8c3hhijek5-uhi20456669/0?width=1920&crop=false"], "tips": [{"text": "Where Banghak-cheon flows into Joongrangcheon", "author": ""}], "category_raw": "river", "tour_count": 2, "nearby_landmarks": ["중랑천", "방학천"], "confidence": "high", "address": "대한민국 서울특별시 도봉구 창동 743-32"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('배둔시외버스터미널', '고성 당항포 인근 라이딩 시 대중교통 점프(복귀) 목적으로 활용하기 좋은 시외버스 간이 정류소입니다. 주변에 기사식당 등 식당이 많아 식사 및 보급에 유리합니다.', '{transit,restaurant,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.366713, 35.055523), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 2, "nearby_landmarks": ["당항포관광지", "배둔시장"], "confidence": "high", "address": "대한민국 경상남도 고성군 회화면 배둔리 811-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('한티고개(독고개) 생태통로', '예산과 서산 경계인 한티고개(독고개) 정상에 위치한 생태통로입니다. 차량 통행이 적은 한적한 구도로 업힐 코스의 정상 랜드마크로 라이더들이 자주 지나는 곳입니다.', '{bridge,landmark,mountain}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.59159, 36.665838), 4326), false, '{"source": "KOMOOT", "source_ids": ["696", "151"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/wx/wxwrwr29izxs1qn7909iygd9n4qmuyo3p-uhi66193001/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 2, "nearby_landmarks": ["한티고개", "가야산", "산수저수지"], "confidence": "high", "address": "대한민국 예산군 대곡1리(한티고개)"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('국립부여박물관', '금강 자전거길 부여 구간에서 접근하기 좋은 박물관입니다. 자전거를 세워두고 국보인 백제 금동대향로를 감상하며 쾌적하게 쉬어가기 좋습니다.', '{museum,historic,landmark,rest_area,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.918251, 36.276095), 4326), false, '{"source": "KOMOOT", "source_ids": ["786", "19"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/jy/jyzaowzv6n9dlzp9igaxtsy03xohhv7k-uhi42660300/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/sx/sxg9hydyvhls1e63pnhr974ka3xohhv7h-uhi42660301/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1e/1er8fpeduc33712hpkkpyv17xy3xohhv9w-uhi42660302/0?width=1920&crop=false"], "category_raw": "historical_site", "tour_count": 2, "nearby_landmarks": ["정림사지", "궁남지", "부소산성", "백마강"], "confidence": "high", "address": "대한민국 충청남도 부여군 부여읍 동남리 37-29"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('범계역', '지하철 4호선 범계역으로 주말 자전거 점프(환승)가 가능한 교통 거점입니다. 주변 상권이 매우 발달해 식사와 보급을 해결하기 좋습니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.95091, 37.389913), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/8/83/Anyang027.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b3/Anyang037.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f3/Anyang026.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/03/Anyang036.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/79/Beomgyest01.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["롯데백화점 평촌점", "평촌1번가 문화의거리"], "confidence": "high", "address": "대한민국 경기도 안양시 동안구 동안로 130 지하 1층"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('범골탐방지원센터', '사패산 등산로가 시작되는 범골계곡 입구(범골탐방지원센터)입니다. 산악 라이딩(MTB) 코스 진입 전 정비하거나 자연 속에서 휴식하기 좋은 지점입니다.', '{checkpoint,mountain,nature,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.043716, 37.728773), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/8/8e/U112_Bumgol_01.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["사패산", "범골탐방지원센터", "호암사", "범골약수터"], "confidence": "high", "address": "대한민국 의정부시 호원2동 범골"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('벚나무 가로수', '왕숙천과 사릉천 합수부 인근의 벚나무 가로수길입니다. 봄철 화려한 벚꽃 터널과 시원한 그늘을 제공하여 쾌적한 자전거 라이딩을 즐기기 좋은 힐링 구간입니다.', '{nature,viewpoint,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.15204, 37.652933), 4326), false, '{"source": "KOMOOT", "source_ids": ["626", "883"], "category_raw": "191", "tour_count": 2, "nearby_landmarks": ["왕숙천 자전거길", "사릉천"], "confidence": "high", "address": "대한민국 경기도 남양주시 진건읍 진관리 966-87"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오곡리 논길', '금광베네스타 아파트 뒤편 오곡리로 이어지는 논길입니다. 길 끝부분 공사가 마무리되지 않았을 수 있어 라이딩 시 각별한 주의가 필요합니다.', '{nature,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.689066, 35.914853), 4326), false, '{"source": "KOMOOT", "source_ids": ["360", "69"], "tips": [{"text": "Careful going out onto the new rice field road past Benesta Apartments not quite finished at the end", "author": "Christopher E"}], "category_raw": "trail", "tour_count": 2, "nearby_landmarks": ["금광베네스타아파트"], "confidence": "high", "address": "대한민국 전북특별자치도 군산시 옥구읍 오곡리 192-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('변산해수욕장', '변산해변자전거길의 주요 경유지로, 아름다운 서해안 일몰을 감상할 수 있는 해수욕장입니다. 화장실과 주차장 등 편의시설이 잘 갖춰져 있어 라이딩 중 휴식하기 좋습니다.', '{beach,restroom,parking,rest_area,viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.531295, 35.680179), 4326), false, '{"source": "KOMOOT", "source_ids": ["880", "67"], "category_raw": "12", "tour_count": 2, "nearby_landmarks": ["채석강", "새만금홍보관", "격포항", "고사포해수욕장"], "confidence": "high", "address": "대한민국 전북특별자치도 부안군 변산면 대항리 528-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('보령호', '봄철 벚꽃길과 가을 단풍이 아름다운 호반 라이딩 명소입니다. 차량 통행이 적고 길이 잘 닦여 있어 쾌적하게 호수를 한 바퀴 도는 코스로 인기가 높습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.666428, 36.251138), 4326), false, '{"source": "KOMOOT", "source_ids": ["584", "284"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["보령댐물빛공원", "보령댐애향박물관", "양각산"], "confidence": "high", "address": "대한민국 충청남도 보령시 미산면 용수리 763-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('보은시외버스터미널', '보은 지역을 오가는 시외버스와 농어촌버스를 이용할 수 있는 터미널입니다. 인근에 보은전통시장과 식당가가 있어 라이딩 전후로 보급과 휴식을 취하기 좋습니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.721833, 36.483021), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 2, "nearby_landmarks": ["보은전통시장", "결초보은시장", "뱃들공원", "보청천"], "confidence": "high", "address": "대한민국 충청북도 보은군 보은읍 삼산리 16-1번지"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('본포마을회관', '낙동강 자전거길과 본포수변생태공원 인근에 위치한 마을회관입니다. 라이딩 중 화장실을 이용하거나 잠시 휴식하기 좋으며, 대중교통 연계가 가능합니다.', '{rest_area,transit,restroom,park,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.646124, 35.368271), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 2, "nearby_landmarks": ["본포수변생태공원", "낙동강 자전거길", "본포교"], "confidence": "high", "address": "대한민국 경상남도 창원시 의창구 동읍 본포리 183-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('봉명역', '수도권 전철 1호선 봉명역입니다. 천안천 자전거길과 인접해 있어 자전거 점프(대중교통 연계) 경유지로 유용하며, 주변에 편의점과 카페가 많아 라이딩 중 보급하기 좋습니다.', '{transit,restroom,convenience_store,cafe}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.135635, 36.801571), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/b/b9/Bongmyeong_Stn._Platform.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/96/Bongmyeong_Station2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/35/Bongmyeong_Stn._Nameplate.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/eb/봉명역20200529_174640.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/cd/Bongmyeong_Stn._Waiting_room.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["순천향대학교 부속 천안병원", "천안천 자전거길"], "confidence": "high", "address": "대한민국 충청남도 천안시 동남구 순천향3길"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('부여관북리유적', '유네스코 세계유산인 사비 백제 시대의 왕궁터입니다. 백마강 자전거길과 가까워 라이딩 중 넓은 잔디밭에서 역사적 정취를 느끼며 쉬어가기 좋습니다.', '{historic,landmark,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.911538, 36.285145), 4326), false, '{"source": "KOMOOT", "source_ids": ["123", "1558"], "category_raw": "15", "tour_count": 2, "nearby_landmarks": ["부소산성", "백마강", "정림사지", "구드래조각공원"], "confidence": "high", "address": "대한민국 충청남도 부여군 부여읍 구아리 3-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('북평버스터미널', '정선군 북평면의 대중교통 거점으로, 라이딩 중 버스 점프(이동)를 하거나 인접한 나전역과 연계해 휴식 및 정비를 하기 좋은 터미널입니다.', '{transit,rest_area,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.666164, 37.448829), 4326), false, '{"source": "KOMOOT", "source_ids": ["921", "103"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1q/1qzu003wzui5k1vjy2kctlrabl3dvys9ty-uhi13807253/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 2, "nearby_landmarks": ["나전역", "정선토속음식맛전수관", "북평면행정복지센터"], "confidence": "high", "address": "대한민국 강원특별자치도 정선군 북평면 북평리 686-11"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('북한강', '북한강 자전거길이 지나는 춘천 서면 구간으로, 탁 트인 강변 풍경이 일품입니다. 수려한 자연을 만끽하며 시원하게 라이딩하기 좋은 코스입니다.', '{river,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.702107, 37.942013), 4326), false, '{"source": "KOMOOT", "source_ids": ["228", "1367"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["북한강 자전거길", "신매대교", "서상대교"], "confidence": "high", "address": "대한민국 강원특별자치도 춘천시 서면 서상리 78-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('비내섬 인증센터', '남한강 자전거길의 주요 인증센터입니다. 바로 옆에 매점과 화장실 등 휴게 시설이 있어 라이딩 중 보급과 휴식을 취하기 좋습니다.', '{checkpoint,rest_area,convenience_store,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.809555, 37.110329), 4326), false, '{"source": "KOMOOT", "source_ids": ["434", "893"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/y7/y75kugqobo801r4rz1sr922y837enyo65-uhi9479666/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/4y/4yjlid0plmzmniuu4hq7ersw37enypw9-uhi9479667/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1h/1hob273ltc0eqddcbnmvydy1w5d19were-uhi86079852/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 2, "nearby_landmarks": ["비내섬", "남한강"], "confidence": "high", "address": "대한민국 충청북도 충주시 앙성면 남한강변길"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('비룡저수지', '속리산 자락에 위치한 대형 저수지로 ''삼가저수지''로도 불립니다. 만수계곡과 이어지는 수려한 경관을 감상하며 한적하게 라이딩하기 좋은 곳입니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.846485, 36.492916), 4326), false, '{"source": "KOMOOT", "source_ids": ["694", "1096"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["속리산", "만수계곡", "삼가천"], "confidence": "high", "address": "대한민국 충청북도 보은군 속리산면 삼가리 산26-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('상주상풍교 인증센터', '국토종주 새재 자전거길과 낙동강 자전거길이 이어지는 상주상풍교 인증센터입니다. 무인 얼음물 판매대가 있으며, 매협재 업힐 전후로 쉬어가기 좋은 필수 스탬프 포인트입니다.', '{checkpoint,rest_area,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.265761, 36.498764), 4326), false, '{"source": "KOMOOT", "source_ids": ["1289", "769"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1n/1nhryz17qb69kwd8aofsff17l5du4zjqb-uhi87159896/0?width=1920&crop=false"], "category_raw": "other_man_made", "tour_count": 2, "nearby_landmarks": ["상풍교", "매협재", "낙동강"], "confidence": "high", "address": "대한민국 경상북도 상주시 사벌국면 매호리 산31-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('이화원 사의지', '가평 자라섬 인근 식물원인 ''이화원'' 내에 조성된 전통 연못입니다. 북한강 자전거길과 인접해 있어 라이딩 중 고즈넉한 풍경을 감상하며 쉬어가기 좋습니다.', '{park,nature,lake,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.519302, 37.818555), 4326), false, '{"source": "KOMOOT", "source_ids": ["46"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["이화원", "자라섬", "북한강 자전거길", "가평역"], "confidence": "high", "address": "대한민국 경기도 가평군 가평읍 대곡리 56-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('늑도 유적지', '삼천포와 남해를 잇는 늑도에 위치한 고대 무역항 유적지입니다. 창선·삼천포대교 자전거길을 따라 남해안 절경을 감상하며 들르기 좋습니다.', '{historic,landmark,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.037225, 34.923378), 4326), false, '{"source": "KOMOOT", "source_ids": ["77", "1998"], "category_raw": "15", "tour_count": 2, "nearby_landmarks": ["창선대교", "삼천포대교", "초양도"], "confidence": "high", "address": "대한민국 경상남도 사천시 늑도동 250-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('산본역', '지하철 4호선 산본역입니다. 주말 자전거 점프(대중교통 연계)나 라이딩 출발 및 합류 지점으로 활용하기 좋으며, 역사 내외로 화장실과 편의시설이 풍부합니다.', '{transit,restroom,convenience_store,cafe,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.932935, 37.358175), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/8/8d/444_Sanbon_01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/74/Sanbon_Station_Platform.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/56/444_Sanbon_02.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/ko/9/9b/Sanbon_Station_platporm.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3e/444_Sanbon_03.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["산본로데오거리", "뉴코아아울렛 산본점"], "confidence": "high", "address": "대한민국 경기도 군포시 광정동 1231"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼동역', '경강선 삼동역입니다. 주말 자전거 승차(점프)가 가능해 남한강 자전거길 등으로 연계하기 좋으며, 라이딩 출발지나 휴식처로 유용합니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.203483, 37.408471), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["중대물빛공원"], "confidence": "high", "address": "대한민국 경기도 광주시 중대동 산18-46"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼정지에듀', '제주영어교육도시 내 위치한 대단지 아파트로, 주변 도로를 라이딩할 때 현재 위치를 파악하는 이정표로 참고하기 좋습니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.278036, 33.284954), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 2, "nearby_landmarks": ["제주영어교육도시", "제주신화월드", "제주항공우주박물관"], "confidence": "high", "address": "대한민국 제주특별자치도 서귀포시 대정읍 보성리 2427"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼천포천', '최근 생태하천으로 복원되어 쾌적한 자전거길과 산책로를 갖춘 사천시의 도심 하천입니다. 맑은 물길을 따라 여유롭게 라이딩하며 휴식하기 좋습니다.', '{river,nature,park,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.077364, 34.939438), 4326), false, '{"source": "KOMOOT", "source_ids": ["9", "46"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["용두공원", "와룡산"], "confidence": "high", "address": "대한민국 경상남도 사천시 한내4길 132"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('상광정리', '하조대에서 어성전리로 이어지는 418번 지방도 상의 조용한 송이마을입니다. 차량 통행이 적고 경사가 완만하여 여유롭고 평화로운 라이딩을 즐기기 좋습니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.69853, 38.015087), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 2, "nearby_landmarks": ["현북중학교", "현북축구장", "광정천"], "confidence": "high", "address": "대한민국 양양군 상광정리"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('상당산', '경산 남천면에 위치한 해발 96m의 산입니다. 성암산, 금장산과 이어지는 능선 코스에 있어 산악자전거(MTB) XC 라이더들이 다이내믹한 싱글길을 즐기기 좋습니다.', '{mountain}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.715366, 35.786408), 4326), false, '{"source": "KOMOOT", "source_ids": ["104", "523"], "category_raw": "21", "tour_count": 2, "nearby_landmarks": ["금장산", "하당산", "성암산"], "confidence": "high", "address": "대한민국 경상북도 경산시 남천면 산전리 168"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('상동지석묘군', '수성못 서편에 위치한 청동기 시대 고인돌 유적지입니다. 수성못이나 신천 자전거길 라이딩 중 가볍게 들러 역사적 정취를 느끼며 쉬어가기 좋습니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.610394, 35.827356), 4326), false, '{"source": "KOMOOT", "source_ids": ["33", "554"], "category_raw": "15", "tour_count": 2, "nearby_landmarks": ["수성못", "신천 자전거길"], "confidence": "high", "address": "대한민국 대구광역시 수성구 상동 619-20"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('상풍교 한옥 게스트하우스', '상풍교 인증센터에서 약 500m 거리에 위치한 자전거 여행자 맞춤형 숙소입니다. 조·석식 및 세탁 서비스를 제공하여 국토종주 라이더들에게 매우 인기가 높습니다.', '{rest_area,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.261749, 36.495733), 4326), false, '{"source": "KOMOOT", "source_ids": ["777", "1297"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/z9/z9k2qd3sfqkealx782652kte4qis8lsq-uhi66062526/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/10/10v563vrbc1stthjz9uexk2m04qis8m14-uhi66062528/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1c/1c7a481ot02911vdyve72384ty4qis8m3v-uhi66062529/0?width=1920&crop=false"], "tips": [{"text": "새재자전거길 상풍교인증센터에서 약 500m 거리. 저녁과 아침을 제공. 빨래도 해 줌. 주인아주머니가 친절함", "author": "Seunghun Kim"}], "category_raw": "facilities", "tour_count": 2, "nearby_landmarks": ["상주상풍교 인증센터", "상풍교"], "confidence": "high", "address": "대한민국 경상북도 상주시 사벌국면 매호리 439-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('서대전역', '호남선 KTX와 일반 열차가 정차하는 기차역입니다. 자전거 주차타워와 편의시설이 잘 갖춰져 있어 타 지역으로 자전거 점프(연계 이동) 시 유용한 교통 거점입니다.', '{transit,parking,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.402705, 36.322384), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/e/e5/Seodaejeon_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/22/Seodaejeon_Station_entrance.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/86/HEMU-430X_Test_run.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/ko/7/7b/%EC%84%9C%EB%8C%80%EC%A0%84%EC%97%AD_%EC%8A%B9%EA%B0%95%EC%9E%A5.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bd/Korail_KTX-Sancheon_01.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["서대전역 광장", "서대전육교", "서대전공원"], "confidence": "high", "address": "대한민국 대전광역시 중구 유천동 10-30"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('서산중학교.석림공원', '서산중학교와 석림공원 인근의 버스 정류장입니다. 석림공원 내부는 자전거 통행이 전면 금지되어 있으므로 라이딩 시 진입에 주의해야 합니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.458733, 36.770092), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 2, "nearby_landmarks": ["서산중학교", "석림공원"], "confidence": "high", "address": "대한민국 충청남도 서산시 석림동 807-31"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('서원주역', '섬강 자전거길과 이어지는 중앙선·강릉선 기차역입니다. 역 내외부에 편의점이나 식당이 없어 보급이 불가능하므로, 라이딩 전 간식과 식수를 반드시 미리 준비해야 합니다.', '{transit,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.840918, 37.348779), 4326), false, '{"source": "KOMOOT", "source_ids": ["715", "437"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/18/18ngu001hlo1i4ivuj06j0fv53q6l3pa6-uhi31016036/0?width=1920&crop=false"], "tips": [{"text": "Seowonju station, is a railway station in Jijeong-myeon, Wonju, South Korea. It is served by the Gyeonggang Line and Jungang Line. The station belongs to Jungang Line opened on 25 September 2012. Gyeonggang Line for Gangneung station opened on 22 December 2017.", "author": "AsuRa"}, {"text": "Seowonju station, is a railway station in Jijeong-myeon, Wonju, South Korea. It is served by the Gyeonggang Line and Jungang Line. The station belongs to Jungang Line opened on 25 September 2012. Gyeonggang Line for Gangneung station opened on 22 December 2017.", "author": ""}], "category_raw": "facilities", "tour_count": 2, "nearby_landmarks": ["간현관광지", "소금산 출렁다리", "섬강 자전거길"], "confidence": "high", "address": "대한민국 강원특별자치도 원주시 지정면 간현리 1183-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('석산못', '부산 기장군 석산리에 위치한 작은 연못으로, 오시리아역 및 내리 인근을 지나는 라이더들에게 한적한 자연 경관을 제공하는 지점입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.209006, 35.209235), 4326), false, '{"source": "KOMOOT", "source_ids": ["339", "69"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["오시리아역", "내리휴먼시아아파트", "내리초등학교"], "confidence": "high", "address": "대한민국 부산광역시 기장군 기장읍 석산리 산28-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('석촌호수', '서울의 대표적인 랜드마크 호수공원입니다. 호수 내부 산책로는 자전거 탑승이 제한되지만, 외곽 자전거길을 통해 한강이나 올림픽공원으로 진입하기 좋은 라이딩 거점입니다.', '{lake,park,landmark,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.102648, 37.509874), 4326), false, '{"source": "KOMOOT", "source_ids": ["62", "29"], "image_urls": ["https://photos.komoot.de/wiki/commons/8/86/석촌_호수공원_(1).jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/21/LacSeokchon.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/ea/Lotte_World_day_view_10.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/16/20230325_석촌호수공원.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/fb/20230325_석촌호수공원2.jpg?width=1920&crop=false"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["롯데월드타워", "롯데월드", "잠실한강공원"], "confidence": "high", "address": "대한민국 서울특별시 송파구 잠실동 49"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('섬말공원', '여수천 자전거길 끝자락에 위치한 근린공원으로, 강남300 코스 등 업힐 라이딩 전후로 연꽃 호수를 보며 쉬어가기 좋은 휴식처입니다.', '{park,rest_area,lake,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.153415, 37.41716), 4326), false, '{"source": "KOMOOT", "source_ids": ["956", "370"], "category_raw": "191", "tour_count": 2, "nearby_landmarks": ["여수천", "도촌동행정복지센터", "갈마치터널"], "confidence": "high", "address": "대한민국 성남시 도촌동행정복지센터"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('성남역', 'GTX-A와 경강선이 지나는 성남역입니다. 탄천 자전거길과 인접해 있어 라이딩 중 화장실을 이용하거나 주말 지하철 점프(연계)를 하기에 좋습니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.119418, 37.394611), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/3/3d/20240330_경강선_성남역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/63/20240330_경강선_성남역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e1/20240330_성남역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/30/20240330_성남역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c0/240906_성남역_1번_출구_2.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["탄천 자전거길", "판교역", "이매역"], "confidence": "high", "address": "대한민국 경기도 성남시 분당구 백현동 545-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('소쇄원', '조선시대 최고의 민간 정원으로 꼽히는 담양의 대표 명승지입니다. 광주호 주변 누정 자전거 코스 중 고즈넉한 대나무 숲과 정자에서 쉬어가기 좋은 역사적 랜드마크입니다.', '{historic,landmark,nature,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.012137, 35.183483), 4326), false, '{"source": "KOMOOT", "source_ids": ["427", "192"], "image_urls": ["https://photos.komoot.de/wiki/commons/d/d8/Korea-Damyang-Soswaewon_in_spring-01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/aa/KOCIS_Korea_Soswaewon_01_%287581350982%29.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/fa/Soswaewon.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/43/Soswaewon_1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/07/Soswaewon_2.jpg?width=1920&crop=false"], "category_raw": "2", "tour_count": 2, "nearby_landmarks": ["광주호", "식영정", "환벽당", "한국가사문학관"], "confidence": "high", "address": "대한민국 전라남도 담양군 가사문학면 지곡리 산28"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('속초저수지', '홍천군 영귀미면에 위치한 조용한 저수지입니다. 진입로가 좁아 라이딩 시 주의가 필요하지만, 한적한 자연 풍경을 즐기며 쉬어가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.98355, 37.6715), 4326), false, '{"source": "KOMOOT", "source_ids": ["1092", "1823"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["만대산", "수타사"], "confidence": "high", "address": "대한민국 강원특별자치도 홍천군 영귀미면 속초리 산27-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('송도해수욕장', '포항운하와 인접한 해수욕장으로 전용 자전거도로가 잘 조성되어 있습니다. 포스코 야경을 감상하며 해안도로를 따라 라이딩 후 쉬어가기 좋습니다.', '{beach,viewpoint,rest_area,cafe}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.378521, 36.038637), 4326), false, '{"source": "KOMOOT", "category_raw": "12", "tour_count": 2, "nearby_landmarks": ["포항운하", "형산강 워터폴리", "포스코"], "confidence": "high", "address": "대한민국 경상북도 포항시 남구 송도동 532"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('송정솔바람해수욕장', '보물섬 남해 자전거길 코스에 위치한 아름다운 해수욕장입니다. 울창한 소나무 숲 그늘과 화장실, 음수대 등 편의시설이 잘 갖춰져 있어 라이딩 중 휴식하기 좋습니다.', '{beach,nature,rest_area,restroom,water_fountain,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.025001, 34.721329), 4326), false, '{"source": "KOMOOT", "source_ids": ["609", "1601"], "category_raw": "12", "tour_count": 2, "nearby_landmarks": ["상주은모래비치", "송정솔바람해변 캠핑장"], "confidence": "high", "address": "대한민국 경상남도 남해군 미조면 송정리 1109-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('송정천', '해운대에서 기장으로 이어지는 길목에 위치한 하천입니다. 송정해수욕장 인근 해안 라이딩 코스를 달리며 자연 경관을 감상하기 좋습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.206584, 35.18839), 4326), false, '{"source": "KOMOOT", "source_ids": ["409", "306"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["송정해수욕장", "구 송정역(폐역)"], "confidence": "high", "address": "대한민국 부산광역시 해운대구 송정동 886-12"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('송탄역', '수도권 전철 1호선 송탄역입니다. 진위천 자전거길이나 평택 지역 라이딩 시 대중교통 점프(연계) 목적으로 활용하기 좋으며, 주변에 식당과 편의시설이 풍부합니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.054607, 37.075371), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/a/ae/Songtan_Station_Sign_at_Night_-_2008-04-13.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/74/Songtan_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/77/Songtan_Station_Inside.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/10/Songtan_Station_Platforms_at_Night_-_2008-04-13.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c0/SongtanStationtraintoSeoul.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["평택국제중앙시장", "진위천 자전거길", "송탄관광특구"], "confidence": "high", "address": "대한민국 경기도 평택시 신장동 248-33"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('쇄암리 철책길', '평화누리길 1코스(염하강철책길)에 속한 비포장 자갈길입니다. 우측 철책 너머로 강화도와 염하강 풍경이 펼쳐지며, 군 초소와 철조망이 독특한 분위기를 자아냅니다.', '{nature,river,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.531458, 37.680448), 4326), false, '{"source": "KOMOOT", "source_ids": ["357", "1150"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1l/1la0avn7drlr0649cje4mg19j3fq97dxb-uhi16916501/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/18/18hdrj6ytjat333xd3e0upj5a3fq97eg8-uhi16916502/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/bc/bc3uxvpjmozeohh1urij6vn3fq97enp-uhi16916503/0?width=1920&crop=false"], "tips": [{"text": "Initially nice and flat, with views on Ganghwa Island to right, albeit partially obscured by razor wire topped high fencing, the  occasional concrete observation post which is all a little menacing, disconcerting and exciting! The first time I came this way, I turned back and found a detour! There are 3 little pitches in elevation as the track winds away from the estuary and heads into woodland. There’s a break in the tree line to the right before the final little rise. There are burial tombs, look out tower, views of the coastline and a more western style cemetery on an opposing hillsides, albeit on terraces. We managed to negotiate this on 25mm road bikes but that was very gingerly and got off a couple times to avoid slipping and falling - GREAT fun but MTB/Gravel/Wider tyre choice recommend - Enjoy", "author": "Jon"}, {"text": "Initially nice and flat, with views on Ganghwa Island to right, albeit partially obscured by razor wire topped high fencing, the  occasional concrete observation post which is all a little menacing, disconcerting and exciting! The first time I came this way, I turned back and found a detour! There are 3 little pitches in elevation as the track winds away from the estuary and heads into woodland. There’s a break in the tree line to the right before the final little rise. There are burial tombs, look out tower, views of the coastline and a more western style cemetery on an opposing hillsides, albeit on terraces. We managed to negotiate this on 25mm road bikes but that was very gingerly and got off a couple times to avoid slipping and falling - GREAT fun but MTB/Gravel/Wider tyre choice recommend - Enjoy", "author": ""}], "category_raw": "trail", "tour_count": 2, "nearby_landmarks": ["염하강", "쇄암리전망대쉼터", "강화도"], "confidence": "high", "address": "대한민국 경기도 김포시 대곶면 쇄암리 145-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('수련제', '전북 부안군 상서면에 위치한 소규모 저수지입니다. 한적한 농촌 풍경을 감상하며 라이딩 중 잠시 쉬어가기 좋은 자연 경관 포인트입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.640753, 35.689641), 4326), false, '{"source": "KOMOOT", "source_ids": ["1137", "215"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["개암사", "우금산", "변산반도 국립공원"], "confidence": "high", "address": "대한민국 전북특별자치도 부안군 상서면 통정리 692-20"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('수리산역 (MTB 임도 출발점)', '수리산 MTB 임도 코스의 대표적인 출발점인 4호선 전철역입니다. 엘리베이터와 넓은 게이트가 갖춰져 있어 자전거를 휴대하고 이동하기 매우 편리합니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.92532, 37.350465), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/e/ec/Surisan_Station_Platform.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/53/Q497879_Surisan_A01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/54/Surisan_Station_in_Gunpo_City,_Gyeonggi-do_20241128.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/4d/Q497879_Surisan_A02.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["수리산 도립공원", "철쭉동산"], "confidence": "high", "address": "대한민국 군포시 수리산역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('수색역-DMC 연결 지하보도', '수색역과 상암동 DMC를 연결하는 지하보도(굴다리)입니다. 보행자와 혼잡하므로 자전거 통행 시 반드시 하차하여 끌고 가야 합니다.', '{tunnel,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.894823, 37.580162), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/0/0b/Susaek_train_stn.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d6/수색역_풍경.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/12/Korail_Susaek_station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/1f/KNR-GyeongEui-line-Susaek-station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b7/20170721_Gyeongui_Line_Susaek_Stn.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["수색역", "디지털미디어시티(DMC)"], "confidence": "high", "address": "대한민국 서울특별시 마포구 상암동 1053-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('수안보온천 인증센터', '새재자전거길의 주요 인증센터입니다. 이화령 업힐 전후로 온천욕과 숙박, 식사 등 보급을 해결하며 피로를 풀기 좋은 국토종주 핵심 거점입니다.', '{checkpoint,rest_area,restroom,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.004593, 36.841638), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["물탕공원", "이화령", "소조령"], "confidence": "high", "address": "대한민국 충주시 수안보온천역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('순천만', '순천만 서쪽 해안을 따라 화포해변으로 이어지는 길목으로, 탁 트인 갯벌과 갈대밭 풍경을 감상하며 힐링 라이딩을 즐기기 좋은 생태 명소입니다.', '{nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.466173, 34.844669), 4326), false, '{"source": "KOMOOT", "source_ids": ["2168", "1485"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1n/1nj3j7xbmoi684wxp991dr8pa5dr0y98l-uhi87067345/0?width=1920&crop=false"], "category_raw": "other_natural", "tour_count": 2, "nearby_landmarks": ["순천만습지", "화포해변"], "confidence": "high", "address": "대한민국 순천시 죽전삼거리"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('현북리 데크길', '금강 자전거길 중 부여 현북리에 위치한 약 800m 길이의 나무 데크 구간입니다. 숲 위를 가로지르는 형태로 조성되어 라이딩 시 아름다운 자연 경관을 즐길 수 있습니다.', '{nature,river,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.966845, 36.239648), 4326), false, '{"source": "KOMOOT", "source_ids": ["273", "180"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/yh/yh9fv0nubf7y117e4213rz5wa4z3qvrg3-uhi71989083/0?width=1920&crop=false"], "tips": [{"text": "section of the longer path. but this segment was maybe 800m and very cool!", "author": "Jesse Badash"}], "category_raw": "trail", "tour_count": 2, "nearby_landmarks": ["금강자전거길", "백마강"], "confidence": "high", "address": "대한민국 충청남도 부여군 부여읍 현북리 76-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('강경 대흥시장 옛날통닭', '강경 대흥시장 내에 위치한 옛날식 시장통닭 전문점입니다. 금강 자전거길과 가까워 라이딩 중 푸짐하고 바삭한 치킨으로 에너지를 보충하기 좋은 로컬 맛집입니다.', '{restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.012566, 36.155558), 4326), false, '{"source": "KOMOOT", "source_ids": ["333", "426"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/ng/ngzuf7f07mok14d9z7f76yygl42wxg7v3-uhi46877377/0?width=1920&crop=false"], "category_raw": "restaurant", "tour_count": 2, "nearby_landmarks": ["강경대흥시장", "금강 종주 자전거길", "강경근대역사문화거리"], "confidence": "medium", "address": "대한민국 충청남도 논산시 강경읍 대흥리 53-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대전 시청역', '대전 도시철도 1호선 시청역입니다. 주말 및 공휴일에 자전거를 싣고 대중교통을 연계(점프)하기 좋으며, 깨끗한 개방 화장실을 이용할 수 있습니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.386599, 36.351439), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/7/73/DJET_City_Hall_Station-Exit_No_8.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e2/DJET_City_Hall_Station-Gate.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["대전광역시청", "보라매공원", "둔산동 상권"], "confidence": "high", "address": "대한민국 대전광역시 서구 둔산중로 지하 55"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신도저수지', '신시모도 라이딩 코스 중 지나는 고즈넉한 저수지입니다. 수변 데크길은 현재 안전상 폐쇄되었으나, 조용한 섬의 자연 풍경을 감상하며 지나가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.45934, 37.527408), 4326), false, '{"source": "KOMOOT", "source_ids": ["71", "155"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["구봉산", "신시도연도교", "푸른벗말마을"], "confidence": "high", "address": "대한민국 인천광역시 옹진군 북도면 신도리 37-79"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신둔도예촌역', '경강선 전철역으로 이천 원적산 MTB 코스나 여주 이포보 방향 라이딩의 주요 출발점으로 활용하기 좋습니다. 자전거를 싣고 점프하기 편리한 대중교통 거점입니다.', '{transit,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.405629, 37.315632), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/4/45/Shindun-Doyechon_Station_Panorama.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/7d/Shindun-doyechon_stn_1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/03/Shindun-Doyechon_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/fc/Shindun-Doyechon_Station_Exit_1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b8/Shindun-Doyechon_Station_Exit_2.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["원적산", "정개산", "사기막골 도예촌", "예스파크"], "confidence": "high", "address": "대한민국 경기도 이천시 신둔면 남정리 363"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신매역', '대구 도시철도 2호선 신매역입니다. 대구스타디움 및 금호강 자전거길로 이어지는 라이딩 코스의 주요 대중교통 기점입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.704969, 35.840847), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["대구스타디움", "금호강 자전거길", "신매광장"], "confidence": "high", "address": "대한민국 대구광역시 매호동 신매"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신반포역', '지하철 9호선 신반포역입니다. 반포한강공원 접근성이 뛰어나 라이딩 전후 대중교통 연계나 만남의 장소로 활용하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.996401, 37.503639), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/68/20240611_신반포역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a0/922_Sinbanpo.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a0/20240611_신반포역_4번출구.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/7c/20240611_신반포역_승강장.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["반포한강공원", "반포푸르지오아파트", "세화고등학교"], "confidence": "high", "address": "대한민국 서울특별시 서초구 신반포로15길 4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신봉저수지', '충남 아산시 영인면에 위치한 조용한 저수지로, 한적한 교외 라이딩 중 수변 풍경을 감상하며 가볍게 지나가기 좋은 곳입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.003476, 36.893271), 4326), false, '{"source": "KOMOOT", "source_ids": ["270", "238"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["영인산", "고용산", "성내저수지"], "confidence": "high", "address": "대한민국 충청남도 아산시 영인면 신봉리 159-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('시음리 느티나무 쉼터', '부여군 양화면 시음리에 있는 500년 수령의 느티나무(보호수)입니다. 금강 자전거길 라이딩 중 시원한 나무 그늘 아래서 땀을 식히며 쉬어가기 좋은 자연 쉼터입니다.', '{nature,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.86167, 36.078453), 4326), false, '{"source": "KOMOOT", "source_ids": ["659", "261"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/10/106zji5ibfek81e0abhegdc7qz50lkj56l-uhi73857450/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/y5/y59hso3qs82y7b4g3i115s0j52tmwcj9-uhi76542005/0?width=1920&crop=false"], "category_raw": "natural_monument", "tour_count": 2, "nearby_landmarks": ["금강", "금강 자전거길"], "confidence": "high", "address": "대한민국 충청남도 부여군 양화면 시음리 264-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신용산역', '한강 자전거길과 남산 접근성이 뛰어난 4호선 지하철역입니다. 주변 용리단길에 식당과 카페가 많아 라이딩 전후 보급 및 만남의 장소로 좋습니다.', '{transit,restroom,convenience_store,cafe,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.967793, 37.529214), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/db/Seoul-metro-429-Sinyongsan-station-platform-20191022-154052.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/5a/Q497868_Sinyongsan_A04.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f2/Sinyongsan_Station_Platform.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8c/Sinyon03.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3c/Q497868_Sinyongsan_A03.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["용산역", "용리단길", "이촌 한강공원"], "confidence": "high", "address": "대한민국 서울특별시 신용산역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신행정타운', '홍천경찰서 등 주요 공공기관이 모여 있는 행정 구역입니다. 도로가 넓고 쾌적하여 라이딩 중 안전하게 통과하거나 공공시설의 화장실을 이용하기 좋습니다.', '{landmark,police,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.908718, 37.706667), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 2, "nearby_landmarks": ["홍천경찰서", "홍천종합운동장", "홍천군농업기술센터"], "confidence": "high", "address": "대한민국 홍천군 신행정타운"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('아바이마을', '동해안 자전거길 속초 구간에서 식사와 휴식을 취하기 좋은 명소입니다. 명물인 아바이순대로 든든하게 배를 채우고 갯배를 구경하며 쉬어갈 수 있습니다.', '{restaurant,landmark,historic,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.594162, 38.201918), 4326), false, '{"source": "KOMOOT", "source_ids": ["295", "1754"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1c/1c22n8ub45nd61at4cmpbkeuhl30kx8mji-uhi6404857/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1f/1fe80vwrghnl51qs9zwm2p5kru30kxj295-uhi6405067/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/mx/mxms8ivkjwp7pdzmwvjmoi7q30kxj5lg-uhi6405068/0?width=1920&crop=false"], "category_raw": "settlement", "tour_count": 2, "nearby_landmarks": ["갯배선착장", "설악대교", "청호해수욕장", "청초호"], "confidence": "high", "address": "대한민국 강원특별자치도 속초시 청호동 932"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('아양교', '금호강 자전거길의 주요 거점 교량으로 봄철 벚꽃 라이딩 명소로 유명합니다. 인근 아양기찻길과 동촌유원지에서 휴식하며 경치를 즐기기 좋습니다.', '{bridge,river,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.639954, 35.887183), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/f/fd/아양교역_Photo_827.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/29/Daegu-metropolitan-transit-corporation-137-Ayanggyo-station-entrance-3-20161009-091038.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9b/아양교역.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/86/Ayanggyo_station_platform_20180221_172620.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["금호강 자전거길", "아양기찻길", "동촌유원지"], "confidence": "high", "address": "대한민국 대구광역시 동구 80-11"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('선유리 경의선 건널목', '파주 선유리 아파트 단지 앞 경의선 철도 건널목입니다. 자전거 통과 시 선로 홈에 바퀴가 빠지거나 미끄러지지 않도록 직각으로 안전하게 건너고, 열차 접근에 주의하세요.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.788955, 37.864041), 4326), false, '{"source": "KOMOOT", "source_ids": ["364", "509"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1p/1patuet54o1v81rpa86ydecb014d9ilq07-uhi56103617/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1n/1nob8ok89p3w1ghy7doj1equc4d9ilu3d-uhi56103618/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1q/1q0u7lyng8r361paxxjbeju2c44d9ilx72-uhi56103619/0?width=1920&crop=false"], "category_raw": "other_man_made", "tour_count": 2, "nearby_landmarks": ["경의선 철도", "선유리 아파트 단지"], "confidence": "high", "address": "대한민국 경기도 파주시 문산읍 선유리 923-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('안동터미널', '안동 지역 자전거 라이딩의 주요 출발 및 도착지로, 대중교통을 이용한 점프(자전거 적재 후 이동)에 필수적인 교통 시설입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.674593, 36.574577), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/8/8d/안동역.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/cc/안동역3.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d7/20211114_안동역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d8/20211114_안동역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/18/Andongstation.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["안동역", "안동종합버스터미널"], "confidence": "high", "address": "대한민국 경상북도 안동시 송현동 649-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('암사역', '8호선 암사역입니다. 한강 자전거길 접근성이 뛰어나 한강 동부나 팔당 방면 라이딩 시 만남의 장소 및 주말 지하철 점프 포인트로 유용합니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.12754, 37.550124), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/e/e6/20240810_암사역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d3/810_amsa_04.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/ab/20240810_암사역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/cc/Seoul-metro-810-Amsa-station-entrance-4-20180914-134226.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/84/810_amsa_03.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["광나루 한강공원", "암사초록길", "암사동 선사유적지"], "confidence": "high", "address": "대한민국 서울특별시 암사"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('압구정', '강남의 대표적인 번화가로, 한강 자전거길(압구정나들목)과 인접해 있어 라이더들이 도심으로 진출입하거나 모임 장소로 자주 활용하는 지역입니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.028542, 37.526183), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/e/ec/Apgujeong_Station_20220423_002.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e4/Apgujeong_Station_20220423_003.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3b/Apgujeong_Station_2.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f4/Apgujeong_Station_7483.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/78/Jeong_Seon-Apgujeong.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["압구정로데오거리", "갤러리아백화점", "압구정나들목(한강공원 진입로)"], "confidence": "high", "address": "대한민국 서울특별시 강남구 압구정로 334-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('야방산', '진도군 고군면 지막리에 위치한 해발 약 44m의 아주 낮은 야산입니다. 진도 해안도로 라이딩 중 가벼운 언덕 코스로 지나치게 되는 한적한 구간입니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.35379, 34.48183), 4326), false, '{"source": "KOMOOT", "source_ids": ["1636", "125"], "category_raw": "21", "tour_count": 2, "nearby_landmarks": ["지막리 마을", "벌포 바다"], "confidence": "high", "address": "대한민국 전라남도 진도군 고군면 지막리 632-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('하나분식', '광주천 자전거길과 인접한 양동시장 내 유명 국밥집(하나분식)입니다. 머리고기와 진한 장터국밥을 맛볼 수 있어 라이딩 중 든든하게 에너지를 보충하기 좋습니다.', '{restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.901566, 35.154102), 4326), false, '{"source": "KOMOOT", "source_ids": ["61", "482"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1o/1ocbu8dyen1nkd1q4j7igf6qk5cskpdcj-uhi85733427/0?width=1920&crop=false"], "category_raw": "restaurant", "tour_count": 2, "nearby_landmarks": ["양동시장", "광주천"], "confidence": "high", "address": "대한민국 광주광역시 서구 양동시장2길 2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('양원역', '경의중앙선 양원역입니다. 주말과 공휴일에 자전거 승차가 가능해 라이딩 전후 전철 점프(이동) 거점으로 활용하기 좋습니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.108067, 37.606374), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/b/b6/Yangwon.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c1/Jungang_Line_Yangwon_Station_2.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["중랑캠핑숲", "서울특별시 북부병원"], "confidence": "high", "address": "대한민국 서울특별시 중랑구 망우동 269-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('여량버스터미널', '정선 아우라지 인근의 소규모 시골 버스터미널입니다. 작은 슈퍼가 매표소를 겸하고 있어 라이딩 중 가벼운 보급이나 대중교통 연계(점프) 거점으로 활용하기 좋습니다.', '{transit,convenience_store,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.723046, 37.471595), 4326), false, '{"source": "KOMOOT", "source_ids": ["1566", "722"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/wm/wmlzq5rqi7ay4t7fikvj3dbh3dvywi34-uhi13807388/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 2, "nearby_landmarks": ["아우라지", "정선레일바이크 아우라지역"], "confidence": "high", "address": "대한민국 강원특별자치도 정선군 여량면 여량리 272-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('여의도 한강공원 어린이 놀이터', '자전거 대여소(카드 전용)와 깨끗한 화장실, 벤치가 있어 라이딩 중 휴식하기 좋은 한강공원 놀이터입니다. 가족 단위 라이더에게 특히 추천합니다.', '{park,rest_area,restroom,bike_shop,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.936939, 37.525112), 4326), false, '{"source": "KOMOOT", "source_ids": ["193", "142"], "tips": [{"text": "Nice park along Han river with a children''s playground and bicycle rentals (does not accept cash). Different type of bikes available. A family bike on four wheels, tandem bikes, regular bikes and children bikes with or without trainers. There are picnic tables, benches and clean restrooms in the area.", "author": "Jon Snow"}], "category_raw": "facilities", "tour_count": 2, "nearby_landmarks": ["여의도나들목", "유람선 선착장(이랜드크루즈)", "여의나루역"], "confidence": "high", "address": "대한민국 서울특별시 영등포구 여의동 85"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('역평저수지', '충남 금산군 남이면에 위치한 한적한 산골 저수지입니다. 배티재나 남이자연휴양림 방면 라이딩 시 자연 경관을 즐기며 지나기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.40103, 36.064298), 4326), false, '{"source": "KOMOOT", "source_ids": ["490", "270"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["배티재", "백암산", "남이자연휴양림"], "confidence": "high", "address": "대한민국 충청남도 금산군 남이면 역평리 566-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('연천공영버스터미널', '평화누리 자전거길 등 연천 지역 라이딩 시 대중교통 점프 거점으로 유용한 공영버스터미널입니다. 연천역과 인접해 접근성이 좋고 화장실, 대합실 등 편의시설을 갖추고 있습니다.', '{transit,restroom,rest_area,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.078254, 38.101263), 4326), false, '{"source": "KOMOOT", "source_ids": ["813", "312"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/ou/ouvsqmxzv3y8kb4fcio31sr93ffndvlk-uhi16388604/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 2, "nearby_landmarks": ["연천역", "연천역 급수탑", "차탄천"], "confidence": "high", "address": "대한민국 경기도 연천군 연천읍 차탄리 621"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('영월역', '영월 라이딩(별마로 천문대, 동강 등)의 주요 출발지입니다. 고풍스러운 한옥 형태의 기차역으로 주차장과 화장실이 잘 갖춰져 있어 라이더가 이용하기 편리합니다.', '{transit,landmark,historic,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.480551, 37.182571), 4326), false, '{"source": "KOMOOT", "source_ids": ["1"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/2h/2hvp1fyrqbrg1xqpo08w4xgsv3dyb9hik-uhi13877263/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/pd/pd2gzl5n9ydru1i3cd89vg853dyb9lfa-uhi13877268/0?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["동강", "별마로 천문대", "청령포"], "confidence": "high", "address": "대한민국 강원특별자치도 영월군 영월읍 덕포리 507-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('영일대해수욕장', '동해안 자전거길 종주 중 탁 트인 바다와 포스코 야경을 감상하며 쉬어가기 좋은 포항의 대표 해수욕장입니다. 주변에 편의시설이 많아 보급에 유리합니다.', '{beach,viewpoint,rest_area,landmark,restroom,cafe,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.383644, 36.063633), 4326), false, '{"source": "KOMOOT", "source_ids": ["185", "19"], "category_raw": "beach", "tour_count": 2, "nearby_landmarks": ["영일대 누각", "환호공원 스페이스워크", "포항여객선터미널"], "confidence": "high", "address": "대한민국 경상북도 포항시 북구 두호동 1002-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('영주댐', '무섬마을에서 이어지는 자전거길의 주요 목적지로, 영주호의 탁 트인 절경을 감상하며 쉬어가기 좋은 라이딩 명소입니다.', '{viewpoint,lake,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.676149, 36.735799), 4326), false, '{"source": "KOMOOT", "source_ids": ["82", "12", "277", "102"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k0/1o/1orrpr2eix6yhun67zob6sr5m1x1hx0n1-uhi541519/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k0/gz/gzs4nr5fzge9lp78eqb6uvnp1x1fct34-uhi541450/0?width=1920&crop=false"], "category_raw": "viewpoint", "tour_count": 2, "nearby_landmarks": ["용마루공원", "영주댐 물문화관", "영주호 오토캠핑장"], "confidence": "high", "address": "대한민국 경상북도 영주시 평은면 금광리 산82-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('영주댐', '무섬마을과 이어지는 자전거길 코스의 주요 목적지이자 탁 트인 영주호 풍경을 감상할 수 있는 뷰포인트입니다. 물문화관과 용마루공원 등 휴식 공간이 잘 갖춰져 있습니다.', '{viewpoint,landmark,lake,park,rest_area,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.68671, 36.736697), 4326), false, '{"source": "KOMOOT", "source_ids": ["82", "12", "277", "102"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k0/1o/1orrpr2eix6yhun67zob6sr5m1x1hx0n1-uhi541519/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k0/gz/gzs4nr5fzge9lp78eqb6uvnp1x1fct34-uhi541450/0?width=1920&crop=false"], "category_raw": "viewpoint", "tour_count": 2, "nearby_landmarks": ["영주호", "영주댐 물문화관", "용마루공원", "용혈폭포"], "confidence": "high", "address": "대한민국 경상북도 영주시 평은면 강동리 산194-12"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오미저수지', '제천 용두산 임도 코스와 이어지는 한적한 계곡형 저수지입니다. 맑은 물과 수려한 경관을 감상하며 힐링 라이딩을 즐기기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.196289, 37.243321), 4326), false, '{"source": "KOMOOT", "source_ids": ["246", "468"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["용두산", "오미리계곡", "오미리산촌체험마을"], "confidence": "high", "address": "대한민국 충청북도 제천시 송학면 오미리 145-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오봉저수지', '금오산 자락에 위치한 김천 최대 규모의 저수지입니다. 수변 데크길과 주변 도로가 잘 정비되어 있어 경치를 감상하며 여유롭게 라이딩하기 좋습니다.', '{lake,park,rest_area,viewpoint,bridge,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.239956, 36.117704), 4326), false, '{"source": "KOMOOT", "source_ids": ["199", "329", "586"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["금오산", "드림밸리 오색테마공원"], "confidence": "high", "address": "대한민국 경상북도 김천시 남면 오봉리 886-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오산역 환승센터', '1호선 전철과 버스를 이용할 수 있는 오산역 환승센터입니다. 대규모 자전거 주차장과 화장실이 있어 대중교통 연계(점프) 및 휴식 거점으로 유용합니다.', '{transit,parking,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.067668, 37.145492), 4326), false, '{"source": "KOMOOT", "source_ids": ["117", "112", "267", "202", "74", "153", "25", "156", "506", "152"], "image_urls": ["https://photos.komoot.de/wiki/commons/c/c8/Korail_Osan_Stn_20090621.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b1/오산역_환승센터_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/49/Osan_station_sign.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["오산역 환승센터", "오산천 자전거길"], "confidence": "high", "address": "대한민국 경기도 오산시 오산동 603-168"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오산천 동탄여울공원 구간', '동탄여울공원 인근을 지나는 오산천 자전거길 구간입니다. 평탄하고 경치가 좋아 동탄에서 오산, 평택으로 이어지는 라이딩 코스로 인기가 많습니다.', '{river,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.084166, 37.194451), 4326), false, '{"source": "KOMOOT", "source_ids": ["915", "82"], "category_raw": "river", "tour_count": 2, "nearby_landmarks": ["동탄여울공원", "오산천 자전거길"], "confidence": "high", "address": "대한민국 경기도 화성시 오산동 557-12"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('옥정호', '매년 그란폰도 대회가 열리는 전북 임실의 대표적인 라이딩 명소입니다. 물안개 낀 호수 순환도로와 벚꽃길을 달리며 붕어섬, 출렁다리 등 수려한 경관을 즐길 수 있습니다.', '{lake,nature,viewpoint,bridge,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.106571, 35.588994), 4326), false, '{"source": "KOMOOT", "source_ids": ["648", "363"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["붕어섬", "옥정호 출렁다리", "국사봉 전망대", "운암대교"], "confidence": "high", "address": "대한민국 전북특별자치도 임실군 운암면 운정리 220-78"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('옥천역', '대청호와 금강을 따라 달리는 ''향수 100리 자전거길''의 주요 출발점인 옥천역입니다. 무궁화호 등 대중교통 연계가 가능해 자전거 여행의 거점으로 활용하기 좋습니다.', '{transit,landmark,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.565977, 36.297937), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/e/e3/Okcheon_Station_20240730_(02).jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/89/Korail_gyeongbu_line_Okcheon_station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/57/Okcheon_Station_by_Mins.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/48/Korail_gyeongbu_line_Okcheon_station_platform.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["향수 100리 자전거길", "정지용 생가"], "confidence": "high", "address": "대한민국 충청북도 옥천군 옥천읍 금구리 112-107"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('온실', '제주시 오라2동 중산간 지역에 위치한 농업용 온실로 추정됩니다. 라이딩 시 길을 확인하는 시각적 랜드마크로 활용할 수 있으며, 별도의 편의시설은 없습니다.', '{other,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.51404, 33.467371), 4326), false, '{"source": "KOMOOT", "source_ids": ["1419", "398"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1e/1er9xr9th5pwu1rktxv7h36z6v4cgug0o0-uhi55442199/0?width=1920&crop=false"], "category_raw": "other_man_made", "tour_count": 2, "nearby_landmarks": ["오라동 메밀밭", "한라산 중산간 도로"], "confidence": "low", "address": "대한민국 제주특별자치도 제주시 오라이동 73-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('온천천', '부산 도심을 흐르는 생태하천으로 평탄한 자전거길이 조성되어 라이딩하기 좋습니다. 산책하는 시민이 많아 보행자 안전에 유의하며 주행해야 합니다.', '{river,park,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.096752, 35.207447), 4326), false, '{"source": "KOMOOT", "source_ids": ["71", "1427"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["온천천시민공원", "수영강 자전거길"], "confidence": "high", "address": "대한민국 부산광역시 동래구 명장동 267-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('왕산리 지석묘', '경안천 자전거길 인근에 위치한 경기도 최대 규모의 청동기 시대 고인돌 유적입니다. 라이딩 중 잠시 들러 역사적 정취를 느끼며 쉬어가기 좋습니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.252438, 37.335698), 4326), false, '{"source": "KOMOOT", "source_ids": ["205", "244"], "image_urls": ["https://photos.komoot.de/wiki/commons/0/08/%EC%9A%A9%EC%9D%B8_%EC%99%95%EC%82%B0%EB%A6%AC_%EC%A7%80%EC%84%9D%EB%AC%98.jpg?width=1920&crop=false"], "category_raw": "15", "tour_count": 2, "nearby_landmarks": ["경안천", "관청천", "한국외국어대학교 글로벌캠퍼스"], "confidence": "high", "address": "대한민국 경기도 용인시 처인구 모현읍 왕산리 503-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('왕숙천', '한강 합수부에서 포천 방향으로 이어지는 하천으로, 쾌적한 자전거 전용도로가 조성되어 수도권 동북부 라이딩의 핵심 코스로 꼽힙니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.15116, 37.657462), 4326), false, '{"source": "KOMOOT", "source_ids": ["601", "908"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["경춘선 자전거길", "진관교", "광릉수목원"], "confidence": "high", "address": "대한민국 경기도 남양주시 진건읍 신월리 656-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('용덕저수지', '용인 처인구에 위치한 맑은 저수지로 오색둘레길과 낚시터가 있습니다. 인근 묵리임도와 연계하여 MTB나 그래블 라이딩을 즐기기 좋은 코스입니다.', '{lake,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.225791, 37.186416), 4326), false, '{"source": "KOMOOT", "source_ids": ["979", "39"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["신원낚시터", "오색둘레길", "안젤리미술관", "묵리임도"], "confidence": "high", "address": "대한민국 경기도 용인시 처인구 이동읍 묵리 884-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('용수저수지', '구미 해평면에 위치한 한적한 저수지로, 도리사나 냉산 업힐 코스를 향하는 라이더들이 경치를 즐기며 지나가기 좋은 자연 포인트입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.390135, 36.229629), 4326), false, '{"source": "KOMOOT", "source_ids": ["570", "461"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["도리사", "냉산"], "confidence": "high", "address": "대한민국 경상북도 구미시 해평면 송곡리 산108"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('용연계곡', '제주환상자전거길 용두암 인근의 아름다운 계곡과 출렁다리입니다. 보행자 전용 다리이므로 자전거는 내려서 끌고 이동해야 하며, 경관과 야경이 뛰어납니다.', '{bridge,viewpoint,river,nature,landmark,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.514109, 33.514922), 4326), false, '{"source": "KOMOOT", "source_ids": ["126", "17"], "category_raw": "14", "tour_count": 2, "nearby_landmarks": ["용두암", "용담공원", "용두암인증센터"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 용담이동 454-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('용인시청 공영주차장', '용인시청 인근 공영 주차장으로, 경안천 자전거길이나 와우정사 방면 라이딩을 시작하는 출발지로 활용하기 좋습니다. 시청·용인대역과 가까워 대중교통 연계도 편리합니다.', '{parking,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.179072, 37.239821), 4326), false, '{"source": "KOMOOT", "source_ids": ["1229", "468"], "category_raw": "14", "tour_count": 2, "nearby_landmarks": ["용인시청", "시청·용인대역", "경안천 자전거길"], "confidence": "high", "address": "대한민국 경기도 용인시 처인구 삼가동 233-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('용인중앙시장', '경안천 자전거길과 바로 연결되어 있어 라이딩 중 순대국 등 든든한 식사와 간식을 즐기며 휴식하기 좋은 전통시장입니다.', '{restaurant,rest_area,restroom,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.209078, 37.2378), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/7/7e/Undongjangsongdamdae-o.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/ko/9/9e/Undongjangsongdamdae-a.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/ec/Undongjangsongdamdae-g.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/04/Undongjangsongdamdae-s.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/25/Undongjangsongdamdae-y.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["경안천 자전거길", "용인중앙시장역(에버라인)"], "confidence": "high", "address": "대한민국 경기도 용인시 처인구 김량장동 144-14"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('우동제', '부안 내변산 자락에 위치한 저수지로, 비가 올 때만 나타나는 장엄한 선계폭포를 조망할 수 있습니다. 한적한 자연 풍경을 즐기며 라이딩하기 좋은 코스입니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.631905, 35.624944), 4326), false, '{"source": "KOMOOT", "source_ids": ["494", "858"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["선계폭포", "반계유형원유적지", "내변산"], "confidence": "high", "address": "대한민국 전북특별자치도 부안군 보안면 우동리 산137-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('웅포대교', '금강자전거길 종주 코스에 위치한 다리로, 전북 익산과 충남 부여를 연결합니다. 금강의 탁 트인 경관을 감상하며 라이딩하기 좋습니다.', '{bridge,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.879773, 36.107013), 4326), false, '{"source": "KOMOOT", "source_ids": ["352", "566"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/o3/o3u5h7sj9abaxohyi1i3bqnf4ntlpye7-uhi63157175/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/8d/8dnkvzz2ytn61lehqx0f0i6w94ntlq0rf-uhi63157176/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 2, "nearby_landmarks": ["금강자전거길", "금강", "웅포곰개나루"], "confidence": "high", "address": "대한민국 전북특별자치도 익산시 웅포면 맹산리 274-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('웅포대교 자전거길', '금강을 가로지르는 웅포대교에 위치한 자전거길입니다. 금강자전거길 종주 시 강을 건너는 주요 길목이며, 탁 트인 강 풍경과 일몰을 감상하며 달리기 좋습니다.', '{bridge,river,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.868821, 36.105475), 4326), false, '{"source": "KOMOOT", "source_ids": ["337", "583"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1u/1ungkco2vrvt2bjfk3r5zcw4v4m5lvn3w-uhi61564427/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1i/1imrwiiuhdz9im5njktukyy5u4m5lvphh-uhi61564428/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1e/1es5u6q31lbh3pqpvlrzfwutm4m5lvrw4-uhi61564429/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 2, "nearby_landmarks": ["금강", "웅포대교", "웅포곰개나루", "신성리 갈대밭"], "confidence": "high", "address": "대한민국 충청남도 부여군 양화면 내성리 84-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('원덕역', '경의중앙선 전철 점프를 통해 흑천 자전거길이나 남한강, 산수유마을 코스 라이딩을 시작하기 좋은 한적한 역입니다. 역 내 화장실 이용이 가능합니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.546707, 37.468118), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/56/Ancien_gare_de_Wondeok.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b8/Gare_de_Wondeok.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["흑천", "추읍산", "남한강 자전거길"], "confidence": "high", "address": "대한민국 경기도 양평군 양평읍 원덕리 299-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('원동천', '낙동강 자전거길과 배내골 방향 코스가 갈라지는 분기점 하천입니다. 봄철 원동역과 순매원 주변의 매화 라이딩 명소로 유명합니다.', '{river,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.91795, 35.373519), 4326), false, '{"source": "KOMOOT", "source_ids": ["1266", "34"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["원동역", "순매원", "낙동강종주자전거길", "원동교"], "confidence": "high", "address": "대한민국 경상남도 양산시 원동면 용당리 1521-14"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('월곡역', '서울 지하철 6호선 월곡역입니다. 정릉천 자전거도로 진출입이 용이하며, 역 인근 따릉이 대여소와 대형 마트가 있어 점프 및 보급 거점으로 유용합니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.041429, 37.601926), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/6b/Seoul-metro-641-Wolgok-station-platform-20181125-144806.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/87/Seoul-metro-641-Wolgok-station-entrance-5-20181125-145306.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/81/Seoul-metro-641-Wolgok-station-entrance-4-20181125-145152.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b0/Q490057_Wolgok_A01.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["정릉천", "동덕여자대학교", "홈플러스 월곡점"], "confidence": "high", "address": "대한민국 서울특별시 성북구 월곡로 지하 107"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('월산저수지', '양평 그란폰도 및 MTB 코스에 포함되는 한적한 저수지입니다. 탁 트인 수변 풍경을 감상하며 라이딩 중 잠시 쉬어가기 좋습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.651459, 37.471154), 4326), false, '{"source": "KOMOOT", "source_ids": ["119", "1611"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["석불역", "미리내캠프", "지평낚시터"], "confidence": "high", "address": "대한민국 경기도 양평군 지평면 월산리 산334-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('월평역', '대전 지하철 1호선 월평역입니다. 갑천 자전거길과 유림공원으로 접근하기 좋으며, 역 주변에 자전거 보관소와 타슈(공영자전거) 대여소가 있습니다.', '{transit,parking,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.364586, 36.358344), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/0/07/Wolpyeong_Stn._platform.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2a/Wolpyeong_Stn._exit.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/60/Wolpyeong_Stn._nameplate.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["갑천 자전거길", "유림공원", "이마트 트레이더스"], "confidence": "high", "address": "대한민국 대전광역시 월평역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('유성온천', '갑천 자전거길과 인접해 있으며, 라이딩 후 무료 야외 족욕체험장에서 발의 피로를 풀며 쉬어가기 좋은 대전의 대표적인 휴식 명소입니다.', '{rest_area,landmark,transit,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.34168, 36.353715), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/2/28/Yuseong_Spa_Stn._platform.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/49/Yuseong_Spa_Station_2nd_Exit.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/ee/Yuseong_Spa_Stn._exit.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a3/Yuseong_Spa_Stn._nameplate.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/1f/Yuseong_Spa_Stn._waiting_room.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["유성온천 족욕체험장", "유성온천문화공원", "갑천 자전거길", "유림공원"], "confidence": "high", "address": "대한민국 대전광역시 유성온천역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('명지 유수지 공원', '명지동에 위치한 수변 유수지로, 주변에 자전거길과 산책로가 잘 조성되어 있어 라이딩 중 자연을 감상하며 가볍게 휴식하기 좋은 장소입니다.', '{lake,park,rest_area,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.928709, 35.104282), 4326), false, '{"source": "KOMOOT", "source_ids": ["61", "41"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["명지IC", "을숙도 생태공원", "명지오션시티"], "confidence": "high", "address": "대한민국 부산광역시 강서구 명지동 1279-19"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('응봉역 공공자전거 대여소', '응봉역 인근에 위치한 성동구 공공 자전거 대여소 및 공영 주차장입니다. 공중화장실이 마련되어 있어 중랑천이나 한강 라이딩 전후 정비와 휴식을 취하기 좋습니다.', '{bike_shop,restroom,parking,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.03458, 37.55034), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/e/e2/Q58953_Eungbong_A01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a8/Korail-K115-Eungbong-station-platform-20191023-100414.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/85/Eungbong_Station_2019.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/34/Korail-K115-Eungbong-station-entrance-1-20191023-100928.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/28/Eungbg02.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["응봉역", "응봉산", "중랑천 자전거길"], "confidence": "high", "address": "대한민국 서울특별시 성동구 응봉동 3-11"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('이계천', '구미 진평동을 가로질러 낙동강으로 합류하는 도심 하천입니다. 낙동강 자전거길로 진입하기 좋으나, 현재 생태하천 복원 공사가 진행 중이므로 라이딩 시 주의가 필요합니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.408733, 36.105), 4326), false, '{"source": "KOMOOT", "source_ids": ["6", "2256"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["낙동강", "반달교", "임수교"], "confidence": "high", "address": "대한민국 경상북도 구미시 진평동 645"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('이촌역 (한강공원 진입)', '이촌 한강공원 자전거길로 진입하기 좋은 지하철역입니다. 경의중앙선을 이용해 자전거를 싣고 이동(점프)하기 편리하며, 주변에 따릉이 대여소가 있습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.973476, 37.522403), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/da/Q58957_Ichon_A01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a2/Seoul-metro-430-Ichon-station-platform-20191022-152540.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/56/Seoul-metro-430-Ichon-station-entrance-1-20191022-152014.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/04/430ichon.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b4/Ichon_Station.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["이촌한강공원", "국립중앙박물관"], "confidence": "high", "address": "대한민국 서울특별시 이촌역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('인덕원역', '수도권 하트코스(학의천~과천 구간) 라이딩의 핵심 거점인 인덕원역 일대입니다. 대중교통 연계가 편하고 주변 상권이 발달해 보급과 휴식을 취하기 좋습니다.', '{transit,checkpoint,parking,convenience_store,restaurant,cafe,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.976835, 37.401627), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/58/Indeogwon1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/4b/Q497978_Indeogwon_A01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/18/20200903_인덕원역_8번출구.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/52/Indeogwon2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a1/Indeogwon_Station.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["학의천", "안양천", "백운호수"], "confidence": "high", "address": "대한민국 경기도 안양시 동안구 관양동 1566"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('인천베이호텔 근처 한식 국밥집', '인천베이호텔(레스티아) 인근에 위치해 가성비 좋게 든든한 한 끼를 해결할 수 있는 국밥집입니다. 아라뱃길 자전거길과 가까워 라이딩 전후로 식사하기 좋습니다.', '{restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.619394, 37.56238), 4326), false, '{"source": "KOMOOT", "source_ids": ["158", "172"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1k/1ksfxqcnpofzrqldty997wc2s5eryb6sb-uhi88344259/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1l/1l0qrje0thsfrfgqlk0317s5e5eryb7lg-uhi88344260/0?width=1920&crop=false"], "tips": [{"text": "Cheap place to eat if you are spending the night at Incheon Bay Hotel.", "author": "jesselyon"}], "category_raw": "restaurant", "tour_count": 2, "nearby_landmarks": ["레스티아 인천베이호텔", "경인아라뱃길", "정서진"], "confidence": "high", "address": "대한민국 인천광역시 서구 오류동 1597"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광주천 자전거길 (기아챔피언스필드 입구)', '광주천을 따라 이어지는 자전거 전용 도로의 진입 구간입니다. 기아챔피언스필드 인근에 위치해 광주천 자전거길 라이딩을 시작하기 좋습니다.', '{checkpoint,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.885808, 35.165685), 4326), false, '{"source": "KOMOOT", "source_ids": ["45", "446"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1b/1b1w1tz3nqsjztaqvt1bb2iww5if86xue-uhi93618819/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 2, "nearby_landmarks": ["광주기아챔피언스필드", "광주천"], "confidence": "high", "address": "대한민국 광주광역시 북구 임동 616"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('장전역 (온천천 자전거길)', '온천천 자전거길과 바로 연결되는 부산 1호선 전철역입니다. 자전거 보관소와 화장실이 마련되어 있어 라이딩 출발 및 도착지나 휴식처로 활용하기 좋습니다.', '{transit,parking,restroom,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.087866, 35.238206), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/5d/Busan-subway-129-Jangjeon-dong-station-1st-entrance.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/cc/129jangjeondong.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/55/Jangjeon_Station_2010.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f5/Busan-subway-129-Jangjeon-dong-station-platform.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["온천천 자전거길", "부산대학교"], "confidence": "high", "address": "대한민국 부산광역시 장전역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광진교 8번가', '광진교 교각 하부에 위치한 이색 전망대입니다. 자전거 도로와 연결되어 라이딩 중 탁 트인 한강 뷰를 보며 실내에서 쉬어가기 좋습니다. (월요일 휴관)', '{viewpoint,bridge,rest_area,river,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.114728, 37.544393), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 2, "nearby_landmarks": ["광진교", "광나루한강공원", "천호자전거거리"], "confidence": "high", "address": "대한민국 서울특별시 강동구 구천면로 77"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('국수리 남한강 전망대', '남한강 자전거길 국수역 인근에 위치한 전망대로, 탁 트인 남한강 풍경을 감상하며 라이딩 중 잠시 쉬어가기 좋은 휴식처입니다.', '{viewpoint,rest_area,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.388959, 37.510027), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 2, "nearby_landmarks": ["남한강 자전거길", "국수역", "남한강"], "confidence": "high", "address": "대한민국 경기도 양평군 양서면 국수리 산72-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('앙덕리 전망쉼터', '남한강 자전거길에 위치한 앙덕리 전망쉼터입니다. 커다란 느티나무 아래서 남한강의 탁 트인 풍경을 감상하며 쉬어가기 좋은 포인트입니다.', '{viewpoint,rest_area,river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.509574, 37.441218), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 2, "nearby_landmarks": ["남한강", "개군레포츠공원", "흑천"], "confidence": "high", "address": "대한민국 경기도 양평군 개군면 앙덕리 29-28"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오도재 지리산 조망공원', '지리산 주능선이 한눈에 들어오는 오도재 정상의 전망대입니다. 험난한 업힐 코스를 정복한 라이더들이 웅장한 경치를 감상하며 쉬어가기 좋은 필수 휴식처입니다.', '{viewpoint,rest_area,landmark,mountain,parking,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.700652, 35.44404), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 2, "nearby_landmarks": ["지리산제일문", "오도재", "지리산 조망공원", "지안재"], "confidence": "high", "address": "대한민국 경상남도 함양군 휴천면 월평리 산123-20"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대관령 반정 전망대', '대관령 옛길 힐클라임 코스 정상 부근에 위치한 전망대입니다. 강릉 시내와 동해 바다의 탁 트인 절경을 감상하며 가쁜 숨을 고르기 좋은 라이딩 필수 휴식처입니다.', '{viewpoint,rest_area,landmark,mountain}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.760438, 37.687378), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 2, "nearby_landmarks": ["신사임당 사친시비", "대관령 표지석", "대관령 옛길 반정"], "confidence": "high", "address": "대한민국 강원특별자치도 강릉시 성산면 어흘리 산2-12"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('죽령 바람길 전망대', '소백산 죽령 업힐 정상에 위치한 ''죽령 바람길 파노라마 전망대''입니다. 고된 업힐 후 카페와 휴게 공간에서 탁 트인 절경을 감상하며 쉬어가기 좋습니다.', '{viewpoint,rest_area,cafe,convenience_store,parking,restroom,mountain}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.435565, 36.898678), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 2, "nearby_landmarks": ["죽령", "소백산 국립공원", "죽령탐방지원센터"], "confidence": "high", "address": "대한민국 충청북도 단양군 대강면 용부원리 43-78"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('정자역', '탄천 자전거길과 인접한 수인분당선·신분당선 환승역으로, 라이딩 출발이나 복귀 시 지하철 점프(이동)에 유용합니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.108051, 37.366234), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/b/be/城南市盆唐区_亭子駅前の様子.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/cd/K230Jeongjastation02.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/59/Q31038_Jeongja_B01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a1/水仁盆唐線_亭子駅の1番出入り口.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f3/新盆唐線_亭子駅の6番出入り口.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["탄천 자전거길", "정자동 카페거리"], "confidence": "high", "address": "대한민국 경기도 성남시 분당구 성남대로 지하 333"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('용두암 인증센터', '제주 환상자전거길의 기점이자 종점인 용두암 인증센터입니다. 바위 뒤편에 위치해 자칫 지나치기 쉬우니 주의 깊게 살펴보세요.', '{checkpoint,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.511176, 33.5151), 4326), false, '{"source": "KOMOOT", "source_ids": ["144", "238"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/i5/i52sgr9y1bi2vpi536qyp2hy5edw6hvo-uhi87787501/0?width=1920&crop=false"], "tips": [{"text": "It is 25 meters of the trail tucked away behind a rock, easy to miss.", "author": "Fitz_carraldo"}], "category_raw": "facilities", "tour_count": 2, "nearby_landmarks": ["용두암", "제주관광안내센터"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 용담이동 571-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('제주민속오일시장', '제주 환상 자전거길 인근의 대규모 오일장(2, 7일)입니다. 장날에 방문하면 다양한 로컬 먹거리로 배를 채우고 휴식하기 좋습니다.', '{restaurant,rest_area,restroom,transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.475418, 33.493044), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 2, "nearby_landmarks": ["제주국제공항", "이호테우해변"], "confidence": "high", "address": "대한민국 제주시 월광로"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('제주유리의성', '제주 서부 중산간 지역에 위치한 유리 공예 테마파크입니다. 화려한 유리 조형물들을 감상하며 라이딩 중 이색적인 휴식을 취하기 좋은 명소입니다.', '{museum,landmark,park,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.272171, 33.313745), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 2, "nearby_landmarks": ["환상숲곶자왈공원", "오설록티뮤지엄", "저지오름"], "confidence": "high", "address": "대한민국 제주시 제주유리의성"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('조강저수지', '평화누리길 2코스 라이딩 중 만나는 한적한 저수지입니다. 매점과 화장실이 있어 쉬어가기 좋으며, 문수산과 애기봉 주변의 평화로운 자연 풍경을 감상할 수 있습니다.', '{lake,rest_area,convenience_store,restroom,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.572333, 37.744241), 4326), false, '{"source": "KOMOOT", "source_ids": ["753", "529"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["애기봉", "문수산", "평화누리길"], "confidence": "high", "address": "대한민국 경기도 김포시 월곶면 조강리 241"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('상남면 제1공영주차장', '설악그란폰도의 중심지인 인제군 상남면에 위치한 제1공영주차장입니다. 자전거 라이딩 전 차량을 주차하고 출발 준비를 하기에 좋습니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.260088, 37.872241), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 2, "nearby_landmarks": ["상남면행정복지센터", "인제라이딩센터"], "confidence": "high", "address": "대한민국 강원특별자치도 인제군 상남면 상남로 23"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('중계역 자전거 보급소', '지하철 7호선 중계역 인근 지점으로 중랑천 및 당현천 자전거길 접근성이 뛰어납니다. 주변 상권이 발달해 라이딩 중 식사나 보급을 해결하기 좋습니다.', '{transit,convenience_store,cafe,restaurant,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.063881, 37.645519), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/b/b8/Seoul-metro-714-Junggye-station-sign-20181122-141246.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f3/Seoul-metro-714-Junggye-station-entrance-6-20181122-142250.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/7c/Q68696_Junggye_A01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2f/Seoul-metro-714-Junggye-station-platform-20181122-141446.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["중계역", "중랑천 자전거길", "당현천"], "confidence": "high", "address": "대한민국 서울특별시 노원구 중계동 366-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('중대물빛공원', '구 중앙저수지로 현재는 ''중대물빛공원''입니다. 내부 산책로는 자전거 탑승이 금지되어 끌바나 우회가 필요하며, 라이딩 중 화장실과 음수대를 이용하며 쉬어가기 좋습니다.', '{lake,park,restroom,water_fountain,rest_area,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.221584, 37.40136), 4326), false, '{"source": "KOMOOT", "source_ids": ["33"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["중대천", "삼동역"], "confidence": "high", "address": "대한민국 경기도 광주시 중대동 334-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('지족역', '대전 도시철도 1호선 지족역입니다. 자전거 보관소와 타슈(공영자전거) 대여소가 있어 대중교통 연계 라이딩 및 휴식에 유용합니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.319779, 36.384366), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/d2/Jijok_Sta._nameplate.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/96/Jijok_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/da/Jijok_Sta._exit.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/81/Jijok_Sta._platform.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["한국침례신학대학교", "롯데마트 노은점"], "confidence": "high", "address": "대한민국 대전광역시 유성구 노은로 273"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('지축역', '창릉천 자전거길과 인접한 3호선 전철역입니다. 주말 및 공휴일에 자전거 휴대 승차가 가능해 라이딩 출발이나 복귀 지점으로 활용하기 좋습니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.913896, 37.648121), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/61/Q79841_Jichuk_A01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/28/Q79841_Jichuk_A03.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/ad/Q79841_Jichuk_A05.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/62/Q79841_Jichuk_A07.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/1d/Q79841_Jichuk_A02.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["창릉천 자전거길", "북한산"], "confidence": "high", "address": "대한민국 고양시 지축"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('진부(오대산)역', '오대산, 대관령, 강릉 방면 자전거 투어의 주요 출발지이자 KTX 점프 포인트입니다. 역사 내 편의점과 화장실 등 편의시설을 이용하기 좋습니다.', '{transit,convenience_store,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.574269, 37.642744), 4326), false, '{"source": "KOMOOT", "source_ids": ["1468"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1m/1mogojh2wfx5grvapugtntsmy3e86jgl9-uhi14447066/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/ya/yab48f471f5e1t395y3u9wzjh3jg74jwn-uhi24188930/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/fu/fuop6pbv0eyvorw4822lrj7c3kd4m5oq-uhi25436238/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 2, "nearby_landmarks": ["오대산", "오대천", "월정사"], "confidence": "high", "address": "대한민국 강원특별자치도 평창군 진부면 송정리 1383-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('진영역', '자전거 점프(기차 연계)가 가능한 KTX 진영역입니다. 봉하마을과 화포천 습지로 향하는 자전거길의 주요 출발점이며, 편의점과 화장실 등 편의시설이 잘 갖춰져 있습니다.', '{transit,convenience_store,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.773712, 35.29818), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/f/fc/Korail_jinyoung.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a4/Korail0jinyeong2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0e/신진영역.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/07/Jin3.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/20/Jin4.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["봉하마을", "화포천 습지생태공원"], "confidence": "high", "address": "대한민국 경상남도 김해시 진영읍 설창리 산15-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('진은동', '서귀포시 남원읍 태흥리에 속한 자연마을 및 버스 정류장입니다. 제주 환상 자전거길 남원 구간 인근의 일주도로를 라이딩할 때 지나게 되는 거점입니다.', '{transit,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.730475, 33.282595), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 2, "nearby_landmarks": ["남원읍사무소", "태흥리 해안도로"], "confidence": "high", "address": "대한민국 서귀포시 진은동"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('차곡지', '경산 남천임도 MTB 라이딩의 주요 출발지이자 휴식처입니다. 저수지 앞에 정자와 주차장이 마련되어 있어 라이딩 전후로 쉬어가기 좋습니다.', '{lake,rest_area,parking,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.703065, 35.782709), 4326), false, '{"source": "KOMOOT", "source_ids": ["480", "147"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["남천임도", "비내고개", "경흥사", "이목지"], "confidence": "high", "address": "대한민국 경상북도 경산시 남천면 산전리 542"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('창녕함안보 인증센터', '낙동강 종주길 ''낙동사막'' 구간의 단비 같은 인증센터입니다. 건물 2층에 편의점과 화장실 등 편의시설이 잘 갖춰져 있어 라이딩 중 든든하게 쉬어갈 수 있습니다.', '{checkpoint,convenience_store,restroom,rest_area,parking,viewpoint,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.552073, 35.380184), 4326), false, '{"source": "KOMOOT", "source_ids": ["233"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1a/1art1bzcremu1mqyt8grhlk383bhf69s6-uhi11112122/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/wj/wjcu4q3b8or2lr9c6u7l9j693bhf6jh9-uhi11112125/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/y8/y8jy3peqp54zwzs0s50zndbx3bhf6jhr-uhi11112126/0?width=1920&crop=false"], "tips": [{"text": "낙동강자전거 종주길 중 인증센터.\n인증센터 옆에 편의점이 있어 쉬어가기 좋다.", "author": "대철"}], "category_raw": "14", "tour_count": 2, "nearby_landmarks": ["창녕함안보", "낙동강"], "confidence": "high", "address": "대한민국 경상남도 창녕군 길곡면 증산리 818-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('철원 노동당사', '차량 통행이 적고 평탄해 자전거 라이더들의 장거리 투어 성지로 꼽히는 철원의 대표적인 역사적 랜드마크입니다. 근처 매점에서 보급과 휴식이 가능합니다.', '{historic,landmark,rest_area,convenience_store,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.201381, 38.255072), 4326), false, '{"source": "KOMOOT", "source_ids": ["427", "709"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/15/15fb06gaky1hi1c25udll1eqdh3djofvop-uhi13226205/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1x/1x4p9pd9qignlzqpgjt0d9mhq3djofxtg-uhi13226209/0?width=1920&crop=false"], "category_raw": "historical_site", "tour_count": 2, "nearby_landmarks": ["소이산 생태숲", "철원역사문화공원", "백마고지", "고석정"], "confidence": "high", "address": "대한민국 강원특별자치도 철원군 철원읍 관전리 4-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('청담역', '지하철 7호선 청담역입니다. 따릉이 대여소가 있으며, 한강 자전거길(청담나들목)과 가까워 라이딩 출발지나 대중교통 점프 거점으로 활용하기 좋습니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.051656, 37.51917), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/7/78/20240607_청담역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/75/Seoul-metro-729-Cheongdam-station-entrance-10-20181123-110100.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/ee/Seoul-metro-729-Cheongdam-station-platform-20181123-105504.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c9/20240607_청담역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/ad/Cheongdam02.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["청담나들목", "청담대교", "영동대교"], "confidence": "high", "address": "대한민국 서울특별시 청담동 75-1번지 청담역 강남구 서울특별시 KR"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('축산물급식지원센터 주차장', '청주 무심천 자전거길 인근에 위치한 주차장입니다. 라이딩 출발지나 만남의 장소로 활용하기 좋습니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.507258, 36.603874), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 2, "nearby_landmarks": ["무심천 자전거길", "방서교", "무심천"], "confidence": "high", "address": "대한민국 충청북도 청주시 상당구 방서동 115-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('춘천역 자전거 거점', '북한강 자전거길과 의암호 순환 코스의 주요 출발점인 춘천역입니다. 전철(ITX) 연계가 가능하며 주변에 주차장과 자전거 대여소가 있습니다.', '{transit,parking,bike_shop,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.716953, 37.884211), 4326), false, '{"source": "KOMOOT", "source_ids": ["128", "1569", "882", "121"], "image_urls": ["https://photos.komoot.de/wiki/commons/9/99/Chuncheon_station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b5/New_Chuncheon_Station.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9f/춘천역.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bb/Chuncheonstation.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/93/ChuncheonSta.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["춘천역", "북한강 자전거길", "의암호", "소양강 스카이워크"], "confidence": "high", "address": "대한민국 강원특별자치도 춘천시 근화동 556-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('통영 문화동 벅수', '통영 세병관으로 오르는 길목에 위치한 익살스러운 표정의 석장승입니다. 라이딩 중 가볍게 들러 사진을 남기기 좋은 역사적 명소입니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.423157, 34.846429), 4326), false, '{"source": "KOMOOT", "source_ids": ["77", "1192"], "category_raw": "15", "tour_count": 2, "nearby_landmarks": ["통영 세병관", "통영 삼도수군통제영"], "confidence": "high", "address": "대한민국 경상남도 통영시 문화동 122-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('카페 비앤허니', '직접 양봉한 천연 꿀과 벌집 아메리카노를 맛볼 수 있는 이색 카페입니다. 마안산 입구에 위치해 라이딩 중 확실한 당 충전과 휴식을 취하기 좋습니다.', '{cafe}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.958525, 36.935115), 4326), false, '{"source": "KOMOOT", "source_ids": ["569", "368"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/11/11j6zqxpdrkwv18r7bjz7qiw7i3u3gieq6-uhi36983353/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/77/7757mjaobywlpjgwg6wxb2i03u3gifeg-uhi36983356/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/pu/pu4d46edvr5g1uyzi0gv6s6xx3u3gifey-uhi36983357/0?width=1920&crop=false"], "tips": [{"text": "Nice cafe that produces their own Honey on site.", "author": ""}, {"text": "Nice cafe that produces their own Honey on site.", "author": "Curry (カレー)"}], "category_raw": "cafe", "tour_count": 2, "nearby_landmarks": ["마안산", "평택호"], "confidence": "high", "address": "대한민국 경기도 평택시 현덕면 대안리 15-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('탄금호 국제 조정 경기장', '탄금호 순환 자전거길의 주요 랜드마크입니다. 강물 위에 떠 있는 1.4km 길이의 중계도로(부교)를 자전거로 달리며 탁 트인 호수 풍경과 야경을 감상할 수 있습니다.', '{lake,landmark,bridge,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.864372, 37.022464), 4326), false, '{"source": "KOMOOT", "source_ids": ["557", "388"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/vq/vqry6bvr85iw1uwtj9j8qeefg37ljxybv-uhi9539295/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1o/1o5x53k584a0o11b171ysdpsuz37ljy4pn-uhi9539298/0?width=1920&crop=false"], "category_raw": "lake", "tour_count": 2, "nearby_landmarks": ["중앙탑 사적공원", "탑평리 칠층석탑(중앙탑)", "충주박물관"], "confidence": "high", "address": "대한민국 충청북도 충주시 중앙탑면 중앙탑길 150"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('태훈 파크 (제주 MTB 파크)', '제주도 연동에 위치한 산악자전거(MTB) 전용 파크입니다. 펌핑, 롤링, 갭점프 등 다양한 오프로드 테크닉을 연습할 수 있어 제주 라이더들에게 인기가 높습니다.', '{park,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.499914, 33.464692), 4326), false, '{"source": "KOMOOT", "source_ids": ["364", "1384"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/ld/ldalxzf6b3m212jfsn5j9owe4phv7ejc-uhi64917547/0?width=1920&crop=false"], "category_raw": "mtb_park", "tour_count": 2, "nearby_landmarks": ["한라수목원", "연동교차로"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 연동 939-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('통영삼도수군통제영', '조선시대 수군 본영으로, 통영 시내 라이딩 시 방문하기 좋은 대표적인 역사 랜드마크입니다. 국보인 세병관 등 웅장한 전통 건축물을 감상하며 쉬어갈 수 있습니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.422832, 34.848845), 4326), false, '{"source": "KOMOOT", "source_ids": ["89", "1204"], "category_raw": "18", "tour_count": 2, "nearby_landmarks": ["세병관", "동피랑 벽화마을", "통영중앙전통시장"], "confidence": "high", "address": "대한민국 경상남도 통영시 문화동 7-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('투썸플레이스 문경영신점', '영신강변과 영신숲 유원지 앞에 위치해 탁 트인 뷰를 자랑하는 대형 카페입니다. 넓은 매장과 테라스가 있어 라이딩 중 커피와 샌드위치를 즐기며 휴식하기 좋습니다.', '{cafe,rest_area,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.210291, 36.592617), 4326), false, '{"source": "KOMOOT", "source_ids": ["944", "1845"], "tips": [{"text": "guter Ort für Salat, Sandwich und Kaffee", "author": "on-the-way"}], "category_raw": "cafe", "tour_count": 2, "nearby_landmarks": ["영신숲 유원지", "영신강변"], "confidence": "high", "address": "대한민국 경상북도 문경시 영신로 102"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('트리풀시티 레이크포레', '갑천 자전거길과 갑천생태호수공원 인근에 위치한 대단지 아파트입니다. 단지 상가의 편의점과 카페를 이용할 수 있으며, 타슈 대여소가 있어 라이딩 기점으로 좋습니다.', '{landmark,convenience_store,cafe}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.348028, 36.325328), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 2, "nearby_landmarks": ["갑천생태호수공원", "갑천 자전거길", "도솔산"], "confidence": "high", "address": "대한민국 대전광역시 도안동"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('판교역', '신분당선과 경강선 환승역인 판교역입니다. 자전거 보관소 등 편의시설이 풍부하며, 주말 경강선을 이용해 여주 방면으로 자전거 점프(대중교통 연계)하기 좋은 주요 거점입니다.', '{transit,restroom,convenience_store,cafe,restaurant,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.11153, 37.394654), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/d0/城南市盆唐区_板橋駅の3番出入り口.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d7/20240907_신분당선_판교역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/7f/城南市盆唐区_板橋駅の2番出入り口.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/7c/城南市盆唐区_板橋駅の駅前広場.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f9/D11Pangyo.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["현대백화점 판교점", "판교테크노밸리", "화랑공원", "탄천 자전거길"], "confidence": "high", "address": "대한민국 경기도 성남시 분당구 백현동 534-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('팔당역', '남한강 자전거길의 주요 출발점인 경의중앙선 전철역입니다. 자전거 휴대 승차가 가능해 수도권 라이더들의 대표적인 만남의 장소로 꼽힙니다.', '{transit,landmark,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.243785, 37.547502), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/6f/Korail_Paldang_Station.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/67/K128_Paldang_02.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/7c/K128_Paldang_01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/aa/K128_Paldang_04.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/60/Facade_avant_de_la_gare_de_Paldang.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["남한강 자전거길", "팔당대교"], "confidence": "high", "address": "대한민국 경기도 남양주시 와부읍 팔당리 364-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('팔봉교', '수주팔봉과 달천의 멋진 절경을 감상하며 건널 수 있는 다리입니다. 인근에 캠핑장과 출렁다리가 있어 라이딩 중 경치를 보며 쉬어가기 좋습니다.', '{bridge,viewpoint,river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.921142, 36.899494), 4326), false, '{"source": "KOMOOT", "source_ids": ["291", "417"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/8y/8ype9xb92qhw1i1jny9ffhfmy3riocsiz-uhi32886823/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/6r/6rd6yy21cz0bcx397ntgdu9d3riod128-uhi32886827/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 2, "nearby_landmarks": ["수주팔봉", "수주팔봉 캠핑장", "수주팔봉 출렁다리", "달천"], "confidence": "high", "address": "대한민국 충청북도 충주시 살미면 토계리 417-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('평촌역', '지하철 4호선 평촌역입니다. 주말 자전거 휴대 승차를 통한 점프가 가능하며, 주변 상권이 발달해 식사와 행동식 보급을 해결하기 좋습니다.', '{transit,restroom,convenience_store,restaurant,cafe}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.963881, 37.394286), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/e/e6/Pyeongchon_station_nameplate.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/11/Pyeongchst01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d0/Pyeongchon_Subway_Station_-_Anyang_-_South_Korea_-_2018.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e1/Pyeongchst04.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e8/Pyeongchst03.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["평촌중앙공원", "평촌미관광장", "학의천 자전거길", "안양시청"], "confidence": "high", "address": "대한민국 경기도 안양시 동안구 관양동 1608-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('평화누리길 12코스(통일이음길)', '연천군 대광리를 지나는 평화누리길 12코스(통일이음길) 구간입니다. 차탄천 둑방길과 호젓한 농촌 풍경을 감상하며 여유롭게 라이딩하기 좋은 코스입니다.', '{nature,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.161506, 38.238713), 4326), false, '{"source": "KOMOOT", "source_ids": ["326", "634"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/aa/aaw8ceoxtml81ty1lkp5o7607358i9n6r-uhi8564994/0?width=1920&crop=false"], "category_raw": "trail", "tour_count": 2, "nearby_landmarks": ["대광리역", "차탄천", "신탄리역"], "confidence": "high", "address": "대한민국 경기도 연천군 신서면 대광리 4-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('화랑대 철도공원', '경춘선숲길 자전거길에 위치한 화랑대 철도공원입니다. 옛 증기기관차 관람과 이색 기차 카페에서 라이딩 중 휴식을 취하기 좋습니다.', '{historic,landmark,park,cafe,rest_area,museum,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.090483, 37.623414), 4326), false, '{"source": "KOMOOT", "source_ids": ["740", "1003"], "tips": [{"text": "Here you will see a old steam locomotive. cozy cafe and a no longer used trainstation", "author": "Andy"}], "category_raw": "man_made_monument", "tour_count": 2, "nearby_landmarks": ["경춘선숲길", "화랑대 철도공원", "구 화랑대역", "육군사관학교"], "confidence": "high", "address": "대한민국 서울특별시 노원구 공릉동 103-69"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('풍산역', '경의중앙선 풍산역으로 주말 자전거 점프(전철 탑승)가 가능합니다. 인근에 일산호수공원과 애니골 먹자골목이 있어 라이딩 전후 식사와 휴식을 취하기 좋습니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.78618, 37.672012), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/c/c0/Korail_Gyeongui_Line_Pungsan_Station.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["일산호수공원", "애니골", "밤가시마을"], "confidence": "high", "address": "대한민국 고양시 풍산역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('학여울', '양재천과 탄천이 합류하는 지점 인근으로, 자전거도로 진출입이 용이해 라이더들의 주요 만남의 장소이자 휴식처로 활용되는 거점입니다.', '{river,landmark,transit,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.069857, 37.496559), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/e/e6/Seoul-metro-346-Hangnyeoul-station-sign-20181123-151620.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e8/Seoul-metro-346-Hangnyeoul-station-entrance-1-20181123-152032.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b8/Daedongyeojido_(Gyujanggak)_13-04.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/83/Hangnyeoul_station_platform_20121229.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/1f/Seoul-metro-346-Hangnyeoul-station-sign-20181123-151534.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["학여울역", "SETEC", "양재천 합수부", "대치교"], "confidence": "high", "address": "대한민국 서울특별시 강남구 대치동 50-70"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('여의도 한강공원', '과거 ''I SEOUL U'' 조형물이 있던 여의도 한강공원입니다. 현재 조형물은 철거되었으나, 자전거 도로와 편의시설이 잘 갖춰져 있어 라이딩 중 휴식하기 좋습니다.', '{park,river,rest_area,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.930419, 37.53039), 4326), false, '{"source": "KOMOOT", "source_ids": ["229", "192"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1c/1ca5k4zrwxgf81m6jq1kf2chif4dcmupwy-uhi56169155/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/ga/gaqrh9z93gnu1t3sg54splwqs4dcmuqn9-uhi56169156/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1c/1clablf1x2qqd1gsenkrld8y8a4dcmur58-uhi56169157/0?width=1920&crop=false"], "category_raw": "man_made_monument", "tour_count": 2, "nearby_landmarks": ["여의도 한강공원", "마포대교", "여의나루역"], "confidence": "high", "address": "대한민국 서울특별시 영등포구 여의동 84"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('한남나들목', '한강 자전거길에서 한남동 시내와 남산으로 진입할 때 통과하는 나들목(토끼굴)입니다. 남산 라이딩을 시작하는 라이더들의 주요 기점입니다.', '{tunnel,checkpoint,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.009173, 37.529563), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/ko/a/af/K113%ED%95%9C%EB%82%A8%EC%97%AD01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/fa/Korail-K113-Hannam-station-platform-20191023-095108.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/90/Korail_JungAng_line_K113_Hannam_station_entrance.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/ko/c/c0/K113%ED%95%9C%EB%82%A8%EC%97%AD04.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/ko/1/10/K113%ED%95%9C%EB%82%A8%EC%97%AD05.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["한남역", "한강자전거길", "한남대교"], "confidence": "high", "address": "대한민국 서울특별시 용산구 한남동 503-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('한밝저수지', '1100도로와 제1산록도로가 만나는 어승생삼거리 인근의 저수지입니다. 한라산 업힐 라이딩 중 고즈넉한 풍경을 감상하며 지나치기 좋은 랜드마크입니다.', '{lake,landmark,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.481476, 33.413127), 4326), false, '{"source": "KOMOOT", "source_ids": ["543", "171"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["어승생삼거리", "어승생오름", "1100도로"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 해안동 산63-37"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('한천서원 은행나무', '수령 1,000년의 웅장한 은행나무와 한천서원이 있는 역사적인 장소입니다. 육각정자와 나무 그늘이 마련되어 있어 라이딩 중 고즈넉하게 쉬어가기 좋습니다.', '{historic,landmark,nature,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.654455, 35.779607), 4326), false, '{"source": "KOMOOT", "source_ids": ["194", "433"], "category_raw": "14", "tour_count": 2, "nearby_landmarks": ["한천서원", "한천서원 지석묘"], "confidence": "high", "address": "대한민국 대구광역시 달성군 가창면 행정리 874-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('함양터소류지', '함양읍 구룡리에 위치한 작은 저수지로, 지리산 인근 라이딩 코스에서 한적한 자연 경관을 즐기며 지나가기 좋은 포인트입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.699432, 35.476664), 4326), false, '{"source": "KOMOOT", "source_ids": ["41", "1688"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["해송마을"], "confidence": "high", "address": "대한민국 경상남도 함양군 함양읍 구룡리 산122-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구 해마레저 터', '과거 놀이공원이었으나 현재는 철거된 터입니다. 동해안 자전거길 낙산해변 구간에 위치하며, 지도에 표시되어 있어도 실제 시설은 없으니 그대로 통과하시면 됩니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.63954, 38.111541), 4326), false, '{"source": "KOMOOT", "source_ids": ["823", "1508"], "category_raw": "32", "tour_count": 2, "nearby_landmarks": ["낙산해수욕장", "동해안 자전거길", "오션밸리리조트"], "confidence": "high", "address": "대한민국 강원특별자치도 양양군 양양읍 해맞이길 135"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('해반천', '김해 도심을 흐르는 생태하천으로 보행로와 분리된 자전거 전용도로가 있어 라이딩하기 좋습니다. 조만강, 낙동강 종주길과 이어지며 주변에 가야 유적지가 많습니다.', '{river,nature,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.872659, 35.23601), 4326), false, '{"source": "KOMOOT", "source_ids": ["10", "300", "34", "1111"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["봉황대공원", "국립김해박물관", "대성동고분박물관"], "confidence": "high", "address": "대한민국 경상남도 김해시 봉황동 498"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('수기해변', '신시모도 라이딩 코스 중 시도에 위치한 수기해변입니다. 화장실과 캠핑장 등 편의시설이 잘 갖춰져 있어 바다 풍경을 감상하며 쉬어가기 좋습니다.', '{beach,rest_area,restroom,viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.431729, 37.54459), 4326), false, '{"source": "KOMOOT", "source_ids": ["1073", "235", "165", "199", "99", "897", "1734", "322", "710", "284"], "image_urls": ["https://photos.komoot.de/wiki/commons/d/d1/주문진해수욕장_향호해변.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bd/Jumunjin_Beach_20220501_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/30/Jumunjin_Beach_20220501_007.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/10/Jumunjin_Beach_20220501_013.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2a/Jumunjin_Beach_20220501_016.jpg?width=1920&crop=false"], "category_raw": "12", "tour_count": 2, "nearby_landmarks": ["수기해변 전망대", "수기해수욕장 야영장"], "confidence": "high", "address": "대한민국 인천광역시 옹진군 북도면 시도로86번길"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('행신역', '경의중앙선과 KTX가 정차하는 행신역입니다. 창릉천 자전거길과 가까워 라이딩 중 대중교통 연계(점프) 및 화장실, 편의점 이용을 위한 보급지로 유용합니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.834066, 37.611632), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/1/1e/Haengsin_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0b/행신역_1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3d/행신역_역사.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/df/행신역_폴사인.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2d/행신역_플랫폼_2.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["창릉천 자전거길", "강매역", "행주산성"], "confidence": "high", "address": "대한민국 경기도 고양시 덕양구 강매동 614-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('국립대전현충원', '공주 방향 삽재 업힐의 주요 기점이 되는 랜드마크입니다. 내부 둘레길은 자전거 출입이 제한될 수 있으나, 입구에 자전거 거치대가 있어 참배와 휴식이 가능합니다.', '{historic,landmark,park,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.321488, 36.359385), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/f/f5/National_Cemetery_Stn._platform.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a0/National_Cemetery_Stn._nameplate.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["삽재", "현충원역", "계룡산"], "confidence": "high", "address": "대한민국 대전광역시 유성구 구암동 422-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('협동 할인점', '낙동강 자전거길 낙단보 인근에 위치한 친절한 동네 마트입니다. 라이딩 중 생수와 간식 등 기본 보급품을 구매하고 쉬어가기 좋습니다.', '{convenience_store,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.29803, 36.36363), 4326), false, '{"source": "KOMOOT", "source_ids": ["241", "755"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/4w/4wpksan6ckyc187uvl2i4731u4pgkqy4u-uhi64868701/0?width=1920&crop=false"], "tips": [{"text": "extremely nice owner! has all the basics", "author": ""}], "category_raw": "facilities", "tour_count": 2, "nearby_landmarks": ["낙동강 자전거길", "낙단보"], "confidence": "high", "address": "대한민국 경상북도 상주시 낙동면 낙동리 729-23"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('추곡저수지 낚시터', '태화산 자락 추곡저수지에 위치한 낚시터입니다. 물 위에 떠 있는 방갈로가 이색적인 풍경을 자아내며, 라이딩 중 한적한 호수 경치를 감상하며 쉬어가기 좋습니다.', '{lake,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.306087, 37.285113), 4326), false, '{"source": "KOMOOT", "source_ids": ["797", "724"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1d/1dvscci19g25dnm4ngbd2uu94qlwj4vz-uhi66144561/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/cp/cptjm96ldbiw5a31gqtgo4mg4qlwj7wg-uhi66144563/0?width=1920&crop=false"], "category_raw": "lake", "tour_count": 2, "nearby_landmarks": ["태화산", "유정저수지", "산두른마을"], "confidence": "high", "address": "대한민국 경기도 광주시 도척면 추곡리 산6-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('호수 전망', '진양호 순환 자전거도로 대평면 구간에 위치한 전망 포인트입니다. 잔잔한 호수의 탁 트인 풍경을 감상하며 라이딩 중 잠시 쉬어가기 좋습니다.', '{viewpoint,lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.990595, 35.160627), 4326), false, '{"source": "KOMOOT", "source_ids": ["413", "689"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/17/1717siyzlo9fv13pzsvza0861b5c2wln9g-uhi84972762/0?width=1920&crop=false"], "category_raw": "viewpoint", "tour_count": 2, "nearby_landmarks": ["진양호"], "confidence": "high", "address": "대한민국 경상남도 진주시 대평면 내촌리 719-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('도개자전거쉼터', '낙동강 자전거길 도개면 구간에 위치한 수변 공원입니다. 탁 트인 강 전망과 함께 화장실 등 휴식 시설이 있어 라이딩 중 쉬어가기 좋습니다.', '{viewpoint,park,restroom,rest_area,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.331799, 36.296634), 4326), false, '{"source": "KOMOOT", "source_ids": ["611", "97"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/12/12svkw3f9vigi1veuu76zsqmtd4phgpnnk-uhi64910705/0?width=1920&crop=false"], "tips": [{"text": "park with toilets. maybe water source around", "author": "Alex Kasch"}], "category_raw": "viewpoint", "tour_count": 2, "nearby_landmarks": ["낙동강 자전거길", "도개자전거쉼터"], "confidence": "medium", "address": "대한민국 경상북도 구미시 도개면 궁기리 181-60"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('호티제', '전북 진안군 용담면 송풍리에 위치한 지점(고개 또는 저수지)으로, 자전거 라이더들의 투어 코스 웨이포인트 및 업힐 구간으로 활용되는 장소입니다.', '{checkpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.516011, 35.947788), 4326), false, '{"source": "KOMOOT", "source_ids": ["699", "1156"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["용담호", "송풍저수지"], "confidence": "medium", "address": "대한민국 전북특별자치도 진안군 용담면 송풍리 1312-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('홍대입구역 (경의선숲길)', '경의선 숲길과 이어져 있어 자전거 모임 장소로 인기가 많으며, 한강 자전거길로 진입하기 좋은 대중교통 거점입니다.', '{transit,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.925747, 37.558218), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/b/b1/Hongik-university-station-entrance-9-20181121-083316.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0d/239_Hongik_University_Line_2_platforms_20240630_101906.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/70/Hongik-university-station-entrance-8-20181121-083542.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/16/Hongik_univ_station_exit3_2006.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/ac/20250510_홍대입구역_3번출구.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 2, "nearby_landmarks": ["경의선숲길", "연트럴파크", "홍대걷고싶은거리"], "confidence": "high", "address": "대한민국 서울특별시 마포구 동교동 167-36"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('홍산교 - 삼천 - 구이', '전주 홍산교에서 시작해 삼천 천변 자전거길을 따라 구이저수지 방향으로 이어지는 약 20km의 쾌적한 라이딩 코스입니다.', '{river,bridge,lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.109829, 35.808668), 4326), false, '{"source": "KOMOOT", "source_ids": ["165", "52"], "tips": [{"text": "천변옆 자전거도로 이용, 1시간 정도(20km)", "author": "워닝샷"}], "category_raw": "cycle_way", "tour_count": 2, "nearby_landmarks": ["홍산교", "삼천 자전거길", "구이저수지", "모악산"], "confidence": "high", "address": "대한민국 전북특별자치도 전주시 완산구 효자동1가 719"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('황락저수지', '서산 가야산 자락에 위치한 아름다운 저수지입니다. 해미읍성, 일락사, 개심사 등과 연계하여 풍광을 즐기는 MTB 및 투어 라이딩 코스로 인기가 높습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.574064, 36.720285), 4326), false, '{"source": "KOMOOT", "source_ids": ["423", "451"], "category_raw": "190", "tour_count": 2, "nearby_landmarks": ["해미읍성", "일락사", "개심사", "가야산"], "confidence": "high", "address": "대한민국 충청남도 서산시 해미면 황락리 산67-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('2사단 지원여단', '평택 캠프 험프리스(미군기지) 내 제2보병사단 지원여단입니다. 일반 자전거 라이더는 출입할 수 없는 군사 보안구역이므로 안성천 자전거길 등으로 우회해야 합니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.987212, 36.977293), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["캠프 험프리스", "안성천 자전거길", "내리문화공원"], "confidence": "high", "address": "대한민국 경기도 평택시 팽성읍 도두리 82-13"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광주호 제4수원지', '무등산 산장이나 광주호로 향하는 길목에 위치한 저수지입니다. 울창한 숲 터널과 시원한 수변 경관을 자랑하여 라이더들에게 인기 있는 라이딩 명소입니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.961886, 35.161825), 4326), false, '{"source": "KOMOOT", "source_ids": ["877", "229"], "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["무등산", "청풍쉼터", "충장사"], "confidence": "high", "address": "대한민국 광주광역시 4수원지"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('굴포천 자전거길', '굴포천을 따라 경인아라뱃길로 이어지는 자전거길 구간입니다. 평탄한 강변 코스로 쾌적한 라이딩을 즐길 수 있습니다.', '{river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.759639, 37.533645), 4326), false, '{"source": "KOMOOT", "source_ids": ["188"], "category_raw": "river", "tour_count": 1, "nearby_landmarks": ["굴포천", "서운일반산업단지", "서운체육공원"], "confidence": "high", "address": "대한민국 인천광역시 계양구 서운동 121-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('보수동 책방골목', '부산의 명물 보수동 책방골목입니다. 좁은 골목에 헌책방이 밀집해 있어 자전거는 끌고 이동해야 하며, 레트로한 분위기를 즐기며 쉬어가기 좋습니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.026525, 35.103475), 4326), false, '{"source": "KOMOOT", "source_ids": ["294"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1x/1x3zufkjqtiv61faw4stcvgo34h1k71hp-uhi57607625/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1e/1epnawvalvxnbwiy38hj4xbap4h1k71l6-uhi57607626/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1k/1k7loqfag361j2mqld8a0ebq54h1k71lo-uhi57607627/0?width=1920&crop=false"], "category_raw": "other_man_made", "tour_count": 1, "nearby_landmarks": ["국제시장", "부평깡통시장", "용두산공원"], "confidence": "high", "address": "대한민국 부산광역시 중구 보수동1가 127-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('천부 해안 전망대', '울릉도 북면의 탁 트인 바다와 해안 절경을 조망할 수 있는 전망 포인트입니다. 자전거 일주 중 멋진 풍경을 배경으로 사진을 남기고 쉬어가기 좋습니다.', '{viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(130.912763, 37.541737), 4326), false, '{"source": "KOMOOT", "source_ids": ["243"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["천부항", "관음도", "삼선암"], "confidence": "medium", "address": "대한민국 경상북도 울릉군 북면 천부리 산2-30"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('안동역(구) 210번 버스 정류장', '하회마을로 향하는 210번 시내버스 탑승처입니다. 구 안동역(현 모디684) 인근에 위치해 대중교통 연계나 만남의 장소로 유용합니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.730741, 36.563194), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["구 안동역(모디684)", "안동구시장"], "confidence": "high", "address": "대한민국 경상북도 안동시 운흥동 234-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('CU 함안칠서점', '낙동강 종주 자전거길 함안 칠서면 구간에 위치한 편의점입니다. 남지철교를 건너기 전후로 식수와 간식을 보급하며 쉬어가기 좋은 포인트입니다.', '{convenience_store,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.488666, 35.383078), 4326), false, '{"source": "KOMOOT", "source_ids": ["345"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/jb/jbexwd8qbov2140m9nvh562gg4lnjmx03-uhi61005568/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 1, "nearby_landmarks": ["낙동강 자전거길", "남지철교", "남지교"], "confidence": "high", "address": "대한민국 경상남도 함안군 칠서면 계내리 251-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('커피냅로스터스 평택점', '진위천 자전거길 인근에 위치해 라이더들이 쉬어가기 좋은 빈티지 감성의 로스터리 카페입니다. 옛 양조장을 개조한 독특한 공간과 수백 년 된 보호수 느티나무가 매력적입니다.', '{cafe,rest_area,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.09001, 37.098724), 4326), false, '{"source": "KOMOOT", "source_ids": ["359"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1n/1n3vu5d6i5wnab0gy05kkbjoz5gzzh1y2-uhi91349390/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1s/1sapi1h4vl40lmf43xnsl5ctk5gzzh7f2-uhi91349391/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1t/1ty822utt6kw3afngho32il435gzzh7f2-uhi91349392/0?width=1920&crop=false"], "category_raw": "cafe", "tour_count": 1, "nearby_landmarks": ["진위천", "진위천유원지", "보호수(느티나무)"], "confidence": "high", "address": "대한민국 경기도 평택시 진위면 봉남리 181-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('DMC첨단산업센터', '상암동에 위치한 대형 오피스 건물입니다. 불광천 및 한강 자전거길과 인접해 있어 라이딩 중 위치를 파악하는 이정표 역할을 합니다.', '{landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.886417, 37.583942), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["불광천", "난지한강공원", "월드컵공원"], "confidence": "high", "address": "대한민국 서울특별시 DMC첨단산업센터"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오천그린광장', '순천 동천 자전거길과 인접한 풍덕동의 녹지 공간으로, 라이딩 중 휴식하며 경관을 즐기기 좋은 장소입니다.', '{park,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.500074, 34.933981), 4326), false, '{"source": "KOMOOT", "source_ids": ["89"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1s/1siv9mcfzum51s8exd7jeqnhd4xnphf0l-uhi70503274/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1f/1fxpsseo2mx5iab37wp7q1bdi4xnphgnw-uhi70503275/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1n/1nzskhpjzn5dqwareb958f1fc4xnphgny-uhi70503276/0?width=1920&crop=false"], "category_raw": "other_man_made", "tour_count": 1, "nearby_landmarks": ["순천 동천", "풍덕경관정원", "오천그린광장"], "confidence": "medium", "address": "대한민국 전라남도 순천시 풍덕동 676-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('양산 경민아파트', '양산시 물금읍에 위치한 아파트 단지로, 도심 구간 라이딩 시 길잡이나 일행과의 만남 장소로 활용하기 좋습니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.009761, 35.332638), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["양산천 자전거길", "남양산역", "양산부산대학교병원"], "confidence": "high", "address": "대한민국 양산시 경민아파트"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('LG디지털파크', '진위천 자전거길 인근에 위치한 대규모 산업단지(LG디지털파크)입니다. 라이딩 중 위치를 파악하기 좋은 거대한 랜드마크 역할을 합니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.090926, 37.127531), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["진위천", "진위역"], "confidence": "high", "address": "대한민국 평택시 LG전자"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('만송정 숲', '안동 하회마을 낙동강 변에 자리한 천연기념물 소나무 숲입니다. 시원한 그늘 아래서 강 건너 부용대 절경을 감상하며 라이딩 중 쉬어가기 좋은 명소입니다.', '{nature,rest_area,viewpoint,historic,landmark,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.515911, 36.54069), 4326), false, '{"source": "KOMOOT", "source_ids": ["666"], "category_raw": "191", "tour_count": 1, "nearby_landmarks": ["안동 하회마을", "부용대", "낙동강"], "confidence": "high", "address": "대한민국 경상북도 안동시 풍천면 하회리 693"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('마티고개', '대전·공주 지역 라이더들의 성지로 불리는 해발 203m 옛길 업힐 코스입니다. 터널 개통으로 차량 통행이 적어 안전하며, 정상에 매점과 화장실이 있어 휴식하기 좋습니다.', '{mountain,convenience_store,restroom,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.221437, 36.407116), 4326), false, '{"source": "KOMOOT", "source_ids": ["340"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/11/11ztvqwzw1stcbthgmlo902dg5blb07iu-uhi84519664/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1g/1gact93q13bac15jv3drkriogi5blb0c4o-uhi84519665/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1u/1uay4r9ke0vab1e8krkfwi5usr5blb0c4q-uhi84519666/0?width=1920&crop=false"], "category_raw": "mountain_pass", "tour_count": 1, "nearby_landmarks": ["마티터널", "청벽산", "마암뜰"], "confidence": "high", "address": "대한민국 충청남도 공주시 반포면 마암리 산45-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('평창 올림픽 환승주차장', '평창 동계올림픽 때 조성된 대규모 환승 주차장입니다. 부지가 넓고 대관령IC와 가까워 대관령, 안반데기 등 평창 일대 라이딩의 출발지로 활용하기 좋습니다.', '{parking,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.70662, 37.66631), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["대관령IC", "평창올림픽플라자"], "confidence": "high", "address": "대한민국 강원특별자치도 평창군 대관령면 횡계리 726-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('포항 효자 SK뷰 1차', '형산강 자전거길 바로 옆에 위치한 포항 효자동 아파트 단지입니다. 눈에 띄는 랜드마크로 라이더들의 만남의 장소나 코스 기준점으로 활용하기 좋습니다.', '{landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.334918, 36.007631), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["형산강 자전거길", "효자시장", "포항공과대학교"], "confidence": "high", "address": "대한민국 경상북도 포항시 남구 효자동 81-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('샘그레이커피', '용담저수지 인근의 한적한 브런치 카페로 라이딩 중 쉬어가기 좋습니다. 매주 일요일과 월요일은 휴무이므로 주말 라이딩 코스 계획 시 유의하세요.', '{cafe,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.300715, 37.174492), 4326), false, '{"source": "KOMOOT", "source_ids": ["1046"], "tips": [{"text": "Good coffee stop, nice brunch! Shut Sundays and Mondays though!!", "author": ""}], "category_raw": "cafe", "tour_count": 1, "nearby_landmarks": ["용담저수지", "용인농촌테마파크"], "confidence": "high", "address": "대한민국 경기도 용인시 처인구 원삼면 사암리 844-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('경주 신라대종', '경주 시내 대릉원 인근에 위치한 웅장한 종각입니다. 도심 자전거 투어 중 잠시 들러 사진을 찍고 쉬어가기 좋은 역사적 랜드마크입니다.', '{landmark,historic,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.21166, 35.840326), 4326), false, '{"source": "KOMOOT", "source_ids": ["783"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1t/1t1b412ntw8aehw4xxos358jz4m5xqxhd-uhi61574832/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/17/17w0m3w6uwjxn12ot6wnc0qk344m5xqzze-uhi61574835/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/14/14cenecxtv5ec1xpacvu2879fr5hyhcnb9-uhi92920284/0?width=1920&crop=false"], "category_raw": "man_made_monument", "tour_count": 1, "nearby_landmarks": ["대릉원", "봉황대", "황리단길", "첨성대"], "confidence": "high", "address": "대한민국 경상북도 경주시 노동동 1-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('해산전망대', '해산령 업힐 코스에 위치한 해산전망대입니다. 파로호의 멋진 전경을 감상하며 힘든 업힐 후 탁 트인 경치와 함께 쉬어가기 좋은 포인트입니다.', '{viewpoint,mountain,nature,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.82276, 38.187029), 4326), false, '{"source": "KOMOOT", "source_ids": ["569"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["해산령", "파로호", "평화의 댐", "화천 백립암복합체"], "confidence": "high", "address": "대한민국 강원특별자치도 화천군 화천읍 동촌리 산11-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼선암 전망대', '울릉순환로 라이딩 중 만나는 북면 해안 조망점입니다. 삼선암, 딴바위 등 울릉도의 웅장한 기암괴석과 바다 풍경을 감상하며 잠시 쉬어가기 좋습니다.', '{viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(130.906948, 37.548475), 4326), false, '{"source": "KOMOOT", "source_ids": ["277"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["삼선암", "딴바위", "천부해중전망대", "관음도"], "confidence": "medium", "address": "대한민국 경상북도 울릉군 북면 천부리 산5-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('Viewpoint', '진도 해안일주도로에 위치한 뷰포인트로 세방낙조 전망대와 가깝습니다. 다도해의 절경과 환상적인 일몰을 감상하며 라이딩 중 잠시 쉬어가기 좋은 장소입니다.', '{viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.10357, 34.440882), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["세방낙조 전망대", "진도해안일주도로"], "confidence": "high", "address": "대한민국 전라남도 진도군 지산면 가학리 산25-15"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('율하e편한세상 아파트', '김해 율하천 자전거길 인근에 위치한 아파트 단지입니다. 라이딩 중 위치를 파악하거나 코스의 출발 및 도착지로 삼기 좋은 랜드마크 역할을 합니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.819832, 35.171076), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["율하천", "율하카페거리", "조만강생태공원"], "confidence": "high", "address": "대한민국 김해시 율하e-편한"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('e편한세상15단지후문', '양주 옥정신도시 e편한세상 15단지 후문 및 버스정류장입니다. 인근에 선돌근린공원이 있어 도심 라이딩 중 위치를 확인하거나 가볍게 쉬어가기 좋습니다.', '{transit,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.083334, 37.816454), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["선돌근린공원", "옥정신도시"], "confidence": "high", "address": "대한민국 양주시 e편한세상15단지후문"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('海士ヶ瀬公園駐車場', '일본 굴지의 절경인 츠노시마 대교 진입 전 위치한 주차장 겸 공원입니다. 화장실과 자판기가 있어 라이딩 전후 휴식과 기념사진 촬영을 하기에 완벽한 체크포인트입니다.', '{parking,restroom,viewpoint,rest_area,park,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(130.896456, 34.348366), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["츠노시마 대교", "해사가세 공원 전망대"], "confidence": "high", "address": "3464 Hōhokuchō Ōaza Kanda, Shimonoseki, Yamaguchi 759-5331 일본"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('馬田溜池', '나가사키현 이키섬에 위치한 한적한 농업용 저수지입니다. 조용한 시골길을 따라 평화로운 자연 풍경을 감상하며 라이딩하기 좋은 지점입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.688046, 33.770426), 4326), false, '{"source": "KOMOOT", "source_ids": ["742"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["이도 저수지(井道溜池)", "야나기다 초등학교"], "confidence": "high", "address": "5 Gonouracho Hanseihonmurafure, Iki, Nagasaki 811-5111 일본"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('가곡천', '삼척 그란폰도 코스에 포함된 맑고 아름다운 하천입니다. 동해안 자전거길에서 내륙 산악 코스로 이어지는 길목으로, 경치가 뛰어나 라이딩하기 좋습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.307578, 37.151278), 4326), false, '{"source": "KOMOOT", "source_ids": ["1241"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["호산항", "동활계곡", "가곡유황온천"], "confidence": "high", "address": "대한민국 강원특별자치도 삼척시 원덕읍 노경리 647"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('중앙탑 하나로마트', '남한강 자전거길 중앙탑사적공원 인근의 농협 및 하나로마트입니다. 라이딩 중 식수와 간식을 보충하거나 화장실을 이용하기 좋습니다.', '{convenience_store,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.85905, 37.027122), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["중앙탑사적공원", "남한강 자전거길", "충주 탑평리 칠층석탑"], "confidence": "high", "address": "대한민국 충청북도 충주시 중앙탑면 탑평리 185-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('가락시장', '탄천 자전거길에서 접근하기 쉬운 대형 농수산물 도매시장으로, 라이딩 중 든든한 식사나 휴식을 취하기 좋은 장소입니다.', '{restaurant,restroom,parking,transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.11864, 37.492528), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/0/05/20240825_3호선_가락시장역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/55/Seoul-metro-Garak-market-station-entrance-1-20181124-162720.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e6/Seoul-metro-817-Garak-market-station-platform-20181124-162212.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9c/Seoul-metro-Garak-market-station-entrance-2-20181124-162604.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/04/817_가락시장.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["탄천 자전거길", "가락시장역"], "confidence": "high", "address": "대한민국 서울특별시 송파구 가락동 184-35"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('가산디지털단지역', '1호선과 7호선이 교차하는 대형 환승역입니다. 안양천 자전거길 진출입이 용이해 라이딩 기점이나 휴식 및 보급 장소로 활용하기 좋습니다.', '{transit,landmark,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.88339, 37.480607), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/7/70/Gasan_digital_complex_station_from_high.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f7/Gasan_digital_complex_station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/86/Seoul-metro-746-Gasan-digital-complex-station-sign-20191023-180708.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/26/Seoul-metro-746-Gasan-digital-complex-station-entrance-2-20191023-180146.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f7/20230531_가산디지털단지역_2번출구.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["안양천 자전거길", "마리오아울렛", "G밸리"], "confidence": "high", "address": "대한민국 서울특별시 금천구 벚꽃로 309 지하1층 지하24"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('가산못', '합천호와 합천댐 인근에 위치한 조용한 농촌 저수지입니다. 합천호 주변 라이딩 시 한적한 자연 풍경을 감상하며 지나가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.013066, 35.524698), 4326), false, '{"source": "KOMOOT", "source_ids": ["280"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["합천호", "합천댐", "악견산"], "confidence": "high", "address": "대한민국 경상남도 합천군 대병면 회양리 1427-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('가수원네거리', '갑천 자전거길과 인접한 대전 서구의 주요 교차로입니다. 장태산이나 방동저수지, 엑스포 광장 방면 라이딩의 주요 기점 및 경유지로 자주 활용됩니다.', '{checkpoint,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.354243, 36.305637), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["갑천 자전거길", "가수원교", "가수원 전통시장"], "confidence": "high", "address": "대한민국 대전광역시 가수원네거리"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('가야산', '영산강 자전거길과 만봉천 자전거길이 지나는 해발 190.5m의 산입니다. 앙암바위 부근 강변 데크길을 따라 달리기 좋으며, 탁 트인 나주평야와 강변 풍경을 감상할 수 있습니다.', '{mountain,viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.690832, 34.991683), 4326), false, '{"source": "KOMOOT", "source_ids": ["1887"], "category_raw": "191", "tour_count": 1, "nearby_landmarks": ["영산강 자전거길", "만봉천 자전거길", "앙암바위", "영천사"], "confidence": "high", "address": "대한민국 전라남도 나주시 운곡동 152-20"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('가야저수지', '김해 가야랜드 인근에 위치한 저수지로, 한적한 자연 경관을 즐기며 지나가기 좋은 라이딩 포인트입니다. 현재 생태휴식공원과 둘레길 조성이 추진되고 있습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.900338, 35.257299), 4326), false, '{"source": "KOMOOT", "source_ids": ["488"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["가야랜드", "가야테마파크", "신어산"], "confidence": "high", "address": "대한민국 경상남도 김해시 삼방동 806-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('가양역', '한강 자전거길과 인접한 9호선 가양역입니다. 주말 일반열차를 이용한 점프나 라이딩의 출발 및 종료 지점으로 활용하기 좋습니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.855111, 37.561157), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/50/20250508_가양역_급행_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e7/907_Gayang_01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b3/Gayang_Station_Line9_Exit_No.1.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/32/20250508_가양역_일반_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/46/907_Gayang_04.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["가양대교", "강서한강공원"], "confidence": "high", "address": "대한민국 서울특별시 강서구 가양동 14-84번지 가양역 지하1층"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('가오리역', '우이신설선 가오리역입니다. 경전철 특성상 일반 자전거 승차는 불가하지만(접이식 가능), 개방 화장실을 이용하거나 만남의 장소로 활용하기 좋습니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.016645, 37.641988), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/c/c3/Gaori.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["강북문화예술회관", "국립재활원", "수유중앙시장"], "confidence": "high", "address": "대한민국 서울특별시 강북구 수유동 338-46"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('가온마을2·3단지 정류장', '세종시 다정동 가온마을 2단지와 3단지 사이에 위치한 버스 정류장입니다. 라이딩 중 대중교통 연계나 위치 확인을 위한 기점으로 활용하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.241795, 36.496223), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["가온마을2단지", "가온마을3단지", "다정고등학교"], "confidence": "high", "address": "대한민국 세종특별자치시 가온마을2.3단지"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('가인저수지', '구만산과 북암산 사이 가인계곡에 위치한 조용한 계곡형 저수지입니다. 웅장한 제방과 영남알프스 산세를 감상하며 라이딩하기 좋습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.892332, 35.610131), 4326), false, '{"source": "KOMOOT", "source_ids": ["1540"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["구만산", "북암산", "가인계곡"], "confidence": "high", "address": "대한민국 경상남도 밀양시 산내면 가인리 산28-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('가천대', '탄천 자전거길과 인접해 접근성이 좋으나, 캠퍼스 내부는 경사가 매우 가파른 업힐로 유명합니다. 탄천 라이딩 시 주요 랜드마크나 지하철 점프 지점으로 활용됩니다.', '{landmark,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.126832, 37.448701), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/ko/d/d3/K223_%EA%B0%80%EC%B2%9C%EB%8C%80.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c3/Korail-Bundang-line-K223-Gachon-university-station-entrance-3-20181124-153536.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/24/Korail-Bundang-line-K223-Gachon-university-station-platform-20181124-152922.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d5/Korail-Bundang-line-K223-Gachon-university-station-entrance-2-20181124-153340.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8c/Korail-Bundang-line-K223-Gachon-university-station-sign-20181124-152900.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["탄천 자전거길", "가천대역"], "confidence": "high", "address": "대한민국 경기도 성남시 수정구 태평동 5113-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('가평천', '북한강 자전거길과 이어지는 맑고 아름다운 하천 코스입니다. 봄철 벚꽃 라이딩 명소로 유명하며, 계곡을 따라 여유롭게 달리기 좋습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.526751, 37.860409), 4326), false, '{"source": "KOMOOT", "source_ids": ["148"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["자라섬", "북한강 자전거길", "가평역"], "confidence": "high", "address": "대한민국 경기도 가평군 가평읍 당목가일길 90"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('갈매역', '경춘선 자전거길의 시작점 역할을 하는 전철역입니다. 대중교통 연계(점프)가 용이하며, 라이딩 출발 전 화장실과 편의시설을 이용하기 좋습니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.1145, 37.634005), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/db/Galmae_Station_20131228_111958.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a1/GalMaeDong_Sageori.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8b/Guri''s_GalMaeDong_Sageori.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/70/Galmae_Station_20131228_111528.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/45/Galmae_Station_20131228_111947.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["경춘선 자전거길", "갈매천"], "confidence": "high", "address": "대한민국 구리시 갈매역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('갈미봉', '울산 마골산, 무룡산 등과 이어지는 산악자전거(MTB) 코스에 위치한 330m 높이의 봉우리입니다. 숲길과 임도가 잘 조성되어 있어 오프로드 라이딩을 즐기기 좋습니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.401951, 35.564459), 4326), false, '{"source": "KOMOOT", "source_ids": ["613"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["마골산", "무룡산", "염포산", "찬물내기 약수터"], "confidence": "high", "address": "대한민국 울산광역시 북구 양정동 산33-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('갈산역', '인천 1호선 갈산역입니다. 주말 자전거 휴대 승차가 가능해 굴포천 자전거길과 아라뱃길로 향하는 라이딩 기점으로 유용하며, 역 출구에 자전거 보관소가 있습니다.', '{transit,parking,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.721509, 37.516813), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/7/7b/IRTC-Galsan_Station-Exit_no.3.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e6/Galsan_Station_2.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d9/Q491231_Galsan_A01.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["굴포천 자전거길", "갈산근린공원"], "confidence": "high", "address": "대한민국 인천광역시 갈산역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('갈치저수지', '수리산 자락에 위치한 고즈넉한 저수지입니다. 주변에 식당과 카페가 많아 라이딩 중 식사나 휴식을 취하기 좋습니다.', '{lake,nature,restaurant,cafe,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.905179, 37.333813), 4326), false, '{"source": "KOMOOT", "source_ids": ["91"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["수리산", "반월저수지", "수리산도립공원"], "confidence": "high", "address": "대한민국 경기도 군포시 속달동 산6-13"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('감천교', '창원 감천계곡과 광산사로 향하는 길목에 위치한 다리입니다. 경사가 완만하고 풍경이 수려해 자전거 라이딩 코스로 인기가 높습니다.', '{bridge,river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.509265, 35.210109), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["감천계곡", "광산사", "광려산"], "confidence": "high", "address": "대한민국 창원시 감천교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('갑천', '대전 도심을 가로지르는 갑천 수변의 쾌적한 자전거길입니다. 갑천역과 인접해 대중교통 연계가 편리하며, 평탄한 코스로 누구나 가볍게 라이딩하기 좋습니다.', '{river,transit,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.354529, 36.354571), 4326), false, '{"source": "KOMOOT", "source_ids": ["760", "295", "1327"], "image_urls": ["https://photos.komoot.de/wiki/commons/4/4b/Gapcheon_sta._nameplate.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6e/Gapcheon_sta._exit_3.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/55/Gapcheon_Station_exit_guide.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/93/DJET_Daejeon_Subway_Line_1_Gapcheon_Station.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["갑천역", "카이스트", "유림공원"], "confidence": "high", "address": "대한민국 대전광역시 갑천역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('강동역', '지하철 5호선 강동역입니다. 주말 및 공휴일에 자전거를 휴대하여 탑승할 수 있어 하남이나 한강 방면 라이딩 시 점프나 만남의 장소로 유용합니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.132527, 37.535726), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/a/a3/20230401_강동역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/53/20230401_강동역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/49/Seoul-metro-548-Gangdong-station-entrance-2-1-20180915-083334.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9d/Seoul-metro-548-Gangdong-station-entrance-1-20180915-083214.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0a/20200808_강동역_역명판.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["강동성심병원", "강풀만화거리", "천호대로"], "confidence": "high", "address": "대한민국 서울특별시 강동구 성내제2동 180-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('강정(해평버스정류장방면)', '구미 해평면 방향의 강정 버스정류장입니다. 낙동강 자전거길 인근에 위치하여 대중교통 연계나 가벼운 휴식처로 활용할 수 있습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.360594, 36.192426), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["낙동강 자전거길", "해평면"], "confidence": "high", "address": "대한민국 구미시 강정(해평버스정류장방면)"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('강진공용버스터미널 (전북 임실)', '섬진강 자전거길 종주 출발점(섬진강댐 인증센터)과 약 1.6km 떨어진 관문 터미널입니다. 전남 강진과 혼동하기 쉬워 버스 예매 시 ''전북강진''을 꼭 확인해야 합니다.', '{transit,restroom,convenience_store,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.160849, 35.529467), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["섬진강댐 인증센터", "섬진강 자전거길"], "confidence": "high", "address": "대한민국 임실군 강진터미널"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('강화여자중학교', '강화읍 갑곳리에 위치한 여자중학교입니다. 직접적인 편의시설은 없으나, 라이딩 중 위치를 가늠하는 랜드마크로 참고할 수 있습니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.494628, 37.743881), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["강화대교", "갑곳돈대", "강화여객자동차터미널"], "confidence": "high", "address": "대한민국 인천광역시 강화군 강화읍 갑곳리 177-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('개나리아파트 건너', '경주시 성건동 개나리아파트 맞은편에 위치한 버스 정류장입니다. 라이딩 중 대중교통 연계나 위치 확인용으로 활용할 수 있습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.208891, 35.850158), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["개나리아파트", "성건동"], "confidence": "high", "address": "대한민국 경주시 개나리아파트건너"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('개심저수지', '충북 옥천군 이원면에 위치한 수려한 경관의 저수지입니다. 지방도 501호선을 따라 자전거 도로와 데크 산책로가 조성되어 있어 쾌적한 라이딩과 휴식을 즐기기 좋습니다.', '{lake,nature,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.628348, 36.198134), 4326), false, '{"source": "KOMOOT", "source_ids": ["1357"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["대성산", "천태산", "송학헌 시혜비"], "confidence": "high", "address": "대한민국 충청북도 옥천군 이원면 개심리 479-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('거제경찰서', '거제시 옥포동에 위치한 경찰서로, 라이딩 중 긴급 상황 시 도움을 받을 수 있는 치안 거점입니다. 자전거 출퇴근자를 위한 안전 캠페인이 자주 열리는 곳이기도 합니다.', '{police}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.686816, 34.897609), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["옥포항", "한화오션 거제사업장"], "confidence": "high", "address": "대한민국 거제시 거제경찰서"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('거제소방서', '거제 옥포동에 위치한 소방서로, 라이딩 중 응급 상황 발생 시 도움을 요청할 수 있는 안전 거점입니다. 남파랑길 21코스 등 거제 투어 시 주요 길잡이가 됩니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.686079, 34.895264), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["옥포항", "옥포조각공원"], "confidence": "high", "address": "대한민국 거제시 거제소방서"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('건국지구대', '광주 북구 본촌동에 위치한 경찰 지구대입니다. 라이딩 중 긴급 상황 시 도움을 요청하거나 야간에도 안전하게 머물 수 있는 치안 거점입니다.', '{police}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.878746, 35.219201), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["양산호수공원", "본촌일반산업단지"], "confidence": "high", "address": "대한민국 광주광역시 건국지구대"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('검섬산', '경남 사천에 위치한 해발 55.3m의 아주 낮은 야산입니다. 중턱까지 포장길이 이어져 있어 주변 해안도로 라이딩 시 가벼운 업힐로 연계하기 좋습니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.980032, 34.98514), 4326), false, '{"source": "KOMOOT", "source_ids": ["373"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["비토섬", "사천만"], "confidence": "high", "address": "대한민국 경상남도 사천시 서포면 선전리 산16-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('경산역', '무궁화호와 일부 KTX가 정차하는 경산역입니다. 남천 자전거길과 가까워 대중교통 점프 및 라이딩 거점으로 활용하기 좋습니다.', '{transit,restroom,convenience_store,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.727186, 35.819166), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/3/3f/경산역_전경4.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c8/경산역_전경2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/dc/경산역_내부.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/5f/경산역_내부2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e2/경산역_전경3.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["남천", "남천 자전거길"], "confidence": "high", "address": "대한민국 경상북도 경산시 사정동 99-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('보문관광단지 (경상북도문화관광공사)', '경주 보문관광단지 중심에 위치한 공공기관입니다. 보문호 주변 자전거 코스를 즐길 때 길잡이가 되는 주요 랜드마크이자 출발점으로 삼기 좋습니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.287615, 35.844046), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["보문관광단지", "보문호", "경주월드"], "confidence": "high", "address": "대한민국 경상북도 경주시 신평동 417-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('경성대·부경대역', '부산 2호선 지하철역이자 번화한 대학가로 식당과 카페가 많아 보급과 휴식에 좋습니다. 역 출구 인근에 자전거 보관소와 공기주입기가 있어 정비 및 대중교통 연계가 편리합니다.', '{transit,convenience_store,cafe,restaurant,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.100515, 35.137581), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/9/99/Busan-subway-212-Kyungsung-univ-Pukyong-natl-univ-station-1-entrance.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/eb/Kyungsung_Univ_Pukyong_Nat''l_Univ_Station_2010.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/ce/212kyungsunguniv.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/fd/212kyungsunguniv2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/38/Busan_subway_Kyungsung_Univ._and_Pukyong_Nat''l_Univ._station_1.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["경성대학교", "부경대학교", "이기대 수변공원", "UN기념공원"], "confidence": "high", "address": "대한민국 부산광역시 대연동 경성대.부경대"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('경안천', '경기도 광주와 용인을 잇는 경안천 자전거길 구간입니다. 한적하고 자연 경관이 뛰어나 쾌적한 라이딩을 즐길 수 있는 하천길입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.238521, 37.362387), 4326), false, '{"source": "KOMOOT", "source_ids": ["41", "72", "288", "87", "79", "353", "361", "467", "354"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["오포생활체육공원", "경안천 자전거길"], "confidence": "high", "address": "대한민국 경기도 광주시 오포읍 추자리 145-42"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('경주 국립공원', '블루원 리조트 인근에 위치한 경주 국립공원 구역입니다. 수려한 자연 경관을 즐기며 라이딩하기 좋으나, 산악 지형 특성상 업힐 코스에 대비해야 합니다.', '{mountain,nature,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.29068, 35.820721), 4326), false, '{"source": "KOMOOT", "source_ids": ["242"], "image_urls": ["https://photos.komoot.de/wiki/commons/1/19/경주국립공원.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/75/Anapji_Pond_2.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6f/Anapji_Pond-Gyeongju-Korea-2006-07.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f9/Gyeongju_NP_-_from_Tohamsan_MT.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/92/Bulguk_Tempel.jpg?width=1920&crop=false"], "category_raw": "2", "tour_count": 1, "nearby_landmarks": ["블루원 리조트", "보문관광단지", "경주엑스포대공원"], "confidence": "high", "address": "대한민국 경상북도 경주시 천군동 산100-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('경주 풍력발전소', '고된 업힐 끝에 거대한 풍력발전기와 탁 트인 절경을 만날 수 있는 힐클라임 명소입니다. 매점이나 식수대가 없으므로 마실 물을 충분히 준비해야 합니다.', '{viewpoint,mountain,landmark,rest_area,parking,restroom,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.36377, 35.750421), 4326), false, '{"source": "KOMOOT", "source_ids": ["358"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/7l/7lagsfkmqqwy1nrd9zd3khj3v49qbjlgk-uhi53028309/0?width=1920&crop=false"], "tips": [{"text": "A rewarding view after a challenging mountain course. Bring extra water, as there''s nowhere to refill.", "author": "Pól"}], "category_raw": "other_man_made", "tour_count": 1, "nearby_landmarks": ["토함산", "불국사", "석굴암", "조항산"], "confidence": "high", "address": "대한민국 경상북도 경주시 문무대왕면 장항리 산599-25"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('경찰병원', '라이딩 중 응급 상황 시 대처가 가능한 대형 종합병원입니다. 3호선 경찰병원역과 인접해 대중교통 점프나 길 찾기 랜드마크로 유용합니다.', '{hospital,landmark,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.123892, 37.495408), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/e/ee/351_경찰병원.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2a/Seoul_subway_national_police_hospital_station_exit_1.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c5/Seoul-metro-351-National-police-hospital-station-platform-20181124-163422.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/67/Seoul-metro-351-National-police-hospital-station-entrance-2-20181124-164122.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0b/경찰병원역_사거리.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["경찰병원역", "가락시장", "오금공원"], "confidence": "high", "address": "대한민국 서울특별시 송파구 가락동 58-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('경치 좋은 해안 항구', '청산도 슬로길 해안가에 위치한 뷰포인트입니다. 푸른 바다와 어우러진 도청항 일대의 고즈넉한 항구 풍경을 감상하며 라이딩하기 좋습니다.', '{viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.861377, 34.173285), 4326), false, '{"source": "KOMOOT", "source_ids": ["55"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/cz/cz53tuc7250dctgdtoqjn1ib5db1nuzg-uhi86480494/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/s3/s3xfyesx177rl4cvbj3qdvwz5db1nvnl-uhi86480495/0?width=1920&crop=false"], "category_raw": "viewpoint", "tour_count": 1, "nearby_landmarks": ["도청항", "청산도 슬로길", "서편제 촬영지"], "confidence": "medium", "address": "대한민국 전라남도 완도군 청산면 당락리 649"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('경포해수욕장', '동해안 자전거길의 주요 경유지로, 탁 트인 동해 바다를 감상하며 재정비하고 쉬어가기 좋은 대표적인 해변입니다.', '{beach,viewpoint,rest_area,landmark,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.909515, 37.803286), 4326), false, '{"source": "KOMOOT", "source_ids": ["28"], "image_urls": ["https://photos.komoot.de/wiki/commons/d/d5/Gyeongpo_Beach_3.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f5/Gyeongpo_Beach_2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b9/Gyeongpo_Beach_1.jpg?width=1920&crop=false"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["경포호", "경포대", "강문해변"], "confidence": "high", "address": "대한민국 강원특별자치도 강릉시 강문동 산4-16"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('계룡고등학교', '계룡시 두마면에 위치한 고등학교로, 라이딩 시 길 찾기의 기준점이 되는 랜드마크입니다. 인근 농소천을 따라 가벼운 라이딩 코스를 계획하기 좋습니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.257615, 36.26747), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["농소천", "계룡대실지구"], "confidence": "high", "address": "대한민국 충청남도 계룡시 두마면 서금암로 89"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('계백장군 조각상', '탑정호 광장에 위치한 계백장군 조각상입니다. 탑정호 둘레길 라이딩 중 잠시 쉬며 호수와 출렁다리를 배경으로 기념사진을 남기기 좋은 랜드마크입니다.', '{landmark,historic,park,rest_area,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.148871, 36.175925), 4326), false, '{"source": "KOMOOT", "source_ids": ["742"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/11/11i4ohvsn257v1o0w3yr91fe4q3xfzxrbr-uhi42419906/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/8a/8a7lmczv5o9514vr5grubwwku3xfzxrc2-uhi42419907/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/ci/ciugondsfomyt0pil6zb2iwd5jnt1uj7-uhi95145992/0?width=1920&crop=false"], "category_raw": "man_made_monument", "tour_count": 1, "nearby_landmarks": ["탑정호 광장", "탑정호 출렁다리", "탑정호 제방"], "confidence": "high", "address": "대한민국 충청남도 논산시 가야곡면 탑정로 773-38"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('계전리주유소', '여주와 양평 경계 부근에 위치한 주유소 겸 버스 정류장입니다. 국도 라이딩 중 위치를 확인하거나 잠시 쉬어가는 웨이포인트로 참고할 수 있습니다.', '{transit,rest_area,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.573073, 37.412506), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["계전2리 정류장", "송촌초등학교"], "confidence": "high", "address": "대한민국 여주시 계전2리"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('고기리 라이딩 거점', '탄천에서 접근하기 좋은 수도권 인기 라이딩 스팟입니다. 여우고개와 말구리고개를 넘는 로드 업힐 코스와 주변 산악 MTB 코스로 유명합니다.', '{checkpoint,nature,restaurant,cafe}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.061971, 37.360232), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["여우고개", "말구리고개", "고기리계곡", "광교산"], "confidence": "high", "address": "대한민국 용인시 고기동마을"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('고기초등학교', '수지구 고기동에 위치한 초등학교로, 자전거 동호인들이 즐겨 찾는 고기리 코스(말구리재 등) 라이딩 시 주요 이정표 역할을 합니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.067003, 37.359081), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["고기리계곡", "말구리재", "고기교"], "confidence": "high", "address": "대한민국 용인시 고기초등학교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('고덕역', '지하철 5호선 고덕역으로, 고덕천을 거쳐 한강 자전거길로 진입하거나 점프(대중교통 연계)하기 좋은 지점입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.153773, 37.55499), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/52/Seoul-metro-552-Godeok-station-sign-20180914-123520.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/45/Seoul-metro-552-Godeok-station-entrance-4-20180914-124006.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6a/고덕역.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/65/고덕역_야외.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/46/고덕역_1번출구.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["고덕천", "고덕수변생태공원", "이마트 고덕점"], "confidence": "high", "address": "대한민국 서울특별시 고덕역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('다부동 328고지', '한국전쟁 다부동 전투의 격전지였던 328고지입니다. 현재는 칠곡군 산악자전거(MTB) 대회 코스 및 임도 라이딩 명소로 유명합니다.', '{mountain,historic,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.417593, 36.003829), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["칠곡호국평화기념관", "작오산", "도개온천"], "confidence": "high", "address": "대한민국 칠곡군 고지"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('고촌역', '김포골드라인 지하철역입니다. 일반 자전거는 승차가 제한되나 접이식 자전거 점프나 라이딩 모임 장소로 활용할 수 있는 교통 거점입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.770231, 37.601273), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["고촌읍행정복지센터", "고촌근린공원"], "confidence": "high", "address": "대한민국 경기도 김포시 고촌읍 신곡리 532-16"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('고흥 우주발사전망대', '고흥 해안도로 라이딩 코스의 주요 랜드마크입니다. 탁 트인 다도해 조망이 가능하며, 7층 회전 카페와 화장실 등 편의시설을 갖춰 업힐 후 쉬어가기 좋습니다.', '{viewpoint,landmark,cafe,rest_area,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.488561, 34.587158), 4326), false, '{"source": "KOMOOT", "source_ids": ["946"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/se/selmqjnxdfqp1a5e97zynd6833y6mniad-uhi43345646/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/r3/r3v8o2vr6vd35j9bpw08vk5u3y6mnl9b-uhi43345648/0?width=1920&crop=false"], "category_raw": "man_made_monument", "tour_count": 1, "nearby_landmarks": ["남열해돋이해수욕장", "용바위"], "confidence": "high", "address": "대한민국 전라남도 고흥군 영남면 남열리 77-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('침실습지 전망대', '섬진강 종주 자전거길이 지나는 침실습지 인근입니다. 이른 아침 물안개와 버드나무 절경이 뛰어나 라이딩 중 잠시 멈춰 경치를 감상하며 쉬어가기 좋은 생태 명소입니다.', '{nature,river,viewpoint,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.304795, 35.283217), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["침실습지", "섬진강 자전거길", "퐁퐁다리", "섬진강기차마을"], "confidence": "high", "address": "대한민국 전라남도 곡성군 오곡면 오지리 1418-82"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('이즈미 해안 전망대', '대마도 182번 지방도에 위치한 해안 전망 포인트입니다. ''골프장''은 ''Gulf(만)''의 번역 오류로 보이며, 탁 트인 바다 절경을 감상하며 쉬어가기 좋은 라이딩 코스입니다.', '{viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.469879, 34.684415), 4326), false, '{"source": "KOMOOT", "source_ids": ["247"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1i/1ih1hbzhxp8luy2vy6a03qeof51ljfutb-uhi74971472/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/16/16vyeua5sie959kypzx2s4zns51ljg1xm-uhi74971473/0?width=1920&crop=false"], "category_raw": "viewpoint", "tour_count": 1, "nearby_landmarks": ["미우다 해수욕장", "슬로스 글램핑"], "confidence": "high", "address": "일본 〒817-1725 Nagasaki, Tsushima, Kamitsushimamachiizumi, 県道182号"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('공단입구', '순천일반산업단지 진입로 지점입니다. 동천 자전거길과 인접해 있어 라이딩 중 위치를 확인하거나 코스를 연계하는 기점으로 활용하기 좋습니다.', '{checkpoint,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.502747, 34.982956), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["순천일반산업단지", "동천 자전거길"], "confidence": "high", "address": "대한민국 순천시 공단입구"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('공릉천', '고양시 관산동을 흐르는 공릉천 자전거길입니다. 길이 평탄하고 쾌적하여 철새 등 자연 경관을 감상하며 여유롭게 라이딩하기 좋습니다.', '{river,park,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.863953, 37.685468), 4326), false, '{"source": "KOMOOT", "source_ids": ["543"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["공릉천문화체육공원", "벽제교"], "confidence": "high", "address": "대한민국 경기도 고양시 덕양구 관산동 193-24"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('공적비', '홍천군 내면 창촌리에 위치한 공적비입니다. 구룡령이나 운두령 라이딩 코스 길목 시내에 있어, 보급이나 휴식 중 잠시 둘러보기 좋은 역사적 랜드마크입니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.3912, 37.775422), 4326), false, '{"source": "KOMOOT", "source_ids": ["546"], "category_raw": "32", "tour_count": 1, "nearby_landmarks": ["창촌삼거리", "내면시외버스터미널", "구룡령", "운두령"], "confidence": "medium", "address": "대한민국 강원특별자치도 홍천군 내면 창촌리 1570-13"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('공항화물청사역', '영종도, 신시모도 등 섬 라이딩의 주요 출발지이자 도착지로 활용되는 공항철도역입니다. 화장실과 편의점이 있어 보급과 휴식에 좋습니다.', '{transit,convenience_store,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.477618, 37.458889), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/d1/AREX-Incheon_Intl_Airport_Cargo_Terminal_Station-Exit_1.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/ab/AREX-Incheon_International_Airport_Cargo_Terminal_Stn-Exterior-2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/25/AREX-Incheon_International_Airport_Cargo_Terminal_Stn-Exit_1-Sign.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e8/A09_Cargo_Terminal_Station_Sign.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/34/AREX-Incheon_Intl_Airport_Cargo_Terminal_Station-Platform.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["인천국제공항 화물청사", "삼목항", "영종도 자전거길", "하늘정원"], "confidence": "high", "address": "대한민국 인천광역시 공항화물청사"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('과천', '서울 양재천과 안양 인덕원을 잇는 주요 라이딩 거점입니다. 자전거 도로가 잘 정비되어 있으며, 인근에 공영자전거 대여소와 지하철역이 있어 접근성이 좋습니다.', '{transit,landmark,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.996904, 37.433106), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/a/ac/Q498095_Gwacheon_A01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bb/2014-05-12_IMG_7455_최광모.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a8/Gwacheon_Station_3.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c5/20150319과천역_출구75.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["과천역", "과천 중앙공원", "경기과천교육도서관", "양재천"], "confidence": "high", "address": "대한민국 경기도 과천시 별양동 2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('곽지해수욕장', '제주 환상자전거길 서쪽 코스의 주요 경유지입니다. 에메랄드빛 바다와 과물노천탕을 감상하며 라이딩 중 시원하게 휴식하기 좋은 해변입니다.', '{beach,rest_area,viewpoint,restroom,convenience_store,cafe,restaurant,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.307493, 33.4484), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["과물노천탕", "한담해안산책로", "애월카페거리"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 애월읍 곽지리 1668-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('중문관광단지 입구', '제주 남부 라이딩 중 중문관광단지로 진입하는 주요 교차로이자 관문입니다. 천제연폭포, 여미지식물원 등 다양한 관광 명소와 숙박시설로 연결됩니다.', '{checkpoint,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.41464, 33.256243), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["중문관광단지", "천제연폭포", "여미지식물원", "테디베어뮤지엄"], "confidence": "high", "address": "대한민국 서귀포시 관광단지 입구"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('관성솔밭해변', '울산과 경주를 잇는 해안 자전거길에 위치한 아름다운 솔밭 해변입니다. 화장실, 매점 등 편의시설이 잘 갖춰져 있어 라이딩 중 바다를 보며 휴식하기 좋습니다.', '{beach,nature,rest_area,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.451142, 35.661009), 4326), false, '{"source": "KOMOOT", "source_ids": ["472"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["하서해안공원", "양남 주상절리 전망대"], "confidence": "high", "address": "대한민국 경상북도 경주시 양남면 수렴리 429-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광곡역 폐역', '보성군 노동면에 위치한 경전선 폐역(광곡역)입니다. 현재 기차는 서지 않지만, 한적한 시골길 라이딩 중 옛 간이역의 정취를 감상하며 잠시 쉬어가기 좋습니다.', '{transit,historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.072954, 34.796398), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["보성강", "명봉역"], "confidence": "high", "address": "대한민국 보성군 광화"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광교중앙역 환승센터', '신분당선과 광역버스를 이용할 수 있는 대규모 환승센터입니다. 역 주변에 공유 자전거 지정 주차 구역이 있으며, 광교호수공원 등 주변 라이딩 코스로 진입하기 좋습니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.051465, 37.288494), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/8/88/Gwanggyo_Jungang_Station_Main_Hall.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/64/Q21025132_Gwanggyo_Jungang_A01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f1/Gwanggyo_Jungang_Station_Exit_1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3d/Suwon_Bus_32-3.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/44/Gwanggyo_Jungang_Bus_Station.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["경기도청", "광교호수공원", "아주대학교"], "confidence": "high", "address": "대한민국 수원시 광교중앙.경기도청.아주대역환승센터"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광나루역', '수도권 전철 5호선 광나루역입니다. 한강 자전거길 및 광나루 자전거공원 진입이 수월하여 라이더들이 대중교통 연계(점프) 및 만남의 장소로 자주 이용합니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.103492, 37.545237), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/4/40/Seoul-metro-546-Gwangnaru-station-platform-20180914-112002.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d0/Seoul-metro-546-Gwangnaru-station-sign-20180914-111930.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e4/Seoul-metro-546-Gwangnaru-station-entrance-4-20180914-112816.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bd/546_광나루.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["광나루 한강공원", "광나루 자전거공원", "광진교"], "confidence": "high", "address": "대한민국 서울특별시 광진구 아차산로 지하 571"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광동호', '백두대간 댓재와 건의령 사이를 지나는 라이딩 코스에 위치한 인공 호수입니다. 태백과 삼척을 오가는 라이더들에게 탁 트인 수변 풍경을 선사합니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.956562, 37.340529), 4326), false, '{"source": "KOMOOT", "source_ids": ["199"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["광동댐", "댓재", "건의령"], "confidence": "high", "address": "대한민국 강원특별자치도 삼척시 하장면 숙암리 209-143"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광령천', '제주환상자전거길 북부 해안 코스에서 만나는 하천입니다. 한라산에서 발원해 바다로 흘러가며, 탁 트인 자연 경관을 감상하며 라이딩하기 좋습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.435616, 33.49185), 4326), false, '{"source": "KOMOOT", "source_ids": ["354"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["제주환상자전거길", "월대천", "내도동 알작지", "외도포구"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 내도동 894-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광명동 팽나무', '350년 수령의 보호수로 고란마을을 지키는 당산나무입니다. 나무 그늘 아래 정비가 잘 되어 있어 라이딩 중 고즈넉하게 쉬어가기 좋은 자연 랜드마크입니다.', '{nature,historic,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.139752, 35.827915), 4326), false, '{"source": "KOMOOT", "source_ids": ["76"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["고란마을", "명주봉"], "confidence": "high", "address": "대한민국 경상북도 경주시 광명동 1400-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광석골소류지', '진해 드림파크와 생태숲 내에 위치한 작은 저수지입니다. 진해 드림로드 라이딩 중 수변 데크길을 따라 자연 경관을 감상하며 쉬어가기 좋습니다.', '{lake,park,nature,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.718062, 35.13228), 4326), false, '{"source": "KOMOOT", "source_ids": ["53"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["진해 드림파크", "진해만 생태숲", "진해 목재문화체험장", "진해 드림로드"], "confidence": "high", "address": "대한민국 경상남도 창원시 진해구 장천동 20-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광안역', '부산 지하철 2호선 광안역입니다. 광안리 해수욕장과 수영강 자전거길로 진입하기 좋은 대중교통 점프 및 만남의 장소로 유용합니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.113208, 35.157911), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/f/fe/Gwangan_Station6.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/75/Gwangan_station_sign_20180317_215155.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/01/209gwangan2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3f/Busan_subway_gwangan_station_1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f6/Busan-subway-209-GwangAn-station-platform.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["광안리 해수욕장", "광안대교"], "confidence": "high", "address": "대한민국 부산광역시 광안역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광안대교', '자전거 진입이 불가한 자동차 전용도로(특별 행사 제외)입니다. 광안리 해변이나 수영강 자전거길에서 화려한 야경을 감상하기 좋은 부산의 대표 랜드마크입니다.', '{bridge,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.11148, 35.135712), 4326), false, '{"source": "KOMOOT", "source_ids": ["283"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/zs/zsl3y3t4svej1c9w4x7c8g8u74ek7zwsh-uhi56694895/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/4i/4ibuv0kxw0gjqyl95ywlwa6s4ek7zy6b-uhi56694897/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1g/1g2101e26nbmj13mj58dwdyk704ek7zy24-uhi56694896/0?width=1920&crop=false"], "tips": [{"text": "Die gigantische Brücke wird abends toll beleuchtet. Man kann sich dann am Strand hinsetzen und zuschauen.", "author": "Wanderschnecke"}], "category_raw": "bridge", "tour_count": 1, "nearby_landmarks": ["광안리해수욕장", "민락수변공원", "마린시티"], "confidence": "high", "address": "대한민국 부산광역시 수영구 남천동 545-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광암주유소', '남양주 화도읍 차산리에 위치한 주유소입니다. 라이딩 중 화장실을 이용하거나 식수를 보충하며 잠시 쉬어가기 좋은 웨이포인트입니다.', '{rest_area,restroom,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.303249, 37.635775), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["차산교회", "차산초등학교"], "confidence": "high", "address": "대한민국 경기도 남양주시 화도읍 차산리 77-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광장시장', '빈대떡, 육회 등 먹거리가 풍부한 서울의 대표 전통시장입니다. 청계천을 따라 라이딩하다가 든든하게 배를 채우며 쉬어가기 좋습니다.', '{restaurant,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.001232, 37.570021), 4326), false, '{"source": "KOMOOT", "source_ids": ["9"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/gc/gcq98xsj72ny1wy3fqy5d13b4rhbg5bd-uhi66863305/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1t/1tzkwr18qr3rc1qb0pwjtaqws33zc23m9a-uhi44536979/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/rh/rhylpfe8ktxsltzud9k9ckus45qaw68w-uhi49273572/0?width=1920&crop=false"], "tips": [{"text": "Genialer Street Food Market", "author": "Andre - Mindblow-africa"}], "category_raw": "other_man_made", "tour_count": 1, "nearby_landmarks": ["청계천", "종묘", "동대문"], "confidence": "high", "address": "대한민국 서울특별시 종로구 종로1.2.3.4가동 395-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광주역', '자전거 점프(대중교통 연계) 및 라이딩 출발·도착지로 활용하기 좋은 광주역입니다. 도심 속 자전거 산책로인 ''푸른길공원''이 시작되는 주요 거점입니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.909767, 35.165996), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/f/ff/Gwangju_Station_Front.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/51/구_전남광주역사.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/91/전남광주역_신역사_홈에서_바라본_모습.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/77/Gwangju_Station_Interior.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/ad/광주(1931)(10000-1)_(cropped).jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["푸른길공원"], "confidence": "high", "address": "대한민국 광주광역시 북구 중흥동 611-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('교대역', '부산 1호선과 동해선 환승역인 교대역입니다. 온천천 자전거길과 인접해 라이딩 진출입이 편리하며, 출구 곳곳에 자전거 보관소가 마련되어 있습니다.', '{transit,parking,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.080068, 35.195217), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/a/a0/Busan-subway-124-Busan-natl-univ-of-edu-station-3-entrance.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/96/124busannatluniv2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/ko/b/b4/BNEStation124BSMetro.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e3/124busannatlunivofedu.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/cc/124busannatlunivofedu2.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["온천천", "부산교육대학교"], "confidence": "high", "address": "대한민국 부산광역시 연제구 거제동 69-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('교동저수지', '옥천 향수 100리 자전거길에 위치한 벚꽃 명소 저수지입니다. 수변 데크길이 잘 조성되어 있으며, 인근 대형 카페와 벤치에서 라이딩 중 휴식하기 좋습니다.', '{lake,nature,park,rest_area,cafe,parking,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.586043, 36.320305), 4326), false, '{"source": "KOMOOT", "source_ids": ["63"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["지용문학공원", "정지용 생가", "육영수 생가", "옥천전통문화체험관"], "confidence": "high", "address": "대한민국 충청북도 옥천군 옥천읍 교동리 175-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('청풍호 만남의 광장', '청풍호(충주호) 라이딩 코스의 주요 경유지이며, 인근에 만남의 광장과 청풍랜드가 위치해 휴식과 보급이 가능한 장소입니다.', '{checkpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.181286, 37.017948), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["청풍호 만남의 광장", "청풍랜드", "교리교차로"], "confidence": "high", "address": "대한민국 충청북도 제천시 청풍면 교리 26-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('교평2리.서라우', '남한강 자전거길 인근 양평군 강상면에 위치한 버스 정류장입니다. 라이딩 중 위치 기준점이나 대중교통 연계 시 참고할 수 있습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.487963, 37.46633), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["남한강 자전거길", "남한강", "강상체육공원"], "confidence": "high", "address": "대한민국 경기도 양평군 강상면 교평리 64-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('보령문화의전당', '구 장항선 대천역 부지를 개조한 보령문화의전당입니다. 철길사계공원이 함께 있어 라이딩 중 자전거를 세우고 화장실 이용 및 휴식을 취하기 좋은 랜드마크입니다.', '{historic,landmark,museum,park,rest_area,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.591421, 36.34991), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["보령문화의전당", "보령박물관", "철길사계공원", "대천천"], "confidence": "high", "address": "대한민국 보령시 대천동 340-2번지 보령시 충청남도 KR"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구 안동역 건너', '구 안동역 맞은편에 위치한 버스 정류장입니다. 안동 시내 중심가에 있어 자전거 종주 전후로 식사나 숙박, 보급을 해결하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.734314, 36.563387), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["구 안동역(폐역)", "안동 문화의거리", "웅부공원"], "confidence": "high", "address": "대한민국 경상북도 안동시 운흥동 188-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('춘포역사전시관', '만경강 자전거길 인근에 있는 우리나라에서 가장 오래된 간이역입니다. 일제강점기의 역사를 간직한 작은 박물관으로, 라이딩 중 쉬어가며 둘러보기 좋습니다.', '{historic,landmark,museum,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.004777, 35.903674), 4326), false, '{"source": "KOMOOT", "source_ids": ["379"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1c/1coiu0p8lgvf9c9zlpua2unim43xjwc9h-uhi47712525/0?width=1920&crop=false"], "category_raw": "historical_site", "tour_count": 1, "nearby_landmarks": ["만경강 자전거길", "대장도정공장", "호소카와 농장 가옥"], "confidence": "high", "address": "대한민국 전북특별자치도 익산시 춘포면 덕실리 481-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구능내역.마재성지', '남한강 자전거길의 주요 거점인 능내역(폐역) 앞 버스정류장입니다. 주변에 마재성지와 자전거 쉼터, 식당, 카페가 많아 보급과 휴식을 취하기 좋습니다.', '{transit,rest_area,historic,cafe,restaurant,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.295476, 37.523544), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["능내역(폐역)", "마재성지", "남한강 자전거길", "다산생태공원"], "confidence": "high", "address": "대한민국 경기도 남양주시 조안면 능내리 139-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구룡포 해수욕장', '동해안 자전거길 코스에 위치한 한적하고 아름다운 해변입니다. 탁 트인 바다 풍경을 감상하며 라이딩 중 잠시 쉬어가기 좋습니다.', '{beach,viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.566481, 35.997194), 4326), false, '{"source": "KOMOOT", "source_ids": ["556"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["구룡포항", "구룡포 일본인가옥거리", "구룡포 주상절리"], "confidence": "high", "address": "대한민국 경상북도 포항시 남구 구룡포읍 호미로426번길 6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구미역 후면광장', '경부선 구미역 후면광장입니다. 자전거 보관소, 화장실, 편의점 등 편의시설이 있어 라이딩 출발·도착 및 대중교통 연계(점프) 거점으로 활용하기 좋습니다.', '{transit,parking,restroom,convenience_store,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.33077, 36.127862), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/b/bc/Gumistation.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["구미역", "금오산", "금오천", "구미새마을중앙시장"], "confidence": "high", "address": "대한민국 경상북도 구미시 원평동 1008-125"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구미보건너', '낙동강 자전거길 구미보 인근에 위치한 버스 정류장입니다. 구미보 인증센터와 가까워 라이딩 중 위치를 파악하거나 비상시 대중교통 연계 지점으로 참고할 수 있습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.354411, 36.231558), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["구미보", "구미보 인증센터", "낙동강 자전거길"], "confidence": "high", "address": "대한민국 구미시 구미보"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구미천', '구미시를 관통해 낙동강으로 흐르는 하천입니다. 하천을 따라 자전거길이 조성되어 있으며, 낙동강 자전거길과 바로 연결되어 라이딩하기 좋습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.359514, 36.127515), 4326), false, '{"source": "KOMOOT", "source_ids": ["543", "301"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["낙동강 자전거길", "지산샛강생태공원", "낙동강체육공원"], "confidence": "high", "address": "대한민국 경상북도 구미시 지산동 840-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구미천', '낙동강 자전거길과 연결되는 구미천 하구 수변 구간입니다. 최근 비산나룻길 데크와 보도교가 조성되어 강변 풍경을 감상하며 쾌적하게 라이딩하기 좋습니다.', '{river,nature,park,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.373031, 36.124696), 4326), false, '{"source": "KOMOOT", "source_ids": ["543", "301"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["낙동강 비산나룻길", "비산체육공원", "낙동강 자전거길"], "confidence": "high", "address": "대한민국 경상북도 구미시 비산동 417-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구반포역', '지하철 9호선 구반포역입니다. 반포천 및 한강공원 자전거길로 진입하기 좋으며, 역사 내 화장실을 이용하거나 대중교통 연계 라이딩을 하기에 유용한 거점입니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.986766, 37.501285), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/0/0e/20240611_구반포역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8c/921_Gubanpo.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/22/20240611_구반포역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/ko/b/b9/Metro9_gubanpo_placard.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/ko/4/43/Metro9_gubanpo_placard2.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["반포한강공원", "반포천", "세화고등학교"], "confidence": "high", "address": "대한민국 서울특별시 서초구 반포동 1142"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구성역', '탄천 자전거길 접근성이 뛰어나 라이딩 출발지나 점프(지하철 탑승) 포인트로 자주 이용되는 역입니다.', '{transit,restroom,convenience_store,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.105751, 37.299009), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/b/b2/K235_guseong_01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/53/Q46207_Guseong_A01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8d/K235_guseong_03.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/27/K235_guseong_04.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/35/20240704_GTX_구성역.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["탄천 자전거길"], "confidence": "high", "address": "대한민국 용인시 구성역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구성저수지', '전남 곡성에 위치한 조용한 저수지로, 섬진강기차마을 등과 연계된 산악자전거(MTB) 및 라이딩 코스의 경유지로 활용되는 자연 경관 포인트입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.285706, 35.253262), 4326), false, '{"source": "KOMOOT", "source_ids": ["74"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["섬진강기차마을", "쌍구저수지"], "confidence": "high", "address": "대한민국 전라남도 곡성군 오곡면 구성리 73-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구암역·유성시외버스정류소', '대전 1호선 구암역과 유성시외버스정류소가 위치한 복합환승센터입니다. 시외버스나 전철을 이용한 자전거 점프 거점 및 보급, 휴식처로 활용하기 좋습니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.330867, 36.356586), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/d8/Guam_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/ad/Dajeon_Public_Bicycle_Tashu_at_Guam_Station.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["유성시외버스정류소", "유성복합환승센터"], "confidence": "high", "address": "대한민국 대전광역시 유성구 구암동 96-16"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구억리 검은굴', '제주 전통 옹기를 굽던 조선시대 가마터입니다. 라이딩 중 제주의 독특한 도기 문화를 엿볼 수 있는 역사 유적지입니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.285867, 33.281532), 4326), false, '{"source": "KOMOOT", "source_ids": ["315"], "category_raw": "15", "tour_count": 1, "nearby_landmarks": ["구억리 옹기마을", "제주영어교육도시"], "confidence": "high", "address": "대한민국 제주특별자치도 서귀포시 대정읍 구억리 838-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구영리 팽나무', '거제 구영리 마을을 지키는 300년 수령의 당산목(팽나무)입니다. 고즈넉한 어촌 마을의 정취를 느끼며 라이딩 중 잠시 쉬어가기 좋은 자연 랜드마크입니다.', '{nature,historic,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.697686, 35.029849), 4326), false, '{"source": "KOMOOT", "source_ids": ["265"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["구영등성", "구영해수욕장"], "confidence": "high", "address": "대한민국 경상남도 거제시 장목면 구영리 241-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구영해수욕장', '거제도 최북단의 작고 한적한 해수욕장입니다. 포플러 나무 그늘이 많고 파도가 잔잔하여 라이딩 중 조용히 쉬어가기 좋은 휴식처입니다.', '{beach,rest_area,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.691057, 35.030839), 4326), false, '{"source": "KOMOOT", "source_ids": ["287"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["구영마을 성터", "황포해수욕장"], "confidence": "high", "address": "대한민국 경상남도 거제시 장목면 구영리 392-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구의역', '지하철 2호선 구의역입니다. 주말 및 공휴일에 자전거 휴대 승차가 가능하여 라이딩 중 대중교통 연계(점프)나 모임 장소로 활용하기 좋습니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.086222, 37.537165), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/4/49/Q488778_Guui_B04.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/45/Q488778_Guui_B01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/71/Seoul-metro-213-Guui-station-entrance-4-20181122-095312.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2b/Q488778_Guui_B03.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/37/Eastern_Seoul_Bus_Terminal.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["광진구청", "구의공원", "자양사거리"], "confidence": "high", "address": "대한민국 서울특별시 자양제2동 구의"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('울릉문화예술체험장(구 장흥초교)', '울릉도 사동리 해안 일주도로변에 위치한 폐교(현 울릉문화예술체험장)입니다. 넓은 운동장이 있어 자전거 일주 중 안전하게 정차하고 쉬어가기 좋은 랜드마크입니다.', '{landmark,rest_area,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(130.888988, 37.473318), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["사동항", "신비섬횟집"], "confidence": "high", "address": "대한민국 구장흥초등"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구조라해수욕장', '거제도 해안 라이딩 중 들르기 좋은 해수욕장입니다. 파도가 잔잔하고 경치가 아름다우며, 화장실과 식당 등 편의시설이 잘 갖춰져 있어 휴식하기 좋습니다.', '{beach,rest_area,restroom,restaurant,parking,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.690624, 34.809177), 4326), false, '{"source": "KOMOOT", "source_ids": ["165"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["구조라항", "구조라성", "샛바람소리길", "윤돌섬"], "confidence": "high", "address": "대한민국 경상남도 거제시 일운면 구조라리 504-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구지중학교앞', '대구 달성군 구지중학교 앞 버스정류장입니다. 낙동강 자전거길과 대구국가산업단지 인근을 지나는 라이더들의 길잡이나 가벼운 경유지로 활용하기 좋습니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.4174, 35.659793), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["구지중학교", "대구국가산업단지"], "confidence": "high", "address": "대한민국 대구광역시 구지중학교앞"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('무주 구천동 시외버스터미널', '무주 덕유산과 구천동 계곡 라이딩의 기점이 되는 시외버스 터미널입니다. 대중교통 연계(점프)가 가능하며, 주변 상권에서 보급과 휴식을 취하기 좋습니다.', '{transit,bridge,rest_area,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.776332, 35.900945), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["덕유산국립공원", "무주구천동 계곡", "구천동관광안내소"], "confidence": "high", "address": "대한민국 전북특별자치도 무주군 설천면 삼공리 942 구천동 제1철교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구천저수지', '원시림과 짙은 녹색 물빛이 어우러진 거제도의 아름다운 저수지입니다. SNS에서 유명한 절벽 포토존과 가을 단풍이 있어 라이딩 중 멋진 풍경을 감상하기 좋습니다.', '{lake,viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.640301, 34.826614), 4326), false, '{"source": "KOMOOT", "source_ids": ["369"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["북병산", "거제수달생태공원", "구천계곡"], "confidence": "high", "address": "대한민국 경상남도 거제시 동부면 구천리 산5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구터미널(농협)', '당진 시내 중심에 위치한 주요 버스 정류장(구터미널)입니다. 주변에 은행과 편의시설이 밀집해 있어 라이딩 중 보급이나 휴식을 위한 거점으로 활용하기 좋습니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.629999, 36.894735), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["농협은행 당진해나루지점"], "confidence": "high", "address": "대한민국 당진시 구터미널(농협)"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구파발역 만남의 광장', '북한산, 진관사, 창릉천 방면 라이딩의 주요 출발지이자 만남의 광장입니다. 구파발역과 롯데몰이 있어 식사, 휴식, 화장실 이용이 매우 편리합니다.', '{transit,rest_area,restroom,restaurant,convenience_store,cafe,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.918801, 37.636892), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/8/85/Gupabal_Station_(Seoul_Subway_Line_3)_20230126_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/07/Seoul-metro-320-Gupabal-station-entrance-2-20191022-124400.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a8/Seoul-metro-320-Gupabal-station-entrance-3-20191022-124040.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/69/Gupabal_Station_platform_in_2018.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e7/Seoul-metro-320-Gupabal-station-platform-20191022-123416.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["구파발역", "롯데몰 은평점", "창릉천 자전거길", "북한산"], "confidence": "high", "address": "대한민국 서울특별시 구파발역.롯데몰"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('국가산단서한이다음건너', '대구국가산단 서한이다음 아파트 맞은편에 위치한 버스 정류장입니다. 아파트 단지 주변 상가를 통해 보급을 하거나 잠시 정차하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.421508, 35.663524), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["대구국가산단서한이다음아파트", "대구소프트웨어마이스터고등학교"], "confidence": "high", "address": "대한민국 대구광역시 국가산단서한이다음건너"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('국제시장', '부산의 대표적인 역사적 전통시장입니다. 아케이드 지붕이 있고 인파가 많아 자전거는 주변에 주차 후 도보로 다양한 먹거리와 볼거리를 즐기는 것을 추천합니다.', '{landmark,historic,restaurant,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.027778, 35.101779), 4326), false, '{"source": "KOMOOT", "source_ids": ["303", "312"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/or/or0mt9a3i1j9k7uphtfcs9np4h1k3hcc-uhi57607602/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/gz/gz8o4jt1zjlt1lcm4pqqidg2c4h1k3u65-uhi57607606/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1w/1wkfc2nrxhwfgl1qtanal0j5d4h1k3u8j-uhi57607607/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/18/18v2bnepofh4q1bpou7gtz7hp74h1k39ts-uhi57607599/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1t/1t9mjk7q8srzfgn8jcuehn5ta4h1k39y5-uhi57607600/0?width=1920&crop=false"], "tips": [{"text": "Der Markt erstreckt sich über mehrere Straßen und ist zum großen Teil überdacht.", "author": ""}, {"text": "Der Markt ist nicht nur in der Straße, sonder in dem ganzen Gebiet.", "author": ""}], "category_raw": "settlement", "tour_count": 1, "nearby_landmarks": ["자갈치시장", "부평깡통시장", "BIFF광장", "용두산공원"], "confidence": "high", "address": "대한민국 부산광역시 중구 부평동1가 13-15"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('국제시장', '부산의 대표적인 전통시장으로 대부분 지붕이 덮여 있습니다. 인파가 많아 자전거는 주변에 주차 후 도보로 다양한 먹거리를 즐기는 것을 추천합니다.', '{landmark,historic,restaurant,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.029334, 35.100712), 4326), false, '{"source": "KOMOOT", "source_ids": ["303", "312"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/or/or0mt9a3i1j9k7uphtfcs9np4h1k3hcc-uhi57607602/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/gz/gz8o4jt1zjlt1lcm4pqqidg2c4h1k3u65-uhi57607606/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1w/1wkfc2nrxhwfgl1qtanal0j5d4h1k3u8j-uhi57607607/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/18/18v2bnepofh4q1bpou7gtz7hp74h1k39ts-uhi57607599/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1t/1t9mjk7q8srzfgn8jcuehn5ta4h1k39y5-uhi57607600/0?width=1920&crop=false"], "tips": [{"text": "Der Markt erstreckt sich über mehrere Straßen und ist zum großen Teil überdacht.", "author": ""}, {"text": "Der Markt ist nicht nur in der Straße, sonder in dem ganzen Gebiet.", "author": ""}], "category_raw": "settlement", "tour_count": 1, "nearby_landmarks": ["자갈치시장", "부평깡통시장", "용두산공원", "보수동책방골목"], "confidence": "high", "address": "대한민국 부산광역시 중구 신창동2가 41"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('제주항 국제여객선터미널', '육지에서 자전거를 싣고 배편으로 제주에 도착하는 라이더들의 주요 관문입니다. 제주환상자전거길 종주를 시작하거나 마무리하기 좋은 거점입니다.', '{transit,restroom,convenience_store,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.544198, 33.525953), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["제주항", "용두암", "탑동광장"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 임항로"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('국화저수지', '강화읍 인근의 고즈넉한 저수지로, 수려한 자연 경관과 생태문화로가 조성되어 있습니다. 라이딩 중 호수 풍경을 감상하며 여유롭게 쉬어가기 좋은 힐링 스팟입니다.', '{lake,nature,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.466745, 37.744042), 4326), false, '{"source": "KOMOOT", "source_ids": ["1154"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["고려산", "국화지 낚시터", "동락천"], "confidence": "high", "address": "대한민국 인천광역시 강화군 강화읍 국화리 289-20"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('군산역', '금강 자전거길 종주 시 대중교통 점프 목적으로 많이 찾는 장항선 기차역입니다. 역 내 편의점과 화장실이 있어 라이딩 전후로 보급과 휴식을 취하기 좋습니다.', '{transit,convenience_store,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.759945, 35.999494), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/4/41/Gunsanstation.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["금강하구둑 인증센터", "내흥동 유적전시관"], "confidence": "high", "address": "대한민국 전북특별자치도 군산시 내흥동 442-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('군산시립도서관', '군산 수송동에 위치한 시립도서관입니다. 자전거 주차가 용이하며, 라이딩 중 화장실과 정수기를 이용하고 쾌적하게 쉬어가기 좋은 거점입니다.', '{rest_area,restroom,water_fountain,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.710829, 35.965296), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["수송근린공원", "새들공원", "지곡초등학교"], "confidence": "high", "address": "대한민국 군산시 군산시립도서관"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('군자역', '5호선과 7호선이 교차하는 군자역입니다. 주말 지하철 점프를 이용하거나 중랑천 자전거길 진입 전 화장실 이용 및 간식 보급을 하기 좋은 거점입니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.079535, 37.557229), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/3/3e/Seoul-metro-544-Gunja-station-sign-20180914-105812.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a5/Seoul-metro-Gunja-station-entrance-6-20180914-104302.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/04/Seoul-metro-544-Gunja-station-platform-20180914-105828.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6d/7호선_군자역_통로.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/79/20250708_5호선_군자역_승강장.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["중랑천 자전거길", "어린이대공원", "군자교"], "confidence": "high", "address": "대한민국 서울특별시 광진구 중곡동 672"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('궁구제', '장성군 진원면에 위치한 고요한 저수지입니다. 수변 산책길과 벤치가 잘 조성되어 있어 라이딩 중 한적하게 자연을 즐기며 휴식하기 좋습니다.', '{lake,nature,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.836741, 35.271011), 4326), false, '{"source": "KOMOOT", "source_ids": ["191"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["불태산"], "confidence": "high", "address": "대한민국 전라남도 장성군 진원면 진원리 721-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('궁평저수지', '아산 최대 규모의 저수지로 주변 임도는 MTB와 그래블 라이딩 코스로 인기가 높습니다. 단, 수변 맨발 황톳길은 자전거 출입이 금지되어 있으니 일반 도로나 임도를 이용해 주세요.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.989692, 36.715891), 4326), false, '{"source": "KOMOOT", "source_ids": ["923"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["광덕산", "외암민속마을", "봉수산"], "confidence": "high", "address": "대한민국 충청남도 아산시 송악면 궁평리 산10-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('권춘섭집앞', '국내 유일하게 일반인 이름을 딴 이색 버스정류장입니다. 아내를 위해 세워진 따뜻한 사연이 있는 곳으로, 라이딩 중 잠시 쉬며 기념사진을 남기기 좋은 랜드마크입니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.992865, 37.261503), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["상사미마을", "검룡소", "건의령"], "confidence": "high", "address": "대한민국 태백시 권춘섭집앞"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('근린공원', '원주 도심에 위치한 근린공원으로, 라이딩 중 가볍게 휴식을 취하거나 식수 보충 및 재정비를 하기에 적합한 장소입니다.', '{park,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.958428, 37.318884), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["단관공원", "단구근린공원", "원주혁신도시"], "confidence": "medium", "address": "대한민국 원주시 근린공원"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('근재고개', '전남 화순군 유천리에 위치한 작은 고개로, 라이더들에게 짧은 업힐 구간으로 이용됩니다. 한적한 시골길을 따라 자연을 느끼며 라이딩하기 좋습니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.003148, 35.080631), 4326), false, '{"source": "KOMOOT", "source_ids": ["988"], "category_raw": "mountain_pass", "tour_count": 1, "nearby_landmarks": ["유천리 마을", "만연산"], "confidence": "low", "address": "대한민국 전라남도 화순군 화순읍 유천리 1-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금강', '금강휴게소 인근을 흐르는 수려한 경관의 강입니다. 탁 트인 강변길을 따라 쾌적하게 라이딩하며 아름다운 자연을 만끽하기 좋습니다.', '{river,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.666359, 36.281264), 4326), false, '{"source": "KOMOOT", "source_ids": ["662"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["금강휴게소", "금강유원지", "어깨산"], "confidence": "high", "address": "대한민국 충청북도 옥천군 동이면 조령리 630"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금남로5가역', '광주 지하철 1호선 역으로 광주천 자전거길과 가까워 진출입 및 만남의 장소로 좋습니다. 인근에 광주시 공공자전거 ''타랑께'' 대여소가 위치해 있습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.910039, 35.153734), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/a/a7/Gwangju-metro-106-Geumnamno-5ga-station-sign-20190521-075736.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0f/Gwangju-metro-106-Geumnamno-5ga-station-entrance-1-20190521-080622.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/06/Gwangju-metro-106-Geumnamno-5ga-station-platform-20190521-075856.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["광주천", "금남로공원"], "confidence": "high", "address": "대한민국 광주광역시 금남로5가"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금능리', '제주환상자전거길이 지나는 해안 마을입니다. 비양도가 보이는 아름다운 금능해수욕장이 있어 라이딩 중 잠시 경치를 감상하며 쉬어가기 좋습니다.', '{beach,viewpoint,rest_area,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.232335, 33.387336), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["금능해수욕장", "협재해수욕장", "한림공원", "비양도"], "confidence": "high", "address": "대한민국 제주시 금능리"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금릉역', '경의중앙선 금릉역입니다. 공릉천 및 소리천 자전거길과 가까워 파주 지역 라이딩 시 점프(대중교통 연계)나 출발 및 도착 지점으로 활용하기 매우 좋습니다.', '{transit,restroom,convenience_store,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.765756, 37.751376), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/df/Q59873_Geumneung_A01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/87/Geumneung_Station_in_2021.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["공릉천 자전거길", "소리천 자전거길", "금릉 로데오거리"], "confidence": "high", "address": "대한민국 경기도 파주시 금촌동 980-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금사저수지', '여주 이포보 인근에 위치한 저수지로, 수변 생태공원과 나무 데크길이 잘 조성되어 있어 라이딩 중 경치를 감상하며 쉬어가기 좋습니다.', '{lake,park,nature,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.482871, 37.385891), 4326), false, '{"source": "KOMOOT", "source_ids": ["232"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["이포보", "이포CC"], "confidence": "high", "address": "대한민국 경기도 여주시 금사면 장흥리 산6-31"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금산시외버스터미널', '금산 지역 라이딩(금강, 대둔산 등)의 주요 출발 및 도착 지점입니다. 시외버스 점프가 가능하며, 주변에 식당과 편의시설이 많아 라이딩 전후 보급과 휴식에 매우 적합합니다.', '{transit,restroom,convenience_store,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.490708, 36.105239), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["금산인삼시장", "금산인삼엑스포공원", "금산군청"], "confidence": "high", "address": "대한민국 충청남도 금산군 금산읍 상리 76-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금암1리', '진위천 자전거길 인근 평택시 서탄면에 위치한 조용한 시골 마을입니다. 오산천과 평택호를 잇는 코스 중 지나치게 되며, 잠시 정차해 휴식하기 좋습니다.', '{other,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.041745, 37.104193), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["진위천 자전거길", "서탄면행정복지센터", "서탄초등학교"], "confidence": "high", "address": "대한민국 경기도 평택시 서탄면 금암리 45-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금양소류지', '남해 상주은모래비치 인근에 위치한 조용한 농업용 소류지입니다. 남해 해안도로 라이딩 중 한적한 저수지 풍경을 감상하며 잠시 쉬어가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.983956, 34.728767), 4326), false, '{"source": "KOMOOT", "source_ids": ["474"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["상주은모래비치", "상주한려해상체육공원"], "confidence": "high", "address": "대한민국 경상남도 남해군 상주면 상주리 878-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금어천', '경안천 자전거길과 연결되는 금어천변 자전거·보행자 겸용도로입니다. 최근 노면 정비가 완료되어 더욱 쾌적하고 안전한 라이딩을 즐길 수 있습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.220269, 37.266302), 4326), false, '{"source": "KOMOOT", "source_ids": ["738"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["경안천", "둔전초등학교", "삼정아파트"], "confidence": "high", "address": "대한민국 경기도 용인시 처인구 고림동 820-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금정산성 북문', '금정산 능선에 위치한 산성 문으로, 업힐과 오프로드를 즐기는 MTB 라이더들의 도전적인 코스입니다. 화장실과 식수대가 있어 휴식하기 좋습니다.', '{historic,landmark,mountain,restroom,water_fountain,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.057544, 35.275517), 4326), false, '{"source": "KOMOOT", "source_ids": ["229"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1o/1oagyclcze62osx0ktgdtd2gi46q2nu40-uhi50118070/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/9u/9ukpo0pdfd7zvgekubqc30k04gcw0nz2-uhi57366154/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/mn/mnt978rp62ycjx7tv8ng1rgi4r885ysd-uhi66690139/0?width=1920&crop=false"], "tips": [{"text": "The North Gate of Geumjeongsanseong Fortress is located 1.6 km west of Beomeosa Temple, at the spot where the main ridge, descending southward from Godangbong Peak, rises again toward Wonhyobong Peak. The North Gate exhibits the crudest appearance of the four gates of Geumjeongsanseong Fortress, has no arch-shaped decoration and is smaller than the other gates. The upper part of the foundational facility, measuring one kan (a unit of measurement referring to the distance between two columns) at the front and one kan at the sides, is a one-story watch tower with a half-hipped roof with a double-wing bracketing system. The gate measures 2.5 meters at the front, and 3.5 meters at the sides. The area around Sesimjeong Pavilion, situated in front of the gate, used to be known as ''Hwaeombeol'' because the venerable Korean Buddhist priest Wonhyo (617-686) preached the Hwaeomgyeong, or Avatamsaka Sutra, there. \r\n\r\nIt was also a training camp for monk-soldiers, including Buddhist monks from Beomeosa Temple, Gukcheongsa Temple, and Haewolsa Temple. The North Gate is known to be the passageway used by independence activists when they carried the Korean Declaration of Independence and the documents related to the independence movement and the March 1st Movement in 1919 at Beomeosa Temple, got off at Mulgeum Station on the Gyeongbu Line, by crossing Godangbong Peak of Geumjeongsan Mountain, and went to the Cheongnyeonam Hermitage.", "author": "Maik"}], "category_raw": "historical_site", "tour_count": 1, "nearby_landmarks": ["범어사", "고당봉", "원효봉"], "confidence": "high", "address": "대한민국 부산광역시 금정구 북문로 122"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금평소류지', '충남 금산군 남이면에 위치한 한적한 소류지(작은 저수지)입니다. 조용한 시골길 라이딩 중 자연 경관을 감상하며 잠시 쉬어가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.444528, 36.069241), 4326), false, '{"source": "KOMOOT", "source_ids": ["151"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["남이자연휴양림", "읍수동마을"], "confidence": "high", "address": "대한민국 충청남도 금산군 남이면 하금리 769-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금호역', '수도권 전철 3호선 금호역입니다. 주말 및 공휴일에 자전거 휴대 승차(점프)가 가능하며, 역사 내 화장실을 이용하거나 일행과 만나기 좋은 포인트입니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.016002, 37.547997), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/3/3d/Seoul-metro-334-Geumho-station-sign-20181125-091650.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/1d/Seoul-metro-334-Geumho-station-entrance-3-20181125-092304.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/12/Geumho_Station_(Seoul)_20240929_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/44/Seoul-metro-334-Geumho-station-platform-20181125-091716.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/13/Seoul-metro-334-Geumho-station-entrance-4-20181125-092446.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["금남시장", "금호터널", "옥수터널"], "confidence": "high", "address": "대한민국 서울특별시 성동구 금호동4가 1466-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼천포대교공원', '삼천포대교 아래 조성된 공원으로, 탁 트인 남해 바다와 웅장한 대교 풍경을 감상하며 라이딩 중 쉬어가기 좋은 휴식처입니다.', '{park,rest_area,viewpoint,parking,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.052664, 34.932719), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["삼천포대교", "사천바다케이블카", "대방진굴항"], "confidence": "high", "address": "대한민국 경상남도 사천시 대방동 684"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('곡성기차마을 전통시장', '섬진강 자전거길 인근에 위치한 곡성의 대표적인 전통시장입니다. 3·8일장과 토요장터가 열리며, 자전거 보관소와 화장실, 다양한 먹거리가 있어 라이딩 중 휴식하기 좋습니다.', '{restaurant,restroom,rest_area,parking,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.297369, 35.279239), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["섬진강기차마을", "섬진강장미공원", "기차당 뚝방마켓"], "confidence": "high", "address": "대한민국 곡성군 의료원.전통시장"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('기흥역', '수인분당선과 에버라인 환승역인 기흥역입니다. 신갈천 자전거길과 연결되어 기흥호수공원 라이딩의 출발점이나 복귀 시 자전거 점프 장소로 매우 유용합니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.116065, 37.275514), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/dd/Q16273_Giheung_A01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/ae/Q16273_Giheung_B01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/30/Everline_Gugal_station_20111228.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/24/기흥역_풀사인.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/56/Giheung-y-g.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["신갈천 자전거길", "기흥호수공원", "백남준아트센터"], "confidence": "high", "address": "대한민국 경기도 용인시 기흥구 구갈동 480-33"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('길동역', '지하철 5호선 길동역입니다. 자전거 점프(지하철 연계)나 라이딩 출발 및 만남의 장소로 활용하기 좋으며 역 내 화장실을 이용할 수 있습니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.140199, 37.53837), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/dc/Gildong_Station_5.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/69/Seoul-metro-549-Gil-dong-station-platform-20180914-114506.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/dc/Seoul-metro-549-Gil-dong-station-entrance-1-20180914-114910.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/dd/Gildong_Station_2.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a6/Seoul-metro-549-Gil-dong-station-sign-20180914-114428.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["길동복조리시장", "길동자연생태공원"], "confidence": "high", "address": "대한민국 서울특별시 강동구 길동 378"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('김대중컨벤션센터', '광주 상무지구의 대표적인 전시·회의 시설입니다. 공공자전거 대여소가 있고 화장실, 카페 등 편의시설이 잘 갖춰져 있어 라이딩 중 휴식하기 좋습니다.', '{landmark,rest_area,restroom,convenience_store,cafe,parking,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.841364, 35.143218), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/8/87/金大中コンベンションセンター駅.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/de/Gwangju-metro-114-KimDaejung-convention-center-station-sign-20190521-115332.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bd/Gwangju-metro-114-KimDaejung-convention-center-station-platform-20190521-115610.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/af/Gwangju-metro-114-KimDaejung-convention-center-station-entrance-1-20190521-121050.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/42/Gwangju-metro-114-KimDaejung-convention-center-station-entrance-2-20190521-120804.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["5·18기념공원", "상무시민공원", "김대중컨벤션센터역"], "confidence": "high", "address": "대한민국 광주광역시 김대중컨벤션센터"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('김천구미역', 'KTX와 SRT가 정차하는 고속철도역입니다. 자전거 포장 시 점프(대중교통 연계)가 가능하며, 역사 내 화장실과 편의점에서 쾌적하게 휴식과 보급을 할 수 있습니다.', '{transit,convenience_store,cafe,restroom,rest_area,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.180537, 36.112735), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["김천혁신도시"], "confidence": "high", "address": "대한민국 경상북도 김천시 남면 옥산리 839-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('계양아라온 다남녹지 전망대', '인천 계양구 다남동의 아라자전거길 북단 구간입니다. 계양아라온과 다남녹지 주변으로 피어나는 야생화와 탁 트인 아라뱃길의 강변 풍경을 감상하며 라이딩하기 좋습니다.', '{river,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.73223, 37.567995), 4326), false, '{"source": "KOMOOT", "source_ids": ["242"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/u9/u9tp5troi0sfcf7rh4ds9ihd46tvr6ru-uhi50241482/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1f/1fpbmh100hlb7j4jkf6lpsiwi46tvr9av-uhi50241483/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/11/11o8m1pe7mlds1x7np8ltrc3c946tvrcxk-uhi50241484/0?width=1920&crop=false"], "category_raw": "river", "tour_count": 1, "nearby_landmarks": ["경인아라뱃길", "아라자전거길", "계양아라온", "다남경관녹지", "계양대교"], "confidence": "high", "address": "대한민국 인천광역시 계양구 다남동 92-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('까치말지', '울산 울주군 덕현리에 위치한 소규모 저수지입니다. 영남알프스와 석남사 인근 라이딩 시 고즈넉한 수변 풍경을 감상하며 잠시 쉬어가기 좋은 자연 포인트입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.05028, 35.62331), 4326), false, '{"source": "KOMOOT", "source_ids": ["85"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["석남사", "가지산", "영남알프스"], "confidence": "high", "address": "대한민국 울산광역시 울주군 상북면 덕현리 667-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('꽃뫼저수지', '고삼저수지 인근에 위치한 한적한 저수지로 ''꽃뫼저수지''로도 불립니다. 벚꽃길 등 주변 경관이 아름답고 인근에 카페가 있어 라이딩 중 경치를 보며 쉬어가기 좋습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.288718, 37.076306), 4326), false, '{"source": "KOMOOT", "source_ids": ["645"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["고삼저수지", "꽃뫼마을", "꽃뫼카페휴게소"], "confidence": "high", "address": "대한민국 경기도 안성시 고삼면 봉산리 175"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('꽃바위 아파트', '울산 방어동에 위치한 아파트 단지로, 대왕암공원과 슬도로 이어지는 해안 자전거길 라이딩 시 길잡이가 되는 랜드마크입니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.409681, 35.483805), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["화암추등대", "슬도", "대왕암공원", "꽃바위바다소리길"], "confidence": "high", "address": "대한민국 울산광역시 꽃바위아파트"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('제주영어교육도시 꿈에그린아파트', '제주영어교육도시 내에 위치한 아파트 단지입니다. 라이딩 중 길 찾기를 위한 참고 지점으로 활용하기 좋습니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.271991, 33.281374), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["제주영어교육도시", "곶자왈 도립공원", "제주신화월드"], "confidence": "high", "address": "대한민국 서귀포시 꿈에그린아파트"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('진위천유원지 I LOVE JINWI 조형물', '진위천 자전거길 옆 진위천유원지의 ''I LOVE JINWI'' 조형물입니다. 한적해 쉬어가기 좋으나, 주변 자전거길 일부가 모래 등으로 고르지 않을 수 있어 주의바랍니다.', '{landmark,park,river,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.083315, 37.097556), 4326), false, '{"source": "KOMOOT", "source_ids": ["340"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/da/dayo2422vxpr1kf7170c0nq6z3rq1wn5u-uhi33215578/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/o3/o3xirq0d1r6k3b93g4kjkgmv3rq1wkq4-uhi33215576/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/y7/y7346m9wx1ezjbul41p4xz93rq1wmj7-uhi33215577/0?width=1920&crop=false"], "tips": [{"text": "It''s seems abandoned now.  The lights were not up in late summer 2022, but the sign is still there.  Nice quiet place to ride around, and there''s a bike path along the stream (which can get bumpy and sandy in certain spots).", "author": "Suzanne"}], "category_raw": "other_man_made", "tour_count": 1, "nearby_landmarks": ["진위천유원지", "진위천 레일바이크", "진위천 오토캠핑장"], "confidence": "high", "address": "대한민국 경기도 평택시 진위면 봉남리 498"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('나릿재마을5단지', '세종시 나성동의 주상복합 아파트 단지입니다. 인근에 제천 자전거길과 상권이 있어 라이딩 중 보급이나 휴식을 위한 경유지로 활용하기 좋습니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.25828, 36.491419), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["제천 자전거길", "나성동 먹자골목", "세종호수공원"], "confidence": "high", "address": "대한민국 세종특별자치시 나성동 801"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('나성중학교,나성초등학교', '세종시 나성동에 위치한 초·중학교입니다. 주변 자전거 도로망이 잘 갖춰져 있어 도심 라이딩 시 길잡이나 중간 기착지로 참고하기 좋은 랜드마크입니다.', '{landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.26353, 36.489606), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["세종예술의전당", "세종중앙공원", "금강 자전거길"], "confidence": "high", "address": "대한민국 세종특별자치시 나성중학교·나성초등학교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('나주역', '영산강 종주 자전거길과 인접해 있어 라이더들이 자전거 점프(대중교통 연계)를 위해 자주 찾는 KTX 나주역입니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.717309, 35.014461), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/7/72/20140605_Naju_Station_01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3c/나주역_2013-08-29_23-57.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6e/Naju_Station_20140605_02.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["영산강 자전거길", "나주시청"], "confidence": "high", "address": "대한민국 전라남도 나주시 송월동 409"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('낙동강', '국토종주 낙동강 자전거길 하류 구간에 위치한 강변입니다. 탁 트인 강 풍경을 감상하며 쾌적하게 라이딩할 수 있습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.985759, 35.292099), 4326), false, '{"source": "KOMOOT", "source_ids": ["303", "279", "72", "346", "467", "1484", "370", "589", "796", "151"], "image_urls": ["https://photos.komoot.de/wiki/commons/f/f0/낙동강.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3e/Andong_Bridge.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a3/Korea-Andong-Nakdong_River-02.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/58/Korea-Andong-Nakdong_River-01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f6/상주보.jpg?width=1920&crop=false"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["낙동강 종주 자전거길", "대동생태체육공원"], "confidence": "high", "address": "대한민국 경상남도 김해시 대동면 덕산리 320"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('낙동강', '대구 달성군 옥포읍 신당리를 지나는 낙동강 자전거길 구간입니다. 시원한 강바람을 맞으며 탁 트인 수변 풍경을 감상하기 좋은 평탄한 코스입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.438384, 35.80554), 4326), false, '{"source": "KOMOOT", "source_ids": ["303", "279", "72", "346", "467", "1484", "370", "589", "796", "151"], "image_urls": ["https://photos.komoot.de/wiki/commons/f/f0/낙동강.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3e/Andong_Bridge.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a3/Korea-Andong-Nakdong_River-02.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/58/Korea-Andong-Nakdong_River-01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f6/상주보.jpg?width=1920&crop=false"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["낙동강 자전거길", "옥포 신당리 정자", "달성신당정보화마을"], "confidence": "high", "address": "대한민국 대구광역시 달성군 옥포읍 신당리 621-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('낙동강', '국토종주 낙동강 자전거길이 지나는 현풍읍 자모리 구간입니다. 시원한 강바람과 함께 수려한 자연 경관을 감상하며 라이딩하기 좋습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.381963, 35.688349), 4326), false, '{"source": "KOMOOT", "source_ids": ["303", "279", "72", "346", "467", "1484", "370", "589", "796", "151"], "image_urls": ["https://photos.komoot.de/wiki/commons/f/f0/낙동강.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3e/Andong_Bridge.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a3/Korea-Andong-Nakdong_River-02.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/58/Korea-Andong-Nakdong_River-01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f6/상주보.jpg?width=1920&crop=false"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["낙동강 자전거길", "다람재", "도동서원터널"], "confidence": "high", "address": "대한민국 대구광역시 달성군 현풍읍 자모리 산99"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('낙동강하굿둑 인증센터', '국토종주 낙동강 자전거길의 기점이자 종점인 인증센터가 위치한 전망대입니다. 탁 트인 낙동강 하구 풍경을 감상하며 라이딩을 시작하거나 마무리하기 좋습니다.', '{viewpoint,checkpoint,rest_area,river,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.948136, 35.108864), 4326), false, '{"source": "KOMOOT", "source_ids": ["59"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["낙동강하굿둑 인증센터", "을숙도 생태공원", "낙동강문화관"], "confidence": "high", "address": "낙동강하굿둑인증센터, 낙동남로1233번길 하단제2동 사하구 부산광역시 대한민국"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('낙동강하굿둑 인증센터', '국토종주 및 낙동강 자전거길의 기종점입니다. 인증센터가 위치해 있으며, 탁 트인 하구 풍경을 감상할 수 있는 라이딩 필수 거점입니다.', '{bridge,checkpoint,landmark,river,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.952781, 35.10696), 4326), false, '{"source": "KOMOOT", "source_ids": ["309"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["을숙도", "낙동강하굿둑 인증센터", "낙동강하구 에코센터"], "confidence": "high", "address": "대한민국 부산광역시 사하구 하단동 1202"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('현수동 세월교', '안성천을 건너는 난간 없는 좁은 세월교입니다. 양끝 진입로가 거친 돌길이라 젖었을 때 매우 미끄러우므로 우천 시 자전거에서 내려 끌고 가는 것을 권장합니다.', '{bridge,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.280933, 37.00253), 4326), false, '{"source": "KOMOOT", "source_ids": ["1049"], "tips": [{"text": "Ok to cross but large rock path either side of bridge slippery / uneven, dangerous when wet", "author": "Jon"}], "category_raw": "bridge", "tour_count": 1, "nearby_landmarks": ["안성천", "안성맞춤아트홀"], "confidence": "high", "address": "대한민국 경기도 안성시 현수동 193"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남광주역', '광주 지하철 1호선 남광주역입니다. 광주천 자전거길과 가까워 라이딩 연계가 편리하며, 인근 남광주시장에서 식사와 보급을 해결하기 좋습니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.922762, 35.139446), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/6c/Gwangju-metro-103-Namgwangju-station-sign-20190521-091444.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/79/Gwangju-metro-103-Namgwangju-station-entrance-1-20190521-090934.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b5/Gwangju-metro-103-Namgwangju-station-platform-20190521-091504.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["남광주시장", "전남대학교병원", "광주천"], "confidence": "high", "address": "대한민국 광주광역시 남광주"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남녕고등학교', '제주시 노형동 도심에 위치한 고등학교로, 시내 구간 라이딩 시 길찾기 기준점이나 만남의 장소로 활용하기 좋은 랜드마크입니다.', '{landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.48304, 33.488126), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["노형오거리", "제주한라병원", "이마트 신제주점"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 노형동 999"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남동낚시터', '승기천 자전거길 인근에 위치한 낚시터입니다. 자전거 주행 중 다양한 철새와 수변 식생 등 자연 경관을 감상하며 쉬어가기 좋습니다.', '{river,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.706004, 37.429193), 4326), false, '{"source": "KOMOOT", "source_ids": ["201"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["승기천", "남동유수지"], "confidence": "high", "address": "대한민국 인천광역시 남동구 남동대로 533"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남목파출소', '울산 동구 남목고개나 주전 해안도로로 향하는 길목에 위치한 파출소입니다. 라이딩 중 긴급 상황 발생 시 도움을 요청할 수 있는 든든한 웨이포인트입니다.', '{police}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.429347, 35.54147), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["남목전통시장", "남목고개"], "confidence": "high", "address": "대한민국 울산광역시 남목파출소"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('전주 남부시장', '전주천 자전거길과 인접해 라이딩 중 접근하기 좋은 전통시장입니다. 피순대, 콩나물국밥 등 든든한 먹거리가 많아 식사와 휴식을 취하기에 최적의 장소입니다.', '{restaurant,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.147042, 35.812015), 4326), false, '{"source": "KOMOOT", "source_ids": ["1171"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1x/1xxfavyrrda02g579abgqwrrt30ymnwnu-uhi6554251/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/ic/iczvwvsyt0zm1f80cvgj89i2g30ympcuy-uhi6554256/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/vw/vwsxlwdtvqi0xzoj6wabzhmf30ympgk6-uhi6554257/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 1, "nearby_landmarks": ["전주천 자전거길", "풍남문", "전주한옥마을"], "confidence": "high", "address": "대한민국 전북특별자치도 전주시 완산구 전동3가 2-245"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남사저수지', '경주 구미산 자락에 위치한 수려한 풍경의 저수지입니다. 주변에 용담정 등 명소가 있으며, 접근 시 가파른 업힐 구간이 있어 라이딩 시 체력 안배가 필요합니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.138604, 35.905491), 4326), false, '{"source": "KOMOOT", "source_ids": ["581"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["용담정", "수운 최제우 선생 생가", "정귀문 노래비"], "confidence": "high", "address": "대한민국 경상북도 경주시 현곡면 남사리 348"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남산', '거제면 남동리에 위치한 해발고도가 낮은 산입니다. 거제도 해안도로 순환 라이딩 시 가벼운 업힐 코스로 지나게 되며, 인근에 남산패총 유적지가 있습니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.590829, 34.847925), 4326), false, '{"source": "KOMOOT", "source_ids": ["36"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["남산패총", "거제면사무소"], "confidence": "high", "address": "대한민국 경상남도 거제시 거제면 남동리 26-16"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남산 케이블카 승강장', '남산 라이딩 코스(소파로)에 위치한 케이블카 하부 승강장입니다. 자전거 동반 탑승은 불가하며, 남산 업힐 시 지나치는 주요 랜드마크입니다.', '{landmark,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.984137, 37.556419), 4326), false, '{"source": "KOMOOT", "source_ids": ["297"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1q/1q32fq76g8yj910u4rdv4qkz2d4zyfjz4z-uhi73147034/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1b/1bbtg37tdnkb16pjhiyynonss54x5i659-uhi79183220/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1a/1a6gbphl89gpb181b13xxetqlf54x5i6e4-uhi79183221/0?width=1920&crop=false"], "tips": [{"text": "So kommt man unproblematisch, schnell und ohne große Anstrengung von der Stadt zur Anfangsstation der Seilbahn auf den Namsan-Berg.", "author": "Su"}], "category_raw": "other_man_made", "tour_count": 1, "nearby_landmarks": ["남산서울타워", "남산공원", "남산오르미"], "confidence": "high", "address": "대한민국 서울특별시 중구 소파로 83"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남선제', '진도군 임회면 굴포리에 위치한 조용한 저수지입니다. 한적한 농어촌 풍경을 감상하며 라이딩 중 가볍게 스쳐 지나가기 좋은 포인트입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.18706, 34.366903), 4326), false, '{"source": "KOMOOT", "source_ids": ["375"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["남선마을", "굴포항", "국립진도자연휴양림"], "confidence": "high", "address": "대한민국 전라남도 진도군 임회면 굴포리 648-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남양호', '평탄하고 곧게 뻗은 주변 도로 덕분에 초보자나 팩라이딩에 적합한 화성시의 인공호수입니다. 그늘이 적어 라이딩 시 대비가 필요합니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.841802, 37.024147), 4326), false, '{"source": "KOMOOT", "source_ids": ["731"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["남양방조제", "발안천"], "confidence": "high", "address": "대한민국 경기도 화성시 장안면 장안리 2364"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남원공용버스터미널', '섬진강 자전거길과 지리산 라이딩의 주요 출발/도착지로 활용되는 남원의 핵심 교통 거점입니다. 화장실, 편의점, 식당이 모여 있어 라이딩 전후 보급과 점프(이동)에 매우 편리합니다.', '{transit,restroom,convenience_store,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.388025, 35.409533), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["광한루원", "요천 자전거길", "춘향테마파크"], "confidence": "high", "address": "대한민국 남원시 동충동 시외버스터미널"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남원읍 길가의 귤나무', '제주 환상자전거길 남원읍 위미리 구간에 위치한 길가의 귤나무입니다. 라이딩 중 제주 특유의 싱그러운 귤밭 풍경을 감상하며 힐링하기 좋은 자연 경관입니다.', '{nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.671973, 33.278493), 4326), false, '{"source": "KOMOOT", "source_ids": ["263"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/17/17d0qh9fyumz9lc26j684d8025bu84ibt-uhi84760912/0?width=1920&crop=false"], "category_raw": "other_natural", "tour_count": 1, "nearby_landmarks": ["제주환상자전거길", "위미항", "위미동백나무군락"], "confidence": "medium", "address": "대한민국 제주특별자치도 서귀포시 남원읍 위미리 1510-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남위례역', '서울 지하철 8호선 남위례역입니다. 위례신도시와 연결되는 대중교통 거점이며, 역 주변 보도육교 인근에 자전거 거치대가 있어 연계 라이딩 시 유용합니다.', '{transit,restroom,bridge}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.13948, 37.463109), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/8/86/Namwirye_station_platform.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/fb/20211218_남위례역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c3/Namwirye_station_821.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/88/20211218_남위례역_개찰구.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/50/20211218_남위례역_승강장.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["위례신도시", "창곡천", "남위례역 보도육교"], "confidence": "high", "address": "대한민국 경기도 성남시 수정구 복정동 58-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남창천', '영산강 자전거길과 이어지는 남창천 생태하천입니다. 자전거도로와 야간 경관 조명이 잘 조성되어 있어 야간에도 안전하게 라이딩하기 좋습니다.', '{river,nature,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.482712, 34.812322), 4326), false, '{"source": "KOMOOT", "source_ids": ["601"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["영산강", "남악수변공원"], "confidence": "high", "address": "대한민국 전라남도 무안군 삼향읍 남악리 2605-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남포제', '전북 부안군 보안면에 위치한 저수지입니다. 여름철 인근에 만개하는 배롱나무꽃 길이 아름다워 라이딩 중 경치를 감상하기 좋습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.670613, 35.640208), 4326), false, '{"source": "KOMOOT", "source_ids": ["1319"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["배롱나무길"], "confidence": "high", "address": "대한민국 전북특별자치도 부안군 보안면 남포리 산13-27"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남한강', '남한강 자전거길이 지나는 탁 트인 강변 구간으로, 수려한 자연 경관과 탄금호의 풍경을 감상하며 라이딩하기 좋습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.868226, 37.036205), 4326), false, '{"source": "KOMOOT", "source_ids": ["223", "2025", "140", "253", "233"], "image_urls": ["https://photos.komoot.de/wiki/commons/b/b6/Hangang-s-big.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b7/Korea-Seoul-Han_River-01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/5b/Seoul-Han.River-01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/34/Hangang_Railway_Bridge.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e5/한강경찰대_망원한강치안센터.JPG?width=1920&crop=false"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["남한강 자전거길", "금가 달숯정원", "조정지댐", "탄금호"], "confidence": "high", "address": "대한민국 충청북도 충주시 금가면 월상리 275"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('내리초등학교', '부산 기장군에 위치한 초등학교입니다. 장산이나 안적사 방면 산악자전거(MTB) 코스로 진입할 때 길잡이 및 출발점으로 활용하기 좋은 랜드마크입니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.206353, 35.204078), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["안적사", "장산", "오시리아 관광단지"], "confidence": "high", "address": "대한민국 부산광역시 내리초등학교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('내미리 마을', '구미시 해평면 도문리에 위치한 한적한 시골 자연부락입니다. 낙동강 자전거길 구미보나 해평임도 코스 라이딩 시 지나칠 수 있는 조용한 농경지대입니다.', '{other,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.433788, 36.234427), 4326), false, '{"source": "KOMOOT", "source_ids": ["299"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["구미보", "해평임도", "도리사", "낙동강 자전거길"], "confidence": "high", "address": "대한민국 경상북도 구미시 해평면 도문리 산56-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('내방역', '지하철 7호선 내방역입니다. 서리풀터널을 통해 서초 방면으로 이동하기 좋으며, 주말 라이딩 시 대중교통 점프 포인트로 유용합니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.993548, 37.487657), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/4/46/735_Naebang.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/70/Seoul-metro-735-Naebang-station-platform-20191022-163224.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2a/Seoul-metro-735-Naebang-station-entrance-4-20191022-163838.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/af/Seoul-metro-735-Naebang-station-platform-20191022-165836.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["서리풀터널", "서리풀공원", "몽마르뜨공원"], "confidence": "high", "address": "대한민국 서울특별시 내방역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('내지저수지', '예천 용문사 인근에 위치한 한적한 저수지입니다. 차량 통행이 적은 시골길을 따라 자연 경관을 감상하며 라이딩하기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.368547, 36.705731), 4326), false, '{"source": "KOMOOT", "source_ids": ["579"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["용문사", "초간정", "운암저수지"], "confidence": "high", "address": "대한민국 경상북도 예천군 용문면 내지리 산2-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('냉정저수지', '남해고속도로 옆에 위치한 소규모 저수지입니다. 차량 소음이 다소 있지만, 라이딩 중 물가를 보며 잠시 쉬어가기 좋은 자연 포인트입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.785968, 35.222302), 4326), false, '{"source": "KOMOOT", "source_ids": ["122"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["남해고속도로"], "confidence": "high", "address": "대한민국 경상남도 김해시 부곡동 1050-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('너럭바위전망대', '승학산 임도 코스에 위치한 탁 트인 목재 데크 전망대입니다. 구덕산과 시약산 산줄기를 조망하며 휴식하기 좋아 MTB 라이더들에게 추천하는 포인트입니다.', '{viewpoint,mountain,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.992291, 35.121951), 4326), false, '{"source": "KOMOOT", "source_ids": ["111"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["승학산", "낙조전망쉼터", "승학문화마루터"], "confidence": "high", "address": "대한민국 부산광역시 사하구 당리동 산1-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('노곡저수지', '안성 양성면에 위치한 조용한 저수지로, 이동저수지와 고삼저수지를 잇는 한적한 시골길 라이딩 코스에서 경치를 즐기며 지나기 좋은 수변 경유지입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.254744, 37.105132), 4326), false, '{"source": "KOMOOT", "source_ids": ["452"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["이동저수지", "고삼저수지", "미리내성지"], "confidence": "high", "address": "대한민국 경기도 안성시 양성면 노곡리 245-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('노란꽃길', '순창 유등면 섬진강 자전거길 구간으로, 봄이 되면 강변을 따라 식재된 산수유 등 노란 꽃이 만발해 아름다운 경치를 자랑하는 라이딩 명소입니다.', '{nature,river,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.185494, 35.358513), 4326), false, '{"source": "KOMOOT", "source_ids": ["875"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/xy/xyo3lvajzlwc11vdws22hqd1d5e584qm2-uhi87511970/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 1, "nearby_landmarks": ["섬진강 자전거길", "섬진강"], "confidence": "high", "address": "대한민국 전북특별자치도 순창군 유등면 외이리 896-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('노량진역', '1호선과 9호선이 지나는 환승역으로, 한강 자전거길과 가까워 라이더들이 대중교통 연계(점프)나 만남의 장소로 자주 이용하는 주요 교통 거점입니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.94154, 37.513558), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/2/2f/노량진역,_2번_출입구.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/01/노량진역.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f1/노량진역_폴사인.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8f/노량진역_1번_출입구.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/ac/노량진역_승강장.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["노량진수산시장", "사육신공원", "노들나루공원"], "confidence": "high", "address": "대한민국 서울특별시 동작구 노량진동 59-48"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('노원역 자전거 거점', '중랑천과 당현천 자전거길 진입이 수월한 4·7호선 환승역입니다. 역 주변에 자전거 보관소와 자동식 공기주입기가 설치되어 있어 대중교통 점프나 가벼운 정비 거점으로 유용합니다.', '{transit,convenience_store,cafe,restaurant,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.060462, 37.654585), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/9/9f/Seoul-metro-713-Nowon-station-platform-20181122-135330.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/04/Seoul-metro-Nowon-station-entrance-06-20181122-140122.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/58/20241108_노원역_환승통로.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/5d/411nowon.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bf/Nowsta01.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["중랑천 자전거길", "당현천 자전거길", "노원문화의거리"], "confidence": "high", "address": "대한민국 서울특별시 노원역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('노은역', '대전 1호선 노은역입니다. 타슈(공영자전거) 대여소와 자전거 보관소가 있어 대중교통 연계 라이딩이나 화장실 이용 등 휴식 거점으로 활용하기 좋습니다.', '{transit,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.317887, 36.374108), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/0/07/Noeun_Stn._platform.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0d/Noeun_Stn._exit.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b9/Noeun_Stn._nameplate.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["은구비공원", "노은역광장"], "confidence": "high", "address": "대한민국 대전광역시 유성구 노은로 지하 161"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('노인봉', '울릉도 해안 일주도로(926번 지방도) 바로 옆에 위치한 200m 높이의 기암괴석입니다. 노인의 주름살을 닮은 독특한 주상절리를 감상하며 라이딩 중 쉬어가기 좋은 뷰포인트입니다.', '{mountain,nature,landmark,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(130.831671, 37.528904), 4326), false, '{"source": "KOMOOT", "source_ids": ["460"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["공암(코끼리바위)", "현포항", "송곳산"], "confidence": "high", "address": "대한민국 경상북도 울릉군 북면 현포리 453"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('녹천역', '중랑천 자전거길과 인접한 1호선 전철역입니다. 주말 라이딩 시 전철 점프(연계)나 화장실 이용을 위해 들르기 좋은 거점입니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.051541, 37.644666), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/4/4b/Korail-117-Nokcheon-station-platform-20181126-141730.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/fc/Korail-117-Nokcheon-station-entrance-4-20181126-142150.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d2/Korail_nokcheon_station_exit1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/47/Korail_nokcheon_station_exit2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c5/Korail-117-Nokcheon-station-entrance-3-20181126-142014.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["중랑천 자전거길", "녹천교", "초안산"], "confidence": "high", "address": "대한민국 서울특별시 녹천"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('늘사랑어린이집', '통영 용남면 동암길에 위치한 어린이집입니다. 특별한 자전거 편의시설은 없으나, 용남해안로 등 주변 코스를 지날 때 길잡이가 되는 로컬 포인트입니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.448668, 34.867436), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["통영옻칠미술관", "동남지방통계청 통영사무소", "용남해안로"], "confidence": "high", "address": "대한민국 통영시 늘사랑어린이집"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('능곡역', '경의중앙선과 서해선이 지나는 능곡역 및 공영주차장입니다. 자전거 점프(전철 이용)나 행주산성 방면 라이딩을 위한 출발 및 만남의 장소로 유용합니다.', '{transit,parking,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.820571, 37.619369), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/3/38/Q59852_Neunggok_A01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c9/Q59852_Neunggok_A02.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d0/Neunggok_Station_2017.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/95/20230701_능곡역_분기점.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/73/Q59852_Neunggok_A04.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["능곡역", "행주산성", "능곡전통시장"], "confidence": "high", "address": "대한민국 경기도 고양시 덕양구 토당동 454-63"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('능골근린공원', '강일역 4번 출구와 연결된 근린공원으로 고덕천 자전거길 진입이 수월합니다. 공중화장실과 따릉이 대여소가 있어 라이딩 출발지나 휴식처로 유용합니다.', '{park,rest_area,restroom,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.174328, 37.5571), 4326), false, '{"source": "KOMOOT", "source_ids": ["980"], "category_raw": "191", "tour_count": 1, "nearby_landmarks": ["강일역", "고덕천", "에너지마루", "고덕리엔파크"], "confidence": "high", "address": "대한민국 서울특별시 강일역.고덕리엔파크3단지.2단지"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신평동교차로', '제공된 좌표는 다대포가 아닌 신평동교차로(을숙도대교 인근)입니다. 낙동강 자전거길을 따라 다대포 해수욕장으로 향하는 길목에 위치한 라이딩 경유지입니다.', '{checkpoint,bridge,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.955322, 35.09544), 4326), false, '{"source": "KOMOOT", "source_ids": ["20"], "category_raw": "beach", "tour_count": 1, "nearby_landmarks": ["신평동교차로", "을숙도대교", "낙동강 자전거길"], "confidence": "high", "address": "대한민국 부산광역시 사하구 신평동 642-16"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('다정동', '세종시 다정동(가온마을) 일대입니다. 제천 자전거길과 인접해 있으며, 인근에 자전거 매장과 복합커뮤니티센터가 있어 라이딩 중 정비나 휴식을 취하기 좋습니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.256435, 36.494817), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["다정동 복합커뮤니티센터", "제천 자전거길", "삼천리자전거 다정점"], "confidence": "high", "address": "대한민국 세종특별자치시 다정동"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('단석저수지', '양평군 양동면에 위치한 한적한 저수지로, 주변 경관을 감상하며 라이딩하기 좋습니다. 인근에 단석저수지 고개와 산악자전거를 즐기기 좋은 코스가 있습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.738322, 37.403412), 4326), false, '{"source": "KOMOOT", "source_ids": ["1292"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["양동레포츠공원", "단석저수지 고개"], "confidence": "high", "address": "대한민국 경기도 양평군 양동면 쌍학리 산74-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('단양1교', '단양군 단성면 죽령천을 건너는 교량(단양1교)입니다. 단성생태공원과 인접해 있으며, 남한강 주변 라이딩 시 지나게 되는 길목입니다.', '{bridge}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.335904, 36.931321), 4326), false, '{"source": "KOMOOT", "source_ids": ["2315"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/uc/uc63d74j6x001fhb52gsjuilf37eof9b9-uhi9479841/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/wa/wacstfvvpj0h1rfo2okcqb7do37eof9or-uhi9479842/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 1, "nearby_landmarks": ["단성생태공원", "단성역(폐역)", "한국호텔관광고등학교"], "confidence": "high", "address": "대한민국 충청북도 단양군 단성면 북하리 151-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('달래내고개', '평균 경사도 4%의 완만한 고개로 초보자도 부담 없이 오를 수 있습니다. 하오고개, 여우고개 등 수도권 남부 코스와 연계하기 좋은 주요 길목입니다.', '{mountain,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.088963, 37.409166), 4326), false, '{"source": "KOMOOT", "source_ids": ["362"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1v/1v8z0qzycwl6sg3vp8mb9at8v3ap2c8pp-uhi10839466/0?width=1920&crop=false"], "tips": [{"text": "Fairly gentle burn of 4% of 2.5km", "author": "Jon"}], "category_raw": "climb", "tour_count": 1, "nearby_landmarks": ["청계산", "경부고속도로"], "confidence": "high", "address": "대한민국 경기도 성남시 수정구 금토동 310-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('달미공원', '안산 선부동에 위치한 달미공원(구 와동제3공원)입니다. 자전거 라이딩 중 가볍게 휴식하며 재정비하기 좋은 한적한 도심 속 공원입니다.', '{park,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.809349, 37.349394), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/7/79/Dalmi_Stn._Entrance_1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/59/S24_달미역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/88/S24_달미역_스크린도어.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/98/Dalmi_Stn._Platform.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f6/Dalmi_Stn._Escalator.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["달미역", "화정천"], "confidence": "high", "address": "대한민국 경기도 안산시 단원구 선부동 1161-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('달천', '충주 탄금대와 수안보를 잇는 새재자전거길이 지나는 하천입니다. 맑은 물과 탁 트인 강변 풍경을 감상하며 시원하게 라이딩하기 좋습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.879999, 36.960833), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["새재자전거길", "한국교통대학교 충주캠퍼스"], "confidence": "high", "address": "대한민국 충청북도 충주시 대소원면 만정리 14-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('달천 아이파크1차', '울산 북구 달천동에 위치한 아파트 단지입니다. 단지 상가에 편의점이 있으며, 바로 맞은편에 위치한 달천철장 유적공원에서 자전거를 세우고 휴식하기 좋습니다.', '{other,convenience_store,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.329775, 35.634279), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["달천철장 유적공원", "천마산 편백산림욕장"], "confidence": "high", "address": "대한민국 울산광역시 달천아이파크1차"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('담방마을 사거리', '장수천 자전거길과 인접한 교차로입니다. 동쪽 서창동 방향은 도로가 단절되어 장수천 다리와 무네미로 인도를 통한 우회가 필요하므로 라이딩 시 주의해야 합니다.', '{checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.732173, 37.439578), 4326), false, '{"source": "KOMOOT", "source_ids": ["387"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["장수천", "남동체육관", "남동아시아드럭비경기장"], "confidence": "high", "address": "대한민국 인천광역시 남동구 수산동 597-20"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('담양 국수 거리', '영산강 자전거길 바로 옆에 위치해 라이딩 중 든든하게 배를 채우고 휴식하기 좋은 담양의 명물 거리입니다.', '{restaurant,rest_area,landmark,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.983108, 35.324118), 4326), false, '{"source": "KOMOOT", "source_ids": ["258"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/16/16pbz8n7oha74romzktkjsm1137e532im-uhi9476413/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/la/lafmja9vwwje1qoza4ygi36jl5cu7yd90-uhi85807528/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/f3/f3vfqlvtsjnlyh9rm8esp2ut5cu7yevq-uhi85807529/0?width=1920&crop=false"], "category_raw": "restaurant", "tour_count": 1, "nearby_landmarks": ["관방제림", "죽녹원", "영산강 자전거길"], "confidence": "high", "address": "대한민국 전라남도 담양군 담양읍 객사리 175-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('금성 시외버스정류소', '영산강 자전거길 종주 후 섬진강(순창 방면)으로 점프하거나 복귀할 때 유용한 금성면 시외버스 정류소입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.027221, 35.344089), 4326), false, '{"source": "KOMOOT", "source_ids": ["382"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1s/1snrni0mcf6qwwfxh9ioljip937e4ifnu-uhi9476342/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 1, "nearby_landmarks": ["영산강 자전거길", "담양댐", "금성면사무소"], "confidence": "high", "address": "대한민국 전라남도 담양군 금성면 석현리 94-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('담양댐 인증센터', '영산강 자전거길 종주의 시작점이자 끝나는 지점입니다. 바로 옆에 편의점과 화장실이 있어 보급과 휴식을 취하기 좋으며, 섬진강으로 점프하기 위한 거점으로도 활용됩니다.', '{checkpoint,convenience_store,restroom,rest_area,river,lake}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.018109, 35.371433), 4326), false, '{"source": "KOMOOT", "source_ids": ["445"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/14/14eelvoogtmwh1mx2g89yk0yev37e4n8f4-uhi9476359/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/6g/6gxwmllssy9v10ojjrcygw3o237e4n9a0-uhi9476360/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/11/114atq91viism1putg8dd4zxgz37e4n9p4-uhi9476361/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 1, "nearby_landmarks": ["담양댐", "영산강", "오감서 편의점"], "confidence": "high", "address": "대한민국 전라남도 담양군 금성면 대성리 34-33"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('당거2리', '평택 안성천(평택강) 자전거길이 지나는 마을입니다. 인근 당거쉼터에 공공자전거 대여소와 휴식 공간이 있어 라이딩 중 쉬어가기 좋습니다.', '{rest_area,river,nature,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.98223, 36.992991), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["당거쉼터", "안성천 자전거길", "두바퀴의 행복 2호점"], "confidence": "high", "address": "대한민국 평택시 당거2리"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('당구이곳', '인천 무의도 해안도로(대무로) 변에 위치한 자연 해안 돌출부(곶)입니다. 라이딩 중 탁 트인 바다 풍경을 감상하며 지나가기 좋은 경관 포인트입니다.', '{viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.417321, 37.402618), 4326), false, '{"source": "KOMOOT", "source_ids": ["136"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["큰무리선착장", "무의대교", "실미해수욕장"], "confidence": "high", "address": "159 Daemu-ro Road, Korea, 중구 인천광역시 대한민국"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('당진천', '당진천을 따라 조성된 자전거 도로로, 봄철 벚꽃길 풍경이 아름다워 라이딩하기 좋은 명소입니다. 보행로와 자전거 도로가 잘 분리되어 안전하게 달릴 수 있습니다.', '{river,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.624818, 36.900933), 4326), false, '{"source": "KOMOOT", "source_ids": ["17"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["당진천 벚꽃길"], "confidence": "high", "address": "대한민국 충청남도 당진시 읍내동 695-87"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대곡역', '대구 도시철도 1호선 대곡역입니다. 진천천 자전거길과 연결되어 낙동강 자전거길, 사문진 주막촌으로 향하는 라이딩 출발점으로 유용합니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.512457, 35.809489), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["진천천 자전거길", "사문진 주막촌", "화원유원지"], "confidence": "high", "address": "대한민국 대구광역시 달성군 화원읍 구라리 1736-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('iM뱅크 본점', '대구은행(현 iM뱅크) 본점입니다. 신천 자전거길과 인접해 있어 라이딩 중 현금 인출이나 급한 은행 업무를 보기에 유용한 랜드마크입니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.61411, 35.859762), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/a/a7/232daegubank.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/ec/Daegu-metropolitan-transit-corporation-232-Daegu-bank-station-entrance-1-20161010-074858.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/67/Daegu-metropolitan-transit-corporation-232-Daegu-bank-station-platform-20161010-075524.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["대구은행역", "수성교", "신천 자전거길", "대구광역시교육청"], "confidence": "high", "address": "대한민국 대구광역시 대구은행"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대기저수지', '황매산과 모산재의 수려한 산세가 어우러진 아름다운 저수지입니다. 황매산 업힐 라이딩 전후로 탁 트인 자연 경관을 감상하며 지나기 좋은 포인트입니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.006265, 35.468045), 4326), false, '{"source": "KOMOOT", "source_ids": ["676"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["황매산", "모산재", "영암사지"], "confidence": "high", "address": "대한민국 경상남도 합천군 가회면 둔내리 882"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('담양 대나무숲 인증센터', '영산강 자전거길 종주 코스의 필수 기착지입니다. 울창한 대나무숲이 시원한 그늘을 제공하며, 담양대나무숲 인증센터가 위치해 있습니다.', '{checkpoint,nature,rest_area,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.942666, 35.271583), 4326), false, '{"source": "KOMOOT", "source_ids": ["786"], "category_raw": "191", "tour_count": 1, "nearby_landmarks": ["영산강 자전거길", "담양대나무숲 인증센터"], "confidence": "high", "address": "대한민국 전라남도 담양군 봉산면 신학리 477-20"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대동다숲.마린푸르지오2단지APT', '진해 장천동의 대동다숲, 마린푸르지오 아파트 앞 버스 정류장입니다. 남파랑길 등 진해 해안 라이딩 시 대중교통 연계나 길잡이로 활용하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.705704, 35.129911), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["진해드림파크", "진해구청", "장천항"], "confidence": "high", "address": "대한민국 경상남도 창원시 진해구 장천동 119-19"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대동저수지', '순천 왕지동에 위치한 한적한 저수지입니다. 산세가 어우러진 수변 경관을 감상하며 라이딩 중 잠시 쉬어가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.542399, 34.977597), 4326), false, '{"source": "KOMOOT", "source_ids": ["80"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["조례호수공원", "대동마을"], "confidence": "high", "address": "대한민국 전라남도 순천시 왕지동 191-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대봉교', '대구 신천을 가로지르는 다리로 하부에 쾌적한 신천 자전거길이 조성되어 있습니다. 대구 3호선이 지나 접근성이 좋고 주야간 라이딩 코스로 인기가 많습니다.', '{bridge,river,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.606336, 35.854987), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/5d/Daebonggyo_Station_20150424_162421.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/83/Daebonggyo_Station_20150424_162409.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8c/대봉교역_대백프라자_진입통로.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/aa/Daebonggyo_Station_20150424_162307.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["신천자전거길", "대봉교역(대구 3호선)", "김광석다시그리기길"], "confidence": "high", "address": "대한민국 대구광역시 대봉교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대사1리', '안성천 자전거길과 평택섶길 코스 인근의 한적한 시골 마을입니다. 대사1리 마을쉼터가 있어 라이딩 중 잠시 쉬어가기 좋습니다.', '{rest_area,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.062902, 36.944681), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["안성천", "대사1리 마을쉼터", "대추리평화마을"], "confidence": "high", "address": "대한민국 평택시 대사1리"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대성리역', '북한강 자전거길과 인접해 전철 점프(연계) 코스로 사랑받는 경춘선 대성리역입니다. 화장실과 편의점 등 보급 시설이 있어 라이딩 출발이나 도착, 휴식처로 매우 유용합니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.379041, 37.683964), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/6a/Q49973_Daesongri_A01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c0/대성리역.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/75/구_대성리역.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/04/20211107_대성리역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/88/Q49973_Daesongri_A02.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["북한강 자전거길", "대성리 국민관광지"], "confidence": "high", "address": "대한민국 경기도 가평군 청평면 경춘로 88"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대안저수지', '원주 외곽의 조용하고 경치 좋은 계곡형 저수지입니다. 양안치고개 등 인근 임도 코스와 연계하기 좋으며, 최근 대형 카페가 생겨 라이딩 중 휴식하기 좋습니다.', '{lake,nature,rest_area,cafe,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.877768, 37.279849), 4326), false, '{"source": "KOMOOT", "source_ids": ["243"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["고래호수 카페", "양안치고개", "연세대학교 미래캠퍼스"], "confidence": "high", "address": "대한민국 강원특별자치도 원주시 흥업면 대안리 1558-16"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대잠그린파크아파트', '명칭 때문에 공원으로 오해하기 쉬우나 실제로는 포항 대잠동의 아파트 단지입니다. 인근에 포항 철길숲 자전거길이 있어 라이딩 시 이정표로 참고하기 좋습니다.', '{landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.341025, 36.020258), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["포항 철길숲", "양학공원", "포항시청"], "confidence": "high", "address": "대한민국 포항시 대잠그린파크"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대전역', '자전거 라이딩의 주요 거점인 대전역입니다. 기차를 이용한 점프(이동)가 용이하며, 식당과 화장실 등 편의시설이 잘 갖춰져 있어 출발 및 도착지로 매우 적합합니다.', '{transit,restroom,convenience_store,restaurant,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.434747, 36.332068), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/7/70/Daejeon_Station_2017.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/1d/Daejeon_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/4b/Q20919_Daejeon_Station_A01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/01/대전역_동광장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f9/Taiden_Station.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["성심당 대전역점", "대전천 자전거길", "대전중앙시장"], "confidence": "high", "address": "대한민국 대전광역시 정동 대전"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대접제', '진안읍 운산리에 위치한 작은 저수지(소류지)입니다. 한적한 농촌 풍경과 수변 경관을 감상하며 라이딩 중 잠시 쉬어가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.441056, 35.81535), 4326), false, '{"source": "KOMOOT", "source_ids": ["74"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["검북마을"], "confidence": "high", "address": "대한민국 전북특별자치도 진안군 진안읍 운산리 1265-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대천공용버스터미널', '청도 운문댐 인근에 위치한 버스 터미널입니다. 대중교통을 이용한 자전거 점프나 라이딩 중 식사 및 휴식을 취하기 좋은 거점입니다.', '{transit,restroom,restaurant,cafe,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.914553, 35.716631), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["운문댐", "운문댐하류보유원지"], "confidence": "high", "address": "대한민국 경상북도 청도군 운문면 대천리 1462-116"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대천천', '낙동강 화명생태공원과 금정산을 잇는 도심 속 하천입니다. 하천을 따라 자전거 도로가 잘 조성되어 있어 시원한 풍경을 즐기며 쾌적하게 라이딩하기 좋습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.012533, 35.240662), 4326), false, '{"source": "KOMOOT", "source_ids": ["21"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["화명생태공원", "금정산", "화명수목원"], "confidence": "high", "address": "대한민국 부산광역시 북구 금곡동 1906"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대추리 어도, 담양군', '영산강 자전거길 담양 구간에 위치한 어도(물고기길)입니다. 라이딩 중 영산강의 생태와 시원한 강변 풍경을 감상하며 지나가기 좋은 지점입니다.', '{river,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.954608, 35.294315), 4326), false, '{"source": "KOMOOT", "source_ids": ["188"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/mk/mkeri0q0u8l3jbk9v3f8w7pt37e55qt1-uhi9476422/0?width=1920&crop=false"], "category_raw": "river", "tour_count": 1, "nearby_landmarks": ["영산강", "영산강 자전거길"], "confidence": "medium", "address": "대한민국 전라남도 담양군 봉산면 대추리 855-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('소노문 단양 주차장', '소노문 단양(구 대명리조트) 내에 위치한 대형 주차장입니다. 남한강 자전거길과 단양강 잔도 등 단양 지역 라이딩의 출발지로 활용하기 좋습니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.362769, 36.976493), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["소노문 단양", "단양강 잔도", "남한강 자전거길"], "confidence": "high", "address": "대한민국 충청북도 단양군 단양읍 상진리 4-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대화터미널', '평창 대화면의 버스 터미널로, 라이딩 중 화장실 이용과 휴식이 가능합니다. 주변 대화장과 식당에서 보급을 하거나 타 지역으로 점프(대중교통 연계)할 때 유용한 거점입니다.', '{transit,restroom,rest_area,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.45286, 37.500522), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["대화장", "평창강", "더위사냥 캠핑파크"], "confidence": "high", "address": "대한민국 강원특별자치도 평창군 대화면 대화리 1012-29"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('덕계천 근린공원', '양주 회천신도시 내에 위치한 공원 부지입니다. 덕계천 자전거길과 인접해 있어 라이딩 중 잠시 쉬어가기 좋은 휴식처입니다.', '{park,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.056926, 37.818666), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/a/a9/Deokgye_Stn._Platform.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/86/Deokgye_Stn._Nameplate.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["덕계천 자전거길", "덕계역", "양주회천지구"], "confidence": "high", "address": "대한민국 경기도 양주시 덕계동 940"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('덕곡제', '여수 소라면 덕양리에 위치한 조용한 저수지입니다. 한적한 시골길을 따라 자연을 감상하며 여유롭게 라이딩을 즐기거나 잠시 쉬어가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.623944, 34.779046), 4326), false, '{"source": "KOMOOT", "source_ids": ["2161"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["여수 덕양 곱창골목"], "confidence": "high", "address": "대한민국 전라남도 여수시 소라면 덕양리 448-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('덕산온천', '충남 예산의 유명 온천 단지로, 무료 족욕장과 황톳길이 조성되어 있어 라이딩 중 지친 발의 피로를 풀며 쉬어가기 좋은 휴식처입니다.', '{rest_area,landmark,nature,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.65979, 36.690049), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["수덕사", "충의사", "가야산", "스플라스 리솜"], "confidence": "high", "address": "대한민국 예산군 덕산온천"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('덕수초등학교', '제주 서귀포시 안덕면에 위치한 초등학교입니다. 단산과 산방산, 송악산 방면으로 향하는 제주 남서부 라이딩 시 유용한 이정표가 됩니다.', '{landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.302985, 33.250639), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["단산", "산방산", "송악산"], "confidence": "high", "address": "대한민국 서귀포시 덕수초등학교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('덕풍천둑', '하남시 덕풍천을 따라 이어지는 제방길로, 한강 자전거길과 남한산성 방면을 연결하는 한적하고 경치 좋은 라이딩 코스입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.198005, 37.518401), 4326), false, '{"source": "KOMOOT", "source_ids": ["166"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["덕풍천", "광주향교", "남한산성"], "confidence": "high", "address": "대한민국 경기도 하남시 하사창동 264-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('만덕고개 전망대', '만덕고개 업힐 코스에 위치한 전망데크입니다. 라이딩 후 해운대와 마린시티 등 부산 도심의 탁 트인 풍경을 감상하며 휴식하기 좋습니다.', '{viewpoint,rest_area,mountain}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.056073, 35.214012), 4326), false, '{"source": "KOMOOT", "source_ids": ["453"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["만덕고개", "금정산"], "confidence": "high", "address": "대한민국 부산광역시 동래구 온천동 산153-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('도곡역', '3호선과 수인분당선 환승역인 도곡역입니다. 주말 자전거 휴대 승차가 가능하며, 인근 양재천 자전거길로 진입하기 좋은 거점입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.055466, 37.490633), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/d7/Dogok_Station_3.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b7/Dogoksta01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e3/Seoul-metro-344-Dogok-station-platform-20181123-145202.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e6/道谷駅の4番出入り口.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/31/Dogok_Station_2.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["양재천", "타워팰리스"], "confidence": "high", "address": "대한민국 서울특별시 강남구 도곡동 466-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('도램마을 20단지', '원수산 MTB 공원 입구와 인접한 세종시 도담동의 아파트 단지입니다. 단지 내 상가에 마트가 있어 라이딩 전후 보급이 가능합니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.2647, 36.517466), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["원수산 MTB 공원", "방축천"], "confidence": "high", "address": "대한민국 세종특별자치시 도램마을20단지"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('도량천', '구미 도량동을 가로질러 낙동강으로 이어지는 도심 하천입니다. 가벼운 자전거 산책이나 낙동강 자전거길로 진입하기 위한 연계 코스로 활용하기 좋습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.316438, 36.137191), 4326), false, '{"source": "KOMOOT", "source_ids": ["43"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["도량번개시장", "낙동강"], "confidence": "high", "address": "대한민국 경상북도 구미시 도량동 860-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('도리봉', '이천 원적산 둘레길 임도 코스에 위치한 도리봉입니다. MTB나 그래블 라이딩 시 자연을 만끽하며 지날 수 있는 산악 포인트입니다.', '{mountain,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.425558, 37.334735), 4326), false, '{"source": "KOMOOT", "source_ids": ["272"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["원적산 둘레길", "정개산"], "confidence": "high", "address": "대한민국 경기도 이천시 신둔면 지석리 287-66"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('도봉산', '중랑천 자전거길과 연결되는 서울 북부의 대표적인 명산입니다. 라이더들에게 훌륭한 랜드마크이자 목적지가 되지만, 국립공원 내 자전거 출입은 제한적이니 주의하세요.', '{mountain,landmark,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.046559, 37.689215), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/4/41/Korail-113-Dobongsan-station-sign-20181122-124558.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/19/Korail-Dobongsan-station-platform.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3e/Korail-113-Dobongsan-station-entrance-1-20181122-125116.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f4/도봉산역_환승출구.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/be/Dobongsan.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["도봉산역", "중랑천 자전거길", "도봉천", "무수골"], "confidence": "high", "address": "대한민국 서울특별시 도봉동 16번지 도봉산 도봉구 서울특별시 KR"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('독후산', '전남 나주 반남면에 위치한 작은 야산입니다. 북두저수지와 한적한 시골 농로가 인접해 있어 여유로운 풍경을 감상하며 라이딩하기 좋습니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.651625, 34.920253), 4326), false, '{"source": "KOMOOT", "source_ids": ["1629"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["북두저수지", "반남고분군", "국립나주박물관"], "confidence": "high", "address": "대한민국 전라남도 나주시 반남면 신촌리 671-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('돌거북 정수대', '지역 주민들이 식수를 길어가는 돌거북 모양의 약수터(정수대)입니다. 자전거 라이딩 중 시원한 물을 보충하고 쉬어가기 좋습니다.', '{water_fountain,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.105813, 36.660933), 4326), false, '{"source": "KOMOOT", "source_ids": ["741"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/kt/ktp4bmhf4wixzb4ihlffepzd4pg1mdkz-uhi64861772/0?width=1920&crop=false"], "tips": [{"text": "locals filling up there water here", "author": "Alex Kasch"}], "category_raw": "other_man_made", "tour_count": 1, "nearby_landmarks": ["영강", "구랑리 철로자전거", "카페 하내리"], "confidence": "medium", "address": "대한민국 경상북도 문경시 마성면 하내리 6-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('돌꽃카페', '실내외 정원이 아름다운 식물원 컨셉의 카페입니다. 용담저수지 인근 라이딩 중 커피와 베이커리를 즐기며 힐링하기 좋은 휴식처입니다.', '{cafe,rest_area,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.297472, 37.154931), 4326), false, '{"source": "KOMOOT", "source_ids": ["952"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1f/1f8q6yq81h6pmri9kjxhmdez0503l04pg-uhi73299131/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/l1/l1bq0i6erfimjpcukh61wzwp503l0774-uhi73299134/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/12/12y3zbptv9wxm1ig0snc0r2ypr503l08o0-uhi73299138/0?width=1920&crop=false"], "tips": [{"text": "Worth going for both the indoor and outdoor gardens, coffee and bakery were good enough but it’s definitely the surroundings that make a visit worthwhile! \n\n[NAVER Map]\nDolkkot Cafe\n경기 용인시 처인구 원삼면 이원로 1037-29 돌꽃카페\nhttps://naver.me/FpZ8EjgF", "author": ""}], "category_raw": "cafe", "tour_count": 1, "nearby_landmarks": ["용담저수지", "원삼오토캠핑장"], "confidence": "high", "address": "대한민국 경기도 용인시 처인구 원삼면 문촌리 145-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('돌하르방캠핑장', '제주 서부 내륙 한경면에 위치한 넓은 잔디밭을 갖춘 캠핑장입니다. 자전거 여행 중 텐트를 치고 숙박하며 자연 속에서 휴식하기 좋은 장소입니다.', '{rest_area,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.239883, 33.321264), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["협재해수욕장", "오설록", "유리의성"], "confidence": "high", "address": "대한민국 제주시 돌하르방캠핑장"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동강서원 신도비', '형산강 자전거길 경주 구간에 위치한 동강서원의 신도비입니다. 포항으로 이어지는 길목에 있어 라이딩 중 잠시 쉬며 둘러보기 좋은 역사적 랜드마크입니다.', '{historic,landmark,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.291226, 35.998932), 4326), false, '{"source": "KOMOOT", "source_ids": ["354"], "category_raw": "15", "tour_count": 1, "nearby_landmarks": ["동강서원", "형산강 자전거길", "형산강역사문화관광공원"], "confidence": "high", "address": "대한민국 경상북도 경주시 강동면 유금리 1544-12"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동구릉', '조선 최대 왕릉군이자 유네스코 세계문화유산입니다. 내부 자전거 출입은 불가하지만 매표소 앞 거치대에 주차 후 아름다운 숲길을 도보로 산책하기 좋습니다.', '{historic,landmark,park,nature,parking,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.138156, 37.610521), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["왕숙천", "구리한강시민공원", "동구릉역"], "confidence": "high", "address": "대한민국 경기도 구리시 인창동 412-47"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동그란말림', '이천시 백사면에 위치한 이름처럼 둥근 형태의 작은 야산입니다. 인적이 드문 자연 지형으로, 그래블이나 MTB 라이딩 시 가벼운 산길 코스로 만날 수 있습니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.511393, 37.338372), 4326), false, '{"source": "KOMOOT", "source_ids": ["338"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["백우리 마을", "이천 산수유마을"], "confidence": "high", "address": "대한민국 경기도 이천시 백사면 백우리 13-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동대산', '무룡산과 연계하기 좋은 울산의 대표적인 MTB 명소입니다. 평탄한 테마 임도와 다이내믹한 싱글 코스가 어우러져 초보부터 숙련자까지 라이딩을 즐기기 좋습니다.', '{mountain,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.379271, 35.637271), 4326), false, '{"source": "KOMOOT", "source_ids": ["664"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["무룡산", "마우나오션", "매봉재", "강동해변"], "confidence": "high", "address": "대한민국 울산광역시 북구 대안동 산288-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동두천역 쌈지공원', '1호선 동두천역 앞 쌈지공원입니다. 신천 자전거길과 가까워 전철 점프 및 라이딩 기착지로 활용하기 좋으며, 화장실과 휴식 공간이 있습니다.', '{transit,rest_area,park,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.055233, 37.928222), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/6b/Dgduchst08.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/30/Dgduchst03.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/7b/Dongducheon-GW-O-1.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3e/Dgduchst01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/54/101Dongducheon.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["동두천역", "신천 자전거도로"], "confidence": "high", "address": "대한민국 경기도 동두천시 동두천동 245-164"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동막산', '대구 수성못 동쪽에 위치한 해발 97m의 작은 산입니다. 수성못 둘레길 라이딩 시 주변 자연 경관을 감상하며 가볍게 지나치기 좋습니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.623757, 35.828958), 4326), false, '{"source": "KOMOOT", "source_ids": ["86"], "category_raw": "191", "tour_count": 1, "nearby_landmarks": ["수성못", "수성유원지", "법이산"], "confidence": "high", "address": "대한민국 대구광역시 수성구 두산동 614-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동매역 자전거 보관소', '부산 1호선 동매역으로 각 출구에 자전거 보관소가 있습니다. 주말 라이딩 시 자전거를 싣고 이동하는 지하철 점프 거점으로 유용합니다.', '{transit,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.973267, 35.089754), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/7/75/Dongmae_station_sign_20180521_195051.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/53/Busan-subway-100-Dongmae-station-entrance-5-20180401-122018.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/06/CU_Dongmae-yeok_branch_20180401_121542.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/fb/Dongmae_station_platform_20180521_195021.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a6/Dongmae_Station_exit_1_during_test_drive_period_in_2017.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["사하소방서", "신평종합시장", "신평장림산업단지"], "confidence": "high", "address": "대한민국 부산광역시 동매"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동뫼', '통영 도산면 해안도로 인근에 위치한 작은 언덕(산)입니다. 자전거 라이딩 중 남해 바다의 탁 트인 경치를 감상하며 지나가기 좋은 자연 지점입니다.', '{mountain,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.307655, 34.895566), 4326), false, '{"source": "KOMOOT", "source_ids": ["480"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["도산면 해안도로", "남해 바다"], "confidence": "medium", "address": "대한민국 경상남도 통영시 도산면 저산리 163-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동백호수공원', '신갈천 자전거길과 연결되어 기흥호수공원까지 이어지는 라이딩 코스의 주요 거점입니다. 공원 내부는 산책로 위주이므로 자전거에서 내려 호수 주변에서 휴식하기 좋습니다.', '{lake,park,rest_area,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.149838, 37.275595), 4326), false, '{"source": "KOMOOT", "source_ids": ["49"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["신갈천 자전거길", "이마트 동백점"], "confidence": "high", "address": "대한민국 경기도 용인시 기흥구 중동 843"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동산', '순창군 복흥면 동산리에 위치한 작은 산(동산)입니다. 한적한 시골길 라이딩 중 주변 자연 경관을 감상하며 지나치기 좋은 지점입니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.926909, 35.459383), 4326), false, '{"source": "KOMOOT", "source_ids": ["439"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["동산마을", "동산저수지"], "confidence": "medium", "address": "대한민국 전북특별자치도 순창군 복흥면 동산리 140-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동산방죽', '상주시 화북면 운흥리에 위치한 작은 저수지입니다. 고즈넉한 농촌 풍경과 수변 경관을 감상하며 라이딩 중 가볍게 쉬어가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.824556, 36.600979), 4326), false, '{"source": "KOMOOT", "source_ids": ["330"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["운흥2리 마을회관", "용화보건진료소"], "confidence": "high", "address": "대한민국 경상북도 상주시 화북면 운흥리 141-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동상호', '수려한 산세와 맑은 물이 어우러진 아름다운 호수입니다. 대아저수지와 이어지는 호반도로는 경치가 뛰어나 자전거 라이딩 코스로 인기가 높습니다.', '{lake,viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.278296, 35.951346), 4326), false, '{"source": "KOMOOT", "source_ids": ["480"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["대아저수지", "위봉폭포", "위봉산성"], "confidence": "high", "address": "대한민국 전북특별자치도 완주군 동상면 수만리 665-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동송시외버스터미널', '철원 DMZ 및 한탄강 자전거길 라이딩 시 버스 점프(출발 및 복귀) 지점으로 유용한 핵심 교통 거점입니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.218301, 38.207872), 4326), false, '{"source": "KOMOOT", "source_ids": ["857"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1g/1gc9uvlc2563m18pqxeu9fnx13qkyad2s-uhi31585429/0?width=1920&crop=false"], "tips": [{"text": "Dongsong Bus Terminal", "author": ""}], "category_raw": "facilities", "tour_count": 1, "nearby_landmarks": ["금학산", "노동당사", "동송전통시장"], "confidence": "high", "address": "대한민국 강원특별자치도 철원군 동송읍 이평리 680-84"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동아아파트', '군산 소룡동 생태터널과 월명공원 인근의 아파트 단지입니다. 주변에 편의점과 식당이 있어 라이딩 중 길 찾기 기준점이나 가벼운 보급처로 활용하기 좋습니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.684362, 35.970139), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["소룡동 생태터널", "월명공원"], "confidence": "high", "address": "대한민국 군산시 동아아파트"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동오역', '부용천 자전거길과 인접한 의정부 경전철 동오역입니다. 일요일과 공휴일에 자전거 승차가 가능하여 점프(대중교통 연계)나 휴식, 만남의 장소로 활용하기 좋습니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.057037, 37.745203), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/c/ce/U118_Dongo_01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/33/Dong_O_station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/ce/U_Line_Dongo_Station.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["부용천 자전거길", "의정부버스터미널"], "confidence": "high", "address": "대한민국 의정부시 신곡동 동오"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('목천 동우아파트', '천안 목천읍에 위치한 주거 단지입니다. 독립기념관이나 병천 방면으로 향하는 라이딩 시 경로 확인을 위한 이정표나 출발지로 활용할 수 있습니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.194987, 36.771032), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["독립기념관", "천안종합휴양관광지"], "confidence": "high", "address": "대한민국 천안시 동우아파트"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동진대교', '창원과 고성을 잇는 교량으로 ''한국의 아름다운 길 100선''에 선정된 해안도로 구간입니다. 수려한 바다 풍경을 감상하며 라이딩하기 좋은 명소입니다.', '{bridge,viewpoint,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.464039, 35.077073), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["창포만", "동해면 해안도로"], "confidence": "high", "address": "대한민국 경상남도 창원시 마산합포구 진전면 창포리 산36-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동촌', '금호강 자전거길이 지나는 동촌 일대입니다. 인근에 동촌유원지와 해맞이다리, 동촌역이 있어 라이딩 중 휴식하거나 대중교통을 연계하기 좋은 거점입니다.', '{river,park,rest_area,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.650399, 35.886026), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["동촌유원지", "동촌해맞이다리", "동촌역", "금호강 자전거길"], "confidence": "high", "address": "대한민국 대구광역시 동구 검사동 991-123"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동탄 버스공영차고지', '화성시 금곡동에 위치한 버스 공영차고지입니다. 오산천 자전거길과 인접해 있어 라이딩 중 위치를 확인하거나 대중교통을 연계할 때 참고하기 좋습니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.078605, 37.185927), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["동탄신도시", "오산천 자전거길"], "confidence": "high", "address": "대한민국 경기도 화성시 금곡동 90-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동탄호수공원', '평탄하고 안전한 자전거 전용도로가 조성된 도심 속 라이딩 명소입니다. 아름다운 호수 경관을 감상하며 쉴 수 있고, 화장실과 카페 등 편의시설이 풍부합니다.', '{lake,park,rest_area,restroom,cafe,parking,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.101022, 37.16769), 4326), false, '{"source": "KOMOOT", "source_ids": ["153"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["오산천 자전거길", "장지천 자전거길", "레이크꼬모"], "confidence": "high", "address": "대한민국 경기도 화성시 동탄호수2길 25"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동호이주단지', '영주댐 건설로 인한 수몰민을 위해 조성된 마을입니다. 영주댐 일주 자전거 코스의 주요 기점이자 동호대교부터 자전거길이 시작되는 곳입니다.', '{rest_area,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.681335, 36.735603), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["영주댐", "동호대교", "용마루공원"], "confidence": "high", "address": "대한민국 영주시 동호이주단지"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동호해변 인증센터', '동해안 자전거길 강원 구간의 무인 인증센터입니다. 언덕 위에 자리해 동호해변의 탁 트인 바다 풍경을 조망하며 쉬어가기 좋습니다.', '{checkpoint,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.67951, 38.061977), 4326), false, '{"source": "KOMOOT", "source_ids": ["733"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/15/15bdg23mu183p5z74t9cgnx0z3r9plwy3-uhi32547648/0?width=1920&crop=false"], "tips": [{"text": "Dongho Beach Bicycle Certification Center", "author": ""}], "category_raw": "facilities", "tour_count": 1, "nearby_landmarks": ["동호해변", "양양국제공항", "수산항"], "confidence": "high", "address": "대한민국 강원특별자치도 양양군 손양면 동호리 191-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('돼지생막창', '청도 와인터널 인근에 위치한 돼지 생막창 전문 식당입니다. 라이딩 중 든든하게 고기를 구워 먹으며 체력을 보충하기 좋습니다.', '{restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.725265, 35.707055), 4326), false, '{"source": "KOMOOT", "source_ids": ["424"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1x/1xpehuyfs3gvxm129trh9f49z54qhvyfn-uhi78956655/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/bw/bwhit2ey4utf1n8ed3a00gfu454qhw6b0-uhi78956662/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/dl/dlu9qu0tft2skay2yh183n5g54qhwa26-uhi78956663/0?width=1920&crop=false"], "category_raw": "restaurant", "tour_count": 1, "nearby_landmarks": ["청도 와인터널"], "confidence": "medium", "address": "대한민국 경상북도 청도군 화양읍 송금리 455-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('두호남부초등학교', '포항 영일대해수욕장과 환호공원 인근에 위치한 초등학교입니다. 자전거 라이딩 시 위치를 가늠하는 랜드마크로 참고하기 좋습니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.375124, 36.060078), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["영일대해수욕장", "환호공원"], "confidence": "high", "address": "대한민국 포항시 두호남부초등학교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('둔내', '횡성군 둔내면 시내로 편의점, 식당, 카페 등 다양한 보급처가 밀집해 있어 자전거 라이딩 중 휴식과 식사를 하기에 매우 좋은 거점입니다.', '{convenience_store,cafe,restaurant,restroom,rest_area,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.221194, 37.510426), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["둔내역", "둔내버스터미널", "웰리힐리파크"], "confidence": "high", "address": "대한민국 강원특별자치도 횡성군 둔내면 자포곡리 427-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('둔촌동역', '지하철 5호선 둔촌동역입니다. 주말 라이딩 시 자전거를 싣고 점프(대중교통 이동)하기 좋으며, 인근 올림픽공원이나 일자산으로 연계하기 편리합니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.13625, 37.527801), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/e/e2/Seoul-metro-P549-Dunchon-dong-station-platform-20180915-092648.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d1/Seoul-metro-P549-Dunchon-dong-station-entrance-1-20180915-092112.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3d/Dunchondong_Sta_Line5_SEOUL.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/ed/Seoul-metro-P549-Dunchon-dong-station-sign-20180915-092620.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["올림픽공원", "일자산"], "confidence": "high", "address": "대한민국 서울특별시 강동구 둔촌동 416"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('뒷동산', '이천역 뒤편에 자리한 해발 80m의 작은 야산입니다. 설봉산으로 이어지는 가벼운 MTB나 그래블 라이딩 코스로 연계하기 좋습니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.437681, 37.268648), 4326), false, '{"source": "KOMOOT", "source_ids": ["327"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["이천역", "이천시청", "솔미산"], "confidence": "high", "address": "대한민국 경기도 이천시 증일동 산21-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('간절곶 등대', '동해안 라이딩 중 만나는 일출 명소 간절곶의 상징적인 등대입니다. 탁 트인 바다 풍경을 감상하며 사진을 남기고 쉬어가기 좋은 랜드마크입니다.', '{landmark,viewpoint,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.360942, 35.35891), 4326), false, '{"source": "KOMOOT", "source_ids": ["420"], "category_raw": "19", "tour_count": 1, "nearby_landmarks": ["간절곶 소망우체통", "간절곶 공원", "진하해수욕장"], "confidence": "high", "address": "대한민국 울산광역시 울주군 서생면 대송리 산110-22"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('등촌잔등산', '이천시 신둔면에 위치한 해발 93.7m의 작은 산입니다. 고도가 낮아 가볍게 넘기 좋으며, 원적산 및 정개산과 연계한 오프로드 라이딩 코스로 적합합니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.4543, 37.329742), 4326), false, '{"source": "KOMOOT", "source_ids": ["96"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["원적산", "정개산", "천덕봉"], "confidence": "high", "address": "대한민국 경기도 이천시 신둔면 장동리 2-11"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('디지털미디어시티', '자전거 도로가 잘 정비되어 있고 따릉이 대여소가 많아 도심 라이딩에 적합합니다. 불광천과 난지한강공원, 월드컵공원 자전거길로 진입하기 좋은 주요 거점입니다.', '{landmark,transit,convenience_store,cafe,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.901357, 37.576254), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/3/33/Korail_DMC_Station.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f4/Digital_Media_City_Station_20220701_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/06/Seoul-metro-618-Digital-media-city-station-entrance-4-20191023-090140.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/61/Korail_Gyeongui_Line_Digital_Media_City_Station_Platform_no.4.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/25/디지털미디어시티역_6호선_승강장.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["월드컵공원", "난지한강공원", "불광천", "하늘공원"], "confidence": "high", "address": "대한민국 서울특별시 디지털미디어시티"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('거제 디큐브백화점', '거제 장평동에 위치한 지역 유일의 백화점입니다. 내부에 식당가, 카페, 대형 마트가 있어 라이딩 중 쾌적하게 휴식하며 식사와 보급을 해결하기 좋습니다.', '{landmark,restaurant,cafe,restroom,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.61597, 34.890666), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["고현항", "삼성중공업 거제조선소", "고현버스터미널"], "confidence": "high", "address": "대한민국 거제시 디큐브백화점"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('딴산 유원지', '화천 산소 100리 자전거길에 위치한 유원지입니다. 북한강과 웅장한 인공폭포 경치를 감상하며 화장실을 이용하고 쉬어가기 좋습니다.', '{rest_area,viewpoint,park,mountain,river,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.75972, 38.122506), 4326), false, '{"source": "KOMOOT", "source_ids": ["122"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["딴산 인공폭포", "화천 산소100리길", "처녀고개", "꺼먹다리"], "confidence": "high", "address": "대한민국 강원특별자치도 화천군 화천읍 대이리 5-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('진도 갈두항', '진도 지산면 보전리의 ''땅끝에마을'' 인근 소형선 부두(진도 갈두항)입니다. 인적이 드문 한적한 해안가로, 라이딩 중 탁 트인 바다를 조망하며 쉬어가기 좋은 반환점입니다.', '{viewpoint,nature,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.161332, 34.482556), 4326), false, '{"source": "KOMOOT", "source_ids": ["412"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["땅끝에마을", "진도 갈두항"], "confidence": "high", "address": "대한민국 전라남도 진도군 지산면 보전리 1222-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('라파 서울 클럽하우스', '가로수길에 위치한 자전거 라이더들의 성지입니다. 프리미엄 사이클링 의류 쇼핑과 함께 카페에서 커피를 마시며 휴식하기 좋은 공간입니다.', '{cafe,bike_shop,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.022296, 37.521197), 4326), false, '{"source": "KOMOOT", "source_ids": ["239"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/qa/qaskni4lr3161m536poncyzya40gjgko9-uhi45222028/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/qe/qeyekvo386u114iolpmshsfyp40gjgki0-uhi45222026/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/w0/w05hu86ewq2xrfko1kgewmxm40gjgk7t-uhi45222025/0?width=1920&crop=false"], "tips": [{"text": "Seoul loves road cycling. The ambiance here is exciting and colorful, akin to the Gangnam district, where Rapha Seoul is located. The Clubhouse''s position also gives visitors convenient access to the bike route that runs alongside the Han River, making Rapha Seoul an excellent stop for both riders and shoppers looking for a coffee and a bite to eat.\r\n\r\nRapha Seoul offers rides, special events, and live race broadcasts, as well as acting as the headquarters of the Rapha Cycling Club''s Seoul branch (RCC). Rides roll out to the adjacent Namsan and Bukak mountains, which provide stunning views of the cityscape.", "author": "Rapha"}], "category_raw": "cafe", "tour_count": 1, "nearby_landmarks": ["가로수길", "잠원한강공원"], "confidence": "high", "address": "대한민국 서울특별시 강남구 압구정로10길 35-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('롯데마트 제주점', '제주 시내 노형동에 위치한 대형 마트입니다. 라이딩 중 식수와 간식 등 보급품을 구매하고 화장실을 이용하며 휴식하기 좋습니다.', '{convenience_store,restroom,restaurant,parking,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.482187, 33.482041), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["노형오거리", "이마트 신제주점"], "confidence": "high", "address": "대한민국 제주시 롯데마트"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('마곡나루역', '9호선·공항철도 환승역입니다. 따릉이 대여소가 많고 한강 자전거길 접근성이 뛰어나 라이딩 시작점이나 대중교통 점프 거점으로 매우 유용합니다.', '{transit,restroom,convenience_store,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.827825, 37.566226), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/8/81/Magongnaru-station_20140524_195434.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/4f/20250508_9호선_일반_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/34/Magongnaru-station_20140524_195716.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0a/20250508_마곡나루역_9호선_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f8/20240206_9호선_마곡나루역_급행_승강장.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["서울식물원", "마곡나들목"], "confidence": "high", "address": "대한민국 서울특별시 강서구 마곡동 761-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('마둔저수지', '서운산 자락에 위치한 경치 좋은 저수지로 6.5km의 둘레길과 월동천 자전거도로가 연결되어 있습니다. 배티고개 등 업힐 코스와 연계하여 풍경을 즐기며 라이딩하기 좋습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.313399, 36.970074), 4326), false, '{"source": "KOMOOT", "source_ids": ["880"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["서운산", "배티고개", "석남사"], "confidence": "high", "address": "대한민국 경기도 안성시 금광면 장죽리 132-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('마산', '김포 한강신도시 마산동의 지명 유래가 된 도심 속 야산입니다. 고도가 낮아 가벼운 산악 자전거(MTB) 라이딩이나 산책 코스로 연계하기 좋습니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.644221, 37.640652), 4326), false, '{"source": "KOMOOT", "source_ids": ["916", "413"], "image_urls": ["https://photos.komoot.de/wiki/commons/b/b4/Gimpo_Gold_Line_Masan_Station3.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["마산역(김포골드라인)", "은여울공원", "솔터체육공원"], "confidence": "high", "address": "대한민국 김포시 마산"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('마산', '가평 호명산 인근 명지지맥에 위치한 산봉우리입니다. 주로 MTB나 산악 자전거 코스로 활용되며 자연 속 숲길 라이딩을 즐길 수 있습니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.443466, 37.762136), 4326), false, '{"source": "KOMOOT", "source_ids": ["916", "413"], "image_urls": ["https://photos.komoot.de/wiki/commons/b/b4/Gimpo_Gold_Line_Masan_Station3.JPG?width=1920&crop=false"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["호명산", "상천역", "청평호"], "confidence": "high", "address": "대한민국 경기도 가평군 청평면 상천리 산422-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('마산', '경기도 여주시 흥천면 계신리에 위치한 작은 산(일명 마봉)입니다. 한적한 시골길 라이딩 중 만날 수 있는 가벼운 업힐 코스입니다.', '{mountain}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.53404, 37.380239), 4326), false, '{"source": "KOMOOT", "source_ids": ["916", "413"], "image_urls": ["https://photos.komoot.de/wiki/commons/b/b4/Gimpo_Gold_Line_Masan_Station3.JPG?width=1920&crop=false"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["계신리 마애여래입상", "계장천"], "confidence": "high", "address": "대한민국 경기도 여주시 흥천면 계신리 142-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('장군목 인증센터', '섬진강 자전거길 종주를 위한 장군목 무인 인증센터입니다. 마실캠핑장 내에 위치하여 라이딩 중 스탬프를 찍고 쉬어가기 좋습니다.', '{checkpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.201491, 35.460511), 4326), false, '{"source": "KOMOOT", "source_ids": ["611"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1a/1a098w0ynpxp51ld3gff5p2m7p5e57zsll-uhi87511896/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 1, "nearby_landmarks": ["섬진강마실캠핑장", "장군목 유원지", "요강바위"], "confidence": "high", "address": "대한민국 전북특별자치도 순창군 동계면 장군목길"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('마전역', '인천 2호선 마전역입니다. 화장실 이용이나 일행과의 만남 장소로 활용하기 좋으며, 역 주변 상권에서 라이딩 중 필요한 식수와 간식을 보급할 수 있습니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.667253, 37.597571), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/9/95/ITC-Majeon_Stn-Gate.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/77/Q20823458_Majeon_A01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f8/Q20823458_Majeon_Station_Exit_1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/80/Q20823458_Majeon_Station_Exit_2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d1/Q20823458_Majeon_Station_Exit_3.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["능내공원", "마전중학교", "검단복지회관"], "confidence": "high", "address": "대한민국 인천광역시 서구 완정로 68"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('비비정', '만경강 자전거길을 대표하는 랜드마크로, 탁 트인 강변 풍경과 일몰을 감상하며 라이딩 중 쉬어가기 좋은 역사적인 정자입니다.', '{historic,viewpoint,rest_area,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.068695, 35.899259), 4326), false, '{"source": "KOMOOT", "source_ids": ["297"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1n/1njfdzgmv6ioq91ifhqj4ibwi5jql8wzh-uhi95212835/0?width=1920&crop=false"], "category_raw": "man_made_monument", "tour_count": 1, "nearby_landmarks": ["비비정 예술열차", "만경강", "신천습지"], "confidence": "high", "address": "대한민국 전북특별자치도 완주군 삼례읍 후정리 132-62"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('만날고개입구', '마산 지역 라이더들이 즐겨 찾는 만날고개 업힐 코스의 시작점입니다. 무학산 둘레길과 만날근린공원으로 이어지며, 가파른 경사로 인해 훈련 장소로 인기가 높습니다.', '{checkpoint,transit,mountain,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.552013, 35.185827), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["만날근린공원", "무학산", "경남대학교"], "confidence": "high", "address": "대한민국 경상남도 창원시 마산합포구 월영동 207"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('만리포해수욕장', '상점과 식당이 늘어선 산책로가 조성되어 있어 라이딩 중 보급과 휴식을 취하기 좋은 해변입니다.', '{beach,restaurant,convenience_store,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.144232, 36.787391), 4326), false, '{"source": "KOMOOT", "source_ids": ["1132"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/17/17sdet76u9zahnx187vdu10174a4mix4j-uhi53423040/0?width=1920&crop=false"], "tips": [{"text": "Small Beach with a prominade offering stores and restaurants", "author": "Matthias Maile"}], "category_raw": "beach", "tour_count": 1, "nearby_landmarks": ["천리포수목원", "천리포해수욕장", "태안해안국립공원"], "confidence": "high", "address": "대한민국 충청남도 태안군 소원면 의항리 1183"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('만봉저수지', '나주시 봉황면에 위치한 수질이 맑고 경관이 뛰어난 대형 저수지입니다. 영산강 자전거길과 이어지는 만봉천 라이딩 코스에서 경치를 감상하며 쉬어가기 좋습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.771628, 34.909946), 4326), false, '{"source": "KOMOOT", "source_ids": ["1022"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["덕룡산", "만봉천", "봉황 고인돌공원"], "confidence": "high", "address": "대한민국 전라남도 나주시 봉황면 만봉리 산185-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('말모이산', '이천 설봉공원 인근에 위치한 해발 93m의 작은 동산입니다. 설봉산이나 설봉공원 방향으로 라이딩할 때 가볍게 지나는 오르막 코스입니다.', '{mountain}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.433516, 37.280222), 4326), false, '{"source": "KOMOOT", "source_ids": ["356"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["설봉공원", "설봉산"], "confidence": "high", "address": "대한민국 경기도 이천시 관고동 산52-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('망금산', '이충무공 벽파진전첩비가 세워져 있는 벽파항 인근의 작은 산입니다. 진도 해안도로 라이딩 중 역사적 의미를 되새기며 탁 트인 바다 전망을 감상하기 좋습니다.', '{mountain,historic,viewpoint,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.343695, 34.538659), 4326), false, '{"source": "KOMOOT", "source_ids": ["322"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["이충무공 벽파진전첩비", "벽파항", "벽파정"], "confidence": "high", "address": "대한민국 전라남도 진도군 고군면 벽파리 682-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('망산', '남해군 창선면 적량마을 뒤편에 위치한 망산입니다. 남파랑길 37코스가 지나며, 한적한 어촌마을과 남해 바다의 탁 트인 경치를 감상할 수 있는 라이딩 포인트입니다.', '{mountain,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.059787, 34.8609), 4326), false, '{"source": "KOMOOT", "source_ids": ["393"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["적량항", "적량마을", "적량보건진료소"], "confidence": "high", "address": "대한민국 경상남도 남해군 창선면 흥선로1198번길 9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('망원유수지 체육공원', '홍제천과 한강 자전거길이 만나는 방울나들목 인근의 체육공원입니다. 자전거 트랙, 음수대, 화장실 등이 잘 갖춰져 있어 라이딩 중 휴식하기 좋습니다.', '{park,rest_area,restroom,water_fountain}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.899121, 37.555993), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["망원한강공원", "홍제천", "방울나들목"], "confidence": "high", "address": "대한민국 서울특별시 마포구 망원동 420-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('매월저수지', '곡성군 입면에 위치한 한적한 저수지로 수려한 자연 경관을 즐길 수 있습니다. 인근에 공중화장실이 있어 라이딩 중 잠시 쉬어가기 좋습니다.', '{lake,nature,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.20152, 35.280599), 4326), false, '{"source": "KOMOOT", "source_ids": ["1046"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["흑석저수지", "동악산"], "confidence": "high", "address": "대한민국 전라남도 곡성군 입면 매월리 산113-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('매포천', '단양 도담삼봉으로 이어지는 생태하천입니다. 하천을 따라 자전거 도로와 생태공원이 조성되어 있어 자연을 즐기며 쾌적하게 라이딩하기 좋습니다.', '{river,park,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.322193, 37.019041), 4326), false, '{"source": "KOMOOT", "source_ids": ["364"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["도담삼봉", "남한강"], "confidence": "high", "address": "대한민국 충청북도 단양군 매포읍 우덕리 120-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('맹방해수욕장', '동해안 자전거길 코스에 위치한 해변으로, 방탄소년단(BTS) 앨범 촬영지로 유명합니다. 탁 트인 바다 풍경을 감상하며 라이딩 중 쉬어가기 좋습니다.', '{beach,viewpoint,rest_area,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.23142, 37.390461), 4326), false, '{"source": "KOMOOT", "source_ids": ["112"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["한재공원 인증센터", "덕봉산"], "confidence": "high", "address": "대한민국 강원특별자치도 삼척시 근덕면 하맹방리 221-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('먹골역', '지하철 7호선 먹골역입니다. 주말과 공휴일에 자전거 휴대 승차가 가능하며, 출구 인근에 공공자전거 따릉이 대여소가 있어 연계 이용이 편리합니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.077608, 37.611436), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/1/13/718_Meokgol.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bf/Seoul-metro-718-Meokgol-station-platform-20181122-150028.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2e/Seoul-metro-718-Meokgol-station-entrance-6-20181122-150352.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["먹골역 7번 출구", "중랑천 자전거길"], "confidence": "high", "address": "대한민국 서울특별시 묵동 239-169번지 지층 중랑구 서울특별시 KR"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('안반데기 멍에전망대 (철거)', '극악의 업힐로 유명한 안반데기 코스의 정상 뷰포인트였습니다. 2023년 4월 철거되어 출입이 불가하지만, 주변 고랭지 배추밭과 풍력발전기 풍경은 여전히 훌륭합니다.', '{viewpoint,landmark,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.741486, 37.626113), 4326), false, '{"source": "KOMOOT", "source_ids": ["890"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["안반데기", "일출전망대", "고루포기산"], "confidence": "high", "address": "대한민국 강원특별자치도 강릉시 왕산면 대기리 2214-391"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('메타세쿼이아길 인증센터', '영산강 자전거길 종주를 위한 필수 무인 인증센터입니다. 아름다운 메타세쿼이아 가로수길 인근에 위치하며, 섬진강 자전거길과 연결되는 분기점입니다.', '{checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.01731, 35.33233), 4326), false, '{"source": "KOMOOT", "source_ids": ["334"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/f5/f5jkpw00187mi1s4ywpe2y1637e4wg3i-uhi9476388/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1x/1x1ci7u7ev33xygha4y3y8is237e4wh31-uhi9476389/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1t/1tbci3jfm1y3im09gbbyd2r5i37e4wiod-uhi9476390/0?width=1920&crop=false"], "category_raw": "trail", "tour_count": 1, "nearby_landmarks": ["메타세쿼이아 가로수길", "금월교"], "confidence": "high", "address": "대한민국 전라남도 담양군 담양읍 학동리 4-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('명수당', '한국외대 글로벌캠퍼스 내 위치한 연못으로, 메타세쿼이아 길과 한옥이 어우러진 풍경이 아름답습니다. 캠퍼스 라이딩 중 경치를 감상하며 사진을 남기기 좋은 포토 스팟입니다.', '{lake,park,nature,landmark,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.27047, 37.338576), 4326), false, '{"source": "KOMOOT", "source_ids": ["271"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["한국외국어대학교 글로벌캠퍼스"], "confidence": "high", "address": "대한민국 경기도 용인시 처인구 모현읍 왕산리 880"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('명일역', '지하철 5호선 명일역입니다. 대중교통 연계(점프) 및 라이딩 모임 장소로 적합하며, 인근 상권에서 식수와 행동식을 보급하기 좋습니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.144082, 37.55196), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/6d/Seoul-metro-551-Myeongil-station-entrance-4-20180914-122700.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3d/Nearby_Myeongil_Subway_Station_-_panoramio.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0a/Seoul-metro-551-Myeongil-station-sign-20180914-122250.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/4c/Seoul-metro-551-Myeongil-station-platform-20180914-122322.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["명일전통시장", "래미안솔베뉴"], "confidence": "high", "address": "대한민국 서울특별시 강동구 양재대로 1640"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('모란', '탄천 자전거길과 인접한 교통 요지이자 모란시장이 위치한 지역입니다. 라이딩 중 식사나 장터 구경을 하며 휴식하거나 전철(모란역)을 연계하기 좋습니다.', '{transit,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.128977, 37.432217), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/4/4f/20240902_수인분당선_모란역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/35/20240902_8호선_모란역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/52/20240902_수인분당선_모란역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/96/Korail-Bundang-line-K225-Moran-station-entrance-02-20181124-145904.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/47/20240902_8호선_모란역_역명판.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["모란역", "모란민속5일장", "탄천 자전거길"], "confidence": "high", "address": "대한민국 성남시 모란"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('모슬포우체국', '제주환상자전거길 인근의 100년 역사를 지닌 우체국입니다. 라이딩 중 불필요한 짐을 택배로 보내거나 ATM을 이용하기 좋으나, 점심시간(12~13시) 휴무에 주의하세요.', '{historic,landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.255673, 33.222664), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["모슬포항", "운진항", "대정읍사무소"], "confidence": "high", "address": "대한민국 제주특별자치도 서귀포시 대정읍 상모리 3943-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('목계솔밭캠핑장', '남한강 자전거길에 위치해 라이딩 중 휴식이나 1박 캠핑을 즐기기 좋은 대규모 캠핑장입니다. 화장실, 매점, 식수대 등 편의시설이 잘 갖춰져 있습니다.', '{convenience_store,restroom,water_fountain,rest_area,park,nature,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.8793, 37.072205), 4326), false, '{"source": "KOMOOT", "source_ids": ["152"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/g3/g340s1f3xwlh1dho84po0vifz37enql1g-uhi9479579/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/u5/u5frfqjy1aig1dtakan5httpl37enqni3-uhi9479581/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 1, "nearby_landmarks": ["남한강", "목계나루", "비내섬"], "confidence": "high", "address": "대한민국 충청북도 충주시 중앙탑면 장천리 399"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('목동초교·베라체 정류장', '화성 동탄신도시 목동초등학교와 베라체 아파트 인근에 위치한 버스 정류장입니다. 라이딩 중 대중교통 연계 및 위치 확인용 웨이포인트로 참고할 수 있습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.12444, 37.190153), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["동탄목동초등학교", "동탄2신도시베라체아파트", "동탄목동이음터"], "confidence": "high", "address": "대한민국 화성시 베라체.목동초"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('목포', '영산강 자전거길 종주의 주요 출발 및 도착지이자 KTX 점프(이동) 거점인 도시입니다. 목포역 주변으로 식당과 숙박 등 편의시설이 풍부합니다.', '{transit,landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.386981, 34.792287), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/a/a6/Mokpo_station.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/af/Mokpo_Station_20241005_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0b/Korail_Honam_Line_Mokpo_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/53/목포역_(1914년).jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/be/Mokpo_Station_20241005_003.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["목포역", "유달산", "목포항"], "confidence": "high", "address": "대한민국 전라남도 목포시 호남동 138"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('목행교 분기점', '남한강 자전거길 종주 시 충주댐과 탄금대 방향 코스가 갈라지는 목행교 남단의 주요 분기점입니다.', '{bridge,checkpoint,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.932327, 37.016242), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["목행교", "목행대교", "남한강"], "confidence": "high", "address": "대한민국 충청북도 충주시 목행동 166-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('목행(시외방향)', '남한강 자전거길 목행교 인근에 위치한 버스 정류장입니다. 충주댐이나 탄금대로 향하는 길목에 있어 대중교통 연계 및 잠시 쉬어가기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.916638, 37.004224), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["목행역(폐역)", "목행교", "남한강 자전거길"], "confidence": "high", "address": "대한민국 충주시 목행역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('몽촌토성역', '올림픽공원과 평화의 문으로 바로 연결되는 8호선 지하철역입니다. 주말과 공휴일에 자전거 휴대 승차가 가능해 올림픽공원 연계 라이딩의 출발지로 유용합니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.112688, 37.517482), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/8/88/813_Mongchontoseong_Exit_1.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/ff/Seoul-metro-813-Mongchontoseong-station-platform-20181125-123038.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e8/Seoul-metro-813-Mongchontoseong-station-entrance-4-20181125-123526.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3e/813_mongchon_01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d6/813_Mongchontoseong_Waiting_Room.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["올림픽공원", "평화의 문", "몽촌토성"], "confidence": "high", "address": "대한민국 서울특별시 송파구 올림픽로 지하 383"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('몽탄대교 북단', '영산강 자전거길 종주 코스 중 나주와 무안을 잇는 몽탄대교의 북단입니다. 탁 트인 영산강 풍경을 감상하며 달리기 좋은 주요 기점입니다.', '{bridge,landmark,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.532527, 34.900208), 4326), false, '{"source": "KOMOOT", "source_ids": ["502"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/oo/oo9j829wqx5j1g2lngbjz6q0937e3zr0n-uhi9476279/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 1, "nearby_landmarks": ["영산강 자전거길", "몽탄대교", "영산강"], "confidence": "high", "address": "대한민국 전라남도 나주시 동강면 옥정리 1123-44"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('묘당산', '전남 보성군 회천면 해안도로 인근에 위치한 해발 19.2m의 아주 낮은 야산입니다. 남해안 자전거 종주나 보성 해안 라이딩 시 가볍게 스쳐 지나가는 지형지물입니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.136423, 34.702687), 4326), false, '{"source": "KOMOOT", "source_ids": ["674"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["율포해수욕장", "남해안 해안도로"], "confidence": "high", "address": "대한민국 전라남도 보성군 회천면 서당리 597"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('무악재', '서대문구 홍제동과 종로구를 잇는 통일로의 대표적인 고개입니다. 차량 통행이 많고 경사가 제법 있어 도심 라이딩 시 주의가 필요한 업힐 구간입니다.', '{mountain,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.950322, 37.582308), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/3/35/Muakjae_Station_3.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/5b/Seoul-metro-325-Muakjae-station-entrance-1-20191022-141758.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9b/Seoul-metro-325-Muakjae-station-entrance-2-20191022-141910.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/4d/Seoul-metro-325-Muakjae-station-sign-20191022-142336.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2f/Seoul-metro-325-Muakjae-station-platform-20191022-142500.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["독립문", "안산", "인왕산", "무악재역"], "confidence": "high", "address": "대한민국 서울특별시 서대문구 홍제동 25-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('무전수변공원', '통영 바다를 따라 조성된 해안 산책로가 있는 수변공원입니다. 자전거 보관소와 화장실이 마련되어 있어 해안도로 라이딩 중 노을을 감상하며 쉬어가기 좋습니다.', '{park,rest_area,restroom,viewpoint,beach}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.419151, 34.859843), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["새통영병원", "롯데마트 통영점"], "confidence": "high", "address": "대한민국 통영시 무전수변공원"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('무주향교', '무주 남대천 자전거길 인근에 위치한 조선시대 교육기관입니다. 고즈넉한 한옥의 정취를 느끼며 라이딩 중 가볍게 둘러보고 쉬어가기 좋은 역사 명소입니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.66593, 36.007841), 4326), false, '{"source": "KOMOOT", "source_ids": ["242"], "category_raw": "15", "tour_count": 1, "nearby_landmarks": ["남대천", "김환태문학관", "최북미술관", "향로산"], "confidence": "high", "address": "대한민국 전북특별자치도 무주군 무주읍 읍내리 265-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('무주호', '적상산 업힐 코스와 연계하기 좋은 고즈넉한 인공 호수입니다. 라이딩 중 무주호 공원에 들러 산세가 비치는 아름다운 풍경을 감상하며 휴식하기 좋습니다.', '{lake,park,nature,rest_area,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.713704, 35.963858), 4326), false, '{"source": "KOMOOT", "source_ids": ["1041"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["적상산", "무주 전력홍보관"], "confidence": "high", "address": "대한민국 전북특별자치도 무주군 적상면 포내리 산18-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('묵4리.현덕', '용인 묵리 임도(MTB 및 그래블 코스) 인근에 위치한 버스정류장입니다. 라이딩 중 위치를 파악하거나 일행과 합류하는 체크포인트로 활용하기 좋습니다.', '{transit,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.235392, 37.179063), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["묵리 임도"], "confidence": "high", "address": "대한민국 경기도 용인시 처인구 이동읍 묵리 산74-13"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('문구산', '해발 153.6m의 낮은 산으로 보성다향고등학교 인근에 있습니다. 고도가 낮아 가벼운 업힐 코스나 라이딩 중 경유지로 적합합니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.09651, 34.761637), 4326), false, '{"source": "KOMOOT", "source_ids": ["1091"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["보성다향고등학교", "보성 생태공원"], "confidence": "high", "address": "대한민국 전라남도 보성군 보성읍 옥평리 631-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('문수산', '용인 모현읍에 위치한 해발 221m의 산입니다. 능선이 완만하고 향수산 등과 연계하기 좋아 MTB 라이더들이 즐겨 찾는 산악 코스입니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.185196, 37.336696), 4326), false, '{"source": "KOMOOT", "source_ids": ["334"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["정몽주선생묘", "충렬서원", "향수산"], "confidence": "high", "address": "대한민국 경기도 용인시 처인구 모현읍 동림리 71-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('문암바위', '동해안 자전거길 삼척 구간의 조용한 문암해변에 위치한 바위입니다. 초곡항과 황영조기념공원이 가까워 라이딩 중 탁 트인 바다를 보며 쉬어가기 좋습니다.', '{beach,viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.284059, 37.311729), 4326), false, '{"source": "KOMOOT", "source_ids": ["1898"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["문암해변", "초곡항", "황영조기념공원", "초곡용굴촛대바위길"], "confidence": "high", "address": "대한민국 강원특별자치도 삼척시 근덕면 초곡리 408-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('문지네거리', '갑천 자전거길과 인접한 대전의 주요 교차로입니다. 전민동에서 엑스포과학공원이나 대덕연구단지 방면으로 라이딩할 때 거쳐 가는 길목입니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.405038, 36.389293), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["갑천", "KAIST 문지캠퍼스", "엑스포과학공원"], "confidence": "high", "address": "대한민국 대전광역시 문지삼거리"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('문학경기장', '인천의 대표적인 종합 스포츠 경기장입니다. 승기천 자전거길과 이어져 라이딩 출발지나 휴식처로 활용하기 좋으며, 화장실, 편의점, 주차장 등 편의시설이 풍부합니다.', '{landmark,park,rest_area,restroom,convenience_store,parking,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.697403, 37.434958), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/8/89/Munhak_Sports_Complex_Station_2.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/02/문학경기장역_역명판.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/60/인천문학경기장역_2024.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6b/Munhak_Sports_Complex_Station_2-1.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a0/IRTC_Incheon_Subway_Line_1_Munhak_Sports_Complex_Station.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["인천SSG랜더스필드", "문학경기장역", "박태환수영장", "승기천 자전거길"], "confidence": "high", "address": "대한민국 인천광역시 연수구 선학동 32-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('문항저수지', '남해 설천면 문항리에 위치한 작은 농업용 저수지입니다. 문항어촌체험마을로 향하는 라이딩 중 한적한 농촌 풍경과 고요한 수변을 감상하기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.92097, 34.912871), 4326), false, '{"source": "KOMOOT", "source_ids": ["1039"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["문항어촌체험마을"], "confidence": "high", "address": "대한민국 경상남도 남해군 설천면 문항리 372-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('문형2통. 영진빌라', '경기 광주시 문형동에 위치한 버스 정류장입니다. 라이딩 중 대중교통 연계나 현재 위치를 파악하기 위한 웨이포인트로 참고할 수 있습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.207447, 37.341667), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["문형삼거리", "문형동잣나무골"], "confidence": "high", "address": "대한민국 광주시 문형2통.영진빌라"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('문호리종점', '북한강 자전거길 인근 서종면 문호리의 버스 종점입니다. 라이딩 중 대중교통(점프)을 이용하거나 주변 식당에서 보급 및 휴식을 취하기 좋습니다.', '{transit,restaurant,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.354369, 37.604062), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["북한강", "황순원문학관"], "confidence": "high", "address": "대한민국 경기도 양평군 서종면 문호리 379-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('물굽이앞', '원주 문막읍의 버스 정류장으로, 섬강 자전거길이나 원주굽이길 라이딩을 시작하거나 종료할 때 대중교통을 연계하기 좋은 포인트입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.814452, 37.306368), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["문막체육공원", "문막시장", "섬강"], "confidence": "high", "address": "대한민국 원주시 물굽이앞"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('물금역', '낙동강 종주 자전거길과 인접한 물금역입니다. 황산공원과 황산베랑길 라이딩의 주요 거점이며, 자전거를 싣고 대중교통을 연계하는 점프 포인트로 유용합니다.', '{transit,restroom,convenience_store,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.985109, 35.30633), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/6c/Korail0mulgeum.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e1/Korail_Mulgeum_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0a/Korail_Mulgeum_Station2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a8/Korail_Gyeongbu_Line_Mulgeum_Station_Platform.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["황산공원", "낙동강 종주 자전거길", "황산베랑길"], "confidence": "high", "address": "대한민국 경상남도 양산시 물금읍 물금리 331-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('물봉', '충북 괴산군 청천면에 위치한 해발 약 208m의 작은 봉우리입니다. 라이딩 중 주변의 한적한 자연 경관을 즐기며 지날 수 있는 산악 지형입니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.783943, 36.66561), 4326), false, '{"source": "KOMOOT", "source_ids": ["516"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["낙영산", "도명산", "괴산 미륵산성"], "confidence": "high", "address": "대한민국 충청북도 괴산군 청천면 고성리 산8-32"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('물소소류지', '밀양 감물리 라이딩 코스에 위치한 작은 저수지입니다. 다랑이논으로 유명한 산간 마을의 고즈넉한 자연 풍경을 감상하며 지나가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.885762, 35.445901), 4326), false, '{"source": "KOMOOT", "source_ids": ["373"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["감물리 다랑이논", "구천산", "당고개"], "confidence": "high", "address": "대한민국 경상남도 밀양시 단장면 감물리 1535"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('물왕호수', '보통천 자전거길과 이어지는 물왕호수(구 물왕저수지) 일대입니다. 호수 주변으로 맛집과 카페가 밀집해 있어 라이딩 중 식사와 휴식을 취하기 좋습니다.', '{lake,restaurant,cafe,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.837697, 37.384863), 4326), false, '{"source": "KOMOOT", "source_ids": ["27"], "category_raw": "settlement", "tour_count": 1, "nearby_landmarks": ["물왕호수", "보통천 자전거길", "관곡지(연꽃테마파크)"], "confidence": "high", "address": "대한민국 경기도 시흥시 물왕동 산37-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('청풍문화재단지 주차장', '청풍문화재단지 주차장입니다. 청풍호반 벚꽃길 라이딩 코스 중 자전거를 주차하고 화장실을 이용하며 쉬어가기 좋은 거점입니다.', '{parking,rest_area,restroom,historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.172123, 37.002287), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["청풍문화재단지", "청풍호", "청풍대교"], "confidence": "high", "address": "대한민국 충청북도 제천시 청풍면 물태리 114-24"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('미금역', '수인분당선과 신분당선 환승역인 미금역입니다. 탄천 자전거길과 가까워 라이딩 전후 지하철 점프나 주변 상권에서 보급하기 좋습니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.109014, 37.35003), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/7/7a/K231Migeum.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/40/K231_Migeum_02.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/42/미금역_오류.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6c/美金01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/38/美金02.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["탄천 자전거길", "미금교", "2001아울렛 분당점"], "confidence": "high", "address": "대한민국 경기도 성남시 분당구 금곡동 성남대로 지하 156"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('미룡주공아파트', '군산대학교와 은파호수공원 인근에 위치한 아파트 단지입니다. 은파호수공원 자전거길로 진입하기 좋은 출발 및 경유지로 참고할 수 있습니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.689649, 35.943272), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["은파호수공원", "군산대학교"], "confidence": "high", "address": "대한민국 군산시 미룡주공APT"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('미림마을', '영주댐 하류 내성천 변에 위치한 미림마을입니다. 365일 태극기가 휘날리는 특색 있는 곳으로, 영주 자전거길 라이딩 시 거쳐가는 웨이포인트입니다.', '{landmark,river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.650104, 36.718723), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["내성천", "미림교", "영주댐"], "confidence": "high", "address": "대한민국 영주시 미림"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('미인명가황제수산', '만촌역 인근에 위치한 횟집입니다. 도심 라이딩 중 식사나 뒤풀이를 위해 들러 해산물을 즐기기 좋은 장소입니다.', '{restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.646072, 35.85849), 4326), false, '{"source": "KOMOOT", "source_ids": ["769"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["만촌역", "달구벌대로"], "confidence": "high", "address": "대한민국 대구광역시 수성구 만촌동 1040-43"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('박정희 전 대통령 창촌초등학교 건립 기념비', '1955년 박정희 전 대통령이 5사단장 시절 창촌초교 건립을 지원한 것을 기념하는 비석입니다. 창촌초등학교 내에 위치하며, 라이딩 중 가볍게 둘러보기 좋은 역사적 포인트입니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.388318, 37.768457), 4326), false, '{"source": "KOMOOT", "source_ids": ["519"], "category_raw": "32", "tour_count": 1, "nearby_landmarks": ["창촌초등학교"], "confidence": "high", "address": "대한민국 강원특별자치도 홍천군 내면 창촌리 1623-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('반곡지', '수백 년 된 왕버들과 저수지 반영이 아름다운 경산의 대표적인 사진 명소입니다. 대구 및 경산 근교 라이딩 시 고요한 자연 속에서 휴식하며 경치를 감상하기 좋습니다.', '{lake,viewpoint,nature,rest_area,landmark,cafe,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.805786, 35.780849), 4326), false, '{"source": "KOMOOT", "source_ids": ["725"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["왕버들 군락지", "반곡지 둘레길"], "confidence": "high", "address": "대한민국 경상북도 경산시 남산면 반곡리 250-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('반변천', '안동 도심을 지나 낙동강과 합류하는 하천입니다. 강변을 따라 한적한 자전거길이 조성되어 있어 여유로운 라이딩을 즐기기 좋습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.789347, 36.54195), 4326), false, '{"source": "KOMOOT", "source_ids": ["2073", "219", "1036"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["안동대학교", "낙동강 자전거길", "송천보"], "confidence": "high", "address": "대한민국 경상북도 안동시 송천동 730-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('반성역', '진주 폐철길 자전거도로와 연결되어 라이딩 출발 및 도착지로 인기 있는 기차역입니다. 무궁화호를 이용해 자전거 점프(연계 이동)를 하기 좋습니다.', '{transit,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.258756, 35.174059), 4326), false, '{"source": "KOMOOT", "source_ids": ["458"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1f/1fttn8vv7ypnjfnrfjt832b225dwnafy0-uhi87226636/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 1, "nearby_landmarks": ["진주 폐철길 자전거도로", "옛 반성역", "경상남도수목원"], "confidence": "high", "address": "대한민국 경상남도 진주시 일반성면 운천리 903-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('반월삼거리 버스정류장', '화성시 반월동에 위치한 버스 정류장입니다. 인근에 롯데마트 맥스(구 빅마켓)와 삼성전자 화성캠퍼스가 있어 라이딩 중 위치를 확인하는 지표로 활용하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.064968, 37.229176), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["롯데마트 맥스 영통점", "삼성전자 화성캠퍼스"], "confidence": "high", "address": "대한민국 화성시 반월1통.빅마켓앞"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('밤실재', '광주 첨단지구와 장성을 연결하는 주요 업힐 구간입니다. 봄철 벚꽃이 아름다워 자전거 라이더들이 자주 찾는 고개입니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.806025, 35.281254), 4326), false, '{"source": "KOMOOT", "source_ids": ["258"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["불태산", "못재"], "confidence": "high", "address": "대한민국 전라남도 장성군 장성읍 단광리 301-21"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('방어동 곰솔', '수령 500년이 넘는 보호수로, 용을 닮아 ''용송''이라 불리는 곰솔나무입니다. 라이딩 중 독특한 수형을 감상하며 잠시 쉬어가기 좋은 자연 명소입니다.', '{nature,historic,landmark,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.424321, 35.482737), 4326), false, '{"source": "KOMOOT", "source_ids": ["254"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["방어진항", "슬도", "대왕암공원"], "confidence": "high", "address": "대한민국 울산광역시 동구 방어동 204-24"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('절영해안산책로 전망대', '절영해안산책로 입구에 위치한 배 모양의 관리센터 건물 전망대입니다. 탁 트인 바다와 해안 산책로 풍경을 감상하며 자전거를 세워두고 쉬어가기 좋습니다.', '{viewpoint,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.041455, 35.081058), 4326), false, '{"source": "KOMOOT", "source_ids": ["579"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1n/1n5rikcdm2bzk111a9x7ovtmqy4zks64v3-uhi72684022/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/2n/2n1xgs2vsf991hwx8z7v6sduc4n2reizz-uhi62449310/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1l/1lgyr6av8w1v11a2vj2tlmeaak4n2rempr-uhi62449312/0?width=1920&crop=false"], "tips": [{"text": "Nett hergerichteter Aussichtspunkt in Form eines Schiffes.Von hier oben kann man schön auf den Küstenweg schauen.", "author": ""}], "category_raw": "viewpoint", "tour_count": 1, "nearby_landmarks": ["절영해안산책로", "흰여울문화마을", "남항대교"], "confidence": "high", "address": "대한민국 부산광역시 영도구 영선동4가 186-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('배낭기미해변', '흑산도 일주도로 라이딩 시 초반에 만나는 흑산도 유일의 해수욕장입니다. 자갈과 모래가 섞인 해변으로 탁 트인 바다를 보며 잠시 쉬어가기 좋습니다.', '{beach,rest_area,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(125.426256, 34.689064), 4326), false, '{"source": "KOMOOT", "source_ids": ["44"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["배낭기미 습지", "예리항(흑산도 여객선터미널)", "진리당", "상라산 전망대"], "confidence": "high", "address": "대한민국 전라남도 신안군 흑산면 진리 586-14"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('백도해변', '동해안 자전거길 고성 구간에 위치한 맑고 한적한 해변입니다. 백도오토캠핑장과 백도항 가리비 직매장이 인접해 있어 라이딩 중 식사와 휴식을 취하기 좋습니다.', '{beach,rest_area,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.545514, 38.300073), 4326), false, '{"source": "KOMOOT", "source_ids": ["1429"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["백도항", "백도오토캠핑장", "능파대"], "confidence": "high", "address": "대한민국 강원특별자치도 고성군 죽왕면 문암진리 96-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('백석역', '수도권 전철 3호선 백석역입니다. 주말 자전거 전철 점프나 라이딩 모임 장소로 적합하며, 역사 내 화장실과 편의시설을 이용할 수 있습니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.788079, 37.643002), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/dd/2014년_5월_26일_고양종합터미널_화재_사고29.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/26/Goyang_Bus_Terminal_20160122.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9f/Baekseok_Station_2.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/27/313_Baekseok_Platform.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/5f/20220725_백석역_역명판_기둥형.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["고양종합터미널", "코스트코 일산점", "국민건강보험 일산병원"], "confidence": "high", "address": "대한민국 경기도 고양시 일산동구 백석2동 중앙로 1042 백석"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구 백원역', '2008년 여객 취급이 중지된 경북선 폐역입니다. 고즈넉한 옛 간이역의 정취를 간직하고 있어 라이딩 중 사진을 남기거나 잠시 쉬어가기 좋은 랜드마크입니다.', '{transit,historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.173933, 36.481278), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["경북선 철도"], "confidence": "high", "address": "대한민국 경상북도 상주시 사벌국면 원흥리 1466-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('백한얼 꽈배기', '신라호텔 제과장 출신 셰프가 갓 튀겨내는 꽈배기 맛집입니다. 대파 꽈배기가 유명하며 라이딩 중 당 충전하기 좋습니다. 재료 소진 시 조기 마감되니 일찍 방문하세요.', '{cafe,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.711604, 33.281207), 4326), false, '{"source": "KOMOOT", "source_ids": ["476"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/17/17buzb86ew0m910bve5g7ivchr5e4slyma-uhi87508420/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/12/12xg1zqtarg8vfv8onho6r7mc5e4sm120-uhi87508421/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/13/13m5625hxyuf2p795f5zjvxsq5e4sm37u-uhi87508422/0?width=1920&crop=false"], "tips": [{"text": "Freshly made Korean rice flour donuts.", "author": ""}], "category_raw": "cafe", "tour_count": 1, "nearby_landmarks": ["남원항", "올레길 5코스"], "confidence": "high", "address": "대한민국 제주특별자치도 서귀포시 남원읍 남원리 1279-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('뱀등', '남원시 인월면에 위치한 해발 456.4m의 산(봉우리)입니다. 지리산 둘레길 인근에 있어 MTB나 업힐 라이딩 코스로 도전하기 좋은 자연 지형입니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.607518, 35.464277), 4326), false, '{"source": "KOMOOT", "source_ids": ["1880"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["지리산 둘레길", "곰재봉", "꾀꼬리봉"], "confidence": "high", "address": "대한민국 전북특별자치도 남원시 인월면 상우리 산1-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('뱃재', '강원도 삼척시 하장면에 위치한 산악 고개입니다. 인적이 드문 한적한 도로를 따라 자연 경관을 감상하며 도전적인 업힐 라이딩을 즐길 수 있습니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.93058, 37.274719), 4326), false, '{"source": "KOMOOT", "source_ids": ["1341"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["광동호", "두타산", "댓재"], "confidence": "high", "address": "대한민국 강원특별자치도 삼척시 하장면 어리 산81-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('버티고개', '남산과 매봉산을 잇는 생태통로가 있는 도심 속 고개입니다. 남산 라이딩 시 연계되는 난이도 있는 업힐 코스로 라이더들에게 유명합니다.', '{mountain,bridge,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.006502, 37.548236), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/2/22/632_beotigoge_01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e8/Beoti07.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/4c/Seoul-metro-632-Beotigogae-station-platform-20181125-162132.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9b/Seoul-metro-632-Beotigogae-station-entrance-3-20181125-161416.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/34/버티고개역_01.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["남산", "매봉산", "버티고개역", "반얀트리 클럽 앤 스파 서울"], "confidence": "high", "address": "대한민국 서울특별시 중구 신당동 432-2163"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('벌교 중도방죽', '소설 ''태백산맥''의 배경이 된 둑길로, 드넓은 갈대밭과 갯벌 풍경이 일품입니다. 평탄한 길이 이어져 있어 풍경을 감상하며 여유롭게 자전거를 타기 좋습니다.', '{nature,viewpoint,historic}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.380182, 34.837062), 4326), false, '{"source": "KOMOOT", "source_ids": ["1856"], "category_raw": "other_man_made", "tour_count": 1, "nearby_landmarks": ["벌교갯벌", "태백산맥 문학관", "벌교생태공원"], "confidence": "high", "address": "대한민국 전라남도 보성군 벌교읍 장양리 196-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('벌약소류지', '지리산 자락 마천면 구양리에 위치한 조용한 소류지입니다. 라이딩 중 고즈넉한 저수지 풍경을 감상하며 잠시 숨을 고르기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.689275, 35.431285), 4326), false, '{"source": "KOMOOT", "source_ids": ["418"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["지리산", "지리산 둘레길"], "confidence": "medium", "address": "대한민국 경상남도 함양군 마천면 구양리 214-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('세종 법원·검찰청·경찰청 예정지', '세종지방법원, 검찰청, 경찰청이 들어설 예정 부지입니다. 현재는 공터 상태이므로 라이딩 시 위치를 가늠하는 랜드마크로 참고하시기 바랍니다.', '{police,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.30166, 36.486866), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["금강보행교(이응다리)", "세종국책연구단지", "괴화산"], "confidence": "high", "address": "대한민국 세종특별자치시 법원.검찰청.경찰청"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('법화산', '용인에 위치한 해발 385m의 산으로, XC 싱글 트레일과 임도가 어우러져 있어 다이내믹한 주행을 즐기는 MTB 라이더들에게 인기 있는 코스입니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.148418, 37.305548), 4326), false, '{"source": "KOMOOT", "source_ids": ["315"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["죽전야외음악당", "천주교용인공원묘원", "물푸레마을"], "confidence": "high", "address": "대한민국 경기도 용인시 기흥구 청덕동 산27-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('별어곡역', '정선선의 작은 간이역인 별어곡역입니다. 내부에 억새전시관이 있으며, 고즈넉하고 레트로한 분위기를 즐기며 잠시 쉬어가기 좋은 라이딩 경유지입니다.', '{transit,historic,landmark,museum,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.739363, 37.269235), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["억새전시관", "민둥산", "지장천"], "confidence": "high", "address": "대한민국 강원특별자치도 정선군 남면 별어곡2길 27"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('병산저수지', '좌광천 자전거길의 종점에 위치한 저수지입니다. 수변 둘레길은 자전거 진입이 제한되지만 화장실과 쉼터가 잘 갖춰져 있어 라이딩 후 휴식하기 좋습니다.', '{lake,rest_area,restroom,viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.182348, 35.343863), 4326), false, '{"source": "KOMOOT", "source_ids": ["550"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["좌광천 자전거길", "좌광천"], "confidence": "high", "address": "대한민국 부산광역시 기장군 정관읍 병산리 산63-15"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('보강천', '오천자전거길이 지나는 증평의 대표적인 하천입니다. 미루나무숲과 생태공원이 잘 조성되어 있어 아름다운 경관을 보며 라이딩과 휴식을 즐기기 좋습니다.', '{river,park,nature,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.568214, 36.780763), 4326), false, '{"source": "KOMOOT", "source_ids": ["35"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["보강천 미루나무숲", "증평자전거공원", "백로공원"], "confidence": "high", "address": "대한민국 충청북도 증평군 증평읍 초중리 518-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('보개농협', '안성 가사동에 위치한 보개농협입니다. 내부에 하나로마트와 화장실이 있어 라이딩 중 식음료를 보급하고 안전하게 쉬어가기 좋은 거점입니다.', '{convenience_store,rest_area,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.285692, 37.012158), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["안성종합버스터미널"], "confidence": "high", "address": "대한민국 경기도 안성시 가사동 75-36"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('보발재 전망대', '해발 540m의 굽이진 헤어핀 코스로 유명한 자전거 업힐 명소입니다. 가을 단풍 절경이 뛰어나며, 화장실과 주차장을 갖춘 신축 전망대가 있어 라이딩 중 휴식하기 좋습니다.', '{viewpoint,mountain,rest_area,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.472136, 37.034704), 4326), false, '{"source": "KOMOOT", "source_ids": ["1200"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["구인사", "온달관광지"], "confidence": "high", "address": "대한민국 충청북도 단양군 가곡면 보발리 산14-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('보청천', '금강과 만나는 지점에 위치한 수려한 경관의 하천입니다. 보청천을 따라 조성된 자전거길은 자연을 만끽하며 라이딩하기 좋은 코스입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.69851, 36.30075), 4326), false, '{"source": "KOMOOT", "source_ids": ["551"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["금강", "보청천 자전거길"], "confidence": "high", "address": "대한민국 충청북도 옥천군 청성면 고당리 465-14"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('보성향교', '조선시대에 건립된 보성의 전통 교육기관으로, 읍내를 지나는 라이더들이 고즈넉한 한옥의 정취를 느끼며 가볍게 둘러보기 좋은 역사 유적지입니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.084067, 34.768356), 4326), false, '{"source": "KOMOOT", "source_ids": ["1135"], "category_raw": "32", "tour_count": 1, "nearby_landmarks": ["보성역", "보성매일시장", "보성군청"], "confidence": "high", "address": "대한민국 전라남도 보성군 보성읍 보성리 130-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('보평역', '경안천 자전거길과 인접한 용인 경전철 보평역입니다. 에버라인은 접이식을 포함한 모든 자전거의 승차가 전면 금지되어 있으므로 점프(대중교통 연계) 목적으로는 이용할 수 없습니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.218407, 37.258919), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/5b/Bopyeong-o.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0a/Bopyeong-g.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9a/Bopyeong-s.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8f/Bopyeong-y.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["경안천 자전거길", "용인시 장애인 종합복지관"], "confidence": "high", "address": "대한민국 경기도 용인시 처인구 경안천로 313"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('복수면 행정복지센터', '대전에서 유등천을 따라 금산으로 향하는 라이딩 코스의 든든한 거점입니다. 화장실 이용과 식수 보충, 안전한 휴식이 가능한 행정복지센터입니다.', '{restroom,water_fountain,rest_area,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.397923, 36.166746), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["유등천", "복수막국수", "뮤지엄B"], "confidence": "high", "address": "대한민국 금산군 복수면사무소"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('봉곡청마루출발지', '구미 봉곡동 청마루아파트 인근에 위치한 시내버스 종점입니다. 대중교통을 연계하여 자전거 라이딩을 시작하거나 복귀하기 좋은 거점입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.306811, 36.155569), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["봉곡청마루아파트", "선주초등학교"], "confidence": "high", "address": "대한민국 구미시 봉곡청마루출발지"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('봉무 유수지', '대구 이시아폴리스 인근의 유수지로, 연못과 가벼운 체육 시설이 조성되어 있습니다. 금호강 자전거길과 가까워 라이딩 중 잠시 쉬어가기 좋은 수변 휴식처입니다.', '{lake,park,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.63179, 35.928982), 4326), false, '{"source": "KOMOOT", "source_ids": ["85"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["이시아폴리스", "금호강 자전거길", "봉무공원"], "confidence": "high", "address": "대한민국 대구광역시 동구 봉무동 1082-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('봉산중학교', '광주 광산구 산월동에 위치한 중학교입니다. 영산강 자전거길과 인접해 있어 첨단지구 부근에서 라이딩을 시작할 때 만남의 장소나 길잡이로 활용하기 좋습니다.', '{landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.844789, 35.208739), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["영산강 자전거길", "봉산초등학교", "첨단지구"], "confidence": "high", "address": "대한민국 광주광역시 봉산중"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('봉암리 느티나무', '300년 수령의 경남 4대 느티나무로 ''강정자나무''로도 불립니다. 동해면 해안 라이딩 중 시원한 그늘 아래서 땀을 식히며 쉬어가기 좋은 훌륭한 휴식처입니다.', '{rest_area,nature,historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.408442, 35.001681), 4326), false, '{"source": "KOMOOT", "source_ids": ["717"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["입암마을", "동해면 해안도로"], "confidence": "high", "address": "대한민국 경상남도 고성군 동해면 봉암리 1100-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('봉은사', '강남 도심 한복판에 위치한 대형 사찰입니다. 한강이나 탄천 자전거길에서 접근하기 좋으며, 라이딩 중 잠시 들러 거대한 불상과 고즈넉한 분위기를 즐기며 쉬어가기 좋습니다.', '{historic,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.057937, 37.513929), 4326), false, '{"source": "KOMOOT", "source_ids": ["8"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1v/1vk1lgcb8nzyy1d0tq91joi24w4r38z65h-uhi66554950/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1f/1f4gpa041emyu1vw8e9gbo6oob4r38z669-uhi66554951/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1u/1uvu1v1t64u76x0wl7uqgn9y4r38z66o-uhi66554952/0?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e8/Seoul-metro-line-9-929-Bongeunsa-station-platform-20181124-111950.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c0/Bongeunsa_Station_Concourse_201604.JPG?width=1920&crop=false"], "tips": [{"text": "Die koreanisch-buddhistische Tempelanlage wird von einer einer 23 m hohen Buddhastatue überragt. Die ältesten Gebäude der Anlage stammen aus dem 19. Jahrhundert.", "author": "Puffin"}], "category_raw": "religious_building", "tour_count": 1, "nearby_landmarks": ["코엑스(COEX)", "탄천 자전거길", "한강공원"], "confidence": "high", "address": "대한민국 서울특별시 강남구 봉은사로"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('봉은사', '도심 속 고즈넉한 대형 사찰로, 한강 및 탄천 자전거길과 가까워 라이딩 중 들러 휴식하거나 문화를 체험하기 좋은 랜드마크입니다.', '{historic,landmark,rest_area,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.060225, 37.514244), 4326), false, '{"source": "KOMOOT", "source_ids": ["8"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1v/1vk1lgcb8nzyy1d0tq91joi24w4r38z65h-uhi66554950/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1f/1f4gpa041emyu1vw8e9gbo6oob4r38z669-uhi66554951/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1u/1uvu1v1t64u76x0wl7uqgn9y4r38z66o-uhi66554952/0?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e8/Seoul-metro-line-9-929-Bongeunsa-station-platform-20181124-111950.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c0/Bongeunsa_Station_Concourse_201604.JPG?width=1920&crop=false"], "tips": [{"text": "Die koreanisch-buddhistische Tempelanlage wird von einer einer 23 m hohen Buddhastatue überragt. Die ältesten Gebäude der Anlage stammen aus dem 19. Jahrhundert.", "author": "Puffin"}], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["코엑스", "탄천 자전거길", "한강공원"], "confidence": "high", "address": "대한민국 서울특별시 봉은사.삼성1파출소앞"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('봉화그린빌', '순천 봉화산 MTB 싱글 다운힐 코스의 진입로 및 기종점으로 활용되는 아파트 단지입니다. 산악 자전거 라이더들에게 코스의 주요 이정표 역할을 합니다.', '{checkpoint,mountain,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.514593, 34.962339), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["봉화산", "봉화산 둘레길"], "confidence": "high", "address": "대한민국 순천시 봉화그린빌"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('부론', '남한강과 섬강 자전거길이 만나는 부론면 소재지입니다. 식당, 카페, 편의점 등이 모여 있어 라이딩 중 보급과 휴식을 취하기 좋은 거점입니다.', '{rest_area,convenience_store,restaurant,cafe,hospital}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.749811, 37.207957), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["남한강 자전거길", "섬강 자전거길", "법천시장"], "confidence": "high", "address": "대한민국 강원특별자치도 원주시 부론면 법천시장길 55"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구덕수원지', '대신공원 내에 위치한 부산 최초의 근대식 수원지(구덕수원지)입니다. 울창한 숲과 호수 풍경이 어우러져 라이딩 중 자연 속에서 휴식하기 좋은 명소입니다.', '{lake,park,nature,historic,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.018618, 35.123079), 4326), false, '{"source": "KOMOOT", "source_ids": ["491"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["대신공원", "구덕민속예술관", "동아대학교 구덕캠퍼스"], "confidence": "high", "address": "대한민국 부산광역시 서구 동대신동3가 산2-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('부산대양산캠퍼스역', '부산 도시철도 2호선 전철역입니다. 양산천 및 낙동강 자전거길 접근성이 좋고, 공공자전거 대여소와 화장실이 있어 라이딩 출발지나 휴식처로 유용합니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.013374, 35.317092), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/d5/Busan-subway-241-Pusan-national-university-yangsan-campus-station-entrance-5-20180401-162822.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/78/Busan-subway-241-Pusan-national-university-yangsan-campus-station-platform-20180401-162124.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d3/241bucam.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/08/241seoksan.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9b/Pusan_National_Univ_Yangsan_Campus_2010.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["양산부산대학교병원", "양산천", "낙동강종주자전거길"], "confidence": "high", "address": "대한민국 양산시 부산대양산캠퍼스역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('부산한솔학교', '부산 강서구 명지오션시티에 위치한 공립 특수학교입니다. 해안을 따라 조성된 명지 갈맷길 자전거도로와 인접해 있어 라이딩 시 길잡이 역할을 하는 랜드마크입니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.898237, 35.082019), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["명지오션시티 자전거길", "명지 갈맷길", "명지근린공원"], "confidence": "high", "address": "대한민국 부산광역시 부산한솔학교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('부산항 전도등', '부산 구봉산에 위치한 선박 길잡이용 철탑입니다. 북항 일대가 한눈에 내려다보이는 탁 트인 전망대이자 소공원으로, 자전거 업힐 및 MTB 코스로 인기가 높습니다.', '{viewpoint,landmark,rest_area,mountain}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.025828, 35.127825), 4326), false, '{"source": "KOMOOT", "source_ids": ["420"], "category_raw": "19", "tour_count": 1, "nearby_landmarks": ["구봉산", "대원사", "대신공원"], "confidence": "high", "address": "42HG+48 대한민국 부산광역시"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('부안임씨가묘', '고려 말 충신 임난수 장군을 기리는 사당입니다. 인근의 독락정과 연계하여 라이딩 중 가볍게 둘러보기 좋은 역사 유적지입니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.270508, 36.481124), 4326), false, '{"source": "KOMOOT", "source_ids": ["56"], "category_raw": "15", "tour_count": 1, "nearby_landmarks": ["독락정", "세종 역사공원"], "confidence": "high", "address": "대한민국 세종특별자치시 나성동 101-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('부여시외버스터미널', '금강 자전거길 종주와 백제 역사 탐방의 주요 출발 및 도착지입니다. 시외버스를 이용한 자전거 점프(이동)에 필수적인 교통 거점입니다.', '{transit,restroom,convenience_store,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.909824, 36.280251), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["정림사지", "부소산성", "궁남지", "국립부여박물관"], "confidence": "high", "address": "대한민국 충청남도 부여군 부여읍 부장대로 64"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('북골못', '기계면 봉계리의 한적한 농로에 위치한 작은 저수지입니다. 봉좌마을과 봉좌산 인근의 조용한 시골길을 달리며 자연을 감상하기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.150301, 36.066495), 4326), false, '{"source": "KOMOOT", "source_ids": ["608"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["봉좌마을", "봉좌산", "봉계수변공원", "분옥정"], "confidence": "medium", "address": "대한민국 경상북도 포항시 북구 기계면 봉계리 1519"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('북면행정복지센터', '가평 5고개(화악산, 도마치재 등) 라이딩의 대표적인 출발지이자 주차 거점입니다. 화장실을 갖추고 있어 라이딩 전후 휴식과 정비에 좋습니다.', '{parking,restroom,rest_area,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.5499, 37.888059), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["목동삼거리", "북면 스카이타워", "화악산", "도마치재"], "confidence": "high", "address": "대한민국 가평군 북면행정복지센터"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('북촌한옥마을', '전통 한옥의 정취를 느낄 수 있는 아름다운 포토 스팟입니다. 주말에는 보행자가 매우 많고 좁은 언덕길이 대부분이라 자전거에서 내려 끌고 이동하는 것을 추천합니다.', '{historic,landmark,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.983546, 37.58292), 4326), false, '{"source": "KOMOOT", "source_ids": ["24"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/dk/dk7js3tzituk1pnq7mv5dlayh4rj3kc2f-uhi66897184/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/9t/9tavfujp9u18gnjy7zmlytuz4rj3kc30-uhi66897185/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/m0/m0nhgjenldk5bhccmw8gq18g4rj3kc4n-uhi66897187/0?width=1920&crop=false"], "tips": [{"text": "Ja nach Tageszeit können wundervolle Fotos geschossen werden. Auch hier gilt für schöne Fotos: Wochenende aufgrund der Menge an Menschen vermeiden.", "author": "Andre - Mindblow-africa"}], "category_raw": "settlement", "tour_count": 1, "nearby_landmarks": ["경복궁", "창덕궁", "삼청동"], "confidence": "high", "address": "대한민국 서울특별시 종로구 가회동 31-45"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('북한산성 입구 보급소', '창릉천 자전거길 종점이자 북한산 라이딩의 주요 반환점입니다. 상가 단지에 편의점, 식당, 화장실 등 편의시설이 밀집해 있어 휴식과 보급을 하기에 최적의 장소입니다.', '{convenience_store,cafe,restaurant,restroom,rest_area,parking,mountain,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.949238, 37.655312), 4326), false, '{"source": "KOMOOT", "source_ids": ["95"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1t/1tvjbpbsmpciiu88pmeqyxhd74flosvv3-uhi57075668/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 1, "nearby_landmarks": ["창릉천 자전거길", "북한산성탐방지원센터", "스타벅스 더북한산점"], "confidence": "high", "address": "대한민국 서울특별시 은평구 진관동 277-16"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('분강리마을회관', '금강 자전거길 공주 구간의 끝자락에 위치한 마을회관입니다. ''아름다운 자전거길 100선''에 선정된 석장리~분강리 코스의 종점으로 라이딩 중 쉬어가기 좋습니다.', '{rest_area,landmark,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.988979, 36.341639), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["금강 자전거길", "금강"], "confidence": "high", "address": "대한민국 충청남도 공주시 탄천면 분강리 138-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('분성산', '김해 시내 조망이 뛰어난 산으로, 천문대까지 이어지는 포장도로 업힐과 다양한 임도가 있어 MTB 라이더들에게 인기가 많습니다.', '{mountain,viewpoint,historic,landmark,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.88769, 35.252565), 4326), false, '{"source": "KOMOOT", "source_ids": ["762"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["김해천문대", "분산성", "김해가야테마파크", "해은사"], "confidence": "high", "address": "대한민국 경상남도 김해시 어방동 산2-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('분장리 지석묘군', '부안 상서면 장동리 분장마을의 고인돌 유적입니다. 서해랑길 49코스가 지나는 한적한 농로에 위치해 라이딩 중 가볍게 둘러보기 좋은 역사적 경유지입니다.', '{historic}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.670003, 35.709051), 4326), false, '{"source": "KOMOOT", "source_ids": ["144"], "category_raw": "15", "tour_count": 1, "nearby_landmarks": ["구암리 지석묘군", "서해랑길 49코스"], "confidence": "medium", "address": "대한민국 전북특별자치도 부안군 상서면 장동리 589-27"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('불광천', '한강으로 이어지는 자전거길이 잘 조성된 도심 하천입니다. 봄철 벚꽃 라이딩 명소로 유명하며, 평탄한 코스로 초중급 라이더가 달리기 좋습니다.', '{river,nature,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.907814, 37.581791), 4326), false, '{"source": "KOMOOT", "source_ids": ["980"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["해담는다리", "증산역", "홍제천", "월드컵경기장"], "confidence": "high", "address": "대한민국 서울특별시 은평구 증산로 271"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('불로초공원 전망대', '영도 봉래산 중턱에 위치한 공원으로 부산항대교와 바다 조망이 매우 뛰어납니다. 업힐 라이딩 중 숨을 고르며 멋진 경치를 감상하기 좋은 휴식처입니다.', '{park,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.053954, 35.086506), 4326), false, '{"source": "KOMOOT", "source_ids": ["460"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1b/1bof776k98h9clsxixbyq1umr4fbxxs9g-uhi56928110/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 1, "nearby_landmarks": ["봉래산", "부산항대교"], "confidence": "high", "address": "대한민국 부산광역시 영도구 청학동 산54-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('브랭섬 홀 아시아', '제주영어교육도시 내 위치한 캐나다 명문 국제학교입니다. 주변 도로가 잘 정비되어 있어 쾌적하게 라이딩하며 이국적인 캠퍼스 풍경을 감상하기 좋습니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.283809, 33.291192), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["제주영어교육도시", "NLCS 제주", "KIS 제주"], "confidence": "high", "address": "대한민국 제주특별자치도 서귀포시 대정읍 보성리 2373"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('비동곡제', '경북 구미시 해평면에 위치한 소규모 저수지입니다. 한적한 시골길 라이딩 중 조용한 자연 풍경을 감상하며 지나가기 좋은 포인트입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.355581, 36.27035), 4326), false, '{"source": "KOMOOT", "source_ids": ["91"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["낙동강", "해평파크골프장"], "confidence": "high", "address": "대한민국 경상북도 구미시 해평면 낙산리 산142-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('비봉산', '순천 가곡동에 위치한 해발 422m의 산입니다. 향림사 인근에서 시작하는 등산로와 임도가 있어 산악 자전거(MTB) 라이딩 코스로 활용하기 좋습니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.480314, 34.971447), 4326), false, '{"source": "KOMOOT", "source_ids": ["564"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["향림사", "국사봉"], "confidence": "high", "address": "대한민국 전라남도 순천시 가곡동 433-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('비숲주차장', '김해 어방동 인제대학교 인근에 위치한 주차장으로, 차량을 이용해 라이딩 출발지로 이동할 때 주차 공간으로 활용할 수 있습니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.902349, 35.246879), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["인제대학교 김해캠퍼스", "신어산"], "confidence": "medium", "address": "대한민국 경상남도 김해시 어방동 616-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('장군목 현수교', '섬진강 자전거길 장군목 유원지에 위치한 빨간색 출렁다리입니다. 다리 위에서 요강바위와 기암괴석 등 섬진강의 아름다운 절경을 감상하며 쉬어가기 좋습니다.', '{bridge,viewpoint,landmark,river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.187455, 35.469328), 4326), false, '{"source": "KOMOOT", "source_ids": ["587"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1v/1vgfzrebndhv4gzj4ph9dirfx5e580za9-uhi87511928/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 1, "nearby_landmarks": ["요강바위", "장군목 유원지", "용궐산 치유의 숲", "섬진강 자전거길"], "confidence": "high", "address": "대한민국 전북특별자치도 순창군 동계면 장군목길 장군목현수교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('저동항 빨간등대', '울릉도 저동항 방파제 끝에 위치한 빨간 등대입니다. 탁 트인 동해 바다 풍경과 일출을 감상하며 라이딩 중 사진을 남기기 좋은 랜드마크입니다.', '{landmark,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(130.91421, 37.497813), 4326), false, '{"source": "KOMOOT", "source_ids": ["179"], "category_raw": "19", "tour_count": 1, "nearby_landmarks": ["저동항", "촛대바위", "행남해안산책로"], "confidence": "high", "address": "8Q9GFWX7+4M"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('사곡역', '대구권 광역철도가 정차하는 사곡역으로, 자전거 점프(대중교통 연계)가 가능한 교통 거점입니다. 라이딩 중 화장실을 이용하거나 잠시 쉬어가기 좋습니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.356612, 36.098365), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/1/1a/Korail0sagok.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e9/Daegyeong_Line_Sagok_Station_20241115.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8b/Groundbreaking_ceremony_of_Gyeongbu_Line_at_Busan,_1901.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["박정희대통령생가", "구미시민운동장"], "confidence": "high", "address": "대한민국 경상북도 구미시 사곡동 470-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('사근진해수욕장', '동해안 자전거길을 따라 달리며 푸른 바다와 소나무 숲을 감상할 수 있는 해변입니다. 화장실, 급수대 등 편의시설이 잘 갖춰져 있어 라이딩 중 쾌적하게 쉬어가기 좋습니다.', '{beach,restroom,parking,water_fountain,viewpoint,nature,cafe,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.898691, 37.812697), 4326), false, '{"source": "KOMOOT", "source_ids": ["167"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["경포해변", "사근진해중공원 전망대", "경포호"], "confidence": "high", "address": "대한민국 강원특별자치도 강릉시 안현동 3-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('사북역', '태백선 무궁화호가 정차하는 사북역입니다. 정선과 태백 지역 라이딩 시 점프(출발 및 복귀) 지점으로 활용하기 좋은 대중교통 거점입니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.817015, 37.22637), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/2/20/Sabuk_station_front_160509.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a4/사북역.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["사북시장", "강원랜드", "지장천"], "confidence": "high", "address": "대한민국 강원특별자치도 정선군 사북읍 사북리 산150-14"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('사육신공원에서 바라본 63빌딩 전망', '노들역 인근 한강 자전거길에서 접근하기 쉬운 사육신공원 내 조망 명소입니다. 63빌딩과 한강의 탁 트인 경치, 아름다운 야경을 감상하며 쉬어가기 좋습니다.', '{viewpoint,park,historic}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.948737, 37.51367), 4326), false, '{"source": "KOMOOT", "source_ids": ["274"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1c/1cllfcg0hd1jx146apb5yeapim5dpo8ppe-uhi87030374/0?width=1920&crop=false"], "category_raw": "viewpoint", "tour_count": 1, "nearby_landmarks": ["63빌딩", "사육신역사공원", "노들섬", "한강대교"], "confidence": "high", "address": "대한민국 서울특별시 동작구 노량진제1동 179-4 사육신공원"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('산곡천', '하남 검단산에서 발원해 한강으로 이어지는 생태하천입니다. 하천을 따라 자전거길이 조성되어 있어 한강 자전거길이나 팔당댐으로 연계 라이딩하기 좋습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.222958, 37.519669), 4326), false, '{"source": "KOMOOT", "source_ids": ["359", "267", "124", "406", "295", "628", "1025", "232", "162", "640"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["검단산", "팔당대교", "한강"], "confidence": "high", "address": "대한민국 경기도 하남시 하산곡동 186-15"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('산동중학교입구', '구미시 산동읍 산동중학교 진입로에 위치한 버스 정류장입니다. 주변 국도 라이딩 시 위치를 가늠하는 웨이포인트나 대중교통 연계 지점으로 활용할 수 있습니다.', '{transit,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.438159, 36.167953), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["산동중학교", "산동농협경제사업소"], "confidence": "high", "address": "대한민국 경상북도 구미시 산동읍 동곡리 941-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('산본저수지', '김해 진례면에 위치한 독특한 하트 모양의 저수지입니다. 맞은편에 숨겨진 명소인 대나무 숲이 있어 라이딩 중 자연 속에서 힐링하며 쉬어가기 좋습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.777157, 35.222842), 4326), false, '{"source": "KOMOOT", "source_ids": ["141"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["진례면 대밭", "관동저수지"], "confidence": "high", "address": "대한민국 경상남도 김해시 진례면 산본리 367-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('산월초교입구', '광주 산월초등학교 인근의 버스 정류장입니다. 도심 라이딩 중 길 찾기 기준점으로 삼거나 잠시 정차하기 좋은 웨이포인트입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.837156, 35.211874), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["산월초등학교", "첨단라인8차아파트"], "confidence": "high", "address": "대한민국 광주광역시 산월초교입구"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('산정제', '장성군 진원면의 한적한 저수지입니다. 수변 데크길이 잘 조성되어 있어 라이딩 중 경치를 보며 쉬어가기 좋고, 인근 로컬푸드 직매장에서 식음료 보급도 가능합니다.', '{lake,nature,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.814506, 35.250688), 4326), false, '{"source": "KOMOOT", "source_ids": ["367"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["남면농협 로컬푸드직매장", "산정제 둘레길"], "confidence": "high", "address": "대한민국 전라남도 장성군 진원면 산정리 산105-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('산촌리 팽나무', '지방도 1018호선 옆 산촌마을 입구에 있는 230년 수령의 거대한 팽나무입니다. 나무 아래 데크 쉼터가 마련되어 있어 라이딩 중 시원한 그늘에서 쉬어가기 좋습니다.', '{landmark,rest_area,nature,historic}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.60295, 34.831357), 4326), false, '{"source": "KOMOOT", "source_ids": ["93"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["산촌마을 입구", "지방도 1018호선"], "confidence": "high", "address": "대한민국 경상남도 거제시 동부면 산촌리 285-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('산현초등학교', '시흥 목감지구에 위치한 초등학교입니다. 인근 물왕저수지나 도심 라이딩 시 이정표로 참고하기 좋습니다.', '{landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.847161, 37.375479), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["물왕저수지", "목감지구"], "confidence": "high", "address": "대한민국 시흥시 산현초"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('살미역', '2024년 11월 개통한 중부내륙선 철도역입니다. 충주호 둘레길, 수주팔봉 등 충주 외곽 라이딩 코스로 향할 때 유용한 대중교통 점프 포인트입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.960397, 36.902566), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["살미면사무소", "중앙경찰학교", "수주팔봉", "충주호"], "confidence": "high", "address": "대한민국 충주시 살미역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼각보도', '교차로에 위치한 삼각형 모양의 보도(교통섬)로, 라이딩 중 횡단보도 신호를 대기하거나 안전하게 방향을 전환할 때 거쳐가는 지점입니다.', '{checkpoint,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.097467, 37.338951), 4326), false, '{"source": "KOMOOT", "source_ids": ["586"], "category_raw": "191", "tour_count": 1, "nearby_landmarks": ["동천동 교차로"], "confidence": "medium", "address": "대한민국 경기도 용인시 수지구 동천동 328-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('전농로 벚꽃길', '제주 시내의 대표적인 벚꽃 명소인 전농로 벚꽃길입니다. 봄철 왕벚꽃 축제 기간에는 차량이 전면 통제되므로 자전거에서 내려 만개한 벚꽃을 감상하며 걷기 좋습니다.', '{landmark,viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.51725, 33.504453), 4326), false, '{"source": "KOMOOT", "source_ids": ["704"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/gs/gsaajfkvxije1fpsteb2w1apr5bxh4dup-uhi84824132/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/8r/8r5alrmgxwum9p2kcnf4pa2p5bxh4duq-uhi84824133/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1s/1savdbmrmcjasg6jp7tgtfto75bxh4duq-uhi84824134/0?width=1920&crop=false"], "tips": [{"text": "During spring cherry blossom week of end March/early April, this road is the Mecca for photographers. This road will be closed for traffic while annual Cherry Blossom Festival will be held. It’s a spectacular sight!", "author": ""}], "category_raw": "natural_monument", "tour_count": 1, "nearby_landmarks": ["삼성혈", "신산공원", "제주KAL호텔"], "confidence": "high", "address": "대한민국 제주시 삼도일동 701-28번지 제주시 제주특별자치도 KR"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼산월드체육관', '굴포천 자전거길과 상동호수공원이 인접해 라이딩 출발지나 휴식처로 좋은 대형 체육시설입니다. 화장실과 자전거 보관소 등 편의시설이 잘 갖춰져 있습니다.', '{landmark,rest_area,restroom,parking,transit,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.742347, 37.50649), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/a/a3/20241003_삼산체육관역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/dc/Samsancheyukgwan-20121030-1.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d8/Samsancheyukgwan-20121030-2.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8e/20241003_삼산체육관역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/ko/7/72/Samsancheyukgwan-20121030-4.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["상동호수공원", "굴포천", "한국만화박물관"], "confidence": "high", "address": "대한민국 부천시 상3동 삼산체육관"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼성역', '서울 지하철 2호선 삼성역입니다. 코엑스와 인접해 유동인구와 차량이 많아 주의가 필요하며, 주말과 공휴일에만 자전거 휴대 승차가 가능합니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.063045, 37.50881), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/0/0c/Samseong_Station_5.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/52/Samseong05.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0b/Seoul-metro-219-Samseong-station-sign-20180916-082816.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/62/Seoul-metro-219-Samseong-station-entrance-5-20180916-091626.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e3/Samseong02.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["코엑스", "무역센터", "탄천 자전거길"], "confidence": "high", "address": "대한민국 서울특별시 강남구 삼성동 172-66"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼성산', '수도권 라이더들에게 ''삼막사 업힐''로 유명한 산입니다. 경인교대에서 KT 통신탑 정상까지 이어지는 가파른 길은 난이도가 높아 도전 욕구를 자극하며, 정상의 조망이 뛰어납니다.', '{mountain,viewpoint,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.93958, 37.435927), 4326), false, '{"source": "KOMOOT", "source_ids": ["326"], "image_urls": ["https://photos.komoot.de/wiki/commons/3/34/Samsungsan.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a3/Mount_Bukhansan_seen_from_Shinseondae_Peak.JPG?width=1920&crop=false"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["삼막사", "KT 통신탑", "경인교대"], "confidence": "high", "address": "대한민국 경기도 안양시 만안구 석수동 산9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼성중앙역', '서울 지하철 9호선 삼성중앙역입니다. 역내 화장실을 이용할 수 있으며, 접이식 자전거를 활용한 대중교통 점프나 도심 라이딩 만남의 장소로 적합합니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.053482, 37.513073), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/4/49/Q17278984_Samsungjungang_A01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/be/Samseong_Jungang_Station_20150328_144513147.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a5/Samseong_Jungang_Station_20150328_145047755.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e8/Samseong_Jungang_Station_20150328_145208843.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f7/Seoul-metro-line-9-928-Samseong-jungang-station-sign-20181124-105746.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["선정릉", "봉은사", "코엑스"], "confidence": "high", "address": "대한민국 서울특별시 강남구 삼성동 111-147"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼송역 창릉천 자전거길 기점', '창릉천 자전거길과 연결되어 한강이나 공릉천 방향으로 이동하기 좋은 라이딩 기점입니다. 지하철역 주변으로 식당과 편의시설이 풍부해 보급 및 휴식에 적합합니다.', '{transit,restroom,convenience_store,cafe,restaurant,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.895552, 37.653115), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/2/2b/Samsong_Station_20230401_005.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b8/Samsong_Station_20230401_003.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/43/Samsong_Station_20230401_002.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f2/Samsong_Station_20250102_01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3d/Samsong_Station_20230401_001.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["창릉천", "스타필드 고양", "북한산"], "confidence": "high", "address": "대한민국 고양시 삼송역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼양사거리', '우이신설선 삼양사거리역이 위치한 강북구의 주요 교차로입니다. 도심 라이딩 시 통과하는 교통 요지로 주변 상권에서 보급하기 좋습니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.020531, 37.621204), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/1/10/Samyangsageori.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/cd/Samyang_Sageori_Station_Screendoor_1.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["삼양사거리역", "솔샘시장", "강북청소년문화정보도서관"], "confidence": "high", "address": "대한민국 서울특별시 강북구 미아동 745-143"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('상현교차로 보급소(CU·이디야)', '상현교차로 인근 오피스텔로 1층에 편의점(CU)과 카페(이디야)가 있어 라이딩 중 보급과 휴식을 취하기 좋습니다.', '{convenience_store,cafe,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.074815, 37.302782), 4326), false, '{"source": "KOMOOT", "source_ids": ["213"], "category_raw": "17", "tour_count": 1, "nearby_landmarks": ["상현교차로", "상현역"], "confidence": "high", "address": "대한민국 용인시 상현교차로.현대2차"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼정해변', '동해안 자전거길(해파랑길 14코스)에 위치한 작고 한적한 해변입니다. 상업시설이 적어 라이딩 중 조용히 바다 풍경을 감상하며 쉬어가기 좋습니다.', '{beach,nature,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.571052, 36.003338), 4326), false, '{"source": "KOMOOT", "source_ids": ["598"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["구룡포 주상절리", "구룡포 일본인 가옥거리", "삼정섬"], "confidence": "high", "address": "대한민국 경상북도 포항시 남구 구룡포읍 삼정리 963-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼척역', '동해안 자전거길이 통과하는 삼척역입니다. 대중교통 연계(점프)가 가능하며, 역 앞 번개시장 등에서 식사와 보급을 해결하기 좋은 주요 거점입니다.', '{transit,landmark,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.178582, 37.429885), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["번개시장", "오십천", "삼표시멘트 삼척공장"], "confidence": "high", "address": "대한민국 강원특별자치도 삼척시 사직동 51-19"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼척사직단', '조선시대 토지신과 오곡신에게 제사를 지내던 역사 유적지입니다. 오십천 자전거길과 가까워 라이딩 중 잠시 들러 역사적 의미를 되새기며 쉬어가기 좋습니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.15254, 37.440818), 4326), false, '{"source": "KOMOOT", "source_ids": ["2659"], "image_urls": ["https://photos.komoot.de/wiki/commons/d/d1/Sajikdan_Shrine_in_Seoul,_Korea_02.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6a/Northern_Section_view_of_Seoul_(c._1884).jpg?width=1920&crop=false"], "category_raw": "15", "tour_count": 1, "nearby_landmarks": ["오십천", "원당현대아파트"], "confidence": "high", "address": "대한민국 강원특별자치도 삼척시 원당동 122-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼천포시외버스터미널', '사천, 남해 지역 라이딩의 주요 출발 및 도착지입니다. 시외버스를 이용한 점프(이동)에 필수적이며 삼천포대교 및 해안도로 접근성이 좋습니다.', '{transit,restroom,convenience_store,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.080358, 34.939625), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["삼천포항", "삼천포대교", "삼천포용궁수산시장", "노산공원"], "confidence": "high", "address": "대한민국 사천시 삼천포시외버스터미널"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삼포해수욕장', '동해안 자전거길 고성 구간에 있는 한적한 해변입니다. 화장실과 편의점 등 편의시설이 잘 갖춰져 있어 라이딩 중 휴식하기 좋습니다.', '{beach,restroom,convenience_store,parking,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.535056, 38.314671), 4326), false, '{"source": "KOMOOT", "source_ids": ["1389"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["오션투유리조트", "자작도해수욕장", "백도해수욕장"], "confidence": "high", "address": "대한민국 강원특별자치도 고성군 죽왕면 삼포리 1-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('삿갓봉', '양양 현북면에 위치한 해발 282.5m의 산봉우리입니다. 원일전리에서 이어지는 순환 임도가 잘 조성되어 있어 산악자전거(MTB) 및 그래블 라이딩 코스로 인기가 높습니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.668221, 37.979388), 4326), false, '{"source": "KOMOOT", "source_ids": ["462"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["한천산", "정족산", "원일전리 금풀애체험관"], "confidence": "high", "address": "대한민국 강원특별자치도 양양군 현북면 원일전리 산69"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('상계역', '지하철 4호선 상계역입니다. 당현천 자전거길을 통해 중랑천으로 진입하기 좋으며, 불암산이나 수락산 방면 라이딩 시 대중교통 점프 포인트로 유용합니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.073567, 37.660686), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/8/8f/20250515_상계역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/89/Sggs01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/dd/Seoul-metro-410-Sanggye-station-building-20181126-113448.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/fc/Seoul-metro-410-Sanggye-station-entrance-1-20181126-114012.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/35/20250515_상계역_승강장.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["당현천", "불암산", "수락산"], "confidence": "high", "address": "대한민국 서울특별시 노원구 중계동 141-85"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('상동역 주변 번화가', '7호선 상동역 일대로 편의점, 식당 등 보급처가 밀집한 도심 번화가입니다. 인근 상동호수공원이나 시민의 강 자전거길과 연계하여 라이딩하기 좋습니다.', '{transit,convenience_store,cafe,restaurant,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.753135, 37.505827), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/dc/Sangdong-Seoul7-20121030-2.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/17/Sangdong-Seoul7-20121030-1.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/7c/Sangdong-Seoul7-20121030-3.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/ko/e/e5/Sangdong-Seoul7-20121030-4.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["상동호수공원", "부천터미널 소풍", "시민의 강"], "confidence": "high", "address": "대한민국 경기도 부천시 원미구 중동 부천시 보건소 상동"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('상록해수욕장', '변산마실길 해안 코스에 위치한 한적하고 깨끗한 해수욕장입니다. 울창한 소나무 숲과 화장실, 식당 등 편의시설이 잘 갖춰져 있어 해안 라이딩 중 쉬어가기 좋습니다.', '{beach,rest_area,restroom,restaurant,parking,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.479694, 35.60295), 4326), false, '{"source": "KOMOOT", "source_ids": ["803"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["격포항", "솔섬", "전라좌수영 세트장", "궁항"], "confidence": "high", "address": "대한민국 전북특별자치도 부안군 변산면 도청리 1077-31"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('상법저수지', '산청군 신등면에 위치한 저수지로, 부암산과 둔철산 등 수려한 산세가 어우러져 라이딩 중 탁 트인 자연 경관을 감상하기 좋은 포인트입니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.972607, 35.440902), 4326), false, '{"source": "KOMOOT", "source_ids": ["184"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["부암산", "감암산", "이교마을", "둔철산"], "confidence": "high", "address": "대한민국 경상남도 산청군 신등면 장천리 1397-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('상봉역', '경춘선과 경의중앙선을 이용해 춘천, 양평 등 외곽 자전거길로 점프(이동)하기 좋은 주요 환승역입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.085592, 37.596083), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/a/ad/Korail_Sangbong_Station.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3f/Seoul-metro-720-Sangbong-station-entrance-1-20181122-160352.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6a/20211106_경춘선_상봉역.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3a/20211126_상봉역_7호선_개찰구.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/cf/Sabost05.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["상봉역", "중랑우체국", "코스트코 상봉점"], "confidence": "high", "address": "대한민국 서울특별시 중랑구 상봉동 115-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('상북농공단지', '태화강 자전거길과 영남알프스를 잇는 길목에 위치한 농공단지입니다. 전국 산악자전거 대회 코스로도 활용되는 주요 라이딩 경유지입니다.', '{landmark,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.074938, 35.610965), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["태화강", "영남알프스", "길천일반산업단지"], "confidence": "high", "address": "대한민국 울산광역시 상북농공단지"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('상생의 손', '동해안의 탁 트인 바다와 쾌적한 도로를 즐길 수 있는 호미곶의 상징적인 랜드마크입니다. 멋진 바다 풍경을 배경으로 라이딩 중 쉬어가기 좋습니다.', '{landmark,viewpoint,park,beach}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.569607, 36.076642), 4326), false, '{"source": "KOMOOT", "source_ids": ["851"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1o/1o3280f0fdxok1ngv30e7nqqaj5kdkwcoc-uhi95861089/0?width=1920&crop=false"], "tips": [{"text": "Very good to ride there, roads in perfect conditions - ocean all over...", "author": "Peter de Alemania"}], "category_raw": "man_made_monument", "tour_count": 1, "nearby_landmarks": ["호미곶 해맞이광장", "호미곶 등대", "새천년기념관"], "confidence": "high", "address": "대한민국 경상북도 포항시 남구 호미곶면 대보리 234-20"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('상이목소류지', '전북 무주군 안성면에 위치한 한적한 소류지(작은 저수지)입니다. 시골길 라이딩 중 조용한 자연 풍경을 감상하며 쉬어가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.657829, 35.849864), 4326), false, '{"source": "KOMOOT", "source_ids": ["814"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["봉화산", "구랑천"], "confidence": "medium", "address": "대한민국 전북특별자치도 무주군 안성면 장기리 608-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신분당선 상현역', '신분당선 상현역으로, 광교호수공원 및 원천천 자전거길로 진입하기 좋은 라이딩 출발지 겸 대중교통 점프 포인트입니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.069297, 37.297583), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/9/98/Q21025131_Sanghyeon_A01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/24/Q21025131_Sanghyeon_A02.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/02/Q21025131_Sanghyeon_A04.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/44/Q21025131_Sanghyeon_A03.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/43/Q21025131_Sanghyeon_A05.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["광교호수공원", "원천천", "신대저수지"], "confidence": "high", "address": "대한민국 경기도 용인시 수지구 상현1동 상현역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('새뜸마을4단지(가온마을1단지)', '새뜸마을4단지와 가온마을1단지 사이에 위치한 버스 정류장입니다. 라이딩 중 위치 확인 및 대중교통 연계 지점으로 활용하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.244452, 36.489323), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["새뜸마을4단지", "가온마을1단지"], "confidence": "high", "address": "대한민국 세종특별자치시 새뜸마을4단지(가온마을1단지)"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('새롬·나성 BRT 정류장', '새롬동과 나성동 경계의 BRT 정류장 일대입니다. 한누리대로 자전거 길과 공공자전거 어울링 대여소가 있어 대중교통과 연계한 도심 라이딩 거점으로 유용합니다.', '{transit,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.257865, 36.486935), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["새롬동·나성동 BRT 정류장", "한누리대로", "나성동 중심상업지구"], "confidence": "high", "address": "대한민국 세종특별자치시 새롬동.나성동"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('새마을사거리', '속초해수욕장과 고속버스터미널 인근에 위치한 교차로입니다. 감성 카페와 식당이 모여있는 ''새마을 골목''과 연결되어 라이딩 중 식사나 휴식을 취하기 좋습니다.', '{convenience_store,cafe,restaurant,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.60145, 38.186049), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["속초해수욕장", "속초고속버스터미널", "조양동 새마을 골목"], "confidence": "high", "address": "대한민국 속초시 새마을"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('사성암 인증센터', '섬진강 자전거길의 필수 기착지인 사성암 인증센터입니다. 아름다운 섬진강 벚꽃길 옆에 위치해 있어 스탬프 인증과 함께 경치를 즐기며 쉬어가기 좋습니다.', '{checkpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.469602, 35.182296), 4326), false, '{"source": "KOMOOT", "source_ids": ["574"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/ri/riwlhqkkg9l3vriyels97hyy5e3v2b2b-uhi87480259/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 1, "nearby_landmarks": ["사성암", "섬진강", "섬진강 벚꽃길"], "confidence": "high", "address": "대한민국 전라남도 구례군 문척면 죽마리 417-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('새양산', '하동군 진교면 양포리 해안가 인근에 위치한 작은 산입니다. 라이딩 중 가벼운 오르막 구간으로 지날 수 있습니다.', '{mountain}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.907408, 34.998933), 4326), false, '{"source": "KOMOOT", "source_ids": ["652"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["남해바다", "금오산", "양포항"], "confidence": "low", "address": "대한민국 경상남도 하동군 진교면 양포리 산84-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('새절역', '불광천 자전거길과 바로 연결되는 6호선 전철역입니다. 따릉이 대여소가 있으며 한강 자전거도로로 진입하기 좋은 주요 접근 포인트입니다.', '{transit,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.913743, 37.591657), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/61/Seoul-metro-616-Saejeol-station-sign-20191022-095836.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/47/Seoul-metro-616-Saejeol-station-entrance-3-20191022-095518.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/ff/새절역_승강장.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9c/새절역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b3/새절역_주박선_승강장.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["불광천", "숭실고등학교"], "confidence": "high", "address": "대한민국 서울특별시 새절역.숭실고입구"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('샘개나루터 샘물', '남한강 자전거길 옆 400년 된 느티나무 아래 위치한 유서 깊은 우물입니다. 라이딩 중 시원한 물을 마시며 쉬어가기 좋은 휴식처입니다.', '{water_fountain,rest_area,historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.757997, 37.166385), 4326), false, '{"source": "KOMOOT", "source_ids": ["994"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/13/13f79senimhga8rh5e0dp09613q6ld9sf-uhi31016970/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/zh/zhegfc6ctnx6111wxecctq61c5567ce34-uhi79500735/0?width=1920&crop=false"], "category_raw": "other_man_made", "tour_count": 1, "nearby_landmarks": ["400년 느티나무", "남한강 자전거길", "샘개나루터"], "confidence": "high", "address": "대한민국 충청북도 충주시 앙성면 강천리 239-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('생태 연못', '동두천 지행동 메타세쿼이아길 산책로 옆에 조성된 생태 연못입니다. 자전거 길과 인접해 있어 라이딩 중 자연 풍경을 감상하며 잠시 쉬어가기 좋습니다.', '{nature,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.055259, 37.888648), 4326), false, '{"source": "KOMOOT", "source_ids": ["320"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["메타세쿼이아길", "지행역", "신천 자전거길"], "confidence": "medium", "address": "대한민국 경기도 동두천시 지행동 725-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('화랑공원 생태호수', '운중천과 금토천 자전거길이 만나는 화랑공원 내 생태호수입니다. 라이딩 중 벤치에 앉아 탁 트인 경치를 감상하며 쉬어가기 좋습니다.', '{lake,park,nature,rest_area,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.103912, 37.398802), 4326), false, '{"source": "KOMOOT", "source_ids": ["241"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["화랑공원", "판교크린타워", "판교환경생태학습원"], "confidence": "high", "address": "observatory, 21 대왕판교로645번길 분당구 성남시 경기도 대한민국"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('서낙동강', '부산 강서구를 흐르는 낙동강 지류입니다. 탁 트인 강변 풍경과 철새 도래지를 감상하며 평온하게 자전거 라이딩을 즐기기 좋은 코스입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.899348, 35.152848), 4326), false, '{"source": "KOMOOT", "source_ids": ["213"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["조만강", "김해평야"], "confidence": "high", "address": "대한민국 부산광역시 강서구 봉림동 767-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('서남교회 주차장', '청주 성화동에 위치한 대형 교회입니다. 주차장이 매우 넓어 라이딩 모임 장소나 출발지로 활용하기 좋으며, 인근에 카페 등 편의시설이 있습니다.', '{landmark,parking,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.450951, 36.618768), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["성화휴먼시아4단지아파트", "소금커피야"], "confidence": "high", "address": "대한민국 청주시 성화휴먼시아4단지아파트"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('서동역', '부산 도시철도 4호선 서동역입니다. 도심 라이딩 중 대중교통 연계(점프)가 가능하며, 인근 서동미로시장에서 식사와 보급을 해결하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.107461, 35.213051), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["서동역", "서동미로시장"], "confidence": "high", "address": "대한민국 부산광역시 금정구 서동 238-59"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('서동탄역', '수도권 전철 1호선 서동탄역입니다. 자전거 보관소와 화장실이 마련되어 있어 라이딩 중 대중교통 연계(점프)나 휴식 지점으로 활용하기 좋습니다.', '{transit,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.051926, 37.195912), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/e/e2/2011-04-29_-_Seodongtan_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d0/Korail-P157-1-Seodongtan-station-platform-20191021-153142.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/fc/Korail-P157-1-Seodongtan-station-entrance-1-20191021-153356.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/12/Korail_Seodongtan_station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0c/Seodongtan_Station.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["병점차량기지", "동탄신도시"], "confidence": "high", "address": "대한민국 경기도 오산시 외삼미로15번길 75-60"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('울산 서동 현대아파트', '울산 동천강 자전거길 인근에 위치한 아파트 단지입니다. 라이딩 중 위치를 파악하는 로컬 랜드마크나 출발 및 도착 지점으로 참고하기 좋습니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.34703, 35.583025), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["동천강 자전거길", "산전교", "동천"], "confidence": "high", "address": "대한민국 울산광역시 중구 동동 7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('서부버스정류장', '부안 시내에서 변산반도, 내소사 방면으로 향하는 길목에 위치한 버스 정류장입니다. 라이딩 중 대중교통 점프나 중간 기착지로 활용하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.730327, 35.726693), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["부안중학교"], "confidence": "high", "address": "대한민국 부안군 서부버스정류장"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('서울대벤처타운역', '도림천(별빛내린천) 자전거길과 바로 연결되는 신림선 전철역입니다. 신림선은 접이식 포함 자전거 승차가 제한되므로 점프(대중교통 연계) 시 주의가 필요합니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.933735, 37.472023), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/e/e2/20220528_서울대벤처타운역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/79/20220419_서울대벤처타운역_2번출구.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f6/20220528_서울대벤처타운역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d2/20220419_서울대벤처타운역_1번출구.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["도림천", "별빛내린천"], "confidence": "high", "address": "대한민국 서울특별시 관악구 신림동 838-22"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('서원리 소나무', '정이품송의 부인으로 불리는 수령 600년의 천연기념물 소나무입니다. 속리산 투어 라이딩 중 웅장한 자태를 감상하며 잠시 쉬어가기 좋은 랜드마크입니다.', '{nature,landmark,historic,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.816228, 36.479696), 4326), false, '{"source": "KOMOOT", "source_ids": ["1158"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1d/1dfnmbmpz6h52suawmzggnpc45kxtz16u-uhi96288108/0?width=1920&crop=false"], "category_raw": "natural_monument", "tour_count": 1, "nearby_landmarks": ["정이품송", "말티재", "삼가저수지", "우당고택"], "confidence": "high", "address": "대한민국 충청북도 보은군 장안면 서원리 45-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('서재자이아파트.평택법원(중)', '서재자이아파트와 평택법원 인근의 중앙버스정류장입니다. 라이딩 중 위치 확인이나 대중교통 점프(연계) 지점으로 참고하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.101858, 37.013057), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["서재자이아파트", "수원지방법원 평택지원", "수원지방검찰청 평택지청"], "confidence": "high", "address": "대한민국 평택시 서재자이아파트.평택법원(중)"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('서정리역', '수도권 전철 1호선 서정리역입니다. 안성천, 평택호, 남양호 방면 자전거 투어의 주요 출발 및 복귀 거점으로 접근성이 좋습니다.', '{transit,restroom,convenience_store,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.053394, 37.057047), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/b/b3/Korail_seojeong-ri_station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0c/Seojeong-ri_Station_3.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0f/Seojeongri_station_metro.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["서정리전통시장", "고덕국제신도시", "안성천 자전거길"], "confidence": "high", "address": "대한민국 평택시 서정리역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('북천 자전거길 종점', '서천에서 이어지는 북천 자전거길이 보문관광단지 부근에서 끝나는 종점입니다. 하천 자전거길 라이딩을 마무리하고 보문단지로 진입하는 주요 거점입니다.', '{river,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.258579, 35.846972), 4326), false, '{"source": "KOMOOT", "source_ids": ["127"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["보문관광단지", "보문호", "경주 동궁원"], "confidence": "high", "address": "대한민국 경상북도 경주시 보문동 28-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('서초역', '서울 지하철 2호선 서초역입니다. 도심 라이딩 시 주말 지하철 점프(연계)나 서리풀공원 방면으로 이동할 때 유용한 기점입니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.007653, 37.49183), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/1/1d/Seoul-metro-224-Seocho-station-platform-20181121-140806.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f9/224_seocho_01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/7c/Seoul-metro-224-Seocho-station-entrance-4-20181121-141346.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/ff/Seochsta01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/02/224_서초_승강장.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["대법원", "서리풀공원", "몽마르뜨공원"], "confidence": "high", "address": "대한민국 서울특별시 서초역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('석대천', '홍천군 내면 광원리를 흐르는 하천으로, 구룡령 업힐 코스를 달리는 라이더들이 맑은 계곡물과 자연 풍경을 감상하며 지나는 길목입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.448836, 37.822552), 4326), false, '{"source": "KOMOOT", "source_ids": ["568"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["구룡령", "계방천", "내린천"], "confidence": "medium", "address": "대한민국 강원특별자치도 홍천군 내면 광원리 545-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('석천사거리', '인천 2호선 석천사거리역이 위치한 도심 교차로입니다. 역 출구에 자전거 보관소가 있으며, 인천시청 방향으로 자전거길이 연결되어 있어 도심 라이딩 경유지로 적합합니다.', '{transit,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.710781, 37.456745), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/1/16/Q20823475_Seokcheon_Sageori_A01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/01/석천사거리역_2번_출입구_야간.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["석천사거리역", "가천대 길병원", "인천시청", "인천 중앙공원"], "confidence": "high", "address": "대한민국 인천광역시 석천사거리"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('석촌고분역', '지하철 9호선 석촌고분역입니다. 따릉이 대여소가 있으며, 인근 석촌동 고분군이나 석촌호수로 향하는 라이딩의 출발점 및 대중교통 연계 지점으로 유용합니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.096615, 37.502497), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/c/ca/932_Seokchon_Gobun_Exit.3.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/24/932_Seokchon_Gobun_board.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a4/932_Seokchon_Gobun_Exit.2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/04/932_Seokchon_Gobun_Exit.4.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/22/Seokchon_Gobun_Station_Exit_1_Pole_Sign_1.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["석촌동 고분군", "석촌호수"], "confidence": "high", "address": "대한민국 서울특별시 송파구 삼전동 90"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('석현저수지', '순천대학교와 향림사 인근에 위치한 한적한 저수지입니다. 동천 자전거길과 연계하여 작은 폭포와 자연 경관을 감상하며 가볍게 쉬어가기 좋습니다.', '{lake,nature,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.467762, 34.976908), 4326), false, '{"source": "KOMOOT", "source_ids": ["519"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["순천대학교", "향림사", "여비산장"], "confidence": "high", "address": "대한민국 전라남도 순천시 석현동 590-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('선부광장', '서해선 선부역 지상에 위치한 넓은 선부광장입니다. 자전거를 세워두고 휴식을 취하거나 대중교통을 연계해 라이딩을 계획하기 좋습니다.', '{park,transit,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.810182, 37.334716), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/6d/Seonbu_Stn._Entrance_1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b7/230909_선부역_출입구.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c7/230909_선부역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/18/230909_선부광장_3.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3a/Seonbu_Stn._board.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["선부역", "다이아몬드광장", "홈플러스 안산선부점"], "confidence": "high", "address": "대한민국 경기도 안산시 단원구 선부동 1074-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('성균관대학교 자연과학캠퍼스', '수원 성균관대학교 자연과학캠퍼스로, 넓은 캠퍼스 내 편의점과 화장실 등 휴식 시설이 잘 갖춰져 있으며 인근 일월저수지 코스와 연계하기 좋습니다.', '{landmark,rest_area,convenience_store,restroom,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.97122, 37.300521), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/f/f5/Sungkyunkwan_University_Station_front_sign_2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/75/Q137235_Sungkyunkwan_University_A01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/59/Korail_Sungkyunkwan_University_Station_building.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/1f/Sungkyunkwan_University_Station_at_Night.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/78/Tanks_at_Sungkyunkwan_University_Station.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["일월저수지", "성균관대역"], "confidence": "high", "address": "대한민국 수원시 율천동 성균관대"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('성동세무서앞', '성동세무서 앞 버스정류장 및 교차로입니다. 중랑천 자전거길과 송정제방길 진출입이 용이해 도심에서 자전거길로 합류하는 거점으로 활용하기 좋습니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.062303, 37.548082), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["성동세무서", "중랑천 자전거길", "송정제방길", "화양사거리"], "confidence": "high", "address": "대한민국 서울특별시 성동구 광나루로 294"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('성복역', '신분당선 성복역으로 성복천 자전거길과 가깝습니다. 대중교통 점프나 역사 내 화장실, 편의점 이용 시 유용한 포인트입니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.080397, 37.313488), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/0/09/Q21025130_Seongbok_A01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/60/Q21025130_Seongbok_A02.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["롯데몰 수지점", "성복천"], "confidence": "high", "address": "대한민국 경기도 용인시 수지구 수지로 지하 134"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('성주산일출전망대', '성주산 업힐 코스 중턱에 위치한 전망대로, 탁 트인 서해 바다와 산 능선을 조망할 수 있습니다. 라이딩 중 멋진 풍경과 함께 휴식과 사진 촬영을 하기 좋은 포인트입니다.', '{viewpoint,mountain,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.632651, 36.337379), 4326), false, '{"source": "KOMOOT", "source_ids": ["903"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["성주산자연휴양림", "성주산 활공장", "성주사지"], "confidence": "high", "address": "대한민국 충청남도 보령시 성주면 성주리 산 37-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('성황당제', '부안 변산면 운산리에 위치한 소규모 저수지로, 한적한 시골길을 따라 여유롭게 라이딩하며 평화로운 농촌 풍경을 즐기기 좋은 지점입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.516934, 35.664416), 4326), false, '{"source": "KOMOOT", "source_ids": ["519"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["운산저수지", "변산반도국립공원"], "confidence": "medium", "address": "대한민국 전북특별자치도 부안군 변산면 운산리 634-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('세검정 홍제천 쉼터', '홍제천 자전거길에서 북악산 방향으로 진입하는 길목입니다. 육교 아래에 자전거 보관대와 벤치가 조성되어 있어 라이딩 중 잠시 쉬어가기 좋습니다.', '{checkpoint,rest_area,transit,historic}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.961224, 37.602281), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["홍제천", "세검정", "장의사지 당간지주"], "confidence": "high", "address": "대한민국 서울특별시 종로구 신영동 198-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('세방낙조전망대', '진도 해안도로에 위치한 다도해 일몰 명소입니다. ''아름다운 자전거길 100선''에 꼽히며, 지속적인 업다운 구간이 있어 라이딩 시 체력 안배가 필요합니다.', '{viewpoint,restroom,parking,nature,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.102443, 34.440266), 4326), false, '{"source": "KOMOOT", "source_ids": ["639"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["다도해", "동석산", "쉬미항", "해비치카페"], "confidence": "high", "address": "대한민국 전라남도 진도군 지산면 가학리 산27-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('세인트존스베리 아카데미 제주', '제주 영어교육도시 내에 위치한 국제학교입니다. 넓고 쾌적한 도로망이 갖춰져 있어 자전거로 주변을 둘러보며 지나가기 좋은 랜드마크입니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.282381, 33.282223), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["제주영어교육도시", "제주신화월드", "오설록 티뮤지엄"], "confidence": "high", "address": "대한민국 서귀포시 세인트존스베리 아케데미제주"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('세종호수공원', '잘 정비된 4.7km의 자전거 전용도로가 있는 국내 최대 인공호수공원입니다. 경사가 평탄하고 경치가 아름다워 초보자도 안전하게 도심 속 힐링 라이딩을 즐기기 좋습니다.', '{park,lake,landmark,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.274963, 36.497259), 4326), false, '{"source": "KOMOOT", "source_ids": ["846"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["국립세종도서관", "대통령기록관", "무대섬"], "confidence": "high", "address": "대한민국 세종특별자치시 연기면 다솜로 216"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('세종고속시외버스터미널', '금강 및 오천 자전거길 종주 시 버스 점프(이동)를 위해 라이더들이 자주 찾는 세종시의 핵심 교통 거점입니다. 터미널 내 편의점과 화장실 등 휴식 인프라가 잘 갖춰져 있습니다.', '{transit,convenience_store,restroom,parking,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.273237, 36.470857), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["금강자전거길", "이응다리(금강보행교)", "학나래교", "세종호수공원"], "confidence": "high", "address": "대한민국 세종특별자치시 세종고속시외버스터미널(지하)"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('세종대왕릉', '남한강 자전거길 여주보 인근에 위치한 유네스코 세계유산입니다. 자전거 종주 중 잠시 들러 역사적 숨결을 느끼며 휴식과 산책을 즐기기 좋은 명소입니다.', '{historic,landmark,museum,park,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.570632, 37.293356), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/0/0b/SejongDaewangneung_Station_Panorama.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/64/Sejong_tomb_1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/73/SejongDaewangneung_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/40/SejongDaewangneung_Station_Exit_1.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["효종대왕릉", "신륵사", "여주보", "남한강 자전거길"], "confidence": "high", "address": "대한민국 경기도 여주시 능서면 신지리 276-13"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('세종예술고등학교', '세종중앙공원 서측에 위치한 예술고등학교입니다. 주변 공원의 자전거 도로가 잘 정비되어 있어 연계 라이딩 코스로 안전하게 지나기 좋습니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.268875, 36.492793), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["세종중앙공원", "세종호수공원", "세종예술의전당"], "confidence": "high", "address": "대한민국 세종특별자치시 세종예술고등학교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('센텀시티', '수영강 자전거길과 인접한 부산의 대표 도심 랜드마크입니다. 다양한 편의시설과 식당, 카페가 밀집해 있어 라이딩 중 쾌적한 휴식과 보급이 가능합니다.', '{landmark,transit,convenience_store,cafe,restaurant,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.131255, 35.168546), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/0/0c/Centum_city_station_sign_20180110_212022_4752.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6a/Busan-subway-206-Centum-city-station-12-entrance.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e7/Q706473_Centum_City_A01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b8/Centum_City_Station,_Busan_Subway_Line_2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8b/Busan-subway-206-Centum-city-station-platform.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["신세계백화점 센텀시티점", "벡스코(BEXCO)", "수영강 자전거길", "APEC나루공원"], "confidence": "high", "address": "대한민국 부산광역시 해운대구 센텀남대로"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('센트럴자이아파트.단재초등학교', '청주 방서동 센트럴자이아파트와 단재초등학교 앞 버스정류장입니다. 서쪽으로 무심천 자전거길이 가까워 라이딩 중 위치를 가늠하거나 대중교통 연계 시 참고하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.504573, 36.599799), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["청주센트럴자이아파트", "단재초등학교", "무심천"], "confidence": "high", "address": "대한민국 충청북도 청주시 상당구 방서동 45-23"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('소광 버스정류장', '전북 부안군 하서면 백련리에 위치한 버스 정류장입니다. 서해랑길 48코스 등 주변을 지나는 라이더들이 대중교통을 연계하거나 잠시 쉬어갈 수 있습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.573039, 35.695469), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["소광교차로", "해창쉼터", "부안신재생에너지테마파크"], "confidence": "high", "address": "대한민국 전북특별자치도 부안군 하서면 백련리 1024"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('양주 소놀이굿전수회관', '국가지정 무형문화재인 양주 소놀이굿을 보존·전승하는 회관입니다. 백석읍 일대를 지나는 라이더들에게 지역 전통문화를 엿볼 수 있는 이색적인 랜드마크가 됩니다.', '{historic,landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.999094, 37.793375), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["양주산성", "불곡산"], "confidence": "high", "address": "대한민국 양주시 소놀이굿전수회관"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('소담고등학교(새샘마을1단지)', '세종시 소담고등학교와 새샘마을 1단지 인근의 버스 정류장입니다. 라이딩 중 위치를 확인하거나 일행과 합류하기 좋은 대중교통 거점입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.303524, 36.481626), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["소담고등학교", "새샘마을1단지", "한국개발연구원(KDI)"], "confidence": "high", "address": "대한민국 세종특별자치시 소담동 587"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('소래습지생태공원', '과거 염전 부지를 복원한 생태공원으로, 갈대밭과 풍차를 배경으로 흙길과 자갈길 등 다채로운 오프로드 라이딩을 즐길 수 있습니다.', '{park,nature,historic,landmark,viewpoint,museum,parking,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.747322, 37.407134), 4326), false, '{"source": "KOMOOT", "source_ids": ["966"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/rt/rtwkg6lxk8iggxcfkvk4iq1i2zbwmvcn-uhi5878499/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/d6/d6yydu4pdzcmznwnwifobxvh2zbwhxk8-uhi5878497/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1l/1ldfxl0k97amf4lu3qrqpxksa2zbwkmxg-uhi5878498/0?width=1920&crop=false"], "tips": [{"text": "Aside from the below features of the park there are also some great walking and cycling trails as well as picnic spots and interactive landmarks. For cyclists there is some single track, rocky track, gravel and raised cycle path above lotus farming ponds and rice fields.  \n\nSome information: \n\nThe Sorae Ecology Park was once a facility used to produce salt until 1999 when it was coverted into a park, restoring the mud flat, tidal channel, and making the closed salt field a ecological habitat for various marine life and migratory birds. The Sorae Ecology Park also provides a history to the facility and houses a Nature Learning Center, where visitors can experience sea salt production and learn more about the various wildlife and plants living in the marsh. \n\nFrom Imagine Your Korea http://english.visitkorea.or.kr/enu/ATR/SI_EN_3_1_1_1.jsp?cid=1751275\n\nOfficial Park Website (KR/EN/JP/CN): http://park.incheon.go.kr/index.do", "author": ""}], "category_raw": "natural_monument", "tour_count": 1, "nearby_landmarks": ["소래포구", "소래포구 종합어시장", "소래습지생태공원 전시관", "풍차"], "confidence": "high", "address": "대한민국 인천광역시 남동구 논현동 1-20"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('소로정류장', '청주시 옥산면 소로리에 위치한 시내버스 정류장입니다. 오천자전거길과 인접해 있으며, 소로리 볍씨 마을을 방문할 때 거쳐가기 좋은 웨이포인트입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.403764, 36.684987), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["소로보건진료소", "소로마을회관", "소로리 볍씨마을"], "confidence": "high", "address": "대한민국 충청북도 청주시 흥덕구 옥산면 소로리 418-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('소요산', '중랑천과 신천 자전거길을 따라 북상하는 라이딩 코스의 인기 목적지입니다. 1호선 소요산역을 이용한 점프(복귀)가 편리해 많은 라이더들이 찾습니다.', '{mountain,nature,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.060645, 37.948022), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/65/Korail_Gyeongwon_Line_Soyosan_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e1/100_소요산역_역명판.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c6/SoyosanStnPlatform2Sign.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/14/Korail_Gyeongwon_Line_Soyosan_Station_Platform1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9b/Korail_Gyeongwon_Line_Soyosan_Station_Platform2.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["소요산역", "신천 자전거길", "자재암"], "confidence": "high", "address": "대한민국 경기도 동두천시 상봉암동 122-11"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('소전소류지', '진천 농다리와 먹뱅이산 인근에 위치한 작고 조용한 저수지입니다. 한적한 시골길 라이딩 중 자연 경관을 감상하며 쉬어가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.478464, 36.817043), 4326), false, '{"source": "KOMOOT", "source_ids": ["191"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["진천농다리", "먹뱅이산", "농암정"], "confidence": "high", "address": "대한민국 충청북도 진천군 문백면 평산리 231-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('소호제', '여수 소호동에 위치한 저수지로, 섬달천이나 와온해변 방향으로 향하는 라이딩 코스의 주요 기점 역할을 합니다. 조용한 자연 경관을 즐길 수 있습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.636717, 34.738398), 4326), false, '{"source": "KOMOOT", "source_ids": ["101"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["안심산", "소호동동다리", "여수소호요트장"], "confidence": "high", "address": "대한민국 전라남도 여수시 소호동 796"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('속초 관광수산시장', '닭강정과 아바이순대 등 먹거리가 풍부한 속초 대표 전통시장입니다. 자전거 라이딩 중 든든하게 배를 채우고 휴식하기 좋은 필수 방문 코스입니다.', '{landmark,restaurant,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.591375, 38.203591), 4326), false, '{"source": "KOMOOT", "source_ids": ["1777"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/16/16zvd0v6mdljq1oejmp2ky8gi730kxic59-uhi6405050/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/i5/i5lr1cd0o99hx9ibk5omoe3x30m8rb39-uhi6416760/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/zp/zp33gezoto8nxeg3u8qpebf30kxigas-uhi6405055/0?width=1920&crop=false"], "tips": [{"text": "Has changed its name to Tourist & Fishery Market (formerly Jungang Market), this market was opened in 1982, and is comprised of around 450 stores throughout 1 basement level and 2 above-ground levels.\nFishery items and hoetjip (raw fish restaurants) are located on the basement level, and general whole sales and retail sales, such as food and clothes, are available on the first and second floors. In addition, many of Sokcho''s famous snacks like dak-gangjeong (sweet and sour chicken) are found at many of the stalls inside the market.", "author": "Wanderschnecke"}], "category_raw": "settlement", "tour_count": 1, "nearby_landmarks": ["아바이마을", "청초호", "영랑호"], "confidence": "high", "address": "대한민국 강원특별자치도 속초시 중앙동 476-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('속초시외버스터미널', '동해안 자전거길 종주 시 출발 및 도착지로 자주 이용되는 대중교통 거점입니다. 주변에 식당과 편의시설이 많아 라이딩 전후 보급과 휴식에 좋습니다.', '{transit,restroom,convenience_store,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.590826, 38.210763), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["동명항", "영금정", "속초항"], "confidence": "high", "address": "대한민국 강원특별자치도 속초시 수복로259번길 13"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('손곡초등학교', '용인 수지구에 위치한 초등학교로, 인근 동막천과 손곡천 자전거도로를 통해 탄천으로 연계 라이딩하기 좋은 웨이포인트입니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.095453, 37.336124), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["동막천", "손곡천", "탄천 자전거도로"], "confidence": "high", "address": "대한민국 용인시 손곡초등학교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('솔밭근린공원', '1천여 그루의 소나무가 울창한 도심 속 평지형 공원입니다. 화장실과 벤치 등 휴식 시설이 잘 갖춰져 있어 라이딩 중 시원한 그늘에서 쉬어가기 좋습니다.', '{park,nature,rest_area,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.013258, 37.656068), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/c/cc/Solbat_Park.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/00/Ui_Line_Solbat_Park_Exit_1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/58/Ui_Line_Solbat_Park_Exit_2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/87/Solbat_Park_Station_Platform_1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d7/Solbat_Park_Station_Screendoor_1.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["북한산 둘레길", "국립4.19민주묘지", "솔밭공원역"], "confidence": "high", "address": "대한민국 서울특별시 솔밭공원"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('송림제', '나주 봉황면에 위치한 송림저수지(송림제)입니다. 탁 트인 수변 풍경을 감상하며 한적한 시골길 라이딩 중 잠시 쉬어가기 좋은 자연 스팟입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.800214, 34.964856), 4326), false, '{"source": "KOMOOT", "source_ids": ["197"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["당촌마을", "빛가람혁신도시"], "confidence": "high", "address": "대한민국 전라남도 나주시 봉황면 송현리 931-11"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('송말2리', '이천 백사면 산수유마을 인근의 조용한 시골 마을입니다. 오래된 느티나무 숲이 있으며, 송말천 자전거길을 통해 복하천과 남한강으로 이어지는 길목에 위치합니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.481383, 37.346682), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["산수유마을", "송말천", "느티나무 숲"], "confidence": "high", "address": "대한민국 이천시 송말2리"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구 송정역', '해운대 블루라인파크 해변열차의 종착역입니다. 옛 송정역 철길의 정취를 느낄 수 있으며, 송정해수욕장과 인접해 라이딩 중 쉬어가기 좋은 랜드마크입니다.', '{transit,landmark,historic,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.199769, 35.180276), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["송정해수욕장", "구 송정역"], "confidence": "high", "address": "대한민국 부산광역시 해운대구 송정동 299-21"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('송학역 체육공원', '과거 태백선 송학역 폐역 부지로 현재는 체육공원으로 조성되어 있습니다. 제천-영월 구간 라이딩 시 이정표 및 가벼운 휴식처로 삼기 좋은 랜드마크입니다.', '{historic,park,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.270016, 37.187139), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/62/Korail_Taebaek_Line_Songhak_Station.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["제천사회인야구장", "송학산", "월명사"], "confidence": "high", "address": "대한민국 충청북도 제천시 송학면 무도리 147-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('쇠소깍 인증센터', '제주 환상자전거길의 필수 기착지인 쇠소깍 인증센터가 있습니다. 효돈천과 바다가 만나는 독특하고 아름다운 절경을 감상하며 쉬어가기 좋은 곳입니다.', '{checkpoint,river,viewpoint,nature,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.623169, 33.252127), 4326), false, '{"source": "KOMOOT", "source_ids": ["146"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/10/10h04qa8t0ywpdr620mdqldrl4xpmdf2w-uhi70534214/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1v/1v6zkha62vv5rt7ztvot8vkff5akp6w99-uhi83572332/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/oq/oqzzh4bfkb691myzyx492f7sy5g1yibaz-uhi90077022/0?width=1920&crop=false"], "tips": [{"text": "Certification Stamp Booth", "author": "Fitz_carraldo"}], "category_raw": "river", "tour_count": 1, "nearby_landmarks": ["쇠소깍", "하효항", "효돈천"], "confidence": "high", "address": "대한민국 제주특별자치도 서귀포시 하효동 995"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('쇠터울천', '구룡령 업힐 코스 길목인 홍천 광원리를 흐르는 작은 하천입니다. 맑은 물과 산세가 어우러져 라이딩 중 자연을 만끽하며 쉬어가기 좋은 포인트입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.419442, 37.820255), 4326), false, '{"source": "KOMOOT", "source_ids": ["671"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["구룡령", "삼봉자연휴양림", "홍천은행나무숲"], "confidence": "high", "address": "대한민국 강원특별자치도 홍천군 내면 광원리 953"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('수성구민운동장', '화장실, 식수대, 주차장이 잘 갖춰져 있어 라이딩 중 휴식하기 좋은 체육공원입니다. 단, 잔디구장 및 트랙 내 자전거 진입은 제한되니 주의가 필요합니다.', '{park,restroom,water_fountain,parking,transit,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.625003, 35.852384), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/d2/20240427_110309._jpg.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/35/Suseong_District_Stadium_Station_20150424_164151.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/ea/Suseong_District_Stadium_Station_20150424_164204.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/69/DTRO_subway_station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e2/Suseong_District_Stadium_Station_20150424_164050.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["수성구민운동장역", "범어공원", "어린이회관"], "confidence": "high", "address": "대한민국 대구광역시 수성구민운동장"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('수성구청', '라이딩 중 안전하게 휴식하며 화장실과 식수를 이용할 수 있는 유용한 거점입니다. 인근에 수성구청역과 범어공원이 있어 접근성이 좋습니다.', '{restroom,water_fountain,rest_area,parking,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.635767, 35.858874), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["수성구청역", "범어공원", "수성경찰서"], "confidence": "high", "address": "대한민국 대구광역시 범어4동 수성구청"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('수영역', '부산 도시철도 2호선과 3호선의 환승역으로, 주말 및 공휴일 자전거 휴대 승차를 이용한 점프(대중교통 이동)나 라이더들의 만남의 장소로 유용한 교통 거점입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.114747, 35.165408), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/3/32/Busan-subway-Suyeong-station-14-entrance.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/ed/Suyeong_station_Busan_metro_line3_sign_20180317_214514.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/da/Suyeong_station_Busan_metro_line2_platform_20180317_214150.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/7a/208suyeong.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/87/301suyeong2.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["수영교차로", "수영구보건소", "팔도시장"], "confidence": "high", "address": "대한민국 부산광역시 광안제3동 수영"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('수철저수지', '망경산과 광덕산 임도 라이딩을 향하는 길목에 위치한 경치 좋은 저수지입니다. 본격적인 업힐 코스 진입 전 풍경을 감상하며 워밍업하기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.060408, 36.725), 4326), false, '{"source": "KOMOOT", "source_ids": ["182"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["산들낚시터", "망경산", "광덕산"], "confidence": "high", "address": "대한민국 충청남도 아산시 배방읍 수철리 272-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('순창공용버스터미널', '섬진강 및 영산강 자전거길 종주 시 대중교통 점프 거점으로 유용한 공용버스터미널입니다. 내부에 화장실과 카페 등 편의시설이 있습니다.', '{transit,restroom,cafe,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.14146, 35.376734), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["순창시장", "순창전통고추장마을"], "confidence": "high", "address": "대한민국 전북특별자치도 순창군 순창읍 순화리 115-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('순천경찰서', '순천시 가곡동에 위치한 순천경찰서입니다. 안전한 라이딩을 위한 랜드마크이자, 긴급 상황 발생 시 신속하게 도움을 요청할 수 있는 주요 치안 시설입니다.', '{police,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.482279, 34.973388), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["가곡동", "동천"], "confidence": "high", "address": "대한민국 순천시 순천경찰서"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('순천문학관', '동천 자전거길 코스에 위치해 라이딩 중 들르기 좋은 문학관입니다. 김승옥, 정채봉 작가의 작품을 감상하며 고즈넉하게 쉬어갈 수 있습니다.', '{museum,rest_area,landmark,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.516467, 34.895741), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["순천만습지", "순천만국가정원", "낭트정원", "스카이큐브 문학관역"], "confidence": "high", "address": "대한민국 전라남도 순천시 교량동 146-21"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('숭례문(남대문)', '서울 도심 라이딩 시 거쳐가는 상징적인 역사 랜드마크입니다. 주변 차량 통행이 많아 주의가 필요하지만 훌륭한 포토 스팟이 됩니다.', '{historic,landmark,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.975512, 37.560291), 4326), false, '{"source": "KOMOOT", "source_ids": ["150"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k0/sk/sk520k2xm88n1re9y6agtl2qt1r6c3cdu-uhi318539/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k0/94/94xv1j1pxjihcvhtyphksg6f1r6c3noi-uhi318540/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1jz/19/19076atea244kl45dzu3hqrmc1fo9h5ka-uhinull/0?width=1920&crop=false"], "tips": [{"text": "Namdaemun (Hangul: 남대문; hanja: 南大門, South Great Gate), officially known as the Sungnyemun (Hangul: 숭례문; hanja: 崇禮門, Gate of Exalted Ceremonies), is one of the Eight Gates in the Fortress Wall of Seoul, South Korea, which surrounded the city in the Joseon dynasty. The gate is located in Jung-gu between Seoul Station and Seoul Plaza, with the historic 24-hour Namdaemun market next to the gate.\nThe gate, dating back to the 14th century, is a historic pagoda-style gateway, and is designated as the first National Treasure of South Korea. It was once one of the three major gateways through Seoul''s city walls which had a stone circuit of 18.2 kilometres (11.3 mi) and stood up to 6.1 metres (20 ft) high. It was first built in the last year of King Taejo of Joseon''s reign in 1398, and rebuilt in 1447.\nIn 2008, the wooden pagoda atop the gate was severely damaged by arson and was restored by 2013. \nThe changing-of-guards ceremonies takes place daily every 2-3 times a day, with free access.\nhttps://en.wikipedia.org/wiki/Namdaemun", "author": "🕊️ 𝑻𝒓𝒂𝒗𝒆𝒍𝒆𝒓"}], "category_raw": "historical_site", "tour_count": 1, "nearby_landmarks": ["남대문시장", "서울시청", "서울역"], "confidence": "high", "address": "대한민국 서울특별시 중구 남대문로4가 24"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('회동수원지 숲길', '회동수원지를 따라 조성된 고즈넉한 숲길입니다. 일부 맨발 걷기 구간 등 자전거 진입이 제한되는 보행자 전용 산책로가 있을 수 있으니 주의하세요.', '{nature,lake,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.125759, 35.261422), 4326), false, '{"source": "KOMOOT", "source_ids": ["415"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/13/130ys4p6be1bibosfsgrfkziz3pqo3p09-uhi30412700/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/5k/5kcrnwkrdgovr8s6eqshms8v3pqo3yir-uhi30412703/0?width=1920&crop=false"], "tips": [{"text": "Forest road", "author": "KS Bang"}], "category_raw": "trail", "tour_count": 1, "nearby_landmarks": ["회동수원지", "땅뫼산 황토숲길", "오륜대"], "confidence": "high", "address": "대한민국 부산광역시 금정구 오륜동 산80-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('스위트팰리스', '부산 명지국제신도시의 아파트 단지입니다. 인근에 울림공원과 낙동강 자전거길이 있어 라이딩 시 만남의 장소나 랜드마크로 활용됩니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.919378, 35.109433), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["울림공원", "낙동강 자전거길"], "confidence": "high", "address": "대한민국 부산광역시 스위트팰리스"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('부산시민공원 자전거 보관소', '부산시민공원 내부는 자전거 진입이 전면 금지되어 있습니다. 라이딩 중 방문 시 공원 각 출입구에 마련된 자전거 보관소에 주차 후 도보로 이용해야 합니다.', '{parking,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.060302, 35.167924), 4326), false, '{"source": "KOMOOT", "source_ids": ["464"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1q/1qr7sev0z041xd3pqhvqfw5mw5i7bou24-uhi93285559/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1f/1fzd6g8wrkydz9ntek5tgd7ar5i8nkedv-uhi93328802/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1l/1l9i0goaziy7bbdhszh18u8uw5i8nkeg8-uhi93328803/0?width=1920&crop=false"], "category_raw": "parking", "tour_count": 1, "nearby_landmarks": ["기억의 숲", "참여의 벽"], "confidence": "high", "address": "대한민국 부산광역시 부산진구 범전동 57 기억의 숲 참여의벽"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('시알들삼거리', '대덕산업단지 내 위치한 교차로입니다. 공단 지역 특성상 대형 차량 통행이 잦을 수 있으므로 라이딩 시 각별한 주의가 필요합니다.', '{transit,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.411553, 36.434629), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["벤처타운장영실관", "대덕산업단지"], "confidence": "high", "address": "대한민국 대전광역시 대덕구 산업단지로116번길 91"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신검단중앙역', '2025년 개통한 인천 1호선 전철역입니다. 자전거 보관소와 화장실이 갖춰져 있어 대중교통 연계(점프) 및 휴식 거점으로 유용합니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.698525, 37.602661), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["산들바람공원", "창신초등학교", "신검단중앙역풍경채어바니티"], "confidence": "high", "address": "대한민국 인천광역시 서구 원당동 636-15"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신계입구', '경주 외동읍 신계마을 진입로에 위치한 버스정류장입니다. 주변에 저수지와 숙박시설이 많아 라이딩 시 위치 확인이나 코스 진입 기점으로 활용하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.31001, 35.766947), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["신계저수지", "괘릉저수지", "성호리조트"], "confidence": "high", "address": "대한민국 경상북도 경주시 외동읍 괘릉리 1084-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신도림역 자전거 거점', '도림천 자전거길과 인접한 교통의 요지 신도림역입니다. 대형 자전거 주차장과 수리 센터가 있어 라이딩 중 정비나 휴식을 취하기 좋습니다.', '{transit,parking,bike_shop,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.891816, 37.509193), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/53/Q43298_Sindorim_B01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2e/Sindorim_Station_(Seoul_Subway_Line_1)_20230430_005.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/94/Korail_Sindorim_Station_platform.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8d/신도림역_지선_승강장에_전동차_진입.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/41/140sindorim.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["도림천", "디큐브시티", "신도림 오페라하우스"], "confidence": "high", "address": "대한민국 서울특별시 구로구 신도림동 349-47"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신동제', '전남 진도군 임회면에 위치한 한적한 저수지입니다. 조용한 시골길 라이딩 중 자연 풍경을 감상하며 잠시 쉬어가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.197613, 34.378483), 4326), false, '{"source": "KOMOOT", "source_ids": ["433"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["국립남도국악원", "여귀산"], "confidence": "high", "address": "대한민국 전라남도 진도군 임회면 봉상리 613-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신림역 별빛내린천', '도림천(별빛내린천) 자전거길과 연결되는 신림역 일대입니다. 인근 자전거종합센터에서 경정비가 가능하며, 상권이 발달해 보급과 휴식에 매우 좋습니다.', '{transit,river,bridge,bike_shop,convenience_store,restaurant,cafe,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.929643, 37.48464), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/2/2a/20200906_신림역_8번_출구.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d6/20231213_신림역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/43/Q487848_Sillim_A02.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8e/20250705_신림역_개찰구.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/de/20230620_신림역_개찰구2.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["신림역", "도림천 자전거길", "관악구 자전거종합센터", "별빛내린천"], "confidence": "high", "address": "대한민국 서울특별시 신림"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신목동역', '안양천 자전거길과 바로 연결되는 9호선 지하철역으로, 한강 합수부나 목동 시내로 진출입하기 매우 편리한 라이딩 거점입니다.', '{transit,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.8831, 37.544206), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/6f/911_Sinmokdong.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["안양천 자전거길", "안양천 한강 합수부", "용왕산 근린공원"], "confidence": "high", "address": "대한민국 서울특별시 신목동역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신복4리 버스정류장', '중미산 업힐 코스 길목에 위치한 버스 정류장입니다. 동부고개 라이딩 중 위치를 가늠하거나 잠시 정차해 쉬어가기 좋습니다.', '{transit,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.456543, 37.586134), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["중미산", "중미산자연휴양림", "신복리 펜션단지"], "confidence": "high", "address": "대한민국 경기도 양평군 옥천면 신복리 90-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신사역', '3호선과 신분당선 환승역인 신사역입니다. 잠원한강공원 자전거길과 가까워 접근성이 좋으며, 주말 3호선을 이용한 자전거 점프(지하철 이동)나 만남의 장소로 유용합니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.019515, 37.516111), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/dc/Q100839_Sinsa_B01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/1f/Sinsa01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a1/Q100839_Sinsa_B05.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6d/Sinsa02.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3e/Q100839_Sinsa_B03.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["가로수길", "잠원한강공원", "한남대교"], "confidence": "high", "address": "대한민국 서울특별시 신사동 신사"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('죽림 신우희가로 아파트', '통영 죽림해안로 인근에 위치한 아파트 단지입니다. 라이딩 시 죽림신도시 진입을 알리는 이정표나 지역 라이더들의 출발 및 만남의 장소로 활용할 수 있습니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.419803, 34.888539), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["죽림해안로", "통영종합버스터미널", "내죽도수변공원"], "confidence": "high", "address": "대한민국 통영시 신우희가로"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신원역', '남한강 자전거길이 지나는 경의중앙선 전철역으로, 대중교통 연계(점프)와 휴식을 위해 라이더들이 자주 찾는 주요 거점입니다.', '{transit,rest_area,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.372701, 37.525749), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/2/21/K131_Sinwon_01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/96/K131_Sinwon_02.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["남한강 자전거길", "몽양 여운형 생가", "부용터널"], "confidence": "high", "address": "대한민국 양평군 신원역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신이문역', '수도권 전철 1호선 신이문역입니다. 중랑천 자전거길과 인접해 있어 라이딩 중 지하철 점프(자전거 휴대 승차)나 화장실을 이용하기 좋은 거점입니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.067173, 37.601687), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/3/31/Korail-121-Sinimun-station-sign-20180914-094246.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/68/Korail_sinimun_station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/97/Korail-121-Sinimun-station-entrance-4-20180914-094030.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/20/121_sinimun_02.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a8/121_sinimun_01.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["중랑천 자전거길", "석관지하보차도"], "confidence": "high", "address": "대한민국 서울특별시 동대문구 이문동 220-358"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신제주오피스텔', '제주시 연동 상권에 위치한 오피스텔입니다. 공항과 가깝고 주변에 식당과 편의시설이 많아 라이딩 전후 숙소나 경유지로 활용하기 좋습니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.489854, 33.483203), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["제주국제공항", "누웨마루거리", "삼무공원"], "confidence": "high", "address": "대한민국 제주시 신제주오피스텔"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신진동', '남한강 자전거길과 강천보가 인접한 여주시의 동네입니다. 평탄한 강변 코스로 국토종주 라이더들이 쾌적하게 지나는 길목입니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.675733, 37.274918), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["남한강 자전거길", "강천보", "금은모래강변공원"], "confidence": "high", "address": "대한민국 여주시 신진동"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신창저수지', '봄철 겹벚꽃 명소로 유명한 저수지입니다. 인근 개심사, 서산 한우목장과 연계하여 아름다운 자연 풍경 속에서 라이딩을 즐기기 좋습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.577237, 36.749548), 4326), false, '{"source": "KOMOOT", "source_ids": ["268"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["개심사", "서산 한우목장"], "confidence": "high", "address": "대한민국 충청남도 서산시 운산면 신창리 81-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신촌저수지', '보령방조제와 오천항으로 향하는 길목에 위치한 고즈넉한 저수지입니다. 해안가 라이딩 중 탁 트인 수변 풍경을 감상하며 쉬어가기 좋습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.543432, 36.445962), 4326), false, '{"source": "KOMOOT", "source_ids": ["497"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["보령방조제", "오천항", "충청수영성"], "confidence": "high", "address": "대한민국 충청남도 보령시 오천면 소성리 산8-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신평역 자전거 주차장', '낙동강 자전거길 및 노을나루길과 연결되며, 대규모 자전거 전용 주차장을 갖춘 부산 1호선 전철역입니다.', '{transit,parking,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.960729, 35.09519), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/db/Sinpyeong_station_002.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/88/Sinpyeong_station_sign_20180420_185951.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/4f/Sinpyeong_Station4.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/38/Sinpyeong_Station_5.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/52/Sinpyoeng_Station_Tracks.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["낙동강 하구둑", "을숙도"], "confidence": "high", "address": "대한민국 부산광역시 신평역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신평1리', '강원도 고성군의 한적한 농촌 마을입니다. 백두대간 산세와 넓은 들판을 감상하며 여유롭게 라이딩하기 좋고, 마을회관 주변에서 잠시 쉬어가기 적합합니다.', '{other,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.533245, 38.256458), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["신평천", "신성봉"], "confidence": "high", "address": "대한민국 고성군 신평1리"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('심곡저수지', '경주 도리마을 은행나무 숲 인근에 위치한 저수지로, 수변 데크길이 조성되어 있어 라이딩 중 고즈넉한 풍경을 감상하며 쉬어가기 좋습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.05912, 35.918004), 4326), false, '{"source": "KOMOOT", "source_ids": ["329"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["도리 은행나무 숲", "심곡저수지 둘레길"], "confidence": "high", "address": "대한민국 경상북도 경주시 서면 심곡리 143-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('심동저수지', '진도 동석산의 웅장한 암릉과 푸른 들판이 어우러진 평화로운 저수지입니다. 세방낙조 해안도로 라이딩 중 탁 트인 자연 경관을 감상하며 지나가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.118848, 34.407765), 4326), false, '{"source": "KOMOOT", "source_ids": ["738"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["동석산", "급치산", "세방낙조전망대"], "confidence": "high", "address": "대한민국 전라남도 진도군 지산면 심동리 532-22"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('심학교', '파주출판단지와 심학산 인근에 위치한 교량입니다. 평화누리길 자전거 코스를 주행할 때 지나가는 주요 길목 역할을 합니다.', '{bridge}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.689512, 37.716608), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["파주출판단지", "심학산", "평화누리길"], "confidence": "high", "address": "대한민국 파주시 심학교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('담양 곰보배추 우렁쌈밥', '영산강 자전거길과 담양습지 인근에 위치한 유명 농가맛집입니다. 라이딩 중 든든하고 건강한 곰보배추 우렁쌈밥으로 기력을 보충하기 좋습니다.', '{restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.880292, 35.248453), 4326), false, '{"source": "KOMOOT", "source_ids": ["91"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/o8/o8g6dtn79ost6yhtux9g26hr37e5ekd3-uhi9476443/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1p/1ponhrj2q9oxylitp9zg250a737e5emou-uhi9476444/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/13/138z5b1207m5w13zcqs6ki32wo37e5en2a-uhi9476445/0?width=1920&crop=false"], "category_raw": "restaurant", "tour_count": 1, "nearby_landmarks": ["영산강 자전거길", "담양습지"], "confidence": "high", "address": "대한민국 전라남도 담양군 대전면 응용리 280-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('쌍룡계곡', '맑은 물과 기암괴석이 어우러진 수려한 계곡입니다. 계곡을 따라 이어지는 도로는 경치가 뛰어나며, 여름철 라이딩 중 시원하게 휴식을 취하기 좋은 자연 명소입니다.', '{nature,river,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.965757, 36.562176), 4326), false, '{"source": "KOMOOT", "category_raw": "55", "tour_count": 1, "nearby_landmarks": ["도장산", "STX리조트", "용추교"], "confidence": "high", "address": "대한민국 경상북도 문경시 농암면 내서리 산17-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('쌍용아진 그린타운1차', '동천 자전거길과 인접한 울산 북구의 아파트 단지입니다. 단지 상가에 편의점이 있어 라이딩 전후 보급품을 구매하거나 만남의 장소로 활용하기 좋습니다.', '{landmark,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.342762, 35.628771), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["동천 자전거길", "동천강"], "confidence": "high", "address": "대한민국 울산광역시 북구 상안동 358-19"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('쓰노시마 대교', '에메랄드빛 바다 위를 달리는 1,780m의 절경 교량입니다. 자전거 전용도로가 없고 갓길이 좁아 차량 주의가 필요하며, 강풍 시 통행이 제한될 수 있습니다.', '{bridge,viewpoint,landmark,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(130.887092, 34.352451), 4326), false, '{"source": "KOMOOT", "source_ids": ["9"], "category_raw": "bridge", "tour_count": 1, "nearby_landmarks": ["쓰노시마 등대", "아마가세 공원", "쓰노시마 오하마 해수욕장"], "confidence": "high", "address": "9V2P+XR 일본 야마구치현 나가토시"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('쓰리재', '설악그란폰도 극악업힐 3대장 중 하나로 악명 높은 인제의 고개입니다. 10% 이상의 가파른 경사도로 라이더들의 한계를 시험하는 도전적인 코스입니다.', '{mountain,viewpoint,checkpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.373005, 38.003794), 4326), false, '{"source": "KOMOOT", "source_ids": ["742"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["설악그란폰도 포토존", "진동계곡", "방동임도"], "confidence": "high", "address": "공원 park, 1014, 진동리 기린면 인제군 강원특별자치도 대한민국"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('쓰시마교통 히타카쓰 영업소', '쓰시마 북부 지역의 버스 노선을 관할하는 쓰시마교통 영업소입니다. 기상 악화나 자전거 고장 시 대중교통(윤행) 이용을 위해 참고할 수 있는 주요 거점입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.4588, 34.653429), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["히타카쓰항", "가미쓰시마 고등학교"], "confidence": "high", "address": "309 Kamitsushimamachi Hitakatsu, Tsushima, Nagasaki 817-1701 일본"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('아도니스CC 진입로', '포천 아도니스CC로 향하는 진입로입니다. 라이딩 중 방향을 확인하거나 코스의 주요 기점으로 삼기 좋은 랜드마크입니다.', '{landmark,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.180087, 37.952036), 4326), false, '{"source": "KOMOOT", "source_ids": ["588"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["아도니스CC", "포천천"], "confidence": "high", "address": "대한민국 포천시 계류1리"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('아메리칸 불고기', '군산 미공군기지 정문 인근에 위치한 가성비 좋은 식당입니다. 푸짐한 양의 퓨전 불고기를 제공하여 라이딩 중 든든하게 에너지를 보충하기 좋습니다.', '{restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.632622, 35.920858), 4326), false, '{"source": "KOMOOT", "source_ids": ["121"], "tips": [{"text": "Just outside Front Gate of Kunsan AB very good and reasonably priced. Large portions from 7 to 10,000 won.", "author": "Christopher E"}], "category_raw": "restaurant", "tour_count": 1, "nearby_landmarks": ["군산 미공군기지"], "confidence": "high", "address": "대한민국 전북특별자치도 군산시 옥서면 선연리 1751-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('아산시공설봉안당', '아산시 송악면에 위치한 공설 장사시설(추모공원)입니다. 광덕산이나 봉수산 임도(MTB 코스)로 진입할 때 위치를 가늠하는 랜드마크로 참고할 수 있습니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.98964, 36.65363), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["광덕산 임도", "봉수산 임도", "각흘고개"], "confidence": "high", "address": "대한민국 아산시 아산시공설봉안당"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('아성교통관광', '괴산과 증평 일대를 운행하는 농어촌 버스 차고지입니다. 라이딩 중 긴급하게 대중교통(점프)을 이용해야 할 때 참고할 수 있는 지점입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.797595, 36.808299), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["괴산시외버스터미널"], "confidence": "high", "address": "대한민국 충청북도 괴산군 괴산읍 동부리 793-41"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('아야진등대', '동해안 자전거길 고성 구간의 아야진항에 위치한 등대입니다. 탁 트인 바다 풍경과 독특한 거북바위를 감상하며 라이딩 중 잠시 쉬어가기 좋은 조망 포인트입니다.', '{landmark,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.556229, 38.274113), 4326), false, '{"source": "KOMOOT", "source_ids": ["1498"], "category_raw": "19", "tour_count": 1, "nearby_landmarks": ["아야진항", "아야진해변", "거북바위", "능파대"], "confidence": "high", "address": "대한민국 강원특별자치도 고성군 토성면 아야진리 1-1 토성면 아야진리 1-1번지 고성군 강원도 KR 24756"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('아우라지', '송천과 골지천이 어우러지는 정선아리랑의 발상지입니다. 수려한 자연경관과 섶다리, 처녀상 등 볼거리가 많아 자전거 여행 중 들르기 좋은 매력적인 명소입니다.', '{river,landmark,historic,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.722215, 37.472741), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["아우라지역", "아우라지 섶다리", "아우라지 처녀상", "정선레일바이크"], "confidence": "high", "address": "대한민국 강원특별자치도 정선군 여량면 여량리 256-12"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('아주 마을회관 공원', '거제 아주동에 위치한 작은 마을회관 공원입니다. 라이딩 중 가볍게 휴식을 취하거나 재정비하기 좋은 한적한 동네 쉼터입니다.', '{park,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.692834, 34.86752), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["아주동 신협"], "confidence": "medium", "address": "대한민국 경상남도 거제시 아주동 463"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('안골광장', '전주시 인후동 안골사거리 일대입니다. 벤치가 있는 안골광장이 있어 도심 라이딩 중 휴식하기 좋으며, 주변에 식당과 카페가 많아 보급하기 편리한 교차로입니다.', '{rest_area,restaurant,cafe,convenience_store,park,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.154679, 35.836536), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["안골사거리", "안골광장"], "confidence": "high", "address": "대한민국 전주시 안골"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('안국역', '인사동, 북촌 등 도심 라이딩의 기점이 되는 3호선 전철역입니다. 유동인구가 많아 보행자 안전에 유의해야 하며, 주말 지하철 점프나 화장실 이용 시 편리합니다.', '{transit,restroom,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.986196, 37.576837), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/3/37/Anguk_Station_20230402_004.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d3/Anguk_Station_20230402_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c7/Seoul_Metro_Anguk_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/84/Seoul-metro-328-Anguk-station-entrance-1-20181126-081934.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2f/Seoul-metro-328-Anguk-station-entrance-2-20181126-081342.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["북촌한옥마을", "인사동", "창덕궁", "경복궁"], "confidence": "high", "address": "대한민국 서울특별시 종로구 재동 99-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('안남동', '제주시 애월읍 하귀1리에 위치한 자연마을 안남동입니다. 제주시에서 애월 방면으로 라이딩 시 거쳐가게 되는 한적하고 조용한 동네입니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.406549, 33.482594), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["애월해안도로", "하귀1리"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 애월읍 하귀1리 1373-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('안산', '대전 한밭대학교와 수통골 인근에 위치한 해발 130m의 얕은 야산입니다. 수통골 라이딩 코스와 연계하여 짧은 업힐이나 가벼운 산책 코스로 다녀오기 좋습니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.29727, 36.347131), 4326), false, '{"source": "KOMOOT", "source_ids": ["329"], "category_raw": "191", "tour_count": 1, "nearby_landmarks": ["한밭대학교", "수통골"], "confidence": "high", "address": "대한민국 대전광역시 유성구 동서대로179번길 28-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('안양역 (안양천 자전거길)', '안양천 자전거길과 가까운 안양역입니다. 대형 쇼핑몰(엔터식스)과 식당가가 있어 라이딩 중 든든한 보급과 휴식, 대중교통 점프가 모두 가능합니다.', '{transit,landmark,convenience_store,restaurant,cafe,restroom,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.923253, 37.401819), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/d7/Anyang_Station_(1).jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/5e/20241012_안양로,_경강선_안양역_공사중.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2b/P147anyang.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/1f/P147anyanglobby.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d7/20150206안양1번가59.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["안양천 자전거길", "안양일번가", "엔터식스 안양역점"], "confidence": "high", "address": "대한민국 안양시 안양역.롯데백화점"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('안양천 합수부', '한강과 안양천 자전거길이 만나는 핵심 교차로로, 라이더들 사이에서 ''안합''으로 불립니다. 자전거 여행의 주요 만남의 광장이자 필수 휴식 거점입니다.', '{river,checkpoint,rest_area,bridge}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.877869, 37.553755), 4326), false, '{"source": "KOMOOT", "source_ids": ["920"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/2q/2qfdbfgrbibx13rgdh0ayce3n4ys8lbnj-uhi71593058/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1b/1bo93wd4j7awouyf5yhsi3gtb4ys8lcpy-uhi71593059/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/n3/n3mdts4emcgwgavc33gc29hb4ys8lgze-uhi71593061/0?width=1920&crop=false"], "tips": [{"text": "Take 3 round and no puncture with you 😁. From here you can take a turn south to Anyang and east to Seongnam following the taecheon river path back to seoul.", "author": "Robert Bauer"}], "category_raw": "river", "tour_count": 1, "nearby_landmarks": ["성산대교", "선유도공원", "안양천교"], "confidence": "high", "address": "대한민국 서울특별시 영등포구 양화동 167-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('안중역', '2024년 11월 개통한 서해선 및 평택선 철도역입니다. 서평택과 평택호 방면 자전거 라이딩 시 유용한 새로운 대중교통 거점입니다.', '{transit,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.937942, 36.972027), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["평택호", "평택항", "안중공용버스터미널"], "confidence": "high", "address": "대한민국 평택시 안중역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('안천공용정류장', '용담댐 라이딩 중 대중교통 점프(시외버스)가 가능한 공용 버스 정류장입니다. 주변에 하나로마트와 카페가 있어 보급과 휴식을 겸하기 좋습니다.', '{transit,rest_area,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.551183, 35.896427), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["안천면 행정복지센터", "하나로마트 안천농협본점", "안천우체국"], "confidence": "high", "address": "대한민국 전북특별자치도 진안군 안천면 노성리 1241-15"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('앙성온천', '남한강 자전거길 종주 중 피로를 풀기 좋은 탄산온천 지구입니다. 라이더들이 온천욕과 숙박을 위해 자주 찾는 주요 휴식처입니다.', '{rest_area,landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.786815, 37.091853), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["남한강 자전거길", "비내섬", "앙성온천광장", "앙성온천역"], "confidence": "high", "address": "대한민국 충청북도 충주시 앙성면 돈산리 324-11"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('야탑역', '탄천 자전거길과 인접해 라이딩 중 합류나 대중교통 점프에 유용한 수인분당선 전철역입니다. 주변 상권이 발달해 식사와 보급을 해결하기 좋습니다.', '{transit,restroom,convenience_store,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.128635, 37.411298), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/3/3f/Q46186_Yatap_A01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/26/Korea_NationalSubway_BundangLine_YaTap_Station_002.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/ff/Yatap_Station_4.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/dc/Korea_NationalSubway_BundangLine_YaTap_Station_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/14/Q46186_Yatap_A02.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["탄천 자전거길", "야탑교", "성남종합버스터미널"], "confidence": "high", "address": "대한민국 경기도 성남시 분당구 성남대로 903 야탑역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('양등마을', '태화강 자전거길 상류 종점(양등교) 부근의 조용한 시골 마을입니다. 영남알프스의 웅장한 산세와 태화강의 자연 경관을 감상하며 라이딩을 마무리하기 좋습니다.', '{checkpoint,viewpoint,river,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.076492, 35.600376), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["태화강 자전거길 종점", "양등교", "영남알프스"], "confidence": "high", "address": "대한민국 울산광역시 양등마을"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('양양종합여객터미널', '2022년 송암리로 이전한 양양종합여객터미널입니다. 시외버스를 이용한 자전거 점프(이동) 거점이며, 출발 전후로 휴식과 보급을 하기 좋습니다.', '{transit,restroom,convenience_store,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.629302, 38.084795), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["양양남대천"], "confidence": "high", "address": "대한민국 강원특별자치도 양양군 양양읍 송암리 29-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('양양고등학교', '전국 최강의 사이클부를 보유한 자전거 명문 고등학교입니다. 남대천 자전거길과 인접해 있어 라이딩 중 지나칠 수 있는 상징적인 지점입니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.618429, 38.073595), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["남대천", "양양전통시장", "양양군청"], "confidence": "high", "address": "대한민국 강원특별자치도 양양군 양양읍 남문리 351-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('양지중학교', '세종시 도담동에 위치한 중학교입니다. 정문 앞 공공자전거(어울링) 대여소가 있으며, 인근 방축천 자전거길과 연계하여 라이딩하기 좋습니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.267934, 36.508439), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["도램마을", "방축천", "양지고등학교"], "confidence": "high", "address": "대한민국 세종특별자치시 양지중학교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('양천구청역', '지하철 2호선 양천구청역입니다. 자전거 보관소와 화장실이 마련되어 있으며, 안양천 자전거길과 가까워 대중교통 연계(점프) 및 휴식 거점으로 유용합니다.', '{transit,restroom,parking,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.865938, 37.512595), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/c/cf/Seoul-metro-234-2-Yangcheon-gu-office-station-entrance-1-20181121-101156.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a1/Yangcheon-gu_Office_Stn._Platform.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/65/234-2yangcheonguoffice.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/69/Yangcheon-gu_Office_20140528_134922.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/af/Seoul-metro-234-2-Yangcheon-gu-office-station-platform-20181121-100822.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["안양천", "양천구청", "신정차량사업소"], "confidence": "high", "address": "대한민국 서울특별시 양천구 목동로3길 지하 33"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('양촌역', '김포골드라인의 시종착역인 양촌역입니다. 일반 자전거 승차가 원칙적으로 금지되어 있어 점프 시 규정 확인이 필수입니다. 주변 편의시설이 부족하므로 보급에 유의하세요.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.614557, 37.641538), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/4/47/Yangchon_Station3.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/97/Yangchon_Station.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f0/Gimpo_Gold_1117.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c9/Yangchon_Station2.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["김포한강차량기지"], "confidence": "high", "address": "대한민국 경기도 김포시 양촌읍 유현리 277-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('양평역 (5호선)', '서울 지하철 5호선 양평역입니다. 안양천 자전거길 진출입이 용이하여 라이딩 전후 대중교통 점프나 일행과의 합류 지점으로 활용하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.886119, 37.525638), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/58/Gyeonggi_Yangpyeong_Station_2010.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/59/양평역.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/60/Yangpyeonggu.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/22/Korail_Jungang_Line_Yangpyeong_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6f/K135_Yangpyeong_01.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["안양천 자전거길", "안양천", "오목교"], "confidence": "high", "address": "대한민국 서울특별시 양평역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('양평 힐', '남한강 자전거길 양평 회현리 구간에 위치한 짧은 업힐입니다. 갈산공원에서 현덕교 방향으로 향할 때 만나는 가벼운 고개로, 라이딩 중 잠시 힘을 쓰는 구간입니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.498206, 37.467961), 4326), false, '{"source": "KOMOOT", "source_ids": ["88"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1m/1mf8t8ub0ljjdk4kkthik6ore5ha4focn-uhi91794297/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1o/1o7vsoitzcmp911wblxzndsos75ha4lkc7-uhi91794413/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/z2/z2tpb2ucawvg10gpu1ygaaab65ha4lp0v-uhi91794414/0?width=1920&crop=false"], "category_raw": "summit", "tour_count": 1, "nearby_landmarks": ["남한강 자전거길", "갈산공원", "현덕교"], "confidence": "medium", "address": "대한민국 경기도 양평군 양평읍 회현리 519-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('어룡역', '의정부 경전철 어룡역입니다. 바로 옆 부용천 자전거길과 연결되며, 주말 및 공휴일에는 자전거 휴대 승차가 가능해 라이딩 중 점프(대중교통 연계) 포인트로 유용합니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.085216, 37.742684), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/1/18/U123_Eoyong_01.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["부용천 자전거길", "용현산업단지"], "confidence": "high", "address": "대한민국 의정부시 용현동 어룡"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('어물리소류지', '공주시 정안면의 한적한 시골 마을에 위치한 작은 저수지입니다. 인적이 드물고 조용해 라이딩 중 자연 경관을 즐기며 잠시 숨을 고르기 좋은 지점입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.146973, 36.594371), 4326), false, '{"source": "KOMOOT", "source_ids": ["487"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["국사봉"], "confidence": "high", "address": "대한민국 충청남도 공주시 정안면 어물리 327-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('어은정', '경주 유금리 형산강 인근에 위치한 전통 정자입니다. 자전거 라이딩 중 고즈넉한 정취를 느끼며 잠시 휴식하기 좋은 역사적 명소입니다.', '{historic,rest_area,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.278429, 36.002885), 4326), false, '{"source": "KOMOOT", "source_ids": ["323"], "category_raw": "15", "tour_count": 1, "nearby_landmarks": ["형산강 자전거길", "만귀정"], "confidence": "high", "address": "대한민국 경상북도 경주시 강동면 유금리 604-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('공릉천 억새 군락지', '파주 공릉천 자전거길을 따라 넓게 펼쳐진 억새 군락지입니다. 가을철 라이딩 시 은빛 물결을 감상하며 달리기 좋은 자연 명소입니다.', '{nature,viewpoint,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.762884, 37.759263), 4326), false, '{"source": "KOMOOT", "source_ids": ["628"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1m/1miibyvmvfv27xyl8zol3sxav5l33sfux-uhi96375433/0?width=1920&crop=false"], "category_raw": "other_natural", "tour_count": 1, "nearby_landmarks": ["공릉천", "공릉천 자전거길"], "confidence": "high", "address": "대한민국 경기도 파주시 금촌동 893"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('엑스포아파트4단지', '갑천 자전거길과 인접한 전민동의 아파트 단지입니다. 봄철 벚꽃과 튤립 명소로 유명해 라이딩 중 경치를 감상하며 쉬어가기 좋은 랜드마크입니다.', '{landmark,viewpoint,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.406235, 36.397841), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["갑천 자전거길", "갑천 벚꽃길", "갑천 튤립단지"], "confidence": "high", "address": "대한민국 대전광역시 유성구 전민동 엑스포로466번길 42"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('여울천', '구리한강시민공원 내 위치한 생태하천입니다. 자전거도로가 잘 연결되어 있어 계절별로 유채꽃과 코스모스를 감상하며 여유롭게 라이딩하기 좋습니다.', '{river,park,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.14046, 37.575881), 4326), false, '{"source": "KOMOOT", "source_ids": ["97"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["구리한강시민공원"], "confidence": "high", "address": "대한민국 경기도 구리시 토평동 839-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('여의나루', '한강 자전거길의 핵심 거점이자 여의도 한강공원 진입로입니다. 자전거 대여소, 편의점 등 편의시설이 풍부하지만 보행자가 많아 라이딩 시 서행해야 합니다.', '{transit,park,river,bike_shop,rest_area,convenience_store,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.932508, 37.52684), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/8/81/20250727_여의나루역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d8/Q490655_Yeouinaru_A04.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/85/Seoul-metro-527-Yeouinaru-station-platform-20180915-141340.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/13/20250727_여의나루역_1번출구.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8b/20250727_여의나루역_2번출구.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["여의도 한강공원", "마포대교", "물빛광장"], "confidence": "high", "address": "대한민국 서울특별시 여의나루역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('부문재(후용고개)', '원주 문막읍과 부론면 경계에 위치한 부문재(후용고개)입니다. 약 3km, 10% 경사도의 업힐 구간으로 여주·원주 자전거 투어 시 라이더들이 거쳐가는 주요 고개입니다.', '{mountain,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.797343, 37.25222), 4326), false, '{"source": "KOMOOT", "source_ids": ["474"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1h/1hw4z2l7mx4wu104eifyedd9j33qg2s04g-uhi31387071/0?width=1920&crop=false"], "category_raw": "settlement", "tour_count": 1, "nearby_landmarks": ["부문재 표지석", "손곡저수지", "경동대학교 원주문막캠퍼스"], "confidence": "high", "address": "대한민국 원주시 부문재"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('여주대학교', '남한강 자전거길 및 강천보와 가까워 국토종주나 여주 외곽 라이딩 시 출발·도착지나 랜드마크로 활용하기 좋은 대학교입니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.63856, 37.26661), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["남한강 자전거길", "강천보", "황학산수목원", "여주종합터미널"], "confidence": "high", "address": "대한민국 경기도 여주시 점봉동 429-14"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('역곡역', '수도권 전철 1호선 역곡역입니다. 주말 및 공휴일에 자전거 휴대 승차가 가능하여 대중교통 점프 포인트로 유용하며, 주변에 식당과 편의시설이 풍부합니다.', '{transit,restaurant,convenience_store,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.811517, 37.485328), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/0/0d/역곡역.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e5/Yeokgok_Station_in_2016.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/45/Korail_Gyeongin_Line_Yeokgok_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/ca/146yeokgok.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["역곡상상시장", "가톨릭대학교 성심교정"], "confidence": "high", "address": "대한민국 경기도 부천시 역곡동 80-7번지"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('연대지', '제주 환상자전거길 인근 외도동 해안에 위치한 기수역 연못입니다. 바닷물과 민물이 만나는 독특한 자연 경관을 감상하며 라이딩 중 잠시 쉬어가기 좋습니다.', '{nature,lake,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.42726, 33.493092), 4326), false, '{"source": "KOMOOT", "source_ids": ["196"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["연대포구", "월대천", "그라벨호텔"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 외도이동 1956-50"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('연사 버스정류장', '거제 주요 버스 노선이 교차하는 연사 정류장입니다. 주변에 편의점이 있어 라이딩 중 가벼운 보급이나 일행과의 만남 장소로 활용하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.646521, 34.910299), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["맑은샘병원", "연초고등학교"], "confidence": "high", "address": "대한민국 경상남도 거제시 연초면 연사리 325-34"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('연수주공3단지', '충주 연수동에 위치한 아파트 단지로, 지역 라이더들의 코스 출발 및 도착지나 동네 모임 장소로 활용되는 주거 구역입니다.', '{other,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.938812, 36.990277), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["충주체육관", "연수동 상가거리"], "confidence": "high", "address": "대한민국 충주시 연수주공3단지"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('외포항 여객터미널', '강화도 외포항에 위치한 여객터미널입니다. 자전거를 싣고 주문도, 볼음도 등 주변 섬으로 라이딩을 떠날 때 이용하는 주요 거점입니다.', '{transit,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.37789, 37.70118), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["외포항", "외포항 젓갈수산물직판장"], "confidence": "high", "address": "대한민국 인천광역시 강화군 내가면 해안서로 907"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('연천역', '수도권 전철 1호선의 최북단 종착역인 연천역입니다. 평화누리길과 차탄천 자전거길 라이딩 시 전철 점프(대중교통 연계)를 하기 좋은 핵심 거점입니다.', '{transit,restroom,historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.074262, 38.100671), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/c/c7/Q483790_Yeoncheon_01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/ef/연천역사.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f5/Yeoncheon_Station_Water_Tower.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bb/Yeoncheon_Station_Box_Water_Tower.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/ee/Q483790_Yeoncheon_03.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["연천역 급수탑", "차탄천", "연천공설운동장"], "confidence": "high", "address": "대한민국 경기도 연천군 연천읍 차탄리 34-443"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('열녀비', '홍천 광원리에 위치한 역사적인 열녀비입니다. 라이딩 중 잠시 멈춰 지역 문화재를 둘러보며 가볍게 쉬어가기 좋은 포인트입니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.412505, 37.81081), 4326), false, '{"source": "KOMOOT", "source_ids": ["622"], "category_raw": "15", "tour_count": 1, "nearby_landmarks": ["홍천 은행나무숲", "삼봉약수"], "confidence": "high", "address": "대한민국 강원특별자치도 홍천군 내면 광원리 산60-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('염불암', '안양 3대 업힐 중 최고 경사도(평균 15% 이상)를 자랑하는 코스입니다. 안양예술공원을 거쳐 오르는 짧고 강렬한 업힐 종착지로, 라이더들의 도전 의식을 자극하는 사찰입니다.', '{historic,landmark,checkpoint,mountain}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.93414, 37.428218), 4326), false, '{"source": "KOMOOT", "source_ids": ["484"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/e5/e5zpnagthptr1ku0m7ap7pj324g70mav5-uhi57303503/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/4h/4h1op94ky0u41vvz1xvz2ay2x4g70mb46-uhi57303504/0?width=1920&crop=false"], "category_raw": "religious_building", "tour_count": 1, "nearby_landmarks": ["안양예술공원", "삼성산", "망해암"], "confidence": "high", "address": "대한민국 경기도 안양시 만안구 예술공원로245번길 150"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('염티재', '청주와 보은을 잇는 해발 290m의 고개로, 피반령과 연계해 대청호 주변을 달리는 라이더들에게 인기 있는 한적하고 경치 좋은 업힐 코스입니다.', '{mountain,nature,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.556293, 36.467218), 4326), false, '{"source": "KOMOOT", "source_ids": ["616"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/55/55buwfm4tw5dsgfa1m12dnzt2zqe0d58-uhi6038476/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1v/1vpv9892y92gfdcyb17ogsiqd5je5bmai-uhi94839941/0?width=1920&crop=false"], "category_raw": "mountain_pass", "tour_count": 1, "nearby_landmarks": ["피반령", "대청호", "남대문공원"], "confidence": "high", "address": "대한민국 충청북도 보은군 회남면 남대문리 산33-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('염포전망대', '울산 시내와 태화강, 동해바다를 조망할 수 있는 동축산 정상의 전망대입니다. 염포119안전센터에서 시작하는 가파른 포장도로 업힐 코스로 오를 수 있으며 화장실이 있습니다.', '{viewpoint,mountain,landmark,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.40551, 35.54169), 4326), false, '{"source": "KOMOOT", "source_ids": ["130"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["동축산", "울산대교", "태화강", "염포119안전센터"], "confidence": "high", "address": "대한민국 울산광역시 북구 염포동 산50-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('영월교', '동강을 가로질러 영월역과 영월 시내를 잇는 교량입니다. 영월을 방문하거나 동강 자전거길을 달리는 라이더들의 주요 진출입로 역할을 합니다.', '{bridge}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.475163, 37.182269), 4326), false, '{"source": "KOMOOT", "source_ids": ["12"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/dt/dtns6tzsii832itf1f9qrogc3dyba0op-uhi13877288/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 1, "nearby_landmarks": ["영월역", "동강", "영월서부시장"], "confidence": "high", "address": "대한민국 강원특별자치도 영월군 영월읍 덕포리 534-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('영일대 모래조각상', '영일대해수욕장 해변에 전시된 이색적인 모래 조각 작품을 감상할 수 있는 곳입니다. 탁 트인 바다를 배경으로 라이딩 중 잠시 멈춰 멋진 기념사진을 남기기 좋습니다.', '{beach,landmark,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.377654, 36.055562), 4326), false, '{"source": "KOMOOT", "source_ids": ["1360"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1x/1x9snghlaysk8fjfjwaks7vzz4nle9k21-uhi62955048/0?width=1920&crop=false"], "category_raw": "other_man_made", "tour_count": 1, "nearby_landmarks": ["영일대해수욕장", "영일대 해상누각", "환호공원 스페이스워크"], "confidence": "high", "address": "대한민국 경상북도 포항시 북구 항구동 338-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('영지', '신라 아사달과 아사녀의 전설이 깃든 고즈넉한 연못입니다. 수변 데크길과 설화공원이 조성되어 있어 라이딩 중 한적하게 휴식하며 경치를 즐기기 좋습니다.', '{lake,park,historic,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.303278, 35.759668), 4326), false, '{"source": "KOMOOT", "source_ids": ["505"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["영지설화공원", "영지석불좌상", "불국사"], "confidence": "high", "address": "대한민국 경상북도 경주시 외동읍 괘릉리 산62-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('영진입구', '동해안 자전거길을 따라 영진해변으로 들어서는 진입로(교차로)입니다. 사천해변과 주문진을 잇는 길목으로 시원한 해안 라이딩을 이어가기 좋습니다.', '{checkpoint,beach,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.836426, 37.870584), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["영진해변", "영진교", "도깨비 촬영지(주문진 방사제)"], "confidence": "high", "address": "대한민국 강릉시 영진입구"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('영천강', '진주혁신도시를 가로지르는 영천강입니다. 잘 정비된 자전거길과 수변공원이 있어 초보자나 가족 단위 라이더도 안전하고 여유롭게 경치를 즐기며 달리기 좋습니다.', '{river,park,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.138221, 35.183781), 4326), false, '{"source": "KOMOOT", "source_ids": ["125"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["진주혁신도시", "영천강 수변공원", "남강"], "confidence": "high", "address": "대한민국 경상남도 진주시 문산읍 소문리 2224-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('영통', '수원시 영통구의 중심지인 영통역 일대입니다. 식당, 카페, 편의점 등 보급처가 풍부하며 대중교통 연계가 가능한 도심 라이딩 거점입니다.', '{transit,convenience_store,cafe,restaurant,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.071252, 37.251363), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/0/0a/Q218354_Yeongtong_A01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0f/Yeongtong_Station_n1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/ko/0/02/K240_kudari.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/ko/3/32/K240_nobori.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/ko/1/10/Yeongtong-BD-G.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["영통역", "경희대학교 국제캠퍼스", "영흥숲공원"], "confidence": "high", "address": "대한민국 경기도 수원시 영통구 봉영로"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오근장역', '충북선 무궁화호가 정차하는 오근장역입니다. 미호강 자전거길과 정북동토성이 가까워 자전거 여행 시 대중교통 연계(점프) 거점으로 유용합니다.', '{transit,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.477524, 36.700135), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/8/83/OgeunjangSta.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["정북동토성", "미호강 자전거길", "청주국제공항"], "confidence": "high", "address": "대한민국 충청북도 청주시 청원구 오동동 68-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오도리 이팝나무', '황매산 라이딩 길목에서 만날 수 있는 350년 수령의 웅장한 이팝나무입니다. 5월에 하얀 꽃이 절경을 이루며, 나무 아래 넓은 그늘은 라이더들의 훌륭한 쉼터가 됩니다.', '{nature,historic,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.022751, 35.450836), 4326), false, '{"source": "KOMOOT", "source_ids": ["773"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["황매산", "오도리마을"], "confidence": "high", "address": "대한민국 경상남도 합천군 가회면 오도리 568-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오류저수지', '전남 진도군 고군면에 위치한 한적한 저수지입니다. 진도 외곽 라이딩 중 조용한 농촌과 수변 풍경을 감상하며 지나가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.333463, 34.53837), 4326), false, '{"source": "KOMOOT", "source_ids": ["1868"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["오류리 마을", "오류염전"], "confidence": "high", "address": "대한민국 전라남도 진도군 고군면 오류리 432-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오류고아라해변', '동해안 자전거길 종주 중 시원한 바다와 송림을 배경으로 휴식하기 좋은 해변입니다. 캠핑장과 화장실 등 편의시설이 잘 갖춰져 있습니다.', '{beach,rest_area,viewpoint,nature,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.507417, 35.822515), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["오류캠핑장", "연동항", "송대말등대"], "confidence": "high", "address": "대한민국 경주시 오류해수욕장"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남한산성 업힐', '성남 양지동에서 남한산성으로 오르는 인기 자전거 업힐 코스입니다. 꾸준한 경사도와 굽이진 길로 수도권 라이더들의 훈련 장소로 사랑받고 있습니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.171278, 37.47004), 4326), false, '{"source": "KOMOOT", "source_ids": ["1736"], "category_raw": "climb", "tour_count": 1, "nearby_landmarks": ["남한산성", "남한산성 유원지", "을지대학교 성남캠퍼스"], "confidence": "high", "address": "대한민국 경기도 성남시 수정구 양지동 산10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오목교', '안양천 자전거길을 가로지르는 주요 교량으로, 다리 하부 그늘은 라이더들의 쾌적한 휴식처이자 만남의 장소로 인기가 높습니다.', '{bridge,river,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.87512, 37.524557), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/f/f8/Omokgyo_Stn._exit.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/1e/Seoul-metro-521-Omokgyo-station-sign-20180915-174204.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/07/Omokgyo_Stn._platform.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/41/Seoul-metro-521-Omokgyo-station-platform-20180915-174316.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/7f/521omokgyo.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["안양천 자전거길", "오목교역", "목동종합운동장"], "confidence": "high", "address": "대한민국 서울특별시 오목교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오봉저수지', '강릉 남대천 상류에 위치한 저수지로, 삽당령이나 안반데기 등 내륙 산악 코스로 향하는 라이더들이 거쳐 가는 길목입니다. 수려한 자연 경관을 감상하며 라이딩하기 좋습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.817593, 37.691844), 4326), false, '{"source": "KOMOOT", "source_ids": ["199", "329", "586"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["남대천", "삽당령", "강릉솔향수목원"], "confidence": "high", "address": "대한민국 강원특별자치도 강릉시 성산면 오봉리 산139-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오십천교', '삼척 오십천을 가로지르는 다리로, 쾌적한 오십천 자전거길과 삼척장미공원으로 이어지는 주요 라이딩 길목입니다.', '{bridge,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.159344, 37.43427), 4326), false, '{"source": "KOMOOT", "source_ids": ["2726"], "image_urls": ["https://photos.komoot.de/wiki/commons/8/80/삼척_죽서루와_오십천-_강원도청.jpg?width=1920&crop=false"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["삼척장미공원", "죽서루", "오십천 자전거길"], "confidence": "high", "address": "대한민국 강원특별자치도 삼척시 성남동 46"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오이도 빨간 등대', '서해안 자전거길의 주요 기점이자 시화방조제 라이딩 전후로 들르기 좋은 상징적인 랜드마크입니다. 탁 트인 바다 뷰와 함께 휴식하기 좋습니다.', '{landmark,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.687364, 37.344453), 4326), false, '{"source": "KOMOOT", "source_ids": ["283"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/tl/tlpqkjtdttau1nv3eaovmhyhx5e0twjcg-uhi87396811/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/ve/ve1sl9xqbs55uphp1rr7xvfz5e0txzjm-uhi87396832/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/83/83pkql365sp4l3md54dp8gls5iwo2q1v-uhi94243277/0?width=1920&crop=false"], "category_raw": "man_made_monument", "tour_count": 1, "nearby_landmarks": ["시화방조제", "배곧한울공원", "오이도 선사유적공원"], "confidence": "high", "address": "대한민국 경기도 시흥시 오이도로 185"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오전천', '안양천 지류인 의왕시의 생태 하천으로, 자전거 도로가 잘 정비되어 있어 안양천 본류까지 쾌적하게 라이딩을 즐길 수 있습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.971289, 37.351023), 4326), false, '{"source": "KOMOOT", "source_ids": ["211"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["안양천 자전거길", "의왕시청"], "confidence": "high", "address": "대한민국 경기도 의왕시 고천동 319-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오창농협 공영주차장', '오창농협 앞 공영주차장입니다. 차량을 주차하고 라이딩을 시작하거나, 인근 하나로마트에서 식수와 행동식을 보급하기 좋은 거점입니다.', '{parking,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.456576, 36.740614), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["오창농협", "오창 하나로마트", "오창전통시장"], "confidence": "high", "address": "대한민국 충청북도 청주시 청원구 오창읍 장대리 279-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오충사', '보성선씨 5인의 충절을 기리는 사당으로, 보성읍 내에 위치해 있습니다. 라이딩 중 잠시 들러 역사적 의미를 되새기며 쉬어가기 좋은 고즈넉한 명소입니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.082448, 34.770079), 4326), false, '{"source": "KOMOOT", "source_ids": ["1142"], "category_raw": "15", "tour_count": 1, "nearby_landmarks": ["보성향교", "보성군청"], "confidence": "high", "address": "대한민국 전라남도 보성군 보성읍 보성리 747-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('옥녀봉', '대전 도안공원 내 위치한 해발 138m의 도심 속 야산입니다. 경사가 완만하고 숲길이 잘 조성되어 있어 가벼운 산악자전거(MTB) 라이딩이나 자연 속 휴식을 즐기기에 좋습니다.', '{mountain,park,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.342521, 36.325866), 4326), false, '{"source": "KOMOOT", "source_ids": ["456"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["도안공원", "목원대학교", "건양대학교병원"], "confidence": "high", "address": "대한민국 대전광역시 서구 도안동 산34-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('옥동정상', '통영 욕지도 일주도로 인근에 위치한 해발 155m의 봉우리입니다. 수풀이 우거져 정상 조망은 없으나, 해안도로 라이딩 코스 중 거쳐가는 지점입니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.282629, 34.624924), 4326), false, '{"source": "KOMOOT", "source_ids": ["485"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["욕지도 일주도로", "노적마을", "망대봉"], "confidence": "high", "address": "대한민국 경상남도 통영시 욕지면 동항리 산29-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('옥산2소류지', '경남 거제시 거제면에 위치한 작은 저수지로, 한적한 농촌 풍경과 자연을 감상하며 라이딩하기 좋은 지점입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.573675, 34.874554), 4326), false, '{"source": "KOMOOT", "source_ids": ["801"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["거제뷰컨트리클럽", "시리봉"], "confidence": "high", "address": "대한민국 경상남도 거제시 거제면 옥산리 1120-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('옥성저수지', '충북 진천군 문백면에 위치한 한적한 저수지입니다. 주변 경관이 아름답고 평탄한 길이 있어 라이딩 중 경치를 감상하며 쉬어가기 좋습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.447646, 36.795833), 4326), false, '{"source": "KOMOOT", "source_ids": ["411"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["진천 농다리", "미호강"], "confidence": "high", "address": "대한민국 충청북도 진천군 문백면 옥성리 산17-17"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('옥수역·옥수나들목', '한강 자전거길로 바로 연결되는 옥수나들목과 옥수역입니다. 자전거 전용 엘리베이터와 수리센터가 있어 라이더들의 주요 만남의 장소로 꼽힙니다.', '{transit,tunnel,rest_area,bike_shop,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.01838, 37.540273), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/51/Seoul-metro-335-Oksu-station-entrance-3-20181122-170102.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/49/335_옥수역.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/1d/Oksu02.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/1b/K114_oksu_stn.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/7a/Oksu_Station_(Gyeongui_Jungang_Line)_20220430_001.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["옥수역", "옥수나들목", "동호대교", "한강공원"], "confidence": "high", "address": "대한민국 서울특별시 성동구 옥수동 490-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('옥수역 자전거 거점', '한강 자전거길 진입이 편리한 옥수나들목과 자전거 대여 및 수리소가 위치한 옥수역입니다. 라이더들의 주요 만남의 장소로 활용됩니다.', '{transit,rest_area,restroom,convenience_store,bike_shop}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.017532, 37.54144), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/51/Seoul-metro-335-Oksu-station-entrance-3-20181122-170102.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/49/335_옥수역.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/1d/Oksu02.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/1b/K114_oksu_stn.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/7a/Oksu_Station_(Gyeongui_Jungang_Line)_20220430_001.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["옥수나들목", "한강 자전거길", "동호대교", "옥수역 자전거대여소"], "confidence": "high", "address": "대한민국 서울특별시 성동구 옥수동 192-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('옥정마을', '군산시 옥구읍에 위치한 조용한 농촌 마을로 전통 장류 특화마을로 알려져 있습니다. 군산교도소 인근에 있으며, 라이딩 중 한적한 시골 풍경을 감상하며 지나가기 좋습니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.695694, 35.937889), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["군산교도소", "은파호수공원"], "confidence": "high", "address": "대한민국 군산시 옥정마을"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('옥창돈대', '평화누리 자전거길 인근에 위치한 조선시대 해안 방어 유적입니다. 터만 일부 남았지만 강화도 돈대 순례 라이딩 시 역사적 의미를 되새기며 들르기 좋습니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.50879, 37.762047), 4326), false, '{"source": "KOMOOT", "source_ids": ["89"], "category_raw": "15", "tour_count": 1, "nearby_landmarks": ["연미정", "월곶돈대", "평화누리 자전거길"], "confidence": "high", "address": "대한민국 인천광역시 강화군 강화읍 옥림리 150-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('온양온천', '곡교천 자전거길 라이딩 후 피로를 풀기 좋은 아산의 대표적인 온천입니다. 온양온천역이 인접해 있어 전철 점프(복귀) 거점으로도 유용합니다.', '{rest_area,transit,landmark,historic}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.003206, 36.780739), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/9/9d/NewOnyangOncheonSta.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/61/2009-09-25_-_Panorama_outside_Onyang_Oncheon_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9c/2009-09-25_-_Panorama_of_Onyang_Oncheon_Station_Platform.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/82/Q167611_Onyangoncheon_A01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/77/온양온천역-20200705_200149.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["온양온천역", "곡교천 자전거길", "신정호"], "confidence": "high", "address": "대한민국 아산시 온양온천"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('올림픽공원', '성내천을 통해 한강 자전거길과 바로 연결되는 동서울의 대표적인 라이딩 명소입니다. 넓은 부지 내에 화장실, 편의점 등 휴식 인프라가 잘 갖춰져 있습니다.', '{park,rest_area,landmark,historic,restroom,convenience_store,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.130929, 37.516148), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/b/b1/Seoul-metro-P550-Olympic-park-station-sign-20180915-093312.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/fc/Seoul-metro-P550-Olympic-park-station-entrance-2-20180915-094106.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/81/올림픽공원역.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/db/20250713_9호선_올림픽공원역_스크린도어.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/79/20250705_올림픽공원역_김포공항역_방면_승강장.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["평화의 문", "몽촌토성", "나홀로나무", "성내천 자전거길"], "confidence": "high", "address": "대한민국 서울특별시 송파구 방이동 89"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('와동현대아파트', '갑천 자전거길과 인접한 아파트 단지로, 대전 공영자전거 ''타슈'' 대여소가 있어 자전거 대여 및 반납이 편리합니다. 갑천을 따라 라이딩을 연계하기 좋은 기점입니다.', '{other,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.423117, 36.400456), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["갑천", "갑천 자전거길", "회덕역"], "confidence": "high", "address": "대한민국 대전광역시 대덕구 와동 39-15"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('와룡저수지', '순천 와룡동에 위치한 조용한 산지 저수지입니다. 차량 통행이 적어 한적하게 자연 경관을 감상하며 업힐 라이딩을 즐기기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.458162, 34.957684), 4326), false, '{"source": "KOMOOT", "source_ids": ["184"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["와룡마을", "옥천"], "confidence": "high", "address": "대한민국 전라남도 순천시 와룡동 186-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('와정소류지', '대청호 방아실 코스(비야대정로) 길목에 위치한 작은 저수지입니다. 옥천 향수 200리 자전거길 등 대청호 주변 라이딩 시 한적한 농촌 풍경을 즐기며 지나가는 포인트입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.534908, 36.387059), 4326), false, '{"source": "KOMOOT", "source_ids": ["575"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["대청호", "방아실", "증약초등학교 대정분교장"], "confidence": "high", "address": "대한민국 충청북도 옥천군 군북면 대정리 787"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('왜갈동산', '춘천 사북면에 위치한 해발 299.7m의 산입니다. 예로부터 왜가리가 서식해 이름 붙여졌으며, 산악 라이딩이나 트래킹 코스의 경유지로 활용됩니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.64554, 38.042582), 4326), false, '{"source": "KOMOOT", "source_ids": ["1117"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["춘천호", "뜀박산", "오탄봉"], "confidence": "high", "address": "대한민국 강원특별자치도 춘천시 사북면 지촌리 284-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('요막산', '여수 적금도에 위치한 해발 61.4m의 작은 산입니다. 팔영대교와 다도해 절경을 조망할 수 있어 섬 자전거 라이딩 중 들르기 좋은 뷰포인트입니다.', '{mountain,viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.512978, 34.627658), 4326), false, '{"source": "KOMOOT", "source_ids": ["489"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["팔영대교", "적금도", "적금마을"], "confidence": "high", "address": "대한민국 전라남도 여수시 화정면 적금리 973"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('용당산', '충남 아산시 둔포면에 위치한 해발 53m의 야산입니다. 아산호와 둔포천 인근 자전거길을 지날 때 주변 풍경을 이루는 자연 지형지물입니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.022694, 36.91593), 4326), false, '{"source": "KOMOOT", "source_ids": ["187"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["아산호", "둔포천"], "confidence": "high", "address": "대한민국 아산시 유한"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('용두암현대1차아파트', '제주환상자전거길 용담 해안도로 구간에 위치한 아파트 단지입니다. 해안도로 라이딩 시 현재 위치를 파악하는 이정표 역할을 합니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.508755, 33.515976), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["용두암 인증센터", "용담레포츠공원", "어영공원"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 용담삼동 503-12"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('용머리', '단양 남조천 변에 위치한 바위 지형입니다. 사인암으로 향하는 길목에 있어 하천 풍경을 감상하며 가볍게 지나치기 좋은 자연 랜드마크입니다.', '{nature,landmark,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.346883, 36.904265), 4326), false, '{"source": "KOMOOT", "source_ids": ["1557"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["남조천", "사인암", "성룡사"], "confidence": "high", "address": "대한민국 충청북도 단양군 대강면 괴평리 192-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('용문역 공영주차장', '경의중앙선 용문역 주차장입니다. 전철 연계와 주차가 편리해 양평 및 용문산 일대 자전거 라이딩의 핵심 출발지이자 복귀 지점으로 자주 이용됩니다.', '{parking,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.595243, 37.481927), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/f/fe/Yongmun_Stn._Exit_5_(DJET).jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9b/Yongmun_Stn._Platform_(DJET).jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d3/Yongmun_Stn._Nameplate_(DJET).jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a2/YongmunSta.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/ko/3/3d/SAM_0036.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["용문역", "용문천년시장"], "confidence": "high", "address": "대한민국 경기도 양평군 용문면 다문리 249-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('용바위', '금강 자전거길 인근 양산팔경 강선대 아래 위치한 기암괴석입니다. 선녀와 용의 전설이 깃든 곳으로, 금강의 수려한 경치를 감상하며 잠시 쉬어가기 좋은 조망점입니다.', '{viewpoint,landmark,nature,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.682994, 36.1311), 4326), false, '{"source": "KOMOOT", "source_ids": ["1156"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["강선대", "금강", "송호국민관광지"], "confidence": "high", "address": "대한민국 충청북도 영동군 양산면 봉곡리 756-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('용산역', '경의중앙선과 ITX-청춘 열차를 이용해 팔당, 춘천 등 외곽으로 자전거 점프(대중교통 이동)를 하기 좋은 핵심 환승 거점입니다.', '{transit,landmark,convenience_store,restroom,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.964417, 37.530306), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/6e/용산역.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/18/Yongsansta01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/09/Yongsan_Station_20230408_006.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c4/용산역_이정표.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/1f/용산역_평면환승.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["아이파크몰", "이촌한강공원", "노들섬"], "confidence": "high", "address": "대한민국 서울특별시 한강로동 용산역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('용연저수지', '독립기념관과 흑성산 자락에 위치한 고즈넉한 저수지입니다. 수변 경관이 뛰어나 천안 지역 라이더들의 힐링 라이딩 코스로 인기가 높습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.228098, 36.807109), 4326), false, '{"source": "KOMOOT", "source_ids": ["164"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["독립기념관", "흑성산", "태조산"], "confidence": "high", "address": "대한민국 충청남도 천안시 동남구 목천읍 서흥리 산2-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('용이1차푸르지오.신흥마을', '평택 용이동 푸르지오 아파트 단지 앞 버스 정류장입니다. 라이딩 중 대중교통 연계(점프)나 위치 확인, 일행과의 합류 지점으로 활용하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.144242, 36.999953), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["용이1차푸르지오", "e편한세상평택용이", "용이초등학교"], "confidence": "high", "address": "대한민국 평택시 용이1차푸르지오.신흥마을"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('우도 해안 전망', '우도 해안도로 라이딩 중 푸른 바다와 해안 절경을 감상할 수 있는 탁 트인 전망 포인트입니다. 자전거를 잠시 세우고 시원한 바닷바람을 맞으며 사진을 남기기 좋습니다.', '{viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.962807, 33.513635), 4326), false, '{"source": "KOMOOT", "source_ids": ["259"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/fs/fs2eo2bhu6u81m05qk6rv8oeq5bvusndi-uhi84788445/0?width=1920&crop=false"], "category_raw": "viewpoint", "tour_count": 1, "nearby_landmarks": ["우도 해안도로", "하고수동해수욕장", "우도 비양도"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 우도면 연평리 711"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('우도 패총', '우도 산호사 해수욕장(홍조단괴해빈) 주차장 인근에 있는 신석기 시대 조개무덤 유적입니다. 해안도로 라이딩 중 제주의 오랜 역사를 엿볼 수 있는 의미 있는 경유지입니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.969711, 33.514927), 4326), false, '{"source": "KOMOOT", "source_ids": ["232"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1q/1qsurnotetw2g8oro33ec3uqt5bubfrpr-uhi84761936/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/i2/i23n6s07pd1s1wamephu4t8la5bubgjku-uhi84761940/0?width=1920&crop=false"], "category_raw": "man_made_monument", "tour_count": 1, "nearby_landmarks": ["홍조단괴해빈", "산호사 해수욕장"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 우도면 연평리 1-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('컬러풀 카페', '우도 해안도로에 위치해 자전거 일주 중 들르기 좋은 오션뷰 카페 겸 식당입니다. 알록달록한 야외 테이블에서 바다를 보며 땅콩 아이스크림과 함께 휴식하기 좋습니다.', '{cafe,restaurant,rest_area,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.957245, 33.522057), 4326), false, '{"source": "KOMOOT", "source_ids": ["333"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1h/1h26kgvz5w6lq8rnok12q0ygg5bvusmvx-uhi84788443/0?width=1920&crop=false"], "category_raw": "cafe", "tour_count": 1, "nearby_landmarks": ["우도 해안도로"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 우도면 연평리 1081-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('우도아름다운소풍', '우도 해안도로에 위치한 오션뷰 중식당입니다. 라이딩 중 짜장면, 짬뽕, 한라산볶음밥으로 든든하게 에너지를 보충하며 쉬어가기 좋습니다.', '{restaurant,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.949567, 33.514962), 4326), false, '{"source": "KOMOOT", "category_raw": "40", "tour_count": 1, "nearby_landmarks": ["우도 해안도로", "하우목동항"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 우도면 연평리 988-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('우수영정류소', '해남과 진도를 잇는 길목에 위치한 시외버스 정류소입니다. 진도대교나 해남 지역 라이딩 시 버스 점프(대중교통 연계) 및 휴식 거점으로 활용하기 좋습니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.313002, 34.597148), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["진도대교", "우수영국민관광지", "명량해상케이블카"], "confidence": "high", "address": "대한민국 전라남도 해남군 문내면 동외리 857-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('창원 팽나무 (우영우 촬영지)', '낙동강 자전거길 옆에 위치한 거대한 팽나무입니다. 드라마 촬영지로 유명하며, 탁 트인 강변 풍경이 제주도를 연상케 하는 멋진 라이딩 코스입니다.', '{landmark,nature,viewpoint,historic}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.736367, 35.34513), 4326), false, '{"source": "KOMOOT", "source_ids": ["683"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/el/elm8cvjwnd265khkxi1f5f1m4c5fte6c-uhi55180530/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1l/1lev5v4w36tf4zvy64s2x6bnn4c5ftv27-uhi55180531/0?width=1920&crop=false"], "tips": [{"text": "자전거길이제주도길같아요", "author": "injun"}], "category_raw": "natural_monument", "tour_count": 1, "nearby_landmarks": ["낙동강 자전거길", "동부마을", "대산미술관"], "confidence": "high", "address": "대한민국 경상남도 창원시 의창구 대산면 유등리 876-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('운남저수지', '원주굽이길 11코스에 위치한 맑고 고즈넉한 계곡형 저수지입니다. 조용한 임도를 따라 라이딩하며 자연 경관을 감상하고 휴식하기 좋습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.91314, 37.180605), 4326), false, '{"source": "KOMOOT", "source_ids": ["474"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["원주굽이길 11코스", "인벌마을 계곡"], "confidence": "high", "address": "대한민국 강원특별자치도 원주시 귀래면 운남리 산41-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('운당2리', '450년 수령의 둥구나무와 전통 축제가 보존된 세종시 소정면의 한적한 농촌 마을입니다. 고즈넉한 시골 풍경을 감상하며 라이딩 중 잠시 쉬어가기 좋은 경유지입니다.', '{landmark,historic,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.149874, 36.705621), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["운당2리 마을회관", "450년 둥구나무", "운당2리 경로당"], "confidence": "high", "address": "대한민국 세종특별자치시 소정면 운당리 208-11"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('운심2리', '남한강 남단 강하면에 위치한 마을로, 로드 라이더들이 즐겨 찾는 ''강하 코스''의 주요 경유지입니다. 한적한 도로를 따라 라이딩하기 좋습니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.392187, 37.490452), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["남한강", "운심2리체육공원", "운심2리마을회관"], "confidence": "high", "address": "대한민국 양평군 운심2리"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('운암지', '탁 트인 수변 풍경과 수상 태양광 시설이 눈에 띄는 예천의 대형 저수지입니다. 한적한 제방길을 따라 조용히 자연을 감상하며 라이딩하기 좋은 포인트입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.358526, 36.707098), 4326), false, '{"source": "KOMOOT", "source_ids": ["600"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["국사봉", "금당지"], "confidence": "high", "address": "대한민국 경상북도 예천군 용문면 두천리 산22-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('운정중앙역', '2024년 말 개통된 GTX-A 노선의 기점인 운정중앙역입니다. 역사 내 편의점과 카페가 있어 보급이 가능하며, 파주 라이딩의 출발이나 복귀 거점으로 활용하기 좋습니다.', '{transit,convenience_store,cafe,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.728285, 37.716148), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["운정신도시", "물향기마을", "한울마을"], "confidence": "high", "address": "대한민국 파주시 운정중앙"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('운중동 행정복지센터', '운중천 자전거길 인근에 위치한 행정복지센터입니다. 전동식 자전거 공기주입기와 개방 화장실이 마련되어 있어 라이딩 중 정비와 휴식을 취하기 좋습니다.', '{rest_area,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.077505, 37.391598), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["운중천 자전거길", "운중체육공원"], "confidence": "high", "address": "대한민국 성남시 운중동행정복지센터"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('울산MBC', '태화강 자전거길 북쪽 도심에 위치한 방송국으로, 라이딩 중 위치를 가늠하거나 만남의 장소로 활용하기 좋은 랜드마크입니다.', '{landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.333617, 35.562876), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["학성공원", "태화강", "울산종합운동장"], "confidence": "high", "address": "Ulsan MBC, 복산2동 울산광역시 대한민국"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('수성지', '영천 임고면에 위치한 한적한 저수지입니다. 봄철 벚꽃과 복사꽃이 만발하여 라이딩 중 아름다운 자연 경관을 감상하며 쉬어가기 좋습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.13578, 36.054967), 4326), false, '{"source": "KOMOOT", "source_ids": ["647"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["운주산", "봉좌산", "이리재"], "confidence": "high", "address": "대한민국 경상북도 영천시 임고면 수성리 산115-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('원동역', '낙동강 종주 자전거길의 주요 거점인 원동역입니다. 기차 점프가 가능하며, 봄철 매화와 낙동강 절경을 감상하며 쉬어가기 좋은 라이딩 명소입니다.', '{transit,landmark,rest_area,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.92112, 35.362661), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/62/Korail_Gyeongbu_Line_Wondong_Station_Platform.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/20/경부선_원동역.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["순매원", "낙동강종주자전거길", "황산강 베랑길"], "confidence": "high", "address": "대한민국 경상남도 양산시 원동면 원리 1178-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('원리 버스회차지', '구미시 선산읍 원리의 버스 회차지(정류장)입니다. 낙동강 종주 자전거길과 금오서원이 가까워 대중교통 연계나 라이딩 기점으로 활용하기 좋습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.338722, 36.22637), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["금오서원", "낙동강 자전거길", "구미보"], "confidence": "high", "address": "대한민국 경상북도 구미시 선산읍 원리 289-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('원리주공아파트앞.한국병원.이마트', '오산 원리주공아파트 인근의 버스 정류장입니다. 주변에 이마트와 한국병원이 위치해 있어 라이딩 중 보급품 구매나 화장실 이용, 긴급 상황 시 유용합니다.', '{transit,hospital}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.074384, 37.140329), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["원리주공아파트", "한국병원", "이마트 오산점"], "confidence": "high", "address": "대한민국 경기도 오산시 밀머리로 19"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('간현관광지 자전거길', '섬강을 따라 달리는 평탄한 자전거길로, 소금산 출렁다리와 간현관광지의 웅장한 암벽 경관을 감상하며 힐링 라이딩을 즐기기 좋습니다.', '{river,mountain,nature,viewpoint,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.834209, 37.356041), 4326), false, '{"source": "KOMOOT", "source_ids": ["686"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/n5/n5m7ljq8ify5jfmaq7xjdw194zt1tw4o-uhi72973531/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1w/1wivx4jtdust61y1c7u0zxizr74zt1tx1o-uhi72973532/0?width=1920&crop=false"], "category_raw": "cycle_way", "tour_count": 1, "nearby_landmarks": ["간현관광지", "소금산 출렁다리", "소금산 그랜드밸리", "원주 레일바이크"], "confidence": "high", "address": "대한민국 강원특별자치도 원주시 지정면 간현리 1023-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('원지', '경산 마곡리에 위치한 한적한 저수지(마곡지)입니다. 시골길 라이딩 중 탁 트인 수변 풍경을 감상하며 잠시 쉬어가기 좋은 자연 스팟입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.845855, 35.843937), 4326), false, '{"source": "KOMOOT", "source_ids": ["264"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["마곡회관", "마곡리 당산나무", "공룡발자국 화석지"], "confidence": "high", "address": "대한민국 경산시 마곡회관 건너"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('원통버스터미널', '설악산, 한계령 등 강원도 내륙 라이딩의 주요 출발 및 복귀 거점으로 활용되는 공용버스터미널입니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.202928, 38.123454), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["원통시장", "인북천"], "confidence": "high", "address": "대한민국 강원특별자치도 인제군 북면 원통리 640-29"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('CU 월계역점', '중랑천 자전거길과 월계역 인근에 위치한 편의점으로, 라이딩 중 보급과 휴식을 취하기 좋습니다.', '{convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.05869, 37.633066), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/5e/Korail-118-Wolgye-station-sign-20181126-133808.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/80/Korail-118-Wolgye-station-sign-20181126-134112.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bc/Korail-118-Wolgye-station-platform-20181126-134020.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/29/Korail-118-Wolgye-station-entrance-3-20181126-134330.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b5/Korail-118-Wolgye-station-sign-20181126-133722.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["월계역", "중랑천 자전거길", "한내교"], "confidence": "high", "address": "대한민국 서울특별시 노원구 월계2동 272-38"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('월곶돈대', '한강과 임진강이 만나는 지점에 위치한 조선시대 방어 시설입니다. 내부의 연미정에서 북한 땅을 조망하며 라이딩 중 쉬어가기 좋습니다.', '{historic,landmark,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.511772, 37.770603), 4326), false, '{"source": "KOMOOT", "source_ids": ["123"], "category_raw": "15", "tour_count": 1, "nearby_landmarks": ["연미정", "조해루", "황형택지"], "confidence": "high", "address": "대한민국 인천광역시 강화군 강화읍 월곳리 242"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('서울월드컵경기장', '불광천과 한강 자전거길이 만나는 길목에 위치한 서울의 대표 랜드마크입니다. 내부에 대형 마트, 식당, 화장실 등 편의시설이 풍부해 라이딩 전후 보급과 휴식을 취하기 좋습니다.', '{landmark,transit,parking,restroom,convenience_store,restaurant,cafe}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.899482, 37.57023), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/8/82/Wcss05.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f8/World_Cup_Stadium_Station_(Seoul)_20201009_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/5e/Seoul-metro-619-Worldcup-stadium-station-sign-20191021-082648.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/80/World_Cup_Stadium_Station_(Seoul)_20201009_005.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3d/Seoulwcupstadiumsta-wc.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["평화의공원", "하늘공원", "불광천", "난지한강공원"], "confidence": "high", "address": "대한민국 서울특별시 마포구 성산동 474-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('월산마을', '제주시 노형동 중산간에 위치한 한적한 주거 마을입니다. 애조로와 인접해 접근성이 좋고 편의점이 있어 라이딩 중 가볍게 보급하며 쉬어가기 적합합니다.', '{convenience_store,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.463302, 33.472972), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["애조로", "한라수목원"], "confidence": "high", "address": "대한민국 제주시 월산마을"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('유등연지', '여름철 붉은 연꽃이 만발하는 청도의 대표적인 연못입니다. 연못 둘레길이 잘 조성되어 있어 자전거를 타고 가볍게 둘러보거나 군자정을 배경으로 사진을 찍으며 쉬어가기 좋습니다.', '{lake,park,nature,viewpoint,rest_area,historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.691666, 35.675018), 4326), false, '{"source": "KOMOOT", "source_ids": ["624"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["군자정"], "confidence": "high", "address": "대한민국 경상북도 청도군 화양읍 연지안길 36"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('유성숲오투그란데 아파트', '대전 유성구 덕명동에 위치한 아파트 단지입니다. 덕명중학교 인근의 주거 구역으로, 라이딩 시 보행자 및 단지 입출입 차량에 주의해야 합니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.301302, 36.346153), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["덕명중학교", "계산초등학교"], "confidence": "high", "address": "대한민국 대전광역시 덕명중학교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('포은 정몽주 선생 묘역', '포은 정몽주 선생을 기리기 위해 건립된 조선시대 서원으로, 라이딩 중 고즈넉한 분위기 속에서 휴식하며 역사를 탐방하기 좋은 장소입니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.171074, 37.339503), 4326), false, '{"source": "KOMOOT", "source_ids": ["1164", "97", "402", "1246"], "category_raw": "15", "tour_count": 1, "nearby_landmarks": ["포은 정몽주 선생 묘", "레이크사이드CC"], "confidence": "high", "address": "대한민국 경기도 용인시 처인구 모현읍 능원리 128-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('율포솔밭해변', '시원한 소나무 숲과 바다 풍경을 즐기며 쉬어가기 좋은 라이딩 휴식처입니다. 화장실, 편의점, 식당 등 편의시설이 잘 갖춰져 있어 보급과 휴식에 매우 적합합니다.', '{beach,nature,rest_area,restroom,convenience_store,cafe,restaurant,parking,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.090786, 34.670397), 4326), false, '{"source": "KOMOOT", "source_ids": ["804"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["율포해수녹차센터", "율포해수풀장"], "confidence": "high", "address": "대한민국 전라남도 보성군 회천면 동율리 539"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('율하천교', '대구 동구 안심로에 위치한 교량으로, 금호강 자전거길과 이어지는 율하천 자전거길 및 산책로로 진입하기 좋은 주요 웨이포인트입니다.', '{bridge,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.692839, 35.86972), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["율하천", "율하역", "율하체육공원"], "confidence": "high", "address": "대한민국 대구광역시 동구 율하동 267-15"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('율하 푸르지오 3단지', '김해 율하천 자전거길과 인접한 아파트 단지로, 라이딩 시 방향을 가늠하는 랜드마크나 출발 및 도착지로 활용하기 좋습니다.', '{landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.808584, 35.174243), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["율하천", "율하카페거리", "율상마을푸르지오4단지"], "confidence": "high", "address": "대한민국 김해시 율상푸르지오3단지"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('은가람중학교.리버스위트칸타빌', '은가람중학교와 리버스위트칸타빌 아파트 단지 앞 버스 정류장입니다. 미사강변도시 인근 자전거 주행 시 위치를 확인하는 이정표로 참고할 수 있습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.179848, 37.575958), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["은가람중학교", "미사강변 리버스위트 칸타빌"], "confidence": "high", "address": "대한민국 하남시 은가람중학교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('은운리 대청호 카페', '대청호 회남로 라이딩 코스에 위치한 뷰 맛집 카페입니다. 아름다운 산과 호수 풍경을 감상하며 대추차나 컵라면으로 든든하게 보급과 휴식을 취하기 좋습니다.', '{cafe,rest_area,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.599743, 36.413468), 4326), false, '{"source": "KOMOOT", "source_ids": ["808"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/19/19rgi4gpm4e1b1p1musvk8gpb95jqti1oa-uhi95215992/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1g/1gs8w6acaawc3hmk5gyf1hnrv5jqti506-uhi95215993/0?width=1920&crop=false"], "category_raw": "cafe", "tour_count": 1, "nearby_landmarks": ["대청호", "독수리봉 전망대"], "confidence": "high", "address": "대한민국 충청북도 보은군 회남면 은운리 200-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('읍내방죽', '계족산 초입에 위치한 생태 연못입니다. 넓은 무료 주차장과 화장실이 마련되어 있어 라이딩 출발지나 휴식처로 활용하기 좋습니다.', '{lake,rest_area,parking,restroom,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.433744, 36.378791), 4326), false, '{"source": "KOMOOT", "source_ids": ["1198"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["계족산", "용화사", "봉황마당"], "confidence": "high", "address": "대한민국 대전광역시 대덕구 읍내동 516"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('읍리지석묘', '청산도 자전거길 코스에 위치한 청동기 시대 고인돌 유적입니다. 라이딩 중 잠시 멈춰 섬의 역사와 정취를 감상하기 좋은 포인트입니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.871649, 34.174901), 4326), false, '{"source": "KOMOOT", "source_ids": ["81"], "category_raw": "15", "tour_count": 1, "nearby_landmarks": ["읍리하마비", "범바위", "청산도 슬로길"], "confidence": "high", "address": "대한민국 전라남도 완도군 청산면 읍리 810-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('응암역 불광천 자전거 거점', '불광천 자전거길이 시작되는 6호선 지하철역입니다. 자전거 정비 거치대와 공공자전거 대여소가 있어 라이딩 출발 및 연계 지점으로 매우 유용합니다.', '{transit,river,rest_area,viewpoint,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.915535, 37.598429), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/7/7c/Eungam_Station_20201009_002.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9c/Seoul-metro-610-Eungam-station-platform-20191022-100712.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e6/Seoul-metro-610-Eungam-station-entrance-4-20191022-101948.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/08/Seoul-metro-610-Eungam-station-entrance-3-20191022-102126.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/5b/응암역.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["불광천", "불광천 자전거길", "신사교 전망공간"], "confidence": "high", "address": "대한민국 서울특별시 응암역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('의림지', '삼한시대에 축조된 유서 깊은 저수지로, 수려한 호수 풍경과 용추폭포를 감상하며 쉬어가기 좋습니다. 삼한의 초록길 자전거도로와 연결되어 라이더들의 필수 코스로 꼽힙니다.', '{lake,historic,landmark,park,viewpoint,rest_area,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.208625, 37.173023), 4326), false, '{"source": "KOMOOT", "source_ids": ["178"], "image_urls": ["https://photos.komoot.de/wiki/commons/b/b6/청풍_성열현인_악성_우륵_552년_임지_부엽공법_제언_시축_기념우표.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/67/의림지_하절기_제방.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/de/의림지_제방의_전경.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b5/의림지_제방_파괴_부분.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/5e/의림지_제방_홍류동_방면_계곡.jpg?width=1920&crop=false"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["용추폭포", "삼한의 초록길", "의림지 파크랜드", "비룡담저수지"], "confidence": "high", "address": "대한민국 충청북도 제천시 모산동 238-12"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('의성산', '정상에 구포왜성 터가 있는 해발 약 70m의 얕은 산입니다. 낙동강과 덕천동 일대를 조망할 수 있으며, 가벼운 업힐이나 끌바로 올라 경치를 즐기기 좋습니다.', '{mountain,historic,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.008908, 35.216777), 4326), false, '{"source": "KOMOOT", "source_ids": ["624"], "category_raw": "191", "tour_count": 1, "nearby_landmarks": ["구포왜성", "북구문화빙상센터", "구룡사"], "confidence": "high", "address": "대한민국 부산광역시 북구 덕천동 506-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('와룡산 이곡봉', '대구 와룡산에 위치한 해발 294.2m의 이곡봉입니다. 산악 자전거(MTB) 코스나 등산 중 거쳐가는 주요 봉우리로, 자연 속에서 휴식하기 좋습니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.515829, 35.850629), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/4/49/Daegu-metropolitan-transit-corporation-222-Igok-station-platform-20161010-144006.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a1/Daegu-metropolitan-transit-corporation-222-Igok-station-entrance-1-20161010-144742.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["와룡산", "상리봉", "배실공원"], "confidence": "high", "address": "대한민국 대구광역시 달서구 용산동 산133-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('이도초등학교', '제주시 이도2동 주택가에 위치한 초등학교입니다. 도심 라이딩 시 길찾기 기준점으로 활용하거나 인근 상권에서 식사 및 보급을 하기 좋습니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.532644, 33.489319), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["제주지방법원", "제주소방서", "제주교육박물관"], "confidence": "high", "address": "대한민국 제주시 이도초등학교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('이순신 장군 동상', '광화문 광장의 상징적인 랜드마크로, 서울 도심 시티 라이딩 중 인증샷을 남기거나 잠시 쉬어가기 좋은 역사적 명소입니다.', '{landmark,historic,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.977027, 37.570859), 4326), false, '{"source": "KOMOOT", "source_ids": ["73"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/ak/aknt661a5w4w1p1ail2hltrc34e5o46vw-uhi56574752/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/16/16dus0ph22bp6e4d2yvg4k4q64e5o493k-uhi56574754/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k6/1k/1kkwcbgf508ybrfkuo79unqz44e5o49ou-uhi56574756/0?width=1920&crop=false"], "tips": [{"text": "Die Statue von Admiral Yi Sun-sin steht auf dem Gwanghwamun-Platz. Hierbei handelt es sich um den koreanischen Kriegshelden Admiral Yi Sun-sin aus dem 16. Jahrhundert. Er führte zeitweise die koreanischen Seestreitkräfte während des Imjin-Kriegs zwischen 1592 und 1598 und trug entscheidend zur Abwehr der japansischen Invasion bei. \n\nEs gilt als eines der wichtigsten Wahrzeichen von Seoul.", "author": "Maik"}], "category_raw": "man_made_monument", "tour_count": 1, "nearby_landmarks": ["세종대왕 동상", "광화문", "경복궁", "청계천"], "confidence": "high", "address": "대한민국 서울특별시 종로구 세종로 세종대로 172"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('이제오름', '제주시 한경면 청수리에 위치한 작고 한적한 오름입니다. 인적이 드물고 자연이 잘 보존되어 있어 라이딩 중 가볍게 둘러보며 쉬어가기 좋은 자연 지점입니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.244982, 33.330804), 4326), false, '{"source": "KOMOOT", "source_ids": ["122"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["가마오름", "저지오름", "문도지오름"], "confidence": "medium", "address": "대한민국 제주특별자치도 제주시 한경면 청수리 1849"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('이터산', '용인시 노고봉과 정광산 자락에 위치한 산입니다. 임도가 개설되어 있어 산악자전거(MTB) 라이딩 코스로 종종 활용되는 곳입니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.261471, 37.329104), 4326), false, '{"source": "KOMOOT", "source_ids": ["309"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["노고봉", "정광산", "한국외국어대학교 글로벌캠퍼스"], "confidence": "high", "address": "87H6+JH 대한민국 경기도 용인시"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('익선동 한옥거리', '좁은 골목에 한옥 카페와 맛집이 밀집한 명소입니다. 주말엔 인파가 많아 자전거를 끌고 가야 하지만, 한적한 시간에는 고즈넉한 매력을 즐기기 좋습니다.', '{cafe,restaurant,historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.983807, 37.577488), 4326), false, '{"source": "KOMOOT", "source_ids": ["213"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/mc/mc9knf0iozbnp6rf5lek3g6k4jibcqbt-uhi59004362/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/e2/e2rxyc7vhx1pmcsg7ntle74q4jibcqlw-uhi59004363/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/tr/tryhal3p04et1pmqqnfa1vinc4jibcqm1-uhi59004364/0?width=1920&crop=false"], "tips": [{"text": "Busy (but manageable to get through) during weekends but a treat during a quiet time. Some lovely buildings.", "author": "Claire Tayler"}], "category_raw": "settlement", "tour_count": 1, "nearby_landmarks": ["종묘", "인사동", "낙원상가", "창덕궁"], "confidence": "high", "address": "대한민국 서울특별시 안국동 58번지 종로구 서울특별시 KR"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('동백호수공원', '신갈천 자전거도로와 연결된 도심 속 호수공원입니다. 주변에 카페, 식당 등 상권이 잘 조성되어 있어 라이딩 중 보급과 휴식을 취하기 매우 좋습니다.', '{lake,park,rest_area,cafe,restaurant,convenience_store,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.155922, 37.286949), 4326), false, '{"source": "KOMOOT", "source_ids": ["91"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["신갈천 자전거도로", "동백 이마트", "동백문월드"], "confidence": "high", "address": "대한민국 경기도 용인시 기흥구 동백동 567"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('인봉', '인봉은 인제군 상남면에 위치한 해발 355m의 암봉입니다. 주변 임도를 따라 MTB나 그래블 바이크 라이딩 시 자연 경관을 즐기며 지날 수 있는 산악 포인트입니다.', '{mountain,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.268103, 37.887576), 4326), false, '{"source": "KOMOOT", "source_ids": ["2032"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["배미산", "미륵골", "446번 지방도"], "confidence": "high", "address": "대한민국 강원특별자치도 인제군 상남면 상남리 3-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('인천 베이 호텔', '아라자전거길 시작점인 정서진 인근에 위치한 호텔입니다. 자전거 프라이빗 무료 보관 서비스를 제공하여 국토종주 라이더들이 휴식하기 좋습니다.', '{rest_area,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.619701, 37.561659), 4326), false, '{"source": "KOMOOT", "source_ids": ["156"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/1q/1qnglf8fil1dp7gt7tdq1wxea564gkjz7-uhi80542851/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 1, "nearby_landmarks": ["아라뱃길", "정서진", "아라자전거길", "아라타워"], "confidence": "high", "address": "대한민국 인천광역시 서구 정서진로 117"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('일산해수욕장 (Ilsan beach)', '해파랑길 자전거 코스와 연결되어 접근성이 뛰어나며, 주변에 식당과 카페 등 편의시설이 많아 라이딩 중 휴식하기 좋은 해변입니다.', '{beach,viewpoint,rest_area,restroom,convenience_store,cafe,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.430413, 35.495251), 4326), false, '{"source": "KOMOOT", "source_ids": ["190"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["대왕암공원", "대왕암 출렁다리", "슬도"], "confidence": "high", "address": "대한민국 울산광역시 동구 일산동 860-13"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('일우한란아파트', '제주 환상자전거길 월대천 인근에 위치한 아파트 단지입니다. 라이딩 중 길을 찾거나 위치를 가늠하는 로컬 이정표로 참고하기 좋습니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.430876, 33.492599), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["월대천", "외도교", "그라벨호텔"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 외도일동 418-11"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('임원해수욕장', '동해안 자전거길에 위치한 해변으로 화장실과 야영장 등 편의시설이 잘 갖춰져 있습니다. 인근 임원항에서 식사와 보급을 해결하기 좋으며, 근처에 임원 인증센터가 있습니다.', '{beach,restroom,parking,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.341127, 37.226832), 4326), false, '{"source": "KOMOOT", "source_ids": ["1499"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["임원항", "임원 인증센터", "수로부인헌화공원"], "confidence": "high", "address": "대한민국 강원특별자치도 삼척시 원덕읍 임원리 241-13"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('임하호', '안동호와 연계하여 라이딩하기 좋은 아름다운 호수입니다. 적당한 낙타등 코스와 수려한 자연 경관을 자랑하여 자전거 투어 명소로 인기가 높습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.924919, 36.532835), 4326), false, '{"source": "KOMOOT", "source_ids": ["1413"], "image_urls": ["https://photos.komoot.de/wiki/commons/0/0e/Korea-Andong-Imha_Dam-01.jpg?width=1920&crop=false"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["임하호캠핑수상레저타운", "지례예술촌", "안동호"], "confidence": "high", "address": "대한민국 경상북도 안동시 임동면 박곡리 164"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('자갈치시장', '부산의 대표적인 수산 시장으로, 신선한 해산물로 식사하며 쉬어가기 좋은 랜드마크입니다. 보행자와 차량이 많아 라이딩 시 주의가 필요합니다.', '{landmark,restaurant,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.030664, 35.09692), 4326), false, '{"source": "KOMOOT", "source_ids": ["328"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/4g/4g2rs48c9xiem7qmr9dq8am84h1jnsy7-uhi57607483/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/lm/lmuzfqvx8r64m9qp5fb7pfzn4h1jnt0k-uhi57607484/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/47/47y9amce8wsr1bcc2jesh7y7y4h1jnt45-uhi57607485/0?width=1920&crop=false"], "category_raw": "other_man_made", "tour_count": 1, "nearby_landmarks": ["영도대교", "BIFF 광장", "용두산공원"], "confidence": "high", "address": "대한민국 부산광역시 중구 남포동5가 114-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('자갈치어시장 항구 전망', '이른 아침이나 해 질 녘 어선들의 활기찬 모습을 감상하며 자전거를 세우고 잠시 쉬어가기 좋은 자갈치시장 뒤편 항구 전망 포인트입니다.', '{viewpoint,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.035093, 35.096552), 4326), false, '{"source": "KOMOOT", "source_ids": ["335"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1o/1otpoz2qemq1yumf4iziwt6vl4h1vzuwa-uhi57611253/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/32/321iholjnjnc1ju5ovmjl0ad54h1vzv0m-uhi57611254/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1w/1ws4pmbe0ln7c13bz3va6j3xah4h1vzv1k-uhi57611255/0?width=1920&crop=false"], "tips": [{"text": "Schöner Standpunkt um das Treiben der Fischerboote zu sehen (vor allem am frühen Morgen oder wenn es anfängt dunkel zu werden)", "author": "Wäller-on-tour"}], "category_raw": "viewpoint", "tour_count": 1, "nearby_landmarks": ["자갈치시장", "영도대교", "남항대교"], "confidence": "high", "address": "대한민국 부산광역시 중구 용미길9번길 6-14"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('자만벽화마을', '가파른 언덕에 위치해 자전거를 타고 오르긴 힘들지만, 한옥마을의 멋진 전경과 아기자기한 벽화를 보며 쉬어가기 좋은 매력적인 포인트입니다.', '{landmark,viewpoint,rest_area,cafe}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.15575, 35.81448), 4326), false, '{"source": "KOMOOT", "source_ids": ["1235"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1p/1phk9yibpxkdb1w3lgioac77w730ymtx66-uhi6554272/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/hm/hm9qw05nldmh1wkh3wrz852om30ymu0sd-uhi6554273/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/17/171xt3fqmjfc4mciwly395ba530ymu4jt-uhi6554274/0?width=1920&crop=false"], "category_raw": "settlement", "tour_count": 1, "nearby_landmarks": ["전주 한옥마을", "오목대", "이목대"], "confidence": "high", "address": "대한민국 전북특별자치도 전주시 완산구 교동 54-81"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('자연조경', '김포 대곶면 약암리에 위치한 조경 업체 또는 묘목장으로 추정됩니다. 강화도로 향하는 길목에 있으며, 라이더를 위한 편의시설은 없는 일반 사업장입니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.551067, 37.643061), 4326), false, '{"source": "KOMOOT", "source_ids": ["2122"], "category_raw": "191", "tour_count": 1, "nearby_landmarks": ["약암홍염천", "초지대교", "대명항"], "confidence": "medium", "address": "대한민국 경기도 김포시 대곶면 약암리 1215-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('유엔기념공원 자전거 주차장', '유엔기념공원 및 평화공원 입구 인근에 위치한 자전거 주차장으로, 공원 방문이나 주변 휴식 시 자전거를 안전하게 보관할 수 있는 유용한 시설입니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.095286, 35.127637), 4326), false, '{"source": "KOMOOT", "source_ids": ["89"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/4x/4xvo8mtt6jgp1uhlrb7rg9fyp4h1vwfqh-uhi57611194/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/22/22dvq17fky1tm4qjdgpcwgxo4xmsih1l-uhi70476000/0?width=1920&crop=false"], "category_raw": "parking", "tour_count": 1, "nearby_landmarks": ["유엔기념공원", "평화공원", "부산박물관", "대연수목전시원"], "confidence": "high", "address": "대한민국 부산광역시 남구 대연동 839-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('진주 남강 자전거 무료대여소', '진주 남강변에 위치한 무료 자전거 대여소입니다. 진주시 공영 자전거(하모타고 등)를 빌려 아름다운 남강 자전거길을 따라 라이딩을 즐기기 좋습니다.', '{bike_shop,river,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.069059, 35.172283), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["남강", "남강자전거길", "신안평거산책로"], "confidence": "high", "address": "대한민국 경상남도 진주시 신안동 608-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('잠곡저수지', '철원 하오터널이나 복주산 방향 업힐 코스 길목에 위치한 저수지입니다. 시원한 호수 풍경과 자연을 감상하며 라이딩하기 좋습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.462607, 38.155584), 4326), false, '{"source": "KOMOOT", "source_ids": ["1250"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["국립복주산자연휴양림", "하오터널", "철원 누에마을"], "confidence": "high", "address": "대한민국 강원특별자치도 철원군 근남면 잠곡리 산122-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('잠신고등학교', '자전거 통학 문화가 잘 조성된 고등학교입니다. 잠실 한강공원 진입로와 가까워 지역 라이더들의 생활 코스 기점이나 길 찾기용 랜드마크로 참고하기 좋습니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.090921, 37.516535), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["잠실한강공원", "잠실새내역", "리센츠아파트"], "confidence": "high", "address": "대한민국 서울특별시 잠신고등학교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('잠실새내역', '한강 자전거길(잠실새내 나들목) 접근성이 뛰어난 2호선 전철역입니다. 주변 상권이 발달해 라이딩 전후 식사나 휴식을 위한 모임 장소로 좋습니다.', '{transit,parking,restaurant,cafe,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.085586, 37.511598), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/f/fb/20210626_잠실새내역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e0/Q488126_Sincheon_A02.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b0/Seoul-metro-217-Jamsilsaenae-station-entrance-2-20181121-160926.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/ed/Q488126_Sincheon_A01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b8/Seoul_Metro_Jamsilsaenae_Station.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["잠실새내 나들목", "잠실한강공원", "잠실종합운동장"], "confidence": "high", "address": "대한민국 서울특별시 잠실새내역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('김포 장기역', '김포골드라인 장기역 일대입니다. 주변 상권에서 보급하기 좋으며, 라베니체 수변공원을 거쳐 평화누리 자전거길로 연계 라이딩하기 좋습니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.668972, 37.644043), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/b/b5/Janggi_Station3.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["장기역", "라베니체 마치에비뉴", "한강중앙공원"], "confidence": "high", "address": "대한민국 김포시 장기"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('장미공원주차장', '창원 장미공원 주차장으로 라이딩 출발지나 휴식처로 적합합니다. 단, 공원 내부는 자전거 출입이 제한되므로 주차 후 도보로 감상하거나 외곽 자전거길을 이용해야 합니다.', '{parking,park,restroom,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.691175, 35.207119), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["창원 장미공원", "가음정공원", "기업사랑공원"], "confidence": "high", "address": "대한민국 경상남도 창원시 성산구 가음동 31"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('장산역', '부산 지하철 2호선 장산역(웅신시네아트)입니다. 주변에 식당, 카페, 편의점 등 상업 시설이 밀집해 있어 라이딩 전후 보급과 휴식, 만남의 장소로 적합합니다.', '{transit,convenience_store,cafe,restaurant,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.175805, 35.16945), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/50/Busan-subway-201-Jangsan-station-8-entrance.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c4/Busan-subway-201-Jangsan-station-entrance-14-20180402-160852.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9e/201jangsan.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/62/201jangsan2.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/29/Jangsan_Station_exit_1_in_2018.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["장산역", "웅신시네아트", "롯데시네마 프리미엄해운대"], "confidence": "high", "address": "대한민국 부산광역시 해운대구 해운대로 802"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('장서마을 마을숲', '2020년에 복원된 부안군 상서면의 전통 마을숲으로, 라이딩 중 나무 그늘 아래서 고즈넉하게 땀을 식히며 휴식하기 좋은 자연 쉼터입니다.', '{park,nature,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.679101, 35.709797), 4326), false, '{"source": "KOMOOT", "source_ids": ["122"], "category_raw": "191", "tour_count": 1, "nearby_landmarks": ["장서마을"], "confidence": "high", "address": "대한민국 전북특별자치도 부안군 상서면 장동리 425-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('장수천 자전거길', '인천대공원에서 소래포구로 이어지는 생태하천 자전거길입니다. 평탄한 코스와 아름다운 자연 경관 덕분에 초보 라이더에게도 인기가 많습니다.', '{river,park,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.746835, 37.450217), 4326), false, '{"source": "KOMOOT", "source_ids": ["352"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["인천대공원", "소래습지생태공원", "소래포구"], "confidence": "high", "address": "대한민국 인천광역시 남동구 장수동 488-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('장신대역 자전거 주차장', '부산김해경전철역으로 자전거 보관소와 공공자전거 대여소가 있습니다. 해반천 자전거길과 인접해 라이딩 출발 및 연계 지점으로 매우 편리합니다.', '{transit,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.86739, 35.259419), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/57/Busan-gimhae-light-rail-transit-20-Presbyterian-university-station-platform-20180331-171422.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f8/Jangsindaeyeok_in_2011.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/5a/Busan-gimhae-light-rail-transit-20-Presbyterian-university-station-entrance-1-20180331-171948.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9f/Busan-gimhae-light-rail-transit-20-Presbyterian-university-station-entrance-2-20180331-171722.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["해반천", "부산장신대학교"], "confidence": "high", "address": "대한민국 김해시 장신대역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('장심리입구', '경기도 광주시 곤지암읍 장심리로 진입하는 입구이자 버스 정류장입니다. 동광주IC 인근에 위치하며, 한적한 장심리 계곡 방면 라이딩 시 거쳐가는 길목입니다.', '{transit,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.405457, 37.372566), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["동광주IC", "장심리 계곡", "만선삼거리"], "confidence": "high", "address": "대한민국 광주시 장심리입구"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('장안저수지', '장태산 자연휴양림 인근의 고즈넉한 저수지입니다. 갑천누리길 3코스와 연결된 자전거도로가 잘 정비되어 있어 수변 경치를 즐기며 라이딩하기 좋습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.345699, 36.226275), 4326), false, '{"source": "KOMOOT", "source_ids": ["716"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["장태산 자연휴양림", "팔마정"], "confidence": "high", "address": "대한민국 대전광역시 서구 장안동 138-11"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('장욱진 고택', '근현대 미술 거장 장욱진 화백의 고택입니다. 고즈넉한 한옥과 양옥을 감상하며, 내부 카페에서 마북천 라이딩 중 여유롭게 문화적 휴식을 취하기 좋은 공간입니다.', '{historic,landmark,cafe,museum,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.120243, 37.301001), 4326), false, '{"source": "KOMOOT", "source_ids": ["112"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["마북천", "집운헌", "관어당"], "confidence": "high", "address": "대한민국 경기도 용인시 기흥구 마북로 113"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('장유고입구', '김해 부곡동 장유고등학교 인근의 교차로 및 버스정류장입니다. 코아상가 등 상업시설이 밀집해 있어 라이딩 중 식수나 간식을 보급하기 좋은 도심 경유지입니다.', '{transit,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.80936, 35.203874), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["장유고등학교", "코아상가"], "confidence": "high", "address": "대한민국 경상남도 김해시 장유로 230"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('장유1동행정복지센터', '과거 장유면사무소였던 장유1동행정복지센터입니다. 자전거 도로가 인접해 있어 라이딩 중 화장실 이용이나 식수 보충 등 가볍게 쉬어가기 좋습니다.', '{rest_area,restroom,water_fountain,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.810971, 35.202254), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["장유전통시장", "무계교"], "confidence": "high", "address": "대한민국 김해시 장유1동행정복지센터"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('장척소류지', '김해 도봉산과 장척계곡 인근에 위치한 조용한 저수지입니다. 한적한 자연 풍경을 감상하며 라이딩 중 잠시 쉬어가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.915623, 35.28813), 4326), false, '{"source": "KOMOOT", "source_ids": ["564"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["도봉산", "장척계곡"], "confidence": "high", "address": "대한민국 경상남도 김해시 상동면 묵방리 378-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('장한평역', '중랑천 자전거길과 인접해 라이딩 연계가 편리한 5호선 지하철역입니다. 출구 주변에 자전거 보관대와 화장실이 마련되어 있습니다.', '{transit,parking,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.064585, 37.561483), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/60/Seoul-metro-543-Janghanpyeong-station-sign-20180915-075902.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/92/Seoul-metro-543-Janghanpyeong-station-entrance-6-20180915-080410.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/58/Seoul-metro-543-Janghanpyeong-station-platform-20180915-075956.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d2/543_장한평.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/44/Q498140_Janghanpyeong_A01.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["중랑천 자전거길", "장안평 중고차시장", "배봉산"], "confidence": "high", "address": "대한민국 서울특별시 장한평역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('잿들소류지', '경남 합천군 봉산면에 위치한 조용한 소류지(작은 저수지)입니다. 한적한 시골길 라이딩 중 자연 풍경을 감상하며 지나가기 좋은 포인트입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.062572, 35.594849), 4326), false, '{"source": "KOMOOT", "source_ids": ["1091"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["강덕산", "계산교"], "confidence": "high", "address": "대한민국 경상남도 합천군 봉산면 계산리 1070"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('적벽강', '부안 변산반도의 붉은 해안 절벽과 바다가 어우러진 절경의 명소입니다. 해안도로 라이딩 중 아름다운 서해 낙조와 자연 경관을 감상하기 좋은 뷰포인트입니다.', '{viewpoint,nature,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.464415, 35.638122), 4326), false, '{"source": "KOMOOT", "source_ids": ["693"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["수성당", "채석강", "격포리 후박나무 군락"], "confidence": "high", "address": "대한민국 전북특별자치도 부안군 변산면 격포리 산35-44"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('전동성당', '전주 한옥마을 초입에 위치한 아름다운 성당으로, 라이딩 중 잠시 멈춰 기념사진을 남기기 좋은 전주의 대표적인 랜드마크입니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.149258, 35.81382), 4326), false, '{"source": "KOMOOT", "source_ids": ["1206"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/4o/4o1n66oxopu2pw7cni4ihwfk30ymnd3x-uhi6554248/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1c/1c0nokslzycxq16shws9io1nhq30xkhyia-uhi6535872/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/jl/jlvmyn80tfs37xkbby7qzyww30xki6zj-uhi6535877/0?width=1920&crop=false"], "category_raw": "religious_building", "tour_count": 1, "nearby_landmarks": ["전주한옥마을", "경기전", "풍남문"], "confidence": "high", "address": "대한민국 전북특별자치도 전주시 완산구 전동 200-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('전류리항 카페', '전류리포구 인근 평화누리길 자전거 코스에 위치한 빈티지 감성의 카페입니다. 라이딩 중 커피 한 잔과 함께 친절한 서비스를 받으며 쉬어가기 좋습니다.', '{cafe,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.662494, 37.6983), 4326), false, '{"source": "KOMOOT", "source_ids": ["132"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1j/1j5be4uxrsej51g8l74xa8xljh387zp6t7-uhi9891764/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/7o/7om0xdenih5114tv03qyx9acr5e7hdf2l-uhi87597270/0?width=1920&crop=false"], "tips": [{"text": "Didn''t eat here but coffee was good, service friendly and the interior was quirky vintage, would definitely stop here again on this route.", "author": "Jon"}], "category_raw": "cafe", "tour_count": 1, "nearby_landmarks": ["전류리포구", "평화누리길 3코스"], "confidence": "medium", "address": "대한민국 경기도 김포시 하성면 전류리 461-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남천교(청연루)', '전주천 자전거길을 지나는 남천교 위의 전통 누각입니다. 시원한 강바람을 맞으며 탁 트인 전주천 풍경을 감상하고 라이딩 중 쉬어가기 좋은 랜드마크입니다.', '{bridge,viewpoint,rest_area,landmark,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.153158, 35.810728), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["전주한옥마을", "전주천 자전거길", "오목교"], "confidence": "high", "address": "대한민국 전북특별자치도 전주시 완산구 교동 192-4 전주천 남천교(청연루)"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('전망대', '낙동강 종주 자전거길 안동 구간에 위치한 전망대입니다. 하회마을로 향하는 길목에서 탁 트인 낙동강 풍경을 감상하며 잠시 휴식하기 좋습니다.', '{viewpoint,rest_area,river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.531809, 36.537471), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["낙동강", "안동 하회마을"], "confidence": "medium", "address": "대한민국 경상북도 안동시 풍천면 하회리 산73"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('화악터널 곰돌이 전망대', '화악산 업힐 코스의 정상부인 화악터널 앞 전망대(가평 별빛정원)입니다. 탁 트인 경관을 감상하며 휴식하기 좋은 라이더들의 필수 정차 및 포토 스팟입니다.', '{viewpoint,rest_area,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.525925, 37.997262), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["화악터널", "화악산", "화악터널 곰돌이상"], "confidence": "high", "address": "XGWG+W9 대한민국 경기도 가평군"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('녹차로 차밭 전망대', '대한다원에서 율포해변으로 이어지는 녹차로에 위치한 차밭 전망대입니다. 자전거를 세우고 드넓은 녹차밭과 영천저수지를 조망하며 휴식하기 좋습니다.', '{viewpoint,rest_area,cafe}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.087408, 34.711895), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["대한다원", "영천저수지", "율포해수욕장"], "confidence": "high", "address": "대한민국 전라남도 보성군 회천면 영천리 산85-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('조발도 전망대', '여수-고흥 백리섬섬길 조발도에 위치한 전망대 겸 쉼터입니다. 다도해와 대교 절경을 감상하며 카페와 화장실을 이용할 수 있어 자전거 라이딩 중 쉬어가기 좋습니다.', '{viewpoint,rest_area,cafe,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.562905, 34.631639), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["화양조발대교", "둔병대교", "백리섬섬길"], "confidence": "high", "address": "대한민국 전라남도 여수시 화정면 조발리 산23-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('전망대', '전북 남원시 지리산 둘레길 및 백두대간 코스 인근에 위치한 전망대로, 자전거(MTB 등) 라이딩 중 휴식을 취하며 주변 경관을 감상하기 좋은 장소입니다.', '{viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.47651, 35.38884), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["지리산 둘레길", "백두대간", "노치마을", "수정봉"], "confidence": "high", "address": "9FQG+GJ 대한민국 전북특별자치도 남원시"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남해 독일마을 전망대', '남해 독일마을 정상에 위치한 전망대입니다. 업힐을 오른 뒤 주황색 지붕의 이국적인 주택들과 푸른 바다를 배경으로 멋진 사진을 남기며 쉬어가기 좋습니다.', '{viewpoint,rest_area,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.039003, 34.79955), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["남해 독일마을", "파독전시관", "원예예술촌", "물건방조어부림"], "confidence": "high", "address": "대한민국 경상남도 남해군 삼동면 물건리 산55"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('말굽재 전망대', '동해안 자전거길 종주 중 만나는 말굽재 업힐 구간의 전망대입니다. 힘든 오르막 끝에 정자에서 용화해변의 탁 트인 풍경을 보며 휴식하기 좋습니다.', '{viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.299603, 37.294799), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["용화해변", "삼척해상케이블카 용화역"], "confidence": "high", "address": "대한민국 강원특별자치도 삼척시 근덕면 용화리 산151-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('할리스커피 신림고시촌점', '미림여고 삼거리 인근 상가 건물(할리스커피 입점)입니다. 산악 전망대가 아니며, 루프탑에서 바라본 뷰를 등록했거나 위치가 잘못 지정된 POI로 추측됩니다.', '{cafe,hospital,viewpoint,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.933802, 37.471346), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["미림여자고등학교", "다이소 미림여고삼거리점", "할리스커피 신림고시촌점"], "confidence": "high", "address": "대한민국 서울특별시 관악구 호암로 605"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('광진교 8번가', '광진교 교각 하부에 위치한 이색 전망대 ''광진교 8번가''입니다. 한강 자전거길에서 접근하기 좋으며, 유리 바닥을 통해 강물을 내려다보며 쉴 수 있습니다.', '{viewpoint,rest_area,bridge,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.112561, 37.54507), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["광진교", "광나루 한강공원"], "confidence": "high", "address": "대한민국 서울특별시 강동구 천호동 527-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('성삼재 휴게소 전망대', '지리산 성삼재 업힐 정상에 있는 전망대입니다. 웅장한 지리산 경치를 감상할 수 있으며, 휴게소 내 매점과 화장실이 있어 라이더들의 필수 보급 및 휴식처입니다.', '{viewpoint,rest_area,convenience_store,cafe,restroom,parking,mountain,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.510609, 35.306286), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["성삼재휴게소", "노고단", "지리산국립공원"], "confidence": "high", "address": "대한민국 전라남도 구례군 산동면 노고단로 1068"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('전망대', '변산반도 해안도로(국도 30호선) 변에 위치한 바다 전망대입니다. 라이딩 중 탁 트인 서해 풍경을 감상하며 잠시 쉬어가기 좋은 포인트입니다.', '{viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.543823, 35.587829), 4326), false, '{"source": "KOMOOT", "source_ids": ["206", "234", "972", "101", "274", "1101", "681", "220", "454", "394"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["변산반도 해안도로", "변산마실길"], "confidence": "medium", "address": "대한민국 전북특별자치도 부안군 진서면 운호리 348-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('필례계곡 전망데크', '인제 필례계곡(은비령길)에 위치한 전망데크로, 라이딩 중 오단폭포와 계곡의 절경을 감상하며 쉬어가기 좋은 뷰포인트입니다.', '{viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.366449, 38.068193), 4326), false, '{"source": "KOMOOT", "source_ids": ["463"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["필례계곡", "오단폭포", "필례약수", "은비령"], "confidence": "high", "address": "3998+7H 대한민국 강원특별자치도 인제군"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('전북도립미술관', '모악산 자락과 구이저수지 인근에 위치한 전북도립미술관입니다. 라이딩 중 문화생활을 즐기며 쾌적하게 휴식하기 좋은 장소입니다.', '{museum,cafe,restroom,parking,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.11014, 35.729325), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["모악산", "구이저수지", "대한민국술테마박물관"], "confidence": "high", "address": "대한민국 완주군 전북도립미술관"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('전주역', '전주 자전거 여행의 주요 관문인 전주역입니다. 기차를 이용한 자전거 점프가 가능하며, 역 내외에 화장실과 편의점 등 휴식 시설이 잘 갖춰져 있어 출발 및 도착지로 좋습니다.', '{transit,parking,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.162626, 35.850477), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/e/e2/Jeonju_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f0/Jeonju_Station_20230408_002.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f7/Jeonju_Station_20230408_019.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6e/Jeonju_Station_platform_under_construction.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["전주역 광장", "첫마중길"], "confidence": "high", "address": "대한민국 전북특별자치도 전주시 덕진구 우아동3가 235-11"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('구암정', '섬진강 자전거길에 위치한 전통 정자 ''구암정''입니다. 아름다운 강변 풍경을 감상하며 라이딩 중 고즈넉하게 쉬어가기 좋은 휴식처입니다.', '{historic,landmark,rest_area,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.205054, 35.43576), 4326), false, '{"source": "KOMOOT", "source_ids": ["666"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1i/1ic4c0iek798hqdws6w4e95045e57y3bm-uhi87511867/0?width=1920&crop=false"], "category_raw": "other_man_made", "tour_count": 1, "nearby_landmarks": ["섬진강", "섬진강 자전거길", "형제암"], "confidence": "high", "address": "대한민국 전북특별자치도 순창군 동계면 구미리 1028"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('점촌역', '새재자전거길 종주 시 점프(대중교통 연계) 기점으로 유용한 경북선 기차역입니다. 넓은 주차장과 화장실이 있으며, 인근 점촌점빵길에서 식사와 보급을 해결하기 좋습니다.', '{transit,parking,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.202544, 36.595778), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/a/ae/Korail_Gyeongbuk_Line_Jeomchon_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/57/Jeomchon_Station_on_August,_2016.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/87/Korail_SL901.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b6/Korail_SL901_Panoramics.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/65/Jeomchon_Station_on_May_20th,_2019.jpg?width=1920&crop=false"], "category_raw": "243", "tour_count": 1, "nearby_landmarks": ["점촌점빵길", "새재자전거길", "영강"], "confidence": "high", "address": "대한민국 경상북도 문경시 점촌동 166-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('정림사지박물관 주차장', '백마강 자전거길과 가까워 라이딩 출발지나 휴식처로 좋은 주차장입니다. 화장실 이용이 가능하며, 유네스코 세계유산인 정림사지와 박물관을 함께 둘러보기 좋습니다.', '{parking,restroom,park,museum,historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.916339, 36.278651), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["정림사지", "정림사지박물관", "백제탑공원", "백마강 자전거길"], "confidence": "high", "address": "대한민국 충청남도 부여군 부여읍 동남리 373"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('정부과천청사', '수도권 인기 자전거 코스인 ''하트코스''의 주요 경유지입니다. 양재천 자전거길이 끝나고 인덕원 방향 공도로 진입하는 기점이 되어 많은 라이더들이 거쳐가는 랜드마크입니다.', '{landmark,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.99001, 37.426351), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/9/94/서울지하철_4호선_정부과천청사역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b4/20200905_정부과천청사역_만남의광장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/4a/20200905_정부과천청사역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/7a/Seoul_Subway_Line_4_Government_Complex_Gwacheon_Station_Platform.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["양재천", "관악산", "과천중앙공원"], "confidence": "high", "address": "대한민국 과천시 정부과천청사"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('정선아리랑시장', '라이딩 중 곤드레밥, 메밀전병 등 든든한 향토 음식으로 보급하며 한국의 옛 정취를 느낄 수 있는 전통시장입니다.', '{restaurant,rest_area,historic,landmark,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.665494, 37.380441), 4326), false, '{"source": "KOMOOT", "source_ids": ["355"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1j/1jjd61pcd9gac10p1zhanxe9w93dvyoh8q-uhi13807147/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1o/1obvize034aa23jz3dfooitpr3e86hdly-uhi14447001/0?width=1920&crop=false"], "tips": [{"text": "The Market has the nostalgia and pure environment of an old Korean Market. If you go to the market, you''ll be able to get a sense of original Korean lifestyle. Korea has a very doleful melody called \" Jeong Seon Arirang \" which originated from this city Jeong Seon. Many people love Jeong Seon because, until the present time, it has retained it''s untouched nature. Jeong Seon is proud of natural features it has been blessed with East River, Blue JoYang River, Hwa Am cave and the special scenery known in Korea as \" Hwa Am 8 Kyoung ( 8 different locations in the Jeong Seon Area ) \"\n\nhttps://www.jeongseon.go.kr/en/tourist_attractions/experience_shopping/5days_market", "author": ""}], "category_raw": "settlement", "tour_count": 1, "nearby_landmarks": ["아라리촌", "병방치 스카이워크", "정선역"], "confidence": "high", "address": "대한민국 강원특별자치도 정선군 정선읍 봉양리 348-19"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('정읍역', '내장산과 정읍천 자전거길 라이딩의 주요 출발점이 되는 기차역입니다. 화장실, 편의점, 카페 등 편의시설이 잘 갖춰져 있어 출발 전후 정비와 휴식에 좋습니다.', '{transit,restroom,convenience_store,cafe,water_fountain,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.842186, 35.57612), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/e/ec/정읍역.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/96/JeongeupStation.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/fb/정읍역_전경.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c5/Jeongeup_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/92/Jeongeup_Station_-_2009-02-04.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["정읍천 자전거길", "내장산", "정읍사공원"], "confidence": "high", "address": "대한민국 전북특별자치도 정읍시 연지동 343-216"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('정이품송', '속리산과 말티재 라이딩 코스의 필수 인증 명소인 천연기념물 소나무입니다. 주변 공원에서 휴식을 취하며 웅장한 자태를 감상하기 좋습니다.', '{landmark,historic,nature,park,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.81567, 36.516923), 4326), false, '{"source": "KOMOOT", "source_ids": ["1049"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1o/1oez5cywop0nkxa7zewh33y05kxty1ui-uhi96288099/0?width=1920&crop=false"], "category_raw": "natural_monument", "tour_count": 1, "nearby_landmarks": ["말티재", "법주사", "속리산 국립공원"], "confidence": "high", "address": "대한민국 충청북도 보은군 속리산면 상판리 18-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('정평', '경산 남천 자전거길이 지나는 정평동 수변 구역입니다. 인근에 풋살장 등 체육시설이 있으며, 평탄한 강변길을 따라 라이딩하며 가볍게 쉬어가기 좋습니다.', '{river,park,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.728325, 35.834024), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["남천 자전거길", "경산 풋살장", "정평역"], "confidence": "high", "address": "대한민국 경상북도 경산시 정평동 137-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('제덕동 팽나무', '수령 250년이 넘는 웅장한 노거수 팽나무입니다. 제포성지 인근 언덕에 위치해 탁 트인 경치를 감상하며 라이딩 중 잠시 쉬어가기 좋은 자연 랜드마크입니다.', '{nature,landmark,historic,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.741941, 35.104099), 4326), false, '{"source": "KOMOOT", "source_ids": ["249"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["제포성지", "제덕마을"], "confidence": "high", "address": "대한민국 경상남도 창원시 진해구 제덕동 622"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('제량지', '대구 평광동에서 새미기재로 향하는 임도에 위치한 아담한 저수지입니다. 본격적인 업힐 전 벤치가 있는 쉼터에서 잠시 쉬어갈 수 있는 MTB 코스의 주요 거점입니다.', '{lake,rest_area,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.728116, 35.931339), 4326), false, '{"source": "KOMOOT", "source_ids": ["388"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["새미기재", "모영재", "평광임도"], "confidence": "high", "address": "대한민국 대구광역시 동구 평광동 산310"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('제민제', '보령시 남포면에 위치한 소규모 저수지(월전지)입니다. 한적한 시골 풍경과 수변을 감상하며 라이딩 중 잠시 쉬어가기 좋은 포인트입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.565477, 36.269962), 4326), false, '{"source": "KOMOOT", "source_ids": ["389"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["월전초등학교"], "confidence": "high", "address": "대한민국 충청남도 보령시 남포면 양기리 658"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('제실산', '세종호수공원과 중앙공원 인근에 위치한 해발 46.6m의 아주 나지막한 산입니다. 자전거 인프라가 훌륭한 호수공원 코스 라이딩 중 가볍게 마주칠 수 있는 자연 랜드마크입니다.', '{mountain,nature,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.282126, 36.504337), 4326), false, '{"source": "KOMOOT", "source_ids": ["316"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["세종호수공원", "세종중앙공원", "국립세종수목원", "대통령기록관"], "confidence": "high", "address": "대한민국 세종특별자치시 연기면 세종리 735-170"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('제월당과 옥오재', '조선시대 양반 가옥의 정취를 느낄 수 있는 대전의 유형문화재입니다. 바로 앞 후곡공원에 정자와 벤치가 있어 라이딩 중 고즈넉하게 쉬어가기 좋습니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.42712, 36.377986), 4326), false, '{"source": "KOMOOT", "source_ids": ["1227"], "category_raw": "15", "tour_count": 1, "nearby_landmarks": ["후곡공원", "계족산"], "confidence": "high", "address": "대한민국 대전광역시 대덕구 읍내동 74-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('제일빌리지', '제주 애월읍 중산간서로 인근에 위치한 주거용 빌라 단지입니다. 중산간 코스 라이딩 시 위치를 가늠하는 이정표로 참고하기 좋습니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.444855, 33.460862), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["제주관광대학교", "제주홀릭뮤지엄"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 애월읍 광령리 30-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('제주시주차장', '제주시 삼도일동 금광아이빌 건물 주소지에 위치한 주차장입니다. 라이딩 시작 전 차량을 주차하거나 잠시 정차할 때 참고할 수 있는 공간입니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.521607, 33.499163), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["금광아이빌"], "confidence": "medium", "address": "대한민국 제주특별자치도 제주시 서광로18길 5-19"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('조개울팔당유원지', '남한강 자전거길 팔당 구간에 위치한 유원지 및 식당가입니다. 라이더들이 즐겨 찾는 맛집이 밀집해 있어 식사와 휴식을 취하기 좋은 주요 거점입니다.', '{transit,restaurant,rest_area,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.255065, 37.540334), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["남한강 자전거길", "팔당댐", "팔당역"], "confidence": "high", "address": "대한민국 경기도 남양주시 와부읍 팔당리 78-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('조양강', '정선 아우라지에서 시작되는 맑고 수려한 강입니다. 기암절벽과 산세가 어우러진 강변 도로는 경치가 뛰어나 자전거 라이딩 코스로 인기가 높습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.719401, 37.475967), 4326), false, '{"source": "KOMOOT", "source_ids": ["676"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["아우라지", "아우라지역", "정선레일바이크"], "confidence": "high", "address": "대한민국 강원특별자치도 정선군 여량면 여량리 223-12"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('보신각', '서울 도심의 상징적인 역사 랜드마크인 보신각입니다. 주변 교통량이 많아 주의가 필요하며, 인근 청계천 자전거길로 진입하기 좋습니다.', '{historic,landmark,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.983184, 37.570155), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/7/7a/Jong_gak_st.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/dc/Seoul-metro-131-Jonggak-station-entrance-06-20181125-172258.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f2/20240413_종각역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d7/Seoul-metro-131-Jonggak-station-entrance-05-20181125-172406.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bc/20240413_종각역_승강장.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["청계천", "종각역", "광화문"], "confidence": "high", "address": "대한민국 서울특별시 종로1가 종각"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('종로5가', '서울 도심의 주요 교차로이자 1호선 지하철역입니다. 바로 옆에 광장시장과 청계천이 위치해 라이딩 중 보급이나 휴식을 위한 경유지로 매우 좋습니다.', '{transit,landmark,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.001948, 37.57099), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/c/c6/20211016_종로5가역.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/37/Jongno_5-ga_Station_1.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f5/Subjr5ga04.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/88/20211016_종로5가역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/47/Seoul-metro-129-Jongno-5ga-station-entrance-03-20181122-114856.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["광장시장", "청계천", "종묘", "동대문"], "confidence": "high", "address": "대한민국 경기도 용인시 기흥구 상갈동 백남준로 13 종로5가"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('종친부 경근당', '국립현대미술관 서울관 내에 위치한 조선시대 종친부 건물입니다. 경복궁, 북촌 등 도심 궁궐 코스 라이딩 시 역사적 정취를 느끼며 가볍게 둘러보기 좋은 포인트입니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.981356, 37.579184), 4326), false, '{"source": "KOMOOT", "source_ids": ["149"], "category_raw": "15", "tour_count": 1, "nearby_landmarks": ["국립현대미술관 서울관", "경복궁", "북촌한옥마을"], "confidence": "high", "address": "대한민국 서울특별시 종로구 소격동 165-11"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('좌광천', '정관신도시부터 임랑해수욕장까지 이어지는 약 14.5km의 생태하천 자전거길입니다. 보행로와 자전거도로가 잘 분리되어 있어 안전하고 쾌적한 라이딩이 가능합니다.', '{river,nature,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.203941, 35.321163), 4326), false, '{"source": "KOMOOT", "source_ids": ["481", "57", "18", "491"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["임랑해수욕장", "병산저수지", "윗골공원", "구목정공원"], "confidence": "high", "address": "대한민국 부산광역시 기장군 정관읍 예림리 1035-102"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('좌광천', '정관신도시를 가로지르는 14.5km의 생태 하천 자전거길입니다. 병산저수지에서 임랑해수욕장까지 이어지며 자연경관이 수려해 라이딩하기 좋습니다.', '{river,park,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.183487, 35.321747), 4326), false, '{"source": "KOMOOT", "source_ids": ["481", "57", "18", "491"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["병산저수지", "임랑해수욕장", "정관신도시"], "confidence": "high", "address": "대한민국 부산광역시 기장군 정관읍 방곡리 288-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('좌광천', '정관신도시에서 임랑해수욕장까지 이어지는 쾌적한 생태하천 자전거길입니다. 노면이 잘 정비되어 있고 경치가 수려해 초보자도 안전하게 라이딩하기 좋습니다.', '{river,park,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.171488, 35.32881), 4326), false, '{"source": "KOMOOT", "source_ids": ["481", "57", "18", "491"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["용수교", "정관신도시", "임랑해수욕장"], "confidence": "high", "address": "대한민국 부산광역시 기장군 정관읍 용수리 1368"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('좌광천', '정관신도시에서 임랑해수욕장까지 이어지는 약 12km의 생태하천 자전거길입니다. 길이 평탄하고 풍경이 아름다워 쾌적한 라이딩을 즐기기 좋습니다.', '{river,park,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.181423, 35.323621), 4326), false, '{"source": "KOMOOT", "source_ids": ["481", "57", "18", "491"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["정관신도시", "임랑해수욕장", "윗골공원"], "confidence": "high", "address": "대한민국 부산광역시 기장군 정관읍 방곡리 446"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('부안 주공3차아파트', '부안읍 내에 위치한 아파트 단지로, 주변 상가를 통해 라이딩 전후 가벼운 보급을 하거나 동호인들의 만남의 장소로 활용하기 좋은 거점입니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.730858, 35.720203), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["부안시외버스터미널", "부안군청"], "confidence": "high", "address": "대한민국 부안군 주공3차아파트"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('주공4단지(건너편)', '충주 연수동 주공4단지 아파트 맞은편에 위치한 버스정류장입니다. 도심 라이딩 중 위치를 확인하거나 잠시 정차하여 쉬어가기 적합합니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.932179, 36.991337), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["연수주공4단지", "지코바치킨 연수동칠금점"], "confidence": "high", "address": "대한민국 충청북도 충주시 연수동 696-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('주문진 등대', '동해안 자전거길 인근 언덕에 위치한 강원도 최초의 등대입니다. 탁 트인 바다와 주문진항을 조망하며 라이딩 중 쉬어가기 좋은 뷰포인트입니다.', '{viewpoint,landmark,historic}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.834005, 37.897679), 4326), false, '{"source": "KOMOOT", "source_ids": ["200"], "category_raw": "19", "tour_count": 1, "nearby_landmarks": ["주문진항", "주문진수산시장", "소돌아들바위공원"], "confidence": "high", "address": "대한민국 강원특별자치도 강릉시 주문진읍 옛등대길 24-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('주문진시외버스터미널', '동해안 자전거길 종주 시 출발, 도착 또는 점프(시외 이동) 거점으로 유용한 버스터미널입니다. 주변에 식당과 편의시설이 많아 보급하기 좋습니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.825098, 37.884613), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["주문진항", "주문진수산시장", "주문진해수욕장", "BTS 버스정류장"], "confidence": "high", "address": "대한민국 강릉시 주문진시외버스터미널"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('주문진해수욕장', '동해안 자전거길 코스에 위치해 시원한 오션뷰를 즐기며 쉬어가기 좋은 해변입니다. 주변에 화장실과 편의시설이 잘 갖춰져 있습니다.', '{beach,rest_area,viewpoint,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.820989, 37.909262), 4326), false, '{"source": "KOMOOT", "source_ids": ["249"], "image_urls": ["https://photos.komoot.de/wiki/commons/d/d1/주문진해수욕장_향호해변.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bd/Jumunjin_Beach_20220501_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/30/Jumunjin_Beach_20220501_007.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/10/Jumunjin_Beach_20220501_013.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2a/Jumunjin_Beach_20220501_016.jpg?width=1920&crop=false"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["향호해변 BTS 버스정류장", "소돌해변", "주문진항"], "confidence": "high", "address": "산35-3, 향호리 주문진읍 강릉시 강원특별자치도 대한민국"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('가계해수욕장 주차장', '가계해수욕장과 진도 신비의 바닷길 인근에 위치한 대형 주차장입니다. 화장실과 음수대 등 편의시설이 잘 갖춰져 있어 라이딩 중 휴식하기 좋습니다.', '{parking,restroom,water_fountain,rest_area,beach}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.349141, 34.427798), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["가계해수욕장", "진도 신비의 바닷길", "진도해양생태관"], "confidence": "high", "address": "대한민국 전라남도 진도군 고군면 금계리 523-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('칠천연륙교 주차장', '거제 칠천연륙교 입구에 위치한 주차장입니다. 칠천도 해안도로 라이딩 코스를 시작하는 베이스캠프나 다리 진입 전 휴식처로 활용하기 좋습니다.', '{parking,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.652892, 34.975312), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["칠천연륙교", "칠천도"], "confidence": "high", "address": "대한민국 경상남도 거제시 하청면 실전리 139-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('장목면사무소 주차장', '장목면사무소 내에 위치한 주차장 및 공공 자전거 보관소입니다. 라이딩 중 안전하게 자전거를 주차하고 화장실을 이용하며 휴식하기 좋습니다.', '{parking,restroom,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.681961, 34.986389), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["장목면사무소", "장목파출소", "장목항"], "confidence": "high", "address": "대한민국 경상남도 거제시 장목면 장목리 248-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신도선착장 무료주차장', '신도·시도·모도 섬 라이딩의 출발점인 신도선착장 무료 주차장입니다. 여객터미널(신도바다역)이 있어 화장실 등 편의시설 이용이 편리합니다.', '{parking,transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.439249, 37.515166), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["신도선착장", "신도바다역"], "confidence": "high", "address": "대한민국 인천광역시 옹진군 북도면 신도리 523-58"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('원통 공영주차장', '강원도 인제군 원통리에 위치한 공영 주차장입니다. 전기차 충전소가 있으며, 한계령이나 미시령 방면 라이딩을 위한 차량 주차 및 출발지(점프 포인트)로 활용하기 좋습니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.219597, 38.128356), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["원통버스터미널", "원통전통시장", "북천"], "confidence": "high", "address": "대한민국 강원특별자치도 인제군 북면 원통리 1650-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('주차장', '이키섬 우쓰미만(内海湾) 인근에 위치한 주차장입니다. 주변에 굴 구이 식당 등이 있어 라이딩 중 식사나 휴식을 위해 자전거를 정차하기 좋습니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.76369, 33.782151), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["우쓰미만(内海湾)", "카키하우스 우쓰미만"], "confidence": "high", "address": "109 Ashibecho Moroyoshiminamifure, Iki, Nagasaki 811-5315 일본"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('인월우체국 공영주차장', '남원인월우체국 및 식당가 앞에 위치한 주차장입니다. 지리산 라이딩의 출발점이나 식사를 위한 휴식처로 활용하기 좋습니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.601206, 35.462298), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["남원인월우체국", "인월버스터미널", "지리산둘레길 인월센터"], "confidence": "high", "address": "대한민국 전북특별자치도 남원시 인월면 서무리 698-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('지족어촌관광단지 주차장', '남해안 자전거길 코스에 위치한 지족어촌관광단지(죽방렴 홍보관) 주차장입니다. 공중화장실이 있어 라이딩 중 자전거를 세우고 휴식하기 좋습니다.', '{parking,restroom,rest_area,museum}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.994958, 34.831231), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["지족어촌관광단지", "죽방렴홍보관"], "confidence": "high", "address": "대한민국 경상남도 남해군 삼동면 죽방로 69"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('거제스포츠파크 주차장', '거제스포츠파크와 거제식물원(정글돔) 인근 주차장입니다. 평탄하고 경치가 좋아 자전거 타기 좋은 ''서정리 무지개길'' 라이딩의 출발점으로 추천합니다.', '{parking,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.581285, 34.852251), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["거제스포츠파크", "거제식물원(정글돔)", "서정리 무지개길"], "confidence": "high", "address": "대한민국 경상남도 거제시 거제면 서정리 823-12"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('임고서원 주차장', '영천 임고서원 입구에 위치한 넓고 쾌적한 무료 주차장입니다. 관리가 잘 된 화장실이 있어 라이딩 출발지나 중간 휴식처로 활용하기 좋습니다.', '{parking,restroom,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.973177, 36.017378), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["임고서원", "선죽교", "조옹대", "임고강변공원"], "confidence": "high", "address": "대한민국 경상북도 영천시 임고면 양항리 799"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('진안읍 군하리 공영주차장', '진안읍 군하리에 위치한 주차장으로, 자전거 라이딩 전 차량 주차 및 출발지(점프)로 활용하기 좋은 장소입니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.425801, 35.787835), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["진안읍내", "마이산 진입로"], "confidence": "medium", "address": "대한민국 전북특별자치도 진안군 진안읍 군하리 238"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('마이산 북부 공영주차장', '마이산 도립공원 북부 진입로에 위치한 대형 공영 주차장입니다. 화장실이 구비되어 있어 마이산이나 산약초타운 방면 라이딩 전후 휴식 및 정비 장소로 유용합니다.', '{parking,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.418939, 35.776035), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["마이산", "마이산 탑사", "산약초타운", "사양제"], "confidence": "high", "address": "대한민국 전북특별자치도 진안군 진안읍 단양리 831"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('주차장', '안동시 옥동 상업지구에 위치한 주차장입니다. 차량으로 자전거를 싣고 와서 라이딩을 시작하거나 주변 편의시설을 이용할 때 활용하기 좋습니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.700332, 36.566739), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["옥동 상업지구"], "confidence": "high", "address": "대한민국 경상북도 안동시 옥동 734-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('앵강공원 주차장', '남해 앵강고개 정상에 위치한 앵강공원 주차장입니다. 업힐 후 숨을 고르기 좋으며, 화장실과 넓은 휴식 공간이 있어 라이더들이 쉬어가기 적합합니다.', '{parking,rest_area,restroom,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.962523, 34.783762), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["앵강고개", "앵강공원", "호구산"], "confidence": "high", "address": "대한민국 경상남도 남해군 이동면 무림리 산165"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('노량주차장', '남해안 자전거길의 주요 기종점인 노량주차장입니다. 남해대교 인근에 위치하여 라이딩 전후 차량 주차 및 휴식을 취하기 좋습니다.', '{parking,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.875279, 34.939728), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["남해대교", "한려해상국립공원 노량분소", "노량공원"], "confidence": "high", "address": "대한민국 경상남도 남해군 설천면 노량리 410-49"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('정관박물관 주차장', '부산 기장군 정관박물관의 무료 주차장입니다. 좌광천 자전거길이나 정관신도시 일대 라이딩을 시작하기 좋은 출발지입니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.181779, 35.326689), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["정관박물관", "좌광천"], "confidence": "high", "address": "대한민국 부산광역시 정관박물관"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('상대온천 주차장', '경산 상대온천 바로 옆에 위치한 주차장입니다. 온천 방문은 물론 주변 자전거 코스나 삼성산 등산 시 출발점 및 휴식처로 활용하기 좋습니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.792979, 35.78045), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["상대온천", "삼성산"], "confidence": "high", "address": "대한민국 경상북도 경산시 남산면 상대리 585"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('노현리 생태습지공원 주차장', '대청호 오백리길 19, 20구간이 만나는 노현리 생태습지공원 주차장입니다. 대청호반과 아름다운 습지 풍경을 감상하며 라이딩 출발지나 휴식처로 활용하기 좋습니다.', '{parking,park,nature,rest_area,lake}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.525076, 36.513876), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["노현리 생태습지공원", "대청호", "대청호 오백리길"], "confidence": "high", "address": "대한민국 충청북도 청주시 상당구 문의면 노현리 616-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('생명누리공원 주차장', '청주 밀레니엄타운 생명누리공원 인근 주차장입니다. 무심천 자전거길과 가까워 차량을 주차하고 라이딩을 시작하는 거점으로 활용하기 좋습니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.478007, 36.682808), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["생명누리공원", "청주밀레니엄타운", "무심천"], "confidence": "high", "address": "대한민국 충청북도 청주시 청원구 정상동 1-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('주차장', '거제 일운면 소동리 인근의 주차장으로, 지세포 해안도로 라이딩 전후 서포트카 주차나 그룹 라이딩 집결지로 활용하기 무난한 공간입니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.701723, 34.843133), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["소노캄 거제", "지세포항", "거제씨월드"], "confidence": "medium", "address": "대한민국 경상남도 거제시 일운면 소동리 62"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('지리산 치즈랜드 주차장', '지리산 치즈랜드와 구만저수지 입구에 위치한 넓은 무료 주차장입니다. 화장실과 벤치 등 편의시설이 있어 라이딩 중 경치를 보며 쉬어가기 좋습니다.', '{parking,rest_area,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.425489, 35.278813), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["지리산 치즈랜드", "구만저수지", "지리산호수공원"], "confidence": "high", "address": "대한민국 전라남도 구례군 산동면 이평리 산31-12"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('죽정지구 공영주차장', '보령시 죽정동에 위치한 죽정지구 공영주차장입니다. 라이딩 시작 전 차량을 주차하거나 주변 상가를 이용할 때 베이스캠프로 활용하기 좋습니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.599386, 36.360118), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["봉황산", "대천천"], "confidence": "high", "address": "대한민국 충청남도 보령시 봉황로 73"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('반디행복누리플랫폼 주차장', '무주 반딧불시장 옆에 위치한 복합 주차장(반디행복누리플랫폼)입니다. 화장실과 공공라운지 등 편의시설이 잘 갖춰져 있어 라이딩 중 쾌적하게 휴식하기 좋습니다.', '{parking,restroom,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.652845, 36.004309), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["무주 반딧불시장", "남대천"], "confidence": "high", "address": "대한민국 전북특별자치도 무주군 무주읍 읍내리 1230-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('합천창녕보 주차장', '낙동강 종주 자전거길 합천창녕보 인근 주차장입니다. 차량을 주차하고 라이딩을 시작하거나 중간에 휴식하기 좋은 거점입니다.', '{parking,rest_area,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.361922, 35.590954), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["합천창녕보", "낙동강 종주 자전거길", "합천창녕보 인증센터"], "confidence": "high", "address": "대한민국 경상남도 창녕군 이방면 등림리 644-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('주차장', '새재자전거길 영강 구간 인근에 위치한 주차장입니다. 자전거 여행 전후로 차량을 주차하거나 라이딩 중 잠시 휴식하기 좋습니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.15836, 36.650977), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["새재자전거길", "영강", "별암교"], "confidence": "medium", "address": "대한민국 경상북도 문경시 호계면 견탄리 산29-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남한강 자전거길 충주댐 구간 주차장', '남한강 자전거길 충주댐 구간 진입로 인근에 위치한 주차장입니다. 차량을 주차하고 바로 자전거길로 나설 수 있어 라이딩 출발지로 적합합니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.938329, 37.017998), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["남한강 자전거길", "목행교", "가리근린공원"], "confidence": "high", "address": "대한민국 충청북도 충주시 용탄동 1126-11"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('주차장', '정선군 사북읍 직전리 산간에 위치한 주차장입니다. 인근 계곡이나 산악 코스 라이딩을 위한 차량 주차 및 출발지로 활용하기 적합합니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.798483, 37.228638), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["직전리 계곡"], "confidence": "medium", "address": "대한민국 강원특별자치도 정선군 사북읍 직전리 산282-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('주촌1제', '지리산 정령치 업힐(고기리 방향) 초입에 위치한 조용한 저수지입니다. 본격적인 업힐을 시작하기 전 호흡을 가다듬으며 풍경을 감상하기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.506393, 35.392846), 4326), false, '{"source": "KOMOOT", "source_ids": ["394"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["정령치", "고기교", "남원백두대간생태교육장전시관"], "confidence": "high", "address": "대한민국 전북특별자치도 남원시 운봉읍 주촌리 산52-11"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('오리엔트커피', '1층에 로스터리 카페(오리엔트커피)가 있는 도안신도시 내 상가주택입니다. 라이딩 중 커피와 디저트를 즐기며 쉬어가기 좋습니다.', '{cafe,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.350699, 36.314352), 4326), false, '{"source": "KOMOOT", "source_ids": ["301"], "category_raw": "17", "tour_count": 1, "nearby_landmarks": ["오리엔트커피", "도안신도시"], "confidence": "high", "address": "대한민국 대전광역시 서구 도안동 1439"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('죽녹원', '영산강 자전거길에 위치한 담양의 대표적인 대나무 숲 랜드마크입니다. 내부 자전거 진입은 불가하므로 입구에 주차 후 도보로 둘러보며 휴식하기 좋습니다.', '{nature,landmark,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.98633, 35.325151), 4326), false, '{"source": "KOMOOT", "source_ids": ["665"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/mq/mqhsbuti1e9d10r41mwyyz27h3xg037q3-uhi42420369/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/fq/fq6ki3wnjruz19tv85vcxepft3xg037rc-uhi42420370/0?width=1920&crop=false"], "category_raw": "forest", "tour_count": 1, "nearby_landmarks": ["관방제림", "담양 국수거리", "메타세쿼이아길"], "confidence": "high", "address": "대한민국 전라남도 담양군 담양읍 향교리 산37-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('죽서루', '관동팔경 중 하나로 오십천 절벽 위에 자리한 역사적인 누각입니다. 오십천 자전거길 라이딩 중 멋진 경치를 감상하며 쉬어가기 좋은 명소입니다.', '{historic,landmark,viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.161158, 37.441298), 4326), false, '{"source": "KOMOOT", "source_ids": ["2686"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["오십천", "삼척 장미공원"], "confidence": "high", "address": "대한민국 강원특별자치도 삼척시 성내동 9-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('죽전역', '탄천 자전거길과 바로 연결되는 수인분당선 전철역입니다. 라이딩 출발 및 종료 지점이나 지하철 점프 포인트로 활용하기 좋습니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.107348, 37.324733), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/a/a7/Jukjeonstation01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a6/Q17226_Jukjeon_A01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/87/Korail-Bundang-line-K233-Jukjeon-station-platform-20181127-120354.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b6/Korail-Bundang-line-K233-Jukjeon-station-entrance-1-20181127-120840.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d0/Jukjeonstation06.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["탄천 자전거길", "신세계백화점 경기점", "이마트 죽전점"], "confidence": "high", "address": "대한민국 경기도 용인시 수지구 죽전동 1288"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('죽천제', '보성군 용문리에 위치한 조용한 저수지(죽천제)입니다. 한적한 시골길 라이딩 중 잔잔한 수변 풍경을 감상하며 잠시 쉬어가기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.079984, 34.782945), 4326), false, '{"source": "KOMOOT", "source_ids": ["1184"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["보성읍", "용문리"], "confidence": "high", "address": "대한민국 전라남도 보성군 보성읍 용문리 산29-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('중리어울림아파트', '낙동강 자전거길 인근 칠곡군 석적읍의 아파트 단지입니다. 라이딩 중 길 찾기 기준점이나 주변 편의시설을 찾기 위한 경유지로 참고하기 좋습니다.', '{landmark,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.407266, 36.076028), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["중리2교", "낙동강 자전거길"], "confidence": "high", "address": "대한민국 칠곡군 중리2교건너"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('중리저수지', '동탄 치동천 자전거길이 이어지는 저수지입니다. 현재 풀무골 수변공원으로 조성 중이며 무봉산, 만의사 방면 라이딩의 주요 기점입니다.', '{lake,park,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.13685, 37.204248), 4326), false, '{"source": "KOMOOT", "source_ids": ["80"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["무봉산", "만의사", "치동천", "카페인중리"], "confidence": "high", "address": "대한민국 경기도 화성시 중동 234-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('중앙상가 주차장', '전민동 엑스포아파트 단지 내 상가 주차장입니다. 갑천 자전거길 진입 전 편의점이나 화장실을 이용하며 잠시 쉬어가기 좋습니다.', '{parking,convenience_store,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.406623, 36.400143), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["엑스포아파트", "갑천 자전거길", "엑스포근린공원"], "confidence": "high", "address": "대한민국 대전광역시 유성구 전민동 464-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('중전리', '충북 제천시 금성면의 한적한 시골 마을입니다. 인근에 충북유형문화재인 중전리 고가와 파크골프장이 있어 라이딩 중 가볍게 둘러보며 쉬어가기 좋습니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.187371, 37.057636), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["중전리 고가", "제천 중전 파크골프장"], "confidence": "high", "address": "대한민국 제천시 중전"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('중천이물', '과거 상명리 주민들의 식수원이었던 연못으로, 200년 된 팽나무 그늘이 있는 생태 쉼터입니다. 한적한 중산간 라이딩 중 잠시 땀을 식히며 쉬어가기 좋습니다.', '{rest_area,nature,historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.272475, 33.357979), 4326), false, '{"source": "KOMOOT", "source_ids": ["663"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["200년 수령 팽나무(보호수)", "상명리 마을"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 한림읍 상명리 1030"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('소사벌 중흥S클래스·호반베르디움 정류장', '평택 소사벌지구 중흥S클래스 및 호반베르디움 아파트 단지 앞 버스 정류장입니다. 라이딩 중 위치 기준점이나 대중교통 점프 지점으로 참고할 수 있습니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.111803, 37.007458), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["중흥S클래스 아파트", "호반베르디움 아파트", "소사벌지구"], "confidence": "high", "address": "대한민국 평택시 중흥S클래스.호반베르디움"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('증평역', '충북선 증평역으로, 에코레일 자전거 열차 투어의 주요 거점입니다. 삼기저수지나 좌구산 MTB 코스 등 증평 지역 라이딩의 출발지로 활용하기 좋습니다.', '{transit,restroom,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.583665, 36.778321), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["증평자전거공원", "보강천 미루나무숲", "삼기저수지"], "confidence": "high", "address": "대한민국 충청북도 증평군 증평읍 신동리 640"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('지게골역', '부산 도시철도 2호선 지게골역입니다. 4번 출구에 자전거 보관소가 마련되어 있으며, 라이딩 중 화장실 이용이나 주말 지하철 점프 등 대중교통 연계 거점으로 좋습니다.', '{transit,parking,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.07422, 35.135662), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/8/8c/215jigegol.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e8/Jigegol_station_sign_Busan_metro_line_2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/14/Busan-subway-215-Jigegol-station-1-entrance.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/47/Jigegol_Station_nameplate.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6c/Busan_subway_jigegol_station_1.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["문현성당", "대양고등학교", "대연고개"], "confidence": "high", "address": "대한민국 부산광역시 남구 문현동 254-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('지곡저수지', '업힐과 다운힐이 어우러진 숲길 라이딩을 즐길 수 있는 한적한 저수지입니다. 인근에 카페와 식당이 있어 코스 중 휴식하기 좋습니다.', '{lake,nature,cafe,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.135139, 37.231347), 4326), false, '{"source": "KOMOOT", "source_ids": ["342"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["지곡낚시터", "한국민속촌", "보라산"], "confidence": "high", "address": "대한민국 경기도 용인시 기흥구 지곡동 71"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('지산저수지', '천안 목천읍에 위치한 조용한 저수지(지산저수지)입니다. 한적한 수변 경치를 감상하며 라이딩 중 가볍게 지나치기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.192635, 36.793239), 4326), false, '{"source": "KOMOOT", "source_ids": ["72"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["독립기념관"], "confidence": "high", "address": "대한민국 충청남도 천안시 동남구 목천읍 지산리 162-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('지선저수지', '순창군 복흥면 지선리에 위치한 조용한 소규모 저수지입니다. 한적한 시골길 라이딩 중 잔잔한 물가 풍경을 감상하며 잠시 쉬어가기 좋습니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.905138, 35.436232), 4326), false, '{"source": "KOMOOT", "source_ids": ["515"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["지선마을"], "confidence": "high", "address": "대한민국 전북특별자치도 순창군 복흥면 지선리 272-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('대금산 진달래군락지', '거제 대금산 정상 부근의 진달래 군락지입니다. 봄철 화려한 진달래와 남해 바다 조망이 일품이며, 임도를 따라 오르는 업힐 라이딩 코스로 인기가 높습니다.', '{mountain,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.700188, 34.952584), 4326), false, '{"source": "KOMOOT", "source_ids": ["1120"], "category_raw": "191", "tour_count": 1, "nearby_landmarks": ["대금산", "반깨고개"], "confidence": "high", "address": "대한민국 경상남도 거제시 연초면 명동리"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('진등산', '대니산과 이어지는 임도 코스가 있어 그래블이나 MTB 라이딩에 적합한 해발 282m의 산입니다. 낙동강의 수려한 조망을 즐길 수 있으며 인근에 도동서원이 있습니다.', '{mountain,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.366257, 35.69399), 4326), false, '{"source": "KOMOOT", "source_ids": ["284"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["도동서원", "대니산", "낙동강"], "confidence": "high", "address": "대한민국 대구광역시 달성군 구지면 도동리 산35-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('진미동행정복지센터앞', '진미동행정복지센터 앞 버스정류장입니다. 평일 주간에는 복지센터 내 개방된 화장실과 정수기를 이용하며 잠시 쉬어가기 좋습니다.', '{transit,restroom,water_fountain,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.418901, 36.105809), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["진미동행정복지센터", "도레이첨단소재 1공장"], "confidence": "high", "address": "대한민국 구미시 진미동행정복지센터건너"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('KTX 진부역', '오대산, 대관령 등 평창 지역 라이딩의 주요 출발점이자 복귀점인 KTX 진부역입니다. 자전거 점프(대중교통 연계) 및 화장실, 편의점 이용이 가능합니다.', '{transit,restroom,convenience_store,parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.574269, 37.642744), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/7/76/Jinbu_(Odaesan)_Station.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["오대산", "월정사", "대관령"], "confidence": "high", "address": "대한민국 강원특별자치도 평창군 진부면 송정리 1383-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('진산리갯돌해변', '청산도 슬로길 8코스에 위치한 몽돌해변입니다. 파도와 갯돌이 부딪히는 경쾌한 소리를 들으며 해안가 힐링 라이딩을 즐기기 좋습니다.', '{beach,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.903364, 34.202794), 4326), false, '{"source": "KOMOOT", "source_ids": ["240"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["청산도 슬로길", "상서돌담마을", "범바위"], "confidence": "high", "address": "대한민국 전라남도 완도군 청산면 청산로 952"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('진해내수면환경생태공원', '여좌천 벚꽃길 인근에 위치한 생태공원입니다. 저수지를 품은 아름다운 자연 경관을 감상하며 라이딩 중 잠시 자전거를 세워두고 산책과 휴식을 취하기 좋습니다.', '{park,nature,lake,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.660288, 35.162237), 4326), false, '{"source": "KOMOOT", "source_ids": ["551"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["여좌천", "진해역"], "confidence": "high", "address": "대한민국 경상남도 창원시 진해구 여좌동 6-15"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('진해루', '진해 앞바다의 탁 트인 풍경을 감상할 수 있는 해변공원 누각입니다. 평탄한 해안 자전거길이 이어져 라이딩 중 휴식하기 좋고 편의시설이 잘 갖춰져 있습니다.', '{landmark,viewpoint,park,rest_area,beach,convenience_store,cafe,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.683768, 35.147382), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["거북선 놀이터", "한주호 준위 동상", "해양레포츠센터"], "confidence": "high", "address": "대한민국 창원시 진해루"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('창원 성산 패총', '철기시대 조개더미 유적과 유물전시관이 있는 역사 공원입니다. 봄철 벚꽃이 아름다워 라이딩 중 한적하게 역사 탐방과 휴식을 즐기기 좋습니다.', '{historic,museum,park,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.679796, 35.208344), 4326), false, '{"source": "KOMOOT", "source_ids": ["670"], "image_urls": ["https://photos.komoot.de/wiki/commons/5/5b/%EC%B0%BD%EC%9B%90_%EC%84%B1%EC%82%B0_%ED%8C%A8%EC%B4%9D.jpg?width=1920&crop=false"], "category_raw": "191", "tour_count": 1, "nearby_landmarks": ["성산패총유물전시관", "야철지", "용화전 석조여래좌상"], "confidence": "high", "address": "대한민국 경상남도 창원시 성산구 외동 853-7"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('채석강', '부안 해안 자전거길의 대표 명소로, 수만 권의 책을 쌓은 듯한 해안 절벽과 노을이 장관입니다. 자전거는 격포항 등에 세워두고 도보로 해식동굴과 절경을 감상하기 좋습니다.', '{viewpoint,nature,beach,landmark,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.468143, 35.626966), 4326), false, '{"source": "KOMOOT", "source_ids": ["354"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["격포해수욕장", "격포항", "적벽강"], "confidence": "high", "address": "대한민국 전북특별자치도 부안군 변산면 격포리 290-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('척동네거리', '전주 서부신시가지와 전주대학교 인근에 위치한 교차로입니다. 도심 라이딩을 하거나 삼천 자전거길로 이동할 때 거쳐 가는 무난한 길목입니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.098469, 35.824535), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["전주대학교", "신시가지서부파출소", "삼천 자전거길"], "confidence": "high", "address": "대한민국 전북특별자치도 전주시 완산구 척동9길 9-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('천마산', '남양주에 위치한 해발 812m의 산입니다. 가곡리 임도 등 산악자전거(MTB) 라이더들이 즐겨 찾는 다이내믹한 업힐과 다운힐 코스가 있습니다.', '{mountain,nature,viewpoint,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.285016, 37.659294), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/a/ab/천마산_역사.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/62/천마산역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/35/천마산역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/83/천마산역_선로측_역사.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/14/Cheonmasan_Station_20131130_111711.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["천마산역", "천마산군립공원"], "confidence": "high", "address": "대한민국 경기도 남양주시 화도읍 묵현리 320-57"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('천안역', '수도권 전철 1호선과 기차를 이용해 자전거 점프가 가능한 천안역입니다. 라이딩 출발 및 도착지로 적합하며 화장실, 편의점 등 각종 편의시설이 잘 갖춰져 있습니다.', '{transit,convenience_store,restroom,cafe,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.147495, 36.810215), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/1/12/Korail_Cheonan_Stn.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3b/Cheonan_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/b2/Korail_Cheonan_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/7e/20240826_천안역_승강장(광운대_방면).jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/78/Q54298_Cheonan_A04.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["천안역 광장", "천안역 지하상가"], "confidence": "high", "address": "대한민국 충청남도 천안시 동남구 대흥동 57-52"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('KTX 아산역', 'KTX와 1호선 환승이 가능한 대형 철도역입니다. 대규모 자전거 주차장이 있으며, 수도권 전철을 이용한 점프(자전거 휴대 승차) 거점으로 유용합니다.', '{transit,parking,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.104071, 36.794266), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/7/7a/천안아산역-20200607_193909x1800.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/29/Cheonan_Asan_Station_sign.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/4e/Chonan-Asan_station_in_SRT.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/ac/20211209_아산역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/ea/아산역--20200607_160955.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["아산역", "장재천 호수공원", "곡교천 자전거길"], "confidence": "high", "address": "대한민국 충청남도 아산시 배방읍 장재리 874-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('천지연낚시터', '남양주 와부읍 고래산로에 위치한 낚시터입니다. 고래산, 먹치고개 등 주변 산악 코스를 라이딩할 때 길잡이가 되는 랜드마크로 참고하기 좋습니다.', '{landmark,lake,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.287858, 37.599179), 4326), false, '{"source": "KOMOOT", "source_ids": ["398"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["고래산", "먹치고개", "월문낚시터"], "confidence": "high", "address": "대한민국 경기도 남양주시 와부읍 월문리 1306-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('천진해수욕장입구', '동해안 자전거길이 지나는 천진해변의 입구이자 버스 정류장입니다. 청간정에서 봉포해변으로 이어지는 길목에 위치하며, 주변에 카페와 편의시설이 있어 라이딩 중 쉬어가기 좋습니다.', '{beach,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.559899, 38.256864), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["천진해수욕장", "청간정", "봉포해변"], "confidence": "high", "address": "대한민국 강원특별자치도 고성군 토성면 천진리 179-107"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('천호 자전거 거리', '자전거 용품점, 의류 매장, 정비소 등이 밀집해 있는 국내 대표적인 자전거 특화 거리입니다. 한강 자전거길과 가까워 라이더들의 만남의 장소이자 성지로 불립니다.', '{bike_shop,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.123423, 37.538562), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/c/c8/Seoul-metro-Cheonho-station-entrance-7-20180914-132434.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/64/Seoul-metro-547-Cheonho-station-sign-20180914-131928.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/03/20240810_8호선_천호역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/99/20240810_8호선_천호역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/ba/Cheonho_Station.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["천호동공원", "광나루 한강공원", "즈믄길 나들목"], "confidence": "high", "address": "대한민국 서울특별시 강동구 올림픽로"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('첫마을4단지', '금강종주자전거길과 인접한 세종시 한솔동의 아파트 단지입니다. 자전거도로 진출입이 용이하여 라이딩의 출발지나 가벼운 경유지로 활용하기 좋습니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.251623, 36.480149), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["금강종주자전거길", "한두리대교", "한솔동 백제고분군"], "confidence": "high", "address": "대한민국 세종특별자치시 첫마을4단지"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('청도 아리아 펜션', '청도 프로방스, 소싸움 경기장, 용암온천 등 주요 관광지와 인접한 숙소입니다. 주변에 식당과 카페가 많아 장거리 라이딩 후 휴식하며 머물기 좋습니다.', '{other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.717501, 35.689021), 4326), false, '{"source": "KOMOOT", "source_ids": ["479"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/on/on611t7ccuy6iqhbra8tw0fl54s0sq9g-uhi79002292/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/9h/9hufpwmr95gm1mbk9r9zgsrt054s193ig-uhi79002669/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/mg/mgtxv7oxdta414uaawh6y2njy54s8vpv1-uhi79014362/0?width=1920&crop=false"], "tips": [{"text": "Great place to stay! All sorts of interesting things nearby, Bull fighting, light show, spa baths etc. Lots of restaurants and cafes", "author": ""}], "category_raw": "facilities", "tour_count": 1, "nearby_landmarks": ["청도 프로방스", "청도 소싸움 경기장", "청도 용암온천"], "confidence": "high", "address": "대한민국 경상북도 청도군 화양읍 삼신리 918-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('청라국제도시역', '공항철도 청라국제도시역입니다. 아라자전거길과 인접해 있어 라이더들이 대중교통 연계(점프)나 만남의 장소로 유용하게 활용하는 주요 교통 거점입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.624938, 37.555886), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/8/84/Cheongna_International_City_Station.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/cd/청라국제도시역_역사.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c6/Cheongna_International_City_Station_20220701_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/7c/청라국제도시역_통로.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/6/6e/청라국제도시역_승강장.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["아라자전거길", "정서진", "베어즈베스트청라GC"], "confidence": "high", "address": "대한민국 인천광역시 서구 청라동 3-46"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('청량리역', '청량리역 앞 왕산로 부근의 웨이포인트입니다. 차량 통행과 유동인구가 매우 많은 복잡한 도심 구간이므로 안전 라이딩에 각별한 주의가 필요합니다.', '{checkpoint,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.044636, 37.57996), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/9/9c/Aboveground_Cheongnyangni_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8e/Seoul_Subway_1_Cheongnyangni_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c1/Korail-Cheongnyangni-station-building-20191023-105204.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f5/Seoul-metro-124-Cheongnyangni-station-entrance-5-20191023-105756.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/55/20201017_청량리역.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["청량리역", "청량리시장"], "confidence": "high", "address": "대한민국 서울특별시 동대문구 왕산로 194 3-4층"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('청룡소류지', '밀양 만어산 임도 MTB 라이딩 코스의 주요 기종점 역할을 하는 작은 저수지입니다. 본격적인 업힐 전후로 한적한 경관을 보며 숨을 고르기 좋습니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.810618, 35.442795), 4326), false, '{"source": "KOMOOT", "source_ids": ["778"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["만어산", "솔태고개", "청룡마을"], "confidence": "high", "address": "대한민국 경상남도 밀양시 삼랑진읍 용성리 87-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('청룡저수지', '수려한 경관을 자랑하는 안성의 계곡형 저수지입니다. 서운산과 청룡사 인근에 위치해 자연을 만끽하며 라이딩하기 좋은 코스입니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.280608, 36.905718), 4326), false, '{"source": "KOMOOT", "source_ids": ["346"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["청룡사", "서운산", "바우덕이 묘"], "confidence": "high", "address": "대한민국 안성시 서운면 청용리 산1-16번지 1층 안성시 경기도 KR"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('청산도항', '아시아 최초 슬로시티 청산도 자전거 여행의 출발점이자 종착지인 항구입니다. 완도항에서 배를 타고 도착해 서편제 촬영지 등 아름다운 섬 라이딩을 시작하기 좋습니다.', '{transit,landmark,restroom,convenience_store,restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.854142, 34.181083), 4326), false, '{"source": "KOMOOT", "category_raw": "47", "tour_count": 1, "nearby_landmarks": ["서편제 촬영지", "범바위", "상서마을 돌담길", "구들장논"], "confidence": "high", "address": "대한민국 전라남도 완도군 청산면 도청리 930-34"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남천교(청연루)', '전주천 자전거길과 연결된 남천교 위의 전통 누각입니다. 한옥마을 라이딩 중 시원한 바람을 맞으며 탁 트인 경치를 감상하고 쉬어가기 좋은 랜드마크입니다.', '{bridge,rest_area,landmark,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.153105, 35.811065), 4326), false, '{"source": "KOMOOT", "source_ids": ["1156"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1a/1ai5rdat8z3y923991c2xmr7v30ymqp4l-uhi6554266/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/c7/c7b4crauxr5tyi5k1giw2ek130ymqsr9-uhi6554267/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/w4/w4hwaizv9agb1g4ffs2majjsk30ymqty1-uhi6554268/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 1, "nearby_landmarks": ["전주한옥마을", "전주천", "전주향교"], "confidence": "high", "address": "대한민국 전북특별자치도 전주시 완산구 교동 192-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('청주역', '무심천과 대청댐 방면 라이딩 출발지로 적합한 기차역입니다. 자전거 보관소와 화장실, 대합실 등 휴식 시설을 갖추고 있습니다.', '{transit,restroom,parking,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.392946, 36.64692), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/b/bd/Cheongjustation.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f2/Korail_Chungbuk_Line_Cheongju_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/f3/20211220_청주역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/cc/20211220_청주역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/97/1973년_10월_26일_청주역.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["무심천", "정북동 토성"], "confidence": "high", "address": "대한민국 청주시 청주역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('청주남부정류장', '무심천 자전거길과 인접해 있어 라이더들이 상주, 대전 등 남부 지역으로 점프할 때 유용한 시외버스 정류장입니다. 가경동 터미널까지 갈 필요가 없어 편리합니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.479788, 36.608509), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["충청북도교육청", "무심천", "청주교육대학교"], "confidence": "high", "address": "대한민국 충청북도 청주시 서원구 분평동 394-15"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('청천천', '굴포천으로 이어지는 도심 하천으로, 하천을 따라 자전거 도로와 산책로가 잘 조성되어 있어 안전하고 쾌적한 라이딩이 가능합니다.', '{river,nature,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.728114, 37.514096), 4326), false, '{"source": "KOMOOT", "source_ids": ["1137"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["굴포천", "한국GM 부평공장"], "confidence": "high", "address": "대한민국 인천광역시 부평구 갈산동 243-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('청평역', '북한강 자전거길 접근성이 뛰어나 라이딩 시작이나 복귀 시 전철 점프(대중교통 연계) 거점으로 활용하기 좋은 경춘선 청평역입니다.', '{transit,restroom,convenience_store}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.426395, 37.735395), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/d/de/Cheongpyeong_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/17/New_Cheongpyeong_Station.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/7c/Q49972_Cheongpyeong_A01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9f/청평역.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/d8/Elevator_of_Cheongpyeong_Station.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["북한강 자전거길", "조종천", "호명산"], "confidence": "high", "address": "대한민국 경기도 가평군 청평면 청평리 125-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('초당순두부마을', '강릉의 대표적인 먹거리 촌으로, 동해안 자전거길 라이딩 중 든든한 식사(보급)를 하기에 매우 좋은 장소입니다.', '{restaurant,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.915506, 37.791154), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["경포호", "강문해변", "허균·허난설헌 기념공원"], "confidence": "high", "address": "대한민국 강릉시 초당순두부마을"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('초월역', '경강선 전철을 이용하여 자전거 점프(이동)가 가능한 대중교통 거점입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.299904, 37.373028), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/2/2b/Chowol_Station_Panorama.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/85/Chowol_Station_Exit_2.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/86/Chowol_stn_1.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/20/Chowol_Station.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["초월롯데캐슬아파트", "곤지암천"], "confidence": "high", "address": "대한민국 광주시 초월역.롯데아파트"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('초장동행정복지센터', '라이딩 중 공중화장실을 이용하거나 식수를 보충하기 좋은 지역 행정복지센터입니다. 일행과 만나거나 안전하게 휴식을 취하는 거점으로 활용할 수 있습니다.', '{landmark,restroom,water_fountain}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.115962, 35.203825), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["초전푸르지오", "장대산"], "confidence": "high", "address": "대한민국 경상남도 진주시 초장동 1009-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('초지대교', '김포와 강화도를 연결하는 주요 교량으로, 강화도 자전거 라이딩 코스로 진입하기 위한 필수 관문이자 랜드마크입니다.', '{bridge,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.531466, 37.62695), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["대명항", "초지진", "강화도"], "confidence": "high", "address": "대한민국 인천광역시 초지대교"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('초지진', '강화도 해안도로 라이딩 코스의 주요 진입 거점이자 역사적 명소로, 초지대교를 건너면 바로 만날 수 있어 라이더들의 휴식처 및 랜드마크로 유용합니다.', '{historic,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.531661, 37.63235), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["초지대교", "황산도", "강화해협"], "confidence": "high", "address": "대한민국 인천광역시 초지진"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('이수역', '지하철 4호선과 7호선이 교차하는 환승역으로, 주말 자전거 점프(지하철 탑승)나 도심 라이딩 모임 장소로 활용하기 좋은 교통 거점입니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.982145, 37.486781), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/2/23/Isusta.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/34/총신대입구_(4)_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/31/736_Isu_02.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0a/Seoul-metro-432-Chongshin-university-station-sign-20191022-160728.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/85/Seoul-metro-432-Chongshin-university-station-entrance-02-20191022-161758.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["사당역", "반포천", "방배카페골목"], "confidence": "high", "address": "대한민국 서울특별시 총신대입구(이수)"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('춘당매', '거제 구조라초등학교 폐교 터에 있는 매화나무로, 전국에서 가장 먼저 꽃을 피우는 것으로 유명해 라이딩 중 들러 경관을 감상하고 사진을 남기기 좋은 명소입니다.', '{landmark,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.695589, 34.807374), 4326), false, '{"source": "KOMOOT", "source_ids": ["147"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["구조라해수욕장", "구조라초등학교(폐교)"], "confidence": "high", "address": "대한민국 경상남도 거제시 일운면 구조라리 48-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('비내섬 맛집', '남한강 자전거길 비내섬 및 오대호아트팩토리 인근에 위치한 식당으로, 라이딩 중 식사와 휴식을 취하기 좋은 보급처입니다.', '{restaurant}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.79402, 37.094891), 4326), false, '{"source": "KOMOOT", "source_ids": ["15"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/5g/5g46t66eg9x11czbx326bwzlo50y9kj85-uhi74283616/0?width=1920&crop=false"], "tips": [{"text": "I also had dinner at this place and it was delicious.", "author": "Sylvain"}], "category_raw": "restaurant", "tour_count": 1, "nearby_landmarks": ["오대호아트팩토리", "비내섬", "앙성탄산온천"], "confidence": "high", "address": "대한민국 충청북도 충주시 앙성면 돈산리 11-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('목포 영산강 자전거터미널', '영산강 자전거길 종주 코스 하류에 위치한 주요 랜드마크로, 인근에 자전거 무상수리와 휴식이 가능한 자전거 터미널이 조성되어 있습니다.', '{landmark,river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.441188, 34.803204), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["영산강 자전거길", "영산강 하구둑", "자전거터미널"], "confidence": "high", "address": "대한민국 목포시 카누경기장"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('칼산', '남한강 자전거길 양평 구간에 위치한 산으로, 강변을 따라 뻗은 벚꽃길과 인접한 갈산공원이 있어 라이더들에게 아름다운 경관을 제공하는 랜드마크입니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.492359, 37.485723), 4326), false, '{"source": "KOMOOT", "source_ids": ["51"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["남한강 자전거길", "갈산공원", "양평군립미술관"], "confidence": "high", "address": "대한민국 경기도 양평군 양평읍 창대리 산26-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('캠프 험프리스 커미서리 (출입제한)', '평택 미군기지(캠프 험프리스) 내에 위치한 미군 전용 마트입니다. 일반 자전거 라이더는 출입할 수 없는 통제구역이므로 우회해야 합니다.', '{convenience_store,other}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.002988, 36.963769), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["캠프 험프리스", "안성천"], "confidence": "high", "address": "대한민국 경기도 평택시 팽성읍 도두리 30-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('킨텍스', '일산의 대표적인 대형 전시장이자 랜드마크로, 파주나 평화누리길 방면 라이딩 시 길잡이 및 만남의 장소로 유용합니다. 주변에 넓은 광장과 편의시설이 있어 휴식하기 좋습니다.', '{landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.748322, 37.665208), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["일산호수공원", "대화역", "킨텍스수변공원"], "confidence": "high", "address": "대한민국 고양시 킨텍스"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('탄천', '한강으로 이어지는 자전거길이 잘 조성되어 있어 수도권 라이더들이 즐겨 찾는 대표적인 하천입니다.', '{river}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.103531, 37.435023), 4326), false, '{"source": "KOMOOT", "source_ids": ["225"], "image_urls": ["https://photos.komoot.de/wiki/commons/7/7a/0_dankook_0.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/5d/Tancheon_and_Seoul_Sports_Complex_01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/fb/Tancheon_-_06_-_An_artificial_island_in_Jukjeon.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/5/5e/탄천.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/ee/1_dankook_05.jpg?width=1920&crop=false"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["서울공항", "상적천"], "confidence": "high", "address": "대한민국 경기도 성남시 수정구 고등동 1-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('탑정호 음악분수', '논산 탑정호 수변에 위치한 음악분수로, 라이딩 중 시원한 경관을 감상하며 휴식하기 좋은 랜드마크입니다. 탑정호 순환 자전거 코스의 주요 사진 촬영 및 인증 포인트로 유용합니다.', '{landmark,viewpoint,lake}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.148901, 36.175938), 4326), false, '{"source": "KOMOOT", "source_ids": ["741"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1f/1f2cxhpd2z0dhfqz22o2bewl13y76h0by-uhi43357734/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/yp/ypwxpm1dm4v5h55qvwrutfxj3y76h0ky-uhi43357735/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1b/1bzstoi7oe3ffcblb6iiyavhd5jnt1rkh-uhi95145991/0?width=1920&crop=false"], "category_raw": "man_made_monument", "tour_count": 1, "nearby_landmarks": ["탑정호 출렁다리", "탑정호 수변생태공원"], "confidence": "high", "address": "대한민국 충청남도 논산시 가야곡면 탑정로 773-38"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('탑정호 출렁다리', '논산 탑정호를 가로지르는 유명한 출렁다리로, 라이딩 중 수려한 호수 경관을 감상하고 사진을 남기기 좋은 주요 랜드마크입니다.', '{bridge,landmark,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.156829, 36.184202), 4326), false, '{"source": "KOMOOT", "source_ids": ["808"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/zb/zb7wl670b7y610oj6bmsztc6k3y76hxlo-uhi43357749/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k5/1r/1rois5x22ldnm1dwvdmv6e2gf23y76hxnq-uhi43357750/0?width=1920&crop=false"], "category_raw": "bridge", "tour_count": 1, "nearby_landmarks": ["탑정호", "탑정호 수변생태공원"], "confidence": "high", "address": "대한민국 충청남도 논산시 부적면 신풍리 755"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('태안공영버스터미널', '태안 및 안면도 해안도로 자전거 투어의 주요 출발지이자 복귀(점프) 지점으로 활용되는 핵심 교통 시설입니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.303009, 36.747734), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["태안군청", "백화산"], "confidence": "high", "address": "대한민국 충청남도 태안군 태안읍 동백로 304"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('탱자봉', '구미시 선기동에 위치한 해발 167m의 산봉우리입니다. 산악 자전거(MTB) 코스나 주변 지형을 파악할 때 참고할 수 있는 자연 지형지물입니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.297919, 36.13131), 4326), false, '{"source": "KOMOOT", "source_ids": ["110"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["덤바우산", "대성저수지"], "confidence": "high", "address": "대한민국 경상북도 구미시 선기동 산53-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('테크노파크역', '인천 1호선 지하철역으로, 송도 지역 라이딩 시 대중교통 연계(점프) 및 만남의 장소, 화장실 이용 등으로 유용한 교통 거점입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.656254, 37.382302), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/5/54/Technopark_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/23/ITC-Technopark_Stn-Gate.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["송도현대프리미엄아울렛", "트리플스트리트", "미추홀공원"], "confidence": "high", "address": "대한민국 인천광역시 테크노파크역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('통구미몽돌해변', '울릉도 해안도로 라이딩 중 만날 수 있는 몽돌해변으로, 거북바위 등 멋진 해안 절경을 감상하며 쉬어가기 좋은 포인트입니다.', '{beach,viewpoint,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(130.864894, 37.460333), 4326), false, '{"source": "KOMOOT", "source_ids": ["955"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["거북바위", "통구미터널"], "confidence": "high", "address": "8Q9GFV67+4X"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('신도바다역', '영종도 삼목선착장에서 배를 타고 들어와 신시모도(신도·시도·모도) 자전거 라이딩을 시작하는 출발점인 여객선 터미널(신도바다역)입니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.439244, 37.514849), 4326), false, '{"source": "KOMOOT", "source_ids": ["74"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["신도바다역", "신도여객터미널", "구봉산"], "confidence": "high", "address": "대한민국 인천광역시 옹진군 북도면 신도로 5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('통영전통공예관', '통영 도남관광단지 내에 위치한 전시관으로, 수륙해안산책로 등 통영 해안도로 라이딩 시 랜드마크 및 휴식 거점으로 활용하기 좋습니다.', '{museum,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.432615, 34.826635), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["도남관광지", "통영국제음악당", "수륙해안산책로", "금호통영마리나리조트"], "confidence": "high", "address": "대한민국 경상남도 통영시 도남동 642-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('파라다이스호텔입구', '제주 환상자전거길(칠십리로) 종주 노선에 위치한 구 파라다이스호텔 진입로 및 공항리무진 버스 정류장입니다. 소정방폭포와 허니문하우스로 향하는 길목으로 라이딩 중 위치를 파악하기 좋은 랜드마크입니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.576933, 33.247508), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["허니문하우스", "소정방폭포", "정방폭포", "서귀포칼호텔"], "confidence": "high", "address": "대한민국 제주특별자치도 서귀포시 동홍동 317-22"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('파주프리미엄아울렛후문', '파주 헤이리 및 통일동산 인근 라이딩 시 길잡이가 되며, 식음료 보급 및 화장실 이용 등 휴식을 취하기 좋은 대형 아울렛의 후문입니다.', '{landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.698565, 37.768903), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["신세계사이먼 파주프리미엄아울렛", "헤이리예술마을", "통일동산"], "confidence": "high", "address": "대한민국 파주시 파주프리미엄아울렛후문"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('판문동행정복지센터', '진주시 판문동에 위치한 행정복지센터로, 라이딩 중 화장실을 이용하거나 식수를 보충하기 좋은 지역 거점입니다.', '{restroom,water_fountain,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.052533, 35.167753), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["남강 자전거길", "진양호"], "confidence": "high", "address": "대한민국 진주시 판문동주민센터"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('판암역', '대전 도시철도 1호선 판암역입니다. 대중교통을 이용한 자전거 점프나 인근 식장산 업힐 코스를 가기 위한 출발지 및 만남의 장소로 유용합니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.458502, 36.316919), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/e/ec/Panam_Station_1.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/05/Panam_station_sign.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["식장산", "판암IC"], "confidence": "high", "address": "대한민국 대전광역시 판암역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('평기지', '경산시 남산면 평기리에 위치한 저수지로, 한적한 수변 경관을 감상하며 라이딩 중 쉬어가기 좋은 자연 지형입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.84944, 35.755761), 4326), false, '{"source": "KOMOOT", "source_ids": ["578"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["들기공원"], "confidence": "high", "address": "대한민국 경상북도 경산시 남산면 평기리 327"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('평암저수지', '정읍시 신정동에 위치한 저수지로, 라이딩 중 한적한 수변 경관을 감상하며 잠시 쉬어가기 좋은 자연 랜드마크입니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.831227, 35.506351), 4326), false, '{"source": "KOMOOT", "source_ids": ["1117"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["내장산IC", "정혜교차로", "신정사거리"], "confidence": "high", "address": "대한민국 전북특별자치도 정읍시 신정동 1119-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('포카리스웨트앞', '기흥호수공원 자전거길 인근 동아오츠카(포카리스웨트 제조사) 지점 앞에 위치한 버스정류장입니다. 독특한 정류장 이름 덕분에 기흥호수를 찾는 라이더들에게 이색적인 랜드마크이자 만남의 장소로 활용됩니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.108447, 37.235537), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["기흥호수공원", "동아오츠카 수원지점"], "confidence": "high", "address": "대한민국 경기도 용인시 기흥구 공세동 296-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('포항운하', '동빈내항과 형산강을 잇는 도심 속 운하로, 자전거길이 잘 조성되어 있어 경관을 즐기며 라이딩하기 좋은 명소입니다.', '{river,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.373248, 36.042828), 4326), false, '{"source": "KOMOOT", "source_ids": ["109"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["포항운하관", "형산강", "동빈내항"], "confidence": "high", "address": "대한민국 경상북도 포항시 남구 운하로 225"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('표선해변 자전거 인증센터', '제주 환상자전거길 종주를 위한 표선해변 무인 인증센터입니다. 자전거 수첩에 스탬프를 찍을 수 있는 필수 경유지입니다.', '{checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.840863, 33.325417), 4326), false, '{"source": "KOMOOT", "source_ids": ["329"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/1o/1opyhkcl7u2yz1azggmkagi5pp5bu89eh3-uhi84760960/0?width=1920&crop=false"], "tips": [{"text": "Certification Stamp Booth", "author": "Fitz_carraldo"}], "category_raw": "facilities", "tour_count": 1, "nearby_landmarks": ["표선해수욕장", "제주민속촌"], "confidence": "high", "address": "대한민국 제주특별자치도 서귀포시 표선면 표선리 44-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('푸른 언덕 전망 포토 스팟', '섬진강 자전거길 순창 적성면 구간에 위치한 전망 포토 스팟으로, 라이딩 중 수려한 자연 경관을 배경으로 사진을 남기며 쉬어가기 좋습니다.', '{viewpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.2291, 35.412453), 4326), false, '{"source": "KOMOOT", "source_ids": ["740"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/au/auzcaevoc31q1fl8z6czcl2ok5e57vzo3-uhi87511834/0?width=1920&crop=false"], "category_raw": "viewpoint", "tour_count": 1, "nearby_landmarks": ["섬진강 자전거길", "채계산 출렁다리", "화산옹"], "confidence": "high", "address": "대한민국 전북특별자치도 순창군 적성면 괴정리 1750"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('풍기역', '자전거 점프(대중교통 연계) 및 만남의 장소로 활용하기 좋은 중앙선 기차역입니다. 역 주변에서 보급 및 휴식이 가능합니다.', '{transit,restroom}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.523157, 36.873847), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/f/f2/Punggi_Station.JPG?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["풍기인삼시장", "풍기역 급수탑"], "confidence": "high", "address": "대한민국 경상북도 영주시 풍기읍 서부리 165"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('풍남문', '전주 한옥마을 인근에 위치한 전주성의 남문으로, 전주 자전거 투어 시 훌륭한 목적지이자 사진 촬영 명소입니다. 남부시장과 인접해 있어 라이딩 중 보급과 휴식을 취하기 좋습니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.147413, 35.813844), 4326), false, '{"source": "KOMOOT", "source_ids": ["1186"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1q/1q0b0zxfxg5fgskb7ffkvbs4h30ymmlrg-uhi6554239/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1v/1vlanvb28tkmi44u3yy9k6cfv30ymmooy-uhi6554240/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/14/14sqspr6o8lngwamek55hyriu30ymmvhp-uhi6554244/0?width=1920&crop=false"], "category_raw": "historical_site", "tour_count": 1, "nearby_landmarks": ["전주한옥마을", "전동성당", "남부시장"], "confidence": "high", "address": "대한민국 전주시 완산구 전동 161-1번지 전주시 전라북도 KR"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('풍무역', '김포골드라인 풍무역으로, 자전거 점프(대중교통 연계) 및 라이딩 출발·도착지로 활용하기 좋은 지하철역입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.732446, 37.612349), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/69/Pungmu_Station.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["이마트 트레이더스 김포점"], "confidence": "high", "address": "대한민국 경기도 김포시 사우동 542-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('필리핀대사관', '남산 소월로와 이태원 경리단길을 잇는 업힐 구간에 위치해 있어, 남산 라이딩 시 위치를 파악하는 랜드마크 역할을 합니다.', '{landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.995227, 37.540714), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["남산", "소월로", "경리단길"], "confidence": "high", "address": "대한민국 서울특별시 용산구 이태원동 5-60"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('하나개해변', '무의도 라이딩 코스의 주요 목적지이자 랜드마크인 해변입니다. 탁 트인 바다 경관과 해상관광탐방로를 감상하며 휴식하기 좋습니다.', '{beach,viewpoint,landmark,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.409709, 37.384672), 4326), false, '{"source": "KOMOOT", "source_ids": ["212"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["무의도", "해상관광탐방로", "호룡곡산"], "confidence": "high", "address": "대한민국 인천광역시 중구 하나개로 140"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('하남검단산역', '수도권 전철 5호선 종착역으로, 팔당대교 및 남한강 자전거길과 가까워 라이딩 출발지나 복귀 시 점프(대중교통 연계) 목적으로 매우 유용한 지하철역입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.223525, 37.539679), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/4/49/20210327_하남검단산역_역명판.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/8d/20210327_하남검단산역_1번출구.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/32/20210327_하남검단산역_승강장.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["팔당대교", "스타필드 하남", "검단산"], "confidence": "high", "address": "대한민국 경기도 하남시 창우동 526-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('하남시청역 (5호선)', '자전거 점프(지하철 연계) 및 라이더들의 만남의 장소로 활용하기 좋은 5호선 지하철역입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.206695, 37.541778), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/9/9c/20210408_하남시청역_승강장.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/33/20210408_하남시청역_역명판.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["덕풍천", "신장시장", "하남시청"], "confidence": "high", "address": "대한민국 경기도 하남시 신장동 423-29"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('하오고개', '수도권 남부 라이더들이 즐겨 찾는 대표적인 업힐 코스입니다. ''하여말(하오-여우-말구리)'' 코스의 주요 구간으로 유명합니다.', '{mountain,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.040545, 37.395722), 4326), false, '{"source": "KOMOOT", "source_ids": ["341"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/9h/9h3un2ngi6bz1mhqffivh9wcs37zmz2ly-uhi9756374/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/ay/ay47vunvylr115twq6apc5b2v37zmz5gv-uhi9756376/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/1l/1llsqctwiofed5ylumgfkj1cm37zmz65z-uhi9756377/0?width=1920&crop=false"], "tips": [{"text": "Climb begins shortly after the entrance to the Academy of Korean Studies,  after the initial first straight, in snakes around a fair bit. Firstly round the side of a small reservoir, with a handful of coffee shops, all the while steadily climbing at an average gradient of 5.5%. \n\nAt around 2/3rds of the way up the road passes for the first time over a high way, at the top of the climb it crosses paths with it once again. The descent down the other side to Uiwang & Anyang is very step with gradients between 8-10%, there are a couple of decent bends that have plenty of debris at the edge. Also, take care because I have encountered the odd person walking up and they can be easily obscured by overgrown bushes etc. In addition keep right at the bottom and I would advise joining the pavement bike path here, as otherwise you’ll end up on the highway with very fast moving traffic.", "author": "Jon"}], "category_raw": "climb", "tour_count": 1, "nearby_landmarks": ["한국학중앙연구원", "하오고개 육교", "청계산"], "confidence": "high", "address": "대한민국 경기도 성남시 분당구 운중동 산80-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('학곡저수지', '치악산국립공원 구룡사 방면 라이딩 시 지나는 저수지로, 수려한 자연 경관을 감상하며 잠시 쉬어가기 좋은 장소입니다.', '{lake,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.05435, 37.43993), 4326), false, '{"source": "KOMOOT", "source_ids": ["158"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1l/1lvbcgi8966wf127syhyuc6wd64rh28ndj-uhi66860674/0?width=1920&crop=false"], "category_raw": "lake", "tour_count": 1, "nearby_landmarks": ["치악산국립공원", "구룡사"], "confidence": "high", "address": "대한민국 강원특별자치도 원주시 소초면 학곡리 산102-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('한강진역', '서울 지하철 6호선 한강진역입니다. 이태원 및 한남동 일대 라이딩 시 대중교통 연계(점프) 목적으로 활용하기 좋은 교통 시설입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.001769, 37.539796), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/4/43/Q278103_Hangangjin_A01.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c5/Seoul-metro-631-Hangangjin-station-platform-20181126-162100.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/14/Seoul-metro-631-Hangangjin-station-entrance-2-20181126-162918.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/9f/한강진역_게이트.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/85/631_한강진.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["블루스퀘어", "리움미술관", "이태원"], "confidence": "high", "address": "대한민국 서울특별시 한남동 한강진"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('한국개발연구원', '금강종주자전거길 세종 구간에 인접해 있는 대형 국책연구기관으로, 강변 자전거길을 지나는 라이더들에게 현재 위치를 파악하기 좋은 랜드마크 역할을 합니다.', '{landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.307656, 36.481276), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["금강종주자전거길", "금강", "학나래교"], "confidence": "high", "address": "대한민국 세종특별자치시 KDI(한국개발연구원)"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('한국은행 분수대', '서울 도심 한복판에 위치한 상징적인 분수대로, 남산이나 시청 방면 도심 라이딩 시 방향을 가늠하고 경유하기 좋은 주요 랜드마크입니다.', '{landmark,historic}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.981202, 37.561376), 4326), false, '{"source": "KOMOOT", "source_ids": ["172"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k8/13/13rm94jhh3fzc1gv1mcapdt9ir4zdyo9zw-uhi72415560/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/hy/hy3qmubsgntd12forr5ybuxdo5hrfz5kn-uhi92576961/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/11/11yn4hp3g1wqt1iztxkhr6r8hh5hrfz67z-uhi92576963/0?width=1920&crop=false"], "tips": [{"text": "Tolle Stadt gerade am Fluss zu gehen macht ebenfalls richtig Spass.. abends oft mit Musik", "author": "Jörg Clef"}], "category_raw": "man_made_monument", "tour_count": 1, "nearby_landmarks": ["한국은행 화폐박물관", "남대문시장", "신세계백화점 본점"], "confidence": "high", "address": "대한민국 서울특별시 중구 충무로1가 3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('한국프랜지 교차로', '울산 동구의 버스정류장 및 교차로입니다. 라이더들이 주전고개를 넘어 주전해변이나 동해안 자전거길로 진입할 때 거쳐 가는 주요 길목입니다.', '{transit,checkpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.428006, 35.539116), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["한국프랜지공업", "주전고개", "남목파출소"], "confidence": "high", "address": "대한민국 울산광역시 한국프렌지앞"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('한티역', '수인분당선 한티역입니다. 자전거 점프(지하철 연계) 및 라이더들의 만남의 장소로 활용할 수 있는 대중교통 거점입니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.052909, 37.496283), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/3/30/Q46122_Hanti_A01.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/01/Korail-Bundang-line-K216-Hanti-station-entrance-4-20181121-153930.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/f/fd/Korail-Bundang-line-K216-Hanti-station-sign-20181121-153258.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/04/Korail-Bundang-line-K216-Hanti-station-platform-20181121-153334.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3d/Korail-Bundang-line-K216-Hanti-station-platform-20181121-154500.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["롯데백화점 강남점", "도곡공원", "대치동 학원가"], "confidence": "high", "address": "대한민국 서울특별시 강남구 선릉로 228 역내"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('함백역', '주민들의 힘으로 복원된 함백선 폐역으로, 라이딩 중 사진을 남기거나 쉬어가기 좋은 역사적 랜드마크입니다.', '{historic,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.697145, 37.216155), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/0/09/Korail_Hambaek_Line_Hambaek_Station_Rearside.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/4/4e/Korail_Hambaek_Line_Hambaek_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/9/92/Korail_Hambaek_Line_Hambaek_Station_Platform.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/d/db/Korail_Hambaek_Line_Hambaek_Station_Platform2.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["함백탄광기념공원", "안경다리"], "confidence": "high", "address": "대한민국 강원특별자치도 정선군 신동읍 방제리 196-13"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('함창 버스정류장', '상주시 함창읍 중심부에 위치한 버스 정류장으로, 대중교통을 이용한 자전거 점프나 인근 상권에서 보급하기 좋은 거점입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.175243, 36.569567), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/9/9e/Reverse_of_Hamchang_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/76/Hamchang_Station.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["함창역", "함창전통시장"], "confidence": "high", "address": "대한민국 경상북도 상주시 함창읍 구향리 166-49"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('함허정', '섬진강 자전거길 인근에 위치한 조선시대 정자로, 섬진강의 아름다운 경관을 조망하며 휴식하기 좋은 역사적 명소입니다.', '{historic,viewpoint,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.221039, 35.321411), 4326), false, '{"source": "KOMOOT", "source_ids": ["1202"], "category_raw": "14", "tour_count": 1, "nearby_landmarks": ["섬진강", "제호정 고택"], "confidence": "high", "address": "대한민국 전라남도 곡성군 입면 제월리 산144-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('인천공항자기부상 합동청사역', '영종도 인천국제공항 인근에 위치한 자기부상철도역으로, 라이딩 중 위치 파악 및 대중교통 연계 지점으로 활용할 수 있는 랜드마크입니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.458518, 37.440496), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/9/9e/Administration_Complex_Station.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/af/Administration_Complex_Station_sign.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/e/e0/Administration_Complex_Station_Platform.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["인천국제공항", "파라다이스시티"], "confidence": "high", "address": "대한민국 인천광역시 합동 청 사역"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('합천시외버스터미널', '자전거 점프(대중교통 연계) 및 타 지역 이동 시 유용한 합천읍 내 시외버스터미널입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.163157, 35.567124), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["황강", "합천군청"], "confidence": "high", "address": "대한민국 경상남도 합천군 합천읍 합천리 322-21"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('우도 해녀상', '우도 해안도로(우도해안길)에 위치한 해녀 동상으로, 자전거 라이딩 중 탁 트인 바다를 배경으로 기념 사진을 남기기 좋은 랜드마크입니다.', '{landmark,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.955041, 33.523808), 4326), false, '{"source": "KOMOOT", "source_ids": ["348"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/3q/3qmelfpvk0e79u1e241jfcgx5bubhn7k-uhi84761946/0?width=1920&crop=false"], "tips": [{"text": "A Haenyeo statue is a sculpture that honors the haenyeo, the traditional female divers of Jeju Island, South Korea.", "author": ""}], "category_raw": "man_made_monument", "tour_count": 1, "nearby_landmarks": ["우도해안길", "답다니탑망대"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 우도해안길 630"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('해돋이공원', '인천 송도국제도시에 위치한 대형 공원으로 자전거 길이 잘 조성되어 있으며, 라이딩 중 화장실 이용 및 휴식을 취하기 매우 좋은 장소입니다.', '{park,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.650343, 37.388832), 4326), false, '{"source": "KOMOOT", "source_ids": ["49"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/bj/bjwc6cwm113zzc38s2b9pt34jxsw65b-uhi59301374/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/1e/1ew0cp2d0d0awintukbwpxiws4jxsw682-uhi59301375/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k7/h9/h9d8kw9ozprmcy53t3e4hks64jxsw699-uhi59301376/0?width=1920&crop=false"], "category_raw": "other_natural", "tour_count": 1, "nearby_landmarks": ["송도센트럴파크", "미추홀공원", "캠퍼스타운역"], "confidence": "high", "address": "대한민국 인천광역시 연수구 송도동 42-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('해미읍성 주차장', '서산 해미읍성 앞 주차장으로, 차량을 이용한 라이딩 출발지(점프)나 만남의 장소로 활용하기 좋습니다. 주변에 화장실과 식당 등 편의시설이 잘 갖춰져 있어 휴식하기에도 적합합니다.', '{parking,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.549024, 36.710816), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["해미읍성", "해미순교성지"], "confidence": "high", "address": "대한민국 충청남도 서산시 해미면 읍내리 101-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('해반천', '김해시를 가로지르는 하천으로, 수변을 따라 자전거 전용도로가 길게 조성되어 있어 안전하고 쾌적한 라이딩을 즐길 수 있는 주요 코스입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.868883, 35.256174), 4326), false, '{"source": "KOMOOT", "source_ids": ["10", "300", "34", "1111"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["가야대역(김해해반천)", "삼계한일유엔아이"], "confidence": "high", "address": "대한민국 김해시 한일유엔아이"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('해반천', '김해시를 가로지르는 도심 하천으로, 하천을 따라 자전거 전용도로가 잘 조성되어 있어 안전하고 쾌적하게 라이딩을 즐길 수 있는 주요 코스입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.865314, 35.264425), 4326), false, '{"source": "KOMOOT", "source_ids": ["10", "300", "34", "1111"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["장신대역", "삼계교", "화정공원"], "confidence": "high", "address": "대한민국 경상남도 김해시 삼계동 1430-8"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('츠노시마 오하마 해수욕장', '야마구치현 츠노시마에 위치한 해변으로, 코발트블루 빛 바다 경관을 감상하며 휴식하기 좋은 라이딩 포인트입니다.', '{beach,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(130.855456, 34.35364), 4326), false, '{"source": "KOMOOT", "source_ids": ["1073", "235", "165", "199", "99", "897", "1734", "322", "710", "284"], "image_urls": ["https://photos.komoot.de/wiki/commons/d/d1/주문진해수욕장_향호해변.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bd/Jumunjin_Beach_20220501_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/30/Jumunjin_Beach_20220501_007.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/10/Jumunjin_Beach_20220501_013.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2a/Jumunjin_Beach_20220501_016.jpg?width=1920&crop=false"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["시오카제노사토 츠노시마", "츠노시마 오하마 해수욕장"], "confidence": "high", "address": "853-4 Hōhokuchō Ōaza Tsunoshima, Shimonoseki, Yamaguchi 759-5332 일본"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('외포 해변 전망대', '거제 장목면 외포리 옥포대첩로 해안도로 변에 위치한 해변으로, 라이딩 중 탁 트인 바다 경관을 감상하며 쉬어가기 좋은 장소입니다.', '{beach,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.716347, 34.955423), 4326), false, '{"source": "KOMOOT", "source_ids": ["1073", "235", "165", "199", "99", "897", "1734", "322", "710", "284"], "image_urls": ["https://photos.komoot.de/wiki/commons/d/d1/주문진해수욕장_향호해변.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bd/Jumunjin_Beach_20220501_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/30/Jumunjin_Beach_20220501_007.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/10/Jumunjin_Beach_20220501_013.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2a/Jumunjin_Beach_20220501_016.jpg?width=1920&crop=false"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["외포항", "옥포대첩로"], "confidence": "medium", "address": "대한민국 경상남도 거제시 장목면 옥포대첩로 1072"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('남열해돋이해수욕장', '고흥의 대표적인 일출 명소이자 서핑 스팟으로, 해안도로 라이딩 중 탁 트인 남해 바다 경관을 감상하며 쉬어가기 좋은 해변입니다.', '{beach,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.476591, 34.579323), 4326), false, '{"source": "KOMOOT", "source_ids": ["1073", "235", "165", "199", "99", "897", "1734", "322", "710", "284"], "image_urls": ["https://photos.komoot.de/wiki/commons/d/d1/주문진해수욕장_향호해변.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bd/Jumunjin_Beach_20220501_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/30/Jumunjin_Beach_20220501_007.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/10/Jumunjin_Beach_20220501_013.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2a/Jumunjin_Beach_20220501_016.jpg?width=1920&crop=false"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["고흥우주발사전망대", "용바위"], "confidence": "high", "address": "대한민국 전라남도 고흥군 영남면 남열리 1216-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('변산해변', '새만금 방조제 남단에 위치한 해변으로, 서해안의 탁 트인 바다 경관을 감상하며 해안 도로를 따라 라이딩하기 좋은 자연 지형입니다.', '{beach,nature,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.538469, 35.688294), 4326), false, '{"source": "KOMOOT", "source_ids": ["1073", "235", "165", "199", "99", "897", "1734", "322", "710", "284"], "image_urls": ["https://photos.komoot.de/wiki/commons/d/d1/주문진해수욕장_향호해변.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/b/bd/Jumunjin_Beach_20220501_001.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/30/Jumunjin_Beach_20220501_007.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/10/Jumunjin_Beach_20220501_013.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/2/2a/Jumunjin_Beach_20220501_016.jpg?width=1920&crop=false"], "category_raw": "12", "tour_count": 1, "nearby_landmarks": ["새만금방조제", "변산해수욕장", "새만금홍보관"], "confidence": "high", "address": "대한민국 전북특별자치도 부안군 변산면 대항리 291-12"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('우도 해안도로 전망대', '우도 해안도로 라이딩 중 아름다운 제주 바다 풍경을 감상하며 사진을 찍고 쉬어갈 수 있는 전망 포인트입니다.', '{viewpoint,beach}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.957302, 33.514673), 4326), false, '{"source": "KOMOOT", "source_ids": ["285"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k3/1a/1aaybsv7gir4k1k37jj9gyzeky36h52mjr-uhi9206155/0?width=1920&crop=false"], "category_raw": "beach", "tour_count": 1, "nearby_landmarks": ["우도 해안도로"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 우도면 연평리 1200-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('해송마을 주차장', '함양 및 지리산 일대 자전거 코스의 출발지로 활용하기 좋은 마을 공용 주차장입니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.693673, 35.484957), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["해송마을"], "confidence": "high", "address": "대한민국 경상남도 함양군 함양읍 구룡리 1256"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('발안만세시장', '화성시 향남읍 평리에 위치한 전통시장입니다. 다양한 식당과 편의시설이 밀집해 있어 자전거 라이딩 중 식사와 보급, 휴식을 취하기에 매우 유용한 장소입니다.', '{landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.907778, 37.131782), 4326), false, '{"source": "KOMOOT", "source_ids": ["565"], "tips": [{"text": "Lots of stores and restaurants on this street", "author": "Curry (カレー)"}], "category_raw": "settlement", "tour_count": 1, "nearby_landmarks": ["발안만세시장", "발안천"], "confidence": "high", "address": "대한민국 경기도 화성시 향남읍 평리 115-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('향수산', '용인 에버랜드 인근에 위치한 산으로, 산악자전거(MTB) 라이더들이 즐겨 찾는 임도 및 싱글 트레일 코스가 조성되어 있습니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.18573, 37.311314), 4326), false, '{"source": "KOMOOT", "source_ids": ["209"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["에버랜드", "88컨트리클럽", "호암미술관"], "confidence": "high", "address": "856P+G7 대한민국 경기도 용인시"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('현충로역', '대구 도시철도 1호선 현충로역입니다. 대중교통을 이용한 자전거 점프나 라이딩 모임 장소로 활용하기 좋은 교통 거점입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.581276, 35.840869), 4326), false, '{"source": "KOMOOT", "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["앞산네거리", "앞산카페거리"], "confidence": "high", "address": "대한민국 대구광역시 현충로"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('현풍시외버스공동정류장', '대구 달성군 현풍읍에 위치한 시외버스 정류장으로, 낙동강 종주 등 자전거 라이딩 전후 대중교통을 이용해 이동(점프)할 때 유용한 교통 거점입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.441492, 35.699034), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["낙동강 자전거길", "현풍백년도깨비시장"], "confidence": "high", "address": "대한민국 대구광역시 달성군 현풍읍 부리 267-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('호국지', '국립대전현충원 내에 위치한 연못으로, 고즈넉한 자연 경관을 감상하며 차분하게 쉬어갈 수 있는 장소입니다.', '{lake,park}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.301263, 36.361542), 4326), false, '{"source": "KOMOOT", "source_ids": ["265"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["국립대전현충원"], "confidence": "high", "address": "대한민국 대전광역시 유성구 갑동 433-5"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('호박소', '밀양 8경 중 하나로 꼽히는 아름다운 계곡 명소입니다. 라이딩 중 시원한 폭포와 계곡 경관을 감상하며 휴식하기 좋습니다.', '{nature,landmark,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.996286, 35.587987), 4326), false, '{"source": "KOMOOT", "source_ids": ["936"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["얼음골", "얼음골케이블카", "오천평반석"], "confidence": "high", "address": "대한민국 경상남도 밀양시 산내면 얼음골로 334-1 민국"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('아산호', '충남 아산시와 경기 평택시 경계에 위치한 거대한 호수입니다. 탁 트인 수변 경관을 자랑하며 아산호(평택호) 순환 자전거길이 조성되어 있어 라이딩 코스로 인기가 높습니다.', '{lake,viewpoint}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.962345, 36.904582), 4326), false, '{"source": "KOMOOT", "source_ids": ["367", "680", "261", "535"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["아산만방조제", "평택호 자전거길"], "confidence": "high", "address": "대한민국 충청남도 아산시 영인면 구성리 388-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('홍대입구역', '경의중앙선과 공항철도를 이용해 자전거 점프(지하철 탑승)가 가능한 주요 환승역이며, 경의선숲길 및 한강 자전거길로 접근하기 좋은 거점입니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.923394, 37.55667), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/b/b1/Hongik-university-station-entrance-9-20181121-083316.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0d/239_Hongik_University_Line_2_platforms_20240630_101906.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/70/Hongik-university-station-entrance-8-20181121-083542.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/1/16/Hongik_univ_station_exit3_2006.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/ac/20250510_홍대입구역_3번출구.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["경의선숲길", "연트럴파크"], "confidence": "high", "address": "대한민국 서울특별시 마포구 동교동 155-6"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('홍제역', '서울 지하철 3호선 홍제역으로, 홍제천 자전거길 진입 전후 대중교통 연계 및 만남의 장소로 유용한 교통 시설입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.944181, 37.588673), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/7/7b/Hongje_Station_3.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/7/73/Hongje_Station_Platform.JPG?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3b/Seoul-metro-324-Hongje-station-sign-20191022-135030.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/c/c3/Seoul-metro-324-Hongje-station-entrance-2-20191022-135746.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/8/82/Seoul-metro-324-Hongje-station-sign-20191022-135048.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["홍제천", "유진상가"], "confidence": "high", "address": "대한민국 서울특별시 서대문구 홍제동 161-10"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('홍제천', '한강 자전거길과 연결되는 주요 지류 하천으로, 라이더들이 진출입 및 주행 코스로 자주 이용하는 자전거 전용 도로가 잘 조성되어 있습니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.905251, 37.563987), 4326), false, '{"source": "KOMOOT", "source_ids": ["72", "64", "540", "106", "118", "165", "876", "435", "479", "330"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["홍제천 자전거길", "마포구청역", "한강 합수부"], "confidence": "high", "address": "대한민국 서울특별시 마포구 성산동 203-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('홍제천', '한강 자전거길과 연결되는 서울의 주요 하천으로, 라이더들이 자주 이용하는 코스이자 자연 경관을 즐길 수 있는 랜드마크입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.958943, 37.59963), 4326), false, '{"source": "KOMOOT", "source_ids": ["72", "64", "540", "106", "118", "165", "876", "435", "479", "330"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["상명대학교", "세검정"], "confidence": "high", "address": "대한민국 서울특별시 종로구 홍지동 99-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('홍죽천', '경기도 양주시 백석읍을 흐르는 하천으로, 자전거 라이딩 시 경관을 즐기거나 코스의 기준점으로 참고하기 좋은 자연 지형입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.974496, 37.80312), 4326), false, '{"source": "KOMOOT", "source_ids": ["597"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["홍죽일반산업단지", "신천"], "confidence": "high", "address": "대한민국 경기도 양주시 백석읍 홍죽리 160-12"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('홍천은행나무숲', '가을철 노란 은행나무 풍경으로 유명한 홍천의 대표적인 명소입니다. 구룡령 등 강원도 내륙 장거리 라이딩 시 아름다운 경관을 감상하며 쉬어가기 좋은 랜드마크입니다.', '{nature,viewpoint,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.469654, 37.831347), 4326), false, '{"source": "KOMOOT", "source_ids": ["658"], "category_raw": "191", "tour_count": 1, "nearby_landmarks": ["구룡령", "오대산국립공원", "계방산"], "confidence": "high", "address": "대한민국 강원특별자치도 홍천군 내면 광원리 686-2"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('화림지', '충남 금산군 금성면에 위치한 저수지(사갑지)로, 한적한 수변 경관을 즐기며 라이딩하기 좋은 자연 지형입니다.', '{lake,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.445117, 36.122299), 4326), false, '{"source": "KOMOOT", "source_ids": ["166"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["사갑지"], "confidence": "high", "address": "대한민국 충청남도 금산군 금성면 화림리 19"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('보문단지 HICO·힐튼 정류장', '경주 보문관광단지 내 화백컨벤션센터(HICO)와 힐튼호텔 앞에 위치한 버스정류장으로, 라이딩 중 길잡이나 가벼운 휴식, 만남의 장소로 활용하기 좋습니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.286984, 35.838929), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["화백컨벤션센터(HICO)", "힐튼호텔 경주", "보문호", "경주월드"], "confidence": "high", "address": "대한민국 경주시 화백컨밴션센타.힐튼호텔"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('수원화성 창룡문 잔디광장', '수원화성 창룡문과 연무대 인근에 위치한 넓은 잔디광장으로, 탁 트인 경관을 감상하며 자전거 라이딩 중 안전하게 휴식하기 좋은 수원의 대표적인 랜드마크입니다.', '{park,historic,rest_area,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.023706, 37.287881), 4326), false, '{"source": "KOMOOT", "source_ids": ["122"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/ie/iepcj32npopr1akg9e86j9g0m3fncvhx9-uhi16700801/0?width=1920&crop=false", "https://d2exd72xrrp1s7.cloudfront.net/www/000/1k4/op/op9vs1ymajai1imkctpezrx0k3fncvle3-uhi16700804/0?width=1920&crop=false"], "category_raw": "historical_site", "tour_count": 1, "nearby_landmarks": ["수원화성", "창룡문", "연무대", "플라잉수원"], "confidence": "high", "address": "대한민국 경기도 수원시 팔달구 창룡대로 105"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('화천공용버스터미널', '자전거를 싣고 시외로 이동(점프)하거나 복귀할 때 필수적인 대중교통 거점입니다. 북한강 자전거길 상류 코스 라이딩의 시작점이나 종착점으로 활용하기 좋으며 주변에서 보급을 해결하기 용이합니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.704382, 38.104531), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["북한강 자전거길", "화천시장", "붕어섬"], "confidence": "high", "address": "대한민국 강원특별자치도 화천군 화천읍 하리 43-37"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('환상숲곶자왈공원', '제주 서부 중산간 지역 라이딩 시 거쳐가기 좋은 독특한 생태 숲 공원입니다. 아름다운 자연 경관을 감상하며 휴식을 취하거나 코스의 주요 랜드마크로 활용하기 좋습니다.', '{park,nature,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.263366, 33.321948), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["생각하는정원", "제주유리의성", "저지오름"], "confidence": "high", "address": "대한민국 제주특별자치도 제주시 한경면 저지리 2857-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('황금역', '대구 도시철도 3호선 황금역입니다. 대중교통 연계(점프) 및 라이딩 경로 상의 주요 이정표로 활용하기 좋은 장소입니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.623846, 35.839097), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/6/60/20240427_104609._jpg.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/0c/Hwanggeum_Station_20150424_165948.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/a/a0/Hwanggeum_Station_20150424_165921.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/3/3b/20240427_104713._황금역.jpg?width=1920&crop=false", "https://photos.komoot.de/wiki/commons/0/00/Hwanggeum_Station_20150424_165809.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["황금네거리", "범어천", "홈플러스 대구수성점"], "confidence": "high", "address": "대한민국 대구광역시 대구광역시 E1N2 범어천"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('황둔천', '원주시 신림면을 흐르는 하천으로, 치악산 둘레길과 원주 산악자전거 파크가 인접해 있어 라이딩 중 수려한 자연 경관을 감상할 수 있는 곳입니다.', '{river,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.190191, 37.260339), 4326), false, '{"source": "KOMOOT", "source_ids": ["288"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["원주 산악자전거 파크", "치악산 둘레길", "황둔리 캠핑장"], "confidence": "high", "address": "대한민국 강원특별자치도 원주시 신림면 황둔리 242-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('황룡2저수지', '충남 보령시 청라면에 위치한 저수지로, 한적한 시골길 라이딩 중 경관을 감상하거나 코스의 길잡이로 삼기 좋은 자연 지형입니다.', '{lake,nature,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.648009, 36.429997), 4326), false, '{"source": "KOMOOT", "source_ids": ["221"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["넙티고개", "황룡2리마을회관"], "confidence": "high", "address": "대한민국 충청남도 보령시 청라면 황룡리 산1-23"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('황매산미리내오토캠핑장', '황매산 업힐 코스 중 휴식과 재정비를 할 수 있는 거점입니다. 고지대에 위치해 경관이 뛰어나며 화장실 등 편의시설을 이용할 수 있어 라이더들에게 유용한 랜드마크입니다.', '{rest_area,landmark,mountain}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.968264, 35.484711), 4326), false, '{"source": "KOMOOT", "source_ids": ["340"], "category_raw": "9", "tour_count": 1, "nearby_landmarks": ["황매산", "황매산군립공원", "황매산수목원"], "confidence": "high", "address": "대한민국 경상남도 산청군 차황면 법평리 산1-16"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('황산녹색쌈지공원', '오십천 자전거길 및 해파랑길 32코스 인근에 위치한 소규모 공원으로, 라이딩 중 가볍게 휴식하거나 웨이포인트로 삼기 좋은 장소입니다.', '{park,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.167358, 37.43563), 4326), false, '{"source": "KOMOOT", "source_ids": ["2766"], "category_raw": "191", "tour_count": 1, "nearby_landmarks": ["오십천", "남양체육공원", "삼척교"], "confidence": "high", "address": "대한민국 강원특별자치도 삼척시 남양동 322-9"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('황어 공용 주차장', '아라자전거길(아라뱃길)과 황어장터 인근에 위치한 공용 주차장으로, 차량에 자전거를 싣고 와서 라이딩을 시작(점프)하기 좋은 거점입니다.', '{parking}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.735672, 37.578563), 4326), false, '{"source": "KOMOOT", "category_raw": "64", "tour_count": 1, "nearby_landmarks": ["아라자전거길", "황어장터 3.1만세운동 기념관", "아라뱃길"], "confidence": "high", "address": "대한민국 인천광역시 계양구 장기동 147-4"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('횡탄정 인증센터', '섬진강 자전거길 국토종주를 위한 필수 인증센터입니다. 횡탄정 정자 옆에 위치하여 라이더들의 휴식처로도 활용됩니다.', '{checkpoint,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.328082, 35.303694), 4326), false, '{"source": "KOMOOT", "source_ids": ["65"], "image_urls": ["https://d2exd72xrrp1s7.cloudfront.net/www/000/1k9/14/14u9jb446adjb1wc5yppo951du5e3v6kcs-uhi87480290/0?width=1920&crop=false"], "category_raw": "facilities", "tour_count": 1, "nearby_landmarks": ["섬진강", "횡탄정"], "confidence": "high", "address": "대한민국 전라남도 곡성군 고달면 뇌죽리 905-28"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('회동저수지', '부산 금정구에 위치한 수려한 경관의 저수지로, 자전거 라이딩 시 목적지나 경유지로 삼기 좋은 탁 트인 자연 랜드마크입니다.', '{lake,nature,viewpoint,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(129.116295, 35.252676), 4326), false, '{"source": "KOMOOT", "source_ids": ["373"], "category_raw": "190", "tour_count": 1, "nearby_landmarks": ["오륜대", "땅뫼산 황토숲길", "회동수원지 둘레길"], "confidence": "high", "address": "대한민국 부산광역시 금정구 오륜동 산97-1"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('횡성역', '강릉선 KTX가 정차하는 기차역으로, 섬강 자전거길과 인접해 있어 자전거 여행 시 대중교통 연계(점프) 거점으로 유용한 장소입니다.', '{transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(128.010602, 37.483321), 4326), false, '{"source": "KOMOOT", "image_urls": ["https://photos.komoot.de/wiki/commons/8/8e/Hoengseong_Station_Building_2.jpg?width=1920&crop=false"], "category_raw": "219", "tour_count": 1, "nearby_landmarks": ["섬강 자전거길", "생운교"], "confidence": "high", "address": "대한민국 강원특별자치도 횡성군 횡성읍 생운리 245-3"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('효문화마을/뿌리공원', '대전 유등천 자전거길의 종점 부근에 위치한 대표적인 랜드마크로, 라이더들의 훌륭한 휴식처이자 목적지입니다. 화장실 등 편의시설이 잘 갖춰져 있고 수변 경관이 뛰어납니다.', '{park,landmark,rest_area}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.383782, 36.285354), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["유등천", "대전오월드", "보문산"], "confidence": "high", "address": "대한민국 대전광역시 효문화마을/뿌리공원"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('흑산여객터미널', '흑산도 자전거 라이딩의 시작점이자 종점 역할을 하는 여객선 터미널입니다. 육지와 섬을 자전거로 오가기 위한 필수 교통 거점입니다.', '{transit,landmark}'::waypoint_type[], ST_SetSRID(ST_MakePoint(125.442175, 34.684497), 4326), false, '{"source": "KOMOOT", "category_raw": "47", "tour_count": 1, "nearby_landmarks": ["흑산도항", "흑산도 해안도로"], "confidence": "high", "address": "대한민국 전라남도 신안군 흑산면 예리 176-125"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('흑석골입구', '전주 서서학동 흑석골로 들어가는 진입로 교차로 및 정류장입니다. 학산이나 남고산성 방면으로 라이딩할 때 길잡이 및 체크포인트로 활용하기 좋습니다.', '{checkpoint,transit}'::waypoint_type[], ST_SetSRID(ST_MakePoint(127.149983, 35.804243), 4326), false, '{"source": "KOMOOT", "category_raw": "63", "tour_count": 1, "nearby_landmarks": ["흑석골", "남고산성", "전주교육대학교"], "confidence": "high", "address": "대한민국 전북특별자치도 전주시 완산구 서서학동 161"}'::jsonb);
INSERT INTO waypoints (name, description, type, location, is_verified, etc) VALUES ('흑악', '서귀포시 남원읍 5.16 도로변에 위치한 작은 오름(검은오름)으로, 라이딩 중 자연 경관을 감상할 수 있는 지점입니다.', '{mountain,nature}'::waypoint_type[], ST_SetSRID(ST_MakePoint(126.61873, 33.34956), 4326), false, '{"source": "KOMOOT", "source_ids": ["1069"], "category_raw": "21", "tour_count": 1, "nearby_landmarks": ["5.16도로", "논고교", "이승악"], "confidence": "high", "address": "대한민국 제주특별자치도 서귀포시 남원읍 신례리 산2-25"}'::jsonb);
